var DICT_EXAMPLES = {
  'ser': { es: 'Soy estudiante de Tokio.', ja: '私は東京の学生です。', trivia: 'ラテン語 esse（存在する）から。英語の essence（本質）や essential（必須の）と同語根。「存在の核」を表す語根です。' },
  'estar': { es: 'Ahora estoy en casa para estudiar.', ja: '今は勉強するために家にいます。', trivia: 'ラテン語 stare（立つ）から。英語の state（状態）・station（駅）・stable（安定した）と同語根。「今その場に立っている」状態を指します。' },
  'tener': { es: 'Tengo una pregunta sobre la gramática.', ja: '文法について質問があります。', trivia: 'ラテン語 tenere（保持する）から。英語の contain（含む）・retain（保持する）・tenant（借家人）と同語根。' },
  'hacer': { es: '¿Qué hacemos esta noche?', ja: '今夜は何をしますか？', trivia: 'ラテン語 facere（作る・する）から。英語の factory（工場）・fact（事実）・affect（影響する）と同語根。' },
  'ir': { es: 'Voy a viajar a España el próximo año.', ja: '来年スペインに旅行するつもりです。', trivia: 'ラテン語 ire（行く）から。英語の exit（出口、"going out"）にその痕跡が残ります。活用形が go/went のように不規則なのは複数語源が混ざったため。' },
  'venir': { es: '¿De dónde vienen ustedes?', ja: 'あなたたちはどこから来ますか？', trivia: 'ラテン語 venire（来る）から。英語の advent（到来）・prevent（先に来る→防ぐ）・convention（共に来る→集会）と同語根。' },
  'poder': { es: '¿Puedo hablar contigo un momento?', ja: '少しお話しできますか？', trivia: 'ラテン語 potere（できる）から。英語の potent（有力な）・potential（可能性）と同語根。「権力（power）」と語源が同じです。' },
  'querer': { es: 'Quiero conocer Cusco y Machu Picchu.', ja: 'クスコとマチュ・ピチュを訪れたいです。', trivia: 'ラテン語 quaerere（求める）から。英語の query（質問）・quest（探求）・question（疑問）と同語根。愛することは「求めること」という概念が根底に。' },
  'saber': { es: '¿Sabes dónde está el aeropuerto?', ja: '空港がどこにあるか知っていますか？', trivia: 'ラテン語 sapere（味わう・知る）から。人類の学名 Homo sapiens（知恵ある人）の sapiens と同語根。英語 savant（博識者）とも関連。' },
  'conocer': { es: 'Quiero conocer otras ciudades cercanas.', ja: '近くの他の都市も知りたいです。', trivia: 'ラテン語 cognoscere（知る）から。英語の recognize（認識する）・cognitive（認知の）・incognito（変名で）と同語根。' },
  'hablar': { es: 'Me gusta hablar español con amigos.', ja: '友達とスペイン語を話すのが好きです。', trivia: 'ラテン語 fabulare（寓話を語る）から。英語の fable（寓話）・fabulous（素晴らしい）と同語根。「話す」行為がもともと「物語る」ことを指していました。' },
  'comer': { es: 'Los mexicanos comen carne con tortillas.', ja: 'メキシコ人はトルティーヤと一緒に肉を食べます。', trivia: 'ラテン語 comedere（食べ尽くす）から。英語で食品を表す comestibles は同語根。"comedy" は「饗宴の歌」の意でやや遠い親戚。' },
  'vivir': { es: 'Vivo en Tokio, pero soy de Fukuoka.', ja: '東京に住んでいますが、福岡の出身です。', trivia: 'ラテン語 vivere（生きる）から。英語の vivid（鮮やか）・survive（生き延びる）・revive（復活）と同語根。' },
  'llegar': { es: 'El avión llega a las ocho de la noche.', ja: '飛行機は夜8時に到着します。', trivia: 'ラテン語 plicare（折り畳む、入港する）から変化。英語の "apply"（応用する）と遠い語根を共有。' },
  'salir': { es: 'Para llegar hay que salir desde Cusco en tren.', ja: 'そこへ行くにはクスコから電車で出発しなければなりません。', trivia: 'ラテン語 salire（跳ぶ）から。英語の salient（突出した）・assault（跳びかかる）・somersault（宙返り）と同語根。' },
  'viajar': { es: '¿Vas a viajar a Perú este agosto?', ja: '今年の8月にペルーに旅行するの？', trivia: '"viaje"（旅）→ ラテン語 viaticum（旅の糧）から。英語の via（〜経由で）と同語根。ローマ時代の街道網が語源の背景。' },
  'llamar': { es: '¿Cómo te llamas? Me llamo Lupe.', ja: 'お名前は？私はルペといいます。', trivia: 'ラテン語 clamare（叫ぶ）から。英語の claim（主張する）・exclaim（叫ぶ）・proclaim（宣言する）と同語根。' },
  'recibir': { es: 'A nosotros nos gusta recibir a los amigos en casa.', ja: '私たちは家に友達を招くのが好きです。', trivia: 'ラテン語 recipere（受け取る）から。英語の receive（受取る）・recipe（レシピ、「受け取れ」の命令形が語源！）と同語根。' },
  'esperar': { es: 'Debo esperar a unas amigas chilenas en el aeropuerto.', ja: '空港でチリ人の友達を待たなければなりません。', trivia: 'ラテン語 sperare（希望する）から。英語 despair（絶望）は「hope（希望）を de（失う）」を意味します。同語根の対義語！' },
  'invitar': { es: '¿Por qué no las invitas a la fiesta?', ja: '彼女たちをパーティーに誘えばいいじゃない？', trivia: 'ラテン語 invitare（招く）から。英語の invite と同語根。もともと「望ましいと思わせる」というニュアンスがありました。' },
  'gustar': { es: 'A nosotros nos gusta recibir a los amigos en casa.', ja: '私たちは家に友達を招くのが好きです。', trivia: 'ラテン語 gustare（味わう）から。英語の gusto（熱意）・disgust（嫌悪、悪い味）と同語根。好きなことは「味わえるもの」という感覚が起源。' },
  'encantar': { es: 'La comida mexicana me encanta.', ja: 'メキシコ料理が大好きです。', trivia: 'ラテン語 incantare（呪文を唱える）から。英語の enchant（魅了する）・chant（詠唱）・incantation（呪文）と同語根。「魅了する」は元来「魔法をかける」こと！' },
  'fascinar': { es: 'La comida mexicana me fascina.', ja: 'メキシコ料理に夢中です。', trivia: 'ラテン語 fascinare（魔法でたぶらかす）から。英語の fascinate と同語根。ローマ人は邪眼（悪魔の目）から守るお守りを fascinumと呼んでいました。' },
  'parecer': { es: 'Me parece perfecto. ¡Me fascina!', ja: '完璧だと思う。大好き！', trivia: 'ラテン語 parescere（現れる）から。英語の appear（現れる）と遠い語根を共有。' },
  'quedar': { es: '¡Qué lugar tan bonito! ¿Dónde queda?', ja: 'なんてきれいな場所！どこにあるの？', trivia: 'ラテン語 quietare（静める・留まる）から。英語の quiet（静かな）と同語根。' },
  'visitar': { es: 'Pienso visitar varias ciudades en agosto.', ja: '8月にいくつかの都市を訪れるつもりです。', trivia: 'ラテン語 visitare（頻繁に行く）から。英語の visit と同語根。vis-（見る）という語根も含み「見に行く」が原義。' },
  'preparar': { es: 'Antonio y yo preparamos una comida mexicana en casa.', ja: 'アントニオと私は家でメキシコ料理を作ります。', trivia: 'ラテン語 praeparare（事前に準備する）から。英語の prepare と同語根。prae（前もって）+ parare（整える）の合成。' },
  'pensar': { es: 'Pienso visitar Cusco cuando allá es invierno.', ja: 'あそこが冬のときにクスコを訪れるつもりです。', trivia: 'ラテン語 pensare（重さを量る・考慮する）から。英語の pensive（物思いにふける）・pension（年金、老後の重みに備えること）と同語根。' },
  'deber': { es: 'Los lugares deben tener valor histórico o natural.', ja: '場所は歴史的あるいは自然的な価値を持っていなければなりません。', trivia: 'ラテン語 debere（義務を負う）から。英語の debt（借金）・due（支払期日）と同語根。「しなければならない」は「借りがある」感覚。' },
  'aprovechar': { es: 'Voy a aprovechar la estancia para conocer otros lugares.', ja: '滞在を利用して他の場所も見て回るつもりです。', trivia: '"provecho"（利益）から。ラテン語 profectus（進歩・利益）→ 食事の際「¡Que aproveche!」は英語の "Enjoy your meal!" に相当します。' },
  'cantar': { es: 'Luego cantamos algunas canciones y bebemos tequila.', ja: 'その後、歌を何曲か歌ってテキーラを飲みます。', trivia: 'ラテン語 cantare（歌う）から。英語の chant（詠唱）・canto（詩の章）・enchant（魅了する、歌で魔法をかける）と同語根。' },
  'beber': { es: '¿Te apetece beber algo frío?', ja: '冷たいものを飲みたい気分ですか？', trivia: 'ラテン語 bibere（飲む）から。英語の imbibe（飲み込む）・beverage（飲み物）と同語根。biblio-（本）と混同しやすいですが別語源。' },
  'acompañar': { es: 'Lo acompañamos con carne de pollo y arroz.', ja: '鶏肉とご飯と一緒に食べます。', trivia: '「compañero」（仲間）と同語根。ラテン語 com（共に）+ panis（パン）→「パンを共に分かち合う者」が仲間！ 英語の companion も全く同じ語源。' },
  'poseer': { es: 'Son lugares que poseen un gran valor histórico y cultural.', ja: 'それらは歴史的・文化的に大きな価値を持つ場所です。', trivia: 'ラテン語 possidere（所有する）から。英語の possess（所有する）と同語根。' },
  'declarar': { es: 'Machu Picchu fue declarado Patrimonio de la Humanidad.', ja: 'マチュ・ピチュは世界遺産に指定されました。', trivia: 'ラテン語 declarare（明らかにする）から。英語の declare（宣言する）と同語根。de（完全に）+ clarus（明るい・明確な）の合成。' },
  'cuidar': { es: 'Debemos cuidar estos lugares para las futuras generaciones.', ja: '将来の世代のためにこれらの場所を保護しなければなりません。', trivia: '古スペイン語 cogitar（考える）が変化。「ラテン語 cogitare（熟考する）→ cogitar → coidar → cuidar」という変化。英語の cogitate と遠い親戚。' },
  'apreciar': { es: 'Muchos viajan para conocer y apreciar su belleza.', ja: 'その美しさを知り、鑑賞するために多くの人が訪れます。', trivia: 'ラテン語 appretiare（値をつける）から。英語の appreciate（感謝する・価値を認める）と同語根。appreciate の本来の意味は「価値を正しく評価する」こと。' },
  'mirar': { es: 'Oh, mira, allí está mi amiga.', ja: 'ああ、見て、あそこに私の友達がいるよ。', trivia: 'ラテン語 mirare（不思議に思って見る）から。英語の admire（賞賛する）・miracle（奇跡）と同語根。「見る」行為の根底に「驚き」がある語根。' },
  'lugar': { es: '¡Qué lugar tan bonito! ¿Dónde queda?', ja: 'なんてきれいな場所！どこにあるの？', trivia: 'ラテン語 locus（場所）から。英語の local（地元の）・location（場所）・allocate（割り当てる）と同語根。数学用語の "locus"（軌跡）も同じ。' },
  'ciudad': { es: 'Cusco es la ciudad más turística de Perú.', ja: 'クスコはペルーで最も観光地として人気の都市です。', trivia: 'ラテン語 civitas（市民共同体）から。英語の civic（市民の）・civilization（文明）・citizen（市民）と同語根。都市は「市民が集まる場所」。' },
  'país': { es: 'Madrid es la capital del país.', ja: 'マドリードはその国の首都です。', trivia: '古フランス語 pays（地方）→ ラテン語 pagus（農村地区）から。英語の peasant（農民）・pagan（異教徒、田舎者）と同語根。' },
  'amigo': { es: 'A nosotros nos gusta recibir a los amigos en casa.', ja: '私たちは家に友達を招くのが好きです。', trivia: 'ラテン語 amicus（友人）から。英語の amicable（友好的な）・amiable（愛想の良い）と同語根。amor（愛）とも同語根。' },
  'amiga': { es: 'Debo esperar a unas amigas chilenas en el aeropuerto.', ja: '空港でチリ人の友達（女性）を待たなければなりません。', trivia: '"amigo"の女性形。ラテン語 amica（女友達）から。英語の amicable・amiable と同語根。古代ローマの格言「Amicus certus in re incerta cernitur（真の友は不確かな時にわかる）」が有名。' },
  'comida': { es: 'La comida mexicana es riquísima.', ja: 'メキシコ料理は最高においしい！', trivia: '"comer"（食べる）→ ラテン語 comedere から。スペインでは「昼食」を特に指すことが多く、スペインの昼食は最も重要な食事とされます。' },
  'fotografía': { es: 'Esta es una fotografía de Machu Picchu.', ja: 'これはマチュ・ピチュの写真です。', trivia: 'ギリシャ語 phōs（光）+ graphē（書くこと）の合成。英語の photograph と同語根。「光で書かれた絵」という詩的な意味の造語（1839年に命名）。' },
  'ruinas': { es: 'Machu Picchu son unas ruinas incaicas de Perú.', ja: 'マチュ・ピチュはペルーのインカの遺跡です。', trivia: 'ラテン語 ruina（崩壊）から。英語の ruin（廃墟）と同語根。動詞 ruere（崩れ落ちる）→ 「崩れたもの」が原義。' },
  'montaña': { es: 'Machu Picchu está en lo alto de una montaña.', ja: 'マチュ・ピチュは山の頂上にあります。', trivia: 'ラテン語 montana（山地）から。英語の mountain（山）と同語根。ラテン語 mons/montis（山）→ Montana（米国の州名）も同じ。' },
  'ciudadela': { es: 'Machu Picchu es una ciudadela en lo alto de una montaña.', ja: 'マチュ・ピチュは山の頂上にある城塞です。', trivia: '"ciudad"の指小辞形（小さな都市）。ラテン語 civitas + -ela（小さいもの）。英語の citadel（城塞）はフランス語 citadelle 経由で同語根。城塞は「小さな都市」でもあります。' },
  'estancia': { es: 'Voy a aprovechar la estancia para conocer otros lugares.', ja: '滞在を利用して他の場所も見て回るつもりです。', trivia: '"estar"（いる）→ ラテン語 stare（立つ）+ -ancia（名詞化）= 「滞在」。英語の stance（立場）・instance（例、「そこに立つもの」）と同語根。南米では広大な牧場（estancia）の意味にもなります。' },
  'historia': { es: 'Ambos tienen una historia muy interesante.', ja: 'どちらもとても興味深い歴史があります。', trivia: 'ギリシャ語 historia（探求・調査）から。ヘロドトスが「探求の記録」として使ったのが歴史叙述の始まり。英語の history・story は同語根（物語も歴史も「調査した事実」）。' },
  'valor': { es: 'Los lugares deben tener valor histórico o natural.', ja: '場所は歴史的あるいは自然的な価値を持たなければなりません。', trivia: 'ラテン語 valere（力がある・価値がある）から。英語の value（価値）・valid（有効な）・valor（勇敢さ）と同語根。' },
  'belleza': { es: 'Viajan para conocer y apreciar su belleza.', ja: 'その美しさを知り、鑑賞するために旅行します。', trivia: '"bello"（美しい）→ ラテン語 bellus（魅力的な）から。英語の belle（美女）・beau（美男）と同語根。フランス語経由で英語に入りました。' },
  'generación': { es: 'Debemos cuidarlos para las futuras generaciones.', ja: '将来の世代のために保護しなければなりません。', trivia: 'ラテン語 generare（生み出す）から。英語の generate（生成する）・gene（遺伝子）・generous（寛大な、もともと「よい血筋の」）と同語根。' },
  'capital': { es: 'Madrid es la capital de España.', ja: 'マドリードはスペインの首都です。', trivia: 'ラテン語 caput（頭）から。英語の capital（首都・大文字）・captain（隊長）・chapter（章）・chief（長）はすべて同語根。「頭（一番上）にあるもの」。' },
  'museo': { es: 'En Madrid está el Museo del Prado, un museo famoso.', ja: 'マドリードにはプラド美術館という有名な美術館があります。', trivia: 'ギリシャ語 mouseion（ムーサの神殿）から。ムーサ（Musa）は芸術・学問の女神たち（英語の Muse と同じ）。英語の museum と同語根。' },
  'estadio': { es: 'También está el estadio Santiago Bernabéu del equipo Real Madrid.', ja: 'レアル・マドリードのスタジアム、サンティアゴ・ベルナベウもあります。', trivia: 'ギリシャ語 stadion（約185mの長さの単位）から。古代ギリシャで1スタディオン（600フィート）の距離を走る競技が行われたことが語源。英語の stadium と同語根。' },
  'playa': { es: 'En Alicante hay numerosas playas y un paseo marítimo agradable.', ja: 'アリカンテには数多くのビーチと心地よい遊歩道があります。', trivia: 'おそらくゲルマン語または前ローマ時代の語から。英語の "beach" とは語源が異なります。フランス語 plage（ビーチ）と同語根。「平らに広がった砂地」というイメージ。' },
  'castillo': { es: 'En Alicante hay un castillo muy antiguo, el Castillo de Santa Bárbara.', ja: 'アリカンテにはとても古いお城、サンタ・バルバラ城があります。', trivia: 'ラテン語 castellum（城砦）から。英語の castle（城）と同語根。カスティーリャ（Castilla）地方の名前もこの語根（「城の地」）。' },
  'salsa': { es: 'El mole es una salsa un poco picante con chocolate.', ja: 'モーレはチョコレートが入った少し辛いソースです。', trivia: '"sal"（塩）→ ラテン語 salsa（塩漬けにした）から。英語の sauce（ソース）・salsa は同語根。"salary"（給料）も塩（sal）が語源。つながっています！' },
  'maíz': { es: 'La base de la alimentación de los mexicanos es el maíz.', ja: 'メキシコ人の食事の基本はトウモロコシです。', trivia: 'タイノ語（カリブ海先住民の言語）mahiz から。コロンブスがスペインに持ち帰った際にそのまま借用。英語の maize（トウモロコシ）も同じ語源。' },
  'canción': { es: 'Luego cantamos algunas canciones y bebemos tequila.', ja: 'その後、歌を何曲か歌ってテキーラを飲みます。', trivia: '"cantar"（歌う）→ ラテン語 cantio から。英語の chant（詠唱）と同語根。スペイン語では歌（song）を指し、英語の "canto"（詩の章）も同語根。' },
  'tren': { es: 'Para llegar hay que salir desde Cusco en tren.', ja: 'そこへ行くにはクスコから電車で出発しなければなりません。', trivia: 'フランス語 train（引っ張る）から。英語の train も同語根。もとは「引きずるもの・行列」の意で、鉄道が発明される前から使われていた語。' },
  'semana': { es: 'Solo voy a estar allí dos semanas.', ja: 'そこにはたった2週間しかいません。', trivia: 'ラテン語 septimana（7日間）から。septem（7）+ dies（日）→ 英語の seven・September（元々7番目の月）と同語根。カレンダーの歴史が語源に凝縮。' },
  'persona': { es: 'Una gran cantidad de personas viaja para ver estos lugares.', ja: '大勢の人々がこれらの場所を見るために旅行します。', trivia: 'エトルリア語 phersu（仮面）→ ギリシャ語 prosōpon → ラテン語 persona（劇の役・登場人物の仮面）から。英語の person・personality・personnel はすべて「仮面」が語源！' },
  'invierno': { es: 'Pienso visitar Perú en agosto, cuando allá es invierno.', ja: '8月にペルーを訪れるつもりです。あそこでは冬ですから。', trivia: 'ラテン語 hibernum（冬の）から。英語の hibernate（冬眠する）と同語根。クマが冬を「過ごす」のも、人間が「冬ごもり」するのも、同じ語根から来ています。' },
  'bueno': { es: 'Para ser un buen líder, hay que tener paciencia.', ja: '良い指導者になるためには、忍耐が必要です。', trivia: 'ラテン語 bonus（よい）から。英語の bonus（ボーナス）・bonanza（大当たり、スペイン語から）・boon（恩恵）と同語根。' },
  'antiguo': { es: 'En Alicante hay un castillo muy antiguo.', ja: 'アリカンテにはとても古いお城があります。', trivia: 'ラテン語 ante（前に）+ -iquus（接尾辞）= 「ずっと前からある」。英語の antique（アンティーク）・antiquity（古代）と同語根。' },
  'famoso': { es: 'El Museo del Prado es un museo famoso.', ja: 'プラド美術館は有名な美術館です。', trivia: 'ラテン語 fama（うわさ・評判）から。英語の fame（名声）・famous・defame（中傷する）と同語根。fama はもともと「人々が語ること」の意。' },
  'interesante': { es: 'Tienen una historia muy interesante.', ja: 'とても興味深い歴史があります。', trivia: 'ラテン語 inter esse（間にあること・重要であること）から。英語の interest（関心・利息）と同語根。「間に入ってくる」もの = 気になるもの！' },
  'turístico': { es: 'Cusco es la ciudad más turística de Perú.', ja: 'クスコはペルーで最も観光地として人気の都市です。', trivia: 'ギリシャ語 tornos（轆轤・円形の道具）→「円を描いて巡る」が語源。英語の tourist・tour と同語根。旅行は「ぐるっと回ること」が語源です。' },
  'cercano': { es: 'Voy a conocer otros lugares cercanos.', ja: '近くの他の場所も見て回ります。', trivia: '"cerca"（近く）→ ラテン語 circa（周囲に・約）から。英語の circa（約〜年）・circle（円）と同語根。「周りを取り囲む」から「近い」へ。' },
  'atractivo': { es: 'Son muy atractivos aquellos sitios declarados Patrimonio de la Humanidad.', ja: '世界遺産に登録されたそれらの場所は非常に魅力的です。', trivia: 'ラテン語 attrahere（引き寄せる）から。英語の attract（引き付ける）・tractor（引っ張る機械）と同語根。' },
  'bonito': { es: '¡Qué lugar tan bonito! ¿Dónde queda?', ja: 'なんてきれいな場所！どこにあるの？', trivia: '"bueno"（良い）の縮小形 bon-ito から。英語の bonus と同語根。カツオの一種もボニート（bonito）と呼ばれます（美しい魚）。' },
  'libre': { es: '¿Estás libre esta noche?', ja: '今夜は暇ですか？', trivia: 'ラテン語 liber（自由な）から。英語の liberty（自由）・liberal（自由主義の）・liberate（解放する）と同語根。図書館 library も「本の自由」が語源。' },
  'picante': { es: 'El mole es una salsa un poco picante.', ja: 'モーレは少し辛いソースです。', trivia: '"picar"（刺す）→ ラテン語 picare から。英語の piquant（ぴりっとした）と同語根。辛いものは「舌を刺す」感覚が語源。' },
  'impresionante': { es: 'El estadio Santiago Bernabéu es muy grande e impresionante.', ja: 'サンティアゴ・ベルナベウはとても大きくて印象的です。', trivia: 'ラテン語 imprimere（押しつける・印刷する）から。英語の impress・impression・print・express（外に押し出す）と同語根。グーテンベルクの印刷機以前は「印象」は「心に刻む」の比喩でした。' },
  'numeroso': { es: 'En Alicante hay numerosas playas.', ja: 'アリカンテには数多くのビーチがあります。', trivia: 'ラテン語 numerus（数）から。英語の number（数）・numeral（数字）・numerous と同語根。数学の "enumeration"（列挙）・"innumerable"（無数の）も同語根。' },
  'especial': { es: 'Todos estos lugares tienen algo especial.', ja: 'これらの場所はすべて何か特別なものを持っています。', trivia: 'ラテン語 specialis（特定の種類の）から。英語の special・species（種）・specimen（標本）と同語根。「特定の種に属する」が原義。' },
  'también': { es: 'También está el estadio Santiago Bernabéu en Madrid.', ja: 'マドリードにはサンティアゴ・ベルナベウスタジアムもあります。', trivia: '"tan"（そんなに）+ "bien"（良く）の組み合わせ。「同じくらい良い」→「〜も」となりました。英語の also（all + so）と発想が同じ。' },
  'solo': { es: 'Solo dos semanas, pero voy a aprovecharlas bien.', ja: 'たった2週間ですが、うまく活用するつもりです。', trivia: 'ラテン語 solus（一人の）から。英語の sole（唯一の）・solo（独奏）・solitude（孤独）と同語根。音楽用語の「ソロ」はスペイン語・イタリア語由来。' },
  'seguramente': { es: 'Seguramente a ti también te gusta el mole.', ja: 'きっとあなたもモーレが気に入るわよ。', trivia: 'ラテン語 securus（心配のない）から。英語の secure（安全な）・sure（確かな）と同語根。se（自分自身から）+ cura（心配）= 「心配から解放された」状態。' },
  'tal vez': { es: 'Tal vez a tus amigas chilenas les gustan los tacos.', ja: 'あなたのチリ人の友達もタコスが好きかもよ。', trivia: '"tal"（そのような）+ "vez"（回・機会）= 「そういう機会に」→ 「もしかしたら」。"vez" はラテン語 vicis（交替・番）から。英語の vice versa（逆に）の "vice" と同語根。' },
  'desde': { es: 'Hay que salir desde Cusco en tren para llegar.', ja: 'そこへ行くにはクスコから電車で出発しなければなりません。', trivia: '"de"（〜から）+ "es"（それ）+ "de" の重ねた形で強調した出発点表現。ラテン語 de ex de に由来。' },
  'para': { es: 'Estoy en Tokio para estudiar.', ja: '勉強するために東京にいます。', trivia: 'ラテン語 per（通じて）+ ad（〜へ）が縮まった形とされます。目的・方向・期限など多義的。英語に直訳できない複数の用法を持つ最重要前置詞の一つ。' },
  'entre': { es: 'Las Cataratas del Iguazú quedan entre Brasil, Paraguay y Argentina.', ja: 'イグアスの滝はブラジル、パラグアイ、アルゼンチンにまたがっています。', trivia: 'ラテン語 inter（間に）から。英語の inter-（国際）・international・interior と同語根。' },
  'ambos': { es: 'En ambos hay construcciones incaicas y tienen una historia interesante.', ja: 'どちらにもインカの建造物があって、興味深い歴史があります。', trivia: 'ラテン語 ambo（両方）から。英語の both と語源的には遠縁（印欧祖語レベルで同根）。' },
  'ninguno': { es: 'Ninguno es menos importante que los otros.', ja: '重要性において劣るものは一つもありません。', trivia: 'ラテン語 nec unus（一つでもない）から。ne（否定）+ unus（一つ）= 「一つもない」。英語の none・not one と概念は同じ。' },
  'algo': { es: 'Todos estos lugares tienen algo especial.', ja: 'これらの場所はすべて何か特別なものを持っています。', trivia: 'ラテン語 aliquid（何か）が縮まった形。英語 some・something に対応。「aliquot（いくらかの）」という数学用語と遠い語根を共有。' },
  'español': { es: 'Estudio español porque me parece muy interesante.', ja: 'とても面白いと思うのでスペイン語を勉強しています。', trivia: '"Hispania"（ローマ時代のイベリア半島の名前）→ "España"→ "español"。Hispania の語源には諸説あり、フェニキア語で「うさぎの地」という説が有名。英語の Hispanic も同語根。' },
  'japonés': { es: 'Soy japonés, soy de Fukuoka.', ja: '私は日本人で、福岡出身です。', trivia: 'マルコ・ポーロが元（モンゴル）の呼び名「ジパング（Cipangu）」を記録。ポルトガル人がそれを "Japão" と呼び、英語の Japan・Japanese になりました。' },
  'coreano': { es: 'No, soy coreano, de Seúl.', ja: 'いや、韓国人だよ。ソウル出身なんだ。', trivia: '高麗（ゴリョ）王朝（918〜1392年）の名前から。Korea・Korean もこれが語源。現在も「コリア」として英語圏で使われています。' },
  'chino': { es: 'Ji Sung, tú eres chino, ¿verdad? — No, soy coreano.', ja: 'ジソン、君は中国人だよね？—いや、韓国人だよ。', trivia: '秦（シン）王朝（紀元前221〜206年）→ 英語 China の語源。始皇帝が統一した最初の統一王朝名が世界中に広まりました。' },
  'mexicano': { es: 'Soy mexicana, de Morelos, México.', ja: '私はメキシコ人で、メキシコのモレロス出身です。', trivia: 'アステカ人の自称「メシカ（Mexica）」から。彼らが住んだ場所が「メキシコ」に。mexico の発音の x は「シュ」音（Méjico と綴る地域も）。' },
  'chileno': { es: 'Debo esperar a unas amigas chilenas en el aeropuerto.', ja: '空港でチリ人の友達を待たなければなりません。', trivia: 'マプチェ語（先住民族の言語）chilli から。「土地が尽きるところ」「冷たい場所」など諸説あり。ペルーのケチュア語で「雪」を意味するという説も。' },
  'a menudo': { es: 'Voy al gimnasio a menudo para mantenerme en forma.', ja: '体型を維持するためによくジムに通っています。', trivia: '"menudo"（細かい・頻繁な）から。ラテン語 minutus（小さい）→ 英語の minute（分・細かい）と同語根。「細かく刻んで」= よく・しばしば。' },
  'algún día': { es: 'Algún día viajaré a España para ver la Sagrada Familia.', ja: 'いつかサグラダ・ファミリアを見にスペインへ旅行するつもりです。', trivia: '「algún」はラテン語 aliquem（何かの）+ unus（一）から。"algún día" は希望・夢を語る際の定番表現。"Someday" に相当。' },
  'anoche': { es: 'Anoche vi una película española muy interesante.', ja: '昨夜、とても面白いスペイン映画を見ました。', trivia: '"a"（前置詞）+ "noche"（夜）の合成。"noche" はラテン語 nox/noctis（夜）→ 英語の nocturnal（夜行性の）と同語根。' },
  'antes': { es: 'Antes vivía en el campo, pero ahora vivo en la ciudad.', ja: '以前は田舎に住んでいましたが、今は都市に住んでいます。', trivia: 'ラテン語 ante（前に）から。英語の ante-（前）という接頭辞と同語根。antecedent（先行する）・anticipate（先に取る）・ancient（前からある→古い）と同語根。' },
  'ayer': { es: 'Ayer fui al mercado y compré frutas y verduras.', ja: '昨日、市場へ行って果物と野菜を買いました。', trivia: 'ラテン語 heri（昨日）から変化。英語の yesterday の "yester-" も同じ印欧祖語 *ghyes（昨日）から来ており、遠い親戚。' },
  'ayer por la tarde': { es: 'Ayer por la tarde estudié español dos horas seguidas.', ja: '昨日の午後、スペイン語を2時間続けて勉強しました。', trivia: '"tarde"（午後）はラテン語 tarde（遅く）から。英語の tardy（遅れた）と同語根。スペインでは「午後（tarde）」は日没まで続き、夜9〜10時からが「noche（夜）」になります。' },
  'cuando era joven': { es: 'Cuando era joven, soñaba con vivir en el extranjero.', ja: '若い時は海外で暮らすことを夢見ていました。', trivia: '"joven"（若い）はラテン語 juvenis から。英語の juvenile（若い・少年の）・rejuvenate（若返る）と同語根。ローマ神話の永遠の若さの女神ユウェンタス（Juventas）も同語根。' },
  'de niño': { es: 'De niño me gustaba mucho jugar al fútbol en el parque.', ja: '子供のころ、公園でサッカーをするのがとても好きでした。', trivia: '"niño"の語源はラテン語 ninnos（子供の愛称）。スペイン語の指小辞 -ito/-ita はよく使われ、niño → niñito のようにさらに愛称化もできます。El Niño（エルニーニョ）は「男の子」で、クリスマス頃に現れる海流現象として命名されました。' },
  'el año pasado': { es: 'El año pasado viajé a México y fue increíble.', ja: '去年メキシコに旅行して、素晴らしかったです。', trivia: '"pasado"は "pasar"（過ぎる）の過去分詞。ラテン語 passus（歩み・足を踏み出すこと）から。英語の past（過去）・passage と同語根。「過ぎ去った年」という時間の流れのイメージ。' },
  'el año que viene': { es: 'El año que viene pienso aprender portugués.', ja: '来年はポルトガル語を習うつもりです。', trivia: '"venir"（来る）→ ラテン語 venire から。「来る年」という表現はスペイン語の時間感覚を示します。英語では "next year"（次の年）と言いますが、スペイン語は「やって来る年」という能動的なイメージ。' },
  'el mes pasado': { es: 'El mes pasado empecé un curso de cocina española.', ja: '先月、スペイン料理の講座を始めました。', trivia: '"mes"（月）はラテン語 mensis（月）から。英語の menstrual（月経の）・semester（半期、「半月」が語源）と同語根。' },
  'el próximo mes': { es: 'El próximo mes voy a visitar a mis abuelos en el pueblo.', ja: '来月、村に住む祖父母を訪ねる予定です。', trivia: '"próximo"はラテン語 proximus（最も近い）から。英語の proximity（近さ）・approximate（近似の）と同語根。' },
  'en aquella época': { es: 'En aquella época, la gente viajaba en barco a América.', ja: 'その時代、人々は船でアメリカへ渡っていました。', trivia: '"época"はギリシャ語 epochē（停止・区切り点）から。英語の epoch（新時代）と同語根。「歴史の流れを止めて区切った期間」が epoch の原義。' },
  'en el futuro': { es: 'En el futuro quiero vivir en un país hispanohablante.', ja: '将来はスペイン語圏の国に住みたいです。', trivia: '"futuro"はラテン語 futurus（これからある）→ esse（あること）の未来分詞。英語の future と同語根。' },
  'en el pasado': { es: 'En el pasado, este barrio era muy tranquilo.', ja: '過去には、この街区はとても静かでした。', trivia: '"pasado" → "pasar"（過ぎる）の過去分詞。ラテン語 passus から。英語の past・passage と同語根。' },
  'esta mañana': { es: 'Esta mañana desayuné café con leche y tostadas.', ja: '今朝はカフェ・コン・レチェとトーストで朝食を取りました。', trivia: '"esta"（この）はラテン語 ista（そこにある）から。英語に直接対応する語はないが、"esto/esta/este"（近称）= this、"ese/esa"（中称）= that、"aquel/aquella"（遠称）= that over there と3段階あるのが英語との違い。' },
  'generalmente': { es: 'Generalmente me levanto a las siete de la mañana.', ja: '一般的に朝7時に起きます。', trivia: '"general" はラテン語 generalis（全体に関わる）から。英語の general・generate・generous（寛大な、もともと「血統の良い」）と同語根。"-mente" はラテン語 mens（心）から来た副詞語尾。' },
  'hace X años': { es: 'Hace diez años, no existían los smartphones.', ja: '10年前、スマートフォンは存在していませんでした。', trivia: '"hacer" の3人称単数現在形が時間表現に使われる独特の用法。"hace + 時間" = 「〜前」。ラテン語 facere（する・作る）から。英語の "ago" に相当しますが、スペイン語は動詞 hace（する）で時間を表すのが特徴的。' },
  'hace X días': { es: 'Hace unos días llegó una carta de España.', ja: '数日前にスペインからの手紙が届きました。', trivia: '"día"（日）はラテン語 dies（日）から。英語の diary（日記）・diurnal（昼間の）と同語根。また "carpe diem"（今日を摘め）の diem も同語根の有名なラテン語表現。' },
  'hace mucho tiempo': { es: 'Hace mucho tiempo, este castillo era la residencia del rey.', ja: 'ずっと前、このお城は王の住居でした。', trivia: '"tiempo"（時間・天気）はラテン語 tempus から。英語の temporal（一時的な）・contemporary（同時代の）・tense（動詞の時制！）と同語根。スペイン語で「時間」と「天気」が同じ語なのは興味深い。' },
  'la próxima semana': { es: 'La próxima semana tengo un examen de español.', ja: '来週スペイン語の試験があります。', trivia: '"próxima" はラテン語 proximus（最も近い）から。スペイン語では「来週」を「最も近い週」と表現する。' },
  'la semana pasada': { es: 'La semana pasada fui al teatro con mis amigos.', ja: '先週は友達と劇場に行きました。', trivia: '"semana"（週）→ ラテン語 septimana（七日間）→ septem（7）から。英語の seven・September（元々7番目の月）と同語根。' },
  'mañana': { es: 'Mañana salgo de viaje a Perú, estoy muy emocionado.', ja: '明日ペルーへ旅立ちます。とても楽しみです。', trivia: 'ラテン語 mane（朝・早く）から。"mañana"は「明日」と「朝」の両方の意味を持ちます。英語の morning（朝）は別語源ですが、「朝に来るもの」という発想は共通。' },
  'pasado mañana': { es: 'Pasado mañana tenemos clase de español por la mañana.', ja: '明後日、朝にスペイン語の授業があります。', trivia: '"pasado mañana" は「明後日」。直訳すると「過ぎ去った明日」で、明日の向こうにある日という発想。英語の "the day after tomorrow" より詩的な構造です。' },
  'pronto': { es: 'Espero que nos veamos pronto otra vez.', ja: 'またすぐに会えるといいですね。', trivia: 'ラテン語 promptus（準備ができた・素早い）から。英語の prompt（即座の）と同語根。イタリア語でも pronto（もしもし！準備OK）の意味で使われます。' },
  'siempre': { es: 'Siempre tomo café por la mañana para despertarme bien.', ja: 'いつもきちんと目を覚ますために朝コーヒーを飲みます。', trivia: 'ラテン語 semper（常に）から。「Semper Fidelis」（常に忠実に）は米海兵隊のモットー。英語で "always"（全ての道）とは発想が違い、「一度も途切れることなく」というニュアンス。' },
  'todos los días': { es: 'Todos los días camino treinta minutos para hacer ejercicio.', ja: '毎日運動のために30分歩いています。', trivia: '"todo"（全ての）はラテン語 totus（全体）から。英語の total（合計）と同語根。"todos los días" は字義通り「全ての日々」= 毎日。英語 "every day" は「それぞれの日」という発想の違いが面白い。' },
  'aceite': { es: 'El aceite de oliva es esencial en la cocina mediterránea.', ja: 'オリーブオイルは地中海料理に欠かせません。', trivia: 'アラビア語 az-zayt（オリーブ油）から。スペイン語の語彙にはアラビア語由来が約4000語あり、8世紀から約800年のイスラム支配の痕跡。英語に直接の借用語は少ないが "elixir"（アラビア語由来）が有名な例。' },
  'agua': { es: 'Quiero un vaso de agua fría, por favor.', ja: '冷たい水を一杯ください。', trivia: 'ラテン語 aqua（水）から。英語の aquarium（水族館）・aquatic（水中の）・aqueduct（水道橋）と同語根。化学記号 H₂O を "agua" と覚えると忘れにくい。' },
  'agua con gas': { es: '¿Prefieres agua con gas o agua sin gas?', ja: '炭酸水と炭酸なし、どちらが好きですか？', trivia: 'gas はラテン語 chaos（混沌・無形の物質）から。フランドルの化学者ファン・ヘルモント（1580〜1644年）が「カオス」をもじって「gas」と命名。炭酸水は18世紀のヨーロッパで「薬用水」として広まりました。' },
  'agua mineral': { es: 'Pido siempre agua mineral cuando como en un restaurante.', ja: 'レストランで食事するときはいつもミネラルウォーターを頼みます。', trivia: 'mineral はラテン語 minera（鉱山）から。英語の mine（鉱山）・mineral と同語根。鉱物が溶け込んだ水という意味が語源に直結しています。' },
  'agua sin gas': { es: 'Para mí, agua sin gas, por favor.', ja: '私には炭酸なしのお水をください。', trivia: '「sin」（〜なし）はラテン語 sine（〜なしで）から。英語の sine（サイン、数学）とは別語源。sin は英語の without に対応するスペイン語の最重要前置詞の一つ。' },
  'alimento': { es: 'El arroz es el alimento principal en Japón.', ja: '米は日本の主食です。', trivia: 'ラテン語 alere（養う）から。英語の alimentary（消化の）と同語根。alimentary canal（消化管）という表現に残ります。' },
  'almeja': { es: 'Las almejas a la marinera son un plato típico de Galicia.', ja: 'アサリのマリネーラ風はガリシアの典型的な料理です。', trivia: 'アラビア語 al-mejha から借用。スペイン語で al- で始まる語の多くはアラビア語由来（almohada：枕、alcalde：市長など）。「アル」はアラビア語の定冠詞。' },
  'almorzar': { es: 'En México, la gente suele almorzar a las dos de la tarde.', ja: 'メキシコでは人々は通常午後2時に昼食を取ります。', trivia: '"almuerzo"（昼食）から。スペインでは夜型の生活習慣から昼食が14〜16時、夕食が21〜23時という遅い食事スケジュールが一般的。' },
  'almuerzo': { es: '¿Qué vas a tomar de almuerzo hoy?', ja: '今日のお昼ご飯は何を食べる？', trivia: 'アラビア語 al-ghurza（一握りのもの、軽食）が語源という説あり。スペインでは almuerzo は午前10〜11時の軽食を指すことも。ラテンアメリカでは昼食（comida）の意味で使われます。' },
  'arroz': { es: 'En Japón comemos arroz en casi todas las comidas del día.', ja: '日本ではほぼすべての食事にお米を食べます。', trivia: 'アラビア語 al-ruzz（米）から借用。英語の rice（米）もアラビア語 → イタリア語 riso を経由して入った語で、大元は同じ。日本語の「ライス」もそのルート。' },
  'atún': { es: 'El sushi de atún es el más popular en Japón.', ja: 'マグロの寿司は日本で最も人気があります。', trivia: 'アラビア語 at-tūna（マグロ）から。英語の tuna も同語源（アラビア語 → スペイン語 atún → 英語へ）。大西洋のマグロ漁は古くからスペイン・ポルトガルが盛んでした。' },
  'azúcar': { es: '¿Cuánto azúcar le pones al café?', ja: 'コーヒーに砂糖はどのくらい入れますか？', trivia: 'アラビア語 al-sukkar（砂糖）→ スペイン語 azúcar。英語の sugar（砂糖）・sucrose（スクロース）と同語根。サトウキビはインド→アラブ→スペイン→新大陸と伝わりました。' },
  'bebida': { es: '¿Qué bebida desea tomar con la comida?', ja: 'お食事と一緒にどのお飲み物にしますか？', trivia: '"beber"（飲む）→ ラテン語 bibere から。英語の imbibe（飲む）・beverage（飲み物）と同語根。' },
  'bocadillo': { es: 'Me tomé un bocadillo de jamón y queso en el bar.', ja: 'バルでハムとチーズのバゲットサンドを食べました。', trivia: '「boca」（口）+ 指小辞 "-adillo"（小さな）= 「ちょっとした口に入れるもの」。スペインでは昼食の前の軽食として定番。英語の "bite to eat"（ちょっと食べること）と発想が同じ。' },
  'café': { es: 'Tomamos un café después de comer para terminar bien la comida.', ja: '食事をうまく締めくくるために食後にコーヒーを飲みます。', trivia: 'アラビア語 qahwa（コーヒー豆のワイン・元気になる飲み物）→ トルコ語 kahve → フランス語 café → 英語の coffee。全部同語根！エチオピアのカッファ地方説もあります。' },
  'café con leche': { es: 'Por las mañanas tomo café con leche con unas tostadas.', ja: '朝はカフェ・コン・レチェとトーストを食べます。', trivia: '"leche"（ミルク）はラテン語 lac/lactis（乳）から。英語の lactose（乳糖）・lactate・galaxy（天の川、「ミルクの道」！）と同語根。スペインの朝食の定番で、大きめのカップで出されます。' },
  'café solo (negro)': { es: 'Prefiero el café solo porque no me gusta el sabor de la leche.', ja: 'ミルクの味が好きじゃないのでブラックコーヒーが好きです。', trivia: '"solo" はラテン語 solus（一人の・単独の）から。イタリアン・バーのエスプレッソ文化がスペインにも広まり、スペインの café solo はエスプレッソよりやや量が多め。' },
  'carne': { es: 'En Argentina la carne asada es muy famosa en todo el mundo.', ja: 'アルゼンチンのアサードは世界中でとても有名です。', trivia: 'ラテン語 caro/carnis（肉・生身の体）から。英語の carnivore（肉食動物）・carnival（謝肉祭）・carnal（肉欲の）・incarnate（肉体を持つ）と同語根。' },
  'cena': { es: 'La cena en España suele ser tarde, a las nueve o diez de la noche.', ja: 'スペインでの夕食は遅く、夜9時か10時が一般的です。', trivia: 'ラテン語 cena（主な食事）から。古代ローマでは cena が夕方の主食で、現代スペインの遅い夕食文化はそのまま継続していると言えます。' },
  'cenar': { es: '¿A qué hora sueles cenar en tu casa?', ja: 'ご自宅では普段何時に夕食を取りますか？', trivia: 'ラテン語 cena（主要な食事）から。古代ローマでは夕方の cena が一日のメイン食事でした。スペインの夕食は21〜23時と非常に遅く、ヨーロッパで最も遅い国の一つ。' },
  'cerdo': { es: 'El jamón ibérico se elabora con carne de cerdo de pura raza.', ja: 'イベリコハムは純血種の豚肉で作られます。', trivia: 'ラテン語 porcus（豚）→ cerdo の語源については諸説あり。英語の pork（豚肉）・porcupine（ヤマアラシ）はラテン語の porcus から。' },
  'cerveza': { es: 'Me apetece una cerveza fría después de un día de trabajo.', ja: '仕事の一日の後に冷たいビールが飲みたいです。', trivia: 'ラテン語 Cerevisiae（ケレス女神の飲み物）から。Ceres はローマの穀物の女神で、英語の cereal（シリアル）と同語根！ビールは「穀物の女神の飲み物」という意味。' },
  'chocolate': { es: 'El chocolate caliente es perfecto para las mañanas de invierno.', ja: 'ホットチョコレートは冬の朝にぴったりです。', trivia: 'ナワトル語（アステカ語）xocolatl = xococ（苦い）+ atl（水）から。「苦い水」が語源。アステカではカカオは貨幣としても使われていました。スペイン人が砂糖を加えて甘くしました。' },
  'desayunar': { es: '¿A qué hora sueles desayunar normalmente?', ja: '普段何時に朝食を取りますか？', trivia: '"des-"（否定）+ "ayunar"（断食する）= 「断食を終える」が語源。英語の breakfast も "break"（破る）+ "fast"（断食）で全く同じ発想。どの言語でも朝食は「一晩の断食を破ること」！' },
  'desayuno': { es: 'Un desayuno típico español es café con leche y tostada con aceite.', ja: 'スペインの典型的な朝食はカフェ・コン・レチェとオイルトーストです。', trivia: '"des-" + "ayuno"（断食）。英語の breakfast と全く同じ概念構造。ayuno の語源はラテン語 jejunum（空の・断食の）→ 医学用語 jejunum（空腸）と同語根。' },
  'fruta': { es: 'Como fruta fresca todos los días para mantenerme sano.', ja: '健康を保つために毎日新鮮な果物を食べます。', trivia: 'ラテン語 fructus（果実・享楽）から。英語の fruit（果物）・fruition（成就）と同語根。「努力の実り」は fruit of labor と表現するのも同じ発想。' },
  'gamba (camarón)': { es: 'Las gambas a la plancha son mi plato favorito del restaurante.', ja: '鉄板焼きのエビがレストランで一番好きな料理です。', trivia: '"gamba" はイタリア語 gamba（脚）から。エビの「脚（ひげ足）」が目立つことから命名。英語の gambit（チェスの初手）・gamble も "gamba"（脚の動き）に由来という説あり。' },
  'hamburguesa': { es: 'A los niños les encantan las hamburguesas con patatas fritas.', ja: '子供たちはフライドポテト付きハンバーガーが大好きです。', trivia: 'ドイツのハンブルク市から。19世紀のドイツ移民がアメリカに「ハンブルク風ステーキ」を持ち込んだのが起源。同様に frankfurter（ソーセージ）もドイツのフランクフルト市が語源。' },
  'hielo': { es: '¿Quieres el refresco con hielo o sin hielo?', ja: '飲み物は氷あり、なしどちらにしますか？', trivia: 'ラテン語 gelu（霜・氷）から。英語の gel（ゼリー状のもの）・gelatin（ゼラチン）・gelid（氷のように冷たい）と同語根。' },
  'huevo': { es: 'Los huevos fritos con jamón son un desayuno muy rico.', ja: 'ハム添えの目玉焼きはとても美味しい朝食です。', trivia: 'ラテン語 ovum（卵）から。英語の oval（楕円形）・ovary（卵巣）・ovum（生物学用語）と同語根。' },
  'jamón': { es: 'El jamón ibérico es una de las especialidades gastronómicas de España.', ja: 'イベリコハムはスペインの美食の特産品の一つです。', trivia: '古フランス語 jambe（脚）から。英語の gammon（塩漬け豚もも肉）と同語根。豚の後ろ脚を使うことから「脚の肉」が語源。' },
  'lechuga': { es: 'La ensalada lleva lechuga, tomate y un poco de aceite.', ja: 'サラダにはレタス、トマト、少量のオリーブオイルが入っています。', trivia: 'ラテン語 lactuca（レタス）から。lac（乳）→ レタスを切ると白い液（乳状の樹液）が出ることから命名。英語の lactose（乳糖）・lactate（乳酸）と同語根。' },
  'mantequilla': { es: 'Me gusta desayunar pan con mantequilla y mermelada.', ja: '朝食にバターとジャムを塗ったパンが好きです。', trivia: '「manteca」（ラード・脂）の指小辞形（manteca + -illa）。ラテン語 mantica（袋）が語源とも言われます。昔はバターを布袋に入れて保存していたことから。' },
  'manzana': { es: 'Una manzana al día mantiene al médico alejado.', ja: '一日一個のリンゴで医者知らず。', trivia: 'ラテン語 Malum Matianum（マティウスのリンゴ）→ ローマの美食家カイウス・マティウスが改良した品種。さらに興味深いのは、ラテンアメリカでは "manzana" は「街区（ブロック）」の意味にもなること！' },
  'marisco': { es: 'En Galicia el marisco es muy fresco y tiene fama internacional.', ja: 'ガリシアでは海産物がとても新鮮で国際的に有名です。', trivia: '"mar"（海）+ "-isco"（形容詞化）= 「海のもの」。ラテン語 mariscus から。英語の marine（海の）・maritime と同語根。' },
  'mayonesa': { es: 'Pon un poco de mayonesa en el bocadillo para que esté más jugoso.', ja: 'バゲットサンドをジューシーにするためにマヨネーズを少し塗って。', trivia: '1756年メノルカ島のマオン（Mahón）でフランス軍がこのソースを「発見」したという説が有名（諸説あり）。英語 mayonnaise も同語源。' },
  'naranja': { es: 'Valencia es famosa por producir las mejores naranjas de España.', ja: 'バレンシアはスペイン最高のオレンジを生産することで有名です。', trivia: 'サンスクリット語 nāranga → ペルシャ語 nārang → アラビア語 nāranj → スペイン語 naranja。英語の orange は最初の n が脱落した形（「ア ナランジ」→「アン オレンジ」）。' },
  'pan': { es: 'En España se come mucho pan en todas las comidas del día.', ja: 'スペインでは毎食パンをたくさん食べます。', trivia: 'ラテン語 panis（パン）から。英語の pantry（食料庫、パンを保管する部屋）と同語根。イタリア語 pane・フランス語 pain も同語根。"companion"（共にパンを食べる者）にも含まれます。' },
  'pasta': { es: 'La pasta italiana es uno de los platos más populares del mundo.', ja: 'イタリアのパスタは世界で最も人気のある料理の一つです。', trivia: 'ギリシャ語 pastē（大麦粥）→ ラテン語 pasta（練り粉）から。英語の paste（ペースト）・pastry（ペストリー）と同語根。パスタ = 「練り合わせた生地」が原義。' },
  'patata (papa)': { es: 'La tortilla española se hace con patatas, huevos y cebolla.', ja: 'スペインのトルティーヤはジャガイモ、卵、玉ねぎで作ります。', trivia: '"patata" はタイノ語 batata（サツマイモ）から。スペインではジャガイモを "patata"、ラテンアメリカでは "papa" と呼ぶことが多い。英語 potato も同語源。chip（英：フライドポテト）が英米で意味が違うように、地域差が面白い食材。' },
  'pescado': { es: 'El pescado fresco del mercado siempre está más rico que el congelado.', ja: '市場の新鮮な魚はいつも冷凍より美味しいです。', trivia: '"pescar"（魚を獲る）→ ラテン語 piscari から。英語の Pisces（魚座）・piscatorial（釣りに関する）と同語根。ちなみにスペイン語では「生きている魚」を pez、「食べるための魚」を pescado と区別します！' },
  'pimienta': { es: 'Añade sal y pimienta al gusto para dar sabor a la carne.', ja: '肉に風味を出すために塩と胡椒をお好みで加えてください。', trivia: 'ラテン語 pigmentum（染料・色素）から。英語の pigment（顔料）・pimento（ピメント）と同語根。胡椒は料理の「色・風味を加えるもの」として命名されました。' },
  'plátano': { es: 'Los plátanos de Canarias son muy dulces y sabrosos.', ja: 'カナリア諸島のバナナはとても甘くて美味しいです。', trivia: 'プラタナス（platanus、スズカケノキ）と混同されて命名。バナナの葉がプラタナスの葉に似ているため。「バナナ」（banana）はギニア語由来で別語源。カナリア諸島産のプラタノが有名。' },
  'pollo': { es: 'Hice pollo asado con ajo y limón para la cena del domingo.', ja: '日曜日の夕食にニンニクとレモンのローストチキンを作りました。', trivia: 'ラテン語 pullus（雛）から。英語の poultry（家禽）と遠い語根を共有。「プロ野球球団のポロ」などに音の類似があります。' },
  'pulpo': { es: 'El pulpo a la gallega es uno de los platos más típicos de Galicia.', ja: 'ガリシア風タコはガリシアで最も典型的な料理の一つです。', trivia: 'ラテン語 polypus → ギリシャ語 polypous（多くの足）から。英語の octopus（8本の足）と発想が同じ（poly = 多い）。医学用語の polyp（ポリープ）も同語根。' },
  'queso': { es: 'En España hay muchas variedades de queso muy diferentes entre sí.', ja: 'スペインにはとても多様なチーズの種類があります。', trivia: 'ラテン語 caseus（チーズ）から。英語の cheese はゲルマン語経由で caseus に由来。スペイン語の queso は直接ラテン語から。化学の casein（カゼイン、乳タンパク質）も同語根。' },
  'sal': { es: 'No le eches demasiada sal a la comida, que no es bueno para la salud.', ja: '健康に良くないので料理に塩を入れすぎないようにしましょう。', trivia: 'ラテン語 sal（塩）から。英語の salary（給料）の語源！ローマ兵士への給料の一部は塩（sal）で支払われたことから。また salad（サラダ）も「塩をかけた野菜」が語源。' },
  'salmón': { es: 'El salmón noruego es muy conocido y apreciado en los restaurantes japoneses.', ja: 'ノルウェー産サーモンは日本のレストランでよく知られ高く評価されています。', trivia: 'ラテン語 salmo（サケ）から。語源には salire（跳ぶ）説があり、サケが川を遡上する際に「跳ぶ」姿から命名という説。英語の salmon も同語根。' },
  'sandwich': { es: 'Me preparé un sándwich de queso y tomate para el almuerzo.', ja: '昼食にチーズとトマトのサンドイッチを作りました。', trivia: 'イギリスの第4代サンドウィッチ伯爵（1718〜1792年）の名前から。カード遊び中に食事を取る時間を惜しんで、パンに肉を挟んで食べたのが起源という説が有名。英語からスペイン語にそのまま入った語です。' },
  'sardina': { es: 'Las sardinas a la plancha son muy típicas del verano en España.', ja: '鉄板焼きイワシはスペインの夏の定番料理です。', trivia: 'サルデーニャ島（Sardinia）が語源。この島の近海でイワシが大量に獲れたことから命名。缶詰で「ぎゅうぎゅう詰め」を英語で "packed like sardines" と言うほど密集する魚。' },
  'té': { es: '¿Te apetece una taza de té verde japonés?', ja: '日本の緑茶を一杯いかがですか？', trivia: '中国語（閩南語）te → オランダ語 thee → ヨーロッパ各国語へ。英語の tea・フランス語 thé と同語根。一方、チャイ（chai）はペルシャ・トルコ・アラブ経由の cha（茶）から来た別ルート。' },
  'ternera (res)': { es: 'El filete de ternera estaba muy tierno y jugoso.', ja: '牛のヒレ肉はとても柔らかくジューシーでした。', trivia: '"ternera" はラテン語 tener（柔らかい・若い）から。英語の tender（柔らかい）と同語根。英語の veal（子牛肉）はフランス語経由のラテン語 vitellus（子牛）から全く別ルート。' },
  'tomate': { es: 'El gazpacho es una sopa fría de tomate muy refrescante en verano.', ja: 'ガスパチョは夏にとても爽やかなトマトの冷製スープです。', trivia: 'ナワトル語（アステカ語）tomatl から直接借用。スペイン人が16世紀にメキシコから持ち帰りました。ヨーロッパでは最初「有毒植物」と思われていたため、食べるまでに時間がかかりました。' },
  'verdura': { es: 'Los médicos recomiendan comer más verdura cada día para estar sanos.', ja: '医師は健康のために毎日もっと野菜を食べるよう勧めています。', trivia: 'ラテン語 viridis（緑の）から。英語の verdant（緑豊かな）・verdigris（緑青色）と同語根。"verde" = 緑色 = 野菜（緑のもの）という発想。' },
  'vinagre': { es: 'La ensalada lleva aceite de oliva, vinagre y un poco de sal.', ja: 'サラダにはオリーブオイル、酢、少量の塩が入っています。', trivia: '"vino"（ワイン）+ "agre"（古語で「酸っぱい」、ラテン語 acer/acris）の合成 = 「酸っぱいワイン」。英語の vinegar も全く同じ構造（vine + aigre）。フランス語経由で英語に入った。' },
  'vino': { es: 'En España el vino de La Rioja es famoso en todo el mundo.', ja: 'スペインではリオハのワインが世界中で有名です。', trivia: 'ラテン語 vinum から。英語の wine（ワイン）・vine（ブドウの木）・vineyard（ブドウ畑）・vintage（収穫年）・vinegar（酢）はすべて同語根！' },
  'yogur': { es: 'Como yogur con frutas frescas en el desayuno todos los días.', ja: '毎日朝食に新鮮な果物入りのヨーグルトを食べます。', trivia: 'トルコ語 yoğurt（凝乳）から直接借用。英語の yogurt・yoghurt も同語源。テュルク語族に由来し、遊牧民が羊の皮袋で乳を発酵させた保存食が起源。' },
  'zanahoria': { es: 'Las zanahorias contienen mucha vitamina A y son muy saludables.', ja: 'ニンジンにはビタミンAがたくさん含まれていてとても健康的です。', trivia: 'アラビア語 isfanāriyya から変化したとされます。スペインへはアラブ人が持ち込みました。英語の carrot（ニンジン）はギリシャ語 karōton から別ルートで来た語。' },
  'zumo (jugo)': { es: 'Tomo un zumo de naranja fresco cada mañana para empezar bien el día.', ja: '一日を元気に始めるために毎朝新鮮なオレンジジュースを飲みます。', trivia: '"zumo" はスペイン固有語。ラテンアメリカでよく使われる "jugo" はラテン語 succus（汁・果汁）から、英語の juice と同語根。同じ「ジュース」を地域によって別語で呼ぶ典型例。' },
  'acostarse': { es: 'Me acuesto a las once de la noche todos los días para descansar bien.', ja: 'よく休むために毎日夜11時に寝ます。', trivia: '"costa"（肋骨・横腹）→「体を横にする」が原義。ラテン語 costa から。英語の coast（沿岸、陸地の「横」）・accost（話しかける、横に来る）と同語根。' },
  'afeitarse': { es: 'Mi padre se afeita todas las mañanas antes de ir al trabajo.', ja: '父は毎朝仕事に行く前にひげをそります。', trivia: '古スペイン語では「美しく飾る・整える」の意。現在は「ひげをそる」に特化。ラテン語 affectare（整える）から。' },
  'bañarse': { es: 'En Japón la gente se baña por la noche antes de dormir.', ja: '日本では人々は寝る前の夜に入浴します。', trivia: 'ラテン語 balineum（浴場）から。英語の bath・bathe と同語根。古代ローマの public baths（公衆浴場）= バリネウム。' },
  'cepillarse los dientes': { es: 'Hay que cepillarse los dientes después de cada comida.', ja: '毎食後に歯を磨かなければなりません。', trivia: '"diente"（歯）はラテン語 dens/dentis（歯）から。英語の dental（歯の）・dentist（歯医者）・trident（三つ叉、三本歯の槍）と同語根。' },
  'despertarse': { es: 'Me despierto a las seis y media todos los días para ir a trabajar.', ja: '仕事に行くために毎日6時半に目が覚めます。', trivia: '「despertar」= des（否定）+ pertar。ラテン語 expertus（熟練した・起きている）から変化。英語の expert（専門家）と同語根！「眠りから目覚める = 熟練者のように覚醒する」。' },
  'ducharse': { es: 'Prefiero ducharme por la mañana para empezar el día bien fresco.', ja: '一日を清々しく始めるために朝シャワーを浴びる方が好きです。', trivia: 'フランス語 douche → イタリア語 doccia → ラテン語 ductio（水を引く）から。英語の duct（管）と同語根。シャワーは「管を通して引いた水」。' },
  'lavarse la cara': { es: 'Lo primero que hago al levantarme es lavarme la cara con agua fría.', ja: '起きてまず最初にすることは冷たい水で顔を洗うことです。', trivia: '"cara"（顔）はラテン語 cara（顔・頬）から。英語の caress（愛撫する、顔に触れる）と同語根。カラ（cara）はイタリア語でも「顔」の意味で、オペラでよく使われます。' },
  'levantarse': { es: 'Los fines de semana me levanto más tarde que entre semana.', ja: '週末は平日より遅く起きます。', trivia: 'ラテン語 levare（持ち上げる）から。英語の lever（てこ）・levitate（空中浮揚）・elevator（エレベーター）・levy（徴税、持ち上げてとる）と同語根。' },
  'maquillarse': { es: 'Ella se maquilla todos los días antes de salir de casa.', ja: '彼女は毎日外出前に化粧します。', trivia: 'フランス語 maquiller（化粧する）から。英語の make-up はフランス語 maquillage の翻訳借用（直訳）。同じ概念を言語ごとに違う語根で表現しています。' },
  'peinarse': { es: 'Después de ducharse, se peina frente al espejo del baño.', ja: 'シャワーを浴びた後、浴室の鏡の前で髪をとかします。', trivia: 'ラテン語 pecten（くし）から。英語の pectinate（くし状の）・pectin（ペクチン、植物の繊維質でくし状構造）と同語根。' },
  'vestirse': { es: 'Los niños ya saben vestirse solos sin ayuda de los padres.', ja: '子供たちはもう親の助けなしで自分で着替えられます。', trivia: 'ラテン語 vestire（服を着せる）から。英語の vest（ベスト）・invest（投資する、もともと「装備を与える」）・divest（剥ぎ取る）・travesty（滑稽な模倣、変装）と同語根！' },
  'autopista': { es: 'La autopista entre Madrid y Barcelona es muy moderna y rápida.', ja: 'マドリードとバルセロナ間の高速道路はとても近代的で速いです。', trivia: '"auto"（自動車）+ "pista"（走路・跑道）の合成。英語の freeway・highway に相当するスペイン語の造語。pista はイタリア語 pista（踏みならされた道）から。' },
  'avenida': { es: 'La Gran Vía es la avenida más famosa y concurrida de Madrid.', ja: 'グランビアはマドリードで最も有名で賑やかな大通りです。', trivia: '"avenir"（〜へやって来る）→「街路に向かって来る」から。英語の avenue はフランス語 avenue（近づくこと）から直接借用。同語根。' },
  'barrio': { es: 'El barrio Gótico de Barcelona es muy pintoresco y lleno de historia.', ja: 'バルセロナのゴシック地区はとても趣があって歴史に満ちています。', trivia: 'アラビア語 barri（外側・郊外）から。スペインのイスラム支配期（711〜1492年）に入った語で、もともとは「城壁の外の地区」を指していました。' },
  'bosque': { es: 'En el bosque hay muchos animales salvajes y plantas interesantes.', ja: '森の中には多くの野生動物と興味深い植物がいます。', trivia: 'ゲルマン語 busk（木立・茂み）から。英語の bush（茂み）・bouquet（花束、もともと「木立ち」！）と同語根。「ブーケ」の語源が「森の茂み」とは意外。' },
  'calle': { es: '¿Cuál es la calle más concurrida de tu ciudad?', ja: 'あなたの街で一番賑やかな通りはどこですか？', trivia: 'ラテン語 callis（細道・踏み分け道）から。古代ローマの都市街路が整備されていく過程で一般化した語。' },
  'camino': { es: 'El Camino de Santiago es un camino de peregrinación muy famoso en el mundo.', ja: 'サンティアゴ巡礼路は世界中でとても有名な巡礼の道です。', trivia: 'おそらくケルト語またはラテン語以前の言語から。英語の come（来る）や go と発想が近い「通る道」の意。「El Camino de Santiago（サンティアゴ巡礼路）」として世界的に有名。' },
  'campo': { es: 'Me encanta el silencio del campo por la mañana temprano.', ja: '早朝の田園の静けさが大好きです。', trivia: 'ラテン語 campus（平らな野原）から。英語の campus（大学のキャンパス）・camp（野営地）・campaign（野戦・選挙運動、野原での戦いが原義）と同語根！' },
  'carretera': { es: 'Esta carretera lleva directamente al aeropuerto internacional.', ja: 'この幹線道路は国際空港に直接つながっています。', trivia: '"carro"（荷車）から。ラテン語 carrus（ガリア人の車）→ 英語の car（自動車）・cargo（積み荷）・carry（運ぶ）・charge（積み込む）と同語根。' },
  'centro': { es: 'El museo más famoso de la ciudad está en el centro histórico.', ja: '市の最も有名な美術館は歴史的中心部にあります。', trivia: 'ギリシャ語 kentron（とがった先端・コンパスの中心点）から。英語の center・central・eccentric（中心から外れた）と同語根。' },
  'continente': { es: 'América del Sur es un continente muy diverso en cultura y naturaleza.', ja: '南アメリカは文化と自然においてとても多様な大陸です。', trivia: 'ラテン語 continere（つなぎとめる）から。英語の contain（含む）・content（内容・満足）・continent（大陸、また「節制のある」）と同語根。大陸は「繋がった土地」。' },
  'cordillera': { es: 'Los Andes son la cordillera más larga del mundo, en América del Sur.', ja: 'アンデス山脈は南アメリカにある世界で最も長い山脈です。', trivia: '「cuerda」（ロープ・弦）の派生語。ラテン語 chorda（弦）→ 英語の cord（コード）・chord（和音）と同語根。山々がロープのように連なるイメージから命名。' },
  'costa': { es: 'La Costa del Sol tiene playas preciosas y mucho sol durante todo el año.', ja: 'コスタ・デル・ソルには美しいビーチと一年中たっぷりの太陽があります。', trivia: 'ラテン語 costa（肋骨・横腹・側面）から。英語の coast（沿岸）・accost（横に近づいて話しかける）と同語根。海岸は陸地の「横腹」。' },
  'desierto': { es: 'El desierto de Atacama es el más árido del mundo.', ja: 'アタカマ砂漠は世界で最も乾燥した砂漠です。', trivia: 'ラテン語 desertum（捨てられた・放棄された場所）から。英語の desert（砂漠、捨てる）・desertion（脱走）と同語根。「人が捨てた場所」が砂漠の原義。' },
  'espacio': { es: 'Los astronautas viven varios meses en el espacio sin gravedad.', ja: '宇宙飛行士は無重力の宇宙で数ヶ月間生活します。', trivia: 'ラテン語 spatium（距離・広がり）から。英語の space（宇宙・空間）・spatial（空間の）と同語根。' },
  'frontera': { es: 'Para cruzar la frontera entre países necesitas el pasaporte.', ja: '国境を越えるには国々のパスポートが必要です。', trivia: '"frente"（額・正面）→ ラテン語 frons/frontis（額・前面）から。英語の front（前面）・frontier（辺境）・affront（正面から向かう→侮辱）と同語根。' },
  'isla': { es: 'Las Islas Canarias son un archipiélago español muy turístico y cálido.', ja: 'カナリア諸島はとても観光地として人気の温暖なスペイン領諸島です。', trivia: 'ラテン語 insula（島）から。英語の insulate（絶縁する、島のように孤立させる）・insulin（インスリン、膵臓の「ランゲルハンス島」から）・peninsula（ほぼ島）と同語根。' },
  'la Tierra': { es: 'La Tierra tiene aproximadamente cuatro mil quinientos millones de años.', ja: '地球はおよそ45億年前にできました。', trivia: 'ラテン語 terra（大地・土）から。英語の terrain（地形）・territory（領土）・terrestrial（地球の）・Mediterranean（中間の大地 = 地中海！）と同語根。' },
  'mar': { es: 'El Mar Mediterráneo es muy tranquilo y cálido durante el verano.', ja: '地中海は夏の間とても穏やかで温かいです。', trivia: 'ラテン語 mare（海）から。英語の marine（海の）・maritime（海事の）・submarine（潜水艦）・mermaid（「海の乙女」が語源！）と同語根。' },
  'mundo': { es: 'El español es el segundo idioma más hablado del mundo.', ja: 'スペイン語は世界で2番目に話者が多い言語です。', trivia: 'ラテン語 mundus（清潔・秩序ある宇宙）から。英語の mundane（世俗的な・平凡な、「この世のこと」）と同語根。「世界は整然としたもの」という古代ローマ人の世界観が語源。' },
  'municipio': { es: 'Cada municipio de España tiene su propio ayuntamiento y alcalde.', ja: 'スペインの各市町村には独自の市役所と市長がいます。', trivia: 'ラテン語 munus（義務・公的職務）+ capere（引き受ける）= 「公的義務を引き受ける人々の集まり」。英語の municipal・municipality と同語根。' },
  'océano': { es: 'El Océano Pacífico es el más grande y profundo del mundo.', ja: '太平洋は世界最大かつ最も深い大洋です。', trivia: 'ギリシャ語 Okeanos（地球を取り囲む大河の神）から。古代ギリシャ人は地球が平らで、その周囲を大河が流れると考えていました。英語の ocean と同語根。' },
  'paseo': { es: 'En las tardes de verano la gente sale a dar un paseo por el parque.', ja: '夏の午後、人々は公園を散歩に出かけます。', trivia: '"paso"（歩み）→ ラテン語 passus（足を踏み出すこと）から。英語の passage（通路）・pass（通過）・surpass（超える）・compass（羅針盤、歩き回る）と同語根。' },
  'península': { es: 'España y Portugal están ubicados en la Península Ibérica.', ja: 'スペインとポルトガルはイベリア半島に位置しています。', trivia: 'ラテン語 paene（ほとんど）+ insula（島）= 「ほとんど島」の合成語。英語の peninsula も同語根。見事に地形を表した造語！' },
  'plaza': { es: 'La Plaza Mayor de Madrid es un lugar emblemático lleno de historia.', ja: 'マドリードのマヨール広場は歴史に満ちた象徴的な場所です。', trivia: 'ラテン語 platea（広い通り）から。英語の place（場所）・plaza・piazza（イタリア語）はすべて同語根。英語の "flat"（平らな）とも遠い語根を共有。' },
  'provincia': { es: 'España está dividida en cincuenta provincias y diecisiete comunidades autónomas.', ja: 'スペインは50の県と17の自治州に分かれています。', trivia: 'ラテン語 provincia（ローマに征服・管理された地域）から。英語の province（地方）・provincial（地方的な）と同語根。' },
  'pueblo': { es: 'Este pueblo medieval es muy pintoresco y tranquilo, sin turistas.', ja: 'この中世の村は観光客もなくとても趣があって静かです。', trivia: 'ラテン語 populus（人民・民衆）から。英語の people（人々）・popular（人気のある）・population（人口）・public（公の）と同語根。面白いことに "pueblo" は「村」と「民衆」の両方を意味します。' },
  'región': { es: 'La región de Cataluña tiene su propia lengua y cultura muy diferente.', ja: 'カタルーニャ地方には独自の言語と非常に異なる文化があります。', trivia: 'ラテン語 regio（方向・地域）から。英語の region（地域）・reign（支配する、同語根！）と同語根。「支配が及ぶ範囲」が region の原義。' },
  'río': { es: 'El río Amazonas es el más caudaloso y largo del mundo.', ja: 'アマゾン川は世界で最も水量が多く長い川です。', trivia: 'ラテン語 rivus（小川）から。英語の rival（ライバル）の語源！同じ川（rivus）の水を使う者同士が競い合うことから「競争相手」の意味に。また arrive（到着する）も「川岸に至る」が原義。' },
  'sierra': { es: 'La Sierra Nevada tiene picos nevados casi todo el año.', ja: 'シエラ・ネバダはほぼ一年中雪をかぶった山頂があります。', trivia: 'ラテン語 serra（のこぎり）から。英語の serrated（鋸歯状の）と同語根。山の稜線がのこぎりの歯のようにギザギザしていることから命名。' },
  'universo': { es: 'El universo tiene aproximadamente trece mil ochocientos millones de años de antigüedad.', ja: '宇宙は約138億年の歴史があります。', trivia: 'ラテン語 universus = uni（一つの）+ versus（回された）= 「一つに向けられた」。英語の universe・university（知識を一つにする場所！）と同語根。' },
  'abierto': { es: 'La tienda está abierta hasta las nueve de la noche.', ja: 'お店は夜9時まで営業しています。', trivia: '"abrir"（開ける）→ ラテン語 aperire から。英語の aperture（開口部）と同語根。また April（4月）の語源も「開く月（春が開く）」説があります。' },
  'animado': { es: 'El centro de la ciudad estaba muy animado el sábado por la noche.', ja: '土曜の夜、市内中心部はとても活気がありました。', trivia: 'ラテン語 anima（息・魂）から。英語の animate（生き生きとさせる）・animal（動物）・anime（アニメ）はすべて同語根！「命の息吹」が原義。' },
  'cerrado': { es: 'La farmacia está cerrada los domingos y los festivos.', ja: '薬局は日曜日と祝日は閉まっています。', trivia: '"cerrar"（閉める）→ ラテン語 serare（かんぬきをかける）から。sara（かんぬき）が語根。' },
  'comercial': { es: 'Esta zona es muy comercial, con muchas tiendas y restaurantes de todo tipo.', ja: 'このエリアは商業的で、様々な種類の店やレストランがたくさんあります。', trivia: 'ラテン語 commercium = com（共に）+ merx（商品）= 「共に商品をやり取りする」。英語の commerce（商業）・merchant（商人）・market（市場）と同語根。' },
  'cosmopolita': { es: 'Nueva York es una ciudad muy cosmopolita, con gente de todo el mundo.', ja: 'ニューヨークは世界中から人が集まるとても国際的な都市です。', trivia: 'ギリシャ語 kosmos（秩序ある宇宙）+ polites（市民）= 「宇宙の市民」。英語の cosmopolitan と同語根。cosmetics（化粧品）も kosmos（顔に秩序を）から！' },
  'cultural': { es: 'Quiero vivir una experiencia cultural auténtica en España.', ja: 'スペインで本物の文化的な体験がしたいです。', trivia: 'ラテン語 cultura（耕すこと）→ colere（耕す）から。英語の culture・agriculture（農業：土地を耕す）・horticulture（園芸）と同語根。知識も「耕す」もの。' },
  'de moda': { es: 'Los vaqueros azules siguen estando muy de moda este año.', ja: '青いジーンズは今年もとても流行しています。', trivia: '"moda"はラテン語 modus（様式・方法・程度）から。英語の mode（流行）・modern・modest（節度ある）・model（模範）と同語根。「流行」は「そのやり方（mode）で」という発想。' },
  'decaído': { es: 'La industria textil de esa región está bastante decaída desde los años noventa.', ja: 'その地方の繊維産業は90年代からかなり衰退しています。', trivia: '"decaer"（衰える）→ ラテン語 de（下に）+ cadere（落ちる）から。英語の decay（腐敗）・cadence（韻律）・accident（不慮の出来事、突然落ちる）・occasion（機会）と同語根。' },
  'global': { es: 'El cambio climático es uno de los problemas globales más urgentes.', ja: '気候変動は最も緊急性の高いグローバルな問題の一つです。', trivia: 'ラテン語 globus（球体）から。英語の globe（地球儀）・global と同語根。地球が「丸い」と認識されてから使われるようになった語。' },
  'histórico': { es: 'Granada es una ciudad histórica con monumentos árabes y cristianos.', ja: 'グラナダはアラブとキリスト教の史跡がある歴史ある都市です。', trivia: 'ギリシャ語 historikos（博識の）→ historia（探求・調査）から。ヘロドトスが「Historíai（調査の記録）」と名付けた著作が歴史学の出発点。英語の historic と同語根。' },
  'industrial': { es: 'Bilbao era una ciudad muy industrial en el siglo veinte.', ja: 'ビルバオは20世紀にとても工業的な都市でした。', trivia: 'ラテン語 industria（精励・勤勉）から。英語の industry（産業・勤勉さ）・industrious（勤勉な）と同語根。「コツコツ作るもの」が工業。' },
  'local': { es: 'Siempre prefiero comprar productos locales y frescos del mercado.', ja: 'いつも市場の地元の新鮮な産品を買うことにしています。', trivia: 'ラテン語 locus（場所）から。英語の local・location・allocate（割り当てる）と同語根。数学の locus（軌跡）も同じ語根。' },
  'moderno': { es: 'El nuevo museo de arte moderno fue inaugurado hace dos años.', ja: '新しい近代美術館は2年前に開館しました。', trivia: 'ラテン語 modernus（今日の）→ modus（尺度・様式）から。英語の modern・mode（流行）・modest（控えめな）と同語根。' },
  'popular': { es: 'La paella es el plato más popular y conocido de la cocina española.', ja: 'パエリャはスペイン料理で最も人気があり知られている料理です。', trivia: 'ラテン語 populus（人民）から。英語の popular・population・public・republic（res publica = 人民のもの！）と同語根。' },
  'regional': { es: 'Esta danza regional se baila en las fiestas populares del pueblo.', ja: 'この地方の踊りは村の民俗祭りで踊られます。', trivia: '"región"から。ラテン語 regio（支配が及ぶ方向・地域）から。英語の region・reign（統治する）と同語根。' },
  'ruidoso': { es: 'El apartamento era demasiado ruidoso por el tráfico de la calle.', ja: 'そのアパートは通りの交通騒音でうるさすぎました。', trivia: '"ruido"（騒音）→ ラテン語 rugire（吠える・轟く）から。英語の raucous（騒々しい）と遠い語根を共有。' },
  'rural': { es: 'La vida rural es tranquila, pero puede ser un poco solitaria a veces.', ja: '田舎の生活は静かですが、時として少し孤独なこともあります。', trivia: 'ラテン語 rus/ruris（田舎・野原）から。英語の rural・rustic（田舎風の）と同語根。' },
  'tranquilo': { es: 'Este café es muy tranquilo y tiene mucha luz natural por las ventanas.', ja: 'このカフェはとても静かで窓から自然光がたくさん入ります。', trivia: 'ラテン語 tranquillus = trans（越えて）+ quies（休息・静寂）= 「静寂を超えた（完全な）静けさ」。英語の tranquil・quiet と同語根。' },
  'universitario': { es: 'Vivo en una residencia universitaria muy cerca del campus principal.', ja: 'メインキャンパスのすぐそばの大学の寮に住んでいます。', trivia: 'ラテン語 universitas（全体）→「知識の全体を扱う場所」が大学の意。英語の university・universe と同語根。' },
  'urbano': { es: 'Prefiero el estilo de vida urbano al rural porque hay más actividades.', ja: '活動が多いので田舎より都会的なライフスタイルが好きです。', trivia: 'ラテン語 urbs/urbis（都市）から。英語の urban（都会の）・suburb（都市の外縁部）・urbane（洗練された）と同語根。都会的 = 洗練された、という語義の拡張も面白い。' },
  'empezar': { es: '¿A qué hora empieza la película esta noche?', ja: '今夜の映画は何時に始まりますか？', trivia: 'ラテン語 impedicare（足を縛る・絡め取る）から変化とされます。英語の impede（妨げる）と同語根。「物事が始まるとき」は何かが「足を捕まえて引き留める」感覚から来ているという説。' },
  'empezó': { es: 'El partido de fútbol empezó puntualmente a las ocho de la noche.', ja: 'サッカーの試合は夜8時に時間通りに始まりました。', trivia: '"empezar"（始める）の点過去3人称単数形。スペイン語では点過去（pretérito indefinido）が「完了した一時点の出来事」を表します。' },
  'llegó': { es: 'El tren llegó con diez minutos de retraso a la estación.', ja: '電車は10分遅れで駅に到着しました。', trivia: '"llegar"（到着する）の点過去形。スペイン語の -gar 動詞は点過去で -gué（1人称）/ -gó（3人称）と変化。' },
  'morir': { es: 'Cervantes murió en 1616, el mismo año que Shakespeare.', ja: 'セルバンテスはシェイクスピアと同じ1616年に亡くなりました。', trivia: 'ラテン語 mori（死ぬ）から。英語の mortal（死ぬべき人間）・immortal（不死の）・mortuary（霊安室）・mortgage（抵当、"mort" = 死 + "gage" = 誓い = 「借金を死ぬまで払う誓い」！）と同語根。' },
  'murió': { es: 'El famoso pintor murió muy joven, a los treinta y siete años.', ja: 'その有名な画家はとても若くして37歳で亡くなりました。', trivia: '"morir"（死ぬ）の点過去3人称単数形。過去の事実として完結した「死」を表す。"Ha muerto"（現在完了）との違いに注意。' },
  'nacer': { es: '¿Dónde naciste? — Nací en Osaka, en el sur de Japón.', ja: 'どこで生まれましたか？日本南部の大阪で生まれました。', trivia: 'ラテン語 nasci（生まれる）から。英語の natal（誕生の）・native（生まれた土地の）・nature（自然、生まれながらのもの）・nation（生まれを共にする集団！）と同語根。' },
  'nació': { es: 'Gaudí nació en Tarragona, Cataluña, en el año 1852.', ja: 'ガウディは1852年にカタルーニャのタラゴナで生まれました。', trivia: '"nacer"（生まれる）の点過去3人称単数形。Nació en 1900 = 「1900年に生まれた」（完結した過去の事実）。' },
  'ocurrir': { es: '¿Qué ocurre aquí? Hay mucha gente agolpada en la calle.', ja: 'ここで何が起きているの？通りに人がたくさん集まっている。', trivia: 'ラテン語 occurrere = ob（向かって）+ currere（走る）= 「走ってぶつかる→出会う→起こる」。英語の occur（起こる）・current（流れ・現在の）と同語根。' },
  'ocurrió': { es: 'El terremoto ocurrió de madrugada, cuando todos dormían.', ja: '地震は皆が眠っている明け方に起きました。', trivia: '"ocurrir"の点過去3人称単数形。突発的に「起こった」一回の出来事を表す。' },
  'pasar': { es: '¿Qué te pasó? Tienes mala cara hoy.', ja: '何かあったの？今日は顔色が悪いよ。', trivia: 'ラテン語 passare（歩み進む）から。英語の pass（通過）・passage（通路）・trespass（侵入）・compass（羅針盤、「ぐるっと歩き回る」）・surpass（超える）と同語根。' },
  'pasó': { es: 'El verano pasó muy rápido este año, sin darnos cuenta.', ja: '今年は夏が気づかないうちにとても早く過ぎてしまいました。', trivia: '"pasar"の点過去3人称単数形。「時が過ぎた」「出来事が起こった」両方に使えます。' },
  'terminar': { es: '¿A qué hora termina tu clase de español esta tarde?', ja: '今日の午後のスペイン語の授業は何時に終わりますか？', trivia: 'ラテン語 terminus（境界石・終点）から。英語の terminal（終点）・terminate（終わらせる）・determine（決定する、境界を決める）・exterminate（根絶する）と同語根。' },
  'terminó': { es: 'La reunión terminó antes de lo previsto y pude salir pronto.', ja: '会議は予定より早く終わり、早く帰ることができました。', trivia: '"terminar"の点過去3人称単数形。「完了・終了した」という確定した事実を表します。' },
  'salió': { es: 'El vuelo salió con dos horas de retraso por el mal tiempo.', ja: 'フライトは悪天候のため2時間遅れで出発しました。', trivia: '"salir"の点過去3人称単数形。ラテン語 salire（跳ぶ）から。英語の salient・assault・somersault と同語根。' },
  'aconsejar que': { es: 'El médico me aconsejó que durmiera más y comiera mejor.', ja: '医師はもっと寝てよく食べるよう勧めました。', trivia: '「consejo」（助言）→ ラテン語 consilium（審議・協議）から。英語の council（評議会）・counsel（助言）と同語根。「共に考えること」が助言の原義。' },
  'alegrarse de que': { es: 'Me alegro mucho de que puedas venir a la fiesta esta noche.', ja: '今夜のパーティーに来られると知ってとても嬉しいです。', trivia: '「alegre」（陽気な）→ ラテン語 alacer（活発な）から。英語の alacrity（機敏さ・快活さ）と同語根。' },
  'desear que': { es: 'Deseo que tengas mucho éxito en tu nuevo trabajo.', ja: '新しいお仕事でたくさん成功されることを願っています。', trivia: 'ラテン語 desiderare（星（sidus）を恋しく思う）から！de（〜から離れて）+ siderus（星）= 「星から引き離されている」→「切望する」が原義。英語の desire・desiderata と同語根。' },
  'esperar que': { es: 'Espero que llegues a tiempo para no perderte el inicio.', ja: '始まりを逃さないように時間に間に合って来ることを望みます。', trivia: 'ラテン語 sperare（希望を持つ）から。英語の despair（絶望 = de + sperare）・prosper（繁栄する = pro + sperare）と同語根。' },
  'ojalá': { es: '¡Ojalá haga buen tiempo mañana para poder ir a la playa!', ja: '明日晴れてビーチに行けるといいな！', trivia: 'アラビア語「لو شاء الله（law sha Allah）」= 「神が望めば（インシャッラー）」から。スペイン語の中で最も有名なアラビア語借用語の一つ。800年のイスラム支配の遺産。' },
  'pedir que': { es: 'Te pido que seas más puntual en las reuniones de trabajo.', ja: '仕事の会議でもっと時間を守るようお願いします。', trivia: 'ラテン語 petere（求める・向かう）から。英語の petition（請願）・compete（共に求める→競争）・appetite（食欲、〜に向かう欲求）と同語根。' },
  'querer que': { es: 'Quiero que me expliques ese tema otra vez con más detalle.', ja: 'そのテーマをもう一度もっと詳しく説明してほしいです。', trivia: 'ラテン語 quaerere（求める・尋ねる）から。英語の query・quest・question と同語根。' },
  'recomendar que': { es: 'Te recomiendo que pruebes la paella valenciana cuando vayas a Valencia.', ja: 'バレンシアに行ったらバレンシア風パエリャを食べてみることをお勧めします。', trivia: 'ラテン語 commendare（委託する・賞賛する）から。英語の commend（称える）・recommend と同語根。' },
  'sorprender que': { es: 'Me sorprende que no sepas nadar viviendo tan cerca del mar.', ja: '海のそんなに近くに住んでいて泳げないことに驚きます。', trivia: '「sorprender」= sobre（上に）+ prender（つかむ）= 「上からいきなりつかまれる」→「驚く」。英語の surprise も sur（上から）+ prise（つかむ）で全く同じ構造！' },
  'Estado': { es: 'El Estado español garantiza el acceso a la educación pública y gratuita.', ja: 'スペイン国家は無償の公教育へのアクセスを保障しています。', trivia: 'ラテン語 status（状態・立場）から。英語の state（状態・州）・status（地位）・estate（財産・身分）・statistic（統計）と同語根。アメリカの「州」もこの語根から。' },
  'admirar': { es: 'Admiro mucho a mi abuela por su fuerza y paciencia.', ja: '私は祖母をその強さと忍耐のためにとても尊敬しています。', trivia: 'ラテン語 admirari = ad（〜に）+ mirari（驚いて見る）から。英語の admire（賞賛する）・miracle（奇跡）・mirror（鏡、自分を見るもの）と同語根。「尊敬」は本来「驚きをもって見つめる」ことでした。' },
  'bailar': { es: 'Los sábados por la noche nos gusta salir a bailar salsa.', ja: '土曜の夜は私たちはサルサを踊りに出かけるのが好きです。', trivia: '俗ラテン語 ballare（踊る）から。英語の ball（舞踏会）・ballet（バレエ）・ballad（バラード、もともと踊りの歌）と同語根。ギリシャ語 ballizein（跳ねる）が源流とされます。' },
  'cansado/a': { es: 'Después de caminar todo el día por la ciudad, estoy muy cansado.', ja: '一日中街を歩き回った後で、とても疲れています。', trivia: 'ラテン語 campsare（向きを変える・引き返す）→「すり減らす」が原義とされます。estar cansado（疲れている）と ser cansado（退屈な人だ）で意味が変わるのがスペイン語の ser/estar の妙です。' },
  'destruir': { es: 'El terremoto destruyó muchos edificios antiguos del centro.', ja: '地震が中心部の多くの古い建物を破壊しました。', trivia: 'ラテン語 destruere = de（下に）+ struere（積み上げる）= 「積み上げたものを崩す」。英語の destroy・structure（構造）・construct（建設する）・instrument（道具）と同語根。' },
  'economizar': { es: 'Este mes tenemos que economizar para poder viajar en verano.', ja: '夏に旅行できるよう今月は節約しなければなりません。', trivia: 'ギリシャ語 oikos（家）+ nomos（管理・法）= 「家計のやりくり」が語源。英語の economy・economic と同語根。元来「経済」とは家庭の運営術を指す言葉でした。' },
  'el abuelo': { es: 'Mi abuelo nos cuenta historias de cuando era joven en el pueblo.', ja: '祖父は村で若かった頃の話を私たちに聞かせてくれます。', trivia: 'ラテン語 avus（祖父）の指小辞 aviolus から。英語の atavism（隔世遺伝、先祖返り）と同語根。スペイン語の指小辞 -elo/-uelo が温かみのある呼び名を作っています。' },
  'el baño': { es: 'Perdone, ¿dónde está el baño, por favor?', ja: 'すみません、お手洗いはどこですか？', trivia: 'ラテン語 balneum（浴場）から。英語の bath・balneotherapy（温泉療法）と同語根。スペイン語の baño は「浴室」と「トイレ」の両方を指し、旅行で最もよく使う単語の一つです。' },
  'el cumpleaños': { es: '¡Feliz cumpleaños! Te he traído un pequeño regalo.', ja: 'お誕生日おめでとう！ちょっとした贈り物を持ってきたよ。', trivia: '"cumplir"（満たす・果たす）+ "años"（年）= 「年を満たす」が直訳。ラテン語 complere（満たす）から。英語の complete・complement と同語根。誕生日は「一年を全うした日」という発想です。' },
  'el periódico': { es: 'Mi padre lee el periódico todas las mañanas con un café.', ja: '父は毎朝コーヒーを飲みながら新聞を読みます。', trivia: 'ギリシャ語 periodos = peri（周りを）+ hodos（道）= 「ひと回りする道筋」→「周期」。英語の period（周期・期間）と同語根。新聞は「定期的に」発行されるものだからこの名がつきました。' },
  'el precio': { es: '¿Cuál es el precio de esta camiseta azul?', ja: 'この青いTシャツの値段はいくらですか？', trivia: 'ラテン語 pretium（価値・代価）から。英語の price・precious（貴重な）・appreciate（価値を認める）・praise（称賛する）と同語根。' },
  'el terrorista': { es: 'La policía detuvo al terrorista antes del atentado.', ja: '警察はテロ攻撃の前にテロリストを逮捕しました。', trivia: 'ラテン語 terrere（恐れさせる）から。英語の terror・terrible・deter（思いとどまらせる）と同語根。-ista はギリシャ語由来の「〜する人」を表す接尾辞で、英語の -ist に対応します。' },
  'la empresa': { es: 'Ella trabaja en una empresa internacional de tecnología.', ja: '彼女は国際的な技術系の企業で働いています。', trivia: 'ラテン語 in + prehendere（つかむ・引き受ける）→「引き受けた事業」が原義。英語の enterprise（企業・進取の気性）・comprehend（理解する、心でつかむ）と同語根。' },
  'la verdura': { es: 'En el mercado compramos verdura fresca todos los domingos.', ja: '毎週日曜日、市場で新鮮な野菜を買います。', trivia: 'ラテン語 viridis（緑の）から。英語の verdant（青々とした）・verdigris（緑青）と同語根。"verde"（緑）= 野菜という発想は、英語の greens（青物野菜）とそっくりです。' },
  'las ruinas': { es: 'Visitamos las ruinas mayas de Chichén Itzá en México.', ja: 'メキシコのチチェン・イッツァのマヤ遺跡を訪れました。', trivia: 'ラテン語 ruina（崩落）→ ruere（崩れ落ちる）から。英語の ruin と同語根。複数形 las ruinas で「遺跡」を指すのが定番で、単数とニュアンスが変わる名詞です。' },
  'limpiar': { es: 'Los sábados limpio toda la casa antes de descansar.', ja: '土曜日は休む前に家中を掃除します。', trivia: 'ラテン語 limpidus（澄んだ・透明な）から。英語の limpid（澄み切った）と同語根。「きれいにする」の根底に「水のように澄んだ状態にする」イメージがあります。' },
  'los gastos': { es: 'Este mes los gastos de la casa han sido muy altos.', ja: '今月は家の出費がとても高くつきました。', trivia: '"gastar"（使う・消費する）→ ラテン語 vastare（荒らす・浪費する）から。英語の waste（浪費する）・devastate（荒廃させる）と同語根。お金を使うことは元来「使い果たす」ことでした。' },
  'regalar': { es: 'Para su cumpleaños le voy a regalar un libro de cocina.', ja: '彼の誕生日に料理の本を贈るつもりです。', trivia: 'フランス語 régaler（もてなす・楽しませる）から。英語の regale（饗応する・楽しませる）と同語根。贈り物は相手を「喜ばせ、もてなす」行為だという発想です。' },
  'rezar': { es: 'Mi abuela reza todas las noches antes de dormir.', ja: '祖母は毎晩眠る前に祈ります。', trivia: 'ラテン語 recitare（声に出して読む・暗唱する）から。英語の recite（暗唱する）・recital（リサイタル）と同語根。祈りは元来「決まった言葉を声に出して唱える」ことでした。' },
  'subir': { es: 'Vamos a subir hasta lo alto de la torre para ver la ciudad.', ja: '街を見渡すために塔のてっぺんまで登りましょう。', trivia: 'ラテン語 subire = sub（下から）+ ire（行く）= 「下から上へ行く」。英語の exit・transit など ire（行く）系の語と同語根。接頭辞 sub- が「下から上へ」と逆方向に働くのが面白い点です。' },
  'sudar': { es: 'Después de correr una hora, estaba sudando muchísimo.', ja: '一時間走った後、ものすごく汗をかいていました。', trivia: 'ラテン語 sudare（汗をかく）から。英語の sweat とは遠い親戚（印欧祖語 *sweid-）。温泉や蒸し風呂を意味する英語 sudatorium も同語根です。' },
  'trabajar': { es: 'Mi hermana trabaja de enfermera en un hospital grande.', ja: '姉は大きな病院で看護師として働いています。', trivia: '俗ラテン語 tripaliare（三本杭の拷問具 tripalium で苦しめる）が語源！「働く」がもともと「苦しむ」を意味したのは、英語の travail（苦労）・フランス語 travailler も同じ。labor の重さを物語る単語です。' },
  'cerrar': { es: 'Por favor, cierra la ventana que hace frío.', ja: '寒いから窓を閉めてください。', trivia: 'ラテン語 serare（かんぬきをかける）→ sera（かんぬき）から。語幹が e→ie に変化する典型的な不規則動詞（cierro, cierras…）で、初級学習者が最初に出会う「靴型変化動詞」の代表例です。' },
  'construir': { es: 'Van a construir un nuevo puente sobre el río.', ja: '川に新しい橋を建設する予定です。', trivia: 'ラテン語 construere = con（共に）+ struere（積み上げる）。英語の construct・structure・instrument と同語根。destruir（破壊する）はこの正反対で、同じ struere を共有します。' },
  'cuarto': { es: 'Son las tres y cuarto de la tarde.', ja: '午後3時15分です。', trivia: 'ラテン語 quartus（第4の）から。英語の quarter（4分の1・15分）・quart（クォート）と同語根。時刻で「y cuarto」は「1時間の4分の1=15分過ぎ」を表します。' },
  'curso': { es: 'Este año hago un curso de español en la universidad.', ja: '今年は大学でスペイン語の課程を受けています。', trivia: 'ラテン語 cursus（走ること・進路）→ currere（走る）から。英語の course・current（流れ）・cursor（カーソル）と同語根。授業は知識を「走り進む道筋」というイメージです。' },
  'decir': { es: '¿Puedes decirme cómo llegar a la estación?', ja: '駅への行き方を教えてもらえますか？', trivia: 'ラテン語 dicere（言う）から。英語の dictionary（辞書）・dictate（口述する）・predict（予言する）・verdict（評決、真実を言う）と同語根。digo, dices… と語幹が大きく変わる最重要不規則動詞です。' },
  'dulce': { es: 'De postre tomamos unos dulces típicos de la región.', ja: 'デザートにその地方の伝統的なお菓子をいただきました。', trivia: 'ラテン語 dulcis（甘い）から。英語の dulcet（甘美な）・音楽用語 dolce（ドルチェ、優しく）と同語根。スペインの dulces は修道院由来のお菓子が多く、文化的にも奥深い言葉です。' },
  'empresa': { es: 'Mi hermano fundó su propia empresa hace cinco años.', ja: '兄は5年前に自分の会社を立ち上げました。', trivia: 'ラテン語 in + prehendere（つかむ・引き受ける）→「引き受けた事業」が原義。英語の enterprise・comprehend（心でつかむ→理解する）と同語根。冠詞なしでも「企業活動・事業」全般を指せます。' },
  'lago': { es: 'El lago Titicaca está entre Perú y Bolivia.', ja: 'チチカカ湖はペルーとボリビアの間にあります。', trivia: 'ラテン語 lacus（湖・水たまり）から。英語の lake・lagoon（潟）と同語根。チチカカ湖は標高約3800mにある世界有数の高地湖です。' },
  'llover': { es: 'En el norte de España llueve mucho en invierno.', ja: 'スペイン北部は冬によく雨が降ります。', trivia: 'ラテン語 pluere（雨が降る）→ 俗ラテン語 plovere から。英語の pluvial（雨の）と同語根。天候動詞なので3人称単数 llueve のみで使う「無人称動詞」です。' },
  'madrugada': { es: 'El avión sale de madrugada, a las cuatro de la mañana.', ja: '飛行機は未明の午前4時に出発します。', trivia: 'ラテン語 maturicare（早める）→ maturus（熟した・早い）から。英語の mature（成熟した）・premature（早すぎる）と同語根。動詞 madrugar は「早起きする」で、ことわざ A quien madruga, Dios le ayuda（早起きは三文の徳）が有名。' },
  'mayor': { es: 'Mi hermana mayor vive en Barcelona desde hace años.', ja: '姉は何年も前からバルセロナに住んでいます。', trivia: 'ラテン語 maior（より大きい）→ magnus（大きい）の比較級から。英語の major・mayor（市長、「より上の者」）・majesty（威厳）と同語根。年齢では「年上」、サイズでは「より大きい」を表します。' },
  'media': { es: 'Te espero a las siete y media en la puerta del cine.', ja: '7時半に映画館の入口で待っているね。', trivia: 'ラテン語 medius（真ん中の）から。英語の medium・middle・mediterranean（地中海＝大地の真ん中）と同語根。時刻の「y media」は「半分=30分過ぎ」を表します。' },
  'mejor': { es: 'Este es el mejor restaurante de toda la ciudad.', ja: 'ここは街全体で一番良いレストランです。', trivia: 'ラテン語 melior（より良い）から。英語の ameliorate（改善する）と同語根。bueno（良い）の不規則比較級で、英語の good→better と同じく語形がまるごと変わるタイプです。' },
  'menor': { es: 'Mi hermano menor todavía va al colegio.', ja: '弟はまだ小学校に通っています。', trivia: 'ラテン語 minor（より小さい）から。英語の minor・minus・minimum・minister（より小さい者＝奉仕者）と同語根。年齢では「年下」、法律では「未成年（menor de edad）」を表します。' },
  'nevar': { es: 'En las montañas suele nevar a partir de noviembre.', ja: '山では11月頃から雪が降るのが普通です。', trivia: 'ラテン語 nix/nivis（雪）から。英語の snow とは遠い親戚（印欧祖語 *sneigwh-）。フランス語 neige・イタリア語 neve も同語根。天候動詞で3人称単数 nieva のみで使います。' },
  'pedir': { es: 'Voy a pedir una sopa y una ensalada, por favor.', ja: 'スープとサラダを注文します。', trivia: 'ラテン語 petere（求める・向かう）から。英語の petition（請願）・appetite（食欲）・compete（競う）と同語根。e→i に変わる語幹変化動詞（pido, pides…）で、preguntar（質問する）との使い分けが学習の山場です。' },
  'peor': { es: 'Hoy el tráfico está peor que ayer por la lluvia.', ja: '今日は雨のせいで昨日より交通がひどいです。', trivia: 'ラテン語 peior（より悪い）から。英語の pejorative（軽蔑的な、意味を悪くする語）と同語根。malo（悪い）の不規則比較級で、bien/mal の副詞比較級も mejor/peor を使います。' },
  'traer': { es: '¿Puedes traer algo de beber a la fiesta?', ja: 'パーティーに飲み物を何か持ってきてくれる？', trivia: 'ラテン語 trahere（引く・引き寄せる）から。英語の tractor（牽引車）・attract（引きつける）・abstract（引き離す）と同語根。1人称が traigo になる不規則動詞です。' },
  'ver': { es: 'Anoche fuimos a ver una película al cine.', ja: '昨夜、映画館に映画を見に行きました。', trivia: 'ラテン語 videre（見る）から。英語の video・vision・evident（明白な）・supervise（監督する）と同語根。1人称 veo、過去分詞 visto と不規則です。「会う」の意味でも日常的に使います。' },
  'volver': { es: 'Pienso volver a España el próximo verano.', ja: '来年の夏にスペインへ戻るつもりです。', trivia: 'ラテン語 volvere（回す・転がす）から。英語の revolve（回転する）・evolve（進化する）・volume（巻物＝巻いたもの）と同語根。o→ue の語幹変化動詞（vuelvo, vuelves…）で、過去分詞は不規則な vuelto です。' },
  'dar': { es: 'Voy a dar un regalo a mi hermana por su cumpleaños.', ja: '妹の誕生日にプレゼントをあげるつもりです。', trivia: 'ラテン語 dare（与える）から。英語の data（データ）は「与えられたもの」、donate（寄付）も同語根。スペイン語ではパーティーを「dar（開催する）」とも言います。' },
  'poner': { es: 'Voy a poner los platos en la mesa antes de comer.', ja: '食事の前にお皿をテーブルに置きます。', trivia: 'ラテン語 ponere（置く）から。英語の component（構成要素）や position（位置）と同語根。「一緒に（com）置く」のが component です。' },
  'creer': { es: 'No puedo creer que ya sea verano.', ja: 'もう夏だなんて信じられません。', trivia: 'ラテン語 credere（信じる）から。英語の credit（信用）、credible（信用できる）と同語根。お金を「貸す」のも相手を「信じる」ことから来ています。' },
  'dejar': { es: 'Voy a dejar las llaves sobre la mesa.', ja: '鍵をテーブルの上に置いていきます。', trivia: 'ラテン語 laxare（緩める、解放する）から。英語の relax（リラックス）や lax（緩い）と同語根。何かを「手放す」イメージが「残す」「させる」へ広がりました。' },
  'encontrar': { es: 'No puedo encontrar mis gafas por ninguna parte.', ja: 'メガネがどこにも見つかりません。', trivia: 'ラテン語 in contra（向かい合って）から。英語の counter（カウンター）や encounter（遭遇）と同語根。「向かい合う」ことが「出会う」「見つける」になりました。' },
  'buscar': { es: 'Estoy buscando un trabajo nuevo en otra ciudad.', ja: '別の街で新しい仕事を探しています。', trivia: '起源は不確かですが、英語 busk（大道芸をする）はスペイン語 buscar（探し回る）から来たとされます。芸人が場所を「探し求める」イメージです。' },
  'entrar': { es: 'Vamos a entrar en el museo antes de que cierre.', ja: '閉まる前に美術館に入りましょう。', trivia: 'ラテン語 intrare（入る）から。英語の entrance（入口）や enter と同語根。語源は inter（〜の間に）で、「中へ進む」ことを表します。' },
  'escribir': { es: 'Me gusta escribir cartas a mano a mis abuelos.', ja: '祖父母に手書きで手紙を書くのが好きです。', trivia: 'ラテン語 scribere（書く）から。英語の describe（描写する）、script（台本）と同語根。もとは「刻みつける」動作を指しました。' },
  'perder': { es: 'Si no corro, voy a perder el tren de las ocho.', ja: '走らないと8時の電車に乗り遅れます。', trivia: 'ラテン語 perdere（破壊する、失う）から。per（完全に）+ dare（与える）で「手放しきる」が原義。英語 perdition（破滅）と同語根です。' },
  'producir': { es: 'Esta fábrica produce miles de coches al año.', ja: 'この工場は年に何千台もの車を生産します。', trivia: 'ラテン語 producere（前へ導き出す）から。pro（前へ）+ ducere（導く）。英語の product（製品）や produce と同語根です。' },
  'entender': { es: 'No entiendo bien esta lección de gramática.', ja: 'この文法のレッスンがよく理解できません。', trivia: 'ラテン語 intendere（〜へ心を向ける）から。inter（間に）+ tendere（伸ばす）。英語の intend（意図する）や tension（緊張）と同語根です。' },
  'permitir': { es: 'Mis padres no me permiten salir tan tarde.', ja: '両親はそんなに遅く外出することを許してくれません。', trivia: 'ラテン語 permittere（通す、許す）から。per（通って）+ mittere（送る）。英語の permit や mission（任務）、missile（ミサイル）と同語根です。' },
  'comenzar': { es: 'Las clases comienzan a las nueve de la mañana.', ja: '授業は朝9時に始まります。', trivia: '俗ラテン語 cominitiare（始める）から。initium（始まり）が中に隠れており、英語の initial（最初の）や initiate（開始する）と同語根です。' },
  'sacar': { es: 'Voy a sacar dinero del cajero antes de viajar.', ja: '旅行の前にATMからお金を引き出します。', trivia: 'ゴート語 sakan（争う、追求する）由来とされる珍しい語。写真を「撮る」（sacar una foto）にも使い、英語の take a photo に対応します。' },
  'necesitar': { es: 'Necesito comprar leche y pan para el desayuno.', ja: '朝食用に牛乳とパンを買う必要があります。', trivia: 'ラテン語 necesse（避けられない）から。ne（〜ない）+ cedere（譲る、退く）で「退けられない」が原義。英語の necessary（必要な）と同語根です。' },
  'mantener': { es: 'Es importante mantener la calma en una emergencia.', ja: '緊急時には冷静さを保つことが大切です。', trivia: 'ラテン語 manu tenere（手で持つ）から。manus（手）+ tenere（持つ）。英語の maintain や manual（手の）、maintenance（維持）と同語根です。' },
  'resultar': { es: 'El examen resultó más fácil de lo que pensaba.', ja: '試験は思っていたより簡単だと分かりました。', trivia: 'ラテン語 resultare（跳ね返る）から。re（戻って）+ saltare（跳ぶ）。英語の result や salmon（跳ねる魚＝鮭）と同語根です。' },
  'leer': { es: 'Me gusta leer una novela antes de dormir.', ja: '寝る前に小説を読むのが好きです。', trivia: 'ラテン語 legere（集める、読む）から。英語の legend（伝説＝読まれるべきもの）、lecture（講義）、collect（集める）と同語根です。' },
  'caer': { es: 'Ten cuidado, te puedes caer en el hielo.', ja: '気をつけて、氷で転ぶかもしれませんよ。', trivia: 'ラテン語 cadere（落ちる）から。英語の cadence（落ち着く調子）、accident（偶然＝降りかかること）、decay（衰える）と同語根です。' },
  'cambiar': { es: 'Quiero cambiar euros por yenes en el banco.', ja: '銀行でユーロを円に両替したいです。', trivia: '後期ラテン語 cambiare（交換する）から。ケルト語起源とされ、英語の exchange（交換）や change と同語根です。' },
  'abrir': { es: '¿Puedes abrir la ventana? Hace mucho calor.', ja: '窓を開けてくれる？とても暑いから。', trivia: 'ラテン語 aperire（開く）から。英語の aperture（カメラの絞り、開口部）や、4月 April（春に大地が開く月とされる説）と同語根です。' },
  'oír': { es: 'No te oigo bien, hay mucho ruido aquí.', ja: 'よく聞こえません、ここはとてもうるさいので。', trivia: 'ラテン語 audire（聞く）から。英語の audio（音声）、audience（聴衆）、auditorium（講堂）と同語根。短い oír に audire が凝縮されています。' },
  'formar': { es: 'Los estudiantes forman un grupo para el proyecto.', ja: '学生たちはプロジェクトのためにグループを作ります。', trivia: 'ラテン語 forma（形）から。英語の form、format、uniform（同じ形＝制服）と同語根。「形を与える」ことが「育てる」意味にも広がりました。' },
  'partir': { es: 'El tren parte de la estación a las diez en punto.', ja: '電車は10時ちょうどに駅を出発します。', trivia: 'ラテン語 partire（分ける）から。英語の part（部分）、partition（仕切り）、apart（離れて）と同語根。「分かれて去る」のが「出発」です。' },
  'aceptar': { es: 'Decidí aceptar la oferta de trabajo.', ja: 'その仕事のオファーを受け入れることに決めました。', trivia: 'ラテン語 accipere（受け取る）から。ad（〜へ）+ capere（つかむ）。英語の accept や capture（捕える）、capable（できる）と同語根です。' },
  'comprender': { es: 'Es difícil comprender otra cultura sin viajar.', ja: '旅をせずに別の文化を理解するのは難しいです。', trivia: 'ラテン語 comprehendere（つかみ取る）から。com（共に）+ prehendere（つかむ）。英語の comprehend や prehensile（物をつかめる）と同語根です。' },
  'explicar': { es: 'El profesor explica la lección con mucha paciencia.', ja: '先生はとても辛抱強くレッスンを説明します。', trivia: 'ラテン語 explicare（広げる、ほどく）から。ex（外へ）+ plicare（折る）。「折りたたまれたものを開く」が原義。英語の explicit（明白な）と同語根です。' },
  'estudiar': { es: 'Tengo que estudiar mucho para el examen de mañana.', ja: '明日の試験のためにたくさん勉強しなければなりません。', trivia: 'ラテン語 studere（熱心に努める）から。英語の study や student、studio と同語根。もとは「熱意」を意味し、学問とは情熱でした。' },
  'dirigir': { es: 'Ella dirige una empresa de tecnología muy grande.', ja: '彼女はとても大きなテクノロジー企業を指揮しています。', trivia: 'ラテン語 dirigere（まっすぐ向ける）から。dis（離れて）+ regere（導く）。英語の direct や regime（体制）、regular（規則的）と同語根です。' },
  'pagar': { es: 'Hoy te invito yo, yo pago la cena.', ja: '今日は私のおごり、夕食は私が払います。', trivia: 'ラテン語 pacare（和解させる、なだめる）から。pax（平和）が語源で、借金を払うのは相手と「和をなす」こと。英語の peace（平和）や pacify と同語根です。' },
  'ayudar': { es: '¿Me puedes ayudar a llevar estas maletas?', ja: 'これらのスーツケースを運ぶのを手伝ってくれますか？', trivia: 'ラテン語 adiutare（助ける）から。英語の aid（援助）や adjutant（副官）と同語根。困っている人へ（ad）力を「向ける」イメージです。' },
  'jugar': { es: 'Los niños juegan al fútbol en el parque.', ja: '子供たちは公園でサッカーをします。', trivia: 'ラテン語 iocari（冗談を言う、遊ぶ）から。iocus（冗談）が語源で、英語の joke（冗談）や jewel（喜ばせるもの）と同語根です。' },
  'escuchar': { es: 'Me encanta escuchar música mientras cocino.', ja: '料理をしながら音楽を聞くのが大好きです。', trivia: 'ラテン語 auscultare（注意して聞く）から。英語の医療用語 auscultation（聴診）と同語根。oír（聞こえる）より「耳を傾ける」能動的な行為です。' },
  'cumplir': { es: 'Mi hijo cumple diez años el próximo mes.', ja: '息子は来月10歳になります。', trivia: 'ラテン語 complere（満たす）から。com（完全に）+ plere（満たす）。英語の complete（完成）や complement（補完）と同語根。約束を「満たす」のが「果たす」です。' },
  'ofrecer': { es: 'La empresa ofrece muchas oportunidades a los jóvenes.', ja: 'その会社は若者に多くの機会を提供しています。', trivia: 'ラテン語 offerre（差し出す）から。ob（〜に向けて）+ ferre（運ぶ）。英語の offer や、宗教の offering（捧げ物）と同語根です。' },
  'descubrir': { es: 'Los científicos descubrieron una nueva especie de pez.', ja: '科学者たちは新種の魚を発見しました。', trivia: 'ラテン語由来。des（取り除く）+ cubrir（覆う）で「覆いを取る」が原義。英語の discover とまったく同じ作りで、cover（覆う）を外すことです。' },
  'intentar': { es: 'Voy a intentar hablar solo en español hoy.', ja: '今日はスペイン語だけで話すことを試みます。', trivia: 'ラテン語 intentare（向ける、企てる）から。tendere（伸ばす）が語源で、英語の intent（意図）や tension（張り）と同語根。心を目標へ「伸ばす」ことです。' },
  'decidir': { es: 'Todavía no he decidido qué estudiar en la universidad.', ja: '大学で何を勉強するか、まだ決めていません。', trivia: 'ラテン語 decidere（切り落とす）から。de（離して）+ caedere（切る）。他の選択肢を「切り捨てる」のが決断。英語の scissors（はさみ）と同語根です。' },
  'repetir': { es: '¿Puede repetir la pregunta, por favor?', ja: '質問をもう一度言っていただけますか？', trivia: 'ラテン語 repetere（再び求める）から。re（再び）+ petere（求める）。英語の repeat や petition（請願）、appetite（食欲）と同語根です。' },
  'olvidar': { es: 'Siempre olvido dónde dejo las llaves.', ja: 'いつも鍵をどこに置いたか忘れます。', trivia: 'ラテン語 oblitare（忘れる）から。英語の oblivion（忘却）や oblivious（気づかない）と同語根。何かが心から「滑り落ちる」イメージです。' },
  'comprar': { es: 'La semana que viene voy a comprar un coche nuevo.', ja: '来週、新しい車を買うつもりです。', trivia: 'ラテン語 comparare（比較して手に入れる）から。英語の compare と同語根で、もとは「価格を比べて買う」という意味。' },
  'caminar': { es: 'Me gusta caminar por la playa al atardecer.', ja: '夕暮れにビーチを歩くのが好きです。', trivia: 'ラテン語 camminus（道）から。英語の camino や camion とつながり、スペインの巡礼路カミーノ・デ・サンティアゴでおなじみ。' },
  'mover': { es: 'Necesito ayuda para mover este sofá tan pesado.', ja: 'このとても重いソファを動かすのに手伝いが必要です。', trivia: 'ラテン語 movere（動かす）から。英語の move・motion・motive・emotion（感情＝心を動かすもの）と同語根。' },
  'matar': { es: 'En la novela el detective descubre quién quiso matar al rey.', ja: '小説の中で探偵は誰が王を殺そうとしたのか突き止めます。', trivia: '俗ラテン語の打ち負かすという語に由来するとされる。チェスの「チェックメイト」はアラビア語の王は死んだ（シャー・マート）から来ており、matar と響きが重なる偶然が面白い。' },
  'hombre': { es: 'Aquel hombre de la esquina es mi profesor de historia.', ja: 'あの角にいる男性は私の歴史の先生です。', trivia: 'ラテン語 homo（人間）から。英語の human・humane と同語根で、もとは大地（humus）から生まれた者という意味合いがある。' },
  'mujer': { es: 'Esa mujer dirige una de las empresas más grandes del país.', ja: 'あの女性は国内最大級の企業の一つを率いています。', trivia: 'ラテン語 mulier（女性）から。フランス語やイタリア語では別語に置き換わったが、スペイン語は古い形をよく保っている。' },
  'niño': { es: 'El niño juega con sus amigos en el parque cada tarde.', ja: 'その男の子は毎日午後に公園で友達と遊びます。', trivia: '幼児が発する「ニニ」という擬音に由来するとされる。英語にも nanny（乳母）など同種の音から生まれた語がある。' },
  'mano': { es: 'Levanta la mano si tienes alguna pregunta.', ja: '質問があれば手を挙げてください。', trivia: 'ラテン語 manus（手）から。英語の manual・manage・manufacture（手で作る）と同語根。manus は「手で扱うこと」全般を表した。' },
  'día': { es: 'Hoy es un día perfecto para salir de excursión.', ja: '今日は遠足に出かけるのにぴったりの日です。', trivia: 'ラテン語 dies（日）から。英語の diary・dial や、スペイン語の挨拶 buenos días と同語根。男性名詞なのに語尾が a の珍しい単語。' },
  'año': { es: 'El año pasado viajamos a México en verano.', ja: '去年の夏、私たちはメキシコへ旅行しました。', trivia: 'ラテン語 annus（年）から。英語の annual・anniversary・annuity と同語根。ñ は ann の二重子音がスペイン語で変化したもの。' },
  'parte': { es: 'Esta parte de la ciudad es muy tranquila por la noche.', ja: '街のこの部分は夜とても静かです。', trivia: 'ラテン語 pars / partem（部分）から。英語の part・partner・portion・particle と同語根。' },
  'momento': { es: 'Espera un momento, ahora mismo vuelvo.', ja: 'ちょっと待ってください、すぐに戻ります。', trivia: 'ラテン語 momentum（動き・はずみ）から。英語の moment と momentum は同じ語が二通りに英語へ入ったもの。movere（動かす）とも同語根。' },
  'forma': { es: 'Las nubes tenían forma de animales esta mañana.', ja: '今朝、雲は動物の形をしていました。', trivia: 'ラテン語 forma（形）から。英語の form・format・uniform・transform と同語根。' },
  'casa': { es: 'Mi casa está cerca de la estación de tren.', ja: '私の家は鉄道の駅の近くにあります。', trivia: 'ラテン語 casa（小屋・あばら家）から。もとは質素な住まいを指したが、現代スペイン語では家全般を表す。英語のカジノ（casino）も小さな家が語源。' },
  'gente': { es: 'Había mucha gente en el concierto del sábado.', ja: '土曜日のコンサートにはたくさんの人がいました。', trivia: 'ラテン語 gens / gentem（一族・民族）から。英語の gentle・gentleman・gene・genus と同語根。集合名詞なので動詞は単数で受ける。' },
  'caso': { es: 'En ese caso, creo que es mejor llamar al médico.', ja: 'その場合は、医者を呼ぶ方がよいと思います。', trivia: 'ラテン語 casus（落ちること・偶然）から。英語の case・casual・cadence・occasion と同語根。cadere（落ちる）に由来する。' },
  'punto': { es: 'No estoy de acuerdo con ese punto de tu argumento.', ja: 'あなたの主張のその点には賛成できません。', trivia: 'ラテン語 punctum（刺された跡・点）から。英語の point・puncture・punctual（時間の一点を守る）と同語根。' },
  'hora': { es: '¿A qué hora empieza la película esta noche?', ja: '今夜、映画は何時に始まりますか。', trivia: 'ギリシャ語 hora（季節・時）からラテン語経由で。英語の hour と同語根。h は発音されないがつづりに残っている。' },
  'manera': { es: 'Lo hizo de una manera muy original y creativa.', ja: '彼はそれをとても独創的で創造的な方法で行いました。', trivia: 'ラテン語 manus（手）に由来し、もとは「手のやり方」という意味。英語の manner と同語根で、mano（手）とも親戚。' },
  'nombre': { es: 'No recuerdo el nombre de aquella canción tan famosa.', ja: 'あの有名な曲の名前が思い出せません。', trivia: 'ラテン語 nomen（名前）から。英語の name・nominate・noun（名詞）と同語根。文法用語で名詞そのものも意味する。' },
  'cuerpo': { es: 'El ejercicio es bueno para el cuerpo y la mente.', ja: '運動は身体にも心にも良いものです。', trivia: 'ラテン語 corpus（体）から。英語の corpse・corporation（法人＝法的な体）・corporal と同語根。' },
  'cabeza': { es: 'Me duele la cabeza desde esta mañana.', ja: '今朝から頭が痛いです。', trivia: '俗ラテン語 capitia（頭部）から、ラテン語 caput（頭）に由来。英語の capital・captain・chief と同語根で、いずれも「頭＝先頭・重要」を表す。' },
  'ojo': { es: 'Tengo algo en el ojo y no puedo ver bien.', ja: '目に何か入っていて、よく見えません。', trivia: 'ラテン語 oculus（目）から。英語の ocular・binocular・monocle と同語根。間投詞 ojo は「注意して」という意味でも使う。' },
  'cara': { es: 'Tu cara muestra que estás muy cansado hoy.', ja: 'あなたの顔は今日とても疲れていることを物語っています。', trivia: 'ギリシャ語 kara（頭・顔）からラテン語経由で。英語のスラング mug などとは違い、こちらは古典語由来。値段が高いという形容詞 caro とは別語源。' },
  'palabra': { es: 'No entiendo el significado de esta palabra en español.', ja: 'スペイン語のこの単語の意味が分かりません。', trivia: 'ギリシャ語 parabole（並べて投げること・たとえ話）からラテン語 parabola を経て。英語の parable・parabola・parole と同語根。' },
  'madre': { es: 'Mi madre cocina la mejor paella de la familia.', ja: '私の母は家族で一番おいしいパエリアを作ります。', trivia: 'ラテン語 mater（母）から。英語の maternal・matrix・material と同語根。マドリードの守護にも通じ、世界中の言語で「母」は m の音で始まることが多い。' },
  'hijo': { es: 'Su hijo mayor estudia medicina en la universidad.', ja: '彼らの長男は大学で医学を学んでいます。', trivia: 'ラテン語 filius（息子）から。f が h に変化するのはスペイン語特有の音変化で、filius が hijo になった。英語の filial（子としての）と同語根。' },
  'familia': { es: 'Toda mi familia se reúne en Navidad cada año.', ja: '私の家族は毎年クリスマスに全員集まります。', trivia: 'ラテン語 familia（家の使用人を含む世帯）から。もとは famulus（召使い）に由来し、血縁より「同じ家に属する集団」を指した。英語の family と同語根。' },
  'gobierno': { es: 'El gobierno anunció nuevas medidas para la economía.', ja: '政府は経済のための新たな施策を発表しました。', trivia: 'ギリシャ語 kybernan（舵を取る）からラテン語経由で。英語の govern と、なんと cybernetics（サイバネティクス）も同じ「舵取り」の語根。' },
  'grupo': { es: 'Nuestro grupo de música toca todos los viernes.', ja: '私たちの音楽グループは毎週金曜日に演奏します。', trivia: 'イタリア語 gruppo（塊・結び目）から。もとはゲルマン語の「丸いもの」に由来し、英語の group・crop と遠い親戚とされる。' },
  'respuesta': { es: 'Todavía estoy esperando una respuesta a mi correo.', ja: '私はまだメールへの返事を待っています。', trivia: 'ラテン語 respondere（応じる・約束し返す）から。英語の response・respond・responsible（応える責任がある）と同語根。' },
  'fin': { es: 'Al fin del verano volvemos a la rutina del trabajo.', ja: '夏の終わりに、私たちは仕事の日常へ戻ります。', trivia: 'ラテン語 finis（境界・終わり）から。英語の final・finish・finance・define と同語根。週末 fin de semana にも登場する。' },
  'guerra': { es: 'La guerra causó muchos daños en aquella región.', ja: 'その戦争はあの地域に多くの被害をもたらしました。', trivia: 'ゲルマン語 werra（争い・混乱）から。英語の war と同語根で、ラテン語系のロマンス諸語が珍しくゲルマン語を借りた例。w が gu に変わるのがスペイン語の特徴。' },
  'paz': { es: 'Después de tantos años por fin llegó la paz.', ja: '長い年月の後、ついに平和が訪れました。', trivia: 'ラテン語 pax / pacem（平和）から。英語の peace・pacific（太平洋）・pacify と同語根。挨拶や祈りの言葉としても広く使われる。' },
  'amor': { es: 'El amor entre ellos creció con el paso del tiempo.', ja: '彼らの間の愛は時とともに育ちました。', trivia: 'ラテン語 amor（愛）から。英語の amorous・amateur（愛好家＝愛ゆえに行う人）と同語根。amigo（友達）とも親戚。' },
  'dinero': { es: 'No me queda mucho dinero hasta fin de mes.', ja: '月末まであまりお金が残っていません。', trivia: 'ローマの銀貨デナリウス（denarius）から。アラビア語のディナール（dinar）も同じ起源で、地中海をまたいで通貨名が広がった。' },
  'libro': { es: 'Estoy leyendo un libro muy interesante sobre historia.', ja: '私は歴史についてとても面白い本を読んでいます。', trivia: 'ラテン語 liber（木の内皮）から。古代では樹皮に文字を書いたため。英語の library と同語根だが、自由を意味する別の liber とは無関係。' },
  'número': { es: '¿Me puedes dar tu número de teléfono?', ja: 'あなたの電話番号を教えてくれますか。', trivia: 'ラテン語 numerus（数）から。英語の number・numeral・enumerate と同語根。' },
  'clase': { es: 'La clase de español empieza a las nueve de la mañana.', ja: 'スペイン語の授業は午前9時に始まります。', trivia: 'ラテン語 classis（ローマ市民を財産で分けた等級・艦隊）から。英語の class・classic・classify と同語根。もとは社会の「区分」を表した。' },
  'fuerza': { es: 'No tengo fuerza suficiente para levantar esa caja.', ja: '私にはあの箱を持ち上げるだけの力がありません。', trivia: 'ラテン語 fortia（強さ）、fortis（強い）から。英語の force・fort・comfort・effort と同語根。映画でおなじみの「フォースと共にあれ」の force も同じ語根。' },
  'nivel': { es: 'Mi hermano estudia en un nivel más avanzado que yo.', ja: '兄は私より上のレベルで勉強しています。', trivia: 'ラテン語 libella（水平器・小さな天秤）から。英語の level と同語根で、もとは水平をはかる道具のこと。' },
  'color': { es: '¿De qué color es tu coche nuevo?', ja: '君の新しい車は何色なの？', trivia: 'ラテン語 color（色・隠すもの）から。動詞 celare（隠す）と関係し、表面を覆うものという発想。英語の color と同源。' },
  'fuego': { es: 'Necesitamos más leña para mantener el fuego.', ja: '火を保つにはもっと薪が必要です。', trivia: 'ラテン語 focus（炉・かまど）から。英語の focus は同じ語で、家の中心だった炉が「焦点」の意味に発展しました。' },
  'luz': { es: 'Por favor, apaga la luz antes de salir.', ja: '出る前に明かりを消してください。', trivia: 'ラテン語 lux（光）から。英語の lucid（明晰な）や lux（照度の単位）と同語根です。' },
  'noche': { es: 'Anoche no pude dormir por el ruido.', ja: '昨夜は騒音で眠れませんでした。', trivia: 'ラテン語 nox（夜）から。英語の nocturnal（夜行性の）と同語根で、ギリシャ語の女神 Nyx（夜）ともつながります。' },
  'tarde': { es: 'Siempre tomamos café por la tarde.', ja: '私たちはいつも午後にコーヒーを飲みます。', trivia: 'ラテン語 tarde（遅く）から。英語の tardy（遅刻した）と同語根。「遅い時間帯」が午後を指すようになりました。' },
  'mes': { es: 'El próximo mes voy a viajar a España.', ja: '来月スペインへ旅行する予定です。', trivia: 'ラテン語 mensis（月）から。月（つき）の満ち欠けが暦の単位の起源で、英語の moon や month とも遠い親戚です。' },
  'sangre': { es: 'El médico me sacó sangre para el análisis.', ja: '医者は検査のために私の血を採りました。', trivia: 'ラテン語 sanguis（血）から。英語の sanguine（楽天的な）は、血が多いと陽気になるという古い体液説に由来します。' },
  'puerta': { es: 'Cierra la puerta, por favor, hace frío.', ja: 'ドアを閉めてください、寒いので。', trivia: 'ラテン語 porta（門）から。英語の port（港）や portal（入口）と同語根で、出入りする場所という共通の発想があります。' },
  'mesa': { es: 'Pon los platos en la mesa, por favor.', ja: 'お皿をテーブルに置いてください。', trivia: 'ラテン語 mensa（食卓・供物台）から。アメリカの地形「メサ」も平らな台形の意味で同じ語に由来します。' },
  'coche': { es: 'Mi coche no arranca esta mañana.', ja: '今朝、私の車が始動しません。', trivia: 'ハンガリーの町 Kocs（コチ）の馬車に由来するといわれ、英語の coach（馬車・長距離バス）と同源です。' },
  'escuela': { es: 'Los niños van a la escuela en autobús.', ja: '子どもたちはバスで学校へ行きます。', trivia: 'ギリシャ語 scholē（余暇）から。古代では自由な時間に学問をしたため、余暇が「学校」の語源になりました。英語の school と同源。' },
  'arte': { es: 'El arte moderno no siempre es fácil de entender.', ja: '現代芸術はいつも理解しやすいとは限りません。', trivia: 'ラテン語 ars（技術・わざ）から。もとは「巧みな技」を指し、英語の art や artisan（職人）と同語根です。' },
  'música': { es: 'La música clásica me ayuda a concentrarme.', ja: 'クラシック音楽は集中する助けになります。', trivia: 'ギリシャ語 mousikē（ムーサたちの技）から。芸術の女神ムーサ（Muses）が語源で、英語の museum とも同じ根を持ちます。' },
  'flor': { es: 'Le regalé una flor roja a mi madre.', ja: '私は母に赤い花を一輪贈りました。', trivia: 'ラテン語 flos（花）から。ローマの花の女神フローラ（Flora）や英語の flour（小麦粉、もとは花のように細かい粉）と同源です。' },
  'perro': { es: 'Mi perro corre por el parque todas las mañanas.', ja: '私の犬は毎朝公園を走ります。', trivia: '語源は不明で、ラテン語 canis を継がない珍しい単語です。羊飼いが犬を呼ぶ「prr」という掛け声からという説があります。' },
  'gato': { es: 'El gato duerme todo el día en el sofá.', ja: '猫は一日中ソファで眠っています。', trivia: '後期ラテン語 cattus から。英語の cat と同源で、北アフリカ起源ともいわれます。車をもち上げる「ジャッキ」もスペイン語で gato と呼びます。' },
  'pájaro': { es: 'Un pájaro pequeño canta en el árbol.', ja: '小さな鳥が木でさえずっています。', trivia: 'ラテン語 passer（スズメ）から。小鳥全般を指すようになり、英語の passerine（スズメ目の）と同語根です。' },
  'pez': { es: 'Hay un pez de colores en la pecera.', ja: '水槽に色とりどりの魚がいます。', trivia: 'ラテン語 piscis（魚）から。英語の Pisces（うお座）や pescatarian（魚は食べる菜食者）と同語根。料理になると pescado に変わります。' },
  'cielo': { es: 'El cielo está despejado y azul hoy.', ja: '今日は空が晴れて青いです。', trivia: 'ラテン語 caelum（空・天）から。英語の celestial（天の）と同語根で、天国と空の両方を表します。' },
  'grande': { es: 'Viven en una casa muy grande cerca del río.', ja: '彼らは川の近くのとても大きな家に住んでいます。', trivia: 'ラテン語 grandis（大きい・立派な）から。英語の grand（壮大な）や grandiose と同源です。' },
  'pequeño': { es: 'Tengo un problema pequeño con mi ordenador.', ja: '私のパソコンに小さな問題があります。', trivia: '俗ラテン語 pitinnus（小さい）に由来するとされます。英語の petit や petty（ささいな）と発想を共有しています。' },
  'malo': { es: 'Hoy hace muy mal tiempo para salir.', ja: '今日は出かけるにはとても悪い天気です。', trivia: 'ラテン語 malus（悪い）から。英語の malice（悪意）や malaria（もとは「悪い空気」mal aria）と同語根です。' },
  'nuevo': { es: 'Compré un teléfono nuevo la semana pasada.', ja: '先週、新しい電話を買いました。', trivia: 'ラテン語 novus（新しい）から。英語の novel（新しい・小説）や innovate（革新する）と同語根です。' },
  'joven': { es: 'Mi vecino es un joven muy trabajador.', ja: '私の隣人はとても働き者の若者です。', trivia: 'ラテン語 juvenis（若い）から。英語の juvenile（少年の）や junior と同語根です。' },
  'alto': { es: 'Ese edificio es el más alto de la ciudad.', ja: 'あの建物は街で一番高いです。', trivia: 'ラテン語 altus（高い・深い）から。英語の altitude（高度）や altar（祭壇、高い台）と同語根です。' },
  'bajo': { es: 'La mesa es demasiado baja para trabajar.', ja: 'その机は作業するには低すぎます。', trivia: '俗ラテン語 bassus（低い・太い）から。英語の base（低い）や音楽の bass（低音）と同源です。' },
  'largo': { es: 'Fue un viaje muy largo y cansado.', ja: 'それはとても長く疲れる旅でした。', trivia: 'ラテン語 largus（豊富な・寛大な）から。英語の large（大きい）と同源ですが、スペイン語では「長い」の意味に変化しました。' },
  'mismo': { es: 'Vivimos en el mismo barrio desde niños.', ja: '私たちは子どもの頃から同じ地区に住んでいます。', trivia: 'ラテン語 metipsimus（まさにその人自身）から。強調表現が縮まってできた語です。' },
  'general': { es: 'En general, prefiero el té al café.', ja: '一般的に、私はコーヒーより紅茶が好きです。', trivia: 'ラテン語 generalis（種族全体に関わる）から。genus（種・属）が語源で、英語の general や genus と同語根。軍の「将軍」は全軍を率いる者の意味です。' },
  'nacional': { es: 'Mañana es una fiesta nacional en mi país.', ja: '明日は私の国の祝日です。', trivia: 'ラテン語 natio（生まれ・民族）から。動詞 nasci（生まれる）が語源で、英語の nation や native と同語根です。' },
  'político': { es: 'El político prometió bajar los impuestos.', ja: 'その政治家は税金を下げると約束しました。', trivia: 'ギリシャ語 polis（都市国家）から。市民生活に関わることを意味し、英語の police や policy とも同じ根を持ちます。' },
  'posible': { es: 'Es posible que llueva esta tarde.', ja: '今日の午後は雨が降るかもしれません。', trivia: 'ラテン語 posse（できる）から。英語の possible や potent（強力な）と同語根です。' },
  'importante': { es: 'Es muy importante llegar a tiempo a la reunión.', ja: '会議に時間通り着くことはとても重要です。', trivia: 'ラテン語 importare（中に運び込む）から。価値あるものを運び込むという発想で、英語の import（輸入）と同語根です。' },
  'necesario': { es: 'No es necesario traer comida a la fiesta.', ja: 'パーティーに食べ物を持ってくる必要はありません。', trivia: 'ラテン語 necesse（避けられない）から。「譲れないこと」が必要性の意味になり、英語の necessary と同源です。' },
  'diferente': { es: 'Cada persona tiene una opinión diferente.', ja: '人それぞれ異なる意見を持っています。', trivia: 'ラテン語 differre（離して運ぶ・異なる）から。dis（離れて）と ferre（運ぶ）が語源で、英語の different と同源です。' },
  'difícil': { es: 'Este ejercicio de matemáticas es muy difícil.', ja: 'この数学の問題はとても難しいです。', trivia: 'ラテン語 difficilis（容易でない）から。否定の dis と facilis（容易な）が合わさった語で、英語の difficult と同源です。' },
  'fácil': { es: 'Aprender este juego es muy fácil.', ja: 'このゲームを覚えるのはとても簡単です。', trivia: 'ラテン語 facilis（しやすい）から。動詞 facere（する・作る）が語源で、英語の facile や facility と同語根です。' },
  'claro': { es: 'Hoy el cielo está claro y sin nubes.', ja: '今日は空が澄んでいて雲ひとつありません。', trivia: 'ラテン語 clarus（明るい・有名な）から。英語の clear や clarify と同源。相づちの「claro」（もちろん）は「はっきりしている」の意味から来ています。' },
  'cierto': { es: 'Es cierto que el español se habla en muchos países.', ja: 'スペイン語が多くの国で話されているのは本当です。', trivia: 'ラテン語 certus（確定した）から。動詞 cernere（見分ける）が語源で、英語の certain や certificate と同語根です。' },
  'humano': { es: 'El cuerpo humano necesita agua para vivir.', ja: '人間の体は生きるために水を必要とします。', trivia: 'ラテン語 humanus（人間の）から。語根 humus（土、大地）と関連し、「土から生まれた者」が原義。英語の human・humble（謙虚な）も同語根。' },
  'blanco': { es: 'El gato blanco duerme en el sofá.', ja: '白い猫がソファで眠っています。', trivia: 'ゲルマン語 blank（輝く、白い）から。英語の blank（空白）や blink（瞬く）と同語根で、もとは「光り輝く」の意味。' },
  'negro': { es: 'Llevo un abrigo negro en invierno.', ja: '冬は黒いコートを着ます。', trivia: 'ラテン語 niger（黒い）から。英語の negative や、写真の「ネガ」も同じ語根。生物名の Niger 川やナイジェリアの国名にもつながります。' },
  'azul': { es: 'El cielo está muy azul hoy.', ja: '今日は空がとても青いです。', trivia: 'アラビア語 lazaward（瑠璃、ラピスラズリ）由来。英語の azure（紺碧）や鉱物名 lazurite も同語源。スペインがアラビア語の影響を受けた名残です。' },
  'feliz': { es: 'Estoy muy feliz de verte otra vez.', ja: 'あなたにまた会えてとても幸せです。', trivia: 'ラテン語 felix（幸運な、実り豊かな）から。英語の felicity（至福）や女性名 Felicia も同語根。新年の挨拶 ¡Feliz Año! でよく使われます。' },
  'fuerte': { es: 'Mi hermano es muy fuerte y juega al rugby.', ja: '私の兄はとても強くてラグビーをします。', trivia: 'ラテン語 fortis（強い）から。英語の fort（要塞）・force（力）・comfort（慰め、力を与える）と同語根。音楽の forte（強く）も同じ。' },
  'débil': { es: 'Después de la fiebre me siento muy débil.', ja: '熱のあとはとても体が弱く感じます。', trivia: 'ラテン語 debilis（弱い）から。英語の debilitate（衰弱させる）と同語根。借金の debit（負債）とも語源的につながりがあります。' },
  'pobre': { es: 'Esa familia es pobre pero muy generosa.', ja: 'あの家族は貧しいですがとても気前がよいです。', trivia: 'ラテン語 pauper（貧しい）から。英語の poor・poverty・pauper（貧者）と同語根。' },
  'alegre': { es: 'La música hace que la fiesta sea más alegre.', ja: '音楽がパーティーをより陽気にします。', trivia: 'ラテン語 alacer（活発な、機敏な）から。英語の alacrity（機敏さ）と同語根。イタリア語の音楽用語 allegro（速く、陽気に）も同じ。' },
  'bello': { es: 'Madrid tiene un parque muy bello en el centro.', ja: 'マドリードには中心部にとても美しい公園があります。', trivia: 'ラテン語 bellus（かわいい、美しい）から。英語の beauty・beautiful・embellish（飾る）と同語根。女性名 Bella も同じ。' },
  'frío': { es: 'El agua del mar está muy fría en invierno.', ja: '冬は海の水がとても冷たいです。', trivia: 'ラテン語 frigidus（冷たい）から。英語の frigid（極寒の）や冷蔵庫を意味する refrigerator と同語根です。' },
  'lento': { es: 'El tren es más lento que el avión.', ja: '電車は飛行機より遅いです。', trivia: 'ラテン語 lentus（粘り強い、ゆっくりした）から。英語の relent（和らぐ）と同語根。音楽用語の lento（ゆっくりと）もここから来ています。' },
  'caro': { es: 'Este reloj es muy caro para mí.', ja: 'この時計は私には高価すぎます。', trivia: 'ラテン語 carus（大切な、いとしい）から。「大切」が「高価」に転じました。英語の charity（慈愛）や cherish（大切にする）と同語根。' },
  'barato': { es: 'Compré este libro porque era muy barato.', ja: 'この本はとても安かったので買いました。', trivia: '語源は諸説あり、ラテン語 baratto（取引、物々交換）に由来するとされます。イタリア語の baratto（交換）と同根です。' },
  'muy': { es: 'Esta sopa está muy caliente, ten cuidado.', ja: 'このスープはとても熱いので気をつけて。', trivia: 'ラテン語 multum（多く）が縮まった形。同語根の mucho とは兄弟語で、muy は名詞の前では使わず形容詞や副詞を強めます。' },
  'bien': { es: 'Mi abuela cocina muy bien la paella.', ja: '私の祖母はパエリアをとても上手に作ります。', trivia: 'ラテン語 bene（よく）から。英語の benefit（利益）・benevolent（慈悲深い）・benediction（祝福）と同語根。' },
  'mal': { es: 'Hoy he dormido mal y estoy cansado.', ja: '今日はよく眠れなくて疲れています。', trivia: 'ラテン語 male（悪く）から。英語の malice（悪意）・malfunction（故障）・dismal（陰気な）と同語根です。' },
  'más': { es: 'Necesito más tiempo para terminar el trabajo.', ja: '仕事を終えるのにもっと時間が必要です。', trivia: 'ラテン語 magis（より多く）から。英語の major（より大きい）や master と同じ語根 mag-（大きい）につながります。' },
  'menos': { es: 'Hoy hay menos gente en la calle que ayer.', ja: '今日は通りに昨日より人が少ないです。', trivia: 'ラテン語 minus（より少なく）から。英語の minus・minimum・minor と同語根。引き算の記号マイナスもここから来ています。' },
  'mucho': { es: 'Te quiero mucho, mamá.', ja: 'お母さん、大好きだよ。', trivia: 'ラテン語 multus（多い）から。英語の multiple・multitude・multiply と同語根。muy とは同じ語源の兄弟語です。' },
  'poco': { es: 'Hablo un poco de francés.', ja: '私はフランス語を少し話します。', trivia: 'ラテン語 paucus（わずかな）から。英語の paucity（欠乏）や few と同語根。否定の意味合いを持つ少なさを表します。' },
  'tampoco': { es: 'No me gusta el café y el té tampoco.', ja: '私はコーヒーが好きではなく、紅茶もまた好きではありません。', trivia: 'tan（そんなに）+ poco（少し）から。también（〜もまた）の否定版で、「〜もまた…ない」を表します。' },
  'nunca': { es: 'Nunca he estado en Japón.', ja: '私は一度も日本に行ったことがありません。', trivia: 'ラテン語 numquam（決して〜ない）から。nun（今）+ quam（かつて）が原形で、英語の never（ne + ever）と発想がそっくりです。' },
  'ahora': { es: 'Ahora mismo no puedo hablar, estoy ocupado.', ja: '今ちょうど話せません、忙しいのです。', trivia: 'ラテン語 hac hora（この時間に）から。hora は英語の hour（時間）と同語根。文字どおり「この時間に」が「今」になりました。' },
  'luego': { es: 'Termino esto y luego te llamo.', ja: 'これを終えてからあとであなたに電話します。', trivia: 'ラテン語 loco（場所に）から。「その場で」が時間的な「すぐあとで」に転じました。別れの挨拶 ¡Hasta luego!（またあとで）で有名。' },
  'entonces': { es: 'Si llueve, entonces nos quedamos en casa.', ja: 'もし雨が降れば、それなら家にいましょう。', trivia: 'ラテン語 in tunc（その時に）に由来。tunc（その時）はラテン語で、英語の then（その時、それなら）と機能も語感も似ています。' },
  'aquí': { es: 'Aquí hace mucho calor en verano.', ja: 'ここは夏とても暑いです。', trivia: 'ラテン語 eccum hic（ほら、ここに）に由来。hic（ここ）は英語の here とは別系統ですが、近称の指示語として同じ役割を持ちます。' },
  'allí': { es: 'Mi coche está aparcado allí, cerca del banco.', ja: '私の車はあそこ、銀行の近くに停めてあります。', trivia: 'ラテン語 illic（あそこに）から。指示詞 ille（あれ）が語源で、スペイン語の冠詞 el や代名詞 él も同じ語根から生まれました。' },
  'cerca': { es: 'Vivo cerca de la estación de tren.', ja: '私は鉄道の駅の近くに住んでいます。', trivia: 'ラテン語 circa（〜のあたりに、周りに）から。英語の circle（円）や circus（円形競技場）と同語根で、もとは「周囲」の意味でした。' },
  'lejos': { es: 'Mi pueblo está muy lejos de la capital.', ja: '私の村は首都からとても遠いです。', trivia: 'ラテン語 laxus（緩んだ、広がった）から。距離が「広がっている」が「遠い」になりました。英語の lax（緩い）や relax と同語根。' },
  'así': { es: 'No debes hablar así a tu madre.', ja: 'お母さんにそんなふうに話してはいけません。', trivia: 'ラテン語 sic（そのように）から。校正記号の sic（原文ママ）と同じ語。así（このように）で様態を表す基本副詞です。' },
  'casi': { es: 'Casi me caigo en la escalera esta mañana.', ja: '今朝、階段でもう少しで転ぶところでした。', trivia: 'ラテン語 quasi（あたかも〜のように）から。英語でも quasi-（準〜、疑似〜）として学術用語に残っています。「ほとんど」の意味になりました。' },
  'bastante': { es: 'Hace bastante frío para ser primavera.', ja: '春にしてはかなり寒いです。', trivia: '動詞 bastar（足りる）の現在分詞から。「足りている」が「十分に、かなり」になりました。英語の baste とは無関係です。' },
  'temprano': { es: 'Mañana tengo que levantarme muy temprano.', ja: '明日はとても早く起きなければなりません。', trivia: 'ラテン語 temporanus（季節に合った、時宜にかなった）から。tempus（時）が語根で、英語の temporary・tempo と同語源です。' },
  'boca': { es: 'Abre la boca, por favor, dijo el dentista.', ja: '「口を開けてください」と歯医者が言いました。', trivia: 'ラテン語 bucca（頬、口）から。英語の debouch（川が広い所に流れ出る）と同語根。川の「河口」もスペイン語で boca と言います。' },
  'brazo': { es: 'Me duele el brazo derecho después del partido.', ja: '試合のあと右腕が痛いです。', trivia: 'ラテン語 bracchium（腕）から。英語の brace（締め具）・bracelet（腕輪）・embrace（抱きしめる）と同語根です。' },
  'cuello': { es: 'Llevo una bufanda para proteger el cuello.', ja: '首を守るためにマフラーをしています。', trivia: 'ラテン語 collum（首）から。英語の collar（襟）と同語根。シャツの「カラー」は文字どおり「首に巻くもの」でした。' },
  'pie': { es: 'Me he hecho daño en el pie izquierdo.', ja: '左足を痛めてしまいました。', trivia: 'ラテン語 pes, pedis（足）から。英語の pedal・pedestrian（歩行者）・pedicure と同語根。詩の韻律単位 foot（脚韻）とも発想が同じ。' },
  'pierna': { es: 'El futbolista se rompió la pierna en el partido.', ja: 'そのサッカー選手は試合で脚を骨折しました。', trivia: 'ラテン語 perna（ハム、もも肉）から。食用の「もも」が人間の脚を指すようになりました。スペインの生ハム jamón とも縁の深い語源です。' },
  'pelo': { es: 'Mi hermana tiene el pelo largo y rizado.', ja: '私の姉は長くて巻いた髪をしています。', trivia: 'ラテン語 pilus（毛、一本の毛）から。英語の depilatory（脱毛剤）や caterpillar（毛虫、「毛のある猫」が語源）と同語根です。' },
  'nariz': { es: 'Tengo la nariz tapada por el resfriado.', ja: '風邪で鼻が詰まっています。', trivia: 'ラテン語 nasus（鼻）から。英語の nasal（鼻の）や nose と同語根。眼鏡を意味する pince-nez（鼻ばさみ）にも nez として残っています。' },
  'hermano': { es: 'Mi hermano mayor trabaja en un banco en el centro.', ja: '私の兄は市内中心部の銀行で働いています。', trivia: 'ラテン語 germanus（同じ親から生まれた本物の）から。英語の germane（密接に関連した）と同語根。' },
  'oficina': { es: 'La oficina abre a las nueve de la mañana todos los días.', ja: '事務所は毎日朝9時に開きます。', trivia: 'ラテン語 officium（義務・職務）から。英語の office と同語根で、もとは「なすべき仕事」の意味。' },
  'mercado': { es: 'Los sábados voy al mercado a comprar fruta fresca.', ja: '土曜日には新鮮な果物を買いに市場へ行きます。', trivia: 'ラテン語 mercatus（商売・取引）から。英語の market・merchant・commerce はすべて同じ語根 merx（商品）。' },
  'ejemplo': { es: 'El profesor puso un ejemplo claro para explicar la regla.', ja: '先生はその規則を説明するために明確な例を挙げました。', trivia: 'ラテン語 exemplum（見本として取り出したもの）から。英語の example・sample はどちらもこの語が起源。' },
  'hecho': { es: 'El hecho de que llegara tarde sorprendió a todos.', ja: '彼が遅れて来たという事実は皆を驚かせました。', trivia: 'ラテン語 factum（なされたこと）から。動詞 hacer の過去分詞でもあり、英語の fact と同語根。' },
  'modo': { es: 'No me gusta el modo en que habla con sus padres.', ja: '彼が両親に話しかけるやり方が私は好きではありません。', trivia: 'ラテン語 modus（尺度・方法）から。英語の mode・model・modern はすべて同語根。' },
  'relación': { es: 'Ellos tienen una buena relación desde la infancia.', ja: '彼らは子どもの頃から良い関係を保っています。', trivia: 'ラテン語 relatio（持ち戻すこと・関連づけ）から。英語の relation・relative と同語根。' },
  'proyecto': { es: 'Estamos trabajando en un proyecto muy importante este mes.', ja: '私たちは今月とても重要なプロジェクトに取り組んでいます。', trivia: 'ラテン語 proiectum（前へ投げ出されたもの）から。英語の project と同語根で、pro（前へ）＋iacere（投げる）の構造。' },
  'programa': { es: 'Mi programa de televisión favorito empieza a las ocho.', ja: '私のお気に入りのテレビ番組は8時に始まります。', trivia: 'ギリシャ語 programma（公に書き示すもの）から。pro（前に）＋graphein（書く）で、英語の program と同語根。' },
  'producto': { es: 'Este producto se vende muy bien en todo el país.', ja: 'この製品は国中でとてもよく売れています。', trivia: 'ラテン語 productum（前へ導き出されたもの）から。英語の product と同語根で、数学の「積」の意味も共通。' },
  'resultado': { es: 'El resultado del examen fue mejor de lo que esperaba.', ja: '試験の結果は私が期待していたよりも良かったです。', trivia: 'ラテン語 resultare（跳ね返る）から。英語の result と同語根で、もとは「跳ね返ってくるもの」の意味。' },
  'interés': { es: 'Ella muestra mucho interés por la historia antigua.', ja: '彼女は古代史にとても強い関心を示しています。', trivia: 'ラテン語 interest（重要である・間にある）から。英語の interest と同語根で、利子の意味も共通。' },
  'futuro': { es: 'En el futuro quiero vivir cerca del mar.', ja: '将来は海の近くに住みたいです。', trivia: 'ラテン語 futurus（これからあるであろう）から。動詞 esse（ある）の未来分詞で、英語の future と同語根。' },
  'duro': { es: 'El pan de ayer está muy duro y difícil de comer.', ja: '昨日のパンはとても硬くて食べにくいです。', trivia: 'ラテン語 durus（硬い）から。英語の durable・endure・during はすべて同語根で「持ちこたえる」の意味につながる。' },
  'pesado': { es: 'Esta maleta es demasiado pesada para llevarla solo.', ja: 'このスーツケースは一人で運ぶには重すぎます。', trivia: 'ラテン語 pensare（重さを量る）から。英語の pensive（物思いにふける）や pound（重量単位）と語根を共有する。' },
  'profundo': { es: 'El lago es muy profundo en el centro.', ja: 'その湖は中央部分がとても深いです。', trivia: 'ラテン語 profundus（底の深い）から。fundus（底）が語根で、英語の profound・fund と同語根。' },
  'gordo': { es: 'El gato de mi vecina está bastante gordo.', ja: '隣人の猫はかなり太っています。', trivia: 'ラテン語 gurdus（鈍い・のろい）から。スペインの年末宝くじの一等は El Gordo（太っちょ）と呼ばれる文化がある。' },
  'guapo': { es: 'Tu hermano es muy guapo y siempre sonríe.', ja: 'あなたの兄はとても格好よく、いつも笑っています。', trivia: 'フランス語経由のゲルマン語 wapa（ろくでなし）から意味が好転した語。もとは悪い意味だったのが「魅力的」に変化した珍しい例。' },
  'feo': { es: 'El tiempo está muy feo y va a llover pronto.', ja: '天気がとても悪く、もうすぐ雨が降りそうです。', trivia: 'ラテン語 foedus（醜い・汚らわしい）から。天気や状況が「ひどい」という比喩的な使い方も日常的。' },
  'enfermo': { es: 'Hoy no voy a trabajar porque estoy enfermo.', ja: '今日は病気なので仕事に行きません。', trivia: 'ラテン語 infirmus（しっかりしていない）から。in（否定）＋firmus（堅固な）で、英語の infirm・firm と同語根。' },
  'ocupado': { es: 'Esta semana estoy muy ocupado con el trabajo.', ja: '今週は仕事でとても忙しいです。', trivia: 'ラテン語 occupare（つかみ取る・占有する）から。英語の occupy・occupied と同語根。電話中も línea ocupada と言う。' },
  'enviar': { es: 'Voy a enviar este paquete a mi familia mañana.', ja: '明日この小包を家族に送るつもりです。', trivia: 'ラテン語 inviare（道に乗せる）から。in（中へ）＋via（道）で、英語の envoy（使節）と同語根。' },
  'responder': { es: 'Ella no quiso responder a mi pregunta.', ja: '彼女は私の質問に答えようとしませんでした。', trivia: 'ラテン語 respondere（誓い返す・応える）から。re（返して）＋spondere（誓う）で、英語の respond・response と同語根。' },
  'gritar': { es: 'No es necesario gritar, te escucho muy bien.', ja: '叫ぶ必要はありません、よく聞こえています。', trivia: 'ラテン語 quiritare（助けを求めて叫ぶ）から。一説にはローマ市民 Quirites に救いを求める声が語源とされる。' },
  'nadar': { es: 'Me gusta nadar en el mar durante el verano.', ja: '夏の間は海で泳ぐのが好きです。', trivia: 'ラテン語 natare（泳ぐ）から。英語の natatorium（屋内プール）と同語根で、フランス語 nager も同系統。' },
  'saltar': { es: 'El perro puede saltar por encima de la valla.', ja: 'その犬は柵を飛び越えることができます。', trivia: 'ラテン語 saltare（跳ねる・踊る）から。英語の somersault（宙返り）や assault（襲撃）と同語根。' },
  'dormir': { es: 'Los fines de semana me gusta dormir hasta tarde.', ja: '週末は遅くまで寝るのが好きです。', trivia: 'ラテン語 dormire（眠る）から。英語の dormitory（寮）・dormant（休眠中の）と同語根。' },
  'enseñar': { es: 'Mi abuela me enseñó a cocinar platos tradicionales.', ja: '祖母は私に伝統料理の作り方を教えてくれました。', trivia: 'ラテン語 insignare（しるしをつける）から。signum（しるし）が語根で、英語の sign・design と同語根。' },
  'gastar': { es: 'No quiero gastar mucho dinero este mes.', ja: '今月はあまりお金を使いたくありません。', trivia: 'ラテン語 vastare（荒らす・浪費する）から。英語の waste・devastate と同語根で、「使い尽くす」の意味につながる。' },
  'pintar': { es: 'Vamos a pintar las paredes de la cocina de azul.', ja: '台所の壁を青く塗るつもりです。', trivia: 'ラテン語 pingere（描く・彩る）から。英語の paint・picture・pigment はすべて同語根。' },
  'papel': { es: 'Necesito una hoja de papel para escribir una carta.', ja: '手紙を書くために一枚の紙が必要です。', trivia: 'ギリシャ語 papyros（パピルス）から。英語の paper も同語根で、ナイル川の植物パピルスが紙の起源。' },
  'reloj': { es: 'Mi reloj se atrasa unos minutos cada semana.', ja: '私の時計は毎週数分ずつ遅れます。', trivia: 'ラテン語 horologium（時を告げるもの）から。ギリシャ語 hora（時）＋legein（告げる）で、英語の horoscope と語根を共有する。' },
  'hoy': { es: 'Hoy hace mucho calor y el cielo está despejado.', ja: '今日はとても暑く、空は晴れわたっています。', trivia: 'ラテン語 hodie（この日に）から。hoc（この）＋die（日）の縮約で、フランス語 aujourd hui の hui と同源。' },
  'estrella': { es: 'Esta noche se ven muchas estrellas en el cielo.', ja: '今夜は空にたくさんの星が見えます。', trivia: 'ラテン語 stella（星）から。英語の stellar・constellation と同語根で、ギリシャ語 aster（アスタリスク）とも遠い親戚。' },
  'luna': { es: 'La luna llena ilumina todo el campo esta noche.', ja: '満月が今夜、野原全体を照らしています。', trivia: 'ラテン語 luna（月）から。lux（光）が語根で、英語の lunar・lunatic（もとは月の影響で狂うと信じられた）と同語根。' },
  'nube': { es: 'Una nube negra cubrió el sol de repente.', ja: '黒い雲が突然太陽を覆いました。', trivia: 'ラテン語 nubes（雲）から。英語の nuance（もとは雲の濃淡の意味）と同語根という意外なつながりがある。' },
  'rápidamente': { es: 'El tren pasó rápidamente por la estación sin detenerse.', ja: '電車は止まらずに素早く駅を通過した。', trivia: 'ラテン語 rapidus（勢いよく奪う、速い）に副詞語尾 -mente を付けた形で、-mente はラテン語 mens（心・様態）に由来する。英語の rapid と完全に同語根であり、「素早く」を意味する rapidly と対応する。' },
  'a': { es: 'Mañana voy a Madrid a visitar a mis amigos.', ja: '明日、友人たちに会いに行くためにマドリードへ行く。', trivia: 'ラテン語の前置詞 ad（〜へ、〜に向かって）が短縮した形で、英語の at や to に意味上対応する。英語 address（宛先、住所）や adjacent（隣接する）の接頭辞 ad- と同じ起源を持つ。' },
  'abogado': { es: 'El abogado defensor presentó nuevas pruebas ante el juez.', ja: '弁護人は裁判官の前に新たな証拠を提出した。', trivia: 'ラテン語 advocatus（呼び寄せられた者、補佐者）に由来し、ad-（〜へ）と vocare（呼ぶ）の合成語。英語の advocate（擁護者、弁護する）と完全に同語根であり、スペイン語では職業名として定着している。' },
  'abuelo': { es: 'Mi abuelo me enseñó a jugar al ajedrez cuando era niño.', ja: '子どもの頃、祖父がチェスの遊び方を教えてくれた。', trivia: '後期ラテン語 aviolus（おじいさん）が転じた形で、さらに古くは avus（祖父）に縮小辞が付いたもの。英語には直接の同語根語はないが、avuncular（おじのような、親しみやすい）は同じ語根 avus に関連する。' },
  'acción': { es: 'Hay que pasar de las palabras a la acción si queremos cambiar algo.', ja: '何かを変えたいなら、言葉から行動に移さなければならない。', trivia: 'ラテン語 actio（行為、行動）に由来し、agere（行う、動かす）の名詞形。英語の action と完全に同語根の国際的な学習語であり、actor（俳優）や activate（活性化する）とも同じ語根 ag- を持つ。' },
  'alguien': { es: 'Alguien ha dejado una mochila olvidada en el pasillo.', ja: '誰かが廊下にリュックサックを置き忘れていった。', trivia: 'ラテン語 aliquem（誰かを）に由来し、aliquis（ある人）の対格形が変化したもの。英語には直接の対応語はないが、「誰か」を意味する someone や somebody に相当し、語根の ali- は英語の alias（別名）や alibi（不在証明）と同じラテン語 alius（他の）に遡る。' },
  'amar': { es: 'Amamos esta ciudad porque aquí crecimos juntos.', ja: 'この街で一緒に育ったので、私たちはこの街を愛している。', trivia: 'ラテン語 amare（愛する）から直接受け継がれた語で、ロマンス語全体に広がっている。英語の amorous（恋愛の）、amiable（愛想のよい）、amicable（友好的な）などはすべてこの語根 am- を共有しており、amateur（アマチュア）も「愛好者」の意味でつながる。' },
  'amplio': { es: 'El nuevo auditorio tiene un espacio amplio para más de mil personas.', ja: '新しい講堂は千人以上を収容できる広いスペースを持っている。', trivia: 'ラテン語 amplus（広い、豊富な）に由来する。英語の ample（十分な、広い）と完全に同語根であり、amplify（増幅する）や amplitude（振幅、広さ）も同じ語源を持つ。' },
  'aprender': { es: 'Aprendo algo nuevo cada día leyendo libros en español.', ja: 'スペイン語の本を読むことで、毎日何か新しいことを学んでいる。', trivia: 'ラテン語 apprehendere（つかむ、把握する）が変化した形で、ad-（〜へ）と prehendere（つかむ）の合成語。英語の apprentice（見習い）は同語根であり、comprehend（理解する）や apprehend（逮捕する・把握する）も同じ語根 preh- に由来する。' },
  'árbol': { es: 'A la sombra del árbol, los niños jugaban tranquilamente.', ja: '木の影の下で、子どもたちは静かに遊んでいた。', trivia: 'ラテン語 arbor（木、樹木）に由来し、英語の arboreal（樹木の）や arboretum（樹木園）と同語根。英語では tree（ゲルマン語系）が一般的だが、学術語では arbor 系の語が使われ、スペイン語と共通の語根を持つ。' },
  'artículo': { es: 'Leí un artículo muy interesante sobre el cambio climático.', ja: '気候変動についての非常に興味深い記事を読んだ。', trivia: 'ラテン語 articulus（小さな関節、節）に由来し、artus（関節）の縮小形。英語の article と完全に同語根であり、articulate（明確に述べる）や joint の概念ともつながる。文法用語「冠詞」としての用法もラテン語の「小さな部分」という意味から派生した。' },
  'asunto': { es: 'Hay un asunto urgente del que tenemos que hablar hoy mismo.', ja: '今日中に話し合わなければならない緊急の案件がある。', trivia: 'ラテン語 assumptus（引き受けられたもの）、動詞 assumere（引き受ける、取り上げる）の過去分詞に由来する。英語の assume（引き受ける、仮定する）や assumption（仮定、引き受け）と同語根であり、ビジネス場面での「案件・用件」という意味はスペイン語独自の発展といえる。' },
  'atención': { es: 'Presta atención a las instrucciones antes de empezar el examen.', ja: '試験を始める前に指示に注意を払いなさい。', trivia: 'ラテン語 attentio（注意を向けること）に由来し、attendere（〜に向ける）の名詞形。英語の attention と完全に同語根であり、attend（出席する、注意を向ける）や attentive（注意深い）も同じ語源 tend-（伸ばす、向ける）を持つ。' },
  'autobús': { es: 'Perdí el autobús y tuve que esperar media hora en la parada.', ja: 'バスに乗り遅れて、バス停で30分待たなければならなかった。', trivia: 'フランス語 autobus（1906年頃）からの借用語で、ギリシャ語 autos（自分自身）とラテン語 omnibus（すべての人のために）が短縮された bus を合わせた合成語。英語の autobus や bus と同語源であり、automobile（自動車）の auto- と同じギリシャ語由来の語根を持つ。' },
  'autor': { es: 'La autora firmó ejemplares de su nuevo libro durante una hora.', ja: 'その女性作家は一時間にわたって新刊にサインをした。', trivia: 'ラテン語 auctor（創始者、著者、保証人）に由来し、augere（増やす、創り出す）と関連する。英語の author と完全に同語根であり、authority（権威）や authentic（本物の）も同じ語根 aug-/aut- に由来する、意味的に豊かな語族を形成している。' },
  'ayuda': { es: 'Gracias por tu ayuda; no habría podido terminar el proyecto sin ti.', ja: '手伝ってくれてありがとう。あなたなしではプロジェクトを終えられなかった。', trivia: 'ラテン語 adiuta（助けられたもの）に由来し、動詞 adiutare（援助する）の名詞形。英語の aid（援助）は同じラテン語系統の語だが、中世フランス語を経由して英語に入っており、より短縮された形。adjust（調整する）も同語根 iut-/iuv- に遡る説がある。' },
  'banco': { es: 'Fui al banco a sacar dinero y luego me senté en un banco del parque.', ja: '銀行にお金を下ろしに行き、その後公園のベンチに座った。', trivia: 'ゲルマン語 bank（長椅子、台）に由来し、中世イタリア語 banco（両替商の台）を経てスペイン語に入った。英語の bank（銀行、土手）と同語源であり、「銀行」の意味は両替商が台の上で取引したことに由来する。bench（ベンチ）も同じゲルマン語語根から派生している。' },
  'baño': { es: 'Después del entrenamiento, me di un largo baño caliente.', ja: 'トレーニングの後、長い時間をかけて熱いお風呂に入った。', trivia: 'ラテン語 balneum（浴場）がスペイン語で変化した形で、さらに古くはギリシャ語 balaneion に遡る。英語には直接の対応語はなく、bath（ゲルマン語系）が使われるが、学術語 balneology（温泉療法学）がラテン語系の同語根を保っている。' },
  'barco': { es: 'El barco zarpó del puerto al amanecer con rumbo a las islas.', ja: '船は夜明けに港を出発し、島々へ向かった。', trivia: '後期ラテン語 barca（小舟）に由来し、ケルト語またはエジプト語からラテン語に入った可能性があるが語源は諸説ある。英語の bark（詩語で「船」）、barge（はしけ）と同語根とされ、embark（乗船する）や disembark（上陸する）にもこの語根 barc- が残っている。' },
  'basura': { es: 'Por favor, no tires basura en la calle; usa las papeleras.', ja: '道路にゴミを捨てないでください。ゴミ箱を使ってください。', trivia: '語源は諸説あり、アラビア語 buzura（種子、くず）に由来するという説や、ラテン語系という説がある。英語には直接の同語根語は定着しておらず、「ゴミ」は garbage（古フランス語系）や trash（ゲルマン語系）が使われる。スペイン語圏では日常的な基本語として広く定着している。' },
  'bienvenida': { es: 'El director dio una cálida bienvenida a los nuevos estudiantes.', ja: '学長は新入生たちに温かい歓迎の言葉を述べた。', trivia: 'スペイン語 bien（よく）と venida（来ること、到着）の合成語で、bien はラテン語 bene（よく）、venida は venire（来る）の名詞形に由来する。英語の welcome と意味は同じだが語構造は異なり、welcome は「望まれた来訪者」（wil- + cuma）という古英語由来の表現。bene- はラテン語系英語の benefit（利益）や benevolent（善意の）に共通する。' },
  'boleto': { es: 'Compré el boleto de tren en línea con dos semanas de anticipación.', ja: '2週間前にオンラインで電車の切符を購入した。', trivia: 'イタリア語 bolletta（領収書、小切手）を経由したラテン語 bulla（封印、印章）に由来し、中南米スペイン語で広く使われる「切符」の意味を持つ。英語の bulletin（掲示、速報）や bullet（弾丸）も同じ語根 bull- に由来しており、いずれも「丸い印や封印」という原義から発展した語群である。' },
  'bolsa': { es: 'Lleva siempre una bolsa de tela para evitar usar bolsas de plástico.', ja: 'プラスチック袋を使わないように、いつも布バッグを持ち歩いている。', trivia: '中世ラテン語 bursa（財布、袋）に由来し、さらにギリシャ語 byrsa（動物の皮）に遡る。英語の purse（財布）や bourse（証券取引所、フランス語経由）と同語根であり、「袋」から転じた「証券取引所」という意味はアムステルダムの Van der Beurse 一族の名前とも関連するとされる。' },
  'botella': { es: 'Abrió la botella de vino y llenó las copas de los invitados.', ja: '彼はワインのボトルを開けて、招待客のグラスに注いだ。', trivia: '古フランス語 bouteille（瓶）を経由した後期ラテン語 butticula（小樽）に由来し、butta（樽）の縮小形。英語の bottle と完全に同語根の国際語であり、両語ともフランス語経由でラテン語語根 butt-（樽）に遡る。英語の butt（大樽）も同じ語源を持つ。' },
  'breve': { es: 'El discurso fue breve pero muy emotivo y lleno de agradecimiento.', ja: 'スピーチは短かったが、とても感動的で感謝の気持ちにあふれていた。', trivia: 'ラテン語 brevis（短い）に由来し、英語の brief と完全に同語根。abbreviate（短縮する）や brevity（簡潔さ）も同じ語根 brev- を持ち、音楽用語の breve（二全音符）もこの語から来ている。英語 brief はフランス語を経由して入った借用語で、スペイン語 breve とは兄弟語の関係にある。' },
  'caballo': { es: 'Mi abuelo tiene un caballo blanco en su finca.', ja: '祖父は農場に白い馬を一頭持っている。', trivia: 'ラテン語 caballus（労働馬・駄馬）に由来し、古典ラテン語 equus より口語的な語として民衆ラテン語に定着した。英語の cavalry（騎兵隊）やフランス語 cheval と同語根で、英語では horse に相当するが語根自体は異なる。' },
  'cada': { es: 'Cada mañana tomo un café antes de salir de casa.', ja: '毎朝、家を出る前にコーヒーを一杯飲む。', trivia: 'ラテン語の kata（ギリシャ語起源、「〜ごとに」の意）が変化したとされ、英語の each や every に相当する。英語には直接の同語根語はないが、category（カテゴリー）と遠い語源的つながりを持つという説もある。' },
  'caja': { es: 'Guarda todos los documentos importantes en una caja de metal.', ja: '重要な書類はすべて金属の箱に保管している。', trivia: 'ラテン語 capsa（容器・箱）に由来し、英語の case（ケース）やcapsule（カプセル）と同語根である。英語の box に意味は近いが語源は全く異なり、box は古英語 box（つげの木）から来ている。' },
  'cama': { es: 'Los niños deben irse a la cama antes de las nueve.', ja: '子供たちは9時前に寝床に入らなければならない。', trivia: '語源には諸説あり、ラテン語 cama（地面・くぼみ）またはケルト語起源とする説がある。英語の chamber（部屋）とは語根が異なり、英語では bed に相当するが、bed 自体はゲルマン語系で全く別の語源を持つ。' },
  'capaz': { es: 'Estoy segura de que eres capaz de aprobar el examen.', ja: 'あなたは必ず試験に合格できると確信している。', trivia: 'ラテン語 capax（「受け容れることができる」の意、capere「取る・収める」から派生）に由来する。英語の capable と全く同語根であり、意味も用法もほぼ対応する典型的なコグネートペアである。' },
  'carácter': { es: 'Tiene un carácter muy alegre y le cae bien a todos.', ja: '彼女はとても明るい性格で、誰にも好かれている。', trivia: 'ギリシャ語 kharaktēr（刻み込まれた印・記号）がラテン語 character を経て伝わった語で、英語の character と完全に同語根の直系コグネートである。複数形は caracteres で、アクセント位置が変わる点に注意が必要。' },
  'carrera': { es: 'Decidió cambiar de carrera después de diez años como ingeniero.', ja: 'エンジニアとして10年働いた後、キャリアを変えることにした。', trivia: '後期ラテン語 carraria（荷車の通り道）に由来し、動詞 correr（走る）とも関連する。英語の career と同語根で、どちらもラテン語 carrus（荷車）にさかのぼる。英語の race（レース）は別語源（古フランス語 rais）である。' },
  'carta': { es: 'Le escribió una carta de amor a mano, sin usar el correo electrónico.', ja: '電子メールを使わず、手書きのラブレターを彼女に書いた。', trivia: 'ラテン語 charta（紙・文書）に由来し、もとはギリシャ語 khartēs（パピルスの葉）から来ている。英語の chart（図表）や card と同語根であり、「地図」の意味でも carta（carta náutica など）が使われる点が英語の map との違いとして興味深い。' },
  'causa': { es: 'La falta de sueño es una de las principales causas del estrés.', ja: '睡眠不足はストレスの主な原因の一つである。', trivia: 'ラテン語 causa（原因・理由・訴訟）に直接由来し、英語の cause と完全に同語根の典型的なコグネートである。法律用語として「訴訟・事件」の意味もあり、英語の case（法的事件）とも遠い語源的つながりを持つ。' },
  'celebrar': { es: 'Vamos a celebrar el cumpleaños de Ana con una cena especial.', ja: 'アナの誕生日を特別なディナーでお祝いしよう。', trivia: 'ラテン語 celebrare（「大勢が集まる場に行く・称える」）に由来し、celeber（賑やかな・有名な）が語根である。英語の celebrate と完全に同語根の直系コグネートで、celebrity（有名人）とも同じ語源ファミリーに属する。' },
  'central': { es: 'La estación central está en el corazón de la ciudad.', ja: '中央駅は街の中心部にある。', trivia: 'ラテン語 centralis（中心の）に由来し、centrum（中心点）が語根でこれ自体はギリシャ語 kentron（刺す点・コンパスの中心）から来ている。英語の central と完全に同語根のコグネートであり、center/centre とも同じ語源ファミリーである。' },
  'cien': { es: 'Hay más de cien estudiantes inscritos en ese curso.', ja: 'そのコースには100人以上の学生が登録している。', trivia: 'ラテン語 centum（100）に直接由来し、英語の cent（セント、100分の1）や century（世紀）と同語根である。cien は単独または名詞の直前で使い、101以上では ciento になるという独特の変化を持つ。' },
  'ciencia': { es: 'La ciencia ha avanzado enormemente en los últimos cien años.', ja: '科学はここ100年で飛躍的な進歩を遂げた。', trivia: 'ラテン語 scientia（知識・学問）に由来し、scire（知る）が語根である。英語の science と完全に同語根のコグネートで、conscious（意識的な）や prescience（予知）とも同じ語根ファミリーに属する。' },
  'cine': { es: '¿Quieres ir al cine esta noche a ver la nueva película de acción?', ja: '今夜、新しいアクション映画を観に映画館に行かない？', trivia: 'ギリシャ語 kinema（動き）の短縮形 cinematógrafo から来た省略語で、英語の cinema と同語根である。kinema はギリシャ語 kinein（動かす）に由来し、英語の kinetic（運動の）や kinesthesia とも同じ語根ファミリーに属する。' },
  'cita': { es: 'Tengo una cita con el médico mañana a las diez.', ja: '明日10時に医者の予約がある。', trivia: 'ラテン語 citare（「呼び出す・召喚する」、ciere「動かす」の反復形）に由来する。英語の citation（引用・呼び出し）や recite（暗唱する）と同語根であり、「引用」の意味でも使われるのはこの語源と直結している。' },
  'ciudadano': { es: 'Todo ciudadano tiene el derecho y el deber de votar.', ja: 'すべての市民には選挙権と投票する義務がある。', trivia: 'ciudad（都市）＋接尾辞 -ano から成り、ciudad 自体はラテン語 civitas（市民共同体・都市）に由来する。英語の citizen と同語根で、civil（市民の）、civilization（文明）とも同じ語根ファミリーに属する典型的なコグネートである。' },
  'clave': { es: 'La comunicación es la clave para mantener una buena relación.', ja: 'コミュニケーションは良い関係を維持するための鍵である。', trivia: 'ラテン語 clavis（鍵）に由来し、英語の clef（音楽の音部記号）やclavicle（鎖骨、「小さな鍵」の意）と同語根である。英語で「鍵・手がかり」に相当する key はゲルマン語系で全く異なる語源を持ち、語源は異なるが意味が近い好例である。' },
  'cliente': { es: 'El dependiente atendió al cliente con mucha amabilidad.', ja: '店員はその客にとても丁寧に対応した。', trivia: 'ラテン語 cliens（「保護者に依存する者・従者」）に由来し、古代ローマのパトロン＝クライアント制度の用語だった。英語の client と完全に同語根の直系コグネートで、もともとは対等ではなく庇護を受ける側を指す社会的階層概念を含む語である。' },
  'clima': { es: 'El clima de esta región es cálido y húmedo durante todo el año.', ja: 'この地域の気候は一年を通じて温暖で湿度が高い。', trivia: 'ギリシャ語 klima（「傾き・地帯」、ギリシャ人が気候を地球の傾きと結びつけたことに由来）がラテン語を経て伝わった。英語の climate と完全に同語根のコグネートで、climax（クライマックス、もとは「梯子・段階」の意）とも同じ語根に由来する。' },
  'cobrar': { es: 'El fontanero cobró doscientos euros por la reparación.', ja: '配管工は修理代として200ユーロを請求した。', trivia: 'ラテン語 cuperare または recuperare（取り戻す）が変化したとされ、英語の recover（回復する）と語源的つながりを持つという説がある。英語では charge や collect に相当するが、cobrar には「当然受け取るべきものを受け取る」というニュアンスが含まれる。' },
  'cocina': { es: 'La cocina de mi abuela siempre huele a especias y hierbas frescas.', ja: '祖母のキッチンはいつもスパイスと新鮮なハーブの香りがする。', trivia: 'ラテン語 coquina（料理場）に由来し、coquere（煮る・焼く）が語根である。英語の cuisine（料理・キュイジーヌ）と同語根で、cook（料理する・料理人）もこのラテン語語根と関連する。英語の kitchen はゲルマン語系で別語源である。' },
  'cocinar': { es: 'Me encanta cocinar platos nuevos los fines de semana.', ja: '週末に新しい料理を作るのが大好きだ。', trivia: 'cocina（台所・料理）と同じく、ラテン語 coquere（煮る・調理する）に由来する動詞派生形である。英語の cook（動詞）と同語根で、concoct（考案する、もとは「一緒に煮込む」の意）とも同じ語源ファミリーに属する。' },
  'coger': { es: 'Tienes que coger el autobús número 5 para llegar al centro.', ja: '市内中心部に行くには5番のバスに乗る必要がある。', trivia: 'ラテン語 colligere（集める・取る）または capere（取る）の変化形に由来するとされる。英語の collect や capture と遠い語根的つながりがある一方、ラテンアメリカの多くの国では下品な意味を持つため、同地域では tomar や agarrar が好まれる点で有名な語用論的注意語である。' },
  'colegio': { es: 'Mi hijo empezará el colegio el próximo septiembre.', ja: '私の息子は来年9月に小学校に通い始める。', trivia: 'ラテン語 collegium（「同僚の集まり・組合」、com-＋legere「選ぶ」）に由来する。英語の college と完全に同語根のコグネートだが、英語の college が高等教育機関を指すのに対し、スペイン語の colegio は主に初等・中等教育の学校を指す「フォルス・フレンズ（偽の友人）」の典型例である。' },
  'como': { es: 'Habla como si fuera un experto en la materia.', ja: 'まるでその分野の専門家であるかのように話す。', trivia: 'ラテン語の quomodo（「どのようにして」、quo「どのように」＋modo「様式」）が縮約して成立した語とされる。英語の as や like に相当し、英語の how とは語根が遠いが機能が近い。como si＋接続法過去という構文は仮定・比喩表現の定型として重要である。' },
  'cómo': { es: '¿Cómo llegaste tan rápido al aeropuerto?', ja: '空港にそんなに早く着いたのですか？', trivia: 'ラテン語の quomodo（どのような方法で）に由来し、quomo が縮まって como となった。英語の how と意味は同じだが語根は異なり、英語 how はゲルマン語系（古英語 hū）に由来する。' },
  'cómodo': { es: 'Este sillón es tan cómodo que me quedo dormido enseguida.', ja: 'この肘掛け椅子はとても快適で、すぐに眠ってしまいます。', trivia: 'ラテン語 commodus（適切な、好都合な）に由来し、com-（共に）＋ modus（方式、尺度）の合成語。英語の commodious（広くて快適な）や commodity（商品）と同語根で、いずれも「適切に合う」という概念を共有する。' },
  'compañía': { es: 'Fundó su propia compañía de diseño cuando tenía treinta años.', ja: '彼女は30歳のときに自分自身のデザイン会社を設立しました。', trivia: 'ラテン語後期の companio（パンを共にする仲間）から派生し、com-（共に）＋ panis（パン）の合成語。英語の company（会社、仲間）と完全に同語根であり、companion（仲間）も同じ語源を持つ。' },
  'compartir': { es: 'Siempre compartimos los gastos del viaje para que salga más barato.', ja: 'いつも旅費を割り勘にするので、費用が安く上がります。', trivia: 'ラテン語 compartire（分割する）に由来し、com-（共に）＋ partire（分ける）の合成語。英語の share は語根が全く異なるゲルマン語系だが、スペイン語 compartir に近い英語としては impart（与える、伝える）や partition（仕切り）が同じラテン語根 pars/partis を持つ。' },
  'común': { es: 'Es común que los jóvenes usen el transporte público en las grandes ciudades.', ja: '大都市では若者が公共交通機関を利用するのは一般的です。', trivia: 'ラテン語 communis（共有の、公共の）に由来し、com-（共に）＋ munus（義務、贈り物）の合成語。英語の common、community、communicate はすべて同語根であり、「みんなで分かち合う」という基本概念を受け継いでいる。' },
  'comunicación': { es: 'La comunicación efectiva es clave para resolver conflictos en el trabajo.', ja: '職場での対立を解決するには、効果的なコミュニケーションが鍵です。', trivia: 'ラテン語 communicatio（共有すること、伝達）に由来し、communis（共有の）から派生した名詞形。英語の communication と完全に同語根かつ同形に近い典型的な学術的借用語（learned borrowing）であり、両言語でほぼ同義に使われる。' },
  'comunidad': { es: 'La comunidad local se organizó para limpiar el parque del barrio.', ja: '地域のコミュニティが集まって、近所の公園を清掃しました。', trivia: 'ラテン語 communitas（共同体、公共性）に由来し、communis（共有の）に抽象名詞語尾 -itas を付けた形。英語の community と同語根で、スペイン語の語尾 -dad は英語の -ty に対応するロマンス語の規則的な変化である。' },
  'crecer': { es: 'Los niños crecen muy rápido y pronto necesitan ropa nueva.', ja: '子どもはとても早く成長するので、すぐに新しい服が必要になります。', trivia: 'ラテン語 crescere（育つ、増える）に由来し、英語の increase（増加する）や crescent（三日月、増大するもの）と同語根。英語で「成長する」を意味する grow はゲルマン語系で語源が異なるが、accrue（蓄積する）はラテン語経由で同じ crescere に遡る。' },
  'criar': { es: 'Mis abuelos criaron a cinco hijos en una casa pequeña del pueblo.', ja: '私の祖父母は村の小さな家で5人の子どもを育てました。', trivia: 'ラテン語 creare（創造する、育てる）に由来し、英語の create（創る）と同語根。しかし英語では create は「作り出す」という意味が強く、「子どもを育てる」には raise や bring up が使われるため、意味の分岐した興味深いコグネートの例といえる。' },
  'crisis': { es: 'El gobierno tomó medidas urgentes para afrontar la crisis económica.', ja: '政府は経済危機に対処するための緊急措置を講じました。', trivia: 'ギリシャ語 krisis（決定的な転換点、判断）に由来し、krinein（分ける、判断する）から派生した語。英語の crisis と完全に同形・同語源であり、医学や政治の文脈でギリシャ語のまま両言語に借用された。英語の critic、criterion も同語根を持つ。' },
  'cruz': { es: 'En la plaza del pueblo hay una cruz de piedra del siglo XVII.', ja: '村の広場には17世紀の石造りの十字架があります。', trivia: 'ラテン語 crux（十字架、苦悩）に由来し、英語の crucial（決定的な、十字の交差のような）や crucify（十字架にかける）と同語根。英語で「十字架」を意味する cross はゲルマン諸語を経由した同じラテン語 crux からの借用で、音変化の違いが興味深い。' },
  'cruzar': { es: 'Hay que esperar el semáforo verde para cruzar la calle con seguridad.', ja: '安全に道路を渡るには、青信号を待たなければなりません。', trivia: 'ラテン語 crux（十字架）に由来し、「十字に切る・交差させる」という意味から動詞化した語。英語の crucial や cruise（クルーズ、十字形に航行する）と同語根で、cruise ship（クルーズ船）の cruise は「交差しながら航行する」という概念に由来する。' },
  'cuadro': { es: 'Colgamos un cuadro de Picasso en la sala de estar como decoración.', ja: 'リビングルームの装飾としてピカソの絵を飾りました。', trivia: 'ラテン語 quadrum（正方形）に由来し、quattuor（4）と関連する。英語の square（正方形）はフランス語経由の同語根語で、quadrant（四分儀）、quadruple（4倍の）なども同じ quattuor から派生している。「絵画」の意味は「四角い枠」から転じたものである。' },
  'cual': { es: 'Llegué al aeropuerto tarde, lo cual me hizo perder el vuelo.', ja: '空港に遅れて到着し、そのせいで飛行機を乗り逃してしまいました。', trivia: 'ラテン語の関係代名詞 qualis（どのような性質の）に由来し、英語の which、quality と同語根。英語の which はゲルマン語系（古英語 hwelc）で語源が異なるが、quality（質）はラテン語 qualis から来ており、cual と同じ根を持つ。' },
  'cuál': { es: '¿Cuál de los dos candidatos te parece más preparado para el puesto?', ja: '2人の候補者のうち、どちらがそのポストにより適していると思いますか？', trivia: 'アクセント記号のない cual（関係代名詞）と同語源のラテン語 qualis から派生した疑問詞。英語の which と意味的に対応するが語根は異なり、スペイン語では文脈によって qué と cuál を使い分ける必要がある点が英語の which との大きな違い。' },
  'cualquier': { es: 'Puedes llamarme a cualquier hora si necesitas ayuda.', ja: '助けが必要ならいつでも（何時でも）電話してください。', trivia: 'cualquier は cualquiera の語末の -a が名詞前で脱落した形で、cual（ラテン語 qualis）＋ quiera（querer の接続法、望む）の合成語。英語の any（いかなる〜でも）と意味的に対応するが、構造的には英語の whatever に近い「何であれ」という概念を持つ。' },
  'cuando': { es: 'Cuando era niño, pasaba los veranos en casa de mis abuelos.', ja: '子どものころ、夏を祖父母の家で過ごしていました。', trivia: 'ラテン語 quando（いつ、〜するとき）に由来し、疑問詞・接続詞の両方に使われる。英語の when と意味的に完全に対応するが、when は古英語 hwonne に由来するゲルマン語系で語源は異なる。ラテン語 quando は英語で最も近い借用語としては、quandary（窮地、どうしたらよいか迷う状態）に痕跡が見られる。' },
  'cuándo': { es: '¿Cuándo piensas volver a España para visitar a tu familia?', ja: '家族に会いにいつスペインに戻るつもりですか？', trivia: 'cuando と同語源のラテン語 quando に由来し、アクセント記号を加えて疑問詞として機能する。英語の when と意味的に対応するが語根は異なる。スペイン語では同じ語形にアクセント記号の有無で疑問詞と接続詞を区別するという特徴的なシステムを持つ。' },
  'cuanto': { es: 'Tómate cuanto tiempo necesites para tomar una buena decisión.', ja: '良い決断を下すために必要なだけ時間をかけてください。', trivia: 'ラテン語 quantus（どれほどの大きさの）に由来し、量・程度を表す。英語の quantity（量）、quantum（量子）と同語根で、物理学用語の quantum はこのラテン語 quantus から直接借用されたもの。英語の as much as に意味的に対応する。' },
  'cuánto': { es: '¿Cuánto cuesta el billete de tren de Madrid a Barcelona?', ja: 'マドリードからバルセロナまでの電車の切符はいくらですか？', trivia: 'ラテン語 quantus（どれほどの）に由来し、英語の how much / how many に対応する。quantum（量子物理学の基本単位）は同語根であり、Einstein や Planck が用いた「最小の量」という概念にこのラテン語根が使われているのは語源的に自然な選択である。' },
  'cuatro': { es: 'Tenemos cuatro gatos en casa y cada uno tiene su propia personalidad.', ja: '家には猫が4匹いて、それぞれ個性が違います。', trivia: 'ラテン語 quattuor（4）に由来し、英語の four はゲルマン語系（古英語 fēower）で語源は異なるが、英語の quarter（四半期）、quartet（四重奏）、quadrant はラテン語 quattuor から借用されており、スペイン語 cuatro と同語根である。' },
  'cubrir': { es: 'Cubrieron el suelo del jardín con hojas secas para protegerlo del frío.', ja: '寒さから守るために、庭の地面を枯れ葉で覆いました。', trivia: 'ラテン語 cooperire（完全に覆う）に由来し、co-（完全に）＋ operire（覆う）の合成語。英語の cover と完全に同語根で、スペイン語 cubrir と英語 cover は同じラテン語から異なる経路（スペイン語は直接継承、英語はフランス語経由）で借用された。' },
  'cuenta': { es: 'Abrí una cuenta bancaria nueva para gestionar mejor mis ahorros.', ja: '貯金をよりうまく管理するために新しい銀行口座を開設しました。', trivia: 'ラテン語 computare（計算する）に由来し、contar（数える）の名詞形。英語の count（数える）、account（口座、説明する）と同語根で、account の ac- は ad-（〜へ）の変形。「勘定」「口座」「お話（darse cuenta＝気づく）」など多義的に使われる点が興味深い。' },
  'cuento': { es: 'La abuela nos leía un cuento antes de dormir todas las noches.', ja: '祖母は毎晩寝る前にお話を読んでくれました。', trivia: 'ラテン語 computare（計算する）から派生した contar（語る、数える）の名詞形で、cuenta と同語源。英語の recount（詳しく話す）は「再び語る」という意味でこの語根に関連する。「お話・物語」という意味への意味転化は、「言葉を並べて数える＝語る」という概念から生じたとされる。' },
  'cuestión': { es: 'La cuestión más importante es si podremos terminar el proyecto a tiempo.', ja: '最も重要な問題は、プロジェクトを時間内に終えられるかどうかです。', trivia: 'ラテン語 quaestio（尋ねること、調査）に由来し、quaerere（求める、尋ねる）から派生した名詞。英語の question と完全に同語根かつ意味も一致する典型的なロマンス語借用語で、quest（探求）、inquest（審問）、query（問い合わせ）なども同じ quaerere に由来する。' },
  'cuidado': { es: 'Hay que tener mucho cuidado al cruzar esta calle tan transitada.', ja: 'この交通量の多い通りを渡るときは、十分に注意しなければならない。', trivia: 'ラテン語 cogitare（考える）が俗ラテン語 cuitare を経て変化したもので、「気を配ること」が原義。英語の care（注意、世話）とは語根が異なるが意味が近く、英語では be careful や take care に相当する。' },
  'cultura': { es: 'México tiene una cultura muy rica con raíces indígenas y europeas.', ja: 'メキシコは先住民とヨーロッパのルーツを持つ非常に豊かな文化を有している。', trivia: 'ラテン語 cultura（耕作、栽培）に由来し、動詞 colere（耕す）が語源。英語の culture と完全な同語根のコグネートで、スペルも意味もほぼ同じ。農地を「耕す」ことから「心を耕す＝教養・文化」へと意味が拡張された。' },
  'daño': { es: 'El granizo causó grandes daños en los cultivos de la región.', ja: 'ひょうがその地域の農作物に大きな被害をもたらした。', trivia: 'ラテン語 damnum（損失、損害）に由来し、語中の -mn- がスペイン語で -ñ- に変化したもの。英語の damage や damn と同じ語根を持つが、スペイン語では意味が「痛み・損害」に特化している。' },
  'dato': { es: 'Necesito más datos antes de tomar una decisión importante.', ja: '重要な決断を下す前に、もっと多くのデータが必要だ。', trivia: 'ラテン語 datum（与えられたもの）の単数形に由来し、「与えられた事実・情報」が原義。英語の data はラテン語 datum の複数形 data がそのまま使われているが、スペイン語では dato が単数、datos が複数形となる。' },
  'de': { es: 'Soy de Japón, pero ahora vivo en España desde hace tres años.', ja: '私は日本出身ですが、今はスペインに3年間住んでいます。', trivia: 'ラテン語前置詞 de（〜から、〜について）がそのまま受け継がれたもの。英語の of や from に相当する多機能な前置詞で、英語の de- という接頭辞（descend, depart など）もこれと同源。最も頻度の高いスペイン語単語の一つである。' },
  'decisión': { es: 'Fue una decisión muy difícil, pero al final elegí quedarme en mi país.', ja: '非常に難しい決断だったが、最終的に自国に残ることを選んだ。', trivia: 'ラテン語 decisio（切り決めること）に由来し、de-（完全に）＋ caedere（切る）が語源。英語の decision と完全な同語根コグネートで、スペルも非常に近い。「刀で切り落とすように決める」という鮮やかなイメージが語源にある。' },
  'dedicar': { es: 'Elena dedica tres horas al día al estudio del español.', ja: 'エレナは毎日3時間をスペイン語の学習に費やしている。', trivia: 'ラテン語 dedicare（捧げる、宣言する）に由来し、de-＋dicare（宣言する、示す）が語源。英語の dedicate と同語根の近似コグネートで、意味も用法もほぼ同じ。英語 indicate（指示する）や abdicate（退位する）とも遠い語根を共有する。' },
  'defender': { es: 'El abogado defendió a su cliente con argumentos muy convincentes.', ja: '弁護士は非常に説得力のある論拠でクライアントを弁護した。', trivia: 'ラテン語 defendere（守る、防ぐ）に由来し、de-（から離す）＋fendere（打つ、突く）が語源。英語の defend と完全な同語根コグネートで、offense/defense の対概念もスペイン語の ataque/defensa と対応する。' },
  'defensa': { es: 'La defensa del medioambiente es una responsabilidad de todos los ciudadanos.', ja: '環境の保護はすべての市民の責任だ。', trivia: 'ラテン語 defensus（守られた）の名詞形に由来し、defender と同じ語根を持つ。英語の defense（米）/ defence（英）と完全な同語根コグネートで、スポーツ・法律・軍事など多分野で対応する意味を持つ。' },
  'definir': { es: 'Es difícil definir con exactitud qué es la felicidad.', ja: '幸福とは何かを正確に定義するのは難しい。', trivia: 'ラテン語 definire（境界を定める）に由来し、de-（完全に）＋finire（終わらせる、境界を設ける）が語源。英語の define と完全な同語根コグネートで、finish や final と同じ語根 finis（端、境界）を共有する。' },
  'definitivo': { es: 'Todavía no hay una respuesta definitiva sobre las causas del accidente.', ja: '事故の原因についてはまだ確定的な回答が出ていない。', trivia: 'ラテン語 definitivus（境界を定めた）に由来し、definire と同語根。英語の definitive と完全な同語根コグネートで、academic writing などで同じように「最終的・決定的」の意味で使われる。' },
  'del': { es: 'El precio del café ha subido mucho en los últimos meses.', ja: 'ここ数ヶ月でコーヒーの値段がかなり上がった。', trivia: '前置詞 de と定冠詞 el が縮約した形で、スペイン語に固有の現象（同様に a + el = al も存在する）。英語には冠詞の縮約形は存在せず、of the や from the が分離したまま使われる点がスペイン語との大きな文法的違いの一つ。' },
  'demás': { es: 'Tú puedes irte ya; los demás nos quedamos a terminar el trabajo.', ja: 'あなたはもう行っていい。残りの人たちは仕事を終わらせるためにここに残る。', trivia: '前置詞 de と副詞 más（もっと）が結合した語で、「それ以上のもの＝残り」という意味を持つ。英語の the others や the rest に相当し、英語の besides（それ以外に）にも意味が近い。' },
  'democracia': { es: 'La democracia requiere la participación activa de todos los ciudadanos.', ja: '民主主義はすべての市民の積極的な参加を必要とする。', trivia: 'ギリシャ語 demokratia（デーモクラティア）に由来し、demos（民衆）＋kratos（力、支配）が語源。英語の democracy と完全な同語根コグネートで、epidemic の epi-demos（民衆に広がる）の demos とも同語根。' },
  'demostrar': { es: 'El científico demostró su teoría con experimentos rigurosos.', ja: 'その科学者は厳密な実験で自分の理論を証明した。', trivia: 'ラテン語 demonstrare（指し示す、証明する）に由来し、de-＋monstrare（見せる、指示する）が語源。英語の demonstrate と完全な同語根コグネートで、monster（怪物）や monstrous とも語根 monstrare を共有する——「見せびらかすもの」が怪物の原義。' },
  'dentro': { es: 'Deja los zapatos fuera y entra dentro de la casa.', ja: '靴を外に置いて、家の中に入りなさい。', trivia: 'ラテン語 de intro（内側から）が縮約したもので、intro（内部）が語源。英語の interior や introduce の intro- と同語根を持つ。英語では inside や within に相当するが、スペイン語の dentro de は英語の inside of と構造的によく対応する。' },
  'departamento': { es: 'Mi departamento tiene dos habitaciones y una vista al mar.', ja: '私のアパートには2部屋と海への眺めがある。', trivia: 'フランス語 département に由来し、ラテン語 de-＋partire（分ける）が語源。英語の department と完全な同語根コグネートで、part や partition とも同語根。中南米では日本語の「マンション・アパート」に相当するが、スペイン本国では piso が一般的。' },
  'depender': { es: 'El éxito del proyecto depende del trabajo en equipo.', ja: 'プロジェクトの成功はチームワーク次第だ。', trivia: 'ラテン語 dependere（ぶら下がる、依存する）に由来し、de-（下に）＋pendere（ぶら下がる）が語源。英語の depend と完全な同語根コグネートで、pendant（ペンダント）や pendulum（振り子）とも同語根——「何かにぶら下がっている」という物理的イメージが比喩的に「依存」へと発展した。' },
  'deporte': { es: 'El fútbol es el deporte más popular en casi toda América Latina.', ja: 'サッカーはラテンアメリカのほぼ全土で最も人気のあるスポーツだ。', trivia: '古スペイン語 deportarse（気晴らしをする）に由来し、de-＋portar（運ぶ）つまり「日常から心を別の場所へ運び去ること」が原義。英語の sport はフランス語 desporter から来ており、スペイン語の deporte と実は同語根——どちらも「気晴らし」という意味から発展した。' },
  'deportivo': { es: 'Prefiero llevar ropa deportiva cuando salgo a caminar por las mañanas.', ja: '朝の散歩に出かけるときはスポーツウェアを着るほうが好きだ。', trivia: 'deporte に形容詞語尾 -ivo を付けたもので、ラテン語 -ivus（〜に関係する）が語源。英語では sporting や athletic に相当し、英語の sportive（古・詩的な「活発な」）とも遠い同語根関係にある。' },
  'derecho': { es: 'Todos los ciudadanos tienen derecho a la educación gratuita.', ja: 'すべての市民には無償教育を受ける権利がある。', trivia: 'ラテン語 directus（まっすぐにされた）に由来し、dirigere（導く、まっすぐにする）が語源。英語の direct や direction と同語根で、「まっすぐ」→「正しい」→「権利・法律」と意味が拡張した。英語では right が「右」と「権利」を兼ねるのと平行的に、スペイン語でも derecho が同じ二役を担う。' },
  'desaparecer': { es: 'El sol desapareció detrás de las nubes y empezó a llover.', ja: '太陽が雲の後ろに隠れて、雨が降り始めた。', trivia: 'des-（否定・逆転）＋aparecer（現れる）から成り、aparecer はラテン語 apparere（現れる）に由来。英語の disappear と完全な同語根コグネートで、意味もスペルの構造もほぼ同じ。appear の語根 parere（見える）は英語の apparent（明らかな）とも共通する。' },
  'desarrollar': { es: 'El gobierno planea desarrollar nuevas infraestructuras en las zonas rurales.', ja: '政府は農村地帯に新しいインフラを整備する計画を立てている。', trivia: 'des-＋arrollar（巻く）から成り、「巻かれたものを広げる＝展開する」が原義。arrollar はラテン語 rotulus（小さな巻き物）に由来し、英語の roll と同語根。英語の develop はフランク語 voloper（包む）に由来する別語根だが、「包んだものを開く」という比喩的意味は共通している。' },
  'desarrollo': { es: 'El desarrollo económico sostenible es clave para reducir la pobreza.', ja: '持続可能な経済発展は貧困を削減するための鍵だ。', trivia: '動詞 desarrollar の名詞形で、語源は同じく des-＋arrollar（巻く）。英語の development に相当し、国際開発の文脈では「途上国」を países en (vías de) desarrollo と表現するが、これは英語の developing countries にほぼ対応する表現である。' },
  'descansar': { es: 'Después de tanto trabajo, necesito descansar un poco antes de seguir.', ja: 'これだけ仕事をした後は、続ける前に少し休む必要がある。', trivia: 'des-＋cansar（疲れさせる）から成り、「疲れを取り除く」が原義。cansar はラテン語 campsare（曲がる、疲れる）または語源諸説あり。英語に直接の同語根語はなく、rest や relax が意味上の対応語。英語では「疲れ」を表す tire がゲルマン語系であるのに対し、スペイン語の cansado（疲れた）はラテン語系という違いがある。' },
  'descanso': { es: 'Después de caminar durante tres horas, necesitamos un descanso.', ja: '3時間歩いた後、私たちは休憩が必要だ。', trivia: 'ラテン語の動詞 *quassare*（揺さぶる）ではなく、*cantus*（縁）に由来するという説もあるが、現代スペイン語では動詞 descansar（休む）の名詞形として定着している。英語の rest に意味が対応し、「de-+cansar（疲れさせる）」という構造から「疲れを除く」ことを表す。' },
  'desear': { es: 'Te deseo mucha suerte en el examen de mañana.', ja: '明日の試験で幸運を祈っています。', trivia: 'ラテン語 *desiderare*（星を見ながら望む；de- + sidus「星」）に由来し、英語の desire と完全な同語根の関係にある。もともと「夜空の星を眺めて切望する」という詩的なニュアンスを持っていた。' },
  'deseo': { es: 'Mi mayor deseo es viajar por todo el mundo.', ja: '私の一番の願いは世界中を旅することだ。', trivia: '動詞 desear と同じくラテン語 *desiderare* に由来し、英語の desire（名詞）と同語根。英語 desire・スペイン語 deseo はともにロマンス語を通じて「切望・欲望」という意味で生き続けている。' },
  'desgracia': { es: 'Por desgracia, el vuelo fue cancelado por la tormenta.', ja: '残念なことに、嵐のためフライトがキャンセルされた。', trivia: 'ラテン語 *gratia*（恵み・感謝）に否定の接頭辞 des- が付いた語で、「恵みがない状態」を意味する。英語の disgrace（不名誉・恥）と同語根だが、スペイン語の desgracia は「不運・災難」という意味が強く、必ずしも道徳的な汚名を含まない点が異なる。' },
  'despacho': { es: 'El director estaba en su despacho revisando los informes.', ja: 'ディレクターは執務室で報告書を確認していた。', trivia: '動詞 despachar（処理する・発送する）の名詞形で、ラテン語の *impedicare*（妨げる）から派生した *espachar* が語源とも言われ、語史は複雑である。英語の dispatch（派遣・急送）と同語根で、「迅速に処理する場所」という元の意味が「執務室・書斎」へと転じた。' },
  'despertar': { es: 'El ruido de la calle me despertó a las seis de la mañana.', ja: '通りの騒音のせいで、朝6時に目が覚めた。', trivia: 'ラテン語 *expertus* ではなく、*ex-* + *vigilare* に関連するという説もあるが、一般的には *dis-* + *expertare* に由来するとされる。英語に直接の同語根語はないが、意味的には wake（up）または arouse に相当し、反射的に用いると despertarse（目が覚める）となる。' },
  'después': { es: 'Primero termina la tarea y después puedes salir a jugar.', ja: 'まず宿題を終わらせてから、その後で遊びに行っていい。', trivia: 'ラテン語 *de post*（〜の後ろから）が縮約した語で、*de*（〜から）+ *post*（後ろ）の構造を持つ。英語の after や then に意味が対応し、英語の postpone（延期する）に含まれる post- と同じラテン語要素を語源に持つ。' },
  'destino': { es: 'El tren con destino a Barcelona saldrá en cinco minutos.', ja: 'バルセロナ行きの列車は5分後に出発します。', trivia: 'ラテン語 *destinare*（固定する・定める）に由来し、英語の destination と同語根の完全な対応語である。さらに de- + *stare*（立つ）という構造から、「あらかじめ定められた場所・運命」という二重の意味を持つ点が特徴的だ。' },
  'detalle': { es: 'Me gusta que este restaurante cuide tanto los detalles de presentación.', ja: 'このレストランが盛り付けの細部までこだわっているのが気に入っている。', trivia: 'フランス語 *détail* を経由してスペイン語に入った語で、もとはラテン語 *taliare*（切り分ける）に由来する。英語の detail と完全に同語根であり、「細かく切り分けられた部分」という原義から「詳細・細部」という意味が生まれた。' },
  'detener': { es: 'La policía detuvo al sospechoso cerca del aeropuerto.', ja: '警察は空港近くで容疑者を逮捕した。', trivia: 'ラテン語 *detinere*（引き留める）に直接由来し、de-（強意）+ *tenere*（保持する）の構造を持つ。英語の detain（拘留する）と同語根の対応語で、どちらも「人や物を引き留める」という意味を保持している。' },
  'determinar': { es: 'El médico necesita hacer más pruebas para determinar la causa de la enfermedad.', ja: '医師は病気の原因を特定するためにさらに検査を行う必要がある。', trivia: 'ラテン語 *determinare*（境界を定める）に由来し、de- + *terminus*（境界・終点）の構造を持つ。英語の determine と完全に同語根であり、「終点を定める→決定する」という意味の発展も両言語で平行している。' },
  'diario': { es: 'Escribo en mi diario personal todos los días antes de dormir.', ja: '寝る前に毎日個人の日記を書いている。', trivia: 'ラテン語 *diarius*（日ごとの）に由来し、*dies*（日）が語根である。英語の diary（日記）と同語根の対応語であり、形容詞「毎日の」と名詞「日記・日刊紙」の両義を持つ点も英語の daily / diary と同様の意味展開をたどっている。' },
  'dice': { es: 'Mi abuela siempre dice que la paciencia es una virtud.', ja: '私の祖母はいつも忍耐は美徳だと言っている。', trivia: '動詞 decir（言う）の直説法現在三人称単数形で、ラテン語 *dicere*（言う）に由来する。英語の diction（発語・語法）や dictate と同語根であり、また英語の say・tell に意味的に対応する語として最もよく使われる基本動詞の一つだ。' },
  'diciembre': { es: 'En diciembre hace mucho frío en la mayor parte de España.', ja: '12月はスペインのほとんどの地域でとても寒い。', trivia: 'ラテン語 *December* に由来し、*decem*（10）が語根である。かつてローマ暦では3月が年の始まりだったため「10番目の月」だったが、後に1月・2月が加えられ12月目になった。英語の December と同語根で、英語の ten（10）やギリシャ語 *deka* とも同じインド・ヨーロッパ語族の語根を共有する。' },
  'diente': { es: 'Al niño se le cayó el primer diente de leche.', ja: 'その子どもは初めての乳歯が抜けた。', trivia: 'ラテン語 *dens / dentis*（歯）に由来し、英語の dental（歯の）、dentist（歯科医）と同語根である。英語では tooth（歯そのもの）と dental（歯に関する形容詞）が語根の違いで区別されるが、スペイン語では diente という一語が日常語と専門語を兼ねる。' },
  'diferencia': { es: 'Hay una gran diferencia entre saber inglés y hablarlo con fluidez.', ja: '英語を知っていることと流暢に話せることには大きな違いがある。', trivia: 'ラテン語 *differentia* に由来し、*dis-*（分離）+ *ferre*（運ぶ）という構造を持つ。英語の difference と同語根の対応語で、「異なる方向へ運ばれる」という原義から「違い・差異」の意味が生まれた。' },
  'dificultad': { es: 'Tuvimos muchas dificultades para encontrar un taxi durante la huelga.', ja: 'ストライキの間、タクシーを見つけるのにずいぶん苦労した。', trivia: 'ラテン語 *difficultas* に由来し、*dis-* + *facilis*（容易な）という構造から「容易でないこと」を意味する。英語の difficulty と同語根の対応語であり、さらに *facilis* は *facere*（する・作る）に由来し、英語の facile・facility とも遠い親戚関係にある。' },
  'dios': { es: 'En la mitología griega, Zeus era el dios del cielo y del trueno.', ja: 'ギリシャ神話において、ゼウスは空と雷の神であった。', trivia: 'ラテン語 *deus*（神）に由来し、インド・ヨーロッパ語族の語根 *dyeu-*（光る・空）に遡る。英語の deity（神性）や divine（神聖な）と同語根であり、また曜日 Tuesday の Tue- もゲルマン語派の同じ語根から来ているという遠縁の関係がある。' },
  'dirección': { es: '¿Me puedes dar la dirección exacta del hotel para llegar en taxi?', ja: 'タクシーで行けるよう、ホテルの正確な住所を教えてもらえますか？', trivia: 'ラテン語 *directio*（まっすぐにすること）に由来し、*dirigere*（導く・まっすぐにする）の名詞形である。英語の direction と同語根の対応語で、「住所・方向・管理・演出」という多義性も英語の direction と共通している。' },
  'directo': { es: 'El programa se emitió en directo desde la Plaza Mayor.', ja: 'その番組はマヨール広場から生放送された。', trivia: 'ラテン語 *directus*（まっすぐにされた）に由来し、*dirigere* の過去分詞形である。英語の direct と同語根の対応語であり、「en directo」は英語の live broadcast（生放送）に相当するイディオムとして特によく使われる表現だ。' },
  'director': { es: 'La directora del colegio organizó una reunión con los padres.', ja: '学校の校長が保護者との会議を開いた。', trivia: 'ラテン語 *director*（導く者）に由来し、*dirigere*（導く）の行為者名詞形である。英語の director と同語根の対応語で、スペイン語では学校長・会社役員・映画監督など広い職種に使われる点も英語の director と共通している。' },
  'disco': { es: 'Mi padre todavía guarda sus discos de vinilo de los años setenta.', ja: '父はまだ70年代のレコード（ビニール盤）を保管している。', trivia: 'ラテン語 *discus*（円盤）を経由し、さらにギリシャ語 *diskos*（投擲用の円盤）に遡る語で、英語の disk / disc と同語根である。古代オリンピックの円盤投げで使われた diskos が、レコード・CDから「ディスコ（ダンスホール）」まで意味を広げた点が興味深い。' },
  'discusión': { es: 'Tuvieron una discusión muy acalorada sobre política en la cena.', ja: '夕食の席で、彼らは政治について白熱した議論をした。', trivia: 'ラテン語 *discussio*（調査・検討）に由来し、*discutere*（打ち砕いて調べる；dis- + quatere「揺さぶる」）の名詞形である。英語の discussion と同語根の対応語だが、スペイン語では「口論・言い争い」という否定的なニュアンスも強く、英語の argument に近い使い方をする場合も多い。' },
  'discutir': { es: 'Los socios discutieron durante horas antes de llegar a un acuerdo.', ja: 'パートナーたちは合意に達するまで何時間も議論した。', trivia: 'ラテン語 *discutere*（打ち砕いて検討する）に由来し、英語の discuss と同語根の対応語である。ただし英語の discuss が中立的な「話し合う」を意味するのに対し、スペイン語の discutir は「言い争う・口論する」というネガティブな意味合いを持つことが多く、いわゆる「偽の友人（falso amigo）」に注意が必要だ。' },
  'distancia': { es: 'La distancia entre Madrid y Barcelona es de unos 620 kilómetros.', ja: 'マドリードとバルセロナの距離は約620キロメートルだ。', trivia: 'ラテン語 *distantia*（離れて立つこと）に由来し、*dis-* + *stare*（立つ）という構造を持つ。英語の distance と同語根の対応語であり、「a distancia」（遠距離で）は英語の at a distance / remotely に対応する慣用句として使われる。' },
  'distinto': { es: 'Los dos hermanos tienen caracteres muy distintos aunque crecieron juntos.', ja: 'その二人の兄弟は一緒に育ったにもかかわらず、まったく異なる性格を持っている。', trivia: 'ラテン語 distinctus（分けられた）から派生し、動詞 distinguere（区別する）が語源。英語の distinct や distinguish と同語根で、意味もほぼ同じである。' },
  'diversión': { es: 'La diversión principal de los niños durante el verano era ir a la piscina.', ja: '夏の間、子どもたちの主な楽しみはプールに行くことだった。', trivia: 'ラテン語 diversio（気をそらすこと）から来ており、divertere（方向を変える）が語源。英語の diversion と同語根で、英語でも「娯楽・気晴らし」の意味を持つ。' },
  'divertido': { es: 'La obra de teatro fue tan divertida que el público no paró de reírse.', ja: 'その舞台はとても面白くて、観客は笑いが止まらなかった。', trivia: '動詞 divertir（楽しませる）の過去分詞が形容詞化したもので、ラテン語 divertere が語源。英語では「楽しい」に相当する語として fun や amusing が使われ、直訳の diverting は「気晴らしになる」という少し古風な意味で用いられる。' },
  'divertir': { es: 'A mi abuela le divierte mucho ver a sus nietos jugar en el jardín.', ja: '祖母は庭で孫たちが遊ぶのを見るのがとても楽しみだ。', trivia: 'ラテン語 divertere（方向を変える・そらす）から来た語幹変化動詞（e→ie）。英語の divert と同語根で、英語では「注意をそらす・迂回させる」という意味が中心だが、スペイン語では「楽しませる」という意味が主となっている点が興味深い。' },
  'dividir': { es: 'La maestra pidió a los alumnos que dividieran la clase en grupos de cuatro.', ja: '先生は生徒たちに、クラスを4人のグループに分けるよう求めた。', trivia: 'ラテン語 dividere（分ける）が語源で、英語の divide と完全に同語根・同意味のコグネートである。数学の「割り算」も表し、英語の division に対応するスペイン語 división も同じ語根を持つ。' },
  'divorcio': { es: 'Después del divorcio, los dos decidieron seguir siendo buenos amigos por el bien de sus hijos.', ja: '離婚の後、二人は子どもたちのために良い友人関係を続けることを決めた。', trivia: 'ラテン語 divortium（分かれ道・別離）から来ており、divertere（方向を変える）が語根。英語の divorce と同語根・同意味であり、形がほぼ同じであるため典型的なコグネートの例として挙げられる。' },
  'doble': { es: 'Quiero un café doble, por favor; el normal no me despierta bien.', ja: 'ダブルのコーヒーをお願いします。普通のだとよく目が覚めなくて。', trivia: 'ラテン語 duplus（2倍の）から派生し、duo（2）が語根。英語の double と同語根・同意味のコグネートで、語形も非常に近い。英語 double のように動詞としても使える（doblar）点も共通している。' },
  'doce': { es: 'La reunión comienza a las doce del mediodía, así que no llegues tarde.', ja: '会議は正午12時に始まるから、遅刻しないようにね。', trivia: 'ラテン語 duodecim（十二）から来ており、duo（2）＋decem（10）の合成語。英語の twelve はゲルマン語系で語根が異なるが、フランス語経由の dozen（ダース・12個）はラテン語 duodecim と同系統である。' },
  'doctor': { es: 'El doctor me recomendó descansar al menos una semana antes de volver al trabajo.', ja: '医者は仕事に戻る前に少なくとも1週間は休むよう勧めてくれた。', trivia: 'ラテン語 doctor（教える人）から来ており、docere（教える）が語源。英語の doctor と完全に同語根・同形のコグネートで、元々は「博士・学識者」を意味し、後に医師の意味でも使われるようになった。英語の docile（従順な）や document も同じ語根を持つ。' },
  'dolor': { es: 'Tengo un fuerte dolor de cabeza desde esta mañana y no puedo concentrarme.', ja: '今朝からひどい頭痛がして、集中できない。', trivia: 'ラテン語 dolor（痛み・悲しみ）が語源で、dolere（痛む）から派生。英語では直接の対応語はないが、英語の condolence（お悔やみ）やスペイン語名 Dolores（痛みの聖母）に同じ語根が見られる。英語では pain または ache に相当する。' },
  'domingo': { es: 'El domingo por la mañana suelo ir al mercado con mi familia.', ja: '日曜日の朝は、家族と一緒に市場へ行くことが多い。', trivia: 'ラテン語 dies Dominica（主の日）から来ており、Dominus（主・神）が語源。英語の Sunday はゲルマン語で「太陽の日」を意味し、語根が全く異なる。スペイン語では週の名称がほぼすべてラテン語の惑星・神名に由来する点が英語との大きな違いである。' },
  'donde': { es: 'Este es el parque donde nos conocimos hace diez años.', ja: 'ここが10年前に私たちが出会った公園だ。', trivia: 'ラテン語 de unde（そこから）が縮約した語で、英語の where に意味・用法が対応する関係副詞。英語の where はゲルマン語系で語根が異なるが、どちらも場所を導く接続詞・関係副詞として機能する点で用法上の対応が明確である。' },
  'dónde': { es: '¿Dónde pusiste las llaves? No las encuentro por ningún lado.', ja: '鍵をどこに置いたの？どこにも見つからないんだけど。', trivia: 'donde と同じくラテン語 de unde を語源とするが、アクセント符号（tilde）をつけることで疑問詞・感嘆詞として区別される。英語の where に対応し、スペイン語では donde（関係副詞）と dónde（疑問詞）を書き分けるルールが英語にない特徴的な点である。' },
  'dormitorio': { es: 'Mi dormitorio es pequeño, pero tiene una ventana grande con una vista bonita.', ja: '私の寝室は狭いが、きれいな景色が見える大きな窓がある。', trivia: 'ラテン語 dormitorium（眠る場所）から来ており、dormire（眠る）が語源。英語の dormitory と同語根・同形のコグネートだが、英語では主に「学生寮」を指し、「個人の寝室」には bedroom を使う点でずれがある典型的な false friend（偽の友）の一例。' },
  'dos': { es: 'Necesito dos entradas para el concierto del sábado.', ja: '土曜日のコンサートのチケットが2枚必要だ。', trivia: 'ラテン語 duo（2）から来ており、英語の two はゲルマン語系で語根が異なる。しかし英語の dual、duet、duplex などラテン語経由の英単語は同じ duo を語根に持ち、スペイン語の dos との共通の祖先を持つ。' },
  'duda': { es: 'Si tienes alguna duda sobre el examen, no dudes en preguntarme.', ja: '試験について何か疑問があれば、遠慮なく聞いてください。', trivia: 'ラテン語 dubitare（疑う）を語源とし、dubius（二つに迷う）から派生。英語の doubt と同語根のコグネートで、英語の doubt の b は発音されないが、スペイン語では消えている点が興味深い歴史的変化を示している。' },
  'dudar': { es: 'No deberías dudar de tu capacidad; tienes todo lo necesario para lograrlo.', ja: '自分の能力を疑うべきではない。成功するために必要なものはすべて持っている。', trivia: 'ラテン語 dubitare（疑う・迷う）から来た動詞で、英語の doubt と同語根。英語では doubt は名詞・動詞両方に使うが、スペイン語では名詞 duda と動詞 dudar を別語形で区別する。英語の dubious（疑わしい）とも同じ語根を持つ。' },
  'dueño': { es: 'El dueño del restaurante salió personalmente a saludar a todos los clientes.', ja: 'レストランのオーナーが直接すべての客に挨拶するために出てきた。', trivia: 'ラテン語 dominus（主人・支配者）から来ており、英語の domain、dominant、dominate と同語根。英語に直接対応する単語はなく、owner または landlord に相当するが、どちらもゲルマン語系で語根が異なる。' },
  'durante': { es: 'Durante las vacaciones, viajamos por toda la costa mediterránea.', ja: '休暇の間、私たちは地中海沿岸を旅した。', trivia: 'ラテン語 durare（続く・持続する）の現在分詞 durantem から来た前置詞で、英語の during と意味・用法が完全に対応する。英語の during もラテン語 durare から来ており、両語は同語根のコグネートである。英語の endure（耐え続ける）も同じ語根を持つ。' },
  'e': { es: 'Habla inglés e italiano con fluidez.', ja: '彼女は英語とイタリア語を流暢に話す。', trivia: '接続詞 y（そして）が、次の語が i または hi で始まる場合に e に変化したもの。この音変化はラテン語 et（そして）に由来する歴史的な規則であり、英語の and に相当するが、英語にはこのような母音衝突回避の変形ルールは存在しない。' },
  'echar': { es: 'Echa un poco más de sal a la sopa; todavía le falta sabor.', ja: 'スープにもう少し塩を入れて。まだ味が足りない。', trivia: 'ラテン語 iactare（投げる）が語源とされるが、語形の変化については諸説あり、vulgar Latin の jactare からの変化とも考えられている。英語の jet（噴射する）や jettison（投棄する）と同語根の可能性があるが、確定的ではない。英語に対応する単語は文脈によって throw、pour、kick out など多岐にわたる。' },
  'edad': { es: 'A su edad, es admirable que todavía corra maratones.', ja: 'その年齢でまだマラソンを走っているのは素晴らしいことだ。', trivia: 'ラテン語 aetatem（年齢・時代）が語源で、英語の age と同語根のコグネート。英語の age はフランス語 âge 経由でラテン語 aetas に戻り、スペイン語 edad と共通の祖先を持つ。また「中世（Edad Media）」のように歴史的時代を表す用法も英語の age と共通している。' },
  'edificio': { es: 'El edificio del ayuntamiento fue construido a principios del siglo XX.', ja: '市庁舎の建物は20世紀初頭に建てられた。', trivia: 'ラテン語 aedificium（建物）から来ており、aedis（家・神殿）＋facere（作る）の合成語。英語の edifice と同語根のコグネートだが、英語の edifice は「壮大な建物」という格式ばった意味合いが強く、日常的には building が使われる点でニュアンスが異なる。' },
  'educación': { es: 'La educación de calidad es un derecho fundamental que todos los niños merecen.', ja: '質の高い教育は、すべての子どもが受けるべき基本的権利だ。', trivia: 'ラテン語 educatio（養育・訓練）から来ており、educare（引き出す・育てる）が語源。英語の education と完全に同語根・同意味のコグネートで、ラテン語 e-（外へ）＋ducere（導く）という「内にある可能性を引き出す」という語源的意味を両言語で共有している。' },
  'educar': { es: 'Los padres educan a sus hijos no solo con palabras, sino también con el ejemplo.', ja: '親は言葉だけでなく、手本を示すことでも子どもを育てる。', trivia: 'ラテン語 educare（養育する・引き出す）が語源で、英語の educate と同語根・同意味のコグネート。語源的には e-（外へ）＋ducere（導く）から成り、英語の educate、duct、conduct なども同じ ducere を語根に持つファミリーを形成している。' },
  'efecto': { es: 'El medicamento tuvo un efecto positivo en los pacientes desde el primer día.', ja: 'その薬は初日から患者に良い効果をもたらした。', trivia: 'ラテン語 effectus（成し遂げられたもの）に由来し、動詞 efficere（成し遂げる）から派生。英語の effect と完全な同語根で、「原因→結果」の意味的核心も共通している。' },
  'eficaz': { es: 'Este método es muy eficaz para aprender vocabulario en poco tiempo.', ja: 'この方法は短時間で語彙を習得するのに非常に効果的だ。', trivia: 'ラテン語 efficax（効果のある）に由来し、efficere（成し遂げる）が語根。英語の efficacious（効力のある）と同語根で、日常語の effective に相当するが、スペイン語の eficaz はより「実証済みの有効性」というニュアンスが強い。' },
  'ejercicio': { es: 'El médico me recomendó hacer ejercicio moderado todos los días.', ja: '医師は毎日適度な運動をするよう私に勧めた。', trivia: 'ラテン語 exercitium（訓練）に由来し、exercere（活動させる、鍛える）が語根。英語の exercise と同語根の直系であり、「身体を動かす訓練」から「練習問題」まで意味が広い点も共通する。' },
  'el': { es: 'El libro que me prestaste es muy interesante.', ja: 'あなたが貸してくれたその本はとても面白い。', trivia: 'ラテン語指示代名詞 ille（あの）の変化形に由来し、古スペイン語 elo を経て短縮された。英語の the とは語源が異なり（英語はゲルマン語系の þe）、形こそ似ているが全くの別系統である。' },
  'él': { es: 'Él llegó tarde a la reunión, pero nadie le dijo nada.', ja: '彼は会議に遅刻したが、誰も何も言わなかった。', trivia: '定冠詞 el と同じラテン語 ille に由来するが、代名詞として使う際はアクセント記号（tilde diacrítica）で区別する。英語の he に相当し、英語も同じくゲルマン語系の別語根（古英語 hē）を持つ。' },
  'elección': { es: 'Las elecciones presidenciales se celebrarán el próximo año.', ja: '大統領選挙は来年行われる予定だ。', trivia: 'ラテン語 electio（選ぶこと）に由来し、eligere（選び出す）が語根。英語の election と同語根の直系同族語（true cognate）であり、スペルも意味もほぼ同一の典型的な「学習者が英語から類推しやすい語」だ。' },
  'elegir': { es: 'Los ciudadanos eligieron a un nuevo presidente en las últimas elecciones.', ja: '市民たちは先の選挙で新しい大統領を選んだ。', trivia: 'ラテン語 *eligere*（選び出す）に由来し、*e-*（外へ）＋ *legere*（集める、読む）が語源。英語の elect・eligible・elite と同語根であり、英語 elite（エリート）もフランス語を経由した同族語で「選ばれし者」を意味する。' },
  'elemento': { es: 'El carbono es un elemento fundamental para la vida en la Tierra.', ja: '炭素は地球上の生命にとって基本的な元素だ。', trivia: 'ラテン語 elementum（基本要素、文字）に由来し、語源は諸説あるが一説にはラテン文字 L・M・N（el-em-en）の読みに基づくとも言われる。英語の element と完全な同語根で、化学・数学・日常語のどちらでも同様に使われる。' },
  'Elena': { es: 'Elena estudia medicina en la Universidad de Madrid.', ja: 'エレナはマドリード大学で医学を学んでいる。', trivia: 'ギリシャ語の Helénē（ヘレネー）に由来し、トロイのヘレネーと同じ語源を持つ。英語の Helen・Helena と同語根であり、光や明るさを意味するギリシャ語 hēlios（太陽）との関連も指摘されるが、語源は諸説ある。' },
  'ellos': { es: 'Ellos ya se fueron antes de que llegáramos nosotros.', ja: '彼らは私たちが着く前にもう出発していた。', trivia: 'ラテン語 illi（あの人たち）の変化形に由来し、el・él と同じ ille 系列の複数形。英語の they はゲルマン語ではなく古ノルド語 þeir に由来しており、スペイン語の ellos とは語根が全く異なる。' },
  'embargo': { es: 'El gobierno impuso un embargo comercial a ese país por violar los derechos humanos.', ja: '政府は人権侵害を理由にその国に通商禁止措置を課した。', trivia: 'スペイン語動詞 embargar（妨げる、差し押さえる）の名詞形で、ラテン語 barra（棒・障壁）が語根。英語の embargo はスペイン語からの借用語であり、「sin embargo（それにもかかわらず）」という成句でも日常的に使われる。' },
  'emoción': { es: 'Sentí una gran emoción cuando vi a mi equipo ganar el campeonato.', ja: '自分のチームが優勝するのを見たとき、大きな感動を覚えた。', trivia: 'ラテン語 emotio（動かすこと）に由来し、emovere（外へ動かす）＝ e-（外へ）＋ movere（動かす）が語根。英語の emotion と同語根の直系同族語で、「心が外に動かされる」という原義が現代語にも生きている。' },
  'emocionante': { es: 'El final de la película fue tan emocionante que todos lloraron.', ja: '映画のラストはとても感動的で、みんなが泣いた。', trivia: '動詞 emocionar（感動させる）の現在分詞が形容詞化した語で、emoción と同系列。英語の moving や exciting に相当し、「人を感動させる」に近いニュアンスを持つ能動的な形容詞である点が日本語の「感動的な」と一致する。' },
  'empleo': { es: 'Encontró un empleo estable después de varios meses de búsqueda.', ja: '数か月の求職活動の末、安定した仕事を見つけた。', trivia: 'ラテン語 implicare（折り畳む、絡み合わせる）に由来し、フランス語 emploi を経由してスペイン語に入ったとも言われる。英語の employment と同語根で、employ の語根 plicare（折る）は deploy・complex なども生んだ多産な語根だ。' },
  'empresario': { es: 'El joven empresario fundó su primera empresa a los veinticinco años.', ja: 'その若い起業家は25歳で最初の会社を設立した。', trivia: 'スペイン語 empresa（企業）の派生語で、empresa はラテン語 imprehendere（着手する）に由来する。英語の entrepreneur はフランス語経由の同語根語であり、entreprendre（着手する）と empresa は同じラテン語の別経路での変形といえる。' },
  'en': { es: 'Nos encontramos en la plaza mayor a las seis de la tarde.', ja: '私たちは午後6時に中央広場で待ち合わせた。', trivia: 'ラテン語前置詞 in に直接由来し、「場所・時間・状態・手段」など幅広い意味を担う。英語の in と完全な同語根で最も近い同族語の一つだが、英語が on・at と使い分ける文脈もスペイン語では en 一語でカバーすることが多い。' },
  'enamorado': { es: 'Está enamorado de su mejor amiga desde hace años.', ja: '彼は何年も前から親友に恋している。', trivia: 'スペイン語 amor（愛）に前置詞的接頭辞 en- が付いた enamorar（恋させる）の過去分詞形で、「愛の中に入れられた状態」を表す。英語では in love に相当し、amor はラテン語 amor と同語源で英語の amorous（愛情深い）とも同語根だ。' },
  'energía': { es: 'Para mantener la energía durante el día, es importante desayunar bien.', ja: '一日中活力を保つためには、朝食をしっかり摂ることが大切だ。', trivia: 'ギリシャ語 energeia（活動、働き）に由来し、en-（中に）＋ ergon（仕事・働き）の合成語。英語の energy と同語根で、ergon はさらに英語の work（語根は違うが概念が近い）や allergy・surgeon などにも痕跡を残す。' },
  'enero': { es: 'Las rebajas de enero son muy esperadas por los compradores españoles.', ja: '1月のセールはスペインの買い物客に大いに期待されている。', trivia: 'ラテン語 Ianuarius（ヤヌスの月）に由来し、入り口と出口を司る二面の神ヤヌス（Janus）から名付けられた。英語の January と同語根の直系同族語で、Janus はさらに英語の janitor（門番）とも語根を共有する。' },
  'enfermedad': { es: 'El médico dijo que su enfermedad requería reposo absoluto durante dos semanas.', ja: '医師は彼の病気には2週間の絶対安静が必要だと言った。', trivia: 'スペイン語 enfermo（病人）に由来し、ラテン語 infirmus（弱い、病弱な）が語根。英語の infirmary（医務室）・infirm（虚弱な）と同語根であり、in-（否定）＋ firmus（固い・強い）という「強くない」状態を表す構造が共通している。' },
  'enorme': { es: 'La diferencia entre los dos presupuestos era enorme.', ja: '2つの予算案の差は莫大なものだった。', trivia: 'ラテン語 enormis（規格外の）に由来し、e-（外へ）＋ norma（規則・基準）の合成語で「基準を超えた」が原義。英語の enormous と完全な同語根の直系同族語で、norm・normal・Norman なども同じ norma を語根に持つ。' },
  'ensayar': { es: 'El director pidió a los actores que ensayaran la escena final tres veces más.', ja: '監督は俳優たちにクライマックスのシーンをさらに3回リハーサルするよう求めた。', trivia: 'ラテン語 exagium（計量・試験）に由来し、「重さを量る→試す→練習する」と意味が転じた。英語の essay（試みる、エッセイ）と同語根で、仏語 essayer（試みる）を経由しており、「試みること」という原義が文学的用法と舞台的用法の両方に残っている。' },
  'ensayo': { es: 'El grupo de teatro tiene ensayo todos los jueves por la tarde.', ja: 'その劇団は毎週木曜日の午後にリハーサルがある。', trivia: 'ensayar と同じくラテン語 exagium（計量・試験）に由来し、ensayar の名詞形。英語の essay（随筆・試み）と同語根で、16〜17世紀にモンテーニュが文学形式「エッセイ」を確立した際も「試み」という原義を意識していたとされる。' },
  'entero': { es: 'Me comí la pizza entera yo solo sin darme cuenta.', ja: '気づかないうちにピザを一人で丸ごと食べてしまった。', trivia: 'ラテン語 integer（手つかずの、完全な）に由来し、in-（否定）＋ tangere（触れる）の合成語で「触れられていない→完全な」が原義。英語の integer（整数）・integrity（誠実さ）・entire と同語根であり、entire はフランス語経由の同族語だ。' },
  'entrada': { es: 'Perdió la entrada del concierto y no pudo entrar al recinto.', ja: 'コンサートのチケットをなくして、会場に入れなかった。', trivia: '動詞 entrar（入る）の女性過去分詞が名詞化した語で、ラテン語 intrare（入る）に由来する。英語の entrance と同語根で、intro-（中へ）系の語根は introduction・intrude などにも広がっており、「内側へ」という方向性が共通している。' },
  'entregar': { es: 'Tienes que entregar el informe antes del viernes.', ja: '金曜日までにレポートを提出しなければならない。', trivia: 'ラテン語 *integrare*（完全にする）ではなく、*in-* + *tradere*（手渡す）に由来するという説が有力で、「相手の手の中に入れる」というイメージが原義。英語の deliver や hand over に相当し、英語 betray（裏切る）と同じラテン語 *tradere* を語根に持つが、意味は正反対で興味深い。' },
  'entrevista': { es: 'Mañana tengo una entrevista de trabajo y estoy muy nervioso.', ja: '明日、就職の面接があって、とても緊張している。', trivia: 'スペイン語の *entre-*（〜の間）＋ *vista*（見ること）から成り、「互いに見合う」が原義。英語の interview と完全に同語根で、フランス語 *entrevue* を経由して英語に入ったもので、両語ともほぼ同じ意味と構造を持つ。' },
  'equipo': { es: 'Nuestro equipo ganó el campeonato regional este año.', ja: '私たちのチームは今年、地域大会で優勝した。', trivia: '古フランス語 *esquiper*（船を装備する）、さらにゲルマン語 *skip*（船）に由来し、「装備・チーム」へと意味が発展した。英語の equip（装備する）や equipment と同語源であり、スペイン語では「チーム」と「設備・機器」の両義を一語で担う。' },
  'error': { es: 'Cometí un error grave al calcular el presupuesto.', ja: '予算を計算する際に重大な誤りを犯してしまった。', trivia: 'ラテン語 *error*（迷い、過ち）から直接来ており、動詞 *errare*（迷う、間違える）が語根。英語の error・erroneous・errant と完全に同語根で、スペリングもほぼ同一のいわゆる「真のコグネート（true cognate）」の好例。' },
  'es': { es: 'Este libro es muy interesante para los estudiantes de historia.', ja: 'この本は歴史の学生にとってとても面白い。', trivia: 'ラテン語 *esse*（存在する）の活用形に由来し、不規則動詞 *ser* の三人称単数現在形。英語の is と共通のインド・ヨーロッパ祖語の語根 *h₁es-*（存在する）を持ち、is・am・are とスペイン語 es・soy・son がはるか昔に同じ語根から分岐した。' },
  'escalera': { es: 'Subí por la escalera porque el ascensor estaba roto.', ja: 'エレベーターが壊れていたので、階段で上った。', trivia: 'ラテン語 *scala*（はしご、階段）に指小辞 *-era* が付いた形で、*scala* は *scandere*（登る）に由来。英語の scale（音階・目盛り）や escalator（エスカレーター）と同語根であり、「段階的に登る」という共通イメージがある。' },
  'escritor': { es: 'La escritora publicó su tercera novela el año pasado.', ja: 'その女性作家は昨年、3作目の小説を出版した。', trivia: 'ラテン語 *scriptor*（書く者）から来ており、動詞 *scribere*（書く）が語根。英語の scribe・script・prescribe と同語根で、英語では writer に相当するが、script 系統の語から派生した点がスペイン語らしい特徴。' },
  'escritorio': { es: 'Dejé mis llaves encima del escritorio y ya no las encuentro.', ja: '鍵を机の上に置いたのに、もう見つからない。', trivia: '同じく *scribere*（書く）から派生し、「書き物をする場所・家具」を指す。英語の desk に意味上は相当するが、英語 desk はゲルマン語系（古英語 *disc*、ラテン語 *discus* 経由）であり、語根が異なる点が興味深い。' },
  'ese': { es: '¿Puedes pasarme ese libro que está en la mesa?', ja: 'テーブルの上にあるその本を取ってもらえますか？', trivia: 'ラテン語の指示代名詞 *ipse*（まさにそれ）または *ecce ipse* が変化したとされ、語源には諸説ある。英語に直接対応する同語根語はなく、英語の that に相当するが、スペイン語は話し手・聞き手・第三者の距離によって este / ese / aquel と三段階に使い分ける点が英語と大きく異なる。' },
  'esfuerzo': { es: 'Con esfuerzo y dedicación, puedes lograr cualquier cosa.', ja: '努力と献身があれば、どんなことでも達成できる。', trivia: '動詞 *esforzar*（強くする、鼓舞する）から来ており、*es-* ＋古フランス語 *forcier*（力を入れる）、さらにラテン語 *fortis*（強い）が語根。英語の force・enforce・fortify と同語根で、英語では effort に相当するが、effort はフランス語 *esfort* を経由した点でスペイン語 esfuerzo と共通の祖先を持つ。' },
  'espalda': { es: 'Me duele mucho la espalda después de trabajar todo el día sentado.', ja: '一日中座って仕事をした後、背中がとても痛い。', trivia: 'ラテン語 *spatula*（へら、肩甲骨）に由来し、*spatha*（広い剣、へら）が語根。英語の spatula（へら）と同語源であり、また shoulder blade（肩甲骨）の解剖学名 scapula も関連するラテン語から来ている。' },
  'España': { es: 'España es conocida en todo el mundo por su cultura y gastronomía.', ja: 'スペインは文化と食文化で世界中に知られている。', trivia: 'フェニキア語 *I-Shaphan*（ハイラックス〔岩狸〕の島）に由来するという説が有力で、ローマ人が *Hispania* と呼んだことから現在の形になった。英語の Spain もラテン語 *Hispania* を経由しており、「Hispanic（ヒスパニック）」という語もここから来ている。' },
  'especialista': { es: 'Necesito consultar a un especialista en enfermedades del corazón.', ja: '心臓病の専門家に相談する必要がある。', trivia: 'ラテン語 *specialis*（特別な）に由来し、*species*（種類、外見）が語根で、さらに *specere*（見る）に遡る。英語の specialist と完全に同語根・同形の国際語で、special・specific・spectacle なども同じ *specere* から派生している。' },
  'especie': { es: 'Esta especie de ave está en peligro de extinción.', ja: 'この種の鳥は絶滅の危機に瀕している。', trivia: 'ラテン語 *species*（種類、外見、美しさ）から直接来ており、*specere*（見る）が語根。英語の species と完全に同語源・同形で、生物学用語としてどちらの言語でも同じ意味で使われる真のコグネートの代表例。' },
  'espectáculo': { es: 'El espectáculo de fuegos artificiales fue increíble esta noche.', ja: '今夜の花火のショーは信じられないほど素晴らしかった。', trivia: 'ラテン語 *spectaculum*（見世物）から来ており、*spectare*（見る）＋場所・事柄を示す接尾辞 *-culum* が語源。英語の spectacle（眼鏡、見世物）と同語根で、spectacular（壮大な）・spectator（観客）なども同じ家族に属する。' },
  'espejo': { es: 'Se miró en el espejo antes de salir de casa.', ja: '家を出る前に鏡を見た。', trivia: 'ラテン語 *speculum*（鏡、手本）に由来し、*specere*（見る）が語根。英語の speculum（医療用鏡）と同語源であり、英語で鏡を意味する mirror はラテン語 *mirare*（見る、驚く）から来ており語根が異なる。' },
  'esperanza': { es: 'No pierdas la esperanza; todo puede mejorar con el tiempo.', ja: '希望を失わないで。時間が経てば何でも良くなれる。', trivia: '動詞 *esperar*（待つ、希望する）から派生し、ラテン語 *sperare*（希望する）が語根。英語に直接の同語根語は少ないが、despair（絶望）はラテン語 *desperare*（希望を失う）= *de-* ＋ *sperare* から来ており、esperanza と表裏一体の関係にある。' },
  'espíritu': { es: 'El espíritu de lucha del equipo fue fundamental para ganar el partido.', ja: 'チームの闘争心が試合に勝つための鍵となった。', trivia: 'ラテン語 *spiritus*（息吹、魂）に由来し、*spirare*（息をする）が語根。英語の spirit・inspire・respire と完全に同語根であり、「息＝命・精神」というイメージが語源に込められている点が英西両語に共通している。' },
  'esquina': { es: 'El café está en la esquina de la calle Mayor con la avenida Central.', ja: 'そのカフェはマヨール通りとセントラル大通りの角にある。', trivia: '古フランス語 *esquine* またはゲルマン語 *skina*（薄板、角張ったもの）に由来するとされ、語源には諸説ある。英語では corner に相当し、英語の shin（すね）と遠縁の関係にある可能性が指摘されているが、確証はなく語源研究上の興味深い例の一つ。' },
  'estación': { es: 'Hay que hacer trasbordo en la estación central para llegar al aeropuerto.', ja: '空港に着くには中央駅で乗り換えなければならない。', trivia: 'ラテン語 *statio*（立つ場所、停泊）に由来し、*stare*（立つ）が語根。英語の station と完全に同語根であり、さらに stable・circumstance・understand なども同じインド・ヨーロッパ祖語の語根 *steh₂-*（立つ）から発展した仲間。' },
  'estado': { es: 'El estado de salud del paciente ha mejorado considerablemente.', ja: '患者の健康状態はかなり改善した。', trivia: 'ラテン語 *status*（立っている状態、位置）から来ており、*stare*（立つ）が語根。英語の state・status・statute と同語根で、英語 state と完全に対応する真のコグネートであり、「国家」「状態」「州」の多義性も英語 state と驚くほど一致している。' },
  'este': { es: 'Este café es el mejor que he probado en mucho tiempo.', ja: 'このコーヒーは長い間飲んだ中で一番おいしい。', trivia: '「この」の意味はラテン語指示詞に由来し、「東」の意味の este はラテン語 *oriens*（昇る）ではなくゲルマン語 *ost-*（東）から来ており、英語の east と同語根。一語に指示形容詞・指示代名詞・方位名詞の三役が同居する点がユニークな単語。' },
  'estilo': { es: 'Tiene un estilo de escritura muy elegante y preciso.', ja: '彼女はとてもエレガントで正確な文体を持っている。', trivia: 'ラテン語 *stilus*（尖筆、文体）に由来し、もともとは蝋板に字を刻む道具を指した。英語の style と完全に同語根であり、style・stylus・stiletto（短剣）はすべてこの「尖ったもの」という原義から枝分かれした同族語群。' },
  'esto': { es: '¿Qué es esto? Nunca había visto algo así.', ja: 'これは何だろう？こんなものは見たことがなかった。', trivia: 'ラテン語の中性指示代名詞 *istud* または *hoc* の系統から発展したとされ、スペイン語では性・数が確定しない事物を指す中性形として機能する。英語の this に相当するが、英語には中性指示代名詞という区別がなく、スペイン語の este（男性）・esta（女性）・esto（中性）という三分法は英語話者には独特に感じられる。' },
  'estrecho': { es: 'Esta calle es demasiado estrecha para que pasen dos coches a la vez.', ja: 'この通りは車が2台同時に通るには狭すぎる。', trivia: 'ラテン語 strictus（締め付けられた）に由来し、英語の strict（厳格な）と同語根。英語では「狭い」という意味では narrow に相当するが、strait（海峡）も同じ語源でスペイン語 estrecho（名詞で「海峡」の意味もある）と対応する。' },
  'estructura': { es: 'La estructura del puente fue diseñada para resistir terremotos.', ja: 'その橋の構造は地震に耐えられるよう設計された。', trivia: 'ラテン語 structura（建築、組み立て）に由来し、動詞 struere（積み上げる）が語根。英語の structure と完全に同語根で、construct（建設する）・instruct（指導する）なども同じ語根ファミリーに属する。' },
  'estudiante': { es: 'Los estudiantes de intercambio llegaron desde varios países de Asia.', ja: '交換留学生たちがアジア各国からやってきた。', trivia: 'ラテン語 studere（熱心に取り組む）に由来し、英語の student と完全に同語根の直接的なコグネート。study（勉強する・スタジオ）も同じ語根で、英語とスペイン語でほぼ同形・同義の珍しい例。' },
  'estudio': { es: 'Necesito más tiempo de estudio para prepararme bien para el examen.', ja: '試験にしっかり備えるためにもっと勉強時間が必要だ。', trivia: 'ラテン語 studium（熱心、努力、研究）に由来し、英語の study と同語根の直接的なコグネート。「書斎」や「録音スタジオ」の意味でも使われ、英語の studio もイタリア語経由で同じラテン語語根に遡る。' },
  'etapa': { es: 'Hemos completado la primera etapa del proyecto sin ningún problema.', ja: 'プロジェクトの第一段階を問題なく完了した。', trivia: '語源については諸説あり、フランス語 étape（宿泊地、区間）経由でゲルマン語 *stapaz（柱・支柱）に由来するという説が有力。英語では stage に相当し、stage もフランス語 estage 経由でラテン語 stare（立つ）に遡るが、直接の語根は異なる。' },
  'Europa': { es: 'Muchos jóvenes sueñan con viajar por Europa al terminar la universidad.', ja: '多くの若者が大学を卒業したらヨーロッパを旅することを夢見ている。', trivia: 'ギリシャ語 Eurṓpē に由来し、「広い顔」または「夕陽の地（西の地）」を意味するとされるが語源は諸説ある。英語の Europe と同語根で発音も類似しており、形容詞形は Spanish で europeo、英語では European に相当する。' },
  'europeo': { es: 'El mercado europeo ofrece grandes oportunidades para las empresas locales.', ja: 'ヨーロッパ市場は地元企業に大きな機会を提供している。', trivia: '固有名詞 Europa（ヨーロッパ）から派生した形容詞・名詞で、英語の European と同語根の直接的なコグネート。スペイン語の語尾 -eo はラテン語の形容詞語尾 -eus に由来し、地名から「〜の」「〜人の」を表す形容詞を作るパターンに従っている。' },
  'evidente': { es: 'Es evidente que necesitamos cambiar nuestra estrategia de ventas.', ja: '私たちの販売戦略を変える必要があることは明白だ。', trivia: 'ラテン語 evidens（明白な）に由来し、ex-（外へ）と videre（見る）が語根。英語の evident と完全に同語根の直接的なコグネートで、video（映像）・vision（視覚）・evidence（証拠）なども同じ videre の語根ファミリーに属する。' },
  'evitar': { es: 'Debes evitar comer demasiado azúcar para mantener una buena salud.', ja: '健康を維持するためには砂糖の摂り過ぎを避けるべきだ。', trivia: 'ラテン語 evitare（避ける）に由来し、ex-（外へ）と vitare（避ける）が語根。英語では avoid に相当するが、avoid はフランス語 éviter 経由でゲルマン語系の語根とも混合しており直接のコグネートではない。inevitable（不可避の）は英語・スペイン語共通の派生語。' },
  'exacto': { es: 'El científico necesita mediciones exactas para que el experimento sea válido.', ja: '実験が有効であるためには科学者には正確な測定値が必要だ。', trivia: 'ラテン語 exactus（精密に計られた）に由来し、exigere（要求する、計測する）の過去分詞が語源。英語の exact と完全に同語根の直接的なコグネートで、exacting（厳格な）・exactly（まさに）も共通する語根ファミリー。' },
  'examen': { es: 'Tuve que estudiar toda la noche para aprobar el examen de química.', ja: '化学の試験に合格するために一晩中勉強しなければならなかった。', trivia: 'ラテン語 examen（計量のための舌、検討）に由来し、exigere（計る、試す）が語根。英語の examination・exam と同語根の直接的なコグネートで、examine（調べる）も同じ語根ファミリー。ラテン語で元々は「天秤の指針」を意味していた。' },
  'excelente': { es: 'La profesora dio una calificación excelente a su trabajo de investigación.', ja: '先生は彼女の研究論文に優秀な評価を与えた。', trivia: 'ラテン語 excellens（突き出た、卓越した）に由来し、ex-（外へ）と cellere（上昇する）が語根。英語の excellent と完全に同語根の直接的なコグネートで、excel（卓越する）・excellence（卓越性）も同じ語根ファミリー。Microsoftの表計算ソフト「Excel」もこの語根から。' },
  'éxito': { es: 'La nueva película fue un gran éxito tanto en taquilla como en crítica.', ja: '新作映画は興行収入でも批評においても大成功を収めた。', trivia: 'ラテン語 exitus（出口、結果、終わり）に由来し、ex-（外へ）と ire（行く）が語根。注意すべき「偽のコグネート（false cognate）」で、英語の exit は「出口」を意味するが、スペイン語の éxito は「成功」を意味する。英語で「成功」は success に相当する。' },
  'experiencia': { es: 'Tener experiencia laboral es fundamental para encontrar un buen empleo.', ja: '良い仕事を見つけるためには職務経験を持つことが不可欠だ。', trivia: 'ラテン語 experientia（試み、経験）に由来し、experiri（試す）が語根。英語の experience と完全に同語根の直接的なコグネートで、experiment（実験）・expert（専門家）も同じ語根ファミリー。「試みることで得られる知識」というのが元々の意味。' },
  'expresión': { es: 'La expresión de su cara revelaba que estaba preocupado por algo.', ja: '彼の表情は何かを心配していることを表していた。', trivia: 'ラテン語 expressio（押し出すこと）に由来し、ex-（外へ）と premere（押す）が語根。英語の expression と完全に同語根の直接的なコグネートで、press（押す）・impress（感銘を与える）・depress（落ち込ませる）なども同じ語根ファミリー。' },
  'extranjero': { es: 'En este barrio viven muchos extranjeros que trabajan en empresas multinacionales.', ja: 'この地区には多国籍企業で働く外国人がたくさん住んでいる。', trivia: 'ラテン語 extraneus（外からの、異質な）に由来し、extra（外側に）が語根。英語の strange（奇妙な）・stranger（見知らぬ人）と同語根だが意味がやや分岐しており、英語で「外国人」は foreigner に相当する。フランス語 étranger（外国人）は意味が近い形で残っている。' },
  'extraño': { es: 'Es extraño que no haya contestado a ninguno de mis mensajes.', ja: '私のメッセージに一つも返信がないのは奇妙だ。', trivia: 'ラテン語 extraneus（外からの）に由来し、extranjero（外国人）と同語根。英語の strange と同語根の直接的なコグネートで、estrange（疎遠にする）も同じ系統。英語の strange がまさにこのラテン語由来でほぼ同義語として対応している。' },
  'fábrica': { es: 'La fábrica de automóviles emplea a más de dos mil trabajadores en la región.', ja: 'その自動車工場は地域で2000人以上の労働者を雇用している。', trivia: 'ラテン語 fabrica（職人の工房、製作物）に由来し、faber（職人、鍛冶師）が語根。注意すべき「偽のコグネート（false cognate）」で、英語の fabric は「布地・織物」を意味するが、スペイン語の fábrica は「工場」を意味する。英語で「工場」は factory に相当し、これは同じ語根に遡る。' },
  'factor': { es: 'El precio es uno de los factores más importantes a la hora de comprar.', ja: '価格は購入する際に最も重要な要因の一つだ。', trivia: 'ラテン語 factor（作る者、実行者）に由来し、facere（作る、行う）が語根。英語の factor と完全に同語根の直接的なコグネートで、fact（事実）・manufacture（製造）・affect（影響する）なども同じ facere 語根ファミリーに属する非常に大きな語族を形成している。' },
  'falta': { es: 'La falta de comunicación fue la causa principal del malentendido.', ja: 'コミュニケーション不足が誤解の主な原因だった。', trivia: 'ラテン語 fallita（欠如、誤り）に由来し、fallere（欺く、失敗する）が語根。英語の fault（欠点、過ち）と同語根の直接的なコグネートで、false（偽の）・fallacy（誤謬）・fail（失敗する）も同じ語根ファミリー。スポーツの「ファウル（foul）」は英語経由だが意味的に対応する。' },
  'faltar': { es: 'Nos falta una hora para terminar de preparar la cena.', ja: '夕食の準備を終えるまであと1時間かかる。', trivia: '名詞 falta（不足）から派生した動詞で、ラテン語 fallere（欠ける、失敗する）が語根。英語の fault（欠点）・false（偽の）と同語根だが、faltar は「〜が不足している」という間接目的語を主語的に取る構文（me falta = 私には〜が足りない）が特徴的で、英語の lack に相当する使い方をする。' },
  'familiar': { es: 'El nombre me resulta familiar, pero no recuerdo dónde lo he escuchado antes.', ja: 'その名前は聞き覚えがあるが、どこで聞いたか思い出せない。', trivia: 'ラテン語 familiaris（家族の、親しい）に由来し、familia（家族）が語根。英語の familiar と完全に同語根の直接的なコグネートで、family（家族）・familiarity（親しみ）も同じ語根ファミリー。「よく知っている」という意味での使い方が英語の familiar と特に共通している。' },
  'farmacia': { es: 'Fui a la farmacia a comprar analgésicos para el dolor de cabeza.', ja: '頭痛薬を買いに薬局へ行った。', trivia: 'ギリシャ語 pharmakeia（薬、魔術による治癒）に由来し、pharmakon（薬・毒）が語根。英語の pharmacy と完全に同語根の直接的なコグネートで、pharmaceutical（製薬の）・pharmacology（薬理学）も同じ語根ファミリー。ギリシャ語では「薬」と「毒」が同じ語で表されていた興味深い語源を持つ。' },
  'fase': { es: 'El proyecto está actualmente en la fase de pruebas antes del lanzamiento.', ja: 'そのプロジェクトは現在、リリース前のテスト段階にある。', trivia: 'ギリシャ語 phasis（現れ、月の満ち欠け）に由来し、phainein（現れる、輝く）が語根。英語の phase と完全に同語根の直接的なコグネートで、phenomenon（現象）・fantasy（幻想）・phosphorus（リン）なども同じ「輝く・現れる」という語根ファミリーに属する。' },
  'favor': { es: '¿Me puedes hacer el favor de cerrar la ventana? Hace mucho frío.', ja: '窓を閉めていただけますか？とても寒いんです。', trivia: 'ラテン語 favor（好意、援助）に由来し、favere（好意を示す）が語根。英語の favor（米）／favour（英）と完全に同語根の直接的なコグネートで、favorable（好意的な）も共通する語根ファミリー。「por favor（どうか〜してください）」はスペイン語の最も基本的な丁寧表現の一つ。' },
  'febrero': { es: 'Mi cumpleaños es el quince de febrero, así que siempre lo celebro con mis amigos.', ja: '私の誕生日は2月15日なので、いつも友達と一緒に祝います。', trivia: 'ラテン語 februarius（februa＝浄化の祭り）に由来し、古代ローマの清めの儀式に捧げられた月名。英語の February と完全に同語根で、語形もほぼ同じ。' },
  'fecha': { es: '¿Cuál es la fecha límite para entregar el informe?', ja: 'レポートを提出する締め切り日はいつですか？', trivia: 'ラテン語 facta（literarum）「書かれたもの」の女性形複数が単数名詞化したもの。英語では date に相当し、英語の fact（ラテン語 factum）と同じ動詞 facere「する・作る」を語根に持つ。' },
  'felicidad': { es: 'La felicidad no siempre depende del dinero, sino de las relaciones con los demás.', ja: '幸福は必ずしもお金に依存するのではなく、他者との関係に依存することもある。', trivia: 'ラテン語 felicitas（幸運、豊かさ）に由来し、felix（幸運な）が語根。英語の felicity（幸福、幸運）と同語根で、Felix という人名も同じ語源を持つ。' },
  'fiesta': { es: 'Esta noche vamos a organizar una fiesta sorpresa para el cumpleaños de Ana.', ja: '今夜、アナの誕生日のためにサプライズパーティーを開く予定です。', trivia: 'ラテン語 festa（祭りの日々）に由来し、英語の feast（ごちそう、祝宴）と同語根。英語の festival もラテン語 festivus を経由した同族語で、fiesta は英語にも外来語として取り込まれている。' },
  'figura': { es: 'El artista dibujó la figura humana con gran detalle y precisión.', ja: 'その芸術家は人体の形を非常に細かく正確に描いた。', trivia: 'ラテン語 figura（形、姿）に由来し、fingere「形作る」が語根。英語の figure と完全に同語源・同語形であり、figuration、figurative なども同族語。' },
  'fijar': { es: 'Necesitamos fijar una fecha para la reunión antes de que termine la semana.', ja: '今週が終わる前に会議の日程を決める必要があります。', trivia: 'ラテン語 figere「固定する、突き刺す」に由来。英語の fix と同語根で、fix もラテン語 figere の過去分詞 fixus から来ており、意味も「固定する」と共通している。' },
  'final': { es: 'El equipo local llegó a la final del campeonato después de meses de entrenamiento.', ja: '地元チームは何ヶ月にも及ぶ練習の末、選手権の決勝戦に進出した。', trivia: 'ラテン語 finalis（終わりの）に由来し、finis「終わり、境界」が語根。英語の final と完全に同語根・同語形で、finance（資金決済）も同じ finis から派生している。' },
  'financiero': { es: 'La empresa publicó su informe financiero anual con resultados positivos.', ja: 'その企業は好調な結果を示す年次財務報告書を発表した。', trivia: '中世ラテン語 financiare（決済する）に由来し、finis「終わり・決済」が語根。英語の financial と同語根で語形も酷似しており、finance、financier なども同族語として英語とスペイン語で対応する。' },
  'firma': { es: 'Necesito tu firma en este contrato para que sea válido.', ja: 'この契約書を有効にするために、あなたの署名が必要です。', trivia: 'ラテン語 firmare「確かにする、確認する」の名詞形に由来し、firmus「固い、確実な」が語根。英語の firm（会社、固い）と同語根で、confirm（確認する）なども同族語にあたる。' },
  'firmar': { es: 'El presidente firmó el acuerdo de paz ante la prensa internacional.', ja: '大統領は国際メディアの前で平和協定に署名した。', trivia: 'ラテン語 firmare「固める、確認する」に直接由来し、firmus「固い」が語根。英語の affirm（断言する）や confirm（確認する）と同語根で、firm という英単語も同じ語源を持つ。' },
  'flaco': { es: 'Después de la enfermedad, quedó muy flaco y necesitaba recuperar fuerzas.', ja: '病気の後、彼はとても痩せてしまい、体力を取り戻す必要があった。', trivia: '語源については諸説あり、ラテン語 flaccus（たるんだ、力のない）に由来するとも、ゲルマン語系の影響とも言われる。英語では thin や skinny に相当し、英語の flaccid（たるんだ）がラテン語 flaccus と関連する同族語候補。' },
  'fondo': { es: 'Al fondo del pasillo hay una puerta que lleva al jardín.', ja: '廊下の奥に庭に続くドアがある。', trivia: 'ラテン語 fundus（底、土地の基盤）に由来し、英語の fund（資金）と同語根。また英語の foundation、profound（深い）なども同じ語根 fundus を共有している。' },
  'foto': { es: 'Saqué una foto preciosa del atardecer en la playa.', ja: '浜辺で夕日の美しい写真を撮った。', trivia: 'ギリシャ語 phōs（光）を語根とする fotografía の短縮形。英語の photo も同じ短縮形で全く同語源。photograph、photon、photosynthesis なども同族語で、「光」という意味が共通している。' },
  'frase': { es: 'El profesor nos pidió que escribiéramos una frase con cada palabra nueva.', ja: '先生は新しい単語それぞれを使って文を書くよう求めた。', trivia: 'ギリシャ語 phrasis（表現、言い回し）に由来し、phrazein「述べる」が語根。英語の phrase と完全に同語根・同語形で、paraphrase（言い換え）なども同族語。' },
  'frecuencia': { es: 'Con qué frecuencia vas al gimnasio? — Unas tres veces a la semana.', ja: 'どのくらいの頻度でジムに行きますか？ — 週に約3回です。', trivia: 'ラテン語 frequentia（人込み、頻繁さ）に由来し、frequens「頻繁な」が語根。英語の frequency と同語根・同語形に近く、frequent も同族語として対応する。' },
  'frente': { es: 'Tenía el sudor en la frente después de correr diez kilómetros.', ja: '10キロ走った後、額に汗をかいていた。', trivia: 'ラテン語 frons / frontis（額、正面）に由来。英語の front、frontier（国境）と同語根で、confront（対峙する）や affront（侮辱）なども同族語。「前面・正面」という意味が英語とスペイン語に共通している。' },
  'fuente': { es: 'La plaza mayor tiene una fuente antigua rodeada de flores.', ja: '中央広場には花に囲まれた古い噴水がある。', trivia: 'ラテン語 fons / fontis（泉、水源）に由来し、英語の font（洗礼盤、泉）や fountain と同語根。英語の font と fountain はいずれも同じラテン語 fons を語根に持つ同族語。' },
  'fuera': { es: 'Los niños están jugando fuera porque hace buen tiempo.', ja: '天気がいいので子どもたちは外で遊んでいる。', trivia: 'ラテン語 foras（扉の外へ）に由来し、英語の foreign（外国の）と同語根とされる。英語では outside や out に相当するが、英語の foreign はラテン語 foris「外」から来た同族語で、意味の広がりが興味深い。' },
  'funcionar': { es: 'El ascensor no funciona; tendremos que subir por las escaleras.', ja: 'エレベーターが動いていないので、階段で上がらなければならない。', trivia: 'ラテン語 functio（遂行、実行）に由来し、fungi「果たす」が語根。英語の function と同語根で、defunct（機能停止した）や perfunctory（おざなりな）なども同族語にあたる。' },
  'función': { es: 'La función principal del hígado es filtrar las toxinas de la sangre.', ja: '肝臓の主な機能は血液から毒素をろ過することである。', trivia: 'ラテン語 functio（職務の遂行）に由来し、fungi「果たす」が語根。英語の function と完全に同語根で、functional、dysfunctional なども英語・スペイン語両言語に同族語として存在する。' },
  'fundación': { es: 'La fundación benéfica dona millones de euros cada año para proyectos educativos.', ja: 'その慈善財団は毎年何百万ユーロもを教育プロジェクトのために寄付している。', trivia: 'ラテン語 fundatio（基礎を据えること）に由来し、fundare「基礎を作る」、fundus「底・土地」が語根。英語の foundation と同語根・同語形に近く、fund、profound なども同族語として対応する。' },
  'fútbol': { es: 'El fútbol es, sin duda, el deporte más popular de España y Latinoamérica.', ja: 'サッカーは間違いなくスペインとラテンアメリカで最も人気のあるスポーツだ。', trivia: '英語の football をスペイン語音に転写した外来語で、foot（足）＋ball（球）の合成語。英米英語では football はアメリカンフットボールを指すことが多く、サッカーは soccer と呼ばれるが、スペイン語圏では fútbol が一般的。' },
  'ganar': { es: 'Nuestro equipo logró ganar el partido en el último minuto con un gol increíble.', ja: '私たちのチームは信じられないゴールで最後の1分に試合に勝つことができた。', trivia: 'ゲルマン語系（ゴート語またはフランク語 waidanjan「狩りで食料を得る」）に由来するとされ、ラテン語ではなく北方民族の語彙が定着した例。英語では win や earn に相当し、いずれも同語根ではないが意味的に対応する。' },
  'ganas': { es: 'Tengo muchas ganas de verte después de tanto tiempo sin vernos.', ja: 'こんなに長い間会っていなかったから、あなたにとても会いたい。', trivia: '動詞 ganar（得る・望む）の名詞形で、「得たいという気持ち」が語義の核。英語では desire や eagerness に相当し、tener ganas de + 不定詞（〜したい）というフレーズで頻用される。英語に直接の同語根語はないが、ganar 自体はゲルマン語系語彙に由来する。' },
  'garantía': { es: 'Este televisor viene con una garantía de dos años contra defectos de fabricación.', ja: 'このテレビは製造上の欠陥に対して2年間の保証付きで販売されている。', trivia: 'ゲルマン語（フランク語 warantia「保護、保証」）に由来し、スペイン語に入った経路はフランス語 garantie を経由したとされる。英語の guarantee および warranty と同語根で、三語はほぼ同じゲルマン語の語幹を共有する同族語。' },
  'garantizar': { es: 'La empresa garantiza la calidad de todos sus productos durante dos años.', ja: 'その会社はすべての製品の品質を2年間保証しています。', trivia: 'スペイン語「garantía（保証）」はゲルマン語派の古フランク語 *warand-（保証人）に由来し、フランス語 garantir を経て借用された。英語の guarantee / warranty と同語根で、いずれも同じゲルマン語の祖形を共有している。' },
  'garganta': { es: 'Me duele la garganta desde ayer; creo que estoy resfriado.', ja: '昨日からのどが痛くて、風邪をひいたようです。', trivia: '後期ラテン語 garganta（のど）に由来し、液体を流す「管・通路」というイメージが根底にある。英語の gargle（うがいする）と同語根で、どちらも「ゴロゴロ」という音を模した擬音的起源を持つ。' },
  'gas': { es: 'Por favor, cierra bien el gas antes de salir de casa.', ja: '外出前にガスをしっかり閉めてください。', trivia: '17世紀にベルギーの化学者ファン・ヘルモントがギリシャ語 chaos（混沌）をもとに造語した科学用語で、ほぼそのまま多言語に借用された。英語の gas も同一語源で、科学語彙がヨーロッパ全土に広まった例の一つ。' },
  'gasto': { es: 'Los gastos del viaje fueron mayores de lo que esperábamos.', ja: '旅行の費用は予想よりもかなり多くかかりました。', trivia: 'ラテン語 vastare（荒廃させる、無駄にする）に由来し、動詞 gastar（使う・費やす）の名詞形。英語の waste と同語根で、「資源を消耗させる」という共通のイメージを持つフォルスフレンド的なペアである。' },
  'generoso': { es: 'Es una persona muy generosa; siempre ayuda a los demás sin esperar nada a cambio.', ja: '彼女はとても気前の良い人で、見返りを期待せずいつも他者を助けます。', trivia: 'ラテン語 generosus（高貴な生まれの）に由来し、genus（種族・血統）が語根。英語の generous も同語源で、「高貴な家柄」→「気前が良い」という意味の変遷経路まで共通している。' },
  'gestión': { es: 'La gestión eficiente de los recursos es clave para el éxito de cualquier empresa.', ja: '資源の効率的な管理は、どんな企業の成功にも不可欠です。', trivia: 'ラテン語 gestio（行為、遂行）に由来し、gerere（行う・運ぶ）が語根。英語の gesture や digest と同語根であり、「何かを動かし処理する」という意味の核を共有している。' },
  'girar': { es: 'El ventilador gira despacio porque necesita que le cambien las aspas.', ja: '扇風機はゆっくり回っています。羽根を交換する必要があるからです。', trivia: '後期ラテン語 gyrare（回転する）に由来し、ギリシャ語 gyros（円・輪）が元の形。英語の gyrate や gyroscope と同語根で、「回転・円運動」というイメージを共有している。' },
  'globo': { es: 'Los niños corrían detrás del globo rojo que se les había escapado.', ja: '子どもたちは逃げてしまった赤い風船を追いかけて走っていました。', trivia: 'ラテン語 globus（球体、塊）に由来する。英語の globe と完全に同語源であり、「地球儀」という意味でも両言語で対応している。global（グローバル）もこの語根から派生した。' },
  'gloria': { es: 'El equipo celebró con gloria su primera victoria en el campeonato nacional.', ja: 'チームは全国選手権での初勝利を栄光をもって祝いました。', trivia: 'ラテン語 gloria（栄光、名声）に由来し、キリスト教ラテン語を通じてヨーロッパ各語に広まった。英語の glory と完全に同語源で、スペルも意味もほぼそのまま対応する典型的なコグネートである。' },
  'gobernador': { es: 'El gobernador de la región anunció nuevas medidas para combatir la pobreza.', ja: 'その地域の知事は貧困対策の新施策を発表しました。', trivia: 'ラテン語 gubernator（舵取り、指揮者）に由来し、ギリシャ語 kubernetes（舵手）が源流。英語の governor と同語源で、現代語のサイバネティクス（cybernetics）もこのギリシャ語語根に遡る。' },
  'gobernar': { es: 'Es muy difícil gobernar un país tan diverso sin el apoyo de la ciudadanía.', ja: '市民の支持なしに、これほど多様な国を統治することは非常に難しい。', trivia: 'ラテン語 gubernare（舵を取る、支配する）に由来し、gobernador と同語根。英語の govern と完全に同語源であり、「統治する」という意味でも直接対応する典型的なコグネートである。' },
  'golpe': { es: 'El golpe de estado fue reprimido por las fuerzas armadas en pocas horas.', ja: 'クーデターは数時間以内に軍によって鎮圧されました。', trivia: '語源は諸説あるが、ゲルマン語 *kolf（棒、こん棒）またはラテン語 colpus に由来するとされる。英語の golf との関連を指摘する説もあるが確定していない。英語では「打撃」を blow や hit と言い、直接対応する同語根語はない。' },
  'gozar': { es: 'Gozamos de un clima excelente durante toda la semana de vacaciones.', ja: '休暇の1週間、私たちはずっと素晴らしい気候に恵まれました。', trivia: '語源には諸説あり、ラテン語 gaudere（喜ぶ）に由来するとする説が有力。英語の joy と同語根で、joy の動詞形 rejoice もラテン語 gaudere に遡る。スペイン語の gozar と英語の joy は「享受する喜び」という意味の核を共有している。' },
  'gracia': { es: 'Me hizo mucha gracia el chiste que contó al final de la reunión.', ja: '会議の最後に彼が言ったジョークがとても面白かった。', trivia: 'ラテン語 gratia（好意、感謝、魅力）に由来し、宗教・世俗両面で広く使われてきた語。英語の grace と完全に同語源で、「優雅さ」「神の恩寵」という意味でも対応する。gratitude（感謝）や gracious（優雅な）も同じ語根から派生している。' },
  'grado': { es: 'La temperatura bajó varios grados durante la noche y amaneció con helada.', ja: '夜の間に気温が数度下がり、朝には霜が降りていました。', trivia: 'ラテン語 gradus（歩み、段階、度）に由来し、「一歩ずつ進む段階」が原義。英語の grade や degree と同語源で、degree はラテン語 de-（下に）＋ gradus の複合形。gradient（傾斜）や gradual（段階的な）も同じ語根ファミリー。' },
  'gran': { es: 'Fue un gran esfuerzo el que hicieron todos los voluntarios durante la catástrofe.', ja: '災害の際にすべてのボランティアが払った努力は素晴らしいものでした。', trivia: 'grande（大きい、偉大な）の短縮形で、男女名詞の単数形の前で使われる。ラテン語 grandis（大きい、成熟した）に由来し、英語の grand と完全に同語源。grand piano（グランドピアノ）などの英語借用語はスペイン語・フランス語経由で普及した。' },
  'grano': { es: 'El agricultor guardó los granos de trigo para sembrarlos en la próxima temporada.', ja: '農家は次のシーズンに種を蒔くため、小麦の粒を保管しました。', trivia: 'ラテン語 granum（粒、種）に由来し、「個々の粒」が原義。英語の grain と完全に同語源で、granary（穀倉）、granite（花崗岩）なども同じ語根に遡る。「粒が集まって岩を成す」という発想でgraniteにもつながっている。' },
  'grasa': { es: 'Este plato tiene demasiada grasa; prefiero una cocina más ligera.', ja: 'この料理は脂肪が多すぎます。もっとあっさりした料理が好きです。', trivia: 'ラテン語 crassus（濃い、太った）に由来し、音変化を経て grasa となった。英語に直接対応する同語根語はないが、英語の grease はフランス語 graisse 経由でやはりラテン語 crassus に由来しており、遠い親戚関係にある。' },
  'grave': { es: 'El accidente fue tan grave que los heridos tuvieron que ser hospitalizados de urgencia.', ja: '事故はとても深刻で、負傷者は緊急入院しなければなりませんでした。', trivia: 'ラテン語 gravis（重い、深刻な）に由来し、「物理的な重さ」→「重大さ」へと意味が発展した。英語の grave（形容詞：深刻な）と完全に同語源で、gravity（重力・重大さ）や aggravate（悪化させる）も同じ語根ファミリーに属する。' },
  'gris': { es: 'Hoy el cielo está completamente gris; parece que va a llover.', ja: '今日は空が完全に灰色で、雨が降りそうです。', trivia: 'ゲルマン語 *gris（灰色）に由来し、古フランス語 gris を経てスペイン語に入った。英語の gray（grey）とは同じゲルマン語の祖形を持つ遠い親戚で、「灰色」を表す語として両言語に残っている。' },
  'grito': { es: 'Se oyó un grito en medio de la noche que despertó a todos los vecinos.', ja: '夜中に叫び声が聞こえ、近所の人全員が目を覚ました。', trivia: '動詞 gritar（叫ぶ）の名詞形で、語源は諸説あるがラテン語 quiritare（大声で叫ぶ）との関連が指摘される。英語に直接対応する同語根語はなく、英語では cry や scream に相当する。' },
  'guante': { es: 'No olvides ponerte los guantes; hace mucho frío esta mañana.', ja: '手袋をつけるのを忘れないで。今朝はとても寒いから。', trivia: 'ゲルマン語 *want（手を覆うもの）に由来し、古フランス語 gant を経てスペイン語に借用された。英語の gauntlet（籠手、決闘の手袋）と同語根で、いずれも同じゲルマン語の祖形を共有している。' },
  'guardar': { es: 'Es importante guardar las contraseñas en un lugar seguro y difícil de adivinar.', ja: 'パスワードは安全で推測されにくい場所に保管することが重要です。', trivia: 'ゲルマン語 *wardōn（見張る、守る）に由来し、古スペイン語に借用された語。英語の guard と完全に同語源で、ward（病棟・後見）、warden（管理人）なども同じゲルマン語語根に遡る親戚語である。' },
  'guardia': { es: 'El guardia de seguridad revisó el bolso de cada persona al entrar al museo.', ja: '警備員は博物館に入る際に一人ひとりのバッグをチェックしました。', trivia: 'guardar と同じゲルマン語語根 *wardōn（見張る）に由来し、イタリア語 guardia 経由でスペイン語に定着した。英語の guard と同語源で、bodyguard（ボディガード）という複合語にも直接その形が見られる。' },
  'guía': { es: 'La guía turística nos explicó la historia del castillo con mucho detalle.', ja: '観光ガイドは城の歴史をとても詳しく説明してくれました。', trivia: 'ゲルマン語 *wītan（知る・示す）またはゴート語 *widan（導く）に由来し、古フランス語 guier を経てスペイン語に入った。英語の guide と完全に同語源で、「道を知る者が他者を導く」という原義を両言語で共有している。' },
  'gusto': { es: 'Me da mucho gusto conocerte en persona después de tanto tiempo.', ja: 'こんなに長い時間を経て、実際にお会いできてとても嬉しいです。', trivia: 'ラテン語 gustus（味覚・好み）に由来し、英語 gusto（熱意、享楽）は同語源の借用語。英語の taste や pleasure に相当する複数の意味を一語でカバーするのが特徴。' },
  'haber': { es: 'Creo que ha habido un malentendido entre nosotros.', ja: '私たちの間で誤解があったと思います。', trivia: 'ラテン語 habēre（持つ）に由来し、英語 have と同語根。英語では have が「持つ」と完了の助動詞を兼ねるように、スペイン語でも haber が完了助動詞と存在（hay）の両方を担う。' },
  'habitación': { es: 'La habitación del hotel tenía una vista increíble al mar.', ja: 'ホテルの部屋から海への素晴らしい眺望がありました。', trivia: 'ラテン語 habitatio（住まい、居住）に由来し、英語 habitation（居住、居住地）と同語根。英語では room に相当するが、habitat（生息地）も同じ語根 habitare（住む）から来ている。' },
  'habitual': { es: 'Es habitual que los españoles cenen tarde, alrededor de las diez de la noche.', ja: 'スペイン人が夜10時頃に遅めの夕食を取るのは普通のことです。', trivia: 'ラテン語 habitualis（慣習的な）に由来し、英語 habitual（習慣的な）と完全な同形異義語（コグネート）。habit（習慣）も同じ語根 habitus から来ており、三語は密接に関連している。' },
  'hacia': { es: 'Caminamos hacia la plaza mayor para ver el espectáculo de luces.', ja: '光のショーを見るためにマヨール広場に向かって歩きました。', trivia: 'ラテン語 facie（顔、方向）から発展したとされ、古スペイン語 faza を経て hacia となった。英語の toward に相当するが、英語に直接対応する同語根語はなく、face（顔）が遠縁にあたるとされる。' },
  'hacienda': { es: 'La hacienda del siglo XVIII todavía produce café y caña de azúcar.', ja: '18世紀の大農園は今もコーヒーとサトウキビを生産しています。', trivia: 'ラテン語 facienda（なすべきこと）の変化形で、中世スペイン語で「財産・農業経営地」を意味するようになった。英語にも hacienda として借用され、メキシコや南西米国の大農場を指す語として定着している。' },
  'hambre': { es: 'Después de caminar cinco horas, teníamos un hambre feroz.', ja: '5時間歩いた後、私たちはひどくお腹が空いていました。', trivia: 'ラテン語 fames（飢え）に由来し、スペイン語では語頭の f が h に変化する典型例（fames → hambre）。英語 famine（飢饉）や famish（餓死させる）は同語根で、スペイン語の変化を経ずにラテン語形を保っている。' },
  'hasta': { es: 'Puedes quedarte aquí hasta las diez, pero no más tarde.', ja: 'ここには10時まで滞在できますが、それ以上は無理です。', trivia: 'アラビア語 ḥattā（〜まで）に由来するとする説が有力で、スペインのアラブ支配期（711〜1492年）に借用されたとされる。英語の until や even に相当するが、直接対応する英語の同語根語は存在しない珍しいアラビア語起源の前置詞。' },
  'hay': { es: 'Hay mucha gente en la calle porque hoy es fiesta nacional.', ja: '今日は国民の祝日なので、通りに人がたくさんいます。', trivia: '動詞 haber の非人称形で、ラテン語 habet（持つ・存在する）に由来。英語の there is / there are に相当するが、スペイン語では単複を問わず hay 一語で表せる点が異なり、英語話者にとって習得しやすい単純な構造となっている。' },
  'herir': { es: 'Las palabras duras pueden herir a una persona más que los golpes físicos.', ja: 'きつい言葉は肉体的な打撃よりも人を深く傷つけることがある。', trivia: 'ラテン語 ferire（打つ、傷つける）に由来し、英語では直接の同語根語はないが、傷を意味する wound（古英語由来）が意味的に相当する。ただし英語 injury はラテン語 injuria から来ており、やや遠縁の関係にある。' },
  'hermoso': { es: 'El paisaje del atardecer sobre el lago era verdaderamente hermoso.', ja: '湖に沈む夕日の風景は本当に美しかった。', trivia: 'ラテン語 formosus（美しい、整った形の）に由来し、語頭の f が h に変化したスペイン語の音韻変化の例。英語 form（形）と同語根で、「形が整っている＝美しい」という発想を共有しているが、英語では beautiful や gorgeous が意味的に相当する。' },
  'herramienta': { es: 'Necesito una herramienta adecuada para reparar esta tubería.', ja: 'この配管を修理するためには適切な工具が必要です。', trivia: 'ラテン語 ferramenta（鉄製の道具）に由来し、ferrum（鉄）が語根。英語 ferrous（鉄の、第一鉄の）や ferrule（金属の輪）も同語根。英語では tool や instrument が意味的に相当するが、これらはゲルマン語系で語根は全く異なる。' },
  'herror': { es: 'Cometí un herror al escribir mi dirección de correo electrónico.', ja: 'メールアドレスを入力する際に間違いを犯してしまいました。', trivia: '※入力リストでは herror と表記されているが、正しいスペルは error。ラテン語 error（迷い、間違い）に由来し、英語 error と完全な同形コグネート。動詞 errar（迷う、誤る）も同語根で、英語 err（誤る）と対応する。' },
  'hija': { es: 'Mi hija mayor acaba de graduarse de la universidad con honores.', ja: '私の長女はつい最近、優秀な成績で大学を卒業しました。', trivia: 'ラテン語 filia（娘）に由来し、語頭の f が h に変化したスペイン語の代表例の一つ。英語 filial（親子間の）や affiliate（提携する）は同語根 filia から来ており、英語では daughter（古英語系）が意味的に相当する。' },
  'hilo': { es: 'Perdí el hilo de la conversación cuando sonó el teléfono.', ja: '電話が鳴ったとき、会話の流れを見失ってしまいました。', trivia: 'ラテン語 filum（糸、線）に由来し、英語 filament（フィラメント、細糸）や file（ファイル、列）と同語根。「スレッドを追う」という意味でのネット用語 hilo（スレッド）は、英語の thread と全く同じ比喩的拡張を経ている。' },
  'hogar': { es: 'Después de años viviendo en el extranjero, por fin volvió a su hogar.', ja: '何年も海外で暮らした後、彼はついに自分の家に戻りました。', trivia: 'ラテン語 focaris（炉の）に由来し、focus（炉、かまど）が語根。英語 focus は同語根で、もともとラテン語で「炉・家庭の中心」を意味した。「家族が集まる炉端」という概念が home の意味につながっており、英語 focus との意外な共通祖先を持つ。' },
  'hoja': { es: 'El viento llevaba una hoja seca de árbol a través del patio.', ja: '風が一枚の枯れ葉を庭の向こうへ運んでいました。', trivia: 'ラテン語 folia（葉、複数形）に由来し、英語 foliage（葉、葉叢）や folio（フォリオ判、葉）と同語根。英語では leaf（古英語系）が意味的に相当するが、folio（書類の「葉」）という意味での hoja との繋がりは今も感じられる。' },
  'hombro': { es: 'El jugador de baloncesto llevaba a su hija pequeña sobre los hombros.', ja: 'そのバスケットボール選手は幼い娘を肩の上に乗せていました。', trivia: 'ラテン語 humerus（肩、上腕骨）に由来し、英語 humerus（上腕骨）と同語根の医学用語として残っている。英語の日常語 shoulder は古英語系で語根が異なるが、解剖学では humeral（上腕の）という形で同語根語が使われる。' },
  'horario': { es: 'El horario del autobús ha cambiado; ahora sale a las ocho y media.', ja: 'バスの時刻表が変わりました。今は8時半に出発します。', trivia: 'ラテン語 horarius（時間の、時刻の）に由来し、hora（時間）が語根。英語 hour（時間）は同語根で、古フランス語 hore を経由して英語に入った。英語では schedule や timetable が意味的に相当するが、horary（時間の）という英語の専門語も同語根から来ている。' },
  'hospital': { es: 'Tuvieron que llevarla al hospital de urgencias después del accidente.', ja: '事故の後、彼女を緊急病院に連れていかなければなりませんでした。', trivia: 'ラテン語 hospitalis（客を迎える、おもてなしの）に由来し、hospes（客人、主人）が語根。英語 hospital、hotel、host、hospitable はすべて同語根で、「客をもてなす場所」という概念が医療施設と宿泊施設の両方に分岐したことが見て取れる。' },
  'hotel': { es: 'Reservamos un hotel céntrico para estar cerca de todos los museos.', ja: 'すべての美術館に近い場所にいられるよう、中心部のホテルを予約しました。', trivia: 'フランス語 hôtel（館、宿泊施設）を通じてラテン語 hospitalis に由来し、英語 hotel と完全な同形コグネート。hospital と hotel は同語根であり、もともとどちらも「旅人や病者をもてなす施設」を指していたことから分化した語である。' },
  'huida': { es: 'La huida del prisionero fue detectada a las pocas horas de producirse.', ja: '囚人の逃亡は発生からわずか数時間で発覚しました。', trivia: '動詞 huir（逃げる）の名詞形で、ラテン語 fugere（逃げる）と関係するとも、古代ゲルマン語の影響とも言われるが語源には諸説ある。英語 fugitive（逃亡者）や fugue（遁走曲）はラテン語 fugere 由来で意味的に関連し、flight（逃亡）が日常語として相当する。' },
  'huir': { es: 'El sospechoso intentó huir, pero fue detenido por la policía.', ja: '容疑者は逃げようとしましたが、警察に取り押さえられました。', trivia: '語源については、ラテン語 fugere に由来するという説と、より複雑な音韻変化を経たとする説がある。英語 fugitive（逃亡者）、refuge（避難所）、subterfuge（ごまかし）はラテン語 fugere 由来で、英語の日常語 flee や escape が意味的に対応する。' },
  'humor': { es: 'El buen humor de los actores hizo reír a todo el público.', ja: '俳優たちの明るいユーモアが観客全員を笑わせました。', trivia: 'ラテン語 humor（液体、体液）に由来し、中世医学の「四体液説」では体液のバランスが気分を左右すると考えられていた。英語 humor（ユーモア、気分）と完全な同形コグネートで、「液体」から「気分」、さらに「おかしみ」へと意味が変化した興味深い語義変化を共有している。' },
  'i': { es: 'En catalán se dice «pa i vi» para referirse al pan y al vino.', ja: 'カタルーニャ語ではパンとワインのことを「pa i vi」と言います。', trivia: '※入力リストでは標準スペイン語の y（そして）の異形として記載されているが、i は主にカタルーニャ語の接続詞。標準スペイン語では、次の語が i または hi で始まる場合に限り y の代わりに e を使う規則がある。英語の and に相当し、ラテン語 et（英語 et cetera の et）とは別系統。' },
  'idioma': { es: 'El español es un idioma hablado por más de 500 millones de personas en todo el mundo.', ja: 'スペイン語は世界中で5億人以上に話されている言語だ。', trivia: 'ギリシャ語の「idioma（固有の特質）」に由来し、「idios（自分自身の）」が語根。英語の「idiom（慣用句）」と同語根だが、英語では「idiom」は個別の慣用表現を指し、スペイン語の「idioma」のように言語全体を意味することは少ない。' },
  'iglesia': { es: 'La iglesia del pueblo fue construida en el siglo XVII.', ja: 'その村の教会は17世紀に建てられた。', trivia: 'ラテン語「ecclesia」、さらにギリシャ語「ekklēsia（召集された集会）」に由来。英語の「ecclesiastical（教会の）」と同語根であり、英語では建物としての「church」はゲルマン語系（ギリシャ語「kyriakon」由来）で語源が異なる。' },
  'igual': { es: 'Todos los ciudadanos son iguales ante la ley.', ja: 'すべての市民は法の前に平等だ。', trivia: 'ラテン語「aequalis（等しい）」に由来。英語の「equal」と同語根の直接的なコグネートで、スペルも意味も非常に近い。英語の「equator（赤道）」や「equitable（公平な）」も同じ語根を持つ。' },
  'iluminar': { es: 'Los faroles iluminan las calles del casco antiguo por la noche.', ja: '街灯が夜になると旧市街の通りを照らす。', trivia: 'ラテン語「illuminare（光を当てる）」に由来し、「in-（上に）＋lumen（光）」の合成語。英語の「illuminate」と同語根の直接的なコグネートで、「luminary（発光体、著名人）」や「luminous（発光する）」も同族語。' },
  'ilusión': { es: 'Tengo mucha ilusión por empezar el nuevo trabajo la semana que viene.', ja: '来週から新しい仕事が始まるのがとても楽しみだ。', trivia: 'ラテン語「illusio（嘲笑、欺き）」に由来し、「illudere（だます）」から派生。英語の「illusion（幻想）」と同語根だが、スペイン語では「期待・楽しみ・わくわく感」という肯定的な意味でも頻繁に使われる点が大きく異なる（英語の「illusion」は欺きの意味が強い）。' },
  'imagen': { es: 'La imagen que publicó en redes sociales recibió miles de comentarios.', ja: '彼女がSNSに投稿した画像には何千ものコメントが寄せられた。', trivia: 'ラテン語「imago（像、姿）」に由来し、「imitari（模倣する）」とも関連するとされる。英語の「image」と同語根の直接的なコグネートで、「imagination」「imagine」「imagery」なども同族語。' },
  'imaginación': { es: 'Los niños tienen una imaginación desbordante que sorprende a los adultos.', ja: '子どもたちはあふれんばかりの想像力を持っており、大人を驚かせる。', trivia: 'ラテン語「imaginatio（心に描くこと）」に由来し、「imago（像）」が語根。英語の「imagination」と同語根のコグネートで、スペルも意味もほぼ同一。英語の「imaginative」「imaginary」も同族語。' },
  'imaginar': { es: 'Imagina que puedes viajar a cualquier lugar del mundo, ¿adónde irías?', ja: '世界のどこへでも旅できると想像してみて。どこへ行く？', trivia: 'ラテン語「imaginari（心に思い描く）」に由来し、「imago（像）」が語根。英語の「imagine」と同語根のコグネートで、語末変化がほぼ対応する。哲学・詩歌においても古くから使われてきた語。' },
  'impedir': { es: 'El mal tiempo impidió que el vuelo despegara a tiempo.', ja: '悪天候のせいで、フライトは時間どおりに離陸できなかった。', trivia: 'ラテン語「impedire（足かせをはめる）」に由来し、「in-（中に）＋pes/pedis（足）」の合成語。英語の「impede（妨げる）」と同語根のコグネート。「pedal（ペダル）」「pedestrian（歩行者）」「expedition（遠征）」なども同じ「pes」語根を持つ。' },
  'imperio': { es: 'El Imperio romano dejó una huella profunda en la cultura y el derecho europeos.', ja: 'ローマ帝国はヨーロッパの文化と法律に深い痕跡を残した。', trivia: 'ラテン語「imperium（命令権、支配）」に由来し、「imperare（命令する）」が語根。英語の「empire」はフランス語経由で同語根、「imperial（帝国の）」「imperious（威圧的な）」も同族語。' },
  'implicar': { es: 'Aceptar ese trabajo implica mudarse a otra ciudad.', ja: 'その仕事を受けることは、別の都市に引っ越すことを意味する。', trivia: 'ラテン語「implicare（折り込む、巻き付ける）」に由来し、「in-（中に）＋plicare（折る）」の合成語。英語の「implicate」と同語根のコグネートで、「imply（暗示する）」「explicit（明示的な）」「complicate（複雑にする）」も同族語。' },
  'importancia': { es: 'No hay que restarle importancia a los pequeños gestos de amabilidad.', ja: '小さな親切の身振りの重要性を軽視してはならない。', trivia: 'ラテン語「importare（持ち込む、意味する）」に由来し、「in-（中に）＋portare（運ぶ）」の合成語。英語の「importance」と同語根のコグネートで、スペルも意味も非常に近い。「porter（ポーター）」「transport（輸送）」も同族語。' },
  'importar': { es: 'No me importa lo que digan los demás; seguiré mi propio camino.', ja: '他の人が何を言おうと気にしない。自分の道を歩み続ける。', trivia: 'ラテン語「importare（持ち込む）」に由来。英語では「import（輸入する、重要性）」と同語根のコグネートだが、スペイン語の「importar」は「気にかかる・重要である」という意味でも日常的に多用され、英語の「matter（重要である）」に相当する用法が特徴的。' },
  'imposible': { es: 'Parece imposible, pero con esfuerzo y dedicación se puede conseguir.', ja: '不可能に思えるが、努力と献身があれば達成できる。', trivia: 'ラテン語「impossibilis（できない）」に由来し、「in-（否定）＋possibilis（可能な）」の合成語。英語の「impossible」と同語根の直接的なコグネートで、スペルも意味もほぼ同一。「possible」「potent」「power」も同じラテン語「posse（できる）」語根に遡る。' },
  'impuesto': { es: 'El gobierno ha decidido aumentar el impuesto sobre las bebidas azucaradas.', ja: '政府は砂糖入り飲料への税金を引き上げることを決定した。', trivia: 'ラテン語「imponere（課す）」の過去分詞「impositus」が転じた形で、「in-（上に）＋ponere（置く）」が語根。英語では「impose（課す）」と同語根だが、税金という名詞には「tax」（古フランス語「taxe」由来）を使う点が異なる。' },
  'impresión': { es: 'Me causó muy buena impresión cuando lo conocí en la reunión.', ja: '会議で彼と知り合ったとき、とても良い印象を受けた。', trivia: 'ラテン語「impressio（押しつけること）」に由来し、「imprimere（押しつける）」が語根。英語の「impression」と同語根の直接的なコグネートで、「impress」「print」「compress」なども同族語。グーテンベルク以来「印刷」の意味でも使われてきた。' },
  'impulsar': { es: 'El gobierno quiere impulsar el uso de energías renovables en todo el país.', ja: '政府は国全体での再生可能エネルギーの利用を推進したいと考えている。', trivia: 'ラテン語「impulsare（繰り返し押す）」に由来し、「impellere（駆り立てる）」の反復動詞。英語の「impel（駆り立てる）」や「impulse（衝動）」と同語根で、「in-（上に）＋pellere（押す）」が語源。「propel（推進する）」「compel（強制する）」も同族語。' },
  'impulso': { es: 'Actuó por impulso y después se arrepintió de lo que había dicho.', ja: '彼は衝動で行動し、後で自分が言ったことを後悔した。', trivia: 'ラテン語「impulsus（押すこと）」に由来し、「impellere（駆り立てる）」の名詞形。英語の「impulse」と同語根の直接的なコグネートで、スペルも意味も非常に近い。「pulse（脈拍）」「repulse（撃退する）」「propulsion（推進力）」も同じ「pellere」語根を持つ。' },
  'inal': { es: 'Al inal del camino, encontramos una pequeña aldea escondida entre los árboles.', ja: '道の終わりに、木々の間に隠れた小さな村を見つけた。', trivia: '「final（終わり）」の誤記・略記とされる語で、ラテン語「finis（境界、終わり）」に由来。英語の「final」と同語根のコグネートで、「finish（終える）」「finite（有限の）」「define（定義する）」なども同族語。' },
  'incapié': { es: 'El profesor hizo incapié en la importancia de revisar bien los exámenes.', ja: '先生は試験をしっかり見直すことの重要性を強調した。', trivia: '「hincapié（強調）」の誤記とされる語で、本来の「hincapié」はスペイン語「hincar（突き刺す）＋pie（足）」の合成語。英語に直接対応するコグネートはないが、「hacer hincapié（強調する）」は英語の「emphasize」や「stress」に相当する慣用表現。' },
  'incendio': { es: 'Los bomberos tardaron varias horas en controlar el incendio del edificio.', ja: '消防士たちはビルの火災を鎮圧するのに数時間かかった。', trivia: 'ラテン語「incendium（火事）」に由来し、「incendere（火をつける）」が語根で「in-（中に）＋candere（輝く、燃える）」の合成語。英語の「incendiary（放火の、煽動的な）」と同語根で、「candid（率直な）」「candle（ろうそく）」も同じ「candere」に遡る。' },
  'incertidumbre': { es: 'La incertidumbre sobre el futuro económico preocupa a muchas familias.', ja: '経済の先行きへの不確実性が多くの家族を心配させている。', trivia: 'ラテン語「incertus（不確かな）」に由来し、「in-（否定）＋certus（確かな）」の合成語。英語の「uncertainty」は同じラテン語語根を持つが、スペイン語は接尾辞「-dumbre」（ラテン語「-tudo」由来）を使う点が異なる。英語の「certain（確かな）」「certify（証明する）」も同族語。' },
  'incluir': { es: 'El precio del hotel incluye el desayuno y el acceso al gimnasio.', ja: 'ホテルの料金には朝食とジムの利用が含まれている。', trivia: 'ラテン語「includere（閉じ込める）」に由来し、「in-（中に）＋claudere（閉じる）」の合成語。英語の「include」と同語根の直接的なコグネートで、「exclude（除外する）」「conclude（結論づける）」「clause（節、条項）」なども同族語。' },
  'incluso': { es: 'Incluso los expertos cometieron errores en ese proyecto tan complicado.', ja: 'あれほど複雑なプロジェクトでは、専門家でさえミスを犯した。', trivia: 'ラテン語「inclusus（閉じ込められた）」、「includere（含む）」の過去分詞が副詞化した語。英語の「even（〜さえも）」に意味的に相当するが、語形は英語「included」に近い。「exclusive（排他的な）」「conclusive（決定的な）」も同じ「claudere」語根を持つ。' },
  'incorporar': { es: 'La empresa decidió incorporar nuevas tecnologías para mejorar la productividad.', ja: 'その会社は生産性を向上させるために新技術を取り入れることを決定した。', trivia: 'ラテン語「incorporare（体に取り込む）」に由来し、「in-（中に）＋corpus（体）」の合成語。英語の「incorporate」と同語根の直接的なコグネートで、「corporal（身体の）」「corporation（法人）」「corpse（死体）」なども同じ「corpus」語根を持つ。' },
  'incrementar': { es: 'El gobierno planea incrementar el presupuesto en educación un diez por ciento el próximo año.', ja: '政府は来年、教育予算を10パーセント増やす計画を立てている。', trivia: 'ラテン語 incrementum（増加）に由来し、動詞化したもの。英語の increment（増分、増加）と同語根で、意味もほぼ同じ。' },
  'incremento': { es: 'El incremento de los precios del petróleo afecta a toda la economía mundial.', ja: '石油価格の上昇は世界経済全体に影響を及ぼす。', trivia: 'ラテン語 incrementum（crescere「成長する」の派生語）に直接由来。英語の increment と完全に同語根であり、どちらも「段階的な増加」を意味する。' },
  'independencia': { es: 'México celebra su independencia el dieciséis de septiembre de cada año.', ja: 'メキシコは毎年9月16日に独立記念日を祝う。', trivia: 'ラテン語の否定接頭辞 in- と dependere（ぶら下がる、依存する）に由来。英語の independence と同語根・同意味であり、スペルもほぼ同じいわゆる「見た目の友人（true cognate）」。' },
  'independiente': { es: 'Es una artista independiente que produce y distribuye su propia música sin sello discográfico.', ja: '彼女はレコード会社を持たずに自分で音楽を制作・配信するインディペンデントアーティストだ。', trivia: 'independencia と同じく in- + dependere に由来する形容詞形。英語の independent と同語根で、略して「インディー」（indie）と呼ぶ用法も両言語で共通。' },
  'indicar': { es: 'El médico indicó que debía descansar al menos una semana.', ja: '医師は少なくとも1週間休むよう指示した。', trivia: 'ラテン語 indicare（指し示す、宣言する）に由来し、接頭辞 in- と dicere（言う）の組み合わせ。英語の indicate と同語根で、indicate・index・indicate はすべて同じ語根 dic- を共有する。' },
  'indicio': { es: 'La policía encontró varios indicios en la escena del crimen que apuntaban al sospechoso.', ja: '警察は犯行現場で容疑者を指し示すいくつかの手がかりを発見した。', trivia: 'ラテン語 indicium（サイン、証拠）に由来し、indicare と同じ語根 dic- を持つ。英語には直接の同形語はないが、indicia（法律用語で「証拠物件」の複数形）として痕跡が残っている。' },
  'individuo': { es: 'Cada individuo tiene el derecho de expresar libremente su opinión.', ja: '人はだれでも自由に意見を表明する権利を持っている。', trivia: 'ラテン語 individuum（分割できないもの）に由来し、in-（否定）＋ dividere（分ける）の構成。英語の individual と同語根で、divide・individual・indivisible はすべてこの語幹から来ている。' },
  'industria': { es: 'La industria automotriz es uno de los pilares de la economía mexicana.', ja: '自動車産業はメキシコ経済の柱の一つだ。', trivia: 'ラテン語 industria（勤勉、活動）に由来し、語源的には「その中で構築する」意を持つとされる。英語の industry と同語根・同形の典型的な真のコグネート（true cognate）。' },
  'infancia': { es: 'Pasó su infancia en un pequeño pueblo rodeado de montañas.', ja: '彼は山に囲まれた小さな村で幼少期を過ごした。', trivia: 'ラテン語 infantia（話すことができない時期）に由来し、in-（否定）＋ fari（話す）の構成。英語の infancy・infant と同語根で、「まだ話せない子」が原義。' },
  'infección': { es: 'El médico recetó antibióticos para tratar la infección bacteriana.', ja: '医師は細菌感染を治療するために抗生物質を処方した。', trivia: 'ラテン語 infectio（染め込む、汚染する）に由来し、in-（中へ）＋ facere（する、作る）の構成。英語の infection と完全に同語根で、defect・affect・infect はすべて -fect-（facere の変形）を共有する。' },
  'inferior': { es: 'La calidad de este producto es claramente inferior a la de la marca anterior.', ja: 'この製品の品質は以前のブランドのものより明らかに劣っている。', trivia: 'ラテン語 inferior（下の、より低い）の比較級形に由来し、inferus（下にある）が語源。英語の inferior と同語根・同形の真のコグネートで、地獄を意味する inferno もこの語根を持つ。' },
  'inflación': { es: 'La inflación ha subido tanto que muchas familias tienen dificultades para llegar a fin de mes.', ja: 'インフレが非常に上昇したため、多くの家庭が月末まで家計をやりくりするのに苦労している。', trivia: 'ラテン語 inflatio（膨らませること）に由来し、in-＋ flare（吹く）の構成。英語の inflation と同語根で、inflate（膨らます）・deflation（デフレ）もすべてこの flare を語根に持つ。' },
  'influir': { es: 'La música que escuchamos en la infancia suele influir en nuestros gustos de adultos.', ja: '幼少期に聴いた音楽は、大人になってからの趣味に影響を及ぼすことが多い。', trivia: 'ラテン語 influere（流れ込む）に由来し、in-（中へ）＋ fluere（流れる）の構成。英語の influence・influenza（本来「星の影響」の意）と同語根で、fluid・flux もこの fluere から来ている。' },
  'información': { es: 'Puedes encontrar toda la información necesaria en la página web oficial.', ja: '必要な情報はすべて公式ウェブページで確認できます。', trivia: 'ラテン語 informatio（形を与えること、概念）に由来し、in-＋ forma（形）の構成。英語の information と同語根・同形の典型的真のコグネートで、form・reform・uniform もこの forma から来ている。' },
  'informar': { es: 'La empresa informó a sus empleados sobre los nuevos cambios en el contrato.', ja: '会社は従業員に契約の新たな変更点について通知した。', trivia: 'ラテン語 informare（形を与える、教える）に由来し、información と同じ語根。英語の inform と同語根・同形の真のコグネートで、「形を与えることで知識を与える」という原義から「伝える」の意に発展した。' },
  'informe': { es: 'El ministro presentó un informe detallado sobre la situación económica del país.', ja: '大臣は国の経済状況に関する詳細な報告書を提出した。', trivia: 'informar と同語根で、動詞の名詞形（report の意）として用いられる。英語では同じ形 inform から直接名詞は作らず report を使うが、スペイン語では informe が「レポート」に相当する自然な語として定着している。' },
  'ingeniería': { es: 'Estudia ingeniería civil en la universidad politécnica de la ciudad.', ja: '彼は市の工科大学で土木工学を学んでいる。', trivia: 'ラテン語 ingenium（才能、独創性、巧みな仕掛け）に由来し、in-＋ gignere（生む）の構成。英語の engineering と同語根で、engine・ingenious・genius もすべてこの gignere/gen- を語根に持つ。' },
  'ingeniero': { es: 'El ingeniero revisó los planos antes de comenzar la construcción del puente.', ja: '技術者は橋の建設を始める前に設計図を確認した。', trivia: 'ingeniería と同じくラテン語 ingenium に由来する職業名詞。英語の engineer と同語根で、両語はスペルも発音も非常に近い真のコグネート。' },
  'Inglaterra': { es: 'Mi prima vive en Inglaterra desde hace más de diez años y trabaja en Londres.', ja: '私のいとこは10年以上イングランドに住んでいて、ロンドンで働いている。', trivia: '中世ラテン語 Anglia（アングル人の土地）に由来し、ゲルマン系のアングル人（Angles）の名前から来ている。英語の England と同語根で、どちらも「アングル人の土地」という意味を持つ。' },
  'inglés': { es: 'Hablar inglés con fluidez es una ventaja enorme en el mercado laboral actual.', ja: '英語を流暢に話すことは、現在の労働市場では大きなアドバンテージだ。', trivia: 'Inglaterra と同じくアングル人（Angles）の名に由来する形容詞・名詞形。英語の English と同語根で、「アングル人の（言語・人）」を意味するが、スペイン語では inglés が England も指すこともあるため、英語話者には文脈が紛らわしいことがある。' },
  'ingresar': { es: 'Su hijo ingresó en la mejor universidad del país tras estudiar durante dos años.', ja: '彼の息子は2年間勉強した末に、国内最高の大学に入学した。', trivia: 'ラテン語 ingressus（入ること）に由来し、in-（中へ）＋ gradi（歩く）の構成。英語の ingress（入口、進入）と同語根だが、英語では日常語として使われず、ingress はやや専門的・形式的な語として残っている。' },
  'ingreso': { es: 'Sus ingresos mensuales no son suficientes para cubrir todos los gastos del hogar.', ja: '彼の月収は家庭のすべての出費を賄うのには十分ではない。', trivia: 'ingresar と同語根のラテン語 ingressus に由来する名詞形。英語の ingress と同語根だが、ingreso は「収入・所得」の意でも広く使われ、英語の income（中英語期に別語根 come in から形成）に相当する意味を担う点が興味深い。' },
  'iniciativa': { es: 'La directora tomó la iniciativa y propuso un plan para mejorar las condiciones laborales.', ja: '女性部長が主導権を取り、労働条件改善のための計画を提案した。', trivia: 'ラテン語 initium（始まり）に由来し、in-（中へ）＋ ire（行く）の構成。英語の initiative と完全に同語根・同形の真のコグネートで、initial・initiate もすべて initium を語根に持つ。' },
  'inmediato': { es: 'La policía llegó de forma inmediata al lugar del accidente.', ja: '警察は事故現場に即座に到着した。', trivia: 'ラテン語 immediatus（間に何もない）に由来し、in-（否定）＋ medius（中間の）の構成。英語の immediate と同語根・同形の真のコグネートで、medium・mediate・medieval もすべてこの medius から来ている。' },
  'inmenso': { es: 'El desierto del Sahara es un espacio inmenso que abarca varios países africanos.', ja: 'サハラ砂漠は複数のアフリカ諸国にまたがる広大な空間だ。', trivia: 'ラテン語 immensus（測れないほど大きい）に由来し、in-（否定）＋ mensus（metiri「測る」の過去分詞）の構成。英語の immense と同語根・同意味の真のコグネートで、measure・dimension もこの metiri を語根に持つ。' },
  'innovar': { es: 'Las empresas tecnológicas deben innovar constantemente para mantenerse competitivas en el mercado global.', ja: 'テクノロジー企業はグローバル市場で競争力を維持するために、常に革新し続けなければならない。', trivia: 'ラテン語 innovare（in-「中に」+ novus「新しい」）から来ており、「新しいものを取り込む」が原義。英語の innovate と完全に同語根の国際語で、スペルも非常に近い。' },
  'inocente': { es: 'El jurado declaró inocente al acusado por falta de pruebas suficientes.', ja: '陪審員は証拠不十分として被告を無罪と宣言した。', trivia: 'ラテン語 innocens（in-「否定」+ nocens「害を与える者」、nocere「傷つける」の現在分詞）が語源。英語の innocent と同語根であり、スペル・意味ともほぼ同一のコグネート。' },
  'inquietud': { es: 'Sentía una profunda inquietud ante los resultados del examen final.', ja: '期末試験の結果を前に、深い不安を感じていた。', trivia: 'ラテン語 inquietudo（in-「否定」+ quies「静けさ、休息」）から派生し、「落ち着きのなさ」が原義。英語の unrest や disquiet に意味が近く、quiet（静かな）と同語根を持つ。' },
  'inscribir': { es: 'Me voy a inscribir en un curso de cocina española que empieza el próximo mes.', ja: '来月始まるスペイン料理のコースに申し込むつもりだ。', trivia: 'ラテン語 inscribere（in-「上に」+ scribere「書く」）が語源で、「書き記す」が原義。英語の inscribe と同語根であり、subscribe（申し込む）や describe（描写する）とも同じ scribere の系譜に属する。' },
  'insecto': { es: 'El insecto más peligroso del mundo es el mosquito, que transmite enfermedades mortales.', ja: '世界で最も危険な昆虫は蚊であり、致死的な病気を媒介する。', trivia: 'ラテン語 insectum（insectus「切り刻まれた」の中性形）が語源で、昆虫の体が節によって「切り分けられた」ように見えることに由来。英語の insect と同語根の直接的なコグネートで、意味・スペルともほぼ同一。' },
  'insistir': { es: 'El médico insistió en que el paciente debía guardar reposo durante al menos una semana.', ja: '医者は患者が少なくとも一週間は安静にしなければならないと強く主張した。', trivia: 'ラテン語 insistere（in-「上に」+ sistere「立つ、立ち止まる」）から来ており、「ある立場に居続ける」が原義。英語の insist と同語根の明確なコグネートで、persist（持続する）や resist（抵抗する）とも同じ sistere の系譜。' },
  'inspección': { es: 'La inspección sanitaria del restaurante reveló varias irregularidades en la cocina.', ja: 'そのレストランの衛生検査で、厨房にいくつかの違反が発覚した。', trivia: 'ラテン語 inspectionem（inspicere「中を見る」の名詞形、in-「中を」+ specere「見る」）が語源。英語の inspection と同語根で、spectacle（見せ物）や respect（尊重する）とも同じ specere の系譜に属する。' },
  'inspirar': { es: 'El discurso del líder inspiró a toda la comunidad a trabajar por el bien común.', ja: 'そのリーダーの演説は、共通善のために働くよう地域社会全体を鼓舞した。', trivia: 'ラテン語 inspirare（in-「中に」+ spirare「息をする、吹く」）が語源で、元来は「息を吹き込む」という神が人間に霊感を与える意味を持っていた。英語の inspire と同語根であり、spirit（精神）や expire（期限が切れる、息を引き取る）とも同じ spirare の系譜。' },
  'instalar': { es: 'El técnico tardó dos horas en instalar el nuevo sistema de aire acondicionado.', ja: '技術者が新しいエアコンシステムを設置するのに2時間かかった。', trivia: '中世ラテン語 installare（in-「中に」+ stallum「場所、馬房」、ゲルマン語起源）が語源で、「所定の場所に置く・据える」が原義。英語の install と同語根のコグネートで、stall（馬房、露店）とも同じゲルマン語系の語根に遡る。' },
  'instancia': { es: 'Presentó una instancia formal al director para solicitar el cambio de horario.', ja: '時間割の変更を申請するために、校長に正式な申請書を提出した。', trivia: 'ラテン語 instantia（instare「迫る、要求する」の名詞形、in-「上に」+ stare「立つ」）が語源。英語の instance と同語根だが、英語では「例、事例」の意味が主流であるのに対し、スペイン語では「申請・嘆願」の意味が強い点に注意が必要な偽コグネート的側面を持つ。' },
  'instante': { es: 'En ese instante, comprendí que mi vida iba a cambiar para siempre.', ja: 'その瞬間、私は自分の人生が永遠に変わるのだと悟った。', trivia: 'ラテン語 instans（instare「迫る、差し迫っている」の現在分詞）が語源で、「今この瞬間に迫っている時」が原義。英語の instant と同語根の直接的なコグネートで、al instante（即座に）は英語の instantly に相当する。' },
  'instituto': { es: 'Mi hijo estudia en un instituto público y le encanta la clase de biología.', ja: '私の息子は公立の中高等学校に通っており、生物の授業が大好きだ。', trivia: 'ラテン語 institutum（instituere「設立する、定める」の過去分詞）が語源。英語の institute と同語根のコグネートだが、スペインでは中等教育機関（日本の中学・高校に相当）を指すことが多く、英語の institute が主に研究機関や協会を意味する点で用法が異なる。' },
  'institución': { es: 'La familia es considerada una institución fundamental en muchas sociedades del mundo.', ja: '家族は世界の多くの社会において基本的な制度とみなされている。', trivia: 'ラテン語 institutionem（instituere「設立する」の名詞形）が語源で、institute と同じ語根に由来する。英語の institution と同語根の直接的なコグネートで、意味・用法ともほぼ一致する国際語。' },
  'instruir': { es: 'La profesora instruyó a los alumnos sobre cómo utilizar el laboratorio de química de forma segura.', ja: '先生は生徒たちに化学実験室を安全に使う方法を指導した。', trivia: 'ラテン語 instruere（in-「中に」+ struere「積み上げる、建てる」）が語源で、「知識を積み上げて構築する」が原義。英語の instruct と同語根のコグネートで、construct（建設する）や structure（構造）とも同じ struere の系譜に属する。' },
  'instrumento': { es: 'El violín es un instrumento muy difícil de dominar, pero su sonido es incomparable.', ja: 'バイオリンは習得がとても難しい楽器だが、その音色は比類がない。', trivia: 'ラテン語 instrumentum（instruere「準備する、整える」の派生名詞）が語源で、「手段・道具」が原義。英語の instrument と同語根の直接的なコグネートで、スペル・意味ともほぼ同一。' },
  'insultar': { es: 'No está bien insultar a las personas por su apariencia física o su forma de hablar.', ja: '人の外見や話し方で侮辱することは良くない。', trivia: 'ラテン語 insultare（in-「上に」+ saltare「跳ぶ」、saltus「跳躍」の頻繁形）が語源で、「上に飛びかかる、踏みにじる」が原義。英語の insult と同語根のコグネートで、assault（暴行）や somersault（宙返り）とも同じ saltare の系譜に属する。' },
  'insulto': { es: 'Ese insulto le dolió profundamente porque venía de su mejor amigo.', ja: 'その侮辱は親友から来たものだったので、深く傷ついた。', trivia: 'ラテン語 insultus（insultare「跳びかかる」の名詞形）が語源で、insultar と同じ語根を持つ。英語の insult（名詞）と同語根の直接的なコグネートで、スペル・意味ともほぼ同一。' },
  'integrar': { es: 'Es importante integrar a los nuevos empleados en el equipo desde el primer día de trabajo.', ja: '新入社員を初日から職場のチームに溶け込ませることが大切だ。', trivia: 'ラテン語 integrare（integer「完全な、手つかずの」の動詞形）が語源で、「完全な状態に戻す・一体化する」が原義。英語の integrate と同語根のコグネートで、entire（全体の）や integrity（誠実さ、統一性）とも同じ integer の系譜に属する。' },
  'intelectual': { es: 'La novela fue muy apreciada en los círculos intelectuales de la ciudad.', ja: 'その小説は市内の知識人の間で高く評価された。', trivia: 'ラテン語 intellectualis（intellectus「理解、知性」の形容詞形、intelligere「理解する」の過去分詞）が語源。英語の intellectual と同語根の直接的なコグネートで、intellect（知性）や intelligence（知能）とも同じ系譜に属する国際語。' },
  'inteligencia': { es: 'La inteligencia artificial está transformando la manera en que trabajamos y nos comunicamos.', ja: '人工知能は私たちの働き方やコミュニケーションの方法を変えつつある。', trivia: 'ラテン語 intelligentia（intelligere「理解する」の名詞形、inter-「間で」+ legere「選ぶ、読む」）が語源で、「識別する能力」が原義。英語の intelligence と同語根のコグネートで、neglect（怠る）や select（選ぶ）とも同じ legere の系譜に属する。' },
  'inteligente': { es: 'Aunque es muy inteligente, siempre busca la opinión de los demás antes de tomar decisiones.', ja: 'とても賢いにもかかわらず、彼女は決断を下す前に常に他の人の意見を求める。', trivia: 'ラテン語 intelligens（intelligere「理解する」の現在分詞）が語源で、inteligencia と同じ語根を持つ。英語の intelligent と同語根の明確なコグネートで、スペル・意味ともほぼ同一の国際語。' },
  'intención': { es: 'No tenía ninguna mala intención; solo quería ayudar a su compañera.', ja: '悪意は全くなかった。ただ同僚を助けたかっただけだった。', trivia: 'ラテン語 intentionem（intendere「向ける、張る」の名詞形、in-「向かって」+ tendere「伸ばす」）が語源で、「心を特定の方向に向けること」が原義。英語の intention と同語根の直接的なコグネートで、tend（傾向がある）や tension（緊張）とも同じ tendere の系譜。' },
  'intensificar': { es: 'Las lluvias se intensificaron durante la noche, causando inundaciones en varias zonas de la ciudad.', ja: '夜間に雨が激しくなり、市内数か所で洪水が発生した。', trivia: 'ラテン語 intensus（intendere「強く張る」の過去分詞）＋ facere（「する、作る」）の合成語が語源で、「強い状態にする」が原義。英語の intensify と同語根のコグネートで、intense（激しい）や intention（意図）とも同じ intendere の系譜に属する。' },
  'intenso': { es: 'Hubo un debate muy intenso sobre las medidas económicas propuestas por el gobierno.', ja: '政府が提案した経済対策について、非常に激しい議論が行われた。', trivia: 'ラテン語 intensus（intendere「強く張る」の過去分詞）が語源で、「強く引き伸ばされた」が原義。英語の intense と同語根の直接的なコグネートであり、スペル・意味ともほぼ同一。' },
  'intento': { es: 'A pesar de varios intentos, no pudo aprobar el examen de conducir.', ja: '何度か試みたにもかかわらず、運転免許試験に合格できなかった。', trivia: 'ラテン語 intentus（intendere「向ける」の過去分詞）またはその名詞形 intentum が語源。英語の intent（意図、形容詞では「熱中した」）と同語根のコグネートだが、スペイン語の intento は「試み・企て」の意味が主流で、英語の attempt に近い用法で使われることが多い。' },
  'intercambiar': { es: 'Los estudiantes intercambian ideas sobre el tema en grupos pequeños.', ja: '生徒たちは小グループでそのテーマについてアイデアを交換し合う。', trivia: 'ラテン語の「inter-（間で）」と「cambiare（交換する）」に由来し、英語の exchange や interchange と同語根。英語の interchange は名詞（高速道路のインターチェンジ）としてもよく使われる。' },
  'intercambio': { es: 'Hice un intercambio de idiomas con una chica francesa el verano pasado.', ja: '去年の夏、フランス人の女の子と語学交換をした。', trivia: 'intercambiar の名詞形で、英語の interchange に対応するが、スペイン語では「語学交流（intercambio de idiomas）」という表現で特によく使われる。英語の exchange とも意味・形が近い。' },
  'interesar': { es: 'A mi hermana le interesan mucho las novelas de ciencia ficción.', ja: '私の姉はSF小説にとても興味がある。', trivia: 'ラテン語「interesse（間にあること、関係すること）」に由来し、英語の interest と同語源。スペイン語では gustar と同様に「物が主語になり人が目的語（間接目的語）」という構文をとる点が特徴的。' },
  'interior': { es: 'El diseño interior del apartamento es muy moderno y luminoso.', ja: 'そのアパートのインテリアデザインはとてもモダンで明るい。', trivia: 'ラテン語「interior（内側の、より内部の）」の比較級形が直接スペイン語に入ったもので、英語の interior と完全に同語根・同義のコグネート。日本語の「インテリア」もこの語からの借用語。' },
  'internacional': { es: 'La empresa firmó un acuerdo internacional con socios de cinco países.', ja: 'その会社は5か国のパートナーと国際的な協定を結んだ。', trivia: 'ラテン語の「inter-（間で）」と「natio（国、民族）」を組み合わせた近代的な造語で、英語の international と完全に同語根・同形のコグネート。19世紀に政治・外交語として広まった。' },
  'internet': { es: 'Hoy en día es casi imposible vivir sin internet.', ja: '今日ではインターネットなしで生活することはほぼ不可能だ。', trivia: '英語の internet をそのまま借用した語で、もとは「inter-（間で）」と「network（ネットワーク）」を組み合わせた略語的造語。スペイン語では男性名詞（el internet）と女性名詞（la internet）の両方が使われる珍しい語。' },
  'interpretar': { es: 'La pianista interpretó una sonata de Beethoven con gran emoción.', ja: 'そのピアニストはベートーヴェンのソナタを深い感情を込めて演奏した。', trivia: 'ラテン語「interpretari（説明する、仲介する）」に由来し、英語の interpret と同語根。「解釈する・演奏する・通訳する」と意味が幅広い点は英語の interpret と共通しており、真のコグネートと言える。' },
  'intérprete': { es: 'Necesitamos un intérprete de japonés para la reunión de mañana.', ja: '明日の会議には日本語の通訳者が必要だ。', trivia: 'interpretar の動作主名詞で、英語の interpreter と同語根・同義のコグネート。ラテン語「interpres（仲介者、交渉人）」が語源で、もともとは「言語間を仲介する人」という意味から通訳者・演奏者の両義を持つ。' },
  'interrumpir': { es: 'Por favor, no me interrumpas cuando estoy hablando por teléfono.', ja: '電話で話しているときは邪魔しないでください。', trivia: 'ラテン語「interrumpere（断ち切る）」に由来し、「inter-（間で）」と「rumpere（壊す、破る）」の合成語。英語の interrupt と完全に同語根で、同じく「破壊・破裂」系の rupture や disrupt とも親戚関係にある。' },
  'intervención': { es: 'La intervención del gobierno fue necesaria para estabilizar la economía.', ja: '経済を安定させるために政府の介入が必要だった。', trivia: 'ラテン語「interventio（介在、仲介）」に由来し、英語の intervention と同語根・同義のコグネート。「inter-（間で）」と「venire（来る）」の合成で、「間に入ってくること」が原義。' },
  'intervenir': { es: 'El médico tuvo que intervenir de urgencia al paciente anoche.', ja: '医師は昨夜、患者に緊急手術を施さなければならなかった。', trivia: 'ラテン語「intervenire（間に入る）」に由来し、英語の intervene と同語根。スペイン語では「発言する・手術する」という医療的・政治的な意味まで広く使われるが、英語の intervene も「介入する」という意味で対応する。' },
  'intestino': { es: 'Una dieta rica en fibra es buena para la salud del intestino.', ja: '食物繊維の豊富な食事は腸の健康に良い。', trivia: 'ラテン語「intestinum（内側の、腸）」に由来し、英語の intestine と同語根のコグネート。「interior（内側）」と同じく「intus（内に）」が語根で、文字通り「体の内側にあるもの」という意味を持つ。' },
  'íntimo': { es: 'Solo le conté ese secreto a mis amigos más íntimos.', ja: 'その秘密を打ち明けたのは最も親しい友人たちだけだ。', trivia: 'ラテン語「intimus（最も内側の）」の最上級形が語源で、英語の intimate と同語根。「intus（内に）」から派生した点で interior や intestino とも遠い親戚関係にあり、「心の奥深く」というニュアンスが原義から来ている。' },
  'introducir': { es: 'La empresa va a introducir un nuevo sistema de pagos el próximo mes.', ja: 'その会社は来月新しい決済システムを導入する予定だ。', trivia: 'ラテン語「introducere（内部へ導く）」に由来し、「intro-（内へ）」と「ducere（導く）」の合成語。英語の introduce と同語根で、「リーダー（leader）」や「デューク（duke）」なども同じ ducere が語源の親戚語。' },
  'introducción': { es: 'La introducción del libro explica claramente el objetivo del autor.', ja: 'その本の序文には著者の意図が明確に説明されている。', trivia: 'introducir の名詞形で、英語の introduction と同語根・同義のコグネート。ラテン語「introductio」がそのまま両言語に伝わった例で、学術論文の「はじめに」という意味でも日常会話の「紹介」という意味でも英語と並行して使われる。' },
  'inundación': { es: 'Las inundaciones causadas por las lluvias torrenciales afectaron a miles de familias.', ja: '豪雨による洪水で何千もの家族が被害を受けた。', trivia: 'ラテン語「inundatio（溢れること）」に由来し、「in-（中に）」と「unda（波）」の合成語。英語の inundation と同語根で、英語の undulate（波打つ）や redundant（冗長な、波があふれる）とも語根が共通している。' },
  'invadir': { es: 'Las redes sociales han invadido todos los aspectos de nuestra vida cotidiana.', ja: 'SNSは私たちの日常生活のあらゆる側面に入り込んでいる。', trivia: 'ラテン語「invadere（攻め込む）」に由来し、「in-（中に）」と「vadere（行く）」の合成語。英語の invade と完全に同語根のコグネートで、英語の evade（回避する）や pervade（広がる）とも同じ vadere から派生している。' },
  'inventar': { es: '¿Quién inventó el teléfono? Hay varias teorías al respecto.', ja: '電話を発明したのは誰か。それについては諸説ある。', trivia: 'ラテン語「invenire（発見する、たどり着く）」に由来し、英語の invent と同語根のコグネート。「in-（上に）」と「venire（来る）」の合成で「偶然たどり着く」が原義。英語の event（出来事）や advent（到来）とも同じ venire が語根。' },
  'invento': { es: 'El invento del motor de vapor transformó la industria en el siglo XIX.', ja: '蒸気機関の発明は19世紀に産業を一変させた。', trivia: 'inventar の名詞形で、英語では invention に相当するが、スペイン語の invento はよりカジュアルに「発明品」を指す語として使われることが多い。ラテン語「inventum（発見されたもの）」が語源。' },
  'invertir': { es: 'Es recomendable invertir parte de los ahorros en fondos de inversión.', ja: '貯蓄の一部を投資信託に投資することが勧められる。', trivia: 'ラテン語「invertere（逆にする、ひっくり返す）」に由来し、「in-（中で）」と「vertere（回す、向ける）」の合成語。英語の invest と綴りは似るが語根が異なる点が注意で、invest はラテン語「vestire（着せる、取り囲む）」が語源。invertir の英語対応語は invert または invest（金融）。' },
  'investigación': { es: 'Los resultados de la investigación se publicarán en una revista científica.', ja: '研究の成果は科学誌に掲載される予定だ。', trivia: 'ラテン語「investigatio（追跡、調査）」に由来し、「in-（中で）」と「vestigium（足跡）」の合成語で「足跡をたどる」が原義。英語の investigation と同語根のコグネートで、英語の vestige（痕跡）も同じ vestigium から派生している。' },
  'investigar': { es: 'Los científicos investigan las causas del cambio climático desde hace décadas.', ja: '科学者たちは何十年も前から気候変動の原因を研究している。', trivia: 'investigación と同じくラテン語「investigare（足跡をたどる）」に由来し、英語の investigate と同語根。「足跡（vestige）をたどって真相に迫る」という原義が今も「捜査・調査」という意味に生きている。' },
  'invisible': { es: 'El gas es invisible, por eso puede ser muy peligroso si no se detecta.', ja: 'ガスは目に見えないため、検知されなければ非常に危険な場合がある。', trivia: 'ラテン語「invisibilis（見えない）」に由来し、「in-（否定）」と「visibilis（見える）」の合成語。英語の invisible と完全に同語根・同義のコグネートで、vision（視覚）や visual（視覚の）なども同じ videre（見る）という語根を持つ。' },
  'invitación': { es: 'Recibí una invitación para la boda de mi prima el próximo agosto.', ja: '来年8月の従妹の結婚式への招待状を受け取った。', trivia: 'ラテン語「invitatio（招待）」に由来し、英語の invitation と同語根のコグネート。語源はラテン語「invitare」だが、その究極の起源は諸説あり、「via（道）」関連とも「vitis（ぶどうの蔓）」関連とも言われる。' },
  'invitado': { es: 'Los invitados a la fiesta llegaron todos puntualmente a las ocho.', ja: 'パーティーへの招待客は全員8時きっかりに到着した。', trivia: 'invitar（招待する）の過去分詞が名詞化したもので、英語では guest または invited guest に相当する。英語の invite と同語根で、television番組の「ゲスト」も英語では guest だが、スペイン語ではinvitado を使う場面が多い。' },
  'izquierda': { es: 'Dobla a la izquierda en el semáforo y verás el banco.', ja: '信号で左に曲がると銀行が見えます。', trivia: '語源は不明確で諸説あり、バスク語起源説が有力とされる。英語の「left」とは語根が異なり、英語では left side / left-hand side に相当する。' },
  'jabón': { es: 'Recuerda lavarte las manos con jabón antes de comer.', ja: '食事の前には石鹸で手を洗うことを忘れずに。', trivia: 'ラテン語 sapo（石鹸）を経由し、ゲルマン語起源ともされる語。英語の soap と語根が近く、同じくゲルマン祖語 *saipô に遡る。' },
  'jardín': { es: 'Mi abuela cultiva rosas y lavanda en su jardín.', ja: '祖母は庭でバラとラベンダーを育てています。', trivia: 'フランク語（ゲルマン系）の gard（囲まれた場所）が語源で、フランス語 jardin を経由してスペイン語に入った。英語の garden と同語根で、いずれも「囲い」を意味するゲルマン祖語に由来する。' },
  'jarra': { es: 'El camarero nos trajo una jarra de agua fría para la mesa.', ja: 'ウェイターはテーブルに冷たい水のピッチャーを持ってきてくれた。', trivia: 'アラビア語 jarra（大きな土器の壺）に由来するとされ、スペインがイスラム支配下にあった時代（711〜1492年）に多くのアラビア語語彙がスペイン語に入った。英語の jar（瓶、壺）はスペイン語 jarra またはアラビア語から直接借用されたと考えられ、同語根の近縁語。' },
  'jefe': { es: 'Mi jefe me pidió que terminara el informe antes del viernes.', ja: '上司は金曜日までにレポートを仕上げるよう私に頼んだ。', trivia: 'フランス語 chef（頭、料理長）に由来し、ラテン語 caput（頭）が語源。英語の chef（料理長）および chief（長、主要な）と同語根で、英語の chief はフランス語からの直接借用だが、スペイン語 jefe は ch→j の音変化を経た形。英語の capital や captain も同じ caput から派生している。' },
  'joya': { es: 'Le regaló una joya de oro para celebrar su aniversario de bodas.', ja: '結婚記念日を祝うために、彼女に金のジュエリーをプレゼントした。', trivia: '古フランス語 joie または joel（宝石、喜び）に由来し、ラテン語 gaudium（喜び）に遡る。英語の jewel（宝石）と同語源で、英語では jewel が宝飾品を指す一方、joy（喜び）も同じ語根から派生しており、「宝石 ＝ 喜びをもたらすもの」という古代の意味的連鎖が見えて興味深い。' },
  'judío': { es: 'La comunidad judía de Madrid celebra sus fiestas religiosas con gran fervor.', ja: 'マドリードのユダヤ人コミュニティは宗教的な祝祭を大きな熱意をもって祝う。', trivia: 'ラテン語 Iudaeus、ギリシャ語 Ioudaios、ヘブライ語 Yehudah（ユダ族）に由来し、英語の Jewish および Judaic と同語根。英語の Jew はアングロ・フランス語 Giu を経由した形で、スペイン語 judío と英語 Jewish は語形は異なるが同じヘブライ語語根を共有する。' },
  'juego': { es: 'El juego de ajedrez requiere mucha concentración y estrategia.', ja: 'チェスというゲームは多くの集中力と戦略を必要とする。', trivia: 'ラテン語 iocus（冗談、遊び）に由来し、英語の joke（冗談）と同語根。英語でゲームや試合を指す game に相当するが、「一組のセット」という意味もスペイン語独自の広がりを持つ。' },
  'jueves': { es: 'Cada jueves tenemos una reunión de equipo en la oficina.', ja: '毎週木曜日、私たちはオフィスでチームミーティングを開く。', trivia: 'ラテン語 Iovis dies（ユピテルの日）に由来し、英語の Thursday（Thor\'s day、北欧神話の雷神トールの日）に意味上対応するが、語根は異なる。ローマとゲルマンで異なる神が雷神として対応していたことが興味深い。' },
  'juez': { es: 'La juez dictó una sentencia justa después de escuchar a ambas partes.', ja: '裁判官は双方の言い分を聞いた後、公正な判決を下した。', trivia: 'ラテン語 iudex（裁く者）に由来し、英語の judge と同語根。judge もスペイン語 juez も同じラテン語祖先を持つ正真正銘のコグネートである。' },
  'julio': { es: 'En julio hace mucho calor en Madrid, así que mucha gente se va a la playa.', ja: '7月はマドリードでとても暑いため、多くの人が海辺に出かける。', trivia: 'ローマの独裁官ユリウス・カエサル（Julius Caesar）の名に由来し、英語の July と完全に同語根の借用語。カエサルが生まれた月（諸説あり）または彼の名誉として名付けられたとされる。' },
  'junio': { es: 'Las flores de junio llenan el jardín de colores vivos.', ja: '6月の花々が庭を鮮やかな色で満たす。', trivia: 'ローマ神話の女神ユノ（Juno）、またはラテン語 iuniores（若者たち）に由来するという説があり、英語の June と同語根。古代ローマの暦でユノに捧げられた月とされる。' },
  'junto': { es: 'Siempre estudiamos juntos en la biblioteca los fines de semana.', ja: '私たちは週末にいつも一緒に図書館で勉強する。', trivia: 'ラテン語 iunctus（つなぐ）に由来し、英語の join や junction と同語根。英語の joined や together に相当し、junto a〜の形で「〜のそばに」という意味でも使われる。' },
  'justicia': { es: 'Luchar por la justicia social es una responsabilidad de todos los ciudadanos.', ja: '社会正義のために戦うことは、すべての市民の責任である。', trivia: 'ラテン語 iustitia（公正）に由来し、英語の justice と同語根の直系コグネート。iustus（正しい）という形容詞が元になっており、スペイン語の justo とも親戚関係にある。' },
  'justo': { es: 'El árbitro tomó una decisión justa que todos aceptaron sin protestas.', ja: '審判員はすべての人が抗議なく受け入れる公正な決断を下した。', trivia: 'ラテン語 iustus（正しい、公正な）に由来し、英語の just（まさに、ちょうど）や justify（正当化する）と同語根。副詞としての「ちょうど」という用法も英語の just とほぼ同じ意味で使われる。' },
  'juventud': { es: 'La juventud de hoy enfrenta desafíos muy distintos a los de generaciones anteriores.', ja: '今日の若者たちは以前の世代とはまったく異なる課題に直面している。', trivia: 'ラテン語 iuventas / iuventus（若さ）に由来し、英語の juvenile（少年の、幼稚な）や rejuvenate（若返らせる）と同語根。英語では youth という別語源（古英語 geoguth）が一般的に使われる。' },
  'juzgar': { es: 'No deberías juzgar a los demás sin conocer bien su situación.', ja: '相手の状況をよく知らずに他人を批判するべきではない。', trivia: 'ラテン語 iudicare（裁く）に由来し、英語の judge（動詞・名詞）と同語根。語尾変化で juzgo となるのは、スペイン語の綴り字規則で -go 音を保つための変化（g→gu ではなく逆）によるもの。' },
  'kilo': { es: 'Compré un kilo de manzanas en el mercado esta mañana.', ja: '今朝、市場でリンゴを1キロ買った。', trivia: 'ギリシャ語 chilioi（千）に由来し、英語の kilo および kilometer、kilogram と完全に同語根。k で始まる単語はスペイン語では比較的珍しく、ほとんどが外来語（ギリシャ語・英語など）である。' },
  'la': { es: 'La película que vimos ayer me pareció muy emocionante.', ja: '昨日観た映画はとても感動的だと思った。', trivia: 'ラテン語の指示代名詞 illa（あれ、それ）に由来し、英語の the に機能的に対応するが語根は異なる。英語の the は古英語 þe に由来するゲルマン語系で、ロマンス語の定冠詞とは系統が異なる。' },
  'labio': { es: 'Se mordió el labio al intentar contener la risa.', ja: '笑いをこらえようとして唇を噛んだ。', trivia: 'ラテン語 labium（唇）に由来し、英語の labial（唇音の）や labiodental（唇歯音の）と同語根。英語で唇を指す lip は古英語系のゲルマン語だが、言語学の専門用語では labial という形で同じ語根が使われる。' },
  'labor': { es: 'La labor de los voluntarios fue fundamental para el éxito del proyecto.', ja: 'ボランティアたちの作業がプロジェクトの成功に不可欠だった。', trivia: 'ラテン語 labor（労働、苦労）に由来し、英語の labor（米）/ labour（英）と完全に同語根の直系コグネート。elaborate（精巧な）や laboratory も同じ語根を持ち、「努力して作り上げる」という意味が共通している。' },
  'laboratorio': { es: 'Los científicos trabajan en el laboratorio para desarrollar nuevas vacunas.', ja: '科学者たちは新しいワクチンを開発するために研究所で働いている。', trivia: 'ラテン語 laborare（働く）＋場所を表す接尾辞 -torium に由来し、英語の laboratory と完全に同語根の直系コグネート。英語では口語で lab と略すが、スペイン語でも同様に labo と略されることがある。' },
  'lado': { es: 'Vive al lado de la escuela, así que tarda solo cinco minutos en llegar.', ja: '学校のすぐ隣に住んでいるので、着くのに5分しかかからない。', trivia: 'ラテン語 latus（側面、脇腹）に由来し、英語の lateral（側面の）や bilateral（二国間の）と同語根。英語で「側」を表す side はゲルマン語系で語源が異なるが、意味上の対応語として使われる。' },
  'lágrima': { es: 'Las lágrimas le corrían por las mejillas al despedirse de su familia.', ja: '家族に別れを告げる際、涙が彼女の頬を伝い流れた。', trivia: 'ラテン語 lacrima（涙）に由来し、英語の lachrymose（涙もろい）や lacrimation（流涙）と同語根。英語で涙を表す tear はゲルマン語系（古英語 tēar）で語源が異なるが、学術・文学語では lachrymose の形で同根語が残っている。' },
  'lanzar': { es: 'El atleta lanzó la pelota con tanta fuerza que llegó hasta el otro extremo del campo.', ja: 'その選手は非常に力強くボールを投げ、フィールドの反対端まで届いた。', trivia: '後期ラテン語 lanceare（槍で突く）に由来し、英語の lance（槍）と同語根。英語の launch（打ち上げる、発売する）もこの語根から来ており、スペイン語 lanzar と launch は同語根のコグネートである。' },
  'lápiz': { es: '¿Me prestas tu lápiz? Necesito apuntar esta dirección.', ja: '鉛筆を貸してもらえる？この住所をメモしなければならないんだ。', trivia: 'ラテン語 lapis（石）に由来し、もともと石筆や石板用の描画道具を指していた。英語の lapis lazuli（ラピスラズリ、青い石）と同語根で、英語で鉛筆を指す pencil はラテン語 penicillum（小さな尾）に由来し語源が全く異なる。' },
  'las': { es: 'Las flores del jardín están en plena floración esta primavera.', ja: '庭の花々がこの春、満開になっている。', trivia: 'ラテン語の指示代名詞 illas（それらを、女性複数対格）に由来し、英語の them（女性・複数の目的格）に機能的に対応するが語源は異なる。英語の the や them はゲルマン語系で、ロマンス語の冠詞とは系統が違う。' },
  'lástima': { es: '¡Qué lástima que no puedas venir a la fiesta esta noche!', ja: '今夜のパーティーに来られないなんて、なんて残念なんだろう！', trivia: 'ギリシャ語 blaptein（傷つける）を経由したラテン語 blastemare に由来するという説と、直接ラテン語 laesio（損害）から来るという説がある。英語では What a pity! や That\'s a shame! に相当し、直接の英語コグネートは定まっていない。' },
  'latín': { es: 'El latín es el origen de muchas palabras del español moderno.', ja: 'ラテン語は現代スペイン語の多くの単語の起源である。', trivia: '古代ローマのラティウム（Latium）地方の名に由来し、英語の Latin と完全に同語根の直系コグネート。英語で「遅い」を意味する late とは語根が異なり、Latin と late は偶然の類似（false friends ではないが無関係）である。' },
  'latino': { es: 'El barrio tiene una fuerte influencia latina, con restaurantes y música de toda América Latina.', ja: 'その地区はラテン系の強い影響を持ち、中南米各地のレストランや音楽が揃っている。', trivia: '古代ローマのラティウム（Latium）地方の形容詞形に由来し、英語の Latin と同語根。英語でもラテン系アメリカ人を指す際に Latino（男性）/ Latina（女性）という形でそのままスペイン語から借用されて使われている。' },
  'lavar': { es: 'Hay que lavarse las manos antes de comer para evitar enfermedades.', ja: '病気を防ぐために、食事の前には手を洗わなければならない。', trivia: 'ラテン語 lavare（洗う）に由来し、英語の lavatory（洗面所、トイレ）や lava（溶岩、もともと「激しく流れるもの」の意）と同語根。英語では wash（古英語系ゲルマン語）が日常語として使われ、lavatory は婉曲表現として残っている。' },
  'lazo': { es: 'El lazo que los une es más fuerte que cualquier distancia.', ja: '彼らを結びつける絆は、いかなる距離よりも強い。', trivia: 'ラテン語 laqueus（罠、輪縄）に由来し、英語の lasso（投げ縄）はこのスペイン語 lazo を英語が直接借用した単語である。英語の lace（レース、ひも）も同じラテン語 laqueus を共通の祖先に持つコグネートである。' },
  'le': { es: 'Le dije la verdad a mi amigo.', ja: '私は友人に真実を話した。', trivia: 'ラテン語の与格代名詞 *illi*（彼に）から発展したもので、スペイン語では間接目的語を表す。英語では「him/her/it」がこれに相当するが、英語は直接・間接目的語の区別がなく同一形を使う点でスペイン語と異なる。' },
  'leal': { es: 'El perro siempre ha sido leal a su dueño.', ja: 'その犬はずっと飼い主に忠実だった。', trivia: 'ラテン語 *legalis*（法律に沿った）から来ており、「正当な」が原義。英語の *loyal* と同語根で、フランス語 *loyal* を経由した英語形と、ラテン語から直接スペイン語に入った形の違いが興味深い。' },
  'lección': { es: 'La lección de hoy trata sobre los verbos irregulares.', ja: '今日の授業は不規則動詞についてです。', trivia: 'ラテン語 *lectio*（読むこと・朗読）から来ており、語根 *leg-*（読む）に由来する。英語の *lesson* と同語源で、フランス語 *leçon* を経て英語に入った。' },
  'lectura': { es: 'La lectura diaria mejora el vocabulario en cualquier idioma.', ja: '毎日の読書はどんな言語でも語彙力を向上させる。', trivia: 'ラテン語 *lectura*（読むこと）から直接来ており、語根 *leg-*（読む）に由来する。英語の *lecture*（講義）と同語源だが、スペイン語の *lectura* は「読書」を意味し、英語の *lecture* のような「口頭発表」の意味は持たない点が異なる。' },
  'legal': { es: 'No es legal conducir sin carné de conducir.', ja: '免許証なしで運転するのは違法です。', trivia: 'ラテン語 *legalis*（法律に関する）から来ており、*lex/legis*（法律）が語根。英語の *legal* と完全な同語源かつ意味も同一であり、スペイン語・英語ともにラテン語から直接借用した学術語。' },
  'legislar': { es: 'El congreso necesita legislar para proteger el medio ambiente.', ja: '議会は環境を守るための法律を制定する必要がある。', trivia: 'ラテン語 *legislare*（法律を提案する）から来ており、*lex*（法律）と *latus*（運ばれた、ferre の過去分詞）の複合語。英語の *legislate* と同語源で意味も同じである。' },
  'legislativo': { es: 'El poder legislativo tiene la responsabilidad de crear nuevas leyes.', ja: '立法権は新しい法律を作る責任を持つ。', trivia: 'ラテン語 *legislativus* から来ており、*legislare*（立法する）の形容詞形。英語の *legislative* と同語源で、三権分立（立法・行政・司法）を表す政治用語として両言語で共通して使われる。' },
  'lejano': { es: 'Hay una estrella muy lejana que apenas podemos ver.', ja: 'ほとんど見えないくらい遠い星がある。', trivia: 'ラテン語 *longe*（遠くに）から来ており、*longus*（長い）が語根。英語の *long* と同語源で「空間的・時間的な長さ・距離」という概念を共有するが、英語の *far* に相当する用法がスペイン語では *lejano/lejos* で表される。' },
  'lema': { es: 'El lema de la empresa es «calidad ante todo».', ja: 'その会社のモットーは「何よりも品質」です。', trivia: 'ギリシャ語 *lēmma*（受け取るもの、前提）から来ており、元々は論理学の用語だった。英語の *lemma*（補題）と同語源だが、英語では数学・言語学の専門用語として残り、スペイン語ではより広く「モットー・標語」の意味で日常的に使われる。' },
  'lengua': { es: 'El español es la lengua materna de más de 400 millones de personas.', ja: 'スペイン語は4億人以上の母語です。', trivia: 'ラテン語 *lingua*（舌・言語）から直接来ており、語根は *lingere*（なめる）に関連するとされる。英語の *language* や *linguistic* と同語源で、フランス語 *langue* を経由した英語形 *language* と直系の親戚関係にある。' },
  'lenguaje': { es: 'El lenguaje corporal dice mucho sobre el estado emocional de una persona.', ja: 'ボディランゲージは人の感情状態について多くを語る。', trivia: 'フランス語 *langage* から借用されており、元をたどればラテン語 *lingua*（舌・言語）に行き着く。英語の *language* とほぼ同語源で意味も近いが、スペイン語では *lengua*（具体的な言語体系）と *lenguaje*（言葉の使われ方・表現様式）を使い分ける傾向がある。' },
  'león': { es: 'El león fue declarado rey de la selva en muchas culturas antiguas.', ja: 'ライオンは多くの古代文化でジャングルの王と宣言された。', trivia: 'ラテン語 *leo/leonis* から来ており、もともとギリシャ語 *léōn* に由来する。英語の *lion* と同語源で、フランス語 *lion* 経由で英語に入った。スペインのカスティーリャ・レオン州の名前の由来でもある。' },
  'les': { es: 'Les dije a ellos que la reunión empezaría a las diez.', ja: '私は彼らに会議が10時に始まると言った。', trivia: 'ラテン語の与格複数形 *illis* から発展した形で、*le* の複数形にあたる。英語には間接目的語の三人称複数として *them* が相当するが、英語では直接・間接目的語が同形であるのに対し、スペイン語は両者を区別する。' },
  'letra': { es: 'No entiendo la letra de esta canción porque canta muy rápido.', ja: '歌うのがとても速くて、この曲の歌詞が理解できない。', trivia: 'ラテン語 *littera*（文字・手紙）から来ており、英語の *letter* と同語源。英語の *letter* が「手紙」と「文字」の両方を意味するのと同様に、スペイン語の *letra* も「文字」や「手形」など複数の意味を持つ。' },
  'luchar': { es: 'Los trabajadores tuvieron que luchar por sus derechos durante muchos años.', ja: '労働者たちは何年もの間、自分たちの権利のために戦わなければならなかった。', trivia: '語源については諸説あり、ラテン語 *luctari*（格闘する）から来たという説が有力。英語の *wrestle* に意味が近いが語根は異なり、英語では *struggle* や *fight* がより広く対応する。' },
  'lujo': { es: 'Vivir en ese hotel de cinco estrellas es un verdadero lujo.', ja: 'あの五つ星ホテルに泊まるのは本当の贅沢だ。', trivia: 'ラテン語 *luxus*（過剰・豪華）から来ており、英語の *luxury* と同語源。英語 *luxury* はラテン語形により近い綴りで借用されたのに対し、スペイン語は *lujo* と短縮された形になっている。' },
  'lunes': { es: 'El lunes por la mañana siempre me cuesta levantarme temprano.', ja: '月曜日の朝は早起きがいつもつらい。', trivia: 'ラテン語 *Lunae dies*（月の日）から来ており、*Luna*（月の女神）に由来する。英語の *Monday* も古英語 *Mōnandæg* でやはり「月の日」を意味し、両語はラテン語・ゲルマン語という異なる経路を経て同じ天体にちなんだ名前を持つ。' },
  'm': { es: 'La letra m es la decimotercera letra del alfabeto español.', ja: '「m」という文字はスペイン語のアルファベットの13番目の文字です。', trivia: 'フェニキア文字 *mem*（水）に由来し、ギリシャ文字 *mu*（μ）、ラテン文字 *M* へと受け継がれた。英語の *m* と完全に同一の起源を持ち、発音も両言語でほぼ同じ両唇鼻音 /m/ である。' },
  'maceta': { es: 'Tengo varias macetas con flores en el balcón de mi apartamento.', ja: '私のアパートのバルコニーにはいくつかの花の鉢植えがある。', trivia: 'スペイン語の *maza*（棍棒・ハンマー）の指小形から来ており、元々はハンマー状の道具を指した。英語には直接の同語源語はなく、*flowerpot* に相当する。フランス語の *massue*（棍棒）と遠縁の関係にある。' },
  'madera': { es: 'La mesa del comedor está hecha de madera de roble.', ja: 'ダイニングテーブルはオークの木材で作られている。', trivia: 'ラテン語 *materia*（木材・物質・素材）から来ており、「素材・材料」が原義。英語の *matter* や *material* と同語源で、英語では抽象的な「物質・問題」の意味が発達したのに対し、スペイン語 *madera* は具体的な「木材」という意味に特化した。' },
  'madrid': { es: 'Madrid es la capital de España y una de las ciudades más vibrantes de Europa.', ja: 'マドリードはスペインの首都であり、ヨーロッパで最も活気ある都市の一つだ。', trivia: '語源については諸説あり、アラビア語 *Magerit* またはラテン語由来の *Matrice*（マンサナーレス川の古名）から来たという説がある。英語では *Madrid* とそのままスペイン語形を借用しており、独自の英語名はない。' },
  'maestro': { es: 'El maestro explicó el tema con mucha paciencia a los alumnos.', ja: '先生は生徒たちにとても丁寧にテーマを説明した。', trivia: 'ラテン語 *magister*（上位者・指導者）から来ており、*magnus*（大きい・偉大な）が語根。英語の *master* や *magistrate* と同語源で、英語 *master* がフランス語 *maître* 経由で入ったのに対し、スペイン語 *maestro* はラテン語により近い形で残っている。' },
  'magia': { es: 'Los trucos del mago parecían magia para los niños pequeños.', ja: '手品師の芸は幼い子供たちには魔法のように見えた。', trivia: 'ラテン語 *magia* から来ており、ギリシャ語 *mageia*（魔術）、さらにペルシャ語 *maguš*（マギ・祭司）に由来する。英語の *magic* と同語源で、東方の三博士（マギ）も同じ語源に由来することが興味深い。' },
  'magistrado': { es: 'El magistrado del Tribunal Supremo emitió una sentencia histórica.', ja: '最高裁判所の判事が歴史的な判決を下した。', trivia: 'ラテン語 *magistratus*（役職者・官吏）から来ており、*magister*（上位者）が語根。英語の *magistrate* と同語源で意味も近く、ローマの行政制度に由来する政治・司法用語として両言語に共通して引き継がれた。' },
  'magnífico': { es: 'La vista desde la cima de la montaña era simplemente magnífica.', ja: '山の頂上からの眺めは本当に素晴らしかった。', trivia: 'ラテン語 *magnificus*（壮大な・堂々とした）から来ており、*magnus*（大きい）と *facere*（作る）の複合語。英語の *magnificent* と同語源で意味も同じだが、スペイン語形は語尾の *-ent* が *-o* に変化した点が特徴的。' },
  'maleta': { es: 'Necesito comprar una maleta nueva antes de mi viaje a México.', ja: 'メキシコへの旅行の前に新しいスーツケースを買う必要がある。', trivia: '後期ラテン語またはゲルマン語の「袋・荷物入れ」に由来するとされるが、語源には諸説ある。英語の「mallet（木槌）」とはスペルが似ているが全く無関係で、英語でスーツケースは suitcase または luggage と言う。' },
  'mamá': { es: 'Mi mamá siempre me prepara el desayuno antes de ir al trabajo.', ja: '私のお母さんはいつも仕事に行く前に朝食を作ってくれる。', trivia: '赤ちゃんが最初に発する「マ」音を重ねた幼児語で、ラテン語 mamma に由来し、世界中の言語で母親を表す語に共通して見られる。英語の mama / mom と完全に同語根で、意味も発音もほぼ同じ親しみやすい語だ。' },
  'manantial': { es: 'El agua del manantial es cristalina y muy fresca.', ja: 'その泉の水は澄んでいてとても冷たい。', trivia: 'ラテン語の manare（流れる・湧き出る）に由来し、スペイン語動詞 manar と同語根。英語に直接対応する同語根語はないが、英語では spring（泉）または natural spring と表現する。' },
  'manar': { es: 'El agua mana de las rocas y forma un pequeño arroyo.', ja: '水が岩から湧き出て小さな小川を形成する。', trivia: 'ラテン語 manare（流れ出る・滴る）に由来し、manantial（泉）と同語根。英語では to flow や to spring forth に相当し、英語の「manner（方法）」とはスペルが似ているが語源は全く異なる。' },
  'mandar': { es: 'El jefe mandó a todos los empleados un correo importante.', ja: '上司は全従業員に重要なメールを送った。', trivia: 'ラテン語 mandare（委ねる・命じる）に由来し、manus（手）と dare（与える）の合成語。英語の command、mandate と同語根で、「手渡す→委ねる→命じる」という意味の発展が英語とほぼ共通している。' },
  'mandato': { es: 'El presidente cumplió su mandato de cuatro años con varias reformas importantes.', ja: '大統領は4年間の任期を複数の重要な改革とともに全うした。', trivia: 'ラテン語 mandatum（委任されたこと）に由来し、mandar と同語根。英語の mandate と同語根・同義の語で、法律や政治の文脈でほぼ同じ意味に使われる典型的な国際語（インターナショナリズム）だ。' },
  'manejar': { es: 'En México, muchos jóvenes aprenden a manejar a los dieciocho años.', ja: 'メキシコでは多くの若者が18歳で車の運転を覚える。', trivia: 'イタリア語 maneggiare（手で扱う）またはラテン語 manus（手）に由来し、「手で操る」が原義。英語の manage と同語根で、意味も「うまく扱う・管理する」という点で非常に近い。スペインでは「運転する」に conducir を使うが、中南米では manejar が一般的。' },
  'manejo': { es: 'El manejo correcto de las herramientas es esencial para la seguridad.', ja: '工具の適切な取り扱いは安全のために不可欠だ。', trivia: 'manejar（扱う）の名詞形で、ラテン語 manus（手）に由来する。英語の management と同語根であり、「手で扱う行為・運用」という概念を共有している。' },
  'manga': { es: 'Esta camisa tiene las mangas demasiado largas para mí.', ja: 'このシャツは私には袖が長すぎる。', trivia: 'ラテン語 manica（袖・手を覆うもの）に由来し、manus（手）と同語根。英語では sleeve に相当するが、英語の mangle（絞り器）とは語源が異なる。日本語の「マンガ（漫画）」はこのスペイン語に逆輸入された形で世界語となっている珍しい例だ。' },
  'manifestación': { es: 'Miles de personas participaron en la manifestación contra el cambio climático.', ja: '気候変動に反対するデモに何千人もの人々が参加した。', trivia: 'ラテン語 manifestatio（明らかにすること）に由来し、manus（手）と fendere（打つ）の合成語が原義とされる。英語の manifestation と完全に同語根・同義で、政治的なデモ集会の意味でも両言語で使われる。' },
  'manifestar': { es: 'El gobierno manifestó su apoyo a las nuevas medidas económicas.', ja: '政府は新たな経済措置への支持を表明した。', trivia: 'ラテン語 manifestare（明らかにする・示す）に由来し、manifestación と同語根。英語の to manifest と同語根で「明らかにする・表明する」の意味を共有しており、近年は英語でも「マニフェストする」と使われるほど意味が定着している。' },
  'mantenimiento': { es: 'El mantenimiento regular del coche evita averías inesperadas.', ja: '定期的な車のメンテナンスは予期せぬ故障を防ぐ。', trivia: 'ラテン語 manu tenere（手で保つ）に由来し、mantener（維持する）の名詞形。英語の maintenance と完全に同語根で、「手で持ち続ける→維持する」という意味の流れが両言語で共通している。' },
  'mapa': { es: 'Necesitamos un mapa detallado para no perdernos en la ciudad.', ja: '街で迷わないために詳しい地図が必要だ。', trivia: '中世ラテン語 mappa mundi（世界の布）の mappa（布・ナプキン）に由来し、地図が布や羊皮紙に描かれていたことから転じた。英語の map と全く同語根・同義であり、珍しく男性名詞（el mapa）であることがスペイン語学習者の注意点となっている。' },
  'maquillar': { es: 'La actriz tardó una hora en maquillarse para la obra de teatro.', ja: 'その女優は舞台劇のために化粧をするのに1時間かかった。', trivia: 'フランス語 maquiller（化粧する）に由来し、さらにオランダ語 maken（作る・するゲルマン語）が語源とされる。英語では to put on makeup または to apply makeup と言い、maquillage はフランス語から英語に入った借用語として化粧品業界で使われる。' },
  'maquinaria': { es: 'La fábrica modernizó toda su maquinaria para aumentar la producción.', ja: '工場は生産を増やすために全ての機械設備を近代化した。', trivia: 'ラテン語 machina（仕掛け・装置）に由来し、máquina の集合名詞形。英語の machinery と完全に同語根・同義であり、ギリシャ語 mēkhanē（仕掛け）まで遡る古い語根を共有している。' },
  'máquina': { es: 'La máquina de café de la oficina se rompió esta mañana.', ja: 'オフィスのコーヒーメーカーが今朝壊れた。', trivia: 'ラテン語 machina（装置・仕掛け）に由来し、ギリシャ語 mēkhanē（工夫・手段）が語源。英語の machine と同語根で、スペイン語では -ch- が -qu- に変化した形で定着しており、「機械」全般を指す広義の語だ。' },
  'maravilla': { es: 'La catedral de Gaudí es una maravilla de la arquitectura moderna.', ja: 'ガウディの大聖堂は現代建築の驚異だ。', trivia: 'ラテン語 mirabilia（不思議なもの・驚くべきこと）に由来し、mirare（見る・驚嘆する）が語根。英語の marvel と同語根であり、「七不思議（seven wonders）」の wonder に意味が近い語として、スペイン語の感嘆表現 ¡maravilloso! に広く使われる。' },
  'maravilloso': { es: 'Pasamos un fin de semana maravilloso en la costa.', ja: '海岸で素晴らしい週末を過ごした。', trivia: 'maravilla（驚異）の形容詞形で、ラテン語 mirabilis（驚くべき）に由来する。英語の marvelous と同語根で意味もほぼ同じ。英語の「miraculous（奇跡的な）」とも同じ語根 mir-（驚く・見る）を共有している。' },
  'marca': { es: 'Esta marca de ropa es muy conocida en todo el mundo.', ja: 'このブランドの服は世界中でとても有名だ。', trivia: 'ゲルマン語 marka（境界・印・記号）に由来し、もとは「境界の印」を意味した。英語の mark（印・マーク）と同語根で、商標の意味での brand に相当するが、スペイン語では marca がより一般的にブランド・銘柄の意味で使われる。' },
  'marcar': { es: 'El delantero marcó tres goles en el partido de ayer.', ja: 'フォワードは昨日の試合で3ゴールを決めた。', trivia: 'ゲルマン語 marka（印）に由来し、marca と同語根。英語の to mark（印をつける）と同語根・同義だが、スペイン語ではさらにサッカーの「得点する」や「電話をダイヤルする」など用途が広い多義語として定着している。' },
  'marco': { es: 'Colocamos la foto de la boda en un marco de madera antiguo.', ja: '結婚式の写真を古い木製の額縁に入れた。', trivia: 'ゲルマン語 mark（境界・枠）に由来し、marca・marcar と同語根。英語の frame に意味が近く、英語の mark とは語根が同じだが「枠・額縁」の意味では英語の frame の方が対応する。ドイツの通貨「マルク（Mark）」も同語根だ。' },
  'marcha': { es: 'La marcha de protesta recorrió las principales calles de la ciudad.', ja: '抗議行進は街の主要な通りを行進した。', trivia: 'フランス語 marche（行進）またはゲルマン語 markon（踏みしめる）に由来するとされる。英語の march（行進・行軍）と同語根で意味も同じだが、スペイン語では車の「ギア」や、スペイン口語で「夜遊び・活気」の意味にも使われる興味深い多義語だ。' },
  'marchar': { es: 'Todo marcha bien con el nuevo proyecto del equipo.', ja: 'チームの新しいプロジェクトは順調に進んでいる。', trivia: 'marcha と同語根で、フランス語 marcher（歩く・機能する）に由来する。英語の to march（行進する）と同語根だが、スペイン語では「物事がうまく進む・機能する」という意味でも頻繁に使われ、英語の to work（機能する）に相当する使い方も持つ。' },
  'marido': { es: 'Su marido le regaló flores para su aniversario de boda.', ja: '彼女の夫は結婚記念日に花をプレゼントした。', trivia: 'ラテン語 maritus（夫・既婚の）に由来し、mare（海）との関連も指摘されるが諸説ある。英語の marry（結婚する）や marriage（結婚）と同語根で、英語では husband が「夫」の一般語だが、語根の maritus は英語の matrimony（婚姻）にもつながっている。' },
  'mariposa': { es: 'Una mariposa de colores se posó sobre las flores del jardín.', ja: '色とりどりの蝶が庭の花の上にとまった。', trivia: '語源には諸説あり、「María pósate（マリアよ、止まれ）」という聖母マリアへの呼びかけが転じたとする説が有名だが確証はない。英語では butterfly と言い、全く異なる語根を持つ。英語 butterfly は「バター色の黄色い蝶」に由来するとされ、両言語で蝶の命名発想が全く異なるのが興味深い。' },
  'marrón': { es: 'Llevaba un abrigo marrón que le quedaba muy bien.', ja: '彼女はとても似合っている茶色のコートを着ていた。', trivia: 'フランス語 marron（栗）を経由し、イタリア語 marrone から来ており、「栗の実の色」が語源。英語の maroon（暗赤褐色）と同根だが、スペイン語 marrón は茶色全般を指し、英語 maroon とは色合いが少し異なるフォルス・コグネート的な存在。' },
  'martes': { es: 'Quedamos para comer juntos el próximo martes.', ja: '次の火曜日に一緒に食事しましょうと約束した。', trivia: 'ラテン語 Martis dies（火星の日）に由来し、ローマ神話の軍神 Mars（マルス）の名を冠する。英語では Tuesday で、こちらはゲルマン神話の神 Tyr にちなむが、「惑星・神の曜日」という命名法は共通している。' },
  'marzo': { es: 'Las flores empiezan a brotar en marzo.', ja: '3月には花が咲き始める。', trivia: 'ローマ神話の軍神 Mars（マルス）を祀る月としてラテン語 Martius から来ており、英語 March と完全に同語根。かつてローマ暦では3月が年の始まりだったため、March/marzo は暦の起点という歴史的重要性を持つ。' },
  'mas': { es: 'Lo intenté con todas mis fuerzas, mas no lo conseguí.', ja: '全力を尽くしたが、それでも成功しなかった。', trivia: 'ラテン語 magis（より多く）に由来する文語的接続詞で、アクセント符号のある más（より多く、副詞）とは別語。英語の but に相当するが、現代日本語でいう「されど」のような格調ある表現で、日常会話では pero が使われる。' },
  'masa': { es: 'El panadero amasó la masa durante diez minutos.', ja: 'パン職人は10分間生地をこねた。', trivia: 'ラテン語 massa（こねた塊）、さらにギリシャ語 maza（大麦の塊）に由来。英語の mass と同語根で、「塊・質量」という物理学的意味から「大衆（masses）」という社会的意味まで両言語で平行して発展した。' },
  'matemática': { es: 'La matemática es fundamental para estudiar física.', ja: '数学は物理学を学ぶ上で不可欠だ。', trivia: 'ギリシャ語 mathematike（学ぶべきもの）、語根 manthanein（学ぶ）に由来。英語 mathematics と同語根で、略して math（英米）または maths（英国）と呼ばれる点と同様、スペイン語でも口語では las mates と略されることがある。' },
  'materia': { es: 'El profesor explicó bien la materia del examen.', ja: '先生は試験の科目の内容をよく説明した。', trivia: 'ラテン語 materia（木材、素材、材料）に由来し、語根は mater（母）と関連し「木の幹＝生み出すもの」が原義とされる。英語の matter および material と同語根で、物理的「物質」から抽象的「題材・教科」まで意味が広がった点も英語と共通。' },
  'matorral': { es: 'El camino atravesaba un matorral espeso y difícil de cruzar.', ja: 'その道は、通り抜けるのが困難な密生した茂みを横切っていた。', trivia: 'スペイン語 mata（低木、茂み）に接尾辞 -orral が付いた形で、mata 自体はラテン語 matta（草むら）に由来するとされる。英語に直接の同語根語はなく、bush や shrubland に相当するが、スペイン語圏の地中海性植生を表すのによく使われる語。' },
  'matrimonio': { es: 'Su matrimonio duró más de cincuenta años.', ja: '二人の結婚は50年以上続いた。', trivia: 'ラテン語 matrimonium（母となる義務・制度）に由来し、語根 mater（母）＋ -monium（状態・制度）の合成語。英語の matrimony と完全に同語根で、どちらも法的・制度的な婚姻関係を指すやや格式ある表現。' },
  'máximo': { es: 'Hay que aprovechar al máximo el tiempo libre.', ja: '自由な時間を最大限に活用しなければならない。', trivia: 'ラテン語 maximus（最も大きい）の最上級形に由来し、magnus（大きい）の最上級。英語の maximum と同語根で、数学・科学分野でも共通して使われる国際的な学術語。反意語 mínimo も英語 minimum と同様に対をなす。' },
  'mayo': { es: 'En mayo florecen los campos de amapolas.', ja: '5月にはポピーの野原に花が咲く。', trivia: 'ローマ神話の女神 Maia（豊穣と成長の女神）に捧げられた月 Maius から来ており、英語 May と完全に同語根。Maia はギリシャ神話でもプレアデス星団の一柱であり、ヘルメスの母としても知られる。' },
  'mayoría': { es: 'La mayoría de los estudiantes aprobó el examen.', ja: '学生の大多数が試験に合格した。', trivia: 'ラテン語 maior（より大きい）の比較級に由来し、magnus（大きい）の系譜。英語の majority と同語根で、どちらも「より大きい側」という比較概念から「多数派・過半数」という政治的・統計的意味に発展した。' },
  'me': { es: '¿Me puedes ayudar con esta tarea, por favor?', ja: 'この課題を手伝ってもらえますか？', trivia: 'ラテン語の一人称単数対格 me に由来し、形をほぼ変えずに現代スペイン語に引き継がれた。英語の me と完全に同語源（印欧祖語 *me- に遡る）で、印欧語族において最も形が安定して保存されてきた代名詞の一つ。' },
  'mecánico': { es: 'El mecánico tardó dos horas en reparar el coche.', ja: '整備士は車を修理するのに2時間かかった。', trivia: 'ギリシャ語 mechanikos（機械に関する）、語根 mechane（仕掛け、工夫）に由来。英語の mechanic および mechanical と同語根で、産業革命以降に技術者・修理士という職業的意味が両言語で定着した。' },
  'mecanismo': { es: 'No entiendo bien el mecanismo de funcionamiento de este aparato.', ja: 'この装置の動作の仕組みがよく分からない。', trivia: 'ギリシャ語 mechanismos（装置）、語根 mechane に由来し、ラテン語経由でスペイン語に入った。英語の mechanism と同語根で、生物学（防衛機制）から政治（決定メカニズム）まで幅広い分野で両言語が平行して使用する国際語。' },
  'medalla': { es: 'El atleta ganó una medalla de oro en los Juegos Olímpicos.', ja: 'その選手はオリンピックで金メダルを獲得した。', trivia: 'イタリア語 medaglia を経由し、俗ラテン語 metallea（金属製のもの）、さらにラテン語 metallum（金属）に由来。英語の medal と同語根で、フランス語 médaille を通じて17世紀頃に英語に入った。' },
  'mediante': { es: 'Resolvieron el conflicto mediante el diálogo y la negociación.', ja: '彼らは対話と交渉によって紛争を解決した。', trivia: 'ラテン語 mediare（真ん中に立つ）の現在分詞形 mediantem に由来し、語根は medius（中間）。英語の by means of に相当するが、語根レベルでは mediate（仲介する）や medium と同源であり、「間に立って橋渡しする」という原義が前置詞的用法に転じた。' },
  'medicina': { es: 'Estudió medicina durante seis años en la universidad.', ja: '彼女は大学で6年間医学を学んだ。', trivia: 'ラテン語 medicina（医術、薬）、語根 mederi（癒す、治療する）に由来。英語の medicine と同語根で、medic、medical なども同系統。印欧祖語 *med-（適切な手段を取る）に遡り、英語 remedy もここから派生している。' },
  'médico': { es: 'El médico me recomendó descansar al menos una semana.', ja: '医師は少なくとも1週間休むよう勧めてくれた。', trivia: 'ラテン語 medicus（医師、癒す者）に由来し、語根 mederi（治療する）から。英語の medical と同語根で、英語の doctor に相当する口語的・日常的な語として機能する点も英語の physician と doctor の使い分けと対応している。' },
  'medida': { es: 'El gobierno tomó medidas urgentes para controlar la inflación.', ja: '政府はインフレを抑制するための緊急措置を講じた。', trivia: 'ラテン語 mensura（測定）から派生した動詞 medir の過去分詞形が名詞化したもので、語根は metiri（測る）。英語の measure と同語根（ラテン語 mensura 経由）で、「寸法・測定」から「手段・対策」への意味拡張も英語と完全に平行している。' },
  'medio': { es: 'Los medios de comunicación informaron sobre el accidente.', ja: 'マスメディアはその事故について報道した。', trivia: 'ラテン語 medius（中間の）に由来し、印欧祖語 *medhyo-（中）に遡る。英語の medium、media と同語根で、「中間」という空間概念から「手段・メディア」への意味拡張も両言語で共通。英語 medium の複数形 media はそのままスペイン語でも使われる。' },
  'mediodía': { es: 'Nos reunimos a mediodía para comer en el parque.', ja: '公園で食事をするために正午に集まった。', trivia: 'スペイン語の medio（中間）＋ día（日）の合成語で、「一日の真ん中」が文字通りの意味。英語の midday と構造・意味ともに完全に平行した合成語であり、noon という別語も持つ英語と異なり、スペイン語では mediodía が最も一般的な「正午」の表現。' },
  'medir': { es: '¿Puedes medir cuánto mide esta ventana antes de comprar las cortinas?', ja: 'カーテンを買う前に、この窓の寸法を測ってもらえますか？', trivia: 'ラテン語 metiri（測る）に由来し、語根は印欧祖語 *med-（適切に処置する、測る）に遡る。英語の measure、meter（メートル）と同語根で、日本語で使う「メートル」という単位名もここに由来している。' },
  'mejilla': { es: 'La niña tenía las mejillas rojas por el frío.', ja: '女の子は寒さで頬が赤くなっていた。', trivia: '語源には諸説あり、アラビア語 muḫḫ（骨髄、脳みそ）経由という説や、ラテン語 maxilla（顎、頬）から変化したという説がある。英語の cheek とは語源が異なり、同根の英語語彙は maxilla（顎骨、解剖学用語）が最も近い。' },
  'mejora': { es: 'Se nota una clara mejora en su pronunciación del español.', ja: '彼のスペイン語の発音に明らかな上達が見られる。', trivia: 'ラテン語 meliorare（より良くする）、語根 melior（より良い）に由来し、動詞 mejorar の名詞形。英語の ameliorate（改善する）と同語根で、フランス語 améliorer にも受け継がれている。英語の improve は語源が異なる（古フランス語 emprouwer）が意味は対応する。' },
  'mejorar': { es: 'Espero que te mejores pronto; el médico dice que el tratamiento está funcionando.', ja: '早く回復するといいね。医者は治療がうまくいっていると言っているよ。', trivia: 'ラテン語 melior（より良い）に由来し、英語の ameliorate（改善する）と同語根。日常会話では「体調が良くなる」の意味で mejorar(se) とよく使われる。' },
  'melón': { es: 'En verano, no hay nada mejor que un trozo de melón frío.', ja: '夏には、冷たいメロンの一切れほどおいしいものはない。', trivia: 'ラテン語 melo（メロン）を経てギリシャ語 mēlopepōn（リンゴのように丸いウリ）に遡る。英語の melon と完全に同語根で、スペルもほぼ同じ。' },
  'memoria': { es: 'Tiene una memoria increíble; recuerda fechas y nombres sin esfuerzo.', ja: '彼女の記憶力は驚異的で、日付や名前を楽々と覚えている。', trivia: 'ラテン語 memoria（記憶）に直接由来し、英語の memory と完全に同語根。memorial（記念碑）や memorize（暗記する）も同じ語族。' },
  'mención': { es: 'Su trabajo recibió una mención honorífica en el concurso nacional.', ja: '彼の作品は全国コンクールで佳作（名誉賞）を受けた。', trivia: 'ラテン語 mentio（言及）に由来し、英語の mention と同語根。ラテン語動詞 meminisse（思い出す）とも関連があるとされる。' },
  'mencionar': { es: 'No mencionó nada sobre el cambio de planes en la reunión.', ja: '彼は会議で計画変更について何も言及しなかった。', trivia: 'mención と同じくラテン語 mentio に由来し、英語の mention とほぼ一対一で対応する動詞。-ar 語尾を加えて動詞化したスペイン語独特の形。' },
  'mensaje': { es: 'Te envié un mensaje de texto pero no me has respondido todavía.', ja: 'テキストメッセージを送ったのに、まだ返事が来ていない。', trivia: 'ラテン語 missus（送られたもの）に由来し、英語の message と同語根。フランス語 message を経由してスペイン語に入った借用語とされる。' },
  'mensajero': { es: 'El mensajero llegó tarde porque había mucho tráfico en la ciudad.', ja: '配達員は市内の渋滞がひどくて遅れて到着した。', trivia: 'mensaje と同語根で、英語の messenger と対応する。語尾 -ero はスペイン語で「職業・役割を担う人」を表す接尾辞で、英語の -er に相当する。' },
  'mente': { es: 'Tienes que tener la mente abierta para aceptar nuevas ideas.', ja: '新しい考えを受け入れるには、柔軟な（オープンな）心を持たなければならない。', trivia: 'ラテン語 mens（心、精神）に由来し、英語の mental（精神的な）や mentality と同語根。英語の mind はゲルマン語系で語源が異なるが、意味は近い。' },
  'mentira': { es: 'Le pillaron en una mentira y tuvo que pedir disculpas a todos.', ja: '嘘をついているのがばれて、彼は全員に謝らなければならなかった。', trivia: 'ラテン語 mentiri（嘘をつく）に由来し、英語には直接の同語根語はないが、mentor（顧問）と語源的に遠縁とする説もある。英語では lie に相当する。' },
  'menú': { es: '¿Me puede traer el menú del día, por favor?', ja: '本日の定食メニューを持ってきていただけますか？', trivia: 'フランス語 menu（詳細なリスト）に由来し、英語の menu と完全に同一語源。ラテン語 minutus（小さい、細かい）が語根で、「細かく書き出したリスト」が原義。' },
  'mercancía': { es: 'El camión transportaba mercancía frágil, así que condujo con mucho cuidado.', ja: 'トラックは壊れやすい商品を運んでいたため、運転手はとても慎重に運転した。', trivia: 'ラテン語 merx / mercis（商品）に由来し、英語の merchandise と同語根。merchant（商人）や market（市場）もこの語族に属する。' },
  'merecer': { es: 'Después de tanto esfuerzo, mereces tomarte unas vacaciones.', ja: 'これだけ頑張ったのだから、あなたは休暇を取るに値する。', trivia: 'ラテン語 merere（稼ぐ、値する）に由来し、英語の merit と同語根。英語の deserve はフランス語経由のゲルマン語系で語源は異なるが、意味はほぼ同じ。' },
  'mérito': { es: 'El proyecto fue aprobado por sus propios méritos, sin necesidad de recomendaciones.', ja: 'そのプロジェクトは推薦状なしに、その内容自体の功績によって承認された。', trivia: 'ラテン語 meritum（稼がれたもの、功績）に由来し、英語の merit と完全に同語根。merit という語は英語にもそのまま借用されている。' },
  'mermelada': { es: 'Me gusta untar mermelada de fresa en las tostadas del desayuno.', ja: '朝食のトーストにイチゴジャムを塗るのが好きだ。', trivia: 'ポルトガル語 marmelada（マルメロのジャム）に由来し、マルメロ（quince）を意味するギリシャ語 melimelon が語根。英語の marmalade と同語源で、もともとはマルメロのジャムを指していた。' },
  'meta': { es: 'Su meta es terminar la carrera universitaria antes de los veinticinco años.', ja: '彼女の目標は25歳になる前に大学を卒業することだ。', trivia: 'ギリシャ語・ラテン語の meta（ゴール、折り返し点）に由来し、英語の meta-（超えた、後の）と同語根。競技のゴールラインを意味するラテン語から転じて「目標」の意味になった。' },
  'meter': { es: '¿Puedes meter los documentos en la carpeta azul, por favor?', ja: '書類を青いフォルダに入れてもらえますか？', trivia: 'ラテン語 mittere（送る、置く）に由来し、英語の admit、permit、commit などに含まれる -mit- と同語根。英語の put に相当する日常動詞として広く使われる。' },
  'método': { es: 'El nuevo método de enseñanza ha mejorado los resultados de los estudiantes.', ja: '新しい教授法が生徒たちの成績を向上させた。', trivia: 'ギリシャ語 methodos（道筋、探求の方法）に由来し、英語の method と完全に同語根。meta-（後に）と hodos（道）の合成語で「目標へ向かう道」が原義。' },
  'metro': { es: 'Prefiero tomar el metro porque es más rápido que el autobús en hora punta.', ja: 'ラッシュ時はバスより地下鉄の方が速いので、地下鉄を使うのが好きだ。', trivia: 'ギリシャ語 metron（測るもの）に由来し、英語の meter（メートル）と同語根。「地下鉄」の意味は metropolis（大都市）の略称 métro から来ており、英語の subway や underground に相当する。' },
  'México': { es: 'México es famoso por su rica gastronomía y sus antiguas civilizaciones.', ja: 'メキシコは豊かな食文化と古代文明で有名だ。', trivia: 'ナワトル語 Mēxihco に由来し、アステカの守護神 Mextli（または Huitzilopochtli）の名を含むとされる。英語でも Mexico と表記するが、スペイン語では x を /x/（ホ行）の音で発音するのが標準的。' },
  'mi': { es: 'Mi hermana vive en Barcelona desde hace tres años.', ja: '私の姉（妹）は3年前からバルセロナに住んでいる。', trivia: 'ラテン語の所有形容詞 meus（私の）の弱形に由来し、英語の my と同語根。アクセント記号なしの mi は所有格形容詞、アクセント記号付きの mí は代名詞と区別される。' },
  'mí': { es: 'Este regalo es para mí, ¿verdad?', ja: 'このプレゼントは私へのものですよね？', trivia: 'ラテン語の対格・奪格形 me に由来し、英語の me と同語根。前置詞の後で使われる強勢形で、アクセント記号は所有格形容詞の mi との区別のために付けられる（発音は同じ）。' },
  'miedo': { es: 'Los niños tienen miedo a la oscuridad, así que dejamos la luz encendida.', ja: '子供たちは暗闇を怖がるので、電気をつけたままにしておく。', trivia: 'ラテン語 metus（恐れ、不安）に由来する。英語には直接の同語根語はなく、fear や fright がゲルマン語系の対応語になる。「tener miedo」（恐れを持つ）という動詞句で使うのが典型的。' },
  'miembro': { es: 'Soy miembro de un club de lectura que se reúne todos los lunes.', ja: '私は毎週月曜日に集まる読書クラブのメンバーだ。', trivia: 'ラテン語 membrum（手足、部分）に由来し、英語の member と同語根。解剖学的な「四肢」の意味も保持しており、英語の limb や member の「身体部位」という古い用法と対応する。' },
  'mientras': { es: 'Mientras tú preparas la cena, yo pongo la mesa.', ja: 'あなたが夕食を作っている間に、私はテーブルをセットするよ。', trivia: 'ラテン語 dum interim（その間に）が変化した形とされ、mientras tanto（その一方で）という表現でよく使われる。英語の while に相当するが、語源的なつながりはなく、while はゲルマン語系。' },
  'miércoles': { es: 'Los miércoles tengo clase de español a las seis de la tarde.', ja: '水曜日は午後6時からスペイン語の授業がある。', trivia: 'ラテン語 Mercurii dies（メルクリウスの日）に由来し、英語の Wednesday（ウォーデン神の日、ゲルマン神話）とは語源が異なる。フランス語 mercredi とは同語源で、どちらもローマ神メルクリウスに由来する。' },
  'mil': { es: 'En la ciudad viven más de mil familias.', ja: 'その街には千を超える家族が住んでいる。', trivia: 'ラテン語 mille（千）に由来し、英語の mile（マイル）も同じ語根——古代ローマの「千歩（mille passuum）」が距離の単位になった。また million（百万）は mille の指小語 milione が語源。' },
  'milagro': { es: 'Fue un milagro que nadie resultara herido en el accidente.', ja: 'その事故で誰も怪我をしなかったのは奇跡だった。', trivia: 'ラテン語 miraculum（驚くべきもの）に由来し、動詞 mirari（驚く）が語根。英語の miracle と完全な同語根で、mirror（鏡）や admire（賞賛する）も同じ mir- の族。' },
  'militar': { es: 'Su padre sirvió como oficial militar durante veinte años.', ja: '彼女の父は20年間、軍の将校として勤務した。', trivia: 'ラテン語 miles / militis（兵士）に由来し、英語の military と完全な同語根。militia（民兵）や militant（闘士）も同族語で、英語でもほぼ同形で通じるインターナショナル語彙。' },
  'millón': { es: 'La empresa ganó más de un millón de euros el año pasado.', ja: 'その会社は昨年100万ユーロ以上の利益を上げた。', trivia: 'ラテン語 mille（千）のイタリア語増大辞 milione（大きな千）を経てスペイン語に入った語。英語の million と同語源で、billion・trillion も同じ構成原理による造語。' },
  'mina': { es: 'Los trabajadores descendieron a la mina para extraer carbón.', ja: '労働者たちは石炭を採掘するために坑道に降りた。', trivia: 'ケルト語またはラテン語後期の minare（掘り進む）に由来するとされ、語源には諸説ある。英語の mine（鉱山）と同語根で、mineral（鉱物）も同族。日本語の「シャープペンシルの芯」という意味は鉛筆の芯（mine en français）から来ている。' },
  'minería': { es: 'La minería del cobre es una actividad económica clave en este país.', ja: '銅の採鉱はこの国の主要な経済活動だ。', trivia: 'mina（鉱山）に派生接尾辞 -ería（産業・業種を表す）が付いた語。英語では mining industry または mining と表現し、ワンワードの直訳語はないが、mineral（鉱物）や mine が同じ語根を持つ。' },
  'ministro': { es: 'El ministro de educación anunció una nueva reforma escolar.', ja: '教育大臣が新たな学校改革を発表した。', trivia: 'ラテン語 minister（召し使い、奉仕者）に由来し、minus（より少ない）が語根——「より低い地位の者」が原義。英語の minister と同語根で、administer（管理する）や minor も同じ min- 族。' },
  'minoría': { es: 'El gobierno debe proteger los derechos de las minorías étnicas.', ja: '政府は少数民族の権利を守らなければならない。', trivia: 'ラテン語 minor（より小さい）に由来し、英語の minority と完全な同語根。語根 minus は「より少ない」を意味し、minister・minute（微小）とも遠い親戚にあたる。' },
  'minuto': { es: 'Espera un minuto, que ahora te llamo.', ja: 'ちょっと待って、今すぐ電話するから。', trivia: 'ラテン語 pars minuta prima（第一の微小部分）に由来し、時間を60等分した「微細な単位」が原義。英語の minute と完全な同語源で、minute（形容詞：微小な、発音は異なる）とも同じ語。' },
  'mío': { es: 'Este libro no es tuyo, es mío.', ja: 'この本はあなたのものではなく、私のものだ。', trivia: 'ラテン語の所有形容詞 meus（私の）の変化形に由来する。英語の mine（私のもの）と語根は異なるが機能が対応しており、英語の my / mine は古英語 mīn に遡りゲルマン語系。スペイン語 mío は後置用法が特徴的。' },
  'mirada': { es: 'Me lanzó una mirada de sorpresa al verme entrar.', ja: '私が入ってくるのを見て、彼は驚いた目を向けた。', trivia: '動詞 mirar（見る）の名詞形で、ラテン語 mirari（驚き見る）に由来する。英語に直訳の一語はなく glance・gaze・look などで使い分けるが、admire（賞賛する）や mirror と同族。' },
  'misa': { es: 'Toda la familia va a misa los domingos.', ja: '家族全員が毎週日曜日にミサに行く。', trivia: 'ラテン語 missa（解散・送り出し）に由来し、礼拝の結びに司祭が言う「Ite, missa est（さあ、解散せよ）」から来た。英語の mass（ミサ）と同語源で、dismiss（解散させる）も同じ mitt- / miss- の語根。' },
  'miserable': { es: 'Las condiciones de vida en ese barrio eran miserables.', ja: 'その地区の生活環境は惨めなものだった。', trivia: 'ラテン語 miserari（哀れむ）に由来し、英語の miserable と完全な同語根。miser（けちん坊）や misery も同族語で、英語の miser はラテン語 miser（哀れな）から来ているが、現代英語では「守銭奴」の意味に特化した。' },
  'miseria': { es: 'Muchas familias vivían en la miseria después de la guerra.', ja: '多くの家族が戦後、貧困の中で暮らしていた。', trivia: 'ラテン語 miseria（不幸、悲惨）に由来し、英語の misery と完全な同語根。miser（守銭奴）・miserable も同族で、共通する語根 miser は「惨めな、哀れな」を意味するラテン語形容詞。' },
  'misión': { es: 'Su misión era llevar los suministros al campo de refugiados.', ja: '彼の任務は難民キャンプに物資を届けることだった。', trivia: 'ラテン語 missio（派遣）に由来し、mittere（送る）が語根。英語の mission と完全な同語根で、missile（ミサイル）・emit（放出する）・commit（委託する）なども同じ mitt- / miss- 語族に属する。' },
  'mitad': { es: 'Ya hemos recorrido la mitad del camino.', ja: '私たちはもう道のりの半分を歩いた。', trivia: 'ラテン語 medietas（中間、半分）に由来し、medius（中間の）が語根。英語の half とは語根が異なるが、medium・middle・median は同じラテン語 medius の族。英語の moiety（半分：法律・文化人類学用語）が最も近い借用語。' },
  'mito': { es: 'El mito de Prometeo sigue siendo relevante en la cultura moderna.', ja: 'プロメテウスの神話は現代文化でも依然として意義を持っている。', trivia: 'ギリシャ語 mythos（言葉、物語、神話）に由来し、英語の myth と完全な同語源。mythology・mythical も同族語で、語根の mythos はギリシャ語由来の数少ない国際的学術語の一つ。' },
  'moda': { es: 'Ese estilo de ropa ya no está de moda.', ja: 'その服のスタイルはもう流行っていない。', trivia: 'ラテン語 modus（様式、尺度）に由来し、英語の mode・fashion（フランス語経由）と語根が同じ。modern（現代的な）・modest・modify も同じ mod- 語族で、「測られた様式」という概念が共通の原義。' },
  'modelo': { es: 'Esta pintora es un modelo a seguir para los jóvenes artistas.', ja: 'この女性画家は若いアーティストたちの手本となる存在だ。', trivia: 'ラテン語 modulus（小さな尺度・規範）に由来し、英語の model と完全な同語根。module（モジュール）・mold（型）も同族で、語根 modus（尺度）から「規範となる型」という意味が生まれた。' },
  'modesto': { es: 'A pesar de su éxito, siempre se ha mostrado modesto.', ja: '成功しているにもかかわらず、彼はいつも謙虚な態度を見せてきた。', trivia: 'ラテン語 modestus（節度ある）に由来し、modus（尺度・節度）が語根。英語の modest と完全な同語根で、moderate（穏やかな）・modulate も同族語。「度を越えない」という概念が語義の核にある。' },
  'modificar': { es: 'Tuvimos que modificar el plan debido al mal tiempo.', ja: '悪天候のためにプランを変更しなければならなかった。', trivia: 'ラテン語 modificare（規格に合わせる）に由来し、modus（尺度）＋ facere（作る）の合成語。英語の modify と完全な同語根で、modification も同族。語尾 -ficar はスペイン語で「〜化する」という動詞を作る生産的な接尾辞。' },
  'mojar': { es: 'La lluvia nos mojó completamente antes de llegar a casa.', ja: '家に着く前に雨でびしょ濡れになった。', trivia: 'ラテン語 molliare または *mollicare（柔らかくする、濡らす）に由来するとされ、mollis（柔らかい）が語根。英語の moist（湿った）とは語根が異なるが意味が近く、moisten に相当する表現。英語の mollify（和らげる）が最も近い同族語。' },
  'molde': { es: 'Vierte la mezcla en el molde y hornéala durante treinta minutos.', ja: '生地を型に流し込んで30分焼いてください。', trivia: 'ラテン語 modulus（小さな尺度・規格）に由来し、英語の mold（型）と完全な同語源。model・module も同族語で、語根 modus（尺度）から派生した一族は「規範・形を与えるもの」という共通概念を持つ。' },
  'molestar': { es: '¿Te molesta si abro la ventana?', ja: '窓を開けても構いませんか？（迷惑ではありませんか？）', trivia: 'ラテン語 molestare（重荷を負わせる、悩ませる）に由来し、moles（重い塊、負担）が語根。英語の molest と完全な同語源だが、英語の molest は主に性的な嫌がらせの意味で使われるのに対し、スペイン語 molestar は「邪魔をする・迷惑をかける」という日常的な意味で広く使われる点が異なる。' },
  'molestia': { es: 'Perdona la molestia, pero ¿podrías ayudarme un momento?', ja: 'お手数をおかけしますが、少し助けていただけますか？', trivia: '動詞 molestar（迷惑をかける）の名詞形で、ラテン語 molestia（重荷、苦労）に直接由来する。英語には molestation という語があるが意味が大きく乖離しており、日常的には inconvenience・bother・trouble が対応語。語根 moles（重い塊）は英語の molecule（分子）にも生きている。' },
  'moneda': { es: 'No tengo monedas sueltas para el parquímetro.', ja: 'パーキングメーターに使う小銭がありません。', trivia: 'ラテン語 Moneta（ユノー女神の称号）に由来し、ローマの造幣所がユノー神殿に隣接していたことから「貨幣」の意味が生まれた。英語の money および mint（造幣所）も同じ語源を持つ。' },
  'mono': { es: 'El mono saltó de árbol en árbol con agilidad increíble.', ja: 'その猿は信じられないほどの俊敏さで木から木へと飛び移った。', trivia: '「サル」の意味の語源は諸説あり、ラテン語の simius とは別系統で、ギリシャ語 maimou などを経たとも言われるが確定していない。英語の monkey とは語根が異なるが意味は同じ。口語で「可愛い」の意味にも使われる点は英語には対応する同語根語がない。' },
  'monte': { es: 'Subimos al monte para disfrutar del paisaje al amanecer.', ja: '夜明けの景色を楽しむために山に登りました。', trivia: 'ラテン語 mons / montis（山）に由来し、英語の mountain（山）や mount と同語根。スペインの地名「モンテビデオ（Montevideo）」にも含まれる。' },
  'monumento': { es: 'El monumento a los caídos está en el centro de la plaza.', ja: '戦没者記念碑は広場の中央にあります。', trivia: 'ラテン語 monumentum（記念物、思い出させるもの）に由来し、monere（警告する、思い出させる）が語根。英語の monument と完全に同語根の国際語彙（インターナショナリズム）で、形も意味もほぼ同じ。' },
  'morder': { es: 'El perro me mordió en la mano cuando intenté acariciarlo.', ja: 'なでようとしたら犬に手を噛まれた。', trivia: 'ラテン語 mordere（噛む）に由来し、英語の remorse（後悔、良心の呵責）はこの語根 mord-「噛む」から来ており、「良心に噛みつかれる」という比喩的意味を持つ。英語で「噛む」は bite で語根は異なる。' },
  'moro': { es: 'La arquitectura mora del sur de España refleja siglos de historia.', ja: 'スペイン南部のムーア様式の建築は何世紀もの歴史を映し出している。', trivia: 'ラテン語 Maurus（北アフリカのムーア人）に由来し、英語の Moor（ムーア人）と同語源。スペインのアルハンブラ宮殿などの建築様式を指す「モリスク（Morisco）様式」という語にも関連する。現代では差別的な含意を持つ場合があるため使用に注意が必要。' },
  'mosca': { es: 'Una mosca entró por la ventana abierta y empezó a molestar.', ja: '開いた窓からハエが入ってきて邪魔をし始めた。', trivia: 'ラテン語 musca（ハエ）に由来し、英語の musk（ムスク、麝香）とは語根が異なる。英語で「ハエ」は fly で語根も系統も全く別。口語でスペイン（特にアルゼンチン）では「お金」の意味にも使われるのは興味深いスラング用法。' },
  'mostrar': { es: 'El guía nos mostró los lugares más interesantes de la ciudad.', ja: 'ガイドは私たちに街の最も興味深い場所を案内してくれた。', trivia: 'ラテン語 monstrare（見せる、指し示す）に由来し、英語の demonstrate（実演する、証明する）や monster（怪物：不吉な「しるし」）と同語根。英語で「見せる」に相当する show とは語根が異なる。' },
  'motivo': { es: 'No entiendo cuál fue el motivo de su renuncia repentina.', ja: '彼の突然の辞職の動機が理解できません。', trivia: 'ラテン語 motivus（動かす）に由来し、movere（動かす）が語根。英語の motive（動機）と完全に同語根で形も意味もほぼ同じ国際語彙。また英語の motivation（モチベーション）も同系統。' },
  'moto': { es: 'Prefiero ir en moto porque evito los atascos de tráfico.', ja: '交通渋滞を避けられるのでバイクで行く方が好きです。', trivia: 'motocicleta の短縮形で、ギリシャ語 kyklos（輪）とラテン語 motus（動き）の合成語から来ている。英語の motorcycle と同語源であり、英語でも口語では bike や moto と短縮される。' },
  'móvil': { es: 'Se me olvidó el móvil en casa y no pude llamar a nadie.', ja: '家に携帯電話を忘れてきて、誰にも電話できなかった。', trivia: 'ラテン語 mobilis（動く、動かせる）に由来し、movere（動かす）が語根。英語の mobile（モバイル、移動式の）と同語根で、mobile phone の省略として使われる英語の mobile と全く同じ用法。' },
  'movimiento': { es: 'El movimiento feminista ha logrado importantes cambios sociales.', ja: 'フェミニスト運動は重要な社会的変化を成し遂げた。', trivia: 'ラテン語 movimentum に由来し、movere（動かす）が語根。英語の movement（運動、動き）と同語根で、社会運動・身体の動き・音楽のムーブメントと多義的に使われる点も英語と共通している。' },
  'mozo': { es: 'El mozo nos trajo la carta sin que se la pidiéramos.', ja: 'ウェイターは頼まなくてもメニューを持ってきてくれた。', trivia: '語源は諸説あり、ラテン語の musteus（新しい、若い）や muttium などが提案されているが確定していない。英語に直接の同語根語はなく、英語では waiter や young man に相当する。中南米では特に「ウェイター」の意味で広く使われる。' },
  'muchacha': { es: 'La muchacha que trabaja en la recepción es muy amable.', ja: '受付で働いている女の子はとても親切です。', trivia: '語源は不明確で、アラビア語起源説（mukhakkha）やラテン語起源説など諸説あるが定説がない。英語の girl や young woman に相当するが、同語根の英単語は存在しない。中南米では家政婦の意味でも使われる。' },
  'muchacho': { es: 'Ese muchacho siempre llega tarde a clase.', ja: 'あの少年はいつも授業に遅刻する。', trivia: 'muchacha と同じく語源は諸説あり確定していない。英語の boy や lad に相当するが直接の語根的つながりはない。muchacho という語形はスペイン語圏で広く親しみを込めて使われ、英語話者にも比較的知られたスペイン語単語の一つ。' },
  'muchedumbre': { es: 'Una muchedumbre se reunió frente al palacio para ver al rey.', ja: '王を見ようと宮殿の前に群衆が集まった。', trivia: 'ラテン語 multitudo に由来する mucho（多い）から派生した抽象名詞。英語の multitude（群衆）は同じラテン語源だが、muchedumbre は独自のスペイン語的発展を遂げた形。英語の crowd や mob とは語根が異なる。' },
  'muela': { es: 'Me duele una muela del juicio y tengo que ir al dentista.', ja: '親知らずが痛くて歯医者に行かなければなりません。', trivia: 'ラテン語 mola（砥石、臼）に由来し、臼のように物をすり潰す形から「臼歯」の意味になった。英語の molar（臼歯）と同語根で、molar も同じくラテン語 mola から来ている。また英語の mill（製粉所）も遠い語根的つながりがある。' },
  'muelle': { es: 'Los pescadores descargaron el barco en el muelle al amanecer.', ja: '漁師たちは夜明けに埠頭で船の荷を降ろした。', trivia: 'ラテン語 moles（堤防、大きな塊）に由来するとされ、英語の mole（防波堤）と同語根。バネ（スプリング）の意味での muelle はラテン語 mollis（柔らかい）に由来し、英語の mollify（和らげる）と同語根という二つの語源が混在している興味深い多義語。' },
  'muerte': { es: 'La muerte del poeta fue una gran pérdida para la literatura.', ja: 'その詩人の死は文学界にとって大きな損失だった。', trivia: 'ラテン語 mors / mortis（死）に由来し、英語の mortal（死すべき運命の）、immortal（不死の）、mortuary（霊安室）と同語根。英語で「死」に相当する death はゲルマン語系で語根が全く異なる。' },
  'muerto': { es: 'El personaje principal aparece muerto al principio de la novela.', ja: '主人公は小説の冒頭で死んだ状態で登場する。', trivia: 'ラテン語 mortuus（死んだ）に由来し、morte（死）と同語根。英語の mortified は同語源だが「ひどく恥ずかしい」という意味に変化した偽りの友人（false friend）的語彙。英語で「死んだ」は dead でゲルマン語系。' },
  'muestra': { es: '¿Me puede dar una muestra gratuita del perfume, por favor?', ja: 'その香水の無料サンプルをいただけますか？', trivia: 'mostrar（見せる）の名詞形で、ラテン語 monstrare（指し示す）に由来。英語の demonstration（実演）や muster（集合、点検）と同語根を持つ。英語で「見本・サンプル」は sample（フランス語経由のラテン語 exemplum）で語根は異なる。' },
  'multitud': { es: 'Una multitud de aficionados esperaba al equipo en el aeropuerto.', ja: '空港で大勢のファンがチームを待ち構えていた。', trivia: 'ラテン語 multitudo（多数、群衆）に由来し、multus（多い）が語根。英語の multitude（群衆、多数）と完全に同語根で形も近い国際語彙。また英語の multiple、multiply も同じ語根 multus を共有している。' },
  'multa': { es: 'Le pusieron una multa por aparcar en zona prohibida.', ja: '駐車禁止区域に停めたため罰金を科せられた。', trivia: 'ラテン語 multa / mulcta（罰金、制裁）に由来し、英語の mulct（罰金を科す、古語・法律用語）と同語根。英語では fine が一般的な「罰金」の語で語根は異なるが、法律用語として mulct が現在も使われる。' },
  'muña': { es: 'La muña es una hierba andina que se usa como remedio digestivo.', ja: 'ムーニャはアンデスのハーブで、消化薬として使われる。', trivia: 'ケチュア語（Quechua）の muña に由来するアンデス固有の植物名で、スペイン語がインカ文化圏に広まった際に取り込まれた借用語。英語には対応する同語根語は存在せず、英語でも muña または Minthostachys mollis という学術名で呼ばれる。' },
  'muñeca': { es: 'Mi hija duerme todas las noches abrazada a su muñeca favorita.', ja: '娘は毎晩お気に入りの人形を抱きしめて眠る。', trivia: '語源はケルト語またはゲルマン語の借用語とされるが確定していない。「手首」と「人形」という二つの全く異なる意味を持つ多義語で、おそらく手首の丸みが人形を連想させたことによると考えられる。英語の wrist（手首）はゲルマン語系で語根が異なり、doll（人形）とも無関係。' },
  'muralla': { es: 'Los turistas admiraron la antigua muralla que rodeaba la ciudad medieval.', ja: '観光客たちは中世の街を取り囲む古い城壁に感嘆した。', trivia: 'ラテン語 murus（壁）に由来し、-alla という増大辞的接尾辞が付いて「大きな壁・防壁」を意味するようになった。英語の mural（壁画）と同語根であり、どちらも「壁」という概念を共有している。' },
  'murete': { es: 'El jardín estaba delimitado por un murete de piedra de apenas un metro de altura.', ja: '庭園はわずか1メートルほどの高さの石造りの低い壁で区切られていた。', trivia: 'muro（壁）の縮小辞形（-ete）で「小さな壁」を表す。ラテン語 murus に遡り、英語の mural と同語根だが、英語には murete に直接対応する一般的な語はなく、英語では low wall や parapet と表現される。' },
  'muriendo': { es: 'La ciudad estaba muriendo lentamente a causa del abandono y la emigración.', ja: 'その街は放棄と移住によってゆっくりと死にかけていた。', trivia: '動詞 morir（死ぬ）の現在分詞形で、語幹母音が o→u に変化する不規則活用が特徴。morir はラテン語 morī に由来し、英語の mortal（死すべき）や murder（殺人）と同語根である。' },
  'muro': { es: 'Derribaron el viejo muro para ampliar el patio de la escuela.', ja: '学校の中庭を広げるために古い壁を取り壊した。', trivia: 'ラテン語 murus（壁）から直接受け継いだ語で、英語の mural（壁画）と同語根。英語で「壁」を意味する wall はゲルマン語系であり語根が異なるが、muro に相当する英語の学術語として mure（古語）も存在する。' },
  'músculo': { es: 'Para ganar músculo es necesario combinar el ejercicio con una dieta rica en proteínas.', ja: '筋肉をつけるには、運動とタンパク質豊富な食事を組み合わせる必要がある。', trivia: 'ラテン語 musculus（小さなネズミ）に由来し、筋肉が動く様子がネズミに似て見えたことからこの名が付いた。英語の muscle と完全な同語根であり、mussel（ムール貝）も同じ語源を持つ。' },
  'musical': { es: 'Fuimos a ver un musical de Broadway que llegó de gira a Madrid.', ja: 'マドリードに巡業してきたブロードウェイのミュージカルを見に行った。', trivia: 'ラテン語 musica（音楽）に由来し、さらにギリシャ語 mousikē（ムーサの芸術）に遡る。英語の musical と全く同形・同意で使われる典型的な共通語であり、国際的な借用語の好例といえる。' },
  'músico': { es: 'Mi hermana es músico profesional y toca el violín en una orquesta sinfónica.', ja: '私の姉はプロの音楽家で、交響楽団でバイオリンを弾いている。', trivia: 'ラテン語 musicus（音楽の）に由来し、ギリシャ語 mousikos（ムーサに関わる）に遡る。英語の musician と同語根だが、スペイン語では músico という短い形が一般的で、英語の music に対応する名詞形としても機能する。' },
  'mutuo': { es: 'El acuerdo se basaba en el respeto mutuo y la confianza entre las dos partes.', ja: 'その合意は両者間の相互の敬意と信頼に基づいていた。', trivia: 'ラテン語 mutuus（お互いの、交換された）に由来する。英語の mutual と完全な同語根で意味も同じだが、スペイン語では mutuo、英語では mutual と形が少し異なる点が学習上の注意点となる。' },
  'n': { es: 'La letra n es una de las más frecuentes en el idioma español.', ja: 'nという文字はスペイン語の中で最も使用頻度の高い文字の一つだ。', trivia: 'フェニキア文字の nūn（魚）に由来し、ギリシャ語のニュー（ν）、ラテン語の N を経て現在の形になった。英語でも同じ文字 n を使い、数学では自然数を表す変数として広く用いられる点も英語と共通している。' },
  'nacimiento': { es: 'El nacimiento del niño llenó de alegría a toda la familia.', ja: '赤ちゃんの誕生は家族全員を喜びで満たした。', trivia: '動詞 nacer（生まれる）に名詞化接尾辞 -miento が付いた形で、ラテン語 nasci（生まれる）に由来する。英語の natal（出生の）や nativity（降誕）と同語根であり、Renaissance（再生・文芸復興）も同じ語根を持つ。' },
  'nación': { es: 'La nación se unió en torno a los valores de libertad y democracia.', ja: 'その国家は自由と民主主義の価値観のもとに結束した。', trivia: 'ラテン語 natio（生まれ、民族）に由来し、nasci（生まれる）と同語根。英語の nation と完全に同語根で意味も同じであり、international、nationality なども共通の語根から派生している。' },
  'nacionalidad': { es: 'Para renovar el pasaporte, debes indicar tu nacionalidad en el formulario.', ja: 'パスポートを更新するには、申請書に国籍を記入する必要がある。', trivia: 'nacional（国家の）に抽象名詞を作る接尾辞 -idad が付いた形で、ラテン語 nationalis に遡る。英語の nationality と完全な同語根で、-idad と -ity はそれぞれスペイン語・英語における同源の接尾辞である。' },
  'nada': { es: 'No tengo nada que hacer esta tarde, así que puedo ayudarte.', ja: '今日の午後は特にやることがないから、手伝えるよ。', trivia: 'ラテン語の res nata（生まれたもの、つまりとるに足りないもの）が縮まった形とされる。英語の nothing や not at all に相当するが、英語と語源的なつながりはなく、むしろ nada はスペイン語・ポルトガル語に特有の発展を遂げた語だ。' },
  'nadie': { es: 'Llamé a la puerta varias veces, pero nadie respondió.', ja: '何度もドアをノックしたが、誰も応答しなかった。', trivia: 'ラテン語 nati（生まれた者たち）の否定形から派生したとされ、nada と同じ語根を持つ。英語の nobody や no one に相当するが、英語との語源的直接関係はなく、スペイン語独自の発達を見せている点が興味深い。' },
  'nal': { es: 'El tribunal nal se encargó de resolver el conflicto entre las dos provincias.', ja: '国家裁判所が二つの州間の紛争の解決を担った。', trivia: 'これは nacional（国家の）の略記・短縮形であり、独立した語としての使用は限定的。ラテン語 nationalis に由来し、英語の national と同語根。正式表現では nacional を用いるのが標準的である。' },
  'narrar': { es: 'El escritor narraba sus aventuras con una voz pausada y llena de detalles.', ja: 'その作家はゆっくりとした声で、細部まで丁寧に自分の冒険を語った。', trivia: 'ラテン語 narrare（話す、語る）に由来し、さらに gnarus（知っている）と同語根とされる。英語の narrate、narrative、narrator と完全に同語根であり、スペイン語と英語でほぼ同形・同意で使われる学術語の好例だ。' },
  'natural': { es: 'Es natural que los niños cometan errores mientras aprenden.', ja: '子供たちが学ぶ過程でミスを犯すのは当然のことだ。', trivia: 'ラテン語 naturalis（自然に関する）に由来し、natura（自然、本質）と同語根。英語の natural と完全に同語根で形・意味ともほぼ同じであり、supernatural（超自然の）など派生語も英語・スペイン語で共通して存在する。' },
  'naturaleza': { es: 'Me encanta salir a caminar por la naturaleza los fines de semana.', ja: '週末に自然の中を歩くのが大好きだ。', trivia: 'ラテン語 natura に接尾辞 -leza が付いた形で、英語の nature と同語根。英語では nature 一語で対応するが、スペイン語では naturaleza が「自然界」の意で、natura の派生形として豊かに発展している。' },
  'naufragio': { es: 'Los supervivientes del naufragio fueron rescatados después de dos días a la deriva.', ja: '難破の生存者たちは2日間漂流した末に救助された。', trivia: 'ラテン語 naufragium（難破）に由来し、navis（船）と frangere（壊す）の合成語。英語の naval（海軍の）は navis と同語根、fracture（骨折）は frangere と同語根であり、英語ではこれに直接対応する一般語は shipwreck が使われる。' },
  'navaja': { es: 'El cocinero abrió la navaja con destreza para preparar los ingredientes.', ja: '料理人は食材を準備するために折りたたみナイフを手際よく開いた。', trivia: 'ラテン語 novacula（カミソリ、小刀）に由来し、novacula は novare（新しくする・削る）と関連するとされる。英語には直接対応する借用語はなく、jackknife や penknife と表現されるが、英語の novel（新しい）と遠い語根のつながりがある可能性も指摘される。' },
  'Navidad': { es: 'Pasamos la Navidad en familia comiendo turrón y viendo las luces de la ciudad.', ja: '家族でトゥロンを食べ、街のイルミネーションを見ながらクリスマスを過ごした。', trivia: 'ラテン語 nativitas（誕生）に由来し、nasci（生まれる）と同語根。英語の nativity（降誕、降誕劇）と完全に同語根で、英語では Christmas が一般的だが、Navidad は「キリストの誕生（Natividad）」という宗教的意味を語形に留めている。' },
  'necedad': { es: 'Fue una necedad gastar todos los ahorros en un solo día.', ja: '全貯金を一日で使い果たすとは愚かな行為だった。', trivia: '形容詞 necio（愚かな）に抽象名詞接尾辞 -dad が付いた形で、necio はラテン語 nescius（知らない）に由来し、ne-（否定）+ scire（知る）の合成語。英語の science（知識・科学）や conscious と同語根であり、「無知から生じる愚かさ」という語源的意味が透けて見える。' },
  'necesidad': { es: 'La necesidad de ahorrar energía se ha vuelto urgente ante el cambio climático.', ja: '気候変動を前に、エネルギーを節約する必要性が緊急のものとなっている。', trivia: 'ラテン語 necessitas（必然性、避けられないこと）に由来し、necesse（避けられない）から派生している。英語の necessity と完全に同語根で、-idad と -ity という対応する接尾辞を持つスペイン語・英語の並行語の典型例だ。' },
  'nefasto': { es: 'El accidente tuvo consecuencias nefastas para toda la comunidad.', ja: 'その事故は地域社会全体に悲惨な影響をもたらした。', trivia: 'ラテン語 nefastus（神聖でない、不吉な）に由来し、ne-（否定）+ fas（神の法、許されたこと）の合成語。英語には nefarious（邪悪な、悪名高い）という同語根の語があり、どちらも「神の法に反する」という原義を持つ。' },
  'negar': { es: 'El sospechoso negó haber estado en el lugar del crimen aquella noche.', ja: '容疑者はその夜、犯行現場にいたことを否定した。', trivia: 'ラテン語 negare（否定する）に由来し、ne-（否定）が語根に含まれる。英語の negate、negative、deny（de- + negare の縮約形）と同語根であり、negotiate（元は「暇でない＝仕事をする」の意）も遠い親戚にあたる。' },
  'negociación': { es: 'Las negociaciones entre los dos países terminaron con un acuerdo de paz.', ja: '両国間の交渉は平和協定で終結した。', trivia: 'ラテン語 negotiatio（商業活動・取引）に由来し、neg-（否定）＋otium（余暇）の合成語、つまり「余暇のないこと＝仕事」が原義。英語の negotiation と同語根の完全な同義コグネート。' },
  'negociar': { es: 'El sindicato y la empresa negociaron un aumento de sueldo durante tres meses.', ja: '労働組合と会社は3か月間にわたって賃上げを交渉した。', trivia: 'ラテン語 negotiari（取引する）から派生し、negociación や negocio と同じ語族。英語の negotiate と完全に同語根であり、スペルも意味も非常に近い。' },
  'negocio': { es: 'Mi tío abrió un negocio de comida en el centro de la ciudad.', ja: '叔父は市の中心部で飲食店を開いた。', trivia: 'ラテン語 negotium（仕事・用件）から直接継承された語。英語の business に相当するが、英語 negotiation（交渉）とも同語根であり、「仕事＝余暇がない状態」という原義を共有している。' },
  'nene': { es: 'La nene se quedó dormida en los brazos de su madre.', ja: '赤ちゃんはお母さんの腕の中で眠ってしまった。', trivia: '語源は幼児語（擬音語的な反復形）で、赤ちゃんが発する「ね」に似た音に由来するとされる。英語に直接対応する同語根の語はなく、baby や infant が意味的に相当する。' },
  'nervio': { es: 'El médico dijo que tenía el nervio ciático inflamado.', ja: '医者は坐骨神経が炎症を起こしていると言った。', trivia: 'ラテン語 nervus（腱・神経）に由来し、英語の nerve と完全に同語根。ギリシャ語 neuron（神経）とも関連しており、英語の neuron や neurological にも同じ古代ギリシャ語の祖先が見られる。' },
  'nervioso': { es: 'Estaba muy nervioso antes de salir al escenario por primera vez.', ja: '初めて舞台に出る前、彼はとても緊張していた。', trivia: 'nervio（神経）から派生した形容詞で、ラテン語 nervosus（力強い・筋肉質な）が原義だったが、現代では「神経質・緊張した」の意味に転じた。英語 nervous と同語根で意味も近く、典型的な透明コグネートの一つ。' },
  'neto': { es: 'Mi salario neto después de impuestos es bastante menor que el bruto.', ja: '税引き後の手取り給与は額面よりかなり少ない。', trivia: 'イタリア語 netto（正味の・清潔な）を経由したラテン語 nitidus（輝く・清潔な）に由来する。英語の net（正味の、純〜）と同語根であり、net weight（正味重量）や net profit（純利益）に相当する用語として使われる。' },
  'neumático': { es: 'Se me pinchó el neumático trasero en medio de la autopista.', ja: '高速道路の真ん中で後ろのタイヤがパンクした。', trivia: 'ギリシャ語 pneumatikos（空気の・息の）に由来し、pneuma（空気・息）が語根。英語の pneumatic（空気圧の）と同語根で、pneumonia（肺炎）や pneumatic drill（空気圧ドリル）にも同じ語根が見られる。' },
  'neutral': { es: 'Suiza ha mantenido una posición neutral en numerosos conflictos internacionales.', ja: 'スイスは多くの国際紛争において中立の立場を維持してきた。', trivia: 'ラテン語 neutralis（どちらでもない）に由来し、ne-（否定）＋uter（どちらか）が語源。英語の neutral と完全に同語根で、形・意味ともほぼ同一の透明コグネート。' },
  'nieve': { es: 'Cayó tanta nieve que no pudimos salir de casa en todo el día.', ja: '雪がたくさん降って、一日中家から出られなかった。', trivia: 'ラテン語 nix / nivis（雪）に由来し、動詞 nevar（雪が降る）とも同族。英語では snow と言い語根は異なるが、英語の niveous（雪のように白い）という形容詞はラテン語 nix と同語根である。' },
  'nido': { es: 'Los pájaros construyeron un nido en el árbol del jardín.', ja: '庭の木に鳥が巣を作った。', trivia: 'ラテン語 nidus（巣）に直接由来し、英語の nest と印欧祖語の同一語根 *ni-sd-（座るところ）を共有している。英語でも nidus という語が生物学・医学用語として「感染巣」の意で使われる。' },
  'nieta': { es: 'La abuela le enseñó a su nieta a hacer tortillas caseras.', ja: '祖母は孫娘に手作りのトルティーヤの作り方を教えた。', trivia: 'ラテン語 nepota（姪・孫娘）に由来し、男性形 nieto と同族。英語の nephew（甥）と同語根であり、どちらもラテン語 nepos（孫・甥）を祖先に持つ。' },
  'nieto': { es: 'El abuelo lleva a su nieto al parque todos los sábados.', ja: '祖父は毎週土曜日に孫を公園に連れて行く。', trivia: 'ラテン語 nepos（孫・甥）の派生形 nepotus に由来する。英語の nephew（甥）と同語根で、イタリア語 nipote も同系。英語 nepotism（縁故主義）もこの語根から来ており、「身内を優遇する」意味で使われる。' },
  'niña': { es: 'La niña aprendió a leer antes de cumplir los cinco años.', ja: 'その女の子は5歳になる前に読み方を覚えた。', trivia: 'ラテン語起源については諸説あるが、幼児語的な表現から定着したとされる。英語では girl に相当するが語根は異なる。「瞳孔」の意味（niña del ojo）でも使われ、英語の pupil（瞳孔・生徒）が「小さな人形」を意味するラテン語 pupilla に由来するのと発想が似ている。' },
  'niñez': { es: 'Guarda muy buenos recuerdos de su niñez en el pueblo.', ja: '彼女は村での幼少期についてとてもよい思い出を持っている。', trivia: 'niño / niña（子供）に抽象名詞を作る接尾辞 -ez を加えた語。英語では childhood に相当するが語根は異なる。-ez はスペイン語特有の接尾辞で、vejez（老年期）や madurez（成熟期）なども同様の構造を持つ。' },
  'níquel': { es: 'La moneda de cinco centavos de dólar se llama nickel y está hecha principalmente de cobre.', ja: '5セント硬貨はニッケルと呼ばれるが、主に銅でできている。', trivia: 'ドイツ語 Nickel に由来し、スウェーデンの鉱山師が「悪魔の銅（Kupfernickel）」と呼んだことに由来する（銅に見えるのに銅が取れなかったため）。英語の nickel と同語根・同義の国際的な借用語。' },
  'nítido': { es: 'La fotografía salió muy nítida gracias a la nueva cámara.', ja: '新しいカメラのおかげで写真がとても鮮明に撮れた。', trivia: 'ラテン語 nitidus（輝く・清潔な・鮮明な）に直接由来する。英語に直接の同語根コグネートはないが、英語の neat（きちんとした）はフランス語経由で同じラテン語 nitidus に由来するとされ、遠い親戚にあたる。' },
  'no': { es: 'No entiendo por qué tomó esa decisión sin consultarnos.', ja: 'なぜ私たちに相談せずにその決断を下したのか、理解できない。', trivia: 'ラテン語 non（否定）の短縮形で、古スペイン語では non のまま使われていた。英語の no や not もゲルマン祖語 *ne に由来しており、印欧祖語の否定辞 *ne という共通の遠い祖先を持つ。' },
  'noble': { es: 'Fue un gesto muy noble de su parte ayudar a los damnificados sin pedir nada a cambio.', ja: '見返りを求めずに被災者を助けたのは、彼にとってとても気高い行為だった。', trivia: 'ラテン語 nobilis（知られた・著名な・貴族の）に由来し、noscere（知る）と同語根。英語の noble と完全に同語根であり、形・意味ともにほぼ同一の典型的な透明コグネート。' },
  'nobleza': { es: 'La nobleza de su carácter se reveló cuando donó toda su herencia a obras benéficas.', ja: '遺産をすべて慈善事業に寄付したとき、彼の人格の気高さが明らかになった。', trivia: 'noble（高潔な・貴族の）に抽象名詞を作る接尾辞 -eza を加えた語で、ラテン語 nobilitas に対応する。英語の nobility と同語根で意味も同じだが、スペイン語では -eza、英語では -ity という異なる接尾辞で抽象名詞を形成している点が興味深い。' },
  'nombramiento': { es: 'El nombramiento del nuevo director fue anunciado en una reunión del consejo.', ja: '新しい理事長の任命は理事会の会議で発表された。', trivia: 'nombrar（指名する）に行為・結果を表す接尾辞 -miento を加えた語で、ラテン語 nominare（名前を付ける）に由来する。英語の nomination と同語根であり、どちらもラテン語 nomen（名前）を祖先に持つ。' },
  'nombrar': { es: 'El presidente nombró a una experta en economía como ministra de finanzas.', ja: '大統領は経済の専門家を財務大臣に任命した。', trivia: 'ラテン語 nominare（名前を付ける・指名する）に由来し、nombre（名前）と同族。英語の nominate と同語根であり、どちらもラテン語 nomen（名前）を語根とする。英語の name もゲルマン語経由で同じ印欧祖語 *nomn- に遡る。' },
  'norma': { es: 'Todos los empleados deben cumplir con las normas de seguridad del trabajo.', ja: 'すべての従業員は職場の安全規則を遵守しなければならない。', trivia: 'ラテン語 norma（大工の定規・基準）に直接由来し、本来は直角を測る道具を指していた。英語の norm や normal と完全に同語根で、英語の enormous（巨大な）も e-（外れた）＋norma（基準）という構造を持つ関連語。' },
  'normal': { es: 'Es completamente normal sentirse nervioso antes de una entrevista de trabajo.', ja: '就職面接の前に緊張するのはまったく普通のことだ。', trivia: 'ラテン語 normalis（直角の・規則に従った）に由来し、norma（基準・定規）と同族。英語の normal と完全に同語根・同義の透明コグネートで、形・アクセント位置も非常に近い。' },
  'norte': { es: 'El norte del país es conocido por sus montañas nevadas y su clima frío.', ja: 'その国の北部は雪を頂く山々と寒冷な気候で知られている。', trivia: 'ラテン語ではなく、古英語の「norþ」に由来するゲルマン語起源の語で、ロマンス諸語に借用された珍しいケース。英語の north と完全に同語根であり、スペルも非常に近い。' },
  'norteamericano': { es: 'Mi vecino norteamericano me enseñó muchas expresiones del inglés coloquial.', ja: '北米出身の隣人が、英語の口語表現をたくさん教えてくれた。', trivia: 'norte（北）＋americano（アメリカの）の合成語。英語では North American に相当し、構造も意味も対応している。スペイン語では特にアメリカ合衆国の人を指す場合に estadounidense も使われ、norteamericano より厳密な場合がある。' },
  'nos': { es: 'El profesor nos explicó la diferencia entre el pretérito indefinido y el imperfecto.', ja: '先生は私たちに、点過去と線過去の違いを説明してくれた。', trivia: 'ラテン語の nos（私たちを・私たちに）に直接由来し、英語の us と同じ機能を持つ。英語の us はゲルマン語系で語根は異なるが、一人称複数の目的格という役割は完全に一致する。' },
  'nosotros': { es: 'Nosotros llegamos al aeropuerto con mucha anticipación para no perder el vuelo.', ja: '私たちはフライトに乗り遅れないよう、空港にずいぶん早く到着した。', trivia: 'ラテン語の nos（私たち）＋ otros（他の者たち）が融合した強調形で、「私たちこそが」というニュアンスが元にある。英語の we に相当するが、英語には同様の強調複合語は存在しない。' },
  'nota': { es: 'Saqué una nota muy alta en el examen de matemáticas gracias a que estudié mucho.', ja: 'たくさん勉強したおかげで、数学の試験でとても高い点数を取ることができた。', trivia: 'ラテン語の nota（印、記号）に由来し、英語の note と完全に同語根。「書き留めたもの」という原義から、メモ・成績・音符など多義的に発展した点も英語の note と共通している。' },
  'notar': { es: 'Noté que algo había cambiado en su actitud desde la última vez que nos vimos.', ja: '前回会ったときから彼の態度に何か変化があったことに気づいた。', trivia: 'ラテン語の notare（印をつける、観察する）に由来し、英語の notice や note と同語根。英語の notice がラテン語 notitia 経由であるのに対し、notar はより直接的に notare から来ている。' },
  'noticia': { es: 'Vi en las noticias que habrá una tormenta fuerte esta tarde.', ja: '今日の午後、強い嵐が来るというニュースを見た。', trivia: 'ラテン語の notitia（知識、情報）に由来し、英語の notice と同語根。英語では news がより一般的なニュースの訳語だが、notice には「気づき・通知」の意味が残っており、スペイン語の noticia に近い原義を保っている。' },
  'notificar': { es: 'El banco me notificó por correo electrónico que había un movimiento inusual en mi cuenta.', ja: '銀行から、私の口座に不審な動きがあったというメールで通知が来た。', trivia: 'ラテン語の notificare（知らせる）＝ nota（知識）＋ facere（する）に由来し、英語の notify と完全に同語根で意味も同じ。英語の notify もラテン語 notificare からの借用語である。' },
  'novato': { es: 'Como soy novato en la cocina, a veces cometo errores básicos con las recetas.', ja: '料理は初心者なので、レシピで基本的なミスをしてしまうことがある。', trivia: 'ラテン語の novus（新しい）に由来し、英語の novice（初心者）や novel（小説・新奇な）と同語根。英語 novice は主に宗教的見習いを指した語だが、スペイン語の novato はより口語的でスポーツや職場の「新人」に幅広く使われる。' },
  'novedad': { es: 'No hay ninguna novedad en el trabajo; todo sigue igual que antes.', ja: '仕事上は特に変わったことはなく、すべて以前と同じままだ。', trivia: 'ラテン語の novitas（新しさ）に由来し、英語の novelty と同語根。英語の novelty が「目新しいもの・珍しさ」というやや軽いニュアンスを持つのに対し、スペイン語の novedad はビジネスや日常会話で「変わった出来事・近況」という意味でも頻繁に使われる。' },
  'novela': { es: 'Estoy leyendo una novela histórica sobre la Guerra Civil Española que me parece fascinante.', ja: 'スペイン内戦を題材にした歴史小説を読んでいるのだが、とても面白い。', trivia: 'イタリア語の novella（新しい話・短編小説）を経由してラテン語の novus（新しい）に由来し、英語の novel（小説）と同語根。英語の novel はイタリア語から直接借用されたもので、スペイン語の novela と歴史的経緯を共有している。' },
  'novelista': { es: 'La novelista colombiana presentó su nuevo libro en la feria internacional del libro de Madrid.', ja: 'コロンビア人の女性小説家がマドリードの国際ブックフェアで新作を発表した。', trivia: 'novela（小説）＋接尾辞 -ista（専門家・従事者）から成り、英語の novelist と同語根・同構造。英語の novelist もフランス語 nouvelliste を経由したもので、スペイン語と同じラテン語 novus（新しい）を共有している。' },
  'noveno': { es: 'Llegamos al noveno piso del edificio y desde allí se veía toda la ciudad.', ja: 'ビルの9階に着くと、そこから街全体が見渡せた。', trivia: 'ラテン語の nonus（9番目の）に由来し、英語の ninth と同じ概念を表すが語根は異なる経路を経ている。ラテン語 novem（9）は英語の nine とも印欧祖語 *newn̥（9）で同語根であり、英語の November（もとは9番目の月）も同じ語根を持つ。' },
  'noventa': { es: 'Mi abuela tiene noventa años y todavía camina todos los días por el parque.', ja: '私の祖母は90歳で、今でも毎日公園を散歩している。', trivia: 'ラテン語の nonaginta（90）に由来し、英語の ninety とは印欧祖語 *newn̥（9）で同語根。ラテン語では nona-（9）＋-ginta（10倍）という構造を持ち、スペイン語では noventa に変化した。' },
  'novia': { es: 'Mi novia y yo llevamos tres años juntos y el mes que viene nos comprometemos.', ja: '彼女と付き合って3年になり、来月婚約する予定だ。', trivia: 'ラテン語の nova（新しい女性）または novia（新婦）に由来し、英語の new と印欧祖語 *newo-（新しい）で同語根。英語には novia に直接対応する単語はなく、girlfriend・fiancée・bride と文脈によって訳し分ける必要がある。' },
  'novio': { es: 'El novio de mi hermana le regaló flores el día de su aniversario.', ja: '姉の彼氏が記念日に花をプレゼントした。', trivia: 'ラテン語の novius（新郎）に由来し、novia の男性形。英語の new と印欧祖語 *newo-（新しい）で同語根。英語では boyfriend・fiancé・groom と役割によって使い分けるのに対し、スペイン語の novio は恋人・婚約者・新郎をすべてカバーする。' },
  'nuca': { es: 'Me duele la nuca después de pasar horas mirando la pantalla del ordenador.', ja: 'パソコンの画面を何時間も見ていたら、うなじが痛くなってきた。', trivia: 'アラビア語の nukhāʿ（脊髄・首の骨）に由来するとされ、英語には直接の同語根語はない。英語では nape（of the neck）と言い、これは古フランス語 nape に由来するが、スペイン語の nuca とは語源が異なる。' },
  'núcleo': { es: 'El núcleo del problema es la falta de comunicación entre los distintos departamentos.', ja: '問題の核心は、各部署間のコミュニケーション不足にある。', trivia: 'ラテン語の nucleus（核・種核）に由来し、英語の nucleus と完全に同語根・同スペル（アクセント記号を除く）。英語の nucleus は科学用語として18世紀にラテン語から直接借用され、スペイン語の núcleo も同じ経路で学術語彙に定着した。' },
  'nuera': { es: 'Mi nuera cocina muy bien y siempre trae un postre casero cuando nos visita.', ja: '義理の娘は料理がとても上手で、訪ねてくるときにはいつも手作りのデザートを持ってきてくれる。', trivia: 'ラテン語の nurus（息子の妻）に由来し、英語の daughter-in-law に相当するが英語との直接の同語根語はない。ラテン語 nurus はサンスクリット語 snuṣā と印欧祖語で共通の語根を持つ古い親族名称で、英語では snore と語根が近いという説もある。' },
  'nuestro': { es: 'Nuestro equipo ganó el campeonato después de meses de entrenamiento intensivo.', ja: '私たちのチームは数か月間の集中トレーニングの末、選手権で優勝した。', trivia: 'ラテン語の noster（私たちの）に由来し、英語の our と同じ意味だが語根は異なる。英語の our はゲルマン語系（古英語 ūre）に由来するのに対し、スペイン語の nuestro はラテン語系。ただし印欧祖語の nos（私たち）まで遡ると共通の起源を持つ。' },
  'nueva': { es: '¿Has oído la nueva? Parece que van a abrir un restaurante japonés en nuestra calle.', ja: 'もう聞いた？私たちの通りに日本料理のレストランがオープンするらしいよ。', trivia: 'ラテン語の nova（新しい女性形）に由来し、英語の new と印欧祖語 *newo-（新しい）で同語根。英語の news（ニュース）も本来 new の複数形であり、「新しい出来事」という意味でスペイン語の nueva（知らせ）と意味的にも並行している。' },
  'nueve': { es: 'El tren de las nueve de la mañana llega siempre con puntualidad.', ja: '午前9時の電車はいつも時間通りに到着する。', trivia: 'ラテン語の novem（9）に由来し、英語の nine と印欧祖語 *newn̥（9）で同語根。英語の November（もとは年の9番目の月）、スペイン語の noviembre も同じ語根を持つ。' },
  'nuez': { es: 'Me gusta añadir nueces picadas al yogur por las mañanas para tener más energía.', ja: '朝のエネルギー補給のため、ヨーグルトに刻んだクルミを加えるのが好きだ。', trivia: 'ラテン語の nux / nucem（木の実）に由来し、英語の nut と印欧祖語 *kneu-（木の実）で同語根とされる。英語の nut はゲルマン語経由、スペイン語の nuez はラテン語直系と経路は異なるが、最終的な起源は共通している可能性が高い。' },
  'nulo': { es: 'El contrato fue declarado nulo por el juez porque no cumplía con los requisitos legales.', ja: 'その契約は法的要件を満たしていなかったため、裁判官によって無効と宣言された。', trivia: 'ラテン語の nullus（何もない、ゼロの）に由来し、英語の null と完全に同語根。英語の null も法律・数学・コンピュータ用語として同じ意味で使われており、スペイン語の nulo と互いに翻訳可能な対応語である。' },
  'numerar': { es: 'El bibliotecario numeró todas las páginas del manuscrito antes de escanearlo.', ja: '司書はスキャンする前に、写本のすべてのページに番号を振った。', trivia: 'ラテン語の numerare（数える、番号をつける）に由来し、英語の numerate や enumerate と同語根。英語の enumerate（列挙する）は e-（外に）＋numerare の合成で、スペイン語の enumerar も同様に存在する。' },
  'numérico': { es: 'El sistema numérico binario es la base de toda la informática moderna.', ja: '二進数の数値システムは、現代のコンピュータ全体の基盤となっている。', trivia: 'ラテン語 numerus（数）から派生した形容詞で、英語の numeric / numerical と完全な同語根の語。数学・情報科学の文脈で両言語ともほぼ同じ意味・用法で使われる。' },
  'nupcial': { es: 'La marcha nupcial resonó en toda la catedral durante la ceremonia.', ja: '式典の間、結婚行進曲が大聖堂全体に響き渡った。', trivia: 'ラテン語 nuptiae（結婚式）に由来し、英語の nuptial と同語根。英語の nuptial は現代では主に文語・詩語として使われるのに対し、スペイン語では「nupcial」は比較的よく使われる形容詞である。' },
  'nutricia': { es: 'La leche materna tiene una función nutricia insustituible para el recién nacido.', ja: '母乳は新生児にとって代替不可能な栄養・養育機能を持っている。', trivia: 'ラテン語 nutrire（養う、育てる）に由来し、英語の nurture や nurse と同語根。日常ではより一般的な nutritivo が使われるが、nutricia は医療・学術文書などで栄養を与える機能そのものを指す際に用いられる。' },
  'nutrición': { es: 'Una buena nutrición durante la infancia es clave para el desarrollo físico y mental.', ja: '幼少期における適切な栄養摂取は、身体的・精神的な発達の鍵である。', trivia: 'ラテン語 nutritio（養育）に由来し、英語の nutrition と同語根かつ同義の典型的な国際語（internacionalismo）。スペイン語でも英語でも医学・食育の分野で広く使われる。' },
  'nutritivo': { es: 'Los frutos secos son muy nutritivos y se pueden tomar como snack saludable.', ja: 'ナッツ類は非常に栄養豊富で、健康的なスナックとして食べることができる。', trivia: 'ラテン語 nutrire（養う）から派生した形容詞で、英語の nutritive あるいは nutritious と同語根。英語では nutritious の方が日常的に使われるのに対し、スペイン語では nutritivo が最もよく使われる一般的な形容詞である。' },
  'o': { es: '¿Prefieres el café o el té por las mañanas?', ja: '朝はコーヒーと紅茶、どちらが好きですか？', trivia: 'ラテン語の接続詞 aut（または）や vel（または）に由来するとされ、英語の or とは語源が異なる（英語の or は古英語 oththe に由来）。なお、数字の 0 と紛らわしい場合は ó とアクセント符号をつける慣習がある（現代正書法では任意）。' },
  'oasis': { es: 'El pequeño café del barrio era un oasis de tranquilidad en medio del ruido urbano.', ja: 'その町の小さなカフェは、都会の喧騒の中の静けさのオアシスだった。', trivia: '古代エジプト語の waḥe（砂漠の居住地）が起源とされ、ギリシャ語 oasis を経由してラテン語・スペイン語へと伝わった。英語の oasis も同じ経路で借用された同形の語で、比喩的用法（安らぎの場）も両言語で共通している。' },
  'obedecer': { es: 'El perro obedece todas las órdenes de su dueño sin dudarlo.', ja: 'その犬は飼い主のすべての命令に迷わず従う。', trivia: 'ラテン語 oboedire（耳を傾ける、従う）に由来し、英語の obey と同語根。英語では obey という短い形に変化したのに対し、スペイン語では obedecer として -ecer 動詞の形を保っている。' },
  'obediencia': { es: 'La obediencia ciega puede ser tan peligrosa como la rebeldía sin motivo.', ja: '盲目的な服従は、理由のない反抗と同様に危険なこともある。', trivia: 'ラテン語 oboedientia に由来し、英語の obedience と同語根の語。スペイン語の -ncia 語尾は英語の -nce に対応するパターンの典型例で（例：diferencia / difference）、両言語で発音は異なるが意味・用法はほぼ同じである。' },
  'obispo': { es: 'El obispo presidió la misa de Navidad ante miles de fieles.', ja: '司教は何千人もの信者を前にクリスマスミサを主宰した。', trivia: 'ラテン語 episcopus を経由し、ギリシャ語 episkopos（監督者、見張り）に由来する。英語の bishop も同じ語源で、古英語での音変化により形がかなり変わった。チェスの駒「ビショップ」もこの語に由来する。' },
  'objeción': { es: 'El abogado presentó una objeción formal al testimonio del testigo.', ja: '弁護士は証人の証言に対して正式な異議を申し立てた。', trivia: 'ラテン語 obiectio（投げつけること、反論）に由来し、英語の objection と同語根の国際語。法廷ドラマでよく聞く「¡Objeción!」は英語の「Objection!」とほぼ同形で、語源的にも意味的にも直結している。' },
  'objetar': { es: 'Nadie objetó nada cuando se propuso cambiar el horario de la reunión.', ja: '会議の時間変更が提案されたとき、誰も何も反対しなかった。', trivia: 'ラテン語 obiectare（繰り返し投げつける、反論する）に由来し、英語の object（動詞）と同語根。英語の object は名詞・動詞兼用だが、スペイン語では動詞 objetar と名詞 objeto は語形が明確に分かれている。' },
  'objetivo': { es: 'Nuestro principal objetivo este año es aumentar las ventas en un veinte por ciento.', ja: '今年の主な目標は売上を20パーセント伸ばすことである。', trivia: 'ラテン語 obiectivus（目の前に置かれた）に由来し、英語の objective と同語根。哲学・科学用語として「客観的な」という意味で使われるほか、「目標」「レンズ（光学）」という意味も持ち、英語の objective と多義性まで共通している。' },
  'objeto': { es: 'Encontraron varios objetos extraños en el fondo del lago.', ja: '湖の底でいくつかの奇妙な物体が発見された。', trivia: 'ラテン語 obiectum（目の前に投げ出されたもの）の中性形に由来し、英語の object と同語根。哲学・文法・日常語として「物体」「対象」「目的語」など多義的に使われる点も英語の object と共通している。' },
  'obligación': { es: 'Tienes la obligación de informar al jefe sobre cualquier problema grave.', ja: '深刻な問題が発生した場合は上司に報告する義務がある。', trivia: 'ラテン語 obligatio（縛ること、契約）に由来し、英語の obligation と同語根。ob-（〜に対して）と ligare（縛る）の複合語で、英語の ligament（靱帯）や religion とも遠縁の関係にある。' },
  'obligar': { es: 'La tormenta nos obligó a cancelar el viaje de fin de semana.', ja: '嵐のせいで週末の旅行をキャンセルせざるを得なくなった。', trivia: 'ラテン語 obligare（縛る、義務づける）に由来し、英語の oblige と同語根。英語の oblige は「（恩義で）喜ばせる」「余儀なくさせる」というやや穏やかなニュアンスで使われることも多いが、スペイン語の obligar はより直接的に「強制する」という意味合いが強い。' },
  'obligatorio': { es: 'El uso del casco es obligatorio para todos los motoristas.', ja: 'ヘルメットの着用はすべてのオートバイ乗りに義務づけられている。', trivia: 'ラテン語 obligatorius に由来し、英語の obligatory と同語根。英語では mandatory や compulsory がより口語的に使われることが多いのに対し、スペイン語では obligatorio が法規・規則において最も標準的な語として広く使われる。' },
  'obra': { es: 'La catedral de Sagrada Familia es considerada la obra maestra de Gaudí.', ja: 'サグラダ・ファミリア大聖堂はガウディの傑作と見なされている。', trivia: 'ラテン語 opera（仕事、作品）に由来し、英語の opera（オペラ）と同語根。英語では opera は音楽劇に意味が特化したが、スペイン語の obra は「作品」「工事」「建設」と意味の幅がはるかに広い。obra maestra（傑作）は英語の masterpiece に相当する。' },
  'obrar': { es: 'Siempre hay que obrar con honestidad, aunque nadie nos esté mirando.', ja: '誰も見ていなくても、常に誠実に行動しなければならない。', trivia: 'ラテン語 operare（働く、作用する）に由来し、obra と同じ語根を持つ。英語の operate と同語根で、スペイン語では obrar の方が古風・文語的な響きがあり、日常会話では actuar や comportarse が使われることが多い。' },
  'obrero': { es: 'Los obreros de la construcción trabajan bajo el sol durante todo el verano.', ja: '建設作業員たちは夏の間中、太陽の下で働いている。', trivia: 'ラテン語 operarius（労働者）に由来し、obra・obrar と同語根。英語の operative（工員、工作員）と遠縁の関係にある。スペイン語の obrero は特に肉体労働者・工場労働者を指し、英語では blue-collar worker に相当する。' },
  'obscuro': { es: 'En aquel obscuro pasillo no había ninguna ventana ni lámpara.', ja: 'その暗い廊下には窓も電灯もなかった。', trivia: 'ラテン語 obscurus（暗い、不明瞭な）に由来し、英語の obscure と同語根。現代スペイン語の正書法では oscuro が標準形だが、obscuro という綴りも文語・詩語として残っている。英語では obscure は「無名の」「難解な」という比喩的意味でもよく使われる。' },
  'observar': { es: 'Los científicos observaron el comportamiento de los delfines durante varias semanas.', ja: '科学者たちは数週間にわたってイルカの行動を観察した。', trivia: 'ラテン語 observare（注意深く見守る、守る）に由来し、英語の observe と同語根の典型的な国際語。ob-（〜に向かって）と servare（守る、見張る）の複合語で、英語の conserve や preserve とも遠縁の関係にある。' },
  'observación': { es: 'El médico hizo una observación importante sobre el estado del paciente.', ja: '医師は患者の状態について重要な指摘を行った。', trivia: 'ラテン語 observatio に由来し、英語の observation と同語根。科学的な「観察」だけでなく、「発言」「指摘」という意味でも使われる点が英語と共通しており、スペイン語の -ción 語尾は英語の -tion に規則的に対応する。' },
  'observatorio': { es: 'Desde el observatorio astronómico se pueden ver miles de estrellas en noches despejadas.', ja: '天文台からは、晴れた夜に何千もの星を見ることができる。', trivia: 'ラテン語 observatorium（見張り所）に由来し、英語の observatory と同語根。語尾 -torio（英語 -tory）は「〜のための場所」を表すラテン語由来の接尾辞で、dormitorio / dormitory（寮）なども同じパターンである。' },
  'obsesión': { es: 'Su obsesión por el orden le impedía disfrutar de los pequeños placeres de la vida.', ja: '整理整頓への強迫観念が、彼女が人生の小さな喜びを楽しむことを妨げていた。', trivia: 'ラテン語 obsessio（包囲、取り憑き）に由来し、英語の obsession と同語根の語。ob-（〜に対して）と sedere（座る、陣取る）の複合語で、英語の siege（包囲）とも語源的に関連している。心理学用語として英語・スペイン語ともに OCD（強迫性障害）の文脈で使われる。' },
  'obstáculo': { es: 'La falta de recursos económicos fue el mayor obstáculo para llevar a cabo el proyecto.', ja: '資金不足がプロジェクト実行の最大の障害だった。', trivia: 'ラテン語 obstaculum（ob-「前に」+ stare「立つ」）に由来し、「前に立ちはだかるもの」が原義。英語の obstacle と完全に同語根の国際的なコグネートである。' },
  'obstante': { es: 'No obstante las dificultades, el equipo logró terminar el trabajo a tiempo.', ja: '困難にもかかわらず、チームは仕事を時間通りに終えることができた。', trivia: 'ラテン語 obstans（obstare「妨げる」の現在分詞）に由来し、単独では使われず no obstante（にもかかわらず）という副詞句で機能する。英語の notwithstanding に意味・機能が近い表現である。' },
  'obtener': { es: 'Después de varios intentos, finalmente obtuvo el permiso para construir la casa.', ja: '何度か試みた末に、ついに家を建てる許可を得た。', trivia: 'ラテン語 obtinere（ob-「向かって」+ tenere「持つ」）に由来し、「しっかりつかみ取る」が原義。英語の obtain と完全に同語根であり、どちらも「努力して手に入れる」というニュアンスを持つ。' },
  'obvio': { es: 'Era obvio que no había dormido bien porque tenía ojeras muy marcadas.', ja: '目の下のくまがひどくて、よく眠れていないのは明らかだった。', trivia: 'ラテン語 obvius（ob-「向かって」+ via「道」、つまり「道の前に現れる」）に由来し、「目の前にある＝明白な」という意味に転じた。英語の obvious と完全に同語根のコグネートである。' },
  'ocasión': { es: 'Aprovechamos la ocasión de estar todos juntos para celebrar el aniversario de la empresa.', ja: '全員が揃った機会を活かして、会社の創立記念日を祝った。', trivia: 'ラテン語 occasio（ob-「向かって」+ cadere「落ちる」の派生形）に由来し、「好機が降りかかる」が原義。英語の occasion と同語根で、スペイン語では「中古品（バーゲン品）」という口語的意味も持つ点が独特である。' },
  'ocaso': { es: 'Nos sentamos en la playa a contemplar el hermoso ocaso mientras el cielo se teñía de naranja.', ja: '空がオレンジ色に染まる中、美しい夕暮れを眺めながら浜辺に座った。', trivia: 'ラテン語 occasus（ob- + cadere「落ちる」、太陽が沈む方向）に由来し、文字通り「太陽が落ちる」が原義。英語には直接の対応語はないが、同じラテン語語根から派生した occasion と遠い親戚にあたる。' },
  'occidental': { es: 'Las culturas orientales y occidentales tienen perspectivas muy distintas sobre el concepto del tiempo.', ja: '東洋文化と西洋文化では、時間の概念について非常に異なる見方をしている。', trivia: 'ラテン語 occidentalis（occidens「日の沈む方角」の形容詞形）に由来し、太陽が沈む西を指す。英語の occidental と同語根で、現在でも Occidental と大文字で書けば英語でも「西洋の」を意味する学術・詩的表現として使われる。' },
  'occidente': { es: 'La filosofía de Occidente ha sido profundamente influenciada por los pensadores griegos.', ja: '西洋哲学はギリシャの思想家たちから深く影響を受けてきた。', trivia: 'ラテン語 occidens（occidere「沈む」の現在分詞）に由来し、「日が沈む方向」が原義。英語の Occident（西洋）と完全に同語根であり、どちらも改まった文体や固有名詞的な用法で「西洋世界」を指す。' },
  'ocio': { es: 'En sus ratos de ocio, le encanta leer novelas históricas y escuchar música clásica.', ja: '余暇の時間には、歴史小説を読んだりクラシック音楽を聴いたりするのが大好きだ。', trivia: 'ラテン語 otium（余暇、休息）に由来し、古代ローマでは知的活動や哲学的思索に費やす時間として肯定的に評価されていた。英語には直接の対応語はないが、otium の否定形 neg-otium（忙しさ）が英語の negotiate（交渉する）の語源となっている。' },
  'octubre': { es: 'En octubre, los árboles del parque se visten de colores rojos y amarillos.', ja: '10月になると、公園の木々が赤や黄色の色に染まる。', trivia: 'ラテン語 october（octo「8」+ 接尾辞 -ber）に由来し、古代ローマの10ヶ月暦では8番目の月だった。英語の October と完全に同語根で、どちらも「8の月」を意味するが、現在は共に10月を指すという歴史的なずれがある。' },
  'ocultar': { es: 'Intentó ocultar su nerviosismo hablando con mucha seguridad ante el público.', ja: '聴衆の前で自信たっぷりに話すことで、緊張を隠そうとした。', trivia: 'ラテン語 occulare（ob- + celare「隠す」）に由来する。英語の occult と同語根で、occulere の過去分詞 occultus が「隠されたもの」→「神秘的・秘儀的」という意味の英語 occult につながった。' },
  'oculto': { es: 'Detrás de esa sonrisa había un dolor oculto que nadie era capaz de ver.', ja: 'その笑顔の裏には、誰にも見えない隠れた痛みがあった。', trivia: 'ラテン語 occultus（occulere「隠す」の過去分詞）に由来する。英語の occult と同語根の直接的なコグネートであり、英語でも「隠された・神秘的な」という意味で使われる occult はスペイン語 oculto とほぼ同じ語形を保っている。' },
  'ocupación': { es: 'En el formulario pedían indicar la ocupación actual y el nivel de estudios.', ja: '申請書には現在の職業と学歴を記入するよう求められていた。', trivia: 'ラテン語 occupatio（occupare「占める」の名詞形）に由来する。英語の occupation と完全に同語根のコグネートで、「職業」という意味に加え「占領・占有」という意味も両言語で共通して持つ。' },
  'ocupar': { es: 'Los manifestantes ocuparon la plaza central durante toda la noche para protestar.', ja: 'デモ参加者たちは抗議のため、一晩中中央広場を占拠した。', trivia: 'ラテン語 occupare（ob-「向かって」+ capere「つかむ」）に由来し、「すぐにつかみ取る」が原義。英語の occupy と完全に同語根で、「空間を占める」「時間を使う」「占領する」という多義的な用法も両言語で共通している。' },
  'ochenta': { es: 'Mi abuela cumplió ochenta años y celebramos su cumpleaños con toda la familia.', ja: '祖母が80歳になり、家族全員でその誕生日を祝った。', trivia: 'ラテン語 octoginta（octo「8」+ ginta「十倍」）に由来し、「8つの十」が原義。英語の eighty とはゲルマン語系（英語）とラテン語系（スペイン語）で語根が異なるが、それぞれ独自に「8×10」を表す語を持つ平行進化の例である。' },
  'ocho': { es: 'El tren sale a las ocho en punto, así que no podemos llegar tarde.', ja: '電車は8時ちょうどに出発するので、遅刻はできない。', trivia: 'ラテン語 octo に由来し、インド・ヨーロッパ語族における「8」の共通語根 *oktō に遡る。英語の eight も同じ語根を持つコグネートで、ギリシャ語の okto、サンスクリット語の aṣṭa とも同語族である。' },
  'odiar': { es: 'Odio tener que madrugar los lunes, pero no tengo más remedio.', ja: '月曜日に早起きしなければならないのが大嫌いだが、仕方がない。', trivia: 'ラテン語 odisse（憎む）に由来し、この動詞はラテン語でも不規則活用を示す完了現在形だった。英語の odious（不快な、憎むべき）と同語根であり、odium（嫌悪・汚名）という英単語もこの語族に属する。' },
  'odio': { es: 'El odio entre los dos bandos duró generaciones y causó mucho sufrimiento.', ja: '両派の間の憎しみは何世代にもわたって続き、多くの苦しみをもたらした。', trivia: 'ラテン語 odium（憎しみ、嫌悪）に由来する。英語でも odium という語が「世間の嫌悪・汚名」という意味の改まった表現として使われており、さらに odious（忌まわしい）も同語根の英語コグネートである。' },
  'oeste': { es: 'El sol se pone por el oeste y tiñe el horizonte de colores cálidos.', ja: '太陽は西に沈み、地平線を暖かい色に染める。', trivia: 'ゲルマン語系の古フランス語 ouest 経由で借用された語で、英語の west と同語根（古ゲルマン語 *westaz）のコグネートである。スペイン語には固有のラテン語系の語 occidente もあるが、方角を示す日常語としては oeste が広く使われる。' },
  'oficial': { es: 'El gobierno publicó un comunicado oficial para aclarar su posición ante la crisis.', ja: '政府は危機に対する立場を明確にするため、公式声明を発表した。', trivia: 'ラテン語 officialis（officium「職務」の形容詞形）に由来する。英語の official と完全に同語根の国際的なコグネートで、公的・正式という意味に加えて名詞用法（将校・役人・職人）を持つ点もほぼ共通している。' },
  'oficio': { es: 'La carpintería es un oficio que requiere mucha paciencia y habilidad manual.', ja: '大工仕事は多くの忍耐と手先の器用さを必要とする職人技だ。', trivia: 'ラテン語 officium（ob- + facere「行う」、つまり「義務として行うこと」）に由来する。英語の office と同語根のコグネートだが、スペイン語の oficio は特に手工業・職人仕事という意味合いが強く、英語の office（事務所）とは意味が分岐している点が興味深い。' },
  'oferta': { es: 'El supermercado tiene una oferta especial: tres latas de atún por el precio de dos.', ja: 'スーパーで特売がある。ツナ缶3つが2つ分の値段だ。', trivia: 'ラテン語 offerta（offerre「提供する」の過去分詞形の女性形）に由来する。英語の offer と同語根で、経済学用語の supply（供給）に対応するスペイン語としても oferta が使われるため、英語と意味の幅が若干異なる点に注意が必要である。' },
  'oído': { es: 'Tiene un oído musical extraordinario y puede reconocer cualquier nota de inmediato.', ja: '彼女は並外れた音楽的な耳を持っており、どんな音符もすぐに聞き分けられる。', trivia: 'ラテン語 auditus（audire「聞く」の名詞形）に由来し、「聴覚・聞こえた結果」という意味を持つ。英語の audio、auditorium、audible などが同語根のコグネートで、スペイン語の oído は外耳を指す oreja とは異なり、内耳・聴覚の機能を指す点が英語の hearing に対応する。' },
  'oler': { es: 'Desde la cocina se podía oler el aroma del pan recién horneado.', ja: '台所から焼きたてのパンの香りが漂ってきた。', trivia: 'ラテン語 olere（匂いを発する）に由来し、語頭が hu- に変化する語根交替（huelo）は二重語化の名残である。英語の olfactory（嗅覚の）と同語根で、ラテン語 olfacere（ol- + facere「匂いを感じる」）に遡る共通の語族に属する。' },
  'olivo': { es: 'En el jardín de la casa había un olivo centenario que daba una sombra agradable.', ja: '家の庭には百年以上たつオリーブの木があり、心地よい木陰を作っていた。', trivia: 'ラテン語 oliva（オリーブの実）に由来し、古代地中海世界における最重要作物の一つだった。英語の olive と同語根のコグネートで、両者ともギリシャ語 elaia を経由したとされるが、さらに古い語源は地中海の先ロマンス系言語にあるとも言われ、詳細は不明な部分もある。' },
  'olor': { es: 'El olor a pan recién horneado llenó toda la casa.', ja: '焼きたてのパンの香りが家中に広がった。', trivia: 'ラテン語 odor（匂い）に由来し、語中の d が脱落して olor になった。英語の odor / odour はラテン語形をほぼそのまま保っており、スペイン語 olor と同語根の姉妹語である。' },
  'olvido': { es: 'Con el paso del tiempo, el olvido borró aquella triste historia.', ja: '時が経つにつれて、忘却があの悲しい物語を消し去った。', trivia: '動詞 olvidar（忘れる）の名詞形で、ラテン語 oblitare（消す、忘れる）に由来する。英語の oblivion（忘却、無意識）と同語根であり、どちらも「消し去る」という原義を共有している。' },
  'ombligo': { es: 'El bebé se quedó dormido tocándose el ombligo.', ja: '赤ちゃんはへそを触りながら眠ってしまった。', trivia: 'ラテン語 umbilicus（臍）に由来し、um- が om- に変化したもの。英語の umbilical（臍の、as in umbilical cord）と同語根であり、さらにラテン語を通じてギリシャ語 omphalos（世界の臍・中心）とも関係する。' },
  'omisión': { es: 'La omisión de ese dato clave causó un grave malentendido.', ja: 'その重要なデータを省略したことが、重大な誤解を招いた。', trivia: 'ラテン語 omissio（省略、放棄）に由来し、omittere（省く）の名詞形。英語の omission と完全に同語根であり、スペルも意味もほぼ同一の学習者に親しみやすいコグネートである。' },
  'omitir': { es: 'Decidió omitir los detalles más personales en su declaración.', ja: '彼は声明の中で最も個人的な詳細を省くことにした。', trivia: 'ラテン語 omittere（放棄する、省く）に由来し、ob-（離れて）＋ mittere（送る）の合成語。英語の omit と直接同語根で、mission（使命）や transmit（送信）などとも mittere を共有する大きな語族に属する。' },
  'onda': { es: 'Las ondas del mar golpeaban suavemente la orilla al atardecer.', ja: '夕暮れ時、海の波が静かに岸を打ち寄せていた。', trivia: 'ラテン語 unda（波）に由来する。英語の undulate（波打つ）、inundate（氾濫させる）、redundant（冗長な、元は「波が溢れる」）はすべて同語根であり、ラテン語 unda の広がりを示している。' },
  'operación': { es: 'El médico explicó con detalle los riesgos de la operación antes de proceder.', ja: '医師は手術を進める前に、そのリスクを詳しく説明した。', trivia: 'ラテン語 operatio（仕事、作業）に由来し、opus（作品、仕事）を語根とする。英語の operation と完全に同語根であり、opus、opera（歌劇）、cooperate（協力する）なども同じ語族に属する。' },
  'ostra': { es: 'En el restaurante pedimos una docena de ostras frescas para compartir.', ja: 'レストランで、みんなでシェアするために新鮮な牡蠣を1ダース注文した。', trivia: 'ラテン語 ostrea（牡蠣）、ギリシャ語 ostreon に由来し、「骨・硬いもの」を意味する語根 osteo- と関係する。英語の oyster も古フランス語を経由した同語根語であり、スペイン語とは見た目が異なる典型的なコグネートである。' },
  'otoño': { es: 'En otoño, las hojas de los árboles se tiñen de colores cálidos.', ja: '秋になると、木々の葉が暖かみのある色に染まる。', trivia: 'ラテン語 autumnus（秋）に由来し、語頭の au- が o- に変化したもの。英語の autumn は au- を保持した形で、スペイン語が変化させた経緯と対比できる典型例。なお英語の fall（秋）はゲルマン系別語源である。' },
  'otorgar': { es: 'El jurado decidió otorgar el primer premio a la joven escritora.', ja: '審査員団は若い女性作家に一等賞を授与することを決めた。', trivia: '語源については諸説あり、ラテン語 auctoricare（保証する）から来たとする説や、古プロバンサル語 autrejar を経由したとする説がある。英語の authorize や authority と同じ auctor（創始者、保証人）の語根を共有している可能性がある。' },
  'otro': { es: '¿Me puedes traer otro vaso de agua, por favor?', ja: '水をもう一杯持ってきてもらえますか？', trivia: 'ラテン語 alter（もう一方の）に由来し、al- が o- に変化したもの。英語の other はゲルマン語系の別語源（古英語 ōþer）であり、偶然意味が同じになった語根の異なる単語だが、alter ego（もう一人の自分）という表現を通じてラテン語 alter の形で英語にも残っている。' },
  'ovarios': { es: 'El médico le explicó que los ovarios producen hormonas esenciales para el organismo.', ja: '医師は、卵巣が体に不可欠なホルモンを産生すると説明した。', trivia: 'ラテン語 ovarium（卵を入れる場所）に由来し、ovum（卵）を語根とする。英語の ovary と完全に同語根であり、ovum、oval（楕円形）、ovulate（排卵する）なども同じ語族に属する。' },
  'oveja': { es: 'El pastor llevó las ovejas al prado para que pastaran.', ja: '羊飼いは羊たちを草原に連れて行き、草を食ませた。', trivia: 'ラテン語 ovicula（小さな羊）の縮小形に由来し、ovis（羊）が語根。英語の ewe（雌羊）は同じインド・ヨーロッパ語根 *owi- を共有するゲルマン語系の姉妹語で、語形は大きく異なるが遠い親戚にあたる。' },
  'ovillo': { es: 'La gata jugó toda la tarde con un ovillo de lana.', ja: '猫は午後中ずっと毛糸玉で遊んでいた。', trivia: 'ラテン語 glomellus（小さな球）、あるいは globellus に由来するとされるが語源は完全には確定していない。英語に直接の同語根語はなく、ball of yarn（毛糸玉）が相当表現となる。ただし globe（球体）と語根が近い可能性も指摘されている。' },
  'óxido': { es: 'La reja del jardín estaba cubierta de óxido por las lluvias.', ja: '庭の鉄柵は雨のせいで錆に覆われていた。', trivia: 'フランス語 oxyde を経由し、ギリシャ語 oxys（鋭い、酸っぱい）に由来する。英語の oxide と完全に同語根であり、oxygen（酸素）、oxidize（酸化する）なども同じ oxys を語根とする。なお oxygen は「酸を生む」という意味でギリシャ語が造語したものである。' },
  'oxígeno': { es: 'Las plantas producen oxígeno durante el proceso de fotosíntesis.', ja: '植物は光合成の過程で酸素を生産する。', trivia: '18世紀にフランスの化学者ラボアジエがギリシャ語 oxys（酸っぱい）＋ genes（生む）から造語した科学用語。英語の oxygen と完全に同語根・同語源の国際的科学語彙であり、当初「酸を生む元素」と誤解されて命名された経緯がある。' },
  'oyente': { es: 'Los oyentes del programa enviaron miles de mensajes de apoyo al presentador.', ja: '番組のリスナーたちは司会者に何千ものメッセージを送った。', trivia: '動詞 oír（聞く）の現在分詞 oyendo から派生した名詞・形容詞で、ラテン語 audire（聞く）に由来する。英語の audience（聴衆）、auditory（聴覚の）、audio と同語根であり、どれも「聞く」という原義を共有している。' },
  'p': { es: 'La letra p no se pronuncia en palabras como \'psicología\'.', ja: '「p」という文字は「psicología（心理学）」のような単語では発音されない。', trivia: 'ラテン語・ギリシャ語のアルファベット文字 P（pi）に由来し、フェニキア語の pe（口）が起源とされる。英語でも同じ文字 P を用い、名称は「ピー」（pee）と発音されるが、スペイン語では「ペ」（pe）と呼ぶ点が異なる。' },
  'paciencia': { es: 'Hace falta mucha paciencia para aprender a tocar el violín.', ja: 'バイオリンを弾けるようになるには、多くの忍耐が必要だ。', trivia: 'ラテン語 patientia（忍耐、受容）に由来し、patior（耐える、苦しむ）が語根。英語の patience と完全に同語根のコグネートであり、passion（情熱・受難）、patient（患者・忍耐強い）なども同じ語根に属する。' },
  'paciente': { es: 'El médico atendió a cada paciente con mucha calma y dedicación.', ja: '医師は一人一人の患者を落ち着いて丁寧に診察した。', trivia: 'ラテン語 patientem（耐える人）に由来し、paciencia と同じ語根 patior（耐える）を共有する。英語の patient と完全に同語根・同形のコグネートで、「苦しみに耐える人→患者」「忍耐強い→形容詞」という二重の意味を英語と同様に持つ。' },
  'pacífico': { es: 'Buscaba un lugar pacífico donde pudiera leer tranquilamente.', ja: '彼は静かに本が読めるような穏やかな場所を探していた。', trivia: 'ラテン語 pacificus（平和をもたらす）に由来し、pax/pacis（平和）＋ facere（作る）の合成語。英語の pacific と完全に同語根のコグネートであり、pact（協定）、appease（なだめる）なども pax を語根に持つ語族に属する。' },
  'pacto': { es: 'Los dos países firmaron un pacto de no agresión.', ja: '両国は不可侵協定に署名した。', trivia: 'ラテン語 pactum（合意、契約）に由来し、pax（平和）と同じ語根 pac- を持つ。英語の pact と完全に同語根・ほぼ同形のコグネートで、peace（平和）もラテン語 pax を経由した同語族語である。' },
  'padecer': { es: 'Muchas personas mayores padecen de soledad sin que nadie lo note.', ja: '多くの高齢者が、誰にも気づかれないまま孤独に苦しんでいる。', trivia: 'ラテン語 patescere（苦しむ）または patior（耐える、苦しむ）に由来すると考えられている。英語の passion（受難、情熱）や patient（忍耐する）と同じ語根を持ち、「受け身で苦しむ」という原義が共通している。英語では suffer に相当する。' },
  'padrino': { es: 'Su padrino le regaló un libro especial el día de su bautizo.', ja: '代父は洗礼の日に彼に特別な本を贈った。', trivia: 'ラテン語 patrinus（父方の）に由来し、padre（父）と同語根。英語の patron（後援者）、patronize（後援する）もラテン語 pater（父）を語根とする同語族語で、godfather（代父）が英語の相当語だがこちらはゲルマン系別語源である。' },
  'pagaré': { es: 'El empresario firmó un pagaré para saldar su deuda con el banco.', ja: '実業家は銀行への借金を返済するために約束手形に署名した。', trivia: '動詞 pagar（支払う）の直説法未来1人称単数形「私は支払うだろう（pagaré）」がそのまま名詞として定着したユニークな語。pagar はラテン語 pacare（宥める、満足させる）に由来し、英語の pay も同じラテン語形を古フランス語経由で受け継いだ同語根語である。' },
  'página': { es: 'Abre la página treinta y dos del libro y lee el primer párrafo.', ja: '本の32ページを開いて、最初の段落を読んでください。', trivia: 'ラテン語 pagina（ページ、板）に由来し、もともとは葡萄の蔓を格子に固定した「板」を意味した。英語の page と完全な同語源であり、スペルも意味もほぼ同じだが、スペイン語では常に女性名詞である点が異なる。' },
  'pago': { es: 'El pago del alquiler se realiza el primer día de cada mes.', ja: '家賃の支払いは毎月1日に行われる。', trivia: 'ラテン語 pacare（平和にする、債権者を満足させる）に由来し、さらに pax（平和）と関連する。英語の pay（支払う）と同語源であり、「債権者を宥める」という原義が両語に共通している。' },
  'paisaje': { es: 'El paisaje de los Pirineos en otoño es absolutamente impresionante.', ja: '秋のピレネー山脈の景色は本当に素晴らしい。', trivia: 'país（国、土地）から派生し、フランス語 paysage の影響を受けて形成された語。英語の landscape は低地ドイツ語 landschap に由来しており、語根は全く異なるが意味は同じ；英語には paisaje と直接対応する同語源語はない。' },
  'paja': { es: 'Los niños bebieron el refresco con una paja de colores.', ja: '子どもたちはカラフルなストローでジュースを飲んだ。', trivia: 'ラテン語 palea（藁、もみ殻）に由来する。英語では直接の同語源語は一般語彙にないが、pale（籠垣）や palea（植物学用語）と遠い親戚関係にある；英語の straw（麦藁・ストロー）とは語根が異なる。' },
  'paje': { es: 'En la novela histórica, el joven paje servía al rey con total dedicación.', ja: '歴史小説の中で、若い小姓は献身的に王に仕えた。', trivia: 'フランス語 page（小姓）を経由し、おそらくイタリア語 paggio またはギリシア語 paidion（少年）に遡る。英語の page（ページ/小姓）と同語源であり、意外にも「本のページ」と「小姓」は同じ語根に由来する。' },
  'palacio': { es: 'El Palacio Real de Madrid es uno de los edificios más grandes de Europa.', ja: 'マドリードの王宮はヨーロッパ最大規模の建物の一つだ。', trivia: 'ローマの七丘の一つ Palatinus（パラティヌスの丘）に由来し、皇帝アウグストゥスがそこに邸宅を構えたことから「宮殿」の意味になった。英語の palace と完全な同語源であり、さらに palatial（宮殿のような）、Palatine（パラティノ）なども同じ語根を持つ。' },
  'palanca': { es: 'Necesitas una palanca para levantar esa piedra tan pesada.', ja: 'あんな重い石を持ち上げるにはてこが必要だ。', trivia: 'ラテン語 palanga または palangca（棒、梃子）に由来し、ギリシア語 phalanx（棒・横隊）と関連するとも言われる。英語の lever（てこ）とは語根が異なるが、英語には palanca の直接の同語源語はほとんどなく、phalanx（ファランクス）が遠い親戚にあたる。' },
  'pálido': { es: 'Se puso pálido cuando le dijeron que había suspendido el examen.', ja: '試験に落ちたと告げられると、彼は青ざめた。', trivia: 'ラテン語 pallidus（青白い）に由来し、pallere（青白くなる）と関連する。英語の pale（青白い）および pallid（青ざめた）と同語源であり、pallor（蒼白）も同じ語根から来ている；三語を比べると pallid がスペイン語 pálido に最も近い形をしている。' },
  'palillo': { es: 'En ese restaurante japonés nos dieron palillos en lugar de tenedor.', ja: 'その日本料理店ではフォークの代わりに箸が出てきた。', trivia: 'palo（棒）の縮小辞 -illo が付いた形で「小さな棒」が原義。英語の pole（ポール）や pale（杭）はラテン語 palus（杭）から来ており palo と同語根；英語では chopsticks（箸）、toothpick（楊枝）と意味によって別語を使い分ける。' },
  'palma': { es: 'Llevaba el teléfono en la palma de la mano mientras caminaba.', ja: '歩きながら手のひらにスマートフォンを乗せていた。', trivia: 'ラテン語 palma（手のひら・ヤシの木）に由来し、ヤシの葉が広げた手のひらに似ていることから同じ語が両義を担った。英語の palm（手のひら・ヤシ）と完全な同語源かつ同形であり、英語でもまったく同じ二重の意味を持っている。' },
  'palo': { es: 'El niño recogió un palo del suelo y empezó a dibujar en la arena.', ja: '男の子は地面から棒を拾い、砂に絵を描き始めた。', trivia: 'ラテン語 palus（杭、棒）に由来する。英語の pole（ポール）、pale（杭・柵）と同語源であり、さらに impale（串刺しにする）も同じ語根を持つ；ただし英語の stick（棒）や club（クラブ）とは語根が異なる。' },
  'paloma': { es: 'Una paloma blanca se posó en el alféizar de la ventana.', ja: '白い鳩が窓の敷居に舞い降りた。', trivia: 'ラテン語 palumba または palumbes（野生のハト）に由来し、語源は諸説ある（灰色を意味する語根との関連が指摘される）。英語の dove や pigeon とは語根が全く異なり、英語に paloma の直接の同語源語はないが、固有名詞として英語圏でも女性名 Paloma として知られる。' },
  'palpar': { es: 'El médico palpó el abdomen del paciente para detectar anomalías.', ja: '医師は異常を調べるために患者の腹部を触診した。', trivia: 'ラテン語 palpare（触る、なでる）に由来し、もともとは「優しくたたく」という意味を持っていた。英語の palpate（触診する）と完全な同語源であり、palpable（触れることができる、明白な）も同じ語根から来ている；英語の feel とは語根が異なる。' },
  'panadería': { es: 'Compro el pan fresco en la panadería de la esquina todas las mañanas.', ja: '毎朝、角のパン屋で焼きたてのパンを買う。', trivia: 'pan（パン）＋接尾辞 -ería（〜屋）から成る派生語で、pan はラテン語 panis（パン）に由来する。英語の pantry（食料庫）、company（仲間、元は「パンを共にする者たち」）なども同じ panis が語根に含まれており、companion（仲間）の com-pan- はまさに「共にパンを食べる」を意味する。' },
  'panal': { es: 'Las abejas construyeron un panal enorme debajo del alero del tejado.', ja: '蜂たちは屋根の軒下に巨大な巣を作った。', trivia: 'ラテン語 favus（蜂の巣）ではなく、pan（パン）との関連でハニカム構造のパンのような見た目から来たとも、あるいは別の語源説もあり確定的ではない。英語の honeycomb とは語根が全く異なり、英語に panal の直接の同語源語はない；honey と pan を組み合わせた英語の発想とスペイン語の命名は対照的である。' },
  'pandilla': { es: 'La pandilla de amigos se reunió en el parque para celebrar el fin de curso.', ja: '友達グループは学年末を祝うために公園に集まった。', trivia: 'pando（広がった）またはラテン語 pandere（広げる）から派生したとされ、「群れをなして広がる」イメージが原義にある。英語の band（グループ）とは語根が異なる可能性が高く、英語の gang に意味が近いが語源は別；英語に pandilla の直接の同語源語はない。' },
  'pánico': { es: 'Cundió el pánico entre los pasajeros cuando el avión empezó a vibrar.', ja: '飛行機が揺れ始めると、乗客の間にパニックが広まった。', trivia: 'ギリシア語 panikon（パンの恐怖）に由来し、牧神パン（Pan）が突然現れて人々を恐慌させるという神話に基づく。英語の panic と完全な同語源で、スペルも発音もほぼ同じであり、英語の pandemonium（大混乱）も語感は似るが別の語根（pan「すべて」＋demon）である。' },
  'pantalla': { es: 'La pantalla de mi portátil se rompió cuando se cayó al suelo.', ja: 'ラップトップが床に落ちて画面が割れてしまった。', trivia: 'ラテン語 phantasma（幻影）またはフランス語 écran の影響を受けたとも言われるが、正確な語源は諸説あり、panto-（すべて）との関連も指摘される。英語の screen や display とは語根が全く異なり、英語に pantalla の直接の同語源語はないが、pantomime（パントマイム）の panto- と遠い関係にある可能性が指摘される。' },
  'pantalón': { es: 'Se manchó el pantalón de café y tuvo que cambiarse antes de la reunión.', ja: 'コーヒーをズボンにこぼしてしまい、会議の前に着替えなければならなかった。', trivia: 'イタリアのコメディア・デラルテの道化キャラクター「パンタローネ（Pantalone）」に由来し、彼のトレードマークの長ズボンから衣類の名称になった。英語の pants および pantaloons と完全な同語源であり、フランス語 pantalon を経由して西ヨーロッパ各語に広まった共通の借用語である。' },
  'paño': { es: 'Limpió el polvo de los muebles con un paño húmedo.', ja: '湿った布で家具のほこりを拭き取った。', trivia: 'ラテン語 pannus（布切れ、ぼろ）に由来する。英語の pane（ガラス板、格子模様の一区画）と同語源であり、いずれも「一枚の布・板」という原義を持つ；また英語の panel も同じ語根から来ており、スペイン語では布という意味が中心に残った。' },
  'pañuelo': { es: 'Se sacó un pañuelo del bolsillo y se sonó la nariz discretamente.', ja: 'ポケットからハンカチを取り出し、さりげなく鼻をかんだ。', trivia: 'paño（布）の縮小辞 -uelo が付いた形で「小さな布」が原義。英語の handkerchief とは語根が全く異なり（hand＋kerchief「頭を覆うもの」）、英語では hanky という口語形がある；スペイン語の pañuelo はシンプルに「小さな布」という命名法が興味深い。' },
  'papa': { es: 'En Perú, la papa es un ingrediente fundamental en la gastronomía tradicional.', ja: 'ペルーでは、ジャガイモは伝統料理に欠かせない食材だ。', trivia: 'ケチュア語 papa（ジャガイモ）に由来するアメリカ先住民起源の語であり、スペインによる征服後にヨーロッパに伝わった。英語の potato は別の語源（タイノ語 batata とケチュア語 papa が混合した形）から来ており、英語には papa（ジャガイモの意）の直接の同語源語はなく、日本語の「ジャガイモ」もジャガタラ（ジャカルタ）経由のオランダ語由来である。' },
  'papá': { es: 'Mi papá me enseñó a montar en bicicleta cuando tenía cinco años.', ja: '5歳のとき、お父さんが自転車の乗り方を教えてくれた。', trivia: '幼児語的な繰り返し音 pa- pa- に由来する普遍的な語であり、ラテン語 papa（幼児語で父）から来ている。英語の papa、dad とほぼ同じ感覚で使われ、フランス語 papa、イタリア語 papà と完全に同語源；幼児が発しやすい両唇音の繰り返しという人類共通のパターンを持つ語である。' },
  'papelería': { es: 'Fui a la papelería a comprar bolígrafos y cuadernos para el nuevo curso.', ja: '新学期のためにボールペンとノートを買いに文房具店へ行った。', trivia: 'papel（紙）＋接尾辞 -ería（〜屋）から成る派生語で、papel はラテン語 papyrus を経てアラビア語 babir から来たとも、直接ラテン語 papyrus から来たとも言われる。英語の paper と完全な同語源であり、両語ともにエジプトのパピルス草（Cyperus papyrus）の名前に最終的に遡る。' },
  'paquete': { es: 'Llegó un paquete a mi nombre con libros que había pedido por internet.', ja: 'ネットで注文した本が入った小包が私の名前で届いた。', trivia: 'フランス語 paquet を経由し、低地ドイツ語または中期オランダ語 pak（荷物の束）に由来するとされる。英語の packet および package と完全な同語源であり、三語はいずれも「荷を束ねたもの」という原義を共有する；英語の pack（荷造りする）も同じ語根を持つ。' },
  'par': { es: 'En el cajón encontré un par de calcetines limpios.', ja: '引き出しの中に、きれいな靴下が一足見つかった。', trivia: 'ラテン語 par（等しい、一対）に由来し、英語の pair（ペア）や parity（同等性）と同語根。形容詞として「偶数の」を意味する点は英語の even に相当し、数学用語でも共通して使われる。' },
  'parabién': { es: 'Le dimos el parabién por su ascenso en el trabajo.', ja: '私たちは彼の仕事での昇進を祝う言葉を贈った。', trivia: 'スペイン語の前置詞 para（〜のために）と bien（よいこと）が合わさった合成語で、「よいことのために（捧げる言葉）」が原義。英語には直訳できる単語がなく、congratulations や compliments に相当するが、よりフォーマルで文語的な表現。' },
  'parado': { es: 'Lleva seis meses parado y está buscando trabajo activamente.', ja: '彼は6か月間失業中で、積極的に仕事を探している。', trivia: '動詞 parar（止まる）のラテン語起源 parare（準備する、止める）に由来し、「止まった状態の」が基本義。英語の stopped や unemployed に相当するが、英語の pardon とは語根が異なる。スペインのみで「失業中」を意味する用法は独特のイベリア的発展。' },
  'paradero': { es: 'Nadie conoce el paradero del testigo desde hace semanas.', ja: '数週間前から、その証人の行方を誰も知らない。', trivia: 'parar（止まる）＋場所を示す接尾辞 -ero から成り、「人や物が最終的に止まる場所」が原義。英語の whereabouts（行方）に意味的に相当するが、語根は全く異なる。英語で言えば final destination や last known location にあたる。' },
  'paradoja': { es: 'Es una paradoja que cuanto más descansamos, más cansados nos sentimos a veces.', ja: '休めば休むほど、かえって疲れを感じることがあるというのはパラドックスだ。', trivia: 'ギリシャ語 paradoxon（para-「反して」＋doxa「意見・通念」）に由来し、ラテン語 paradoxum を経てスペイン語に入った。英語の paradox と完全に同語根の国際語で、論理学・哲学用語として多くの言語に借用されている。' },
  'parador': { es: 'Pasamos la noche en un parador nacional instalado en un castillo medieval.', ja: '私たちは中世の城を改装した国営パラドールで一夜を過ごした。', trivia: 'parar（立ち寄る、宿泊する）に場所・人を示す接尾辞 -or が付いた語で、「旅人が止まる場所」が原義。英語には直接の対応語がなく、スペイン固有の国営高級ホテルブランド Parador としてそのまま使われる。英語の inn や lodge に意味が近い。' },
  'paraguas': { es: 'Siempre llevo un paraguas en el bolso por si llueve.', ja: '雨が降った時のために、いつもバッグに傘を入れている。', trivia: 'para（防ぐ）＋ aguas（水・雨）という合成語で、「水を防ぐもの」が直訳。英語の umbrella はラテン語 umbra（影）に由来し、語源は全く異なる。スペイン語では同様の構造で parasol（日傘：太陽を防ぐ）、parabrisas（フロントガラス：風を防ぐ）なども作られている。' },
  'paraíso': { es: 'Las Maldivas es considerado un paraíso tropical para los turistas.', ja: 'モルディブは観光客にとって熱帯の楽園とみなされている。', trivia: '古代ペルシャ語 pairi-daēza（「囲まれた庭園」の意）に由来し、ギリシャ語 paradeisos、ラテン語 paradisus を経てスペイン語に入った。英語の paradise と完全に同語根・同語源で、もともとは王侯の庭園を指していた語が「天国・楽園」の意味に発展した。' },
  'paraje': { es: 'Encontramos un paraje tranquilo junto al río para descansar.', ja: '私たちは休憩するために川沿いの静かな場所を見つけた。', trivia: 'parar（止まる、滞在する）に由来し、「人が足を止めて滞在する場所」が原義。英語の spot や place に意味的に相当するが、paraje には「人里離れた自然の場所」という含意があり、英語の secluded spot がより近い訳語。英語の parish（小教区）とは無関係。' },
  'paralelo': { es: 'El proyector dibujó dos líneas paralelas en la pared blanca.', ja: 'プロジェクターが白い壁に2本の平行線を映し出した。', trivia: 'ギリシャ語 parallēlos（para-「そばに」＋allēlōn「互いに」）に由来し、ラテン語 parallelus を経てスペイン語に入った。英語の parallel と完全に同語根で、数学・地理・比喩的な用法まで両言語でほぼ同じように使われる国際的な学術語。' },
  'parálisis': { es: 'El accidente le causó una parálisis temporal en las piernas.', ja: 'その事故で彼は一時的に足が麻痺した。', trivia: 'ギリシャ語 paralusis（para-「わきに」＋luein「ほどく・解く」）に由来し、「機能が解かれた状態」が原義。英語の paralysis と完全に同語根で、医学用語として広く共有されている。英語の analysis（ana-「上から」＋lusis）とも語根 -lysis を共有する。' },
  'paralizar': { es: 'La huelga general paralizó el tráfico en toda la ciudad durante horas.', ja: 'ゼネストにより、市内全域の交通が数時間麻痺した。', trivia: 'parálisis（麻痺）から派生した動詞で、ギリシャ語 paralusis が語源。英語の paralyze と完全に同語根・同義で、医学的・比喩的どちらの文脈でも同様に使われる。英語では paralyse（英国式）と paralyze（米国式）の2つのスペルがある。' },
  'parar': { es: 'El autobús paró en la esquina y bajé corriendo.', ja: 'バスが角に止まり、私は走って降りた。', trivia: 'ラテン語 parare（準備する、整える）に由来するが、スペイン語では「止まる・止める」に意味が変化した。英語の prepare（準備する）は同じラテン語 parare と接頭辞 prae-（前に）から成り語源を共有するが、意味は大きく異なる興味深い分岐例。' },
  'parcial': { es: 'El árbitro fue parcial y no sancionó todas las faltas.', ja: '審判は偏っていて、すべての反則を罰しなかった。', trivia: 'ラテン語 partialis（pars「部分」の形容詞形）に由来し、英語の partial と完全に同語根・同義。「部分的な」と「偏った」という二つの意味も両言語で共通して持ち、中南米では「中間試験」の意味でも使われるのが特徴。' },
  'pardo': { es: 'El oso pardo habita en los bosques del norte de la península ibérica.', ja: 'ヒグマはイベリア半島北部の森林に生息している。', trivia: 'ラテン語 pardus（ヒョウ）またはギリシャ語 pardos（まだら模様の獣）に由来するという説と、ラテン語 pallidus（青白い）に由来するという説がある。英語の leopard（leop- ＋ pardus）は同語根を含み、ヒョウのまだら色からくすんだ灰褐色の意味に転じたとされる。' },
  'parecido': { es: 'Mi hermana y yo somos muy parecidos en carácter, aunque no en el físico.', ja: '姉と私は外見は似ていないが、性格はとてもよく似ている。', trivia: '動詞 parecer（似ている、思われる）の過去分詞で、ラテン語 parescere（現れる）に由来。英語の appear と同じラテン語根 parere（現れる）を共有しており、「外見・様子として現れてくる」のが原義。英語の similar や resembling に意味的に相当する。' },
  'pared': { es: 'Colgamos un cuadro grande en la pared del salón.', ja: 'リビングの壁に大きな絵を掛けた。', trivia: 'ラテン語 paries（壁）に直接由来し、英語の wall（ゲルマン語起源）とは語源が全く異なる。英語で pared に相当する語源的な単語はほとんど使われず、wall に置き換わった。ただし parietal（壁の、頭頂の）という英語学術語が同じラテン語根 paries を保存している。' },
  'pareja': { es: 'Mi pareja y yo llevamos cinco años juntos y estamos muy felices.', ja: 'パートナーと私は5年間一緒にいて、とても幸せだ。', trivia: 'ラテン語 par（等しい、一対）に由来し、par の女性形・指小形から発展した語。英語の pair（一対）と完全に同語根で、フランス語経由で英語に入った pair と共通の祖先を持つ。parity（同等性）や peer（同僚・対等な人）も同じ語根。' },
  'pariente': { es: 'Tengo muchos parientes en el extranjero con quienes apenas hablo.', ja: '海外にたくさんの親戚がいるが、ほとんど話さない。', trivia: 'ラテン語 parens（親・生んだ者）の現在分詞形 parentem に由来し、英語の parent と完全に同語根。ただし英語の parent は「親（父母）」のみを指すのに対し、スペイン語 pariente は「親戚全般」を指す点が異なる典型的なフォルスフレンズ（似て非なる語）の例。' },
  'parir': { es: 'La yegua parió un potro sano al amanecer.', ja: 'その牝馬は夜明けに健康な子馬を産んだ。', trivia: 'ラテン語 parere（生む、産む）に由来し、英語の parent（生んだ者）や viviparous（胎生の）の -par- 部分と同語根。英語では give birth to が一般的で、parir に直接対応する1語の一般動詞はないが、学術語の parturition（分娩）が同語根を保存している。' },
  'parlamento': { es: 'El proyecto de ley fue aprobado por el parlamento con amplia mayoría.', ja: 'その法案は議会で大差をもって可決された。', trivia: '古フランス語 parlement（「話し合い・議論」の意）に由来し、parler（話す）が語根。英語の parliament も同じ古フランス語から借用しており、完全に同語源。「話し合いをする場所」が原義で、ラテン語 parabola（話・言葉）にまでさかのぼる。' },
  'paro': { es: 'El gobierno anunció nuevas medidas para reducir el paro juvenil.', ja: '政府は若者の失業率を下げるための新たな措置を発表した。', trivia: '動詞 parar（止まる）の名詞形で、「活動が止まった状態」が原義。英語の stoppage や unemployment に意味的に相当するが、語根的には英語の stop（オランダ語・低地ドイツ語起源）とは全く異なる。英語の par（同等・基準）とは同形だが別語源で、これはラテン語 par（等しい）から。' },
  'párpado': { es: 'Se me hinchó el párpado derecho después de que me picara un insecto.', ja: '虫に刺されて、右のまぶたが腫れてしまった。', trivia: '語源については諸説あり、ラテン語 palpebra（まぶた）が民間語源的変化を経たとする説や、ラテン語 palpare（触れる、なでる）に由来するとする説がある。英語の eyelid は全く異なるゲルマン語起源で、学術語 palpebral（まぶたの）がラテン語根 palpebra を保存している。' },
  'parque': { es: 'Los fines de semana, mucha gente sale a pasear por el parque central.', ja: '週末には、多くの人が中央公園に散歩に出かける。', trivia: '中世ラテン語 parricus（囲い地）またはゲルマン語起源の語に由来し、フランス語 parc を経てスペイン語に入った。英語の park と完全に同語源・同語根で、「柵で囲まれた土地」が原義。駐車場を意味する parking もこの語根から派生した英語由来の外来語として現代スペイン語でも使われる。' },
  'párrafo': { es: 'El último párrafo del ensayo resume bien las ideas principales.', ja: 'そのエッセイの最後の段落は、主要なアイデアをうまくまとめている。', trivia: 'ギリシャ語 paragraphos（para-「わきに」＋graphein「書く」、段落を示すために余白に書かれた記号）に由来し、ラテン語 paragraphus を経てスペイン語に入った。英語の paragraph と完全に同語根で、paragraph の縮約・音変化形が párrafo。英語の graph（グラフ・図）も同じ graphein を語根に持つ。' },
  'parrilla': { es: 'Los domingos hacemos carne a la parrilla en el jardín con toda la familia.', ja: '日曜日は家族全員で庭でバーベキューをします。', trivia: '中世ラテン語 *peticula*（小さなペット・串）の系譜に連なるが、一般には語源は諸説あり。英語では「grill」または「barbecue grill」に相当し、英語の grill はフランス語 grille を経由したラテン語 craticula（格子）に由来する。' },
  'de parte de': { es: 'Le traigo este mensaje de parte de su jefa.', ja: '上司からのメッセージをお届けします。', trivia: 'parte はラテン語 pars / partis（部分、側）に由来し、英語の part や party と同語根。英語では「on behalf of」や「from」に相当し、英語フレーズ「on the part of」とほぼ同じ構造を持つ。' },
  'participar': { es: 'Todos los estudiantes deben participar activamente en el debate.', ja: 'すべての学生がディベートに積極的に参加しなければなりません。', trivia: 'ラテン語 participare（部分を取る）から来ており、pars（部分）と capere（取る）の合成語。英語の participate と完全に同語根であり、意味・用法もほぼ同一のコグネート。' },
  'participación': { es: 'La participación ciudadana es esencial para una democracia sana.', ja: '市民の参加は健全な民主主義に不可欠です。', trivia: 'ラテン語 participatio に由来し、英語の participation と同語根の直接コグネート。接尾辞 -ción はラテン語 -tio に対応し、英語の -tion と完全に対応する。' },
  'partícula': { es: 'Los físicos estudian el comportamiento de las partículas subatómicas.', ja: '物理学者は亜原子粒子の振る舞いを研究しています。', trivia: 'ラテン語 particula（小さな部分）の縮小辞形で、pars（部分）に由来する。英語の particle と同語根の直接コグネートであり、文法用語（助詞）としても両言語で使われる。' },
  'particular': { es: 'Este restaurante tiene un sabor particular que no encuentras en otro lugar.', ja: 'このレストランには他では見つからない独特の風味があります。', trivia: 'ラテン語 particularis（個々の部分に関する）から来ており、英語の particular と同語根の直接コグネート。ただしスペイン語では「個人の・私立の」という意味が英語より強く出る場合があり、要注意。' },
  'partida': { es: 'Jugamos una partida de ajedrez hasta las dos de la madrugada.', ja: '夜中の2時までチェスを1局指しました。', trivia: '動詞 partir（分かつ・出発する）の女性過去分詞が名詞化したもので、ラテン語 partire に由来する。英語では文脈により「game（試合の1局）」「departure（出発）」「certificate（証明書）」など複数の単語に相当し、英語の part と同語根。' },
  'partido': { es: 'El partido de fútbol entre España y Argentina fue emocionante.', ja: 'スペインとアルゼンチンのサッカーの試合はとても白熱しました。', trivia: 'ラテン語 partire（分ける）の過去分詞が名詞化したもので、元来「分かれた派閥・陣営」を意味していた。英語では「party（政党）」「match（試合）」に相当し、英語の party と同語根のコグネートだが、英語の party が「宴会」を意味するのとは異なる点に注意。' },
  'parto': { es: 'El parto fue largo, pero madre e hijo están bien de salud.', ja: 'お産は長くかかりましたが、母子ともに健康です。', trivia: 'ラテン語 partus（誕生、分娩）に由来し、parere（産む）から派生した。英語では直接の対応語は parturition（分娩、医学用語）だが、日常語としては childbirth または labor を使い、スペイン語 parto のほうが日常的に広く使われる。' },
  'pasa': { es: 'Añade un puñado de pasas al arroz con leche para darle más sabor.', ja: 'ライスプディングに干しぶどうをひとつかみ加えると風味が増します。', trivia: 'ラテン語 passa（uva passa = 干しぶどう）に由来し、動詞 passare（通す・乾燥させる）から来ている。英語では raisin（フランス語経由のラテン語 racemus = 房から）を使い、英語の pass と同語根だが「干しぶどう」の意味は英語には引き継がれていない。' },
  'pasillo': { es: 'Al final del pasillo hay una ventana que da al patio interior.', ja: '廊下の突き当たりに中庭に面した窓があります。', trivia: 'paso（通路）の縮小辞形で、ラテン語 passus（歩み、歩幅）に由来する。英語では corridor または hallway に相当し、英語の pass や passage と同語根のコグネート。' },
  'pasión': { es: 'Estudia música con tanta pasión que practica seis horas al día.', ja: '彼女は音楽を情熱的に学び、1日に6時間も練習します。', trivia: 'ラテン語 passio（受けること、苦しみ）に由来し、patior（苦しむ、受ける）から派生した。英語の passion と同語根の直接コグネートであり、「キリストの受難（The Passion）」という宗教的意味も両言語で共有している。' },
  'paso': { es: 'Da un paso adelante si quieres participar en la actividad.', ja: '活動に参加したければ一歩前に出てください。', trivia: 'ラテン語 *passus*（歩幅）から派生し、英語の pace（歩調）と同語根。英語の pass（通過する）も同じラテン語起源を共有している。' },
  'pasaje': { es: 'Compré un pasaje de tren de Madrid a Barcelona por internet.', ja: 'インターネットでマドリードからバルセロナへの列車の切符を買いました。', trivia: 'フランス語 passage を経由してラテン語 passare（通る）に由来する。英語の passage と同語根の直接コグネートだが、英語 passage は主に「通路・一節」を指し「切符」の意味は持たないため、意味のずれに注意。' },
  'pasajero': { es: 'Los pasajeros deben abrocharse el cinturón durante el despegue.', ja: '乗客は離陸中はシートベルトを着用しなければなりません。', trivia: 'pasaje（通過・旅）に接尾辞 -ero（人を表す）が付いた形で、ラテン語 passare に由来する。英語の passenger と同語根のコグネートであり、英語でも「通り過ぎる人」が原義で、現在では「乗客」が主な意味となっている。' },
  'pasado': { es: 'En el pasado, la gente viajaba a caballo de ciudad en ciudad.', ja: '昔、人々は馬に乗って町から町へと旅をしていました。', trivia: '動詞 pasar（通る・過ぎる）の過去分詞が名詞・形容詞として定着したもので、ラテン語 passare に由来する。英語の past と同語根の直接コグネートで、名詞・形容詞・時制名称として両言語で対応する用法を持つ。' },
  'pasaporte': { es: 'No olvides llevar el pasaporte cuando viajes al extranjero.', ja: '外国に旅行するときはパスポートを忘れずに持っていきましょう。', trivia: 'スペイン語 pasar（通る）と puerto（港・門）の合成語で、「港・関門を通る許可証」が原義。英語の passport も同様に pass（通る）と port（港・門）から成る完全な並行コグネートで、語構成・意味ともに一致している。' },
  'pasarla': { es: '¿Cómo la pasaste en las vacaciones? — La pasé de maravilla.', ja: '休暇はどう過ごしましたか？ — 最高でした。', trivia: '動詞 pasar に直接目的語の女性代名詞 la（「それ＝時間や状況」を指す）を付けた口語表現。英語の「to have a good/bad time」に相当し、英語の pass time（時間を過ごす）と同語根だが、代名詞を付けた慣用的形式はスペイン語独自の構造。' },
  'pasatiempo': { es: 'Hacer crucigramas es su pasatiempo favorito cuando viaja en tren.', ja: '電車に乗るときにクロスワードパズルをするのが彼のお気に入りの趣味です。', trivia: 'pasar（過ごす・通す）と tiempo（時間）の合成語で「時間を過ごすもの」が原義。英語の pastime と完全に対応するコグネートで、語構成（pass + time）も意味も一致した並行的な複合語。' },
  'pasear': { es: 'Me encanta pasear por el parque al atardecer cuando hace buen tiempo.', ja: '天気のいい夕暮れ時に公園を散歩するのが大好きです。', trivia: 'paso（歩み）から派生した動詞で、ラテン語 passus に由来する。英語では stroll や take a walk に相当するが、英語には pasear に完全に対応する一語の動詞はなく、スペイン語の語彙が豊かな分野の一つ。英語の pace と同語根。' },
  'pasivo': { es: 'No seas tan pasivo; debes expresar tu opinión con más confianza.', ja: 'そんなに受け身にならないで。もっと自信を持って自分の意見を言うべきです。', trivia: 'ラテン語 passivus（受けること）に由来し、patior（受ける・苦しむ）から派生した。英語の passive と同語根の直接コグネートで、文法用語（受動態）・心理表現・経済用語（負債）と幅広い意味で両言語が対応している。' },
  'pasmado': { es: 'Se quedó pasmado cuando le dijeron que había ganado el primer premio.', ja: '一等賞に当選したと告げられたとき、彼は呆気にとられてしまいました。', trivia: '動詞 pasmar の過去分詞で、語源はラテン語 spasmus（痙攣）またはギリシャ語 spasmos に由来するという説が有力。英語の spasm と同語根で、「痙攣するほど驚く」が原義と考えられており、英語では thunderstruck や dumbfounded に相当する。' },
  'pasmar': { es: 'La actuación de la bailarina pasmó al público entero.', ja: 'そのダンサーのパフォーマンスは観客全員を驚嘆させました。', trivia: 'ラテン語 spasmare（痙攣させる）またはギリシャ語 spasmos に由来するという説が有力で、英語の spasm と同語根とされる。英語では astound や flabbergast に相当し、スペイン語には「驚かせる」という強い感情的含意を持った動詞が豊富に存在する。' },
  'pasmo': { es: 'El mago dejó al público en un estado de pasmo total con su último truco.', ja: 'マジシャンは最後のトリックで観客を完全な呆然状態に陥れた。', trivia: 'ラテン語 *spasmus*（痙攣）に由来し、英語の spasm と同語根。スペイン語では「驚愕」の意味に発展した一方、英語の spasm は身体的な痙攣に特化した意味を保っている。' },
  'pastel': { es: 'Mi abuela preparó un pastel de chocolate para mi cumpleaños.', ja: '祖母が誕生日のためにチョコレートケーキを作ってくれた。', trivia: 'ラテン語後期の *pastellus*（パイ生地）に由来し、英語の pastry（ペイストリー）や paste（ペースト）と同語根。英語でも pastel はパステルカラーの意味で借用されている。' },
  'pastelería': { es: 'Hay una pastelería famosa en el centro que vende croissants recién hechos.', ja: '市内中心部に、焼きたてのクロワッサンを売る有名なケーキ屋がある。', trivia: 'pastel（ケーキ）に場所・職業を表す接尾辞 -ería が付いた形で、英語の pastry shop または patisserie（フランス語経由）に相当する概念。英語の patisserie もラテン語 *pasta* を共通の祖先に持つ。' },
  'pastilla': { es: 'El médico me recetó una pastilla para el dolor de cabeza.', ja: '医師が頭痛のための錠剤を処方してくれた。', trivia: 'pasto（牧草）ではなく、ラテン語 *pastillus*（小さなパン、薬丸）の縮小形に由来し、英語の pastille（トローチ剤）と同語根。英語では pastille はのど飴の意味で使われることが多い。' },
  'pastizal': { es: 'Los caballos pastaban libremente en el amplio pastizal.', ja: '馬たちが広大な牧草地で自由に草を食んでいた。', trivia: 'pasto（牧草）に「豊富な場所」を示す接尾辞 -izal が付いた形。英語の pasture（牧草地）と同語根で、共通のラテン語祖先 *pascere*（放牧する）を持つ。' },
  'pasto': { es: 'Las ovejas comen pasto fresco en el campo toda la mañana.', ja: '羊たちは午前中ずっと野原で新鮮な草を食べる。', trivia: 'ラテン語 *pastus*（飼育、食べ物）に由来し、英語の pasture（牧草地）や pastor（牧師）と同語根。英語の repast（食事、特に正式な食事）も同じ語根から来ている。' },
  'pastor': { es: 'El pastor guiaba a su rebaño de ovejas por los caminos del pueblo.', ja: '羊飼いは村の道を通って羊の群れを導いていた。', trivia: 'ラテン語 *pastor*（羊飼い）から直接借用され、英語の pastor（牧師）と完全に同語根・同形。ラテン語 *pascere*（放牧する）が共通の語根で、pastoral（田園の）も同族語。' },
  'pata': { es: 'El perro levantó la pata trasera para rascarse la oreja.', ja: '犬は後ろ足を上げて耳を掻いた。', trivia: '語源は諸説あり、擬音語的起源とする説や前ラテン語の基層語とする説がある。英語には直接の同語根語はないが、意味的には paw（動物の前足・肉球）に対応する。' },
  'patada': { es: 'El jugador dio una patada al balón y marcó un gol espectacular.', ja: '選手はボールを蹴り、見事なゴールを決めた。', trivia: 'pata（足）に行為を表す接尾辞 -ada が付いた形で「一蹴り」を意味する。英語の kick に意味的に相当するが、語源的な対応語はない。英語の pat（軽く叩く）と形が似るが、語源的なつながりは不明確。' },
  'patata': { es: 'En España, la tortilla de patatas es uno de los platos más populares.', ja: 'スペインではジャガイモのトルティージャが最も人気のある料理の一つだ。', trivia: 'タイノ語（カリブ海の先住民言語）の *batata*（サツマイモ）とケチュア語の *papa*（ジャガイモ）が混合して生まれた語とされる。英語の potato も同じタイノ語起源で、スペイン語経由で伝わった。' },
  'patente': { es: 'La empresa registró una patente para proteger su nueva tecnología.', ja: 'その会社は新技術を守るために特許を登録した。', trivia: 'ラテン語 *patens*（開いている、明らかな）の現在分詞形に由来し、英語の patent と同語根・同形。英語の patent も同様に「特許」と「明白な」の両義を持つ。' },
  'paterno': { es: 'Heredó el carácter tranquilo de su lado paterno.', ja: '彼は父方の穏やかな気質を受け継いだ。', trivia: 'ラテン語 *paternus*（父の）に由来し、英語の paternal と同語根。共通の祖先はインド・ヨーロッパ語族の *pəter-*（父）で、英語の father、ラテン語の *pater* も同系列。' },
  'patilla': { es: 'Ese actor lleva patillas largas que le dan un aspecto clásico.', ja: 'あの俳優は長いもみあげを蓄えており、クラシックな雰囲気を醸し出している。', trivia: 'pata（足・脚）の縮小形 patilla から派生し、顔の横を「脚のように」伸びる毛という発想。英語では sideburns（サイドバーンズ）と言い、南北戦争の将軍 Ambrose Burnside の名に由来するまったく異なる語。' },
  'patinar': { es: 'A los niños les encanta patinar sobre hielo en invierno.', ja: '子供たちは冬にアイススケートをするのが大好きだ。', trivia: 'patín（スケート靴）に動詞語尾 -ar が付いた形で、patín はラテン語 *patta*（足）が起源とも、フランス語 *patin* からの借用とも言われる。英語の skate とは語源が異なり、英語は北ゲルマン語 *skati* に由来する。' },
  'patio': { es: 'La familia se reúne en el patio a cenar cuando hace buen tiempo.', ja: '天気がいい日は家族が中庭に集まって夕食をとる。', trivia: '語源は諸説あるが、ゴート語やラテン語 *spatium* に由来するとも言われる。英語でも patio としてスペイン語からそのまま借用されており、特に屋外テラス・中庭を指す言葉として広く使われている。' },
  'patria': { es: 'Los soldados lucharon valientemente para defender su patria.', ja: '兵士たちは祖国を守るために勇敢に戦った。', trivia: 'ラテン語 *patria*（父の地）に由来し、*pater*（父）が語根。英語の patriot（愛国者）、patriotic、expatriate と同語根で、インド・ヨーロッパ語族の *pəter-*（父）まで遡ることができる。' },
  'patrimonio': { es: 'El casco antiguo de la ciudad fue declarado Patrimonio de la Humanidad.', ja: 'その都市の旧市街が世界遺産に登録された。', trivia: 'ラテン語 *patrimonium*（父から受け継いだ財産）に由来し、*pater*（父）が語根。英語の patrimony（父から受け継いだ遺産）と同語根・ほぼ同形で、英語の matrimony（結婚）の対義語的な構造を持つ。' },
  'patrocinar': { es: 'Una empresa de telecomunicaciones decidió patrocinar el torneo de fútbol.', ja: 'ある通信会社がサッカートーナメントのスポンサーになることを決めた。', trivia: 'ラテン語 *patronus*（保護者、パトロン）に由来し、英語の patronize（後援する、常連として通う）と同語根。英語の patron（常連客、後援者）も同系で、共通の祖先はラテン語 *pater*（父）。' },
  'patrocinio': { es: 'El evento cultural contó con el patrocinio de varias empresas locales.', ja: 'その文化イベントはいくつかの地元企業のスポンサーシップを受けた。', trivia: 'patrocinar（後援する）の名詞形で、英語の patronage（後援、ひいき）と同語根。英語では sponsorship の方が一般的だが、patronage も同義で使われ、どちらもラテン語 *pater*（父）に行き着く。' },
  'patrón': { es: 'El patrón del barco tenía veinte años de experiencia en alta mar.', ja: 'その船の船長は外洋での航行に二十年の経験を持っていた。', trivia: 'ラテン語 *patronus*（保護者）に由来し、英語の patron（後援者）と同語根。英語の pattern（型、パターン）もフランス語経由で同じラテン語起源を持つ興味深い同族語で、「模範となる人」という概念から「型紙」へと意味が発展した。' },
  'patrulla': { es: 'La patrulla de policía recorrió el barrio toda la noche sin incidentes.', ja: '警察のパトロール隊は何事もなく一晩中その地区を巡回した。', trivia: 'フランス語 *patrouille*（泥の中を歩き回ること）に由来し、古フランス語 *patouiller*（水の中を踏む）が語源とされる。英語の patrol も同じフランス語から借用されており、スペイン語と英語は共通の借用元を持つ。' },
  'pauta': { es: 'El profesor estableció las pautas del trabajo final antes de que comenzara el semestre.', ja: '教授は学期が始まる前に期末課題の指針を定めた。', trivia: 'ラテン語 pacta（合意、取り決め）またはゲルマン語系の語に由来するとされるが語源は諸説ある。英語の guideline や standard に相当し、英語の pact（協定）と同語根という説もある。音楽用語「五線譜」としての用法は独自の意味拡張。' },
  'pausa': { es: 'Hagamos una pausa de diez minutos antes de continuar con la reunión.', ja: '会議を続ける前に十分間休憩しましょう。', trivia: 'ラテン語 *pausa*（停止）を経てギリシャ語 *pausis*（停止）に由来し、英語の pause と完全に同語根・同形。両言語ともラテン語から直接受け継いでいるため、発音も意味もほぼ同じという珍しい例。' },
  'pausado': { es: 'El profesor habla de manera pausada para que todos los estudiantes puedan seguirle.', ja: '教師はすべての生徒がついていけるようにゆっくりとした話し方をする。', trivia: 'pausa（休止）の過去分詞形・形容詞で、「間を置いた→ゆっくりとした」という意味に発展。英語の paused（一時停止した）と同語根だが、英語では形容詞として「落ち着いた話し方」を表す用法はなく、スペイン語独自の意味的発展が見られる。' },
  'pavor': { es: 'Sintió un pavor inexplicable al escuchar los pasos en el pasillo oscuro.', ja: '暗い廊下で足音を聞いたとき、説明のつかない恐怖を感じた。', trivia: 'ラテン語 pavor（恐怖、おびえ）に由来し、pavere（おびえる、震える）から派生。英語の fear や dread に相当するが、英語の pavid（臆病な、廃語）が同語根。現代英語では直接の対応語はほぼ使われず、terror や dread が近い。' },
  'payaso': { es: 'Los niños se rieron mucho con el payaso que actuó en la fiesta de cumpleaños.', ja: '誕生日パーティーで演じたピエロに、子どもたちは大笑いした。', trivia: '語源については諸説あり、イタリア語 pagliaccio（道化師、わら）から来たとする説や、スペイン語 país（地方）と関連するとする説がある。英語では clown または jester に相当し、英語の「clown」は北欧語起源で語根は異なる。' },
  'peaje': { es: 'Tuvimos que parar en el peaje para pagar antes de entrar en la autopista.', ja: '高速道路に入る前に料金所で止まって支払いをしなければならなかった。', trivia: 'ラテン語 pedagium（通行税）に由来し、ラテン語 pes/pedis（足）が語根。同じ語根から英語の pedestrian（歩行者）や英語の toll road という概念と対応し、英語では「toll」に相当する。' },
  'peatón': { es: 'Los peatones deben cruzar la calle solo cuando el semáforo esté en verde.', ja: '歩行者は信号が青のときだけ道路を渡らなければならない。', trivia: 'ラテン語 pes/pedis（足）を語根とし、フランス語 piéton を経由してスペイン語に入った。英語の pedestrian と同語根で、どちらも「足で歩く人」を意味し、英語では pedestrian または walker に相当する。' },
  'peca': { es: 'Tiene pecas en la nariz y en las mejillas que le dan un aspecto muy tierno.', ja: '鼻とほほにそばかすがあって、とてもかわいらしい印象を与える。', trivia: '語源は不明確だが、ラテン語 pica（カササギ、斑点）との関連が指摘されることがある。英語では freckle に相当し、英語の freckle は古ノルド語 freknur（そばかす）に由来するため語根は全く異なる。' },
  'pecado': { es: 'En muchas religiones, el orgullo excesivo se considera un pecado capital.', ja: '多くの宗教において、過度な傲慢さは大罪とみなされる。', trivia: 'ラテン語 peccatum（罪、過失）に由来し、動詞 peccare（過ちを犯す）から派生した。英語の sin とは語根が異なるが、同語源の英語 impeccable（非の打ち所がない、sin が不可能な）と同語根で、英語の「sin」に相当する。' },
  'pecador': { es: 'El predicador llamaba pecadores a todos los que no seguían los mandamientos.', ja: 'その説教師は戒律に従わない者全員を罪人と呼んでいた。', trivia: 'ラテン語 peccator（罪を犯す者）に由来し、peccare（過ちを犯す）と共通の語根を持つ。英語では sinner に相当し、英語の impeccable（欠点のない）とも同語根で、「罪を犯すことのできない」という原義を持つ。' },
  'pecar': { es: 'El chef dijo que prefería pecar de exceso antes que servir porciones insuficientes.', ja: 'シェフは量が足りないよりも多すぎるほうがましだと言った。', trivia: 'ラテン語 peccare（過ちを犯す、つまずく）に由来する。英語には直接の同語根語はないが、英語の impeccable（欠点のない）が同語根であり、「〜に偏りすぎる」という用法（pecar de + 形容詞）はスペイン語独自の慣用表現である。' },
  'pece': { es: 'En los textos antiguos, a veces se encontraba la palabra pece en lugar de pez.', ja: '古い文書では、pez の代わりに pece という語が見られることがある。', trivia: 'ラテン語 piscis（魚）に由来する古形・方言形で、現代標準スペイン語では pez が使われる。英語の fish とは語根が異なるが、英語の Pisces（魚座）や piscine（魚の）と同語根であり、英語では fish に相当する。' },
  'pecera': { es: 'Mi hermana tiene una pecera con varios peces de colores en su habitación.', ja: '姉の部屋には色とりどりの魚が入った金魚鉢がある。', trivia: 'pez（魚）にラテン語由来の場所を示す接尾辞 -era を加えた語で、「魚を入れる容器」が原義。英語の fish tank または aquarium に相当し、英語の Pisces と同語根の pez から派生しており、fish（英）とは語根が異なる。' },
  'pecho': { es: 'El nadador respiró profundamente y se lanzó al agua con el pecho bien abierto.', ja: 'その水泳選手は深く息を吸い、胸を大きく張って水に飛び込んだ。', trivia: 'ラテン語 pectus/pectoris（胸、心）に由来し、英語の pectoral（胸の、胸筋）と同語根。英語では chest または breast に相当し、英語の「pectoral muscles（大胸筋）」という解剖学用語に同語根の形が残っている。' },
  'peculiar': { es: 'Tiene un sentido del humor bastante peculiar que no todo el mundo entiende.', ja: '彼は誰もが理解できるわけではない、かなり独特のユーモアセンスを持っている。', trivia: 'ラテン語 peculiaris（個人の財産に関する、私有の）に由来し、pecus（家畜）が語源で「自分の家畜＝私有財産」が原義。英語の peculiar と完全に同語源の同形語（コグネート）で、両言語ともに「独特の、変わった」という意味で使われる。' },
  'pedazo': { es: 'Se le cayó el plato al suelo y se rompió en pedazos.', ja: 'お皿が床に落ちて粉々に割れた。', trivia: 'ラテン語 petium（切れ端、断片）またはラテン語 petiare（切る）に由来するとされる。英語の piece とは諸説あるが語根が近く、古フランス語 piece を経由した英語の piece と同系統とみる説もある。英語では piece または fragment に相当する。' },
  'pedrada': { es: 'La ventana se rompió de una pedrada que lanzó un niño jugando en la calle.', ja: '通りで遊んでいた子どもが投げた石で窓ガラスが割れた。', trivia: 'ラテン語 petra（岩、石）に由来する piedra（石）から派生した語で、「石を投げる行為またはその結果」を指す。英語の petrify（石化する）や petroleum（石油、文字通り「岩の油」）と同語根であり、英語には pedrada に相当する単純な一語はなく「throwing a stone」などと表現する。' },
  'pedido': { es: 'El pedido que hice por internet llegó antes de lo esperado.', ja: 'インターネットで注文した品が予想より早く届いた。', trivia: '動詞 pedir（求める、注文する）の過去分詞が名詞化した語で、ラテン語 petere（求める、向かう）に由来する。英語の petition（請願）や compete（競争する、共に求める）と同語根であり、英語では order または request に相当する。' },
  'pedregoso': { es: 'El camino hacia la cima era muy pedregoso y tuvimos que ir con cuidado.', ja: '頂上までの道はとても石だらけで、慎重に進まなければならなかった。', trivia: 'ラテン語 petra（岩、石）に由来する piedra（石）から形成された形容詞で、接尾辞 -oso は「〜に満ちた」を意味する。英語の petrify（石化する）や Peter（ペテロ、「岩」を意味するギリシャ語由来）と同語根であり、英語では rocky または stony に相当する。' },
  'pegar': { es: '¿Me puedes ayudar a pegar estas fotos en el álbum?', ja: 'このアルバムに写真を貼るのを手伝ってもらえますか？', trivia: 'ラテン語 picare（ピッチで接着する）に由来し、pix/picis（松ヤニ、ピッチ）が語源。英語の pitch（音楽のピッチではなく、タールの意味の pitch）と同語根であり、英語では文脈により to stick、to hit、to glue などに相当する多義語である。' },
  'pegamento': { es: 'El niño usó pegamento para unir las piezas del modelo de avión.', ja: '男の子は飛行機の模型のパーツをつなぐために接着剤を使った。', trivia: 'pegar（貼る、接着する）から派生した名詞で、ラテン語 picare（ピッチで接着する）が語源。英語では glue または adhesive に相当し、英語の pitch（タール、松ヤニ）と同語根だが、英語の glue はラテン語 gluten（膠）に由来するため語根は全く異なる。' },
  'pegajoso': { es: 'Después de comer caramelos, tenía los dedos pegajosos.', ja: 'キャラメルを食べた後、指がベタベタになっていた。', trivia: 'pegar（貼る）から派生した形容詞で、ラテン語 picare（ピッチで接着する）が語源。英語の sticky または catchy に相当し、「耳に残るメロディー」という意味でも使われるが、英語の sticky はゲルマン語系の stick に由来するため語根は異なる。' },
  'peinado': { es: 'Fue a la peluquería para hacerse un peinado especial para la boda.', ja: '結婚式のために特別なヘアスタイルを作ってもらいに美容院へ行った。', trivia: '動詞 peinar（髪をとかす）の過去分詞が名詞・形容詞化した語で、ラテン語 pecten/pectinis（くし）に由来する。英語の pectinate（くし歯状の）と同語根であり、英語では hairstyle または hairdo に相当するが、英語に同語根の日常語はほとんど残っていない。' },
  'peinar': { es: 'Todas las mañanas se peina frente al espejo antes de salir de casa.', ja: '毎朝、家を出る前に鏡の前で髪をとかしている。', trivia: 'ラテン語 pectinare（くしでとかす）に由来し、pecten（くし）が語源。英語の pectinate（くし歯状の）と同語根であり、英語では to comb または to brush one\'s hair に相当するが、英語の comb はゲルマン語系に由来するため語根は全く異なる。' },
  'peine': { es: 'Siempre lleva un peine en el bolsillo para arreglarse el pelo en cualquier momento.', ja: 'いつでも髪を整えられるよう、常にポケットにくしを持ち歩いている。', trivia: 'ラテン語 pecten/pectinis（くし）に由来し、英語の pectinate（くし歯状の）と同語根。英語では comb に相当するが、英語の comb は古英語 camb（古ゲルマン語起源）に由来するため語根は全く異なり、典型的な語彙の平行発展例として興味深い。' },
  'pelar': { es: 'Por favor, pela las patatas antes de echarlas a la olla.', ja: '鍋に入れる前にじゃがいもの皮をむいてください。', trivia: 'ラテン語 pilare（毛を取る、毛をむしる）に由来し、pilus（毛）が語源。英語の depilatory（除毛剤）や pile（毛羽）と同語根であり、英語では to peel（皮をむく）に相当するが、英語の peel は古フランス語 peler 経由で実は同語根（ラテン語 pilare）に遡ることができる近縁語である。' },
  'peldaño': { es: 'El niño subió los peldaños de la escalera de uno en uno.', ja: 'その子は階段の段を一段一段上っていった。', trivia: '語源については諸説あり明確ではないが、ラテン語 gradus（段、歩み）または perlatanu からの変形とする説がある。英語では step または rung（はしごの横棒）に相当し、英語の step はゲルマン語系、rung も古英語 hrung に由来するため語根は異なる。' },
  'pelea': { es: 'Los dos hermanos tuvieron una pelea por el mando a distancia del televisor.', ja: '二人の兄弟はテレビのリモコンをめぐって喧嘩した。', trivia: '動詞 pelear（戦う、喧嘩する）から派生した名詞で、pelear はラテン語 pilare（毛をむしる＝つかみ合う）に由来するとも、ゲルマン語起源とも言われ語源には諸説ある。英語では fight または quarrel に相当し、英語の fight は古英語 feohtan（ゲルマン語系）に由来するため語根は異なる。' },
  'pelear': { es: 'Los dos hermanos pelean constantemente por el mando del televisor.', ja: 'その二人の兄弟はテレビのリモコンをめぐっていつも喧嘩している。', trivia: 'ラテン語の pilus（毛）に由来するという説と、古フランス語 pelee（毛をむしり合う争い）から派生したという説がある。英語の fight とは語根が異なるが、口語的な「取っ組み合い」のニュアンスが近い。' },
  'película': { es: 'Ayer vimos una película de terror que nos dejó sin dormir.', ja: '昨日、怖くて眠れなくなるようなホラー映画を見た。', trivia: 'ラテン語 pellicula（小さな皮・薄膜）に由来し、英語の film と同様に「薄い膜」→「映画フィルム」→「映画」と意味が転じた。英語では film または movie に相当するが、英語にも pelicle（薄膜）という専門語が同語源で存在する。' },
  'peligro': { es: 'El cartel advertía que había peligro de avalanchas en esa zona de montaña.', ja: 'その看板は、その山岳地帯では雪崩の危険があると警告していた。', trivia: 'ラテン語 periculum（試み・危険）に由来し、英語の peril（危険）と同語根である。英語の danger はフランク語系の別語源だが、peligro と danger はほぼ同義で使われる。' },
  'peligroso': { es: 'Es peligroso cruzar la calle sin mirar a ambos lados.', ja: '両側を見ずに道路を横断するのは危険だ。', trivia: 'peligro（危険）に形容詞語尾 -oso を付けた派生語で、英語の perilous（危険な）と同語根。英語の dangerous はフランス語 dangereux 由来で語源が異なるが、意味的には peligroso の対応語として使われる。' },
  'pelota': { es: 'Los niños jugaban a la pelota en el parque después del colegio.', ja: '子どもたちは放課後に公園でボール遊びをしていた。', trivia: '古フランス語 pelote（毛糸玉・小さな球）またはラテン語 pila（球）に由来するとされる。英語の pellet（小さな丸い塊）と同語根と考えられており、スポーツ用語としてバスク地方の球技「ペロタ」としても英語に借用されている。' },
  'peluca': { es: 'El actor llevaba una peluca rubia para interpretar a ese personaje histórico.', ja: 'その俳優はその歴史的人物を演じるために金髪のかつらをつけていた。', trivia: 'フランス語 perruque（かつら）が変化したもので、英語の periwig や wig も同じフランス語源に由来する。英語の wig はもともと periwig の短縮形であり、peluca・periwig・wig は同じ祖先を持つ兄弟語である。' },
  'peluquero': { es: 'Mi peluquero me recomendó un nuevo champú para el cabello seco.', ja: '私の美容師が乾燥した髪向けの新しいシャンプーを勧めてくれた。', trivia: 'peluca（かつら）から派生した語で、もともとはかつら職人を指したが、のちに理容師・美容師全般を指すようになった。英語では hairdresser または barber に相当し、英語に直接対応する同語根語は存在しない。' },
  'pelusa': { es: 'Encontré mucha pelusa debajo del sofá cuando lo moví para limpiar.', ja: '掃除のためにソファを動かしたら、下にたくさんの綿埃が溜まっていた。', trivia: 'pelo（毛・髪）の指小派生語で、「細かい毛」→「産毛」→「綿埃」と意味が広がった。英語の fluff や lint に相当するが、直接の同語根英単語はない。口語で「焼きもち」を意味する用法はスペイン語特有の表現である。' },
  'pena': { es: 'Me da mucha pena que no puedas venir a la fiesta de cumpleaños.', ja: '誕生日パーティーに来られないのは本当に残念だ。', trivia: 'ラテン語 poena（罰・苦痛）に由来し、英語の pain（痛み）や penalty（刑罰）と同語根である。英語の pity（気の毒）とは語源が異なるが、¡Qué pena!（何て残念！）は英語の What a pity! にほぼ対応する慣用表現である。' },
  'penal': { es: 'El jugador cometió una falta dentro del área y el árbitro pitó penal.', ja: '選手がペナルティエリア内でファウルをし、審判はペナルティキックを宣告した。', trivia: 'ラテン語 poenalis（刑罰に関する）に由来し、英語の penal（刑罰の）と完全に同語根の借用語である。英語でも penal code（刑法典）、penal colony（流刑地）のように使われ、両語の形・意味は非常に近い。' },
  'penalidad': { es: 'Los migrantes sufrieron grandes penalidades durante su largo viaje hacia el norte.', ja: '移民たちは北へ向かう長い旅の間、多くの苦難を経験した。', trivia: 'ラテン語 poena（罰）に由来し、英語の penalty や penalize と同語根である。英語の penality という語は存在しないが、penalidad は penalty（罰則）と hardship（苦難）の両方の意味を兼ねるスペイン語特有のニュアンスを持つ。' },
  'penalti': { es: 'El delantero falló el penalti en el último minuto del partido.', ja: 'フォワードは試合の最終分にペナルティキックを外した。', trivia: '英語の penalty をスペイン語の音韻体系に合わせて取り込んだ借用語で、スペインでは penalti、中南米では penal やペネル(pénele)などと呼ばれることもある。英語の penalty 自体はラテン語 poena（罰）由来であり、pena と同語根である。' },
  'penar': { es: 'Ella penó mucho tiempo por la pérdida de su madre.', ja: '彼女は母の死を長い間悲しみ続けた。', trivia: 'ラテン語 poenare（罰する）に由来し、英語の pain（苦痛）・penalize（罰する）と同語根である。英語では「苦しむ」に対応する直接の同語根動詞は廃れており、現代英語では suffer や grieve に相当する。' },
  'pendencia': { es: 'Ese bar tiene fama de ser lugar de pendencias los fines de semana.', ja: 'そのバーは週末に喧嘩が起きることで有名だ。', trivia: 'ラテン語 pendere（ぶら下がる・未決である）に由来し、英語の pending（未決の）や pendency（係属）と同語根である。法律用語の「係属中（pendencia）」と「喧嘩・いさかい」という二つの意味を持つ点がスペイン語特有の意味拡張である。' },
  'tendencia': { es: 'Hay una tendencia creciente a trabajar desde casa entre los jóvenes profesionales.', ja: '若いビジネスパーソンの間で在宅勤務をする傾向が高まっている。', trivia: 'ラテン語 tendere（伸ばす・向かう）に由来し、英語の tendency と完全に同語根の国際語である。英語の tend（〜する傾向がある）、tension（緊張）、extend（伸ばす）なども同じラテン語根を持つ。' },
  'pender': { es: 'Una lámpara antigua pendía del techo de la vieja mansión.', ja: '古い屋敷の天井から古めかしいランプがぶら下がっていた。', trivia: 'ラテン語 pendere（ぶら下がる）に由来し、英語の pend（係属する）、pendant（ペンダント）、depend（依存する）、suspend（吊るす）と同語根である。英語の hang とは語根が異なるが、物理的に「垂れ下がる」という意味では対応する。' },
  'pendiente': { es: 'Todavía tengo varios asuntos pendientes que resolver antes de irme de vacaciones.', ja: '休暇に出発する前に、まだいくつかの未解決事項を片付けなければならない。', trivia: 'ラテン語 pendentem（ぶら下がっている）の現在分詞形に由来し、英語の pending（未決の）と同語根かつ同意の語である。「イヤリング」の意味は「ぶら下がるもの」という原義から来ており、英語の pendant（ペンダント）も同じ発想の語である。' },
  'penetración': { es: 'La penetración de los teléfonos inteligentes en el mercado rural ha sido muy rápida.', ja: '農村市場へのスマートフォンの普及は非常に速かった。', trivia: 'ラテン語 penetrare（奥深く入る）の名詞形 penetratio に由来し、英語の penetration と形・意味ともにほぼ同一の同語根語である。語根の pene- はラテン語で「奥・内部」を意味し、英語の peninsula（半島、pene-「ほぼ」+ insula「島」）にも同じ要素が見られる。' },
  'penetrar': { es: 'La humedad penetró en las paredes del sótano durante las lluvias.', ja: '雨の間、湿気が地下室の壁に染み込んだ。', trivia: 'ラテン語 penetrare（奥深く入る）に由来し、英語の penetrate と完全に同語根の国際語である。科学・医学・軍事など幅広い分野で英語の penetrate と同様に使われ、形容詞 penetrante（鋭い・刺すような）も英語の penetrating と対応する。' },
  'penitencia': { es: 'Como penitencia, el sacerdote le pidió que rezara tres oraciones.', ja: '神父は贖罪として3つの祈りを唱えるよう彼に求めた。', trivia: 'ラテン語 paenitentia（後悔・悔い改め）に由来し、英語の penitence（悔悟）および penitentiary（懲役刑務所）と同語根である。英語の penitent（悔い改めた人）もこの語群に属し、すべてラテン語 paenitere（後悔する）を語源とする。' },
  'penoso': { es: 'Fue penoso ver cómo el equipo perdió el partido en los últimos segundos.', ja: 'チームが最後の数秒で試合を落とすのを見るのは痛ましかった。', trivia: 'pena（苦痛・悲しみ）に形容詞語尾 -oso を付けた語で、英語の painful（痛ましい）と概念的に対応する。ただし英語の painful の語根 pain はラテン語 poena 由来で pena と同語根であるため、penoso と painful は遠い同語根語と言える。' },
  'pensamiento': { es: 'El libro explora los pensamientos más profundos de un filósofo medieval.', ja: 'その本は中世の哲学者の最も深い思想を探求している。', trivia: 'ラテン語 pensare（重さを量る・考える）に由来し、英語の pensive（物思いに沈んだ）と同語根である。英語の thought（考え）はゲルマン語系で語根が全く異なるが、英語の pensieve（ハリー・ポッターの「憂いの篩」）はこの語根からの造語である。' },
  'pensativo': { es: 'Se quedó pensativo durante varios minutos antes de responder a la pregunta.', ja: '彼は質問に答える前に数分間、考え込んでいた。', trivia: 'ラテン語 pensare（考える）に由来し、英語の pensive（物思いに沈んだ）と同語根かつ同意の語である。英語の pensive はフランス語 pensif を経由して英語に入っており、pensativo・pensive は共通のラテン語祖先を持つ。' },
  'penumbra': { es: 'La habitación estaba en penumbra y apenas se podían distinguir los muebles.', ja: '部屋は薄暗く、家具がかろうじて見分けられる程度だった。', trivia: 'ラテン語 paene（ほぼ・半分）と umbra（影）を組み合わせた造語で、英語の penumbra と完全に同形・同義の国際語である。天文学用語として「半影」を意味し、英語でも同じ penumbra が使われる。英語の umbrella（傘）も umbra と同語根である。' },
  'pepino': { es: 'Añadí pepino y tomate a la ensalada para que quedara más fresca.', ja: 'サラダをよりさっぱりさせるためにキュウリとトマトを加えた。', trivia: 'ラテン語 pepo（メロン・大きな瓜）に由来し、英語の pepo（植物学でウリ科の果実の総称）と同語根である。英語でキュウリは cucumber と呼ばれ語根が全く異なるが、スペイン語の口語表現「me importa un pepino（キュウリ一本ほどもどうでもいい）」は英語の I don\'t give a fig に相当する慣用表現である。' },
  'pepita': { es: 'Los niños sacaron las pepitas de la sandía antes de comerla.', ja: '子供たちはスイカを食べる前に種を取り出した。', trivia: 'ラテン語 *pipa*（種）に由来するとされ、スペイン語独自の縮小辞 -ita が付いた形。英語の "pip"（果物の種）と同語根で、英語でも小さな種を pip と呼ぶ。' },
  'pera': { es: 'Me comí una pera madura después del almuerzo.', ja: '昼食の後、熟した洋ナシを一つ食べた。', trivia: 'ラテン語 *pira*（pirus「洋ナシの木」の複数形）に由来し、英語の "pear" と同語根。ゲルマン語を経由して英語に入ったが、語形は異なる。' },
  'percance': { es: 'Llegué tarde a la reunión por un pequeño percance en el camino.', ja: '途中で小さなトラブルがあって、会議に遅刻してしまった。', trivia: '接頭辞 per-（通じて）と cance（機会・運）を合わせたスペイン語固有の語で、ラテン語 *per* + *cadere*（落ちる）に関連するとされる。英語には直接の対応語がなく、"mishap" や "setback" が近い表現となる。' },
  'percibir': { es: 'Percibo un ligero olor a gas en la cocina.', ja: '台所でかすかなガスの匂いに気づく。', trivia: 'ラテン語 *percipere*（完全に掴む）に由来し、英語の "perceive" と完全な同語根。per-（完全に）+ capere（掴む）の構成で、英語の "receive"（re- + capere）とも語根を共有する。' },
  'percha': { es: 'Cuelga el abrigo en la percha antes de entrar al salón.', ja: '居間に入る前にコート掛けにコートを掛けてください。', trivia: '古フランス語 *perche*（棒・竿）を経てラテン語 *pertica*（棒・物差し）に由来する。英語の "perch"（止まり木、また魚のパーチ）と同語根で、どちらも「横に渡した棒」という原義から広がった。' },
  'perdición': { es: 'El juego fue su perdición y acabó arruinándose.', ja: 'ギャンブルが彼の破滅のもとになり、最終的に身を滅ぼした。', trivia: 'ラテン語 *perditio*（喪失・破滅）に由来し、*perdere*（失う・滅ぼす）から派生。英語の "perdition"（地獄への落下・破滅）と完全な同語根で、宗教的な文脈では英語でも同じ単語が使われる。' },
  'pérdida': { es: 'La empresa sufrió grandes pérdidas durante la crisis económica.', ja: 'その企業は経済危機の間に大きな損失を被った。', trivia: 'ラテン語 *perdita*（*perdere*「失う」の過去分詞形）に由来する。英語の "loss" とは語根が異なるが意味は近く、英語では "perdition" や "perdurable" などに同じラテン語語根 *perdere* の痕跡が見られる。' },
  'perdido': { es: 'Estaba completamente perdido en aquella ciudad que no conocía.', ja: '知らない街で完全に道に迷っていた。', trivia: 'ラテン語 *perditus*（*perdere*「失う・滅ぼす」の過去分詞）に由来する。英語の "lost" とは語根が異なるが意味は同じで、英語では "desperate" に通じる "perdido" という語がそのまま使われることもある。' },
  'perdón': { es: 'Le pedí perdón por haber llegado tarde a su fiesta.', ja: '彼のパーティーに遅刻したことを謝った。', trivia: 'ラテン語 *perdonare*（完全に与える・許す）に由来し、per-（完全に）+ donare（贈る）の構成。英語の "pardon" と同語根で、フランス語 *pardon* を経由して英語に入った兄弟語でもある。' },
  'perdonar': { es: 'Es difícil perdonar a quien te ha traicionado.', ja: '自分を裏切った人を許すのは難しい。', trivia: 'ラテン語 *perdonare*（完全に与える）に由来し、per-（完全に）+ donare（贈る・許す）から成る。英語の "pardon" と同語根であり、英語の "forgive" はゲルマン語系で語根は異なるが同じ概念を表す。' },
  'perdurar': { es: 'El recuerdo de ese viaje perdurará en mi memoria para siempre.', ja: 'あの旅の思い出は永遠に記憶の中に残り続けるだろう。', trivia: 'ラテン語 *perdurare*（完全に持続する）に由来し、per-（完全に・通じて）+ durare（持続する）の構成。英語の "endure" や "durable" と同じ語根 *durare* を共有しており、"perdure" という語が英語の古語・詩語として存在する。' },
  'perecedero': { es: 'Los alimentos perecederos deben conservarse en el frigorífico.', ja: '傷みやすい食品は冷蔵庫で保存しなければならない。', trivia: '動詞 *perecer*（滅びる）に形容詞接尾辞 -dero を付けた語で、ラテン語 *perire*（滅びる）に由来する。英語の "perishable" と完全な同語根・同義語で、どちらも「滅びうる・腐りやすい」という意味を持つ。' },
  'perecer': { es: 'Varios marineros perecieron en la tormenta.', ja: '嵐で数人の船乗りが命を落とした。', trivia: 'ラテン語 *perire*（完全に行ってしまう→滅びる）に由来し、per-（完全に）+ ire（行く）の構成。英語の "perish" と同語根で、どちらも「死ぬ・滅びる」という意味を持つフォーマルな表現として使われる。' },
  'peregrino': { es: 'Miles de peregrinos caminan cada año el Camino de Santiago.', ja: '毎年何千人もの巡礼者がサンティアゴの道を歩く。', trivia: 'ラテン語 *peregrinus*（外国人・旅人）に由来し、per-（通じて）+ ager（土地・畑）の構成で「土地を渡り歩く者」が原義。英語の "pilgrim" は同じラテン語から古フランス語 *pelerin* を経由して変化した形で、語根は同じだが語形が大きく異なる。' },
  'pereza': { es: 'La pereza no te dejará alcanzar tus metas.', ja: '怠惰ではあなたの目標を達成できないだろう。', trivia: '語源については諸説あり、ラテン語 *pigritia*（怠惰）が変化した可能性があるが確定していない。英語の "laziness" とは語根が異なり、英語で同系の語は見当たらない。スペイン語の七つの大罪の一つ *pereza*（怠惰）として文化的に定着している。' },
  'perezoso': { es: 'El perezoso pasa la mayor parte de su vida colgado en los árboles.', ja: 'ナマケモノは生涯の大半を木にぶら下がって過ごす。', trivia: '形容詞 *pereza*（怠惰）に接尾辞 -oso（〜に満ちた）を加えた語。英語では動物の"sloth"（怠惰・ナマケモノ）が同様に抽象名詞と動物名を兼ねており、「怠け者→ゆっくり動く動物」という命名の発想が英西で一致している。' },
  'perfección': { es: 'Nadie puede alcanzar la perfección absoluta en todo lo que hace.', ja: '誰も自分のすることすべてに完全な完璧さを達成できるわけではない。', trivia: 'ラテン語 *perfectio*（完成・完全）に由来し、*perficere*（完成する）から派生。英語の "perfection" と完全な同語根・同義語であり、どちらも per-（完全に）+ facere（する・作る）から成る。' },
  'perfeccionar': { es: 'Viví en París durante un año para perfeccionar mi francés.', ja: 'フランス語を磨くために、パリに一年間住んだ。', trivia: 'ラテン語 *perfectio* から派生した動詞で、per-（完全に）+ facere（作る）が語源。英語の動詞 "perfect"（完成させる）と同語根であり、英語では形容詞と動詞が同形だが、スペイン語では *perfecto*（形容詞）と *perfeccionar*（動詞）が区別される。' },
  'perfecto': { es: 'El clima en esta región es perfecto para cultivar uvas.', ja: 'この地域の気候はブドウの栽培に最適だ。', trivia: 'ラテン語 *perfectus*（*perficere*「完成する」の過去分詞）に由来し、per-（完全に）+ facere（する）の構成。英語の "perfect" と完全な同語根・同義語で、文法用語としても英語・スペイン語ともに「完了形」を指すのに使われる。' },
  'perfil': { es: 'Te reconocí de lejos solo por tu perfil.', ja: '横顔だけで遠くからあなただとわかった。', trivia: 'イタリア語 *profilo* を経てラテン語 *profilare*（輪郭を引く）に由来するとされ、per-/pro-（前に）+ filum（糸・線）の構成で「線で描いた輪郭」が原義。英語の "profile" と同語根・同義語で、SNS時代に両言語で「プロフィール」の意味が強まった。' },
  'perfume': { es: 'El perfume de las rosas llenaba todo el jardín.', ja: 'バラの香りが庭全体に漂っていた。', trivia: 'ラテン語 *per fumum*（煙を通じて）に由来し、per-（通じて）+ fumus（煙）の構成で、香を焚いて香りを出す古代の慣習を反映している。英語の "perfume" と完全に同語根・同義語で、フランス語 *parfum* を経由して英語に入った。' },
  'pericia': { es: 'La pericia del cirujano fue determinante para el éxito de la operación.', ja: '外科医の熟練した技術が手術の成功に決定的な役割を果たした。', trivia: 'ラテン語 *peritia*（経験・熟練）に由来し、*peritus*（経験豊富な）から派生。英語では "expertise" や "skill" が近い意味だが、語根は異なる。英語の "empirical"（経験的な）のギリシャ語語源 *peira*（試み）と深いところで関連する可能性が指摘される。' },
  'periferia': { es: 'Muchas familias jóvenes se trasladan a la periferia de las ciudades.', ja: '多くの若い家族が都市の郊外に移住する。', trivia: 'ギリシャ語 *periphereia*（周りを運ぶこと）に由来し、peri-（周りに）+ pherein（運ぶ）の構成。英語の "periphery" と完全な同語根・同義語で、両語ともギリシャ語由来の学術・地理用語として広く使われる。' },
  'periférico': { es: 'El teclado y el ratón son periféricos esenciales para el ordenador.', ja: 'キーボードとマウスはパソコンに欠かせない周辺機器だ。', trivia: 'ギリシャ語 *periphereia* に由来する形容詞で、英語の "peripheral" と完全な同語根・同義語。IT用語として「周辺機器」を意味するのも英語と共通しており、"peripheral device" という表現が両言語で同様に使われる。' },
  'periódico': { es: 'Mi abuelo lee el periódico en papel todas las mañanas.', ja: '祖父は毎朝紙の新聞を読む。', trivia: 'ギリシャ語 *periodikos*（周期的な）に由来し、peri-（周りに）+ hodos（道・周期）の構成。英語の "periodic"（周期的な）と同語根だが、スペイン語では「新聞」という意味が主流になった点が異なる。英語で「新聞」は *newspaper* と表現するが、スペイン語では周期的に発行される印刷物という概念から *periódico* が定着した。' },
  'periodista': { es: 'La periodista investigó durante meses antes de publicar el artículo sobre corrupción.', ja: 'その女性記者は、汚職に関する記事を公開する前に数か月間にわたって調査した。', trivia: 'ラテン語 «periodus»（期間・区切り）を語源とし、定期刊行物を意味する «período» から派生した職業名。英語の journalist と同じ概念だが、スペイン語では «journal»（日誌）ではなく «período»（周期・新聞）が基になっている点が異なる。' },
  'periodismo': { es: 'El periodismo de investigación es fundamental para mantener la democracia.', ja: '調査報道は民主主義を維持するために不可欠だ。', trivia: '«período»（周期・定期刊行物）に職業・活動を表す接尾辞 «-ismo» を付けた語。英語では journalism に相当するが、英語が «journal»（フランス語経由のラテン語 diurnalis「日々の」）に由来するのに対し、スペイン語では «período» が基になっている点が興味深い。' },
  'período': { es: 'Durante el período de la guerra civil, muchas familias tuvieron que emigrar.', ja: '内戦の時期には、多くの家族が移住せざるを得なかった。', trivia: 'ラテン語 «periodus» を経て、ギリシャ語 «períodos»（周回・循環；peri「周り」＋ hodos「道」）に遡る。英語の period と完全に同語根であり、綴りも意味も非常に近いが、スペイン語では «período» と «periodo» の二形が共存している。' },
  'perjuicio': { es: 'Fumar en exceso causa un grave perjuicio para la salud.', ja: '過度な喫煙は健康に深刻な害をもたらす。', trivia: 'ラテン語 «perjudicium»（害・不正）に由来し、«per-»（反する）＋ «judicium»（判断・法）から成る。英語の prejudice（偏見）と同語根だが、スペイン語 «perjuicio» は主に「損害・不利益」の意味で使われ、«prejuicio»（偏見）とは別語となっている点に注意。' },
  'perjudicial': { es: 'El exceso de azúcar es perjudicial para los dientes de los niños.', ja: '砂糖の過剰摂取は子どもの歯に有害だ。', trivia: '«perjuicio»（損害）の形容詞形。ラテン語 «perjudicialis» に由来し、«per-»（反する・完全に）＋ «judicium»（審判）が語源。英語では harmful や detrimental に相当するが、英語の judicial（司法の）と同語根であることは見かけ上わかりにくい。' },
  'perjudicar': { es: 'El ruido excesivo puede perjudicar la concentración de los estudiantes.', ja: '過度な騒音は学生の集中力を損なうことがある。', trivia: 'ラテン語 «perjudicare»（害を与える）に由来。英語の prejudice は同語根の名詞だが、現代英語では「偏見を持つ」という意味で固定しており、「損害を与える」という動詞的意味は harm や damage が担っている。スペイン語では «perjudicar» が純粋に「害する」の意味を保持している。' },
  'perla': { es: 'Me regalaron un collar de perlas para mi graduación.', ja: '卒業のお祝いに真珠のネックレスをもらった。', trivia: '語源は諸説あり、後期ラテン語の «perla» もしくは «perna»（二枚貝の一種）から派生したとされる。英語の pearl も同語根で、フランス語 «perle» を経由して英語に入った。スペイン語・英語ともに「とっておきの名言や人物」という比喩的用法を共有している。' },
  'permanecer': { es: 'Decidimos permanecer en casa durante la tormenta.', ja: '嵐の間は家に留まることにした。', trivia: 'ラテン語 «permanere»（通じて留まる；per-「完全に」＋ manere「留まる」）に由来。英語の remain や permanent と同語根で、特に permanent（永続的な）とは語根が完全に一致する。スペイン語では «quedar(se)» と意味が重なるが、«permanecer» はやや格式ある表現。' },
  'permanencia': { es: 'La permanencia del equipo en la primera división depende de los próximos partidos.', ja: 'そのチームの一部リーグ残留は今後の試合にかかっている。', trivia: 'ラテン語 «permanere»（留まる）の名詞形。英語の permanence と完全に同語根・同意味で、いずれもラテン語 «manere»（留まる）を語幹とする。日本語の「パーマネント」（髪のパーマ）もこの語根に由来する英語 permanent から来ている。' },
  'permanente': { es: 'El daño al medioambiente puede ser permanente si no actuamos ahora.', ja: '今行動しなければ、環境への損害は恒久的なものになりかねない。', trivia: 'ラテン語 «permanens»（留まり続ける）の現在分詞に由来。英語の permanent と完全に同語根・同形で、スペイン語でも英語でも形容詞としても名詞（髪のパーマ）としても使われる国際的な単語。ラテン語 «manere»（留まる）は mansion（邸宅）の語源でもある。' },
  'permiso': { es: 'Necesito pedir permiso a mi jefe para tomarme unos días libres.', ja: '数日休みを取るために上司に許可を求める必要がある。', trivia: 'ラテン語 «permissus»（許された；per-「通じて」＋ mittere「送る・許す」）の名詞形に由来。英語の permission や permit と完全に同語根で、いずれも「通過させる」が原義。missile（ミサイル）や mission（使命）も同じ語根 «mittere» から来ている。' },
  'permuta': { es: 'Ambos profesores acordaron una permuta para poder trabajar en sus ciudades natales.', ja: '両教員は故郷の都市で働けるよう転勤の交換に合意した。', trivia: 'ラテン語 «permutatio»（完全な交換；per-「完全に」＋ mutare「変える」）に由来。英語の permutation（数学の順列・組み合わせの置換）と同語根で、英語では主に数学用語として使われるのに対し、スペイン語では教員・公務員の職位交換という具体的な慣行を指すことが多い。' },
  'permutar': { es: 'Los dos funcionarios decidieron permutar sus puestos para estar más cerca de sus familias.', ja: '2人の公務員は家族のそばにいるために職位を交換することにした。', trivia: 'ラテン語 «permutare»（すっかり変える）に由来し、«per-»＋ «mutare»（変える）が語源。英語の permute（置換する）と同語根だが、英語では主に数学や抽象的な文脈で使われ、日常的な「物品・職位の交換」には swap や exchange を用いる点がスペイン語との使い方の違いとして面白い。' },
  'pernoctar': { es: 'Los excursionistas decidieron pernoctar en una cabaña de montaña.', ja: 'ハイカーたちは山小屋で一泊することにした。', trivia: 'ラテン語 «pernoctare»（夜を過ごす；per-「通じて」＋ nox/noctis「夜」）に由来。英語では直接の対応語はなく「spend the night」や「stay overnight」と表現する。英語の nocturnal（夜行性の）や equinox（春分・秋分）も同じ語根 «nox» を持つ。' },
  'pero': { es: 'Quería ir a la playa, pero empezó a llover.', ja: '海に行きたかったが、雨が降り始めた。', trivia: 'ラテン語 «per hoc»（これによって）または «pero»（しかし）に由来し、古代から逆接を表す接続詞として定着した。英語の but に相当するが語根は異なる（but はゲルマン語系）。スペイン語で名詞として「欠点・異議」を意味する用法（例：no hay pero que valga「言い訳は通らない」）は英語にはない独特の用法。' },
  'persecución': { es: 'La persecución policial terminó cuando el sospechoso se entregó voluntariamente.', ja: '容疑者が自ら出頭したことで警察の追跡は終わった。', trivia: 'ラテン語 «persecutio»（追跡・迫害）に由来し、«per-»（完全に）＋ «sequi»（追う）が語源。英語の persecution と同語根で、sequence（順序）や sequel（続編）も同じ «sequi» から来ている。宗教的迫害の文脈では persecution が歴史用語として定着している点は英西語共通。' },
  'perseguir': { es: 'La policía persiguió al ladrón por las calles del centro.', ja: '警察は市街地の通りで泥棒を追いかけた。', trivia: 'ラテン語 «persequi»（徹底的に追う）に由来。英語の pursue と意味は近いが語根が異なり、pursue はラテン語 «prosequi» 経由のフランス語から。一方、英語の prosecute（起訴する）は «perseguir» と同語根で、「法的に追及する」という意味のつながりが見えると興味深い。' },
  'perseverancia': { es: 'Gracias a su perseverancia, logró terminar la carrera universitaria a pesar de las dificultades.', ja: '粘り強さのおかげで、困難にもかかわらず大学の学位課程を修了することができた。', trivia: 'ラテン語 «perseverantia»（不屈の継続；per-「完全に」＋ severus「厳しい・真剣な」）に由来。英語の perseverance と完全に同語根・同意味で、severe（厳しい）や severity も同じ «severus» を共有している。キリスト教神学では「終末まで信仰を保つ」という神学的概念にも使われる。' },
  'perseverar': { es: 'Hay que perseverar en los estudios aunque a veces sea difícil.', ja: '時に困難であっても、学業に粘り強く取り組まなければならない。', trivia: 'ラテン語 «perseverare»（厳格に続ける）に由来し、«per-»＋ «severus»（厳しい）が語源。英語の persevere と同語根・同意味で、スペルも非常に似ている。ラテン語 «severus» は英語の severe（厳しい）の直接の語源でもあり、「厳しさをもって続ける」という原義が今も意味に反映されている。' },
  'persiana': { es: 'Baja la persiana para que no entre tanto sol por la mañana.', ja: '朝に日差しが入りすぎないようにブラインドを下ろして。', trivia: '「ペルシャの」を意味するスペイン語形容詞 «persa/persiano» に由来し、かつてペルシャ（現イラン）から伝わった日よけ・窓覆いの技術に由来するとされる。英語では venetian blind（ベネチアン・ブラインド）と呼ぶが、これはヴェネツィア経由でヨーロッパに広まったことを示しており、同じ物が国によって異なる地名を冠している点が面白い。' },
  'persistencia': { es: 'La persistencia de los síntomas nos llevó a consultar a un especialista.', ja: '症状が続いたため、私たちは専門医に診てもらうことにした。', trivia: 'ラテン語 «persistentia»（立ち続けること；per-「完全に」＋ sistere「立つ・止まる」）に由来。英語の persistence と完全に同語根・同意味。同じ «sistere» を語根に持つ英語の resist（抵抗する）、assist（助ける）、consist（成り立つ）などと語族を形成している。' },
  'persistir': { es: 'El mal tiempo persistió durante toda la semana.', ja: '悪天候が一週間ずっと続いた。', trivia: 'ラテン語 «persistere»（完全に立ち続ける；per-「完全に」＋ sistere「立つ」）に由来。英語の persist と完全に同語根・同意味で、スペルも非常に似ている。«sistere» はギリシャ語 «histanai»（立てる）とも印欧語の同根語であり、英語の station（駅）や statue（像）とも遠い親戚関係にある。' },
  'personaje': { es: 'El personaje principal de la novela es un detective retirado.', ja: 'その小説の主人公は引退した探偵だ。', trivia: 'ラテン語 «persona»（仮面・役柄）に接尾辞 «-aje»（行為・集合を表す）を加えた語。英語の character（登場人物）に相当するが、英語にも personage（著名人・重要人物）という語があり同語根。«persona» は元来演劇の仮面を指し、英語の person（人）や personality（個性）も同じ語源を持つ。' },
  'personal': { es: 'El jefe de personal anunció nuevas políticas de vacaciones para todos los empleados.', ja: '人事部長が全従業員に向けた新しい休暇制度を発表した。', trivia: 'ラテン語 «personalis»（個人に関わる）に由来し、«persona»（仮面・人格）が語源。英語の personal および personnel（人事・スタッフ）と同語根で、特に名詞用法の「職員・スタッフ」は英語 personnel と意味が重なる。personnel はフランス語経由でスペイン語 personal と同じラテン語語根から派生した双子語である。' },
  'personalidad': { es: 'Tiene una personalidad muy extrovertida que le facilita hacer amigos.', ja: '彼女はとても外向的な性格なので、友達を作るのが容易だ。', trivia: 'ラテン語 «personalitas»（個人としての特質）に由来し、«persona»（仮面・人格）が語根。英語の personality と完全に同語根・同意味で、心理学や日常会話でも同様に広く使われる。«persona» 自体は英語でも「ペルソナ」として借用され、マーケティングや心理学の専門用語として定着している。' },
  'personalizar': { es: 'La aplicación te permite personalizar la interfaz según tus preferencias.', ja: 'そのアプリはインターフェースを好みに合わせてカスタマイズできる。', trivia: 'ラテン語 persona（人、仮面）＋接尾辞 -izar から派生。英語の personalize と完全に同語根で、意味・用法もほぼ一致する。' },
  'perspectiva': { es: 'Desde esa perspectiva, el problema parece mucho más sencillo de resolver.', ja: 'その観点から見ると、問題はずっと簡単に解決できるように思える。', trivia: 'ラテン語 perspicere（見通す）に由来し、英語の perspective と完全に同語根。視覚的な「遠近法」と抽象的な「観点」の両義を持つ点も英語と共通する。' },
  'persuadir': { es: 'Al final, logré persuadir a mis padres para que me dejaran estudiar en el extranjero.', ja: '最終的に、両親を説得して海外留学を許してもらえた。', trivia: 'ラテン語 persuadere（完全に甘くする→納得させる）に由来し、英語の persuade と同語根。語根 suadere は「勧める」を意味し、英語の assuage（和らげる）とも遠い親戚関係にある。' },
  'persuasión': { es: 'La persuasión es una herramienta clave en la negociación comercial.', ja: '説得は商業交渉における重要なツールだ。', trivia: 'ラテン語 persuasio から来ており、英語の persuasion と同語根・同形。「スエード革」を意味する英語 suede はフランス語経由だが、語根 suad- とは別系統であることに注意。' },
  'pertenecer': { es: 'Este cuadro pertenece a una colección privada y nunca se ha expuesto al público.', ja: 'この絵画は個人コレクションに属しており、一般に公開されたことがない。', trivia: 'ラテン語 pertinere（完全に及ぶ）から派生した後期ラテン語 *pertenescere に由来。英語では belong が対応するが、pertinere 系は英語の pertain（関係する）として残っており、スペイン語とは意味が若干分岐している。' },
  'pertenencia': { es: 'El sentido de pertenencia a un grupo es fundamental para el bienestar emocional.', ja: '集団への帰属感は、感情的な健康にとって根本的なものだ。', trivia: 'pertenecer（属する）の名詞形で、英語の belonging と意味的に対応する。複数形 pertenencias は英語の belongings（所持品）にほぼ一致するが、単数形は「帰属意識」の意味で使われる点が異なる。' },
  'pertinente': { es: 'Por favor, limita tus comentarios a los puntos pertinentes al tema de discusión.', ja: '議論のテーマに関連するポイントにコメントを絞ってください。', trivia: 'ラテン語 pertinens（pertinere の現在分詞）に由来し、英語の pertinent と同語根・同形に近い。日常的には relevante の方がよく使われ、pertinente はやや改まった文脈で登場する。' },
  'pertrechos': { es: 'Los soldados llegaron al frente con los pertrechos necesarios para la campaña.', ja: '兵士たちは作戦に必要な軍需品を持って前線に到着した。', trivia: '語源については諸説あり、ラテン語 pertractare（整備する）または古フランス語 par-tresque（完全な道具立て）からとも言われる。英語では equipment や supplies が対応し、直接の英語同語根語は存在しない。' },
  'perversidad': { es: 'La perversidad del personaje principal lo convierte en uno de los villanos más memorables de la literatura.', ja: '主人公の邪悪さが、彼を文学の中で最も記憶に残る悪役の一人にしている。', trivia: 'ラテン語 perversitas（曲がっていること）に由来し、英語の perversity と同語根。接頭辞 per-（完全に）＋vertere（向ける・回す）という構成で、英語の pervert や subvert とも語根を共有する。' },
  'perverso': { es: 'El sistema tiene efectos perversos que nadie anticipó cuando fue diseñado.', ja: 'そのシステムには、設計時に誰も予想しなかった逆効果が生じている。', trivia: 'ラテン語 perversus（完全にひっくり返された）に由来し、英語の perverse と同語根。英語 perverse は「ひねくれた・意地悪な」という意味で使われ、スペイン語 perverso とほぼ対応するが、スペイン語では道徳的な「邪悪さ」のニュアンスがやや強い。' },
  'pesadilla': { es: 'Anoche tuve una pesadilla en la que me perseguían y no podía moverme.', ja: '昨夜、追いかけられて動けない悪夢を見た。', trivia: 'スペイン語 peso（重さ）＋接尾辞 -adilla から来ており、「胸の上に乗ってくる重いもの」という概念が語源。英語の nightmare も同じ発想で、mare は古英語で「夜に乗りかかる悪霊」を指し、両言語で悪夢を「重さ・圧迫」として捉えている点が一致する。' },
  'pesadumbre': { es: 'La noticia de su fallecimiento nos llenó de pesadumbre a todos los presentes.', ja: '彼の訃報は、その場にいた全員を深い悲しみで満たした。', trivia: 'pesar（重さ・悲しみ）から派生した語で、ラテン語 pensare（重さを量る）に由来する。英語には直接の対応語がなく、grief や sorrow が近いが、いずれも語根は異なる。英語の pensive（もの思いにふける）とは遠い親戚関係にある。' },
  'pesar': { es: 'Esta maleta pesa demasiado; tendré que sacar algunas cosas antes de facturarla.', ja: 'このスーツケースは重すぎる。チェックインする前にいくつか出さなければならない。', trivia: 'ラテン語 pensare（重さを計る）に由来し、英語の weigh とは語根が異なるが意味が対応する。英語では pensive（物思いにふける）や pension（年金、もとは「支払い」）が同語根で、「量る・支払う」という古い意味の流れをくむ。' },
  'pesca': { es: 'La pesca artesanal es una fuente de ingresos importante para muchas comunidades costeras.', ja: '伝統的な漁業は、多くの沿岸地域コミュニティにとって重要な収入源だ。', trivia: 'ラテン語 piscari（魚を取る）に由来し、英語の fish とはゲルマン語系対ラテン語系で語根が異なる。ただし英語の piscary（漁業権）や Pisces（魚座）は同じラテン語 piscis（魚）系で、スペイン語 pez（魚）とも共通の祖先を持つ。' },
  'pescadería': { es: 'Compré gambas frescas en la pescadería del mercado municipal.', ja: '市場の鮮魚店で新鮮なエビを買った。', trivia: 'pescado（魚、特に食用の切り身）に接尾辞 -ería（〜を売る店）を付けた語。英語には直接対応する単語はなく、fishmonger\'s や fish market が近い。-ería という接尾辞は英語の -ery に対応し、panadería（パン屋）や carnicería（肉屋）と同じ造語パターンを持つ。' },
  'pescador': { es: 'El pescador regresó al puerto al amanecer con una buena captura.', ja: '漁師は夜明けに豊漁を携えて港へ戻った。', trivia: 'ラテン語 piscator（漁師）に由来し、英語の fisherman とは語根が異なる。英語では piscator という語が詩的・古語的な表現として存在し、Izaak Walton の釣り名著『The Compleat Angler』の語り手の名前として使われている。' },
  'pescar': { es: 'Los domingos, mi abuelo y yo íbamos a pescar al río con cañas sencillas.', ja: '日曜日には、祖父と私はシンプルな竿を持って川へ釣りに行ったものだ。', trivia: 'ラテン語 piscari（魚を取る）に由来し、英語の fish（動詞）とは語根が違うが同じ意味を担う。口語では「情報を探り出す」「病気をもらう」といった比喩的用法があり、英語の fish for（〜を探る）と比喩パターンが一致する。' },
  'pesebre': { es: 'Cada año, los niños del pueblo ayudan a montar el pesebre en la plaza central.', ja: '毎年、村の子供たちが中央広場にキリスト誕生の模型を飾る手伝いをする。', trivia: 'ラテン語 praesepium（囲い・飼い葉桶）に由来し、英語の manger や crib が意味的に対応する。英語 presepium や pressepe（イタリア語 presepe）もほぼ同語根で、クリスマスの降誕場面の模型を指す用語として南欧文化圏で共有されている。' },
  'pesimismo': { es: 'El pesimismo crónico puede afectar negativamente tanto la salud mental como la física.', ja: '慢性的な悲観主義は、精神的・肉体的健康の両方に悪影響を与えうる。', trivia: 'ラテン語 pessimus（最悪の、malus の絶対最上級）に由来し、英語の pessimism と同語根・ほぼ同形。19世紀にショーペンハウアーの哲学を通じてヨーロッパ中に広まった学術語で、英語・スペイン語とも同時代にほぼ同じ形で定着した。' },
  'pesimista': { es: 'No seas tan pesimista; todavía hay muchas posibilidades de que las cosas salgan bien.', ja: 'そんなに悲観的にならないで。まだ物事がうまくいく可能性はたくさんある。', trivia: 'pesimismo と同じくラテン語 pessimus（最悪の）を語根とし、英語の pessimist と同語根。英語の pessimist と同様に形容詞・名詞の両用法があり、-ista（英語 -ist）という接尾辞は職業・主義者を表すラテン・ギリシャ系の共通パターンだ。' },
  'pésimo': { es: 'La atención al cliente de esa empresa es pésima; tardaron tres semanas en responder.', ja: 'あの会社の顧客対応は最悪で、返信に3週間もかかった。', trivia: 'ラテン語 pessimus（最悪の）に直接由来する malo の絶対最上級で、英語には直接の同形語はない。英語では pessimism や pessimist に語根が残るが、形容詞としては使われず、代わりに worst や terrible が対応する。' },
  'peso': { es: 'Desde que empecé a hacer ejercicio, he perdido cinco kilos de peso.', ja: '運動を始めてから、体重が5キロ落ちた。', trivia: 'ラテン語 pensum（重さを量ったもの）に由来し、英語の weight とは語根が異なる。英語では poise（均衡・重さ）が同語根の借用語として存在し、また通貨単位 peso は英語にもそのまま借用されている。' },
  'pestañas': { es: 'Ella se aplica rímel en las pestañas antes de salir a trabajar cada mañana.', ja: '彼女は毎朝仕事に出かける前にまつげにマスカラを塗る。', trivia: '語源については諸説あり、ラテン語 palpebra（まぶた）の変化形、またはアラビア語起源とも言われるが確定していない。英語の eyelash とは語根が全く異なる。現代のデジタル用語としてブラウザの「タブ」を指す用法は、形が細い板状であることからの比喩で、英語 tab とは語根が異なる。' },
  'peste': { es: 'La peste negra del siglo XIV acabó con un tercio de la población europea.', ja: '14世紀の黒死病はヨーロッパの人口の三分の一を死に至らしめた。', trivia: 'ラテン語 pestis（疫病・害悪）に由来し、英語の pestilence や pest と同語根。英語の pest は現代では主に「害虫」や「迷惑な人」を指すが、スペイン語 peste は今も「ペスト菌感染症」という深刻な意味を保持しており、両語の意味が歴史の中で分岐した好例だ。' },
  'pestillo': { es: 'Asegúrate de echar el pestillo antes de acostarte para que nadie pueda entrar.', ja: '誰も入ってこられないように、寝る前に必ず鍵をかけなさい。', trivia: 'ラテン語 pessulus（閂・かんぬき）に由来し、さらにギリシャ語 passalos（杭・くぎ）に遡る。英語の latch や bolt が意味的に対応するが語根は異なる。英語には直接の同語根語はなく、スペイン語独自にラテン語形を保持している珍しい例だ。' },
  'petaca': { es: 'Mi abuelo siempre llevaba una petaca de plata con whisky en el bolsillo del abrigo.', ja: '祖父はいつもコートのポケットにウイスキーを入れた銀のフラスコを持ち歩いていた。', trivia: '語源は諸説あり、アステカ語の「petlacalli（葦で編んだ箱）」に由来するという説が有力で、スペインに持ち込まれた後に意味が変化した。英語の「hip flask」に相当するが、直接の語根的つながりはない。' },
  'petición': { es: 'La organización presentó una petición con más de diez mil firmas ante el ayuntamiento.', ja: 'その団体は市役所に1万件以上の署名を集めた請願書を提出した。', trivia: 'ラテン語「petitio（求めること）」に由来し、動詞「petere（求める）」が語根。英語の「petition」と完全に同語根の直接借用語であり、形も意味もほぼ一致する。' },
  'petróleo': { es: 'Los precios del petróleo han subido considerablemente en los últimos meses.', ja: 'ここ数ヶ月で石油の価格がかなり上昇した。', trivia: '中世ラテン語「petroleum（岩の油）」に由来し、「petra（岩）＋oleum（油）」の合成語。英語の「petroleum」と完全に同語根で、「petro-（岩）」はギリシャ語「petra」から、「-ol（油）」は英語の「oil」とも同根。' },
  'petulancia': { es: 'Su petulancia al hablar en público le restó credibilidad ante el auditorio.', ja: '人前で話す際の横柄な態度が、聴衆の前での信頼性を損なった。', trivia: 'ラテン語「petulantia（生意気、無礼）」に由来し、「petulans（図々しい）」が語根。英語の「petulance」と同語根の直接借用語だが、英語では「ぐずぐずした不機嫌さ」のニュアンスが強いのに対し、スペイン語では「うぬぼれた傲慢さ」の意味合いが強い。' },
  'petulante': { es: 'El joven ejecutivo era tan petulante que interrumpía constantemente a sus colegas más experimentados.', ja: 'その若い管理職はとても生意気で、経験豊富な同僚たちの話をしょっちゅう遮っていた。', trivia: 'ラテン語「petulans（厚かましい、無礼な）」に由来し、「petere（求める・突く）」と関連する。英語の「petulant」と同語根だが、英語では「気難しくぐずる様子」を指すことが多く、スペイン語の「傲慢な自意識過剰」とはニュアンスが少しずれているフォルス・フレンドに近い。' },
  'pezón': { es: 'El bebé buscaba el pezón de su madre para alimentarse.', ja: '赤ちゃんは授乳しようと母親の乳首を探していた。', trivia: 'ラテン語「pectio」またはスペイン語の「pez（魚）」ではなく、「pie（足）」の派生形「pezo」から発展したという説があるが、語源は諸説ある。英語では「nipple」または「teat」に相当し、共通の語根はない。' },
  'piano': { es: 'Ella practica el piano durante dos horas cada mañana antes de ir al trabajo.', ja: '彼女は毎朝、仕事に行く前に2時間ピアノを練習している。', trivia: 'イタリア語の楽器名「pianoforte（弱く・強く）」の短縮形で、「piano（静かに・弱く）」はラテン語「planus（平らな、穏やかな）」に由来する。英語でも「piano」と全く同じ語形が使われ、これはイタリア語からの共通借用語。' },
  'pianista': { es: 'La pianista interpretó la sonata con una técnica impecable y gran sensibilidad.', ja: 'そのピアニストは非の打ち所のない技巧と豊かな感受性でソナタを演奏した。', trivia: 'イタリア語「pianista」から借用され、「piano（ピアノ）＋-ista（奏者・専門家）」の構成。英語の「pianist」と同語根だが、英語は「piano＋-ist」という接尾辞を持ち、どちらもイタリア語を介してラテン語「planus」に遡る。' },
  'picadura': { es: 'Me puse crema para aliviar la picadura de mosquito que tenía en el brazo.', ja: '腕についた蚊に刺された跡を和らげるためにクリームを塗った。', trivia: '動詞「picar（刺す）」に接尾辞「-dura（行為の結果）」が付いた形で、「picar」はラテン語「*piccare（突く）」に由来する可能性があるが詳細は不明。英語では「insect bite」または「sting」に相当し、直接の語根的関係はない。' },
  'picar': { es: 'A mí me picó una avispa mientras trabajaba en el jardín.', ja: '庭で作業中にスズメバチに刺された。', trivia: '語源はラテン語「*piccare」またはゲルマン語系の影響を受けた俗ラテン語とされるが諸説ある。英語の「pick（つつく・選ぶ）」と同語根という説もあり、確かに「突く」という基本概念を共有しているが、学術的には未確定。' },
  'pícaro': { es: 'El protagonista de esa novela es un pícaro que sobrevive gracias a su astucia y sus engaños.', ja: 'その小説の主人公は、機知と策略で生き抜くいたずら者だ。', trivia: 'スペイン語固有の語で、語源は「picar（刺す・つつく）」から派生したという説が有力。スペイン文学の「ピカレスク小説（novela picaresca）」のジャンル名として英語圏にも「picaresque」として輸出され、英語の literary term として定着している。' },
  'picaporte': { es: 'El picaporte de la puerta antigua estaba oxidado y costaba mucho abrirlo.', ja: '古いドアのノブは錆びていて、開けるのがとても大変だった。', trivia: '「picar（突く）＋porte（扉）」の合成語で、フランス語「porte（扉）」はラテン語「porta」に由来する。英語の「latch」や「door handle」に相当するが、「porta」の語根は英語の「portal（門）」「port（港）」などと同じラテン語源を共有する。' },
  'pico': { es: 'El cóndor extendió sus alas y levantó el vuelo desde el pico de la montaña.', ja: 'コンドルは翼を広げ、山頂から飛び立った。', trivia: 'ラテン語「beccus（くちばし）」ではなく、ケルト語または前ラテン語の「*beccus」に由来するという説があるが不明確。英語の「peak（頂上）」とは語根は異なるが意味が重なる部分がある。なお「一時過ぎ（las dos y pico）」のように「端数・少し」の口語的意味でもよく使われる。' },
  'piedad': { es: 'El juez mostró piedad ante el acusado y le redujo la condena.', ja: '裁判官は被告に慈悲を示し、刑期を短縮した。', trivia: 'ラテン語「pietas（信仰心・誠実さ・慈悲）」に由来し、「pius（敬虔な）」が語根。英語の「piety（信仰心）」と同語根で、ミケランジェロの彫刻「ピエタ（Pietà）」もこの語源から来ており、英語の「pity（哀れみ）」もラテン語「pietas」の別経路の派生語。' },
  'piedra': { es: 'Los niños lanzaban piedras al lago para hacer rebotar el agua.', ja: '子供たちは湖に向かって水切り石を投げていた。', trivia: 'ラテン語「petra（岩）」に由来し、これはギリシャ語「pétra」から借用されたもの。英語の「Peter（ペテロ）」という名前はギリシャ語の「Petros（岩）」に由来し同語根。英語では「stone」がゲルマン語系、「rock」がノルマン語系と語根が異なるのに対し、スペイン語は一語「piedra」に統合している。' },
  'piel': { es: 'Ella tiene la piel muy sensible y necesita usar productos sin perfume.', ja: '彼女は肌がとても敏感で、無香料の製品を使う必要がある。', trivia: 'ラテン語「pellis（皮・毛皮）」に由来し、英語の「pelt（毛皮）」「film（膜）」とも遠い語根上のつながりがある。英語では「skin（ゲルマン語系）」「leather（ゲルマン語系）」「hide（毛皮）」と意味が分かれるが、スペイン語の「piel」はこれら複数の意味をカバーする。' },
  'pieza': { es: 'Le falta una pieza al rompecabezas y no puede terminarlo.', ja: 'パズルに1ピース足りなくて、完成できない。', trivia: 'ラテン語「*pettia」またはガリア語「*pettia（断片）」に由来するとされ、フランス語「pièce」と同語源。英語の「piece」もフランス語を経由した同語根の借用語であり、スペイン語「pieza」と英語「piece」は兄弟語といえる。' },
  'pijama': { es: 'Me puse el pijama y me metí en la cama con un buen libro.', ja: 'パジャマを着て、面白い本を持ってベッドに入った。', trivia: 'ヒンディー語・ウルドゥー語「pāyjāma（足の衣）」に由来し、「pāy（足）＋jāma（衣服）」の合成語。英語の「pyjamas / pajamas」と同語源の借用語で、英語経由またはフランス語「pyjama」経由でスペイン語に入った。' },
  'pilar': { es: 'La educación es uno de los pilares fundamentales de cualquier sociedad democrática.', ja: '教育は民主主義社会のあらゆる基盤の一つだ。', trivia: 'ラテン語「pila（柱・桟橋の支柱）」に由来し、英語の「pillar」はフランス語「pilier」を経由した同語根の借用語。また英語の「pile（杭・積み重ね）」や「pillar（柱）」とも関連し、「橋を支える杭」という原義を共有する。' },
  'píldora': { es: 'El médico le recetó una píldora antiinflamatoria que debe tomar dos veces al día.', ja: '医師は1日2回服用する抗炎症薬の錠剤を処方した。', trivia: 'ラテン語「pilula（小球・小丸）」に由来し、「pila（球）」の指小形。英語の「pill（錠剤）」と同語根の直接借用語で、どちらもラテン語「pila」から来ている。英語では「pill」と短縮されたが、スペイン語では指小形「-ola」が残った形。' },
  'piloto': { es: 'La piloto aterrizó el avión con gran precisión a pesar de la tormenta.', ja: 'パイロットは嵐にもかかわらず、高い精度で飛行機を着陸させた。', trivia: 'イタリア語「piloto / pilota（舵手）」に由来し、これはギリシャ語「pēdōn（舵）＋-otēs（者）」に遡るという説がある。英語の「pilot」と同語根の借用語で、どちらもイタリア語経由のギリシャ語由来語。「航路を操る人」という原義は両言語で共通している。' },
  'pimiento': { es: 'Añade pimiento rojo y verde para darle color y sabor a la ensalada.', ja: 'サラダに色と風味を出すために赤と緑のパプリカを加えてください。', trivia: 'ラテン語「pigmentum（色素・香辛料）」に由来し、「pingere（描く・色づける）」が語根。英語の「pigment（色素）」と同語根だが、スペイン語では「香辛料→トウガラシ属の野菜」という意味変化を遂げた。英語では「pepper（コショウ・ピーマン）」が対応するが語根は別。' },
  'pinacoteca': { es: 'La Pinacoteca de Brera en Milán alberga algunas de las obras maestras del Renacimiento italiano.', ja: 'ミラノのブレラ絵画館はイタリア・ルネサンスの傑作を数多く収蔵している。', trivia: 'ギリシャ語「pinakothēkē（絵画の収納庫）」に由来し、「pinax（板・絵）＋thēkē（収納庫）」の合成語。英語では「art gallery」や「picture gallery」に相当し、「pinacotheca」という形でも使われるが一般的ではない。「thēkē」は英語の「thesis」「library」などとも遠い関係にある。' },
  'pincel': { es: 'El artista limpió el pincel con cuidado antes de cambiar de color.', ja: '芸術家は色を変える前に丁寧に絵筆を洗った。', trivia: 'ラテン語「penicillus（小尾・小筆）」に由来し、「penis（尾）」の指小形。英語の「pencil（鉛筆）」と同語根の直接借用語で、どちらも「小さな筆・書く道具」という共通の祖先を持つ。また抗生物質「penicillin（ペニシリン）」も「筆状の形のカビ」からこの語根が使われた。' },
  'pinchar': { es: 'Se me pinchó una rueda en la autopista y tuve que llamar a la grúa.', ja: '高速道路でタイヤがパンクして、レッカー車を呼ばなければならなかった。', trivia: '語源は「picar（刺す）」と同系で、擬音語的な「pinc-」に由来するという説や、ラテン語「*pinnicare」に由来するという説があるが不明確。英語では「to puncture（パンクさせる）」「to prick（刺す）」「to click（クリックする）」など文脈によって複数の語に対応し、スペイン語の多義性は特徴的。' },
  'pinche': { es: 'El pinche de cocina lavaba los platos mientras el chef preparaba los platos principales.', ja: 'シェフがメイン料理を準備する間、料理補助の見習いは皿を洗っていた。', trivia: '中世フランス語 *pinchier*（つまむ、挟む）に由来するとされ、もとは肉の串を扱う下働きを指した。英語の *pinch*（つまむ）と同語根で、メキシコ口語では侮辱語としても広く使われるが、スペイン本土では単に「炊事場の見習い」という中立的な意味に留まる。' },
  'pinchazo': { es: 'Tuve un pinchazo en la autopista y tuve que llamar a la grúa.', ja: '高速道路でタイヤがパンクして、レッカー車を呼ばなければならなかった。', trivia: '動詞 *pinchar*（刺す・突く）から派生した名詞で、*pinchar* はラテン語 *punctiare* と接続するとも中世ロマンス語形由来とも言われ語源は諸説ある。英語の *puncture*（パンク、穿刺）は同じ「刺す」概念を共有するが語根は異なり、英語では *puncture* がタイヤのパンクにも医療的な穿刺にも使われる点でよく対応する。' },
  'pino': { es: 'Los niños jugaban bajo los pinos en el parque después de la escuela.', ja: '子どもたちは放課後、公園の松の木の下で遊んでいた。', trivia: 'ラテン語 *pinus*（松）に直接由来し、英語の *pine*（松の木）も同じラテン語源を共有する同語根語。「逆立ち」の意味（*hacer el pino*）はスペイン語独自の転義で、松の木のように真っすぐ逆さに立つ様子から来ている。' },
  'pinta': { es: 'Tiene buena pinta ese restaurante, vamos a entrar a cenar.', ja: 'あのレストラン、感じがよさそうだ。入って夕食にしよう。', trivia: 'ラテン語 *picta*（描かれたもの、彩色）の俗ラテン語形 *pincta* に由来し、英語の *pint*（パイント、液量の単位）もノルマン・フランス語経由で同語根と考えられている。「外見」という意味は「色や斑点で特徴づけられた様子」から転義したもの。' },
  'pintor': { es: 'El pintor tardó tres semanas en renovar la fachada del edificio.', ja: '塗装工は建物の外壁の塗り替えに3週間かかった。', trivia: 'ラテン語 *pictor*（描く人）から来ており、英語の *painter* とは語根（*pingere*：描く）を共有する関係にある。英語 *picture*（絵・写真）や *pigment*（顔料）も同じ *pingere* 族で、スペイン語でも *pintura*（絵・塗料）、*pincel*（絵筆）が同族語として並ぶ。' },
  'pintura': { es: 'Compramos pintura blanca para renovar las paredes del salón.', ja: 'リビングの壁を塗り直すために白いペンキを買った。', trivia: 'ラテン語 *pictura*（絵画、彩色）に由来し、英語の *picture* と同語根の兄弟語。ただし現代英語で *picture* は主に「写真・絵」を指し「塗料」の意味は持たないのに対し、スペイン語 *pintura* は「絵画」も「ペンキ」も両方カバーする点が特徴的なフォールス・フレンドになっている。' },
  'piña': { es: 'Me tomé un zumo de piña recién hecho en el mercado.', ja: '市場で作りたてのパイナップルジュースを飲んだ。', trivia: 'ラテン語 *pinea*（松かさ）に由来し、もともとは松ぼっくりを指す語だった。スペイン人が中南米でパイナップルを見た際、その形が松ぼっくりに似ていたためこの名を転用した。英語の *pineapple* も同じ発想で、*pine*（松）＋ *apple*（果実）と命名されており、両言語が同じ比喩を使っている点が興味深い。' },
  'pío': { es: 'El rey era conocido por ser un hombre pío que donaba a los pobres.', ja: 'その王は貧しい人々に施しをする敬虔な人物として知られていた。', trivia: 'ラテン語 *pius*（敬虔な、慈悲深い）に直接由来し、英語の *pious*（敬虔な）と完全に同語根の同義語。また固有名詞 *Pío*（ピウス）は歴代ローマ教皇の名としても有名で、英語圏では *Pius* と綴る。小鳥の鳴き声「ピヨ」の擬音語的意味は全く別の語源（オノマトペ）から派生している。' },
  'piojo': { es: 'Los piojos se contagian fácilmente entre niños en edad escolar.', ja: 'シラミは学齢期の子どもたちの間で簡単にうつる。', trivia: '語源は不明確で、ラテン語 *pediculus*（シラミ）の後継語ではなく、イベリア語や前ラテン語の基層語に由来する可能性が指摘されている。英語では *louse*（複数形 *lice*）と言い、こちらは古英語 *lūs* に由来するゲルマン語系で、スペイン語 *piojo* とは語根が完全に異なる。' },
  'pipa': { es: 'Mi abuelo fumaba en pipa en su sillón favorito cada tarde.', ja: '祖父は毎夕、お気に入りの肘掛け椅子でパイプタバコを吸っていた。', trivia: '中世ラテン語 *pipa*（管、笛）に由来し、英語の *pipe* と同語根の同義語。元来は「管状のもの」を指し、喫煙用パイプも樽（ワイン用の大きな樽）も「管・筒」の概念で結ばれている。ひまわりの種の意味はスペイン特有の用法で、殻をむいて食べる習慣から定着した。' },
  'pipí': { es: 'El niño pidió ir al baño porque tenía que hacer pipí.', ja: 'その子はおしっこがしたくてトイレに行きたいと言った。', trivia: 'オノマトペ的な幼児語で、尿の音や響きを模したとされる普遍的な語形。英語の幼児語 *pee*（おしっこ）や *wee*（英国英語）も同様に音象徴・幼児語的起源を持ち、スペイン語 *pipí* と直接の語根的つながりはないが、世界の多くの言語で「p」音が幼児の排泄語に使われる傾向がある。' },
  'pirámide': { es: 'Las pirámides de Egipto siguen siendo una de las maravillas del mundo antiguo.', ja: 'エジプトのピラミッドは今も古代世界の不思議の一つであり続けている。', trivia: 'ギリシャ語 *pyramís*（ピラミッド）に由来し、ラテン語 *pyramis* を経てスペイン語に入った。英語の *pyramid* も同じ経路でギリシャ語から借用されており、スペイン語・英語ともに完全な同語根語。語末の *-ide* は学術・科学用語に多いギリシャ語由来の接尾辞で、幾何学用語としての普及が世界共通語化に貢献した。' },
  'pirata': { es: 'La película trataba de un pirata que buscaba un tesoro escondido en el Caribe.', ja: 'その映画はカリブ海に隠された宝を探す海賊の話だった。', trivia: 'ギリシャ語 *peiratḗs*（試みる者、略奪者）に由来し、ラテン語 *pirata* を経て伝わった。英語の *pirate* も同じ語源で完全な同語根語。形容詞的用法（*software pirata*：海賊版ソフト）は現代のデジタル著作権侵害にも広く使われており、英語の *pirated software* と用法が完全に対応する。' },
  'piropo': { es: 'En algunos países hispanohablantes es costumbre decir piropos a las mujeres en la calle.', ja: 'スペイン語圏の一部の国では、道で女性に褒め言葉をかける習慣がある。', trivia: 'ギリシャ語 *pýrōpos*（火のような目をした、紅宝石）に由来し、もともとはルビーのような宝石を指す語だった。転じて「宝石のような言葉＝美辞麗句」の意味になったとされる。英語には直接の対応語がなく *compliment* や *catcall* で文脈に応じて訳し分けるが、*piropo* のもつ路上での賛辞という文化的ニュアンスは英語では一語で表しにくい。' },
  'piscina': { es: 'En verano, los niños pasan horas en la piscina municipal.', ja: '夏、子どもたちは市営プールで何時間も過ごす。', trivia: 'ラテン語 *piscina*（魚の池、魚を飼う場所）に由来し、*piscis*（魚）が語根。英語の *Pisces*（魚座）や *piscatorial*（漁に関する）と同語根で、元来は観賞・養殖用の池を指したが、スペインでは現代的な水泳プールを指す標準語として定着した。英語では *swimming pool* と言い、ラテン語系の *piscina* は専門的・宗教的文脈（洗礼盤）に限られる。' },
  'piso': { es: 'Vivo en un piso de dos habitaciones en el centro de la ciudad.', ja: '市の中心部にある2部屋のアパートに住んでいる。', trivia: 'ラテン語 *pisare*（踏む、砕く）に由来し、「踏まれる面」→「床」→「建物の一階層」→「その階の住戸全体」と意味が拡張した。英語の *floor*（床、階）はゲルマン語系（古英語 *flōr*）で語根は異なる。英語の *peso*（通貨単位）や動詞 *pisar*（踏む）と同じラテン語族に属し、「押しつける・踏む」という根本イメージを共有している。' },
  'pisar': { es: 'Por favor, no pises el césped recién plantado del jardín.', ja: '庭に植えたばかりの芝生を踏まないでください。', trivia: 'ラテン語 *pisare*（突く、砕く、踏む）に由来し、*piso*（床）と同語根。英語に直接対応する同語根語は現代語には残っていないが、*pestle*（すりこぎ）はラテン語 *pistillum* 経由で同族語と考えられており、「踏んで砕く」という原義をよく示している。' },
  'pista': { es: 'La policía encontró una pista importante en la escena del crimen.', ja: '警察は犯行現場で重要な手がかりを見つけた。', trivia: 'イタリア語 *pista*（踏み固められた道、跡）に由来し、さらにラテン語 *pinsita*（踏み固められた）に遡る。英語の *piste*（スキーのゲレンデ、フェンシングのピスト）はフランス語経由の同語根借用語で、スポーツ用語として英語でも生きている。「手がかり」という意味は「足跡・痕跡をたどる」という発想から派生した。' },
  'pistola': { es: 'El policía desenfundó la pistola al ver al sospechoso armado.', ja: '警察官は武装した容疑者を見てピストルを抜いた。', trivia: 'チェコ語 *píšťala*（管、笛）に由来するとされ、16世紀に火器の名として広まったとされる。英語の *pistol* も同じ経路でチェコ語またはドイツ語 *Pistole* 経由で借用されており、スペイン語 *pistola* と同語根の国際語。管楽器と銃器が「管」という形状で結ばれている語源が興味深い。' },
  'pistón': { es: 'El mecánico revisó los pistones del motor porque el coche perdía potencia.', ja: '車がパワーを失っていたので、整備士はエンジンのピストンを点検した。', trivia: 'フランス語 *piston*（ピストン）に由来し、さらにイタリア語 *pistone*（大きな杵）、ラテン語 *pinsere*（突く、押す）に遡る。英語の *piston* も同じフランス語・イタリア語経路で借用されており、スペイン語・英語ともに完全な同語根語。ラテン語 *pinsere* は *pisar*（踏む）とも遠い親戚関係にある。' },
  'pitillo': { es: 'Salió a fumarse un pitillo en la terraza del bar.', ja: 'バルのテラスに出てタバコを一本吸いに行った。', trivia: 'スペイン語 *pito*（笛、細い管）の指小語形 *pitillo* で、「小さな管」→「細い巻きタバコ」と転義した。英語の *cigarette* はフランス語由来でまったく語根が異なるが、スペイン語では *cigarrillo* と *pitillo* の両方が使われ、後者は口語的表現。「スキニーパンツ」を *pitillos* と呼ぶ用法も、細い管状の形から来ている。' },
  'pito': { es: 'El árbitro sopló el pito para señalar el final del partido.', ja: '審判は試合終了を告げるためにホイッスルを吹いた。', trivia: '語源は諸説あり、鳥の鳴き声を模したオノマトペ起源とも、ラテン語 *pipitare*（さえずる）からとも言われる。英語では *whistle*（ホイッスル）が対応語で、こちらは古英語 *hwistlian* 由来のゲルマン語系。スペイン語口語 *no me importa un pito*（全くどうでもいい）のように「くだらないもの」の意味でも慣用句に頻出する。' },
  'pizarrón': { es: 'El profesor escribió las conjugaciones del verbo en el pizarrón.', ja: '先生は黒板に動詞の活用形を書いた。', trivia: 'スペイン語 *pizarra*（スレート、黒板）の増大語形で、*pizarra* 自体はバスク語 *lapitz-arri*（鉛筆石）に由来すると言われる。英語の *blackboard* や *chalkboard* とは語根が完全に異なり、英語では *slate*（スレート板）が素材名として近い。中南米では *pizarrón* が標準的だが、スペイン本土では *pizarra* のみ使う地域が多い。' },
  'placa': { es: 'La placa del coche estaba cubierta de barro y no se podía leer el número.', ja: '車のナンバープレートが泥で覆われていて番号が読めなかった。', trivia: 'フランク語 *plak*（平らなもの）またはオランダ語 *plak* に由来し、フランス語 *plaque* を経てスペイン語に入った。英語の *plaque*（飾り板、歯垢）も同語源の借用語で、スペイン語 *placa* と同語根。英語の *place* や *plaza*（広場）も遠縁とされ、「平らに広がる」という根本イメージで結ばれている。' },
  'placer': { es: 'Fue un placer conocerte en la conferencia de la semana pasada.', ja: '先週の会議でお会いできて光栄でした。', trivia: 'ラテン語 *placere*（気に入る、満足させる）に直接由来し、英語の *pleasure*（喜び、楽しみ）と同語根の緊密な同族語。英語 *please*（喜ばせる）、*pleasant*（心地よい）、*placid*（穏やかな）なども同じ *placere* 族で、「人を満足させる・穏やかにする」という原義が様々な語に受け継がれている。' },
  'plácido': { es: 'Pasamos una tarde plácida junto al río, sin preocupaciones ni prisa.', ja: '私たちは川のほとりで、心配事も急ぎもなく穏やかな午後を過ごした。', trivia: 'ラテン語 placidus（穏やか・なだらか）に由来し、動詞 placēre（喜ばせる）と同根。英語の placid（穏やかな）と完全な同語根であり、英語 please や placate（なだめる）とも遠縁にあたる。' },
  'plaga': { es: 'La plaga de langostas destruyó los cultivos en pocas horas.', ja: 'イナゴの大発生が数時間で農作物を壊滅させた。', trivia: 'ラテン語 plaga（打撃・傷）に由来し、英語の plague（疫病・天災）と同語根。聖書の「十の災い（Ten Plagues）」の plague と同じ言葉であり、歴史的・宗教的文脈でも頻出する。' },
  'plan': { es: 'Tenemos un plan detallado para el viaje a Argentina.', ja: 'アルゼンチンへの旅行について詳細な計画を立てている。', trivia: 'フランス語 plan を経由しラテン語 planus（平らな・明確な）に由来する。英語の plan と同語源で形・意味ともほぼ同じ。また英語 plane（平面）や plateau（高原）とも根を共にする。' },
  'plancha': { es: 'Se me olvidó quitar la plancha y se quemó la camisa.', ja: 'アイロンを外し忘れてシャツが焦げてしまった。', trivia: 'ラテン語 planca（板）またはそのゲルマン語派生形に由来し、「平らな板」が原義。英語に直接対応する単語はなく、文脈によって iron（アイロン）や griddle（鉄板）に相当する。口語で「大恥」の意味になるのはスペイン語独自の用法。' },
  'planchar': { es: '¿Puedes planchar esta camisa antes de la reunión?', ja: '会議の前にこのシャツにアイロンをかけてもらえる？', trivia: '名詞 plancha（アイロン・平らな板）から派生した動詞。英語では iron（アイロンをかける）または grill（焼く）に相当し、英語の to iron と同様に道具名が動詞化したパターン。' },
  'planeta': { es: 'Marte es el planeta más estudiado después de la Tierra.', ja: '火星は地球に次いで最も研究されている惑星だ。', trivia: 'ギリシャ語 planētēs（さまよう者）に由来し、古代に「不規則に動く星」として区別されたことから。英語の planet と同語根で形・意味ともほぼ一致する国際語彙。' },
  'planetario': { es: 'Llevamos a los niños al planetario para ver las estrellas proyectadas.', ja: '子どもたちを連れてプラネタリウムへ行き、投影された星を見た。', trivia: 'planeta（惑星）＋形容詞接尾辞 -ario から形成。英語の planetary（惑星の）・planetarium（プラネタリウム）と完全に同語根であり、科学用語として近代ラテン語を経由して各言語に普及した国際語。' },
  'planicie': { es: 'La planicie se extendía hasta el horizonte sin ningún árbol.', ja: '平原は木一本もなく地平線まで広がっていた。', trivia: 'ラテン語 planities（平坦な地）に由来し、planus（平らな）と同根。英語の plain（平原）と同語源だが、英語 plain はフランス語経由でより短縮された形になった。英語では plain または flatland に相当する。' },
  'planificación': { es: 'La planificación urbana es esencial para el desarrollo sostenible.', ja: '都市計画は持続可能な発展に不可欠だ。', trivia: 'planificar（計画する）＋名詞化接尾辞 -ción から形成。英語の planning・planification と同語根であり、ラテン語 planus（平ら・明確）を語基に持つ。英語では planning がより一般的で、planification は主に経済・政策分野で使われる。' },
  'planificar': { es: 'Es importante planificar bien el presupuesto antes de empezar el proyecto.', ja: 'プロジェクトを始める前に予算をしっかり計画することが重要だ。', trivia: 'ラテン語 planus（平ら・明確）＋-ficare（〜にする）の合成に由来する。英語の plan や英語には存在しない planify に相当するが、英語では simply plan または schedule という動詞を使うことが多い。' },
  'plano': { es: 'El arquitecto nos mostró el plano del nuevo edificio.', ja: '建築家が新しい建物の設計図を見せてくれた。', trivia: 'ラテン語 planus（平らな・明瞭な）に由来し、英語の plane（平面・飛行機）と同語根。英語 plan（計画）も同じ語源で、「平らな地図に描いたもの」から「計画」へと意味が転じた経緯をスペイン語・英語で共有している。' },
  'planta': { es: 'En la planta baja hay una farmacia y en la primera un restaurante.', ja: '1階に薬局があり、2階にはレストランがある。', trivia: 'ラテン語 planta（足の裏・若芽）に由来し、英語の plant と完全な同語源。「足で踏みつけて植える」という原義から、植物・工場・建物の階など多様な意味が派生した。英語 plant も同様に多義的だが、「階（フロア）」の意味は英語にはなくスペイン語独自。' },
  'plantación': { es: 'Las plantaciones de café en Colombia producen uno de los mejores granos del mundo.', ja: 'コロンビアのコーヒー農園は世界最高品質の豆を生産している。', trivia: 'plantar（植える）から派生し、ラテン語 plantatio に由来する。英語の plantation と同語根で形・意味ともほぼ一致し、アメリカ南部の歴史的な「大農園」も含め国際的に共通のイメージを持つ語彙。' },
  'plantar': { es: 'Este fin de semana vamos a plantar árboles en el parque del barrio.', ja: '今週末、近所の公園に木を植える予定だ。', trivia: 'ラテン語 plantare（植える）に直接由来し、英語の plant（動詞：植える・設置する）と完全に同語根。口語で「待ちぼうけを食わせる・見捨てる」の意味になるのはスペイン語独自の用法で、英語では stand someone up に相当する。' },
  'planteamiento': { es: 'El planteamiento del problema fue muy claro en su presentación.', ja: '彼のプレゼンでは問題の提起が非常に明確だった。', trivia: 'plantear（提起する）＋名詞化接尾辞 -miento から形成。plantear 自体はラテン語 plantare（植える）由来で「問題を据え置く・立てる」という比喩的意味に転じた。英語には直訳の対応語がなく、framing・approach・formulation などで文脈に応じて訳し分けられる。' },
  'plantear': { es: 'El estudiante planteó una pregunta muy interesante al final de la clase.', ja: '授業の最後に学生がとても興味深い質問を投げかけた。', trivia: 'ラテン語 plantare（植える・据える）に由来し、「問題を据え立てる」という比喩的意味に発展した。英語では to raise（a question）・to put forward・to frame に相当するが、一語で対応する動詞はなく、スペイン語の多機能さが際立つ語。' },
  'plantilla': { es: 'El entrenador convocó a toda la plantilla para el partido del sábado.', ja: '監督は土曜日の試合に向けてチーム全員を招集した。', trivia: 'planta（足の裏・型板）の指小形 plantilla から発展し、「型・テンプレート」→「組織を構成する人員一覧」へと意味が広がった。英語では template（テンプレート）・insole（中敷き）・squad/roster（選手団）と文脈ごとに異なる語に対応し、英語に一語対応語はない。' },
  'llanto': { es: 'El llanto del bebé se escuchaba desde el pasillo.', ja: '赤ちゃんの泣き声が廊下まで聞こえてきた。', trivia: 'ラテン語 planctus（嘆き・胸を打つこと）に由来し、動詞 plangere（打つ・嘆く）と同根。英語の plaint（嘆き）や complaint（不満）と遠い同語根関係にあるが、現代英語では crying または weeping に相当し、直接対応する単語はない。' },
  'plasma': { es: 'Los médicos utilizan el plasma sanguíneo en algunas transfusiones.', ja: '医師は一部の輸血で血漿を使用する。', trivia: 'ギリシャ語 plasma（形作られたもの・型）に由来し、動詞 plassein（形作る）と同根。英語の plasma と完全に同語根で形・意味ともほぼ一致する国際科学用語。英語の plastic や plasticine（粘土）とも同じ語根を共有する。' },
  'plasmar': { es: 'El pintor logró plasmar sus emociones en el lienzo con gran destreza.', ja: '画家は巧みにキャンバスに自分の感情を形として表現した。', trivia: 'ギリシャ語 plasma（形作られたもの）→ラテン語 plasmare（形作る）に由来する。英語には直接対応する動詞はなく、to embody・to capture・to give shape to などで表現する。英語の plastic・plasma と同じ語根 plassein（形作る）を持つ。' },
  'plástico': { es: 'Cada vez más países prohíben el uso de bolsas de plástico.', ja: 'プラスチック袋の使用を禁止する国がますます増えている。', trivia: 'ギリシャ語 plastikos（形を作れる・可塑性のある）に由来し、動詞 plassein（形作る）と同根。英語の plastic と完全に同語根で形・意味ともほぼ一致する。20世紀に合成樹脂が普及してから「プラスチック製品」の意味が主流になった点も英語と同様。' },
  'plata': { es: 'En Argentina, la gente suele usar la palabra plata para referirse al dinero.', ja: 'アルゼンチンでは、お金のことを plata という言葉でよく表す。', trivia: 'ラテン語 platus（平らな）→ lámina de plata（薄く延ばした銀板）の意味から「銀」を指すようになった語。英語の silver とは語根が異なり、英語では silver または（口語の金銭の意味では）money・cash に相当する。国名 Argentina もラテン語 argentum（銀）に由来し、plata と同じ概念を持つ。' },
  'plataforma': { es: 'La plataforma de streaming ofrece miles de series y películas.', ja: 'その配信プラットフォームは何千ものドラマや映画を提供している。', trivia: 'フランス語 plateforme（平らな形）を経由し、ラテン語 planus（平ら）＋forma（形）に由来する。英語の platform と同語根で形・意味ともほぼ一致し、鉄道ホームからデジタルサービスまで幅広く使われる現代的語彙の典型例。' },
  'plateado': { es: 'El deportista recibió una medalla plateada en los Juegos Olímpicos.', ja: 'その選手はオリンピックで銀メダルを受け取った。', trivia: 'plata（銀）＋過去分詞接尾辞 -ado から形成され、「銀でコーティングされた・銀色の」が原義。英語では silvery または silver-colored に相当し、英語にも silvered という形はあるが plateado ほど日常的には使われない。' },
  'platillo': { es: 'El músico tocó los platillos con mucha energía durante el solo de batería.', ja: 'ミュージシャンはドラムソロの間、力強くシンバルを叩いた。', trivia: 'plato（皿）の指小形 platillo（小皿）から派生し、「皿状の小さなもの」が原義。英語では文脈によって saucer（ソーサー）・cymbal（シンバル）・dish（料理）・flying saucer（UFO）と異なる語に対応し、英語に一語対応語はない。plato 自体はラテン語 plattus（平らな）に由来し、英語の plate と同語根。' },
  'plato': { es: 'El chef preparó un plato delicioso con ingredientes frescos de temporada.', ja: 'シェフは旬の新鮮な食材を使って美味しい一皿を準備した。', trivia: 'ラテン語 platus（平たい）に由来し、英語の plate と同語根。英語では「皿」を plate、「料理の一品」を dish と言うが、スペイン語では plato がその両方をカバーする。' },
  'platónica': { es: 'Guardaba una admiración platónica por su profesora de literatura desde la adolescencia.', ja: '思春期のころから文学の先生にプラトニックな憧れを抱いていた。', trivia: '古代ギリシャの哲学者プラトン（Platón）の名に由来し、英語の platonic と同語根・同形。プラトンが「饗宴」で論じた精神的・理想的な愛の概念から「肉体的でない純粋な愛」を指すようになった。' },
  'plazo': { es: 'Tienes que entregar el informe antes de que venza el plazo, que es el viernes.', ja: '締め切りは金曜日なので、それまでにレポートを提出しなければならない。', trivia: '語源には諸説あるが、ラテン語 placitum（合意、決定された事柄）から派生したとする説が有力。英語に直接の同語根語はないが、意味的には deadline や term、installment（分割払いの文脈で）に相当する。' },
  'plebe': { es: 'La plebe se manifestó en la plaza principal exigiendo mejores condiciones de vida.', ja: '民衆は広場に集まり、より良い生活環境を求めてデモを行った。', trivia: 'ラテン語 plebs（平民、庶民）に直接由来し、英語の plebeian（平民の）と同語根。古代ローマで貴族（patricii）に対する一般市民を指した言葉で、英語では plebs または the common people と言う。' },
  'plebeyo': { es: 'En la sociedad feudal, un plebeyo tenía muy pocas oportunidades de ascender socialmente.', ja: '封建社会において、平民は社会的に上昇する機会がほとんどなかった。', trivia: 'ラテン語 plebeius（plebs の形容詞形）に由来し、英語の plebeian と同語根。英語では形容詞・名詞両方として使われる plebeian が対応するが、口語では prole や commoner も使われる。' },
  'plegar': { es: 'El mapa era tan grande que tardé varios minutos en plegarlo correctamente.', ja: '地図があまりにも大きくて、正しくたたむのに数分かかった。', trivia: 'ラテン語 plicare（折る、重ねる）に由来し、英語の ply（重ねる、折る）や複合語の imply、reply などと同語根。同じ語源からスペイン語には aplicar（適用する）や implicar（含意する）も派生している。' },
  'plegaria': { es: 'Antes de dormir, la abuela recitaba una plegaria en voz baja junto a la cama.', ja: '寝る前に、祖母はベッドのそばで小声でお祈りを唱えた。', trivia: 'ラテン語 precaria（嘆願、懇願）に由来するとされ、英語の prayer（祈り）と同語根の近縁語。英語の precarious（不安定な）も同じ語根を持ち、もともと「他者の好意に依存した」という意味だった。' },
  'pleito': { es: 'La familia tardó años en resolver el pleito por la herencia de su abuelo.', ja: '家族は祖父の遺産をめぐる訴訟を解決するのに何年もかかった。', trivia: 'ラテン語 placitum（裁判所の決定、審問）に由来し、英語の plea（嘆願、答弁）と同語根。英語では lawsuit が訴訟全体を指すが、plea は特に裁判での申し立て・答弁を意味する点で用法が異なる。' },
  'plenitud': { es: 'En la plenitud de su carrera, el escritor publicó su obra más ambiciosa.', ja: 'キャリアの絶頂期に、その作家は最も野心的な作品を発表した。', trivia: 'ラテン語 plenitudo（満ちていること）に由来し、英語の plenitude または plenteousness と同語根。英語の plenty（豊富さ）や plenary（全員出席の）も同じ語根 plenus（満ちた）から派生している。' },
  'pleno': { es: 'La propuesta fue aprobada en pleno por todos los miembros del consejo.', ja: 'その提案は理事会の全員出席の本会議で承認された。', trivia: 'ラテン語 plenus（満ちた、完全な）に由来し、英語の full に意味上相当するが、同語根の英単語としては plenary（全体会議の）や replenish（補充する）がある。en pleno verano（真夏に）のような熟語表現でよく使われる。' },
  'pliego': { es: 'El contratista entregó el pliego de condiciones para la obra la semana pasada.', ja: '請負業者は先週、工事の仕様書一式を提出した。', trivia: '動詞 plegar（折る）の名詞形で、ラテン語 plicare に由来する。英語では sheet（of paper）や tender document（入札書類）に相当し、直接の同語根英単語はないが、fold と意味的につながりがある。' },
  'plomo': { es: 'Las antiguas tuberías de plomo fueron reemplazadas por otras de cobre por razones de salud.', ja: '健康上の理由から、古い鉛管は銅管に取り替えられた。', trivia: 'ラテン語 plumbum（鉛）に由来し、英語の plumber（配管工）と同語根。かつて配管が鉛で作られていたため、英語で plumber は「鉛を扱う職人」が語源。元素記号 Pb もこの plumbum に基づく。' },
  'pluma': { es: 'Escribió una carta de amor con pluma y tinta en papel perfumado.', ja: '香り付きの紙に万年筆とインクで恋文を書いた。', trivia: 'ラテン語 pluma（羽毛）に直接由来し、英語の plume と同語根。英語の feather が一般的な羽を指すのに対し、plume は装飾的な羽・飾り羽根を指す。かつて羽根ペン（pluma de ave）で書いていたことから「ペン」の意味にも広がった。' },
  'plumaje': { es: 'El plumaje colorido del quetzal lo convierte en uno de los pájaros más hermosos del mundo.', ja: 'ケツァールの色鮮やかな羽毛は、この鳥を世界で最も美しい鳥の一つにしている。', trivia: 'pluma（羽）に集合名詞の接尾辞 -aje を加えた派生語で、英語の plumage と語形・意味ともにほぼ一致する。ラテン語 pluma に由来し、英語では plumage がそのままの形で使われる（フランス語経由で英語に入った）。' },
  'plural': { es: 'Una sociedad plural acepta y valora la diversidad de opiniones y culturas.', ja: '多元的な社会は、意見や文化の多様性を受け入れ、尊重する。', trivia: 'ラテン語 pluralis（複数の）に由来し、英語の plural と同形・同語根。語根 plus / plur-（より多く）は英語の plus、surplus、plurality などにも共通しており、「多さ」を表す語族を形成している。' },
  'plus': { es: 'Los empleados que trabajan los fines de semana reciben un plus por disponibilidad.', ja: '週末に働く従業員は特別手当を受け取る。', trivia: 'ラテン語 plus（より多く）がそのままスペイン語に入った語で、英語の plus と完全に同語根・同形。英語では主に数学的な「プラス」や「利点」の意味で使うが、スペイン語では「追加手当・特別給付」の意味でよく使われる点が実用上異なる。' },
  'plusvalía': { es: 'La plusvalía de su piso aumentó considerablemente gracias a las mejoras del barrio.', ja: '地区の整備のおかげで、彼のマンションの資産価値が大幅に上がった。', trivia: 'スペイン語 plus（より多く）と valía（価値）を合わせた造語で、マルクス経済学の「剰余価値（surplus value）」の訳語としても使われる。英語では capital gain（資本利得）または surplus value（剰余価値）に相当し、直接の同語根英単語はない。' },
  'población': { es: 'La población de la ciudad ha crecido un veinte por ciento en la última década.', ja: 'この都市の人口は過去10年間で20パーセント増加した。', trivia: 'ラテン語 populatio（人々の集まり）に由来し、英語の population と同語根。英語の people や public も同じ語根 populus（民、人々）を持つが、population が最も直接的な対応語。スペイン語では「集落・村」の意味でも使われる点が英語との違い。' },
  'poblado': { es: 'El camino atravesaba un pequeño poblado de apenas doscientos habitantes.', ja: 'その道はわずか200人ほどの小さな集落を通り抜けていた。', trivia: '動詞 poblar（住まわせる）の過去分詞が名詞・形容詞化したもので、ラテン語 populare に由来する。英語の populated（人が住む）と同語根だが、名詞として「集落・小村」を指す用法は英語の hamlet や settlement に相当する。' },
  'poblar': { es: 'Los colonos españoles comenzaron a poblar estas tierras a partir del siglo XVI.', ja: 'スペイン人入植者たちは16世紀からこの土地に移り住み始めた。', trivia: 'ラテン語 populare（人々を住まわせる）に由来し、英語の populate と同語根。英語の populate がそのまま対応するほか、people（人々で満たす）も類縁の用法を持つ。語幹 pueb- は不規則な二重母音化（o→ue）を示す典型例。' },
  'pobreza': { es: 'La pobreza extrema sigue siendo uno de los mayores desafíos a nivel mundial.', ja: '極度の貧困は依然として世界規模で最大の課題の一つだ。', trivia: 'ラテン語 paupertas（貧しさ）ではなく pauper の俗ラテン語形 pober に由来するとされ、英語の poverty と同語根。英語では poverty がそのまま対応し、poor（貧しい）と同じ語源から派生した語族を形成している。' },
  'pocillo': { es: 'Me tomé un pocillo de café bien cargado antes de empezar a trabajar.', ja: '仕事を始める前に、濃いコーヒーを小カップ一杯飲んだ。', trivia: 'poco（少し）または pozo（井戸・くぼみ）の縮小形に由来するとする説がある。英語では demitasse（フランス語由来で「半カップ」の意）が近い概念に相当し、直接の同語根英単語はない。中南米では espresso カップや計量カップとして広く使われる。' },
  'a poco de': { es: 'A poco de llegar al hotel, empezó a llover a cántaros.', ja: 'ホテルに着いてすぐ、土砂降りの雨が降り始めた。', trivia: 'poco はラテン語 paucus（少ない）に由来し、英語の few や paucity と同語根。この前置詞句 a poco de は「〜から少しの時間で」という意味で、英語の shortly after や soon after に相当する表現。' },
  'por poco': { es: 'Por poco me caigo por las escaleras cuando llevaba las bolsas de la compra.', ja: '買い物袋を持っていたとき、もう少しで階段から落ちるところだった。', trivia: 'poco（少し）はラテン語 paucus（少ない）に由来し、英語の paucity（不足）と同語根。por poco という副詞句は英語の almost や nearly に相当するが、「実際には起きなかった」という含意が強く、英語の it was a close call（危ういところだった）のニュアンスに近い。' },
  'podar': { es: 'Es mejor podar los rosales en otoño para que florezcan con fuerza en primavera.', ja: '春に力強く咲くよう、秋にバラを剪定するのが望ましい。', trivia: 'ラテン語 putare（切る、考える）に由来するとされ、英語の prune（剪定する）と意味的に対応するが、prune は古フランス語 proignier 経由で語根は異なる。英語の compute（計算する）や dispute（議論する）も同じ putare（考える・整える）から派生した遠縁語。' },
  'poderdante': { es: 'El poderdante firmó el documento para que su abogado pudiera actuar en su nombre.', ja: '委任者は、弁護士が自分の代理として行動できるよう書類に署名した。', trivia: 'ラテン語の「potere（力を持つ）」に由来する「poder（権力・委任）」と、行為者を表す接尾辞「-ante」が結合した法律用語。英語では "principal" または "grantor of power of attorney" に相当し、英語圏の法律文書の「principal」と概念は同じだが語形は大きく異なる。' },
  'poderío': { es: 'El poderío económico de ese país ha crecido enormemente en las últimas décadas.', ja: 'その国の経済力はここ数十年で著しく成長した。', trivia: 'ラテン語「potere（できる、力を持つ）」に由来し、接尾辞「-ío」が「集合的な力・勢力」のニュアンスを加えた語。英語の "power" や "might" と同語根であり、英語の "potent"（強力な）とも共通の祖先を持つ。' },
  'poderoso': { es: 'El medicamento resultó ser muy poderoso contra la infección.', ja: 'その薬は感染症に対して非常に効果的であることが判明した。', trivia: 'ラテン語「potens（力のある）」の系統を引き、スペイン語「poder」に形容詞接尾辞「-oso」を加えた語。英語の "powerful" にほぼ対応し、"potent"（効力のある）や "omnipotent"（全能の）とも同語根。' },
  'podredumbre': { es: 'La podredumbre del sistema político tardó décadas en salir a la luz.', ja: '政治システムの腐敗が表に出るまでに数十年かかった。', trivia: 'ラテン語「putridus（腐った）」から派生した「pudrir / podrir（腐る）」と、状態・集合を表す接尾辞「-dumbre」が結合した語。英語の "putrid"（腐敗した）や "purulent" と同語根であり、英語では "rot"「decay""corruption" に相当する。' },
  'podrición': { es: 'La podrición del árbol comenzó desde las raíces y se fue extendiendo hacia arriba.', ja: '木の腐敗は根から始まり、徐々に上へと広がっていった。', trivia: '「podrir / pudrir（腐る）」にラテン語由来の名詞接尾辞「-ción」を加えた語で、「podredumbre」のより技術的・地域的な変形。英語の "putrefaction"（腐敗）と同語根であり、どちらもラテン語「putrefacere」に遡る。' },
  'poema': { es: 'Escribió un poema dedicado a su ciudad natal que emocionó a todos los presentes.', ja: '彼は故郷の街に捧げた詩を書き、その場にいた全員を感動させた。', trivia: 'ギリシャ語「poiema（作られたもの）」からラテン語「poema」を経てスペイン語に入った語。英語の "poem" と完全に同語根・同形で、詩の一編を指す点も共通。語根の「poiein（作る）」は英語の "poet" や "poetry" にも通じる。' },
  'poesía': { es: 'La poesía de Federico García Lorca sigue siendo leída en todo el mundo.', ja: 'フェデリコ・ガルシア・ロルカの詩は今日も世界中で読まれている。', trivia: 'ギリシャ語「poiesis（創造、制作）」からラテン語「poesis」を経た語で、英語の "poetry" と同語根。ただし「poesía」は詩というジャンル全体や詩情を指す集合的な語として使われ、個々の詩は "poema" を用いる点が英語の "poetry" と "poem" の使い分けに対応する。' },
  'poeta': { es: 'La poeta chilena Gabriela Mistral fue la primera latinoamericana en ganar el Nobel de Literatura.', ja: 'チリの詩人ガブリエラ・ミストラルは、ノーベル文学賞を受賞した最初のラテンアメリカ人だった。', trivia: 'ギリシャ語「poietes（作る人）」からラテン語「poeta」を経た語で、英語の "poet" と完全に同語根。スペイン語では男女両性に「poeta」を使うことが多いが、近年は女性に「poetisa」や「la poeta」の形も用いられる。' },
  'poética': { es: 'La poética de Aristóteles sentó las bases de la crítica literaria occidental.', ja: 'アリストテレスの詩学は西洋文学批評の基礎を築いた。', trivia: 'ギリシャ語「poietike（詩の技術）」に由来し、英語の "poetics" と同語根・同義。名詞としては詩論・詩学の体系を指し、形容詞としては「詩的な」を意味する点で、英語の "poetic" と重なる。' },
  'polainas': { es: 'Los soldados llevaban polainas de cuero para protegerse las piernas del barro.', ja: '兵士たちは泥から足を守るために革のゲートルを着けていた。', trivia: '語源は諸説あり、フランス語「poulaine（先の尖った靴）」またはスペイン語「Polonia（ポーランド）」に由来するとも言われる。英語では "gaiters" に相当し、英語の "gaiters" はフランス語「guêtre」から来ているため、両語は語源が異なる。' },
  'polar': { es: 'El oso polar está perfectamente adaptado para sobrevivir en el Ártico.', ja: 'シロクマは北極で生き延びるために完璧に適応している。', trivia: 'ラテン語「polus（極）」に形容詞接尾辞「-ar」を加えた語で、英語の "polar" と完全に同語根・同形・同義。さらに「polus」はギリシャ語「polos（軸、天の極）」に遡り、英語の "pole" とも共通の祖先を持つ。' },
  'polarización': { es: 'La polarización política en el país ha dificultado llegar a acuerdos entre los partidos.', ja: 'その国の政治的二極化により、政党間での合意形成が困難になっている。', trivia: '「polar」に動詞化接尾辞「-izar」と名詞化接尾辞「-ción」を重ねた語。英語の "polarization" と完全に同語根・同義であり、光学的な偏光から社会的・政治的な二極化まで同様の意味範囲をカバーする点も共通。' },
  'polarizar': { es: 'El discurso del presidente terminó por polarizar aún más a la sociedad.', ja: '大統領の演説は社会をさらに二極化させる結果となった。', trivia: '「polar」に接尾辞「-izar」を加えた動詞で、英語の "to polarize" と同語根・同義。「-izar」はギリシャ語由来の「-ize」と対応しており、英語・スペイン語ともに科学用語から社会的文脈へ意味が拡張した点で平行した歴史を持つ。' },
  'polen': { es: 'En primavera, hay mucho polen en el ambiente y muchas personas sufren alergias.', ja: '春には空気中に花粉が多く、アレルギーに悩む人が多い。', trivia: 'ラテン語 pollen（細かい粉、小麦粉の粉）に由来し、英語の pollen とそのままの形で一致する国際語。英語の pulverize（粉砕する）やスペイン語の polvo（粉・埃）と同じ語根を持つという説もある。' },
  'polémica': { es: 'La decisión del alcalde generó una gran polémica entre los vecinos del barrio.', ja: '市長の決定は地区の住民の間で大きな論争を引き起こした。', trivia: 'ギリシャ語「polemikos（戦争の、戦闘的な）」からラテン語「polemica」を経た語で、英語の "polemic" や "polemics" と同語根。英語では "controversy" の方が日常的だが、"polemic" も論争・論駁の意味で使われる。' },
  'polémico': { es: 'El libro fue muy polémico porque desafiaba creencias religiosas tradicionales.', ja: 'その本は伝統的な宗教的信念に挑戦するものだったため、非常に物議を醸した。', trivia: 'ギリシャ語「polemikos（戦争に関する）」に由来し、英語の "polemical" や "controversial" に相当。英語の "controversial" はラテン語「controversia」から来ており語源が異なるが、現代では両語がほぼ同じ文脈で使われる好例。' },
  'policía': { es: 'Llamamos a la policía cuando vimos que alguien intentaba forzar la puerta.', ja: '誰かがドアをこじ開けようとしているのを見て、私たちは警察に電話した。', trivia: 'ギリシャ語 polis（都市国家）に由来し、英語の police（警察）と同語根。politics（政治）、policy（政策）、metropolis（大都市）なども同じ polis を語源とする英単語である。' },
  'policial': { es: 'La novela policial me mantuvo en vilo hasta la última página.', ja: 'その警察小説は最後のページまで私をハラハラさせ続けた。', trivia: 'policía（警察）から派生した形容詞で、英語の police に相当する。英語では police procedural（警察手続き物語）や detective novel のような表現が使われるが、スペイン語では novela policial という簡潔な一語で表せる。' },
  'política': { es: 'La política exterior del país ha cambiado considerablemente en los últimos años.', ja: 'その国の外交政策はここ数年で大きく変わった。', trivia: 'ギリシャ語 politiká（市民生活に関すること）に由来し、英語の politics（政治）、policy（政策）と同語根。古代ギリシャの polis（都市国家）が語源で、英語の cosmopolitan（世界市民的な）や megalopolis（巨大都市）にも受け継がれている。' },
  'póliza': { es: 'El seguro de vida cubre los gastos según lo estipulado en la póliza.', ja: '生命保険は、保険証券に定められた条件に従って費用をカバーする。', trivia: 'イタリア語 polizza（証書）を経由し、さらに中世ラテン語 apodissa、ギリシャ語 apódeixis（証明・領収書）に遡るとされる。英語には直接の同語根語はなく、英語では policy（保険証券）が対応するが、英語の policy（政策）とはギリシャ語の別々の語源を持つ同音語である。' },
  'polizón': { es: 'Descubrieron a un polizón escondido en la bodega del barco a mitad del trayecto.', ja: '航行の途中、船倉に隠れていた密航者が発見された。', trivia: '語源には諸説あり、スペイン語の poliza（証書）の派生形とする説や、別系統の俗語に由来するという説もある。英語では stowaway（密航者）に相当し、「積み荷に紛れ込む者」というイメージが共通している。' },
  'polo': { es: 'Los científicos estudian el derretimiento del hielo en el polo norte debido al cambio climático.', ja: '科学者たちは気候変動による北極の氷の融解を研究している。', trivia: 'ラテン語 polus、さらにギリシャ語 pólos（軸・天の極）に由来し、英語の pole（極・棒）と同語根。スポーツの polo はチベット語 pulu（玉）に由来する別系統の単語で、スペイン語・英語ともに同形ながら語源が全く異なる同音異義語が並存している。' },
  'polución': { es: 'La polución del río afecta gravemente a la fauna y la flora de la zona.', ja: '川の汚染はその地域の動植物に深刻な影響を与えている。', trivia: 'ラテン語 pollutio（汚すこと）に由来し、英語の pollution（汚染）と同語根・ほぼ同形の国際語。ラテン語 polluere（汚す）が共通の語源で、英語でも環境問題の文脈で広く使われる。' },
  'polvo': { es: 'Había tanto polvo en la habitación que empezamos a estornudar nada más entrar.', ja: '部屋の中が埃だらけで、入った途端にくしゃみが出始めた。', trivia: 'ラテン語 pulvis（粉・塵）に由来し、英語の powder（粉末）はフランス語経由で同じ pulvis から来ている。英語の pulverize（粉砕する）や pulmonary（肺の）とも語根を共有するという説もある。' },
  'pólvora': { es: 'El olor a pólvora llenó el aire después de los fuegos artificiales.', ja: '花火の後、火薬の匂いが空気に満ちた。', trivia: 'ラテン語 pulvis（粉・塵）に由来し、英語の powder（粉末、火薬）と同語根。英語の gunpowder がスペイン語では pólvora 一語に対応する。' },
  'ponderación': { es: 'La ponderación de los distintos factores fue clave para tomar una buena decisión.', ja: 'さまざまな要因を慎重に検討したことが、良い判断を下す上で重要だった。', trivia: 'ラテン語 ponderatio（重さを量ること）に由来し、英語の ponderation（熟考）と同語根。英語の ponder（熟考する）やponderous（重い、重々しい）とも同じ語根を共有する。' },
  'ponderar': { es: 'Antes de firmar el contrato, el abogado ponderó cuidadosamente cada cláusula.', ja: '契約書にサインする前に、弁護士は各条項を慎重に検討した。', trivia: 'ラテン語 ponderare（重さを量る）に由来し、英語の ponder（熟考する）と同語根。pondus（重さ）はさらに pound（ポンド、重量単位）の語源ともなっている。' },
  'ponente': { es: 'La ponente explicó sus investigaciones con gran claridad ante el auditorio.', ja: '発表者は聴衆の前で自分の研究を非常にわかりやすく説明した。', trivia: 'ラテン語 ponere（置く・提示する）の現在分詞 ponens から来ており、英語では presenter や rapporteur（フランス語借用）に相当する。component（構成要素）や proponent（提唱者）も同じ ponere を語源とする英語である。' },
  'ponzoña': { es: 'La ponzoña de la serpiente puede ser mortal si no se trata a tiempo.', ja: 'ヘビの毒は、適切に処置しなければ命に関わることがある。', trivia: 'ラテン語 potio（飲み物）が俗ラテン語 potionem を経てスペイン語に入ったとされ、英語の poison（毒）と実は同語根である。英語の potion（薬液）とも兄弟語にあたる。' },
  'pop': { es: 'Me encanta escuchar música pop mientras hago ejercicio.', ja: '運動しながらポップミュージックを聴くのが大好きだ。', trivia: '英語 pop（popular music の略）からの借用語で、20世紀半ばに世界中に広まった。英語の popular（大衆的な）はラテン語 populus（民衆）に由来し、スペイン語の pueblo（村・人民）と同語根である。' },
  'popularidad': { es: 'La popularidad de esa cantante ha crecido enormemente en los últimos años.', ja: 'その歌手の人気はここ数年で著しく高まった。', trivia: 'ラテン語 popularis（民衆の）に由来し、英語の popularity と同語根・同形の国際語。スペイン語の pueblo（人々・村）、英語の public（公衆）もすべてラテン語 populus（民衆）を共通の祖先に持つ。' },
  'populacho': { es: 'Los políticos suelen ignorar al populacho cuando toman decisiones importantes.', ja: '政治家たちは重要な決定を下す際、庶民をないがしろにしがちだ。', trivia: 'ラテン語 populus（民衆）に軽蔑的な指小辞 -acho が付いた形で、英語には直接の対応語がなく hoi polloi（大衆）や rabble（烏合の衆）が近い。英語の popular や people とも同じ populus を語根とする。' },
  'popularizar': { es: 'Las redes sociales han logrado popularizar estilos de música que antes solo conocían pocos aficionados.', ja: 'ソーシャルメディアは、以前はごく一部のファンしか知らなかった音楽スタイルを普及させることに成功した。', trivia: 'ラテン語 popularis（民衆の）に由来し、英語の popularize と完全に同語根。接尾辞 -izar（英 -ize）を持つ動詞で、「〜にする」という意味を加える点も英語と共通している。' },
  'por': { es: 'Te llamo por teléfono esta noche para confirmar los detalles del viaje.', ja: '旅の詳細を確認するために、今夜電話するね。', trivia: 'ラテン語の前置詞 per（〜を通じて）に由来し、英語の for や by に相当する多義語。英語の per（〜につき）とは同語根であり、「por hora（1時間につき）」などの用法にその痕跡が見られる。' },
  'porvenir': { es: 'Estudia con dedicación si quieres asegurarte un buen porvenir.', ja: 'よい将来を確保したいなら、熱心に勉強しなさい。', trivia: 'スペイン語の前置詞 por と動詞 venir（来る）が合わさった合成語で、「これから来るもの」という意味。英語の future に相当するが、英語には同じ構造の合成語はなく、ラテン語 futurus（未来の）から直接派生した future が使われる。' },
  'porcentaje': { es: 'Un alto porcentaje de los estudiantes aprobó el examen final sin dificultad.', ja: 'かなり高い割合の学生が、難なく期末試験に合格した。', trivia: 'ラテン語 per centum（100につき）に由来し、英語の percentage と同語根。スペイン語では por ciento（パーセント）という句もあり、porcentaje はその名詞形として定着した。' },
  'porción': { es: 'El camarero trajo una porción generosa de paella para cada comensal.', ja: 'ウェイターは各食事客に気前のよい量のパエリアを運んできた。', trivia: 'ラテン語 portio（分け前）に由来し、英語の portion と同語根・同形でほぼ同義のコグネート。「比例」を意味する proportion（スペイン語 proporción）も同じ語根を持つ。' },
  'pormenor': { es: 'El abogado explicó los pormenores del contrato antes de que su cliente lo firmara.', ja: '弁護士は依頼人が署名する前に、契約の細部を説明した。', trivia: 'スペイン語の por（〜につき）と menor（より小さい）の合成語で、「より小さなことについて」から「詳細」の意味になった。英語の detail に相当するが、por + menor という構造は英語にはなく、スペイン語独自の語形成の例である。' },
  'porque': { es: 'No pude salir a caminar porque estaba lloviendo muy fuerte.', ja: '雨がひどく降っていたので、散歩に出られなかった。', trivia: 'por（〜のために）と que（〜ということ）が融合した接続詞で、英語の because に相当する。英語の because は be（by）+ cause（原因）の合成語で語源は異なるが、いずれも「原因・理由」を示す点は共通している。' },
  'porquería': { es: 'La habitación estaba llena de porquerías; tardamos horas en limpiarla.', ja: '部屋はガラクタだらけで、掃除するのに何時間もかかった。', trivia: 'スペイン語の puerco / puerco（豚）に由来し、豚のイメージから「不潔なもの・くだらないもの」へ意味が拡張した。英語の filth や junk に相当するが、英語の pork（豚肉）とは同じラテン語 porcus（豚）を語源とする遠い親戚にあたる。' },
  'porche': { es: 'En las tardes de verano, la familia se reúne en el porche para tomar el fresco.', ja: '夏の夕方、家族はポーチに集まって涼みます。', trivia: 'フランス語の porche を経由して、ラテン語 porticus（柱廊）に由来する。英語の porch と同語源・同形のコグネートで、意味もほぼ同じ。ラテン語 porta（門）とも関連しており、スペイン語の portal や portico と語根を共有している。' },
  'porra': { es: 'El policía llevaba una porra en el cinturón durante el servicio.', ja: '警察官は勤務中にベルトに警棒を携帯していた。', trivia: '語源は諸説あり、ラテン語 porrum（ネギ）に由来するという説や、棒状の形を表す擬音的な語根とする説がある。英語の baton や club に相当するが直接の語根的関連はなく、スペイン語圏特有の食べ物（太いチュロス）や俗語用法にも広がった興味深い多義語である。' },
  'porrazo': { es: 'Se dio un porrazo tremendo con la puerta al no ver que estaba cerrada.', ja: 'ドアが閉まっているのに気づかず、ものすごく激突した。', trivia: 'porra（棍棒）に増大辞 -azo を加えた派生語で、「強い打撃・激突」を意味する。英語では「strong blow」や「thud」に相当するが、英語の -azo に相当する増大辞はなく、スペイン語の語形成の特徴である。接尾辞 -azo 自体は「一撃」を表す生産的な語形成要素である。' },
  'portaaviones': { es: 'El portaaviones nuclear navegó durante semanas sin necesidad de repostar combustible.', ja: 'その原子力空母は燃料補給なしに何週間も航行した。', trivia: 'portar（運ぶ）と aviones（飛行機の複数形）の合成語で、「飛行機を運ぶ（もの）」の意。英語の aircraft carrier と同じ発想の合成語だが、英語は「航空機を運ぶもの」、スペイン語は「飛行機を運ぶもの」という構造で、両者の語形成の論理が対応している。' },
  'portador': { es: 'El médico explicó que una persona puede ser portadora del virus sin presentar síntomas.', ja: '医師は、ウイルスのキャリアでも症状が出ないことがあると説明した。', trivia: 'ラテン語 portare（運ぶ）＋動作主を表す接尾辞 -dor に由来し、英語の carrier や bearer に相当する。英語の porter（荷物運び人）とは同語根のコグネートで、いずれも「物を運ぶ人」という原義を持つ。' },
  'portaesquís': { es: 'Instalamos el portaesquís en el techo del coche antes de salir hacia la estación de esquí.', ja: 'スキー場へ出発する前に、車の屋根にスキーキャリアを取り付けた。', trivia: 'portar（運ぶ）と esquís（スキーの複数形）の合成語。esquís 自体はノルウェー語 ski に由来し、英語でも ski として同形で使われる。スペイン語の porta- 合成語（portamaletas、portavoz など）は英語の -carrier や -holder に相当する生産的な語形成パターンである。' },
  'portal': { es: 'Nos quedamos charlando un rato en el portal del edificio antes de despedirnos.', ja: '別れを告げる前に、建物の玄関ホールでしばらくおしゃべりした。', trivia: 'ラテン語 porta（門・扉）に由来し、英語の portal と同語根・同形のコグネート。インターネットの「ポータルサイト」という現代的用法は英語から借用されたが、「玄関・入口」という語本来の意味は両言語で共通している。' },
  'estandarte': { es: 'Los soldados llevaban el estandarte del regimiento al frente de la formación.', ja: '兵士たちは隊列の先頭に連隊の軍旗を掲げていた。', trivia: '古フランス語 estandart を経由してゲルマン語に由来し、英語の standard（旗・基準）と同語根のコグネート。英語の standard が「旗」から「基準・規格」という意味に拡張したのと同様に、スペイン語の estandarte も象徴・旗印という意味で使われる。' },
  'portar': { es: 'En algunos países está prohibido portar armas de fuego sin licencia.', ja: '一部の国では、免許なしに銃器を携帯することが禁止されている。', trivia: 'ラテン語 portare（運ぶ）に直接由来し、英語の transport の -port 部分と同語根。英語の carry に相当するが、英語では port という動詞も（軍事・技術用語として）「携行する」の意味で使われ、これも同語根のコグネートである。' },
  'portavoz': { es: 'La portavoz del gobierno compareció ante los medios para explicar la nueva medida.', ja: '政府の報道官はメディアの前に出て、新しい措置について説明した。', trivia: 'portar（運ぶ）と voz（声、ラテン語 vox に由来）の合成語で、「声を運ぶ人」の意。英語の spokesperson も「人々の声を代弁する人」という同じ発想の合成語であり、voz は英語の voice と同語根のコグネートである。' },
  'porte': { es: 'El actor entró en la sala con un porte elegante que llamó la atención de todos.', ja: 'その俳優は優雅な立ち居振る舞いで会場に入り、全員の注目を集めた。', trivia: 'ラテン語 portare（運ぶ）に由来し、英語の carriage（身のこなし・馬車）に意味が近い。英語の import/export の -port とも同語根で、「運ぶ」という原義から「（荷物の）運賃」と「身のこなし」という二つの意味が派生したユニークな語である。' },
  'portero': { es: 'El portero del edificio nos avisó de que había un paquete esperándonos en la recepción.', ja: '建物の管理人が、受付に荷物が届いていると知らせてくれた。', trivia: 'ラテン語 porta（門）＋職業を表す接尾辞 -ero に由来し、英語の doorman や porter（門番・荷物運び）と同語根。英語の porter は「荷物を運ぶ人」の意味でも使われるが、これもラテン語 portare（運ぶ）と porta（門）という近縁の語根から派生した多義語群の一部である。' },
  'portezuela': { es: 'Abrió la portezuela del coche y ayudó a la anciana a subir.', ja: '彼は車のドアを開けて、老女が乗り込むのを手伝った。', trivia: 'puerta（扉）の指小辞形で、ラテン語 porta（門）に由来する。英語の door に相当するが、英語に door の指小辞形はなく、スペイン語の -zuela/-zuelo という指小辞の豊かな語形成が特徴的。英語では「car door」と複合語で表すが、スペイン語では一語で小ささ・限定性を表現できる。' },
  'pórtico': { es: 'Los turistas fotografiaban el majestuoso pórtico de la catedral antes de entrar.', ja: '観光客たちは中に入る前に、大聖堂の壮大な柱廊玄関を撮影した。', trivia: 'ラテン語 porticus（柱廊）に由来し、英語の portico と同語根・同形のコグネートで意味も同じ。ラテン語 porta（門）と同語根であり、英語では stoic philosophy の発祥の地 Stoa（ギリシャ語の柱廊）とは別語源である点に注意。' },
  'portón': { es: 'El granjero abrió el enorme portón de madera para dejar pasar el tractor.', ja: '農場主はトラクターを通すために、大きな木の門を開けた。', trivia: 'puerta（扉）または porta（門）に増大辞 -ón を加えた派生語で、「大きな門・扉」を意味する。英語には同じ増大辞の仕組みはなく、「large gate」や「hatchback」などで表す。ラテン語 porta を語根とし、portal、portero などと同じ語族に属する。' },
  'portugués': { es: 'Mi vecina es portuguesa y me enseña algunas palabras en portugués de vez en cuando.', ja: '隣人はポルトガル人で、時々ポルトガル語の単語を教えてくれる。', trivia: '地名 Portugal に由来し、Portugal 自体はラテン語 Portus Cale（カレの港）に由来する地名。英語の Portuguese と同語根で同義のコグネートであり、スペイン語とポルトガル語は語彙の約89%を共有するという点でも興味深い隣接言語の関係にある。' },
  'posa': { es: 'A lo lejos se oyó la posa de la campana anunciando el funeral.', ja: '遠くから、葬儀を告げる鐘の葬送の音が聞こえた。', trivia: 'ラテン語 pausa（休止）に由来し、英語の pause と同語根。スペインの民俗的文脈では鐘の葬送の合間の「一息」を指す特殊な用法がある。' },
  'posada': { es: 'Los viajeros encontraron una posada acogedora al borde del camino donde pasar la noche.', ja: '旅人たちは道沿いに居心地のよい宿屋を見つけ、そこで一晩過ごした。', trivia: '動詞 posar（置く、泊まる）の過去分詞が名詞化したもので、ラテン語 pausare に遡る。英語の inn や lodge に相当し、メキシコではクリスマス前夜祭の伝統行事「ポサダ」としても知られる。' },
  'posaderas': { es: 'El niño se cayó y se golpeó las posaderas contra el suelo.', ja: '子供が転んで、お尻を地面に強くぶつけた。', trivia: 'posar（腰を下ろす）から派生した語で、「座る部分」という意味合いを持つ。英語には直接の同語根語はなく、buttocks や rear に相当するが、やや婉曲的・ユーモラスなニュアンスがある点でも英語の derrière（フランス語借用）に近い。' },
  'posadero': { es: 'El posadero nos recomendó el plato típico de la región con mucho entusiasmo.', ja: '宿屋の主人は、その地域の名物料理を大いに薦めてくれた。', trivia: 'posada（宿屋）に職業を表す接尾辞 -ero を付けた語。英語では innkeeper に相当し、inn も同じラテン語 pausare 系統の語との意味的並行性がある。' },
  'posar': { es: 'La modelo posó durante horas para que el pintor pudiera capturar cada detalle.', ja: '画家がすべての細部を捉えられるよう、モデルは何時間もポーズをとり続けた。', trivia: 'ラテン語 pausare（休止する、止まる）に由来し、英語の pause と同語根。フランス語経由で「ポーズをとる」意味が加わったとされ、英語 pose もフランス語 poser から借用している。' },
  'posavasos': { es: 'Siempre pongo un posavasos debajo del vaso para no manchar la mesa.', ja: 'テーブルを汚さないように、グラスの下には必ずコースターを置く。', trivia: 'posa（置く、posar の命令形）と vasos（グラスの複数形）を組み合わせた複合語で、「グラスを置くもの」という意味。英語の coaster は「沿岸航行船」が原義で全く異なる語源だが、同じ道具を指す。' },
  'pose': { es: 'Su pose de superioridad no convence a nadie en la oficina.', ja: '彼の優越感のポーズは、オフィスで誰にも通じない。', trivia: 'フランス語 pose を経由して英語にも入り、スペイン語・英語ともに pose として使われる国際的な借用語。ラテン語 pausare が根本にあるが、「気取り・見せかけ」の意味は近代フランス語で発展した。' },
  'poseedor': { es: 'El poseedor del título de campeón tendrá que defenderlo el próximo mes.', ja: 'チャンピオンの称号の保持者は、来月それを防衛しなければならない。', trivia: '動詞 poseer（所有する）の行為者名詞で、ラテン語 possidere（所有する）に由来する。英語の possessor と完全に同語根であり、スペルも意味もほぼ対応している。' },
  'posesión': { es: 'El equipo mantuvo la posesión del balón durante la mayor parte del partido.', ja: 'チームは試合のほとんどの時間、ボール支配率を維持した。', trivia: 'ラテン語 possessio（占有）に直接由来し、英語の possession と同語根・同形の学術・法律用語。サッカー用語「ポゼッション」としても日本語に入っており、三言語で共通して使われる。' },
  'posesivo': { es: 'En español, los adjetivos posesivos concuerdan en número con el sustantivo al que acompañan.', ja: 'スペイン語では、所有形容詞は修飾する名詞と数において一致する。', trivia: 'ラテン語 possessivus に由来し、英語の possessive と同語根で形容詞・文法用語両方に使う。英語では possessive が「独占欲の強い」という感情的な意味でも頻繁に使われる点は共通している。' },
  'posguerra': { es: 'Durante la posguerra, muchas familias tuvieron que reconstruir sus vidas desde cero.', ja: '戦後の時代、多くの家族がゼロから生活を再建しなければならなかった。', trivia: '接頭辞 pos-（ラテン語 post、後）と guerra（戦争）を組み合わせた語。英語の postwar と完全に対応しており、post- という接頭辞は英語・スペイン語ともにラテン語 post から共通して受け継いでいる。' },
  'posibilidad': { es: 'Existe la posibilidad de que el vuelo llegue con retraso debido a la tormenta.', ja: '嵐のせいでフライトが遅延する可能性がある。', trivia: 'ラテン語 possibilitas（可能なこと）に由来し、英語の possibility と同語根。ラテン語 posse（できる）が共通の祖先で、英語の possible・power とも遠い親戚にあたる。' },
  'posibilitar': { es: 'El acuerdo entre los dos países posibilitó el libre comercio en la región.', ja: '両国間の合意が、その地域における自由貿易を可能にした。', trivia: 'posible（可能な）に動詞化接尾辞 -itar を付けた語で、英語には直訳する動詞がなく enable や make possible で表現する。ラテン語 possibilis を起源とする点で英語の possible と同語根。' },
  'posición': { es: 'El gobierno explicó su posición oficial sobre el cambio climático ante la prensa.', ja: '政府は気候変動に関する公式見解を報道陣の前で説明した。', trivia: 'ラテン語 positio（置かれた状態）に由来し、英語の position と同語根で形・意味ともほぼ一致する。ラテン語 ponere（置く）が共通の祖先で、英語の compose・deposit なども同じ語根を持つ。' },
  'positivar': { es: 'El fotógrafo tardó horas en positivar los negativos de la película analógica.', ja: '写真家はアナログフィルムのネガを現像するのに何時間もかかった。', trivia: 'positivo（ポジティブ）を動詞化した語で、写真用語としての「ネガからポジを作る」意味が主。英語には対応する一語の動詞はなく develop や make a print などで表現する。positive 自体はラテン語 positivus に由来する共通語根。' },
  'positivismo': { es: 'El positivismo de Auguste Comte influyó profundamente en las ciencias sociales del siglo XIX.', ja: 'オーギュスト・コントの実証主義は、19世紀の社会科学に深い影響を与えた。', trivia: 'フランスの哲学者コントが提唱した思想に由来し、英語の positivism と完全に同語根・同形。ラテン語 positivus（実際に置かれた）を起源とし、形而上学を排して観察・経験のみを重視する立場を指す。' },
  'positivo': { es: 'El resultado de la prueba fue positivo, así que el médico le recetó antibióticos.', ja: '検査結果が陽性だったため、医師は抗生物質を処方した。', trivia: 'ラテン語 positivus（明確に置かれた、実際の）に由来し、英語の positive と同語根で形・意味ともほぼ対応する。数学の「正の数」から医療の「陽性」、写真の「ポジ」まで多義的な点も英語と共通している。' },
  'posponer': { es: 'Tuvimos que posponer la reunión porque varios miembros estaban enfermos.', ja: '数名のメンバーが体調不良だったため、会議を延期せざるを得なかった。', trivia: 'ラテン語 postponere（後ろに置く）に直接由来し、英語の postpone と同語根で意味・構造ともほぼ同一。post-（後）と ponere（置く）の組み合わせで、スペイン語では pos- と表記される。' },
  'posta': { es: 'El equipo ganó la medalla de oro en la carrera de posta de cuatro por cien metros.', ja: 'チームは400メートルリレー競走で金メダルを獲得した。', trivia: 'イタリア語 posta（置かれたもの、中継所）を経由してラテン語 posita（置かれた）に由来する。英語の post（郵便、柱）と同語根で、中世ヨーロッパの馬による中継輸送システムから「リレー」の意味が生まれた。' },
  'postal': { es: 'Le envié una postal desde Sevilla con una foto de la Giralda.', ja: 'ヒラルダ塔の写真が入った絵はがきをセビリアから送った。', trivia: 'ラテン語 posta（中継所・郵便）に形容詞化接尾辞 -al を付けた語で、英語の postal と同語根・同形。英語では postal と postcard を使い分けるが、スペイン語では postal だけで絵はがきを指す名詞としても機能する。' },
  'poste': { es: 'El balón golpeó el poste y salió fuera en el último minuto del partido.', ja: '試合終了間際にボールがゴールポストに当たって外に出た。', trivia: 'ラテン語 postis（柱、扉の柱）に由来し、英語の post（柱、電柱）と同語根。英語 post は「郵便」の意味でも使われるが、これは別経路（馬の中継所）の同形語であり、「柱」の post とは別語源とする説が有力。' },
  'postergación': { es: 'La postergación del proyecto causó pérdidas millonarias para la empresa.', ja: 'プロジェクトの延期は、会社に数百万の損失をもたらした。', trivia: 'ラテン語 posterus（後の）に由来する postergar の名詞形。英語には直接対応する一語がなく postponement や deferral で表現する。英語の posterior（後部の）や posterity（後世）と同語根で、すべてラテン語 post（後）に遡る。' },
  'postergar': { es: 'No deberías postergar más la visita al médico; lleva meses con esa tos.', ja: '医者への受診をこれ以上先延ばしにすべきではない。もう何ヶ月もあの咳が続いている。', trivia: 'ラテン語 posterus（後に来る）＋ agere（行う）の合成語に由来するとも、単純に post-（後）から派生したとも言われる。英語の postpone に意味が近いが語根は異なり、英語 posterity（後世）とは語根を共有する。' },
  'posteridad': { es: 'El artista esperaba que sus obras fueran reconocidas por la posteridad.', ja: 'その芸術家は、自分の作品が後世に認められることを願っていた。', trivia: 'ラテン語 posteritas（後に来る人々）に由来し、英語の posterity と同語根で意味・形ともほぼ一致する。ラテン語 post（後）が共通の祖先で、posterior・posthumous なども同じ語族に属する。' },
  'posterior': { es: 'En una reunión posterior, el equipo acordó modificar el plan inicial.', ja: 'その後の会議で、チームは最初の計画を修正することで合意した。', trivia: 'ラテン語 posterior（より後の、後部の）に直接由来し、英語の posterior と同語根・同形。解剖学では「後部の・背面の」という意味でも使われ、英語でも同様に technical term として機能する点が共通している。' },
  'posteriormente': { es: 'El médico explicó el diagnóstico y posteriormente indicó el tratamiento adecuado.', ja: '医師は診断を説明し、その後に適切な治療法を指示した。', trivia: 'ラテン語 posterior（後の、後ろの）の副詞形で、post-（後）＋ -terior（比較級接尾辞）から成る。英語の subsequently や thereafter に相当し、英語の posterior（後部の）と同語根。' },
  'postigo': { es: 'Abrió el postigo de la ventana para dejar entrar un poco de aire fresco.', ja: '新鮮な空気を少し入れようと、窓の鎧戸を開けた。', trivia: 'ラテン語 posticum（裏口、後ろのドア）に由来し、post-（後ろ）から派生した語。英語には直接の対応語はなく、shutterやwicket gate が近い表現だが語根は異なる。' },
  'postre': { es: 'De postre pedimos una tarta de queso con mermelada de fresa.', ja: 'デザートにストロベリージャムのチーズケーキを注文した。', trivia: 'ラテン語 postremus（最後の）に由来し、pōne（後ろに）から派生した語。英語の dessert はフランス語経由でまったく異なる語源（desservir「食卓を片付ける」）であり、スペイン語 postre とは語根が異なる。' },
  'postulado': { es: 'Uno de los postulados básicos de la geometría euclidiana es que por dos puntos pasa una sola recta.', ja: 'ユークリッド幾何学の基本的な公理の一つは、2点を通る直線は1本だけであるということだ。', trivia: 'ラテン語 postulatum（要求されたもの、前提）に由来し、postulare（要求する）から派生した。英語の postulate（公理、前提とする）と完全に同語根の同族語（コグネート）。' },
  'postular': { es: 'Varios candidatos postularon para el cargo de director del departamento.', ja: '複数の候補者が学部長職に立候補した。', trivia: 'ラテン語 postulare（要求する、求める）に由来する。英語の postulate（仮定する）と同語根であり、また to apply for（申請する）に相当する意味でも使われる。' },
  'postura': { es: 'El gobierno adoptó una postura firme frente a las negociaciones comerciales.', ja: '政府は通商交渉に対して断固とした態度を取った。', trivia: 'ラテン語 positura（位置、姿勢）に由来し、ponere（置く）の過去分詞 positus から派生。英語の posture と完全に同語根の借用語で、position や pose も同じラテン語の根を持つ。' },
  'potable': { es: 'En algunas regiones rurales, no siempre hay acceso a agua potable.', ja: '農村地域によっては、飲料水へのアクセスが常にあるとは限らない。', trivia: 'ラテン語 potabilis（飲める）に由来し、potare（飲む）から派生した語。英語の potable（飲用に適した）と完全に同語根であり、英語の poison（毒）もラテン語 potio（飲み物）という同じ根を持つ遠縁の語。' },
  'potencia': { es: 'La potencia de ese motor eléctrico supera los doscientos caballos de vapor.', ja: 'その電動モーターの出力は200馬力を超える。', trivia: 'ラテン語 potentia（力、権力）に由来し、posse（できる）から派生した語。英語の potency や power と同語根であり、power 自体はゲルマン語系だが potency はラテン語経由で potencia と完全に同族。' },
  'potenciación': { es: 'El programa gubernamental busca la potenciación del turismo sostenible en la región.', ja: '政府プログラムはその地域における持続可能な観光の強化を目指している。', trivia: '潜在力・力を意味する potencia（ラテン語 potentia）から派生した名詞。英語には potentiation という語があり（主に薬理学で「相乗強化」の意）、同語根だがスペイン語の一般的な「強化・増強」という広い意味とはやや用途が異なる。' },
  'potenciar': { es: 'Esta política educativa pretende potenciar las habilidades creativas de los estudiantes.', ja: 'この教育政策は学生の創造的なスキルを高めることを目指している。', trivia: 'ラテン語 potentia（力）から派生した動詞で、英語の empower や boost に相当する。英語の potentiate（薬の効果を相乗的に高める）と同語根だが、スペイン語 potenciar はより広い文脈で「強化する」という意味で使われる。' },
  'potencial': { es: 'Este joven futbolista tiene un gran potencial para llegar a la élite.', ja: 'この若いサッカー選手はトップ選手になるための大きな可能性を持っている。', trivia: 'ラテン語後期の potentialis（力のある）に由来し、英語の potential と完全に同語根の国際的な借用語。16世紀以降に哲学・科学用語として広まり、日本語の「ポテンシャル」も同じ語源。' },
  'potestad': { es: 'La potestad de tomar decisiones sobre los menores recae en los tutores legales.', ja: '未成年者に関する決定を下す権限は法定後見人にある。', trivia: 'ラテン語 potestas（権力、権限）に由来し、posse（できる）から派生した法律用語。英語の potentate（権力者、君主）や power と遠い語根を共有するが、英語で potestad に最も近い語は authority または legal power。' },
  'potra': { es: 'La potra dio sus primeros pasos en el prado bajo la atenta mirada de la yegua.', ja: '雌の子馬は牝馬の注意深い視線のもと、草原で初めての歩みを踏み出した。', trivia: '中世ラテン語 pulliter または vulgus latinの派生形から来たとされ、potro（雄の子馬）の女性形。口語で「幸運」を意味する用法は語源不明の俗語的転用。英語の filly（雌の子馬）に相当するが語根は異なる。' },
  'potro': { es: 'El potro saltó la valla y escapó al campo abierto.', ja: '子馬は柵を飛び越えて広い野原へと逃げ出した。', trivia: 'ラテン語 pullus（若い動物、ひな）またはケルト・イベリア語起源という説もある。英語の foal（子馬）とは語根が異なるが意味が近く、英語の pullet（若い雌鶏）はラテン語 pullus と同語根で遠縁にあたる。' },
  'pautar': { es: 'Es necesario pautar bien el proceso de evaluación para garantizar la equidad.', ja: '公平性を確保するために評価プロセスの基準をきちんと定めることが必要だ。', trivia: '名詞 pauta（指針、基準）から派生した動詞。英語では to set guidelines や to standardize に相当し、直接対応する英単語はない。pauta 自体の語源については諸説あり、ラテン語 pacta 由来という説が有力。' },
  'pavoroso': { es: 'El incendio presentó un espectáculo pavoroso que aterrorizó a los vecinos.', ja: '火災は近隣住民を恐怖に陥れる凄まじい光景を見せた。', trivia: '名詞 pavor（ラテン語 pavor「恐怖」）から派生した形容詞。英語の appalling や terrifying に相当し、英語で最も近い形容詞は dreadful または horrifying だが語根はそれぞれ異なる。英語に pavid（おびえた）という稀な語があり同語根。' },
  'pavo': { es: 'En España, es tradición comer pavo al horno en Navidad.', ja: 'スペインでは、クリスマスにオーブンで焼いた七面鳥を食べるのが伝統だ。', trivia: 'ラテン語 pavo（クジャク）に由来するが、スペイン語ではシチメンチョウを指す語に意味が転じた（本来はクジャクの意）。英語の turkey（七面鳥）はトルコ（Turkey）経由で伝わったという誤解に基づく別の語源を持ち、pavo とは完全に語源が異なる。' },
  'pozo': { es: 'Los habitantes del pueblo sacaban agua del pozo cada mañana.', ja: '村の住民たちは毎朝井戸から水をくみ上げていた。', trivia: 'ラテン語 puteus（井戸、穴）に由来し、英語の pit（穴、坑）と同語根という説がある。英語では well（井戸）または pit（坑）に相当するが、英語の pit はラテン語 puteus と共通の語根を持つ可能性があり、遠い親戚にあたる。' },
  'pradera': { es: 'Los caballos pastaban libremente en la extensa pradera verde.', ja: '馬たちは広大な緑の草原で自由に草を食んでいた。', trivia: 'ラテン語 prataria（牧草地の集合）に由来し、pratum（草地）から派生した語。英語の prairie（大草原）はフランス語 prairie 経由で同じラテン語 pratum に由来し、スペイン語 pradera と完全に同語根の国際的な借用語。' },
  'prado': { es: 'Los niños jugaban en el prado mientras sus padres descansaban a la sombra.', ja: '子どもたちが草原で遊ぶ間、両親は木陰で休んでいた。', trivia: 'ラテン語 pratum（牧草地）に直接由来し、英語の meadow とは語根が異なるが意味が近い。英語の prairie（大草原）はフランス語を経由した同語根の語で、マドリードの有名な美術館「プラド」もこの語に由来する（もとは王宮前の草原）。' },
  'pragmática': { es: 'La pragmática estudia cómo el contexto influye en la interpretación del lenguaje.', ja: '語用論は文脈が言語の解釈にどのように影響するかを研究する学問だ。', trivia: 'ギリシャ語 pragmatikē（実際的な、実務的な）に由来し、pragma（行為、事柄）から派生した語。英語の pragmatics（語用論）と完全に同語根であり、どちらもギリシャ語 prattein（行う）が究極の語源。' },
  'pragmático': { es: 'Su enfoque pragmático le permitió resolver el conflicto sin recurrir a teorías abstractas.', ja: '彼の現実主義的なアプローチにより、抽象的な理論に頼らずに紛争を解決することができた。', trivia: 'ギリシャ語 pragmatikos（実務の、行動に関する）に由来し、英語の pragmatic と完全に同語根。哲学用語として19世紀のアメリカでプラグマティズムが興隆し、現代では「現実的・実用的」という一般的な形容詞として国際的に使われる。' },
  'pragmatismo': { es: 'El pragmatismo filosófico sostiene que el valor de una idea reside en su utilidad práctica.', ja: '哲学的プラグマティズムは、ある考えの価値はその実用的な有用性にあると主張する。', trivia: 'ギリシャ語 pragma（行為）から派生した哲学用語で、19世紀末にチャールズ・サンダース・パースとウィリアム・ジェームズが体系化した。英語の pragmatism と完全に同語根の国際的な哲学・政治用語で、日本語の「プラグマティズム」も同じ語源。' },
  'precaución': { es: 'Debes conducir con precaución cuando la carretera está mojada.', ja: '道路が濡れているときは注意して運転しなければならない。', trivia: 'ラテン語 praecautio（前もって警戒すること）に由来し、prae-（前）＋ cavere（用心する）の合成語。英語の precaution と完全に同語根で、両語とも「事前の注意」を意味する。' },
  'precedente': { es: 'Este acuerdo sienta un precedente importante para futuras negociaciones.', ja: 'この合意は将来の交渉にとって重要な先例を打ち立てる。', trivia: 'ラテン語 praecedere（前に行く）の現在分詞 praecedens に由来。英語の precedent（先例）および preceding（先行する）と同語根であり、法律や外交の場面でほぼ同じ意味で使われる。' },
  'preceder': { es: 'Un fuerte viento frío precedió a la tormenta de nieve.', ja: '強い冷たい風が吹雪に先立った。', trivia: 'ラテン語 praecedere（prae- 前＋cedere 行く）に直接由来。英語の precede と同語根で、cede（譲る・行く）はスペイン語の ceder にも対応し、exceed（超える）、concede（認める）など多数の英語派生語と語根を共有する。' },
  'precepto': { es: 'Los monjes siguen los preceptos de su orden religiosa con rigor.', ja: '修道士たちは修道会の戒律を厳格に守っている。', trivia: 'ラテン語 praeceptum（前もって命じられたこと）に由来し、prae-（前）＋capere（取る・受け取る）の合成語。英語の precept（格言・規範）と同語根で、concept（概念）や reception（受け取り）とも語根 cap- を共有する。' },
  'preces': { es: 'El sacerdote elevó sus preces al cielo pidiendo la paz.', ja: '司祭は平和を求めて天に祈りを捧げた。', trivia: 'ラテン語 preces（祈り、嘆願）の複数形がそのままスペイン語に入ったもので、ラテン語 precari（祈る）に由来。英語の pray（祈る）や prayer（祈り）もフランス語を経由して同じラテン語源とつながっており、imprecation（呪い）も同語根の英単語である。' },
  'precio': { es: 'El precio del alquiler en las ciudades grandes ha subido mucho este año.', ja: '今年は大都市の家賃がかなり上がった。', trivia: 'ラテン語 pretium（価値、価格、報酬）に由来。英語の price はノルマン・フランス語 pris を経由して同じラテン語源に遡るが、スペイン語 precio の方がラテン語の形により近い。また precious（貴重な）とも同語根である。' },
  'preciosa': { es: 'La niña tiene una voz preciosa que emociona a todos.', ja: 'その女の子はみんなを感動させる美しい声を持っている。', trivia: 'ラテン語 pretiosus（価値ある）の女性形に由来し、precioso の女性形。英語の precious（貴重な、愛らしい）と同語根で、もともと「高価な」という意味から「美しい・愛らしい」という意味にも発展した点も両言語で共通している。' },
  'precioso': { es: 'Qué precioso regalo nos has traído de tu viaje a Japón.', ja: '日本旅行から素晴らしいお土産を持ってきてくれたね。', trivia: 'ラテン語 pretiosus（価値ある）の男性形に由来。英語の precious と同語根で、ラテン語 pretium（価格）がベースにあり、「高価な→貴重な→美しい」と意味が拡張した。英語では precious は主に「貴重な」、スペイン語 precioso は「美しい」の意味でよく使われる点が興味深い。' },
  'precipitación': { es: 'La meteorología prevé una precipitación de más de 50 mm en las próximas horas.', ja: '気象庁は今後数時間で50ミリを超える降水量を予測している。', trivia: 'ラテン語 praecipitatio（急落、転落）に由来し、praeceps（頭から逆さまに）が語源。英語の precipitation と同語根で、化学・気象の専門用語としても共通して使われる。「慌てる」と「降水」という二つの意味を持つ点も英語と同様である。' },
  'precipitado': { es: 'Tomaron una decisión precipitada sin analizar bien las consecuencias.', ja: '彼らは結果をよく分析せずに軽率な決断を下した。', trivia: 'ラテン語 praecipitare（頭から突き落とす）の過去分詞 praecipitatus に由来。英語の precipitate（形容詞：軽率な）と同語根で、化学用語「沈殿物」の意味も英語の precipitate（名詞）と共通する。' },
  'precipitar': { es: 'Los rumores precipitaron la caída del gobierno antes de lo esperado.', ja: '噂が予想より早く政権の崩壊を早めた。', trivia: 'ラテン語 praecipitare（頭から投げ落とす）に由来し、praeceps（頭を前にして）＝ prae-（前）＋ caput（頭）の合成語。英語の precipitate（早める、沈殿させる）と同語根で、capital（首都）や captain（船長）も同じ caput に由来する。' },
  'precipicio': { es: 'El senderista se detuvo al borde del precipicio con el corazón acelerado.', ja: 'ハイカーは心臓をドキドキさせながら断崖の縁で立ち止まった。', trivia: 'ラテン語 praecipicium（崖）に由来し、praeceps（頭から落ちる方向の）が語源。英語の precipice（断崖）と同語根で形もよく似ているが、英語では比喩的に「危機的な状況の瀬戸際」として使われることが多い点は両言語で共通している。' },
  'precisa': { es: 'Se necesita una información precisa para resolver el problema.', ja: '問題を解決するには正確な情報が必要だ。', trivia: 'ラテン語 praecisus（切り取られた、明確な）の女性形に由来し、praecidere（前もって切る）が語源。英語の precise（正確な）と同語根で、decision（決断）や scissors（はさみ）も同じ caedere（切る）に由来する。' },
  'precisamente': { es: 'Llamaste precisamente cuando estaba pensando en ti.', ja: 'ちょうどあなたのことを考えていたときに電話してきた。', trivia: '形容詞 preciso にラテン語由来の副詞語尾 -mente（mente はラテン語で「心・様式」）を付けた派生語。英語の precisely（正確に、まさに）と同語根で、会話で「そのとおり！」と同意するときにも両言語で同じように使われる。' },
  'precisar': { es: 'El informe precisa detalles que no aparecían en el borrador anterior.', ja: '報告書は以前の草稿には載っていなかった詳細を明示している。', trivia: 'ラテン語 praecisus（明確に切り分けられた）から派生した動詞。英語には precisar に直接対応する動詞はなく、「明確にする」は specify や clarify、「必要とする」は require や need で表現する。この動詞が二つの異なる意味（明確化と必要性）を持つ点がスペイン語の特徴である。' },
  'precisión': { es: 'Los cirujanos necesitan una precisión extrema durante las operaciones delicadas.', ja: '外科医は繊細な手術中に極めて高い精度を必要とする。', trivia: 'ラテン語 praecisio（切り落とし、正確さ）に由来。英語の precision と同語根・同形で、科学・技術・軍事の文脈ではほぼそのまま借用語として両言語に共存している。precision bombing（精密爆撃）のような複合語も両言語で同様に使われる。' },
  'preciso': { es: 'Es preciso llegar a un acuerdo antes del final de la jornada.', ja: 'その日のうちに合意に達することが必要だ。', trivia: 'ラテン語 praecisus（きっぱり切り離された、明確な）に由来。英語の precise（正確な）と同語根だが、スペイン語では「必要な・不可欠な」という意味でも頻繁に使われる点が英語の precise との大きな違いである。' },
  'proclama': { es: 'El general leyó la proclama ante sus tropas reunidas en la plaza.', ja: '将軍は広場に集まった部隊の前で布告を読み上げた。', trivia: 'ラテン語 proclamare（大声で叫ぶ）の名詞形に由来し、pro-（前へ）＋ clamare（叫ぶ）の合成語。英語の proclamation（宣言）と同語根で、claim（主張する）や exclaim（叫ぶ）も同じ clamare に由来する英単語である。' },
  'proclamación': { es: 'La proclamación de la independencia fue celebrada por toda la nación.', ja: '独立宣言は国中で祝われた。', trivia: 'ラテン語 proclamatio に由来し、proclamar の名詞形。英語の proclamation と同語根・同形で、法律や政治の文脈でほぼ同じ意味として使われる。ラテン語 clamare（叫ぶ）は英語の clamor（騒ぎ）や acclaim（称賛する）とも語根を共有する。' },
  'proclamar': { es: 'El rey fue proclamado soberano en una ceremonia solemne.', ja: '国王は厳粛な式典で君主として宣言された。', trivia: 'ラテン語 proclamare（pro- 前へ＋clamare 叫ぶ）に直接由来。英語の proclaim（宣言する）と同語根で形もよく似ており、ともに「公に大声で宣言する」という意味の格式ある動詞として使われる。' },
  'proclive': { es: 'Los adolescentes son proclives a tomar decisiones impulsivas.', ja: '10代の若者は衝動的な決断をしがちである。', trivia: 'ラテン語 proclivis（傾斜している、傾きやすい）に由来し、pro-（前へ）＋ clivus（傾斜）の合成語。英語では直接の対応語は prone（〜しがちな）や inclined（傾向がある）だが、英単語 proclivity（傾向）はこのラテン語源から来ており、スペイン語 proclive と深く関連している。' },
  'procreación': { es: 'La procreación es uno de los instintos más fundamentales de los seres vivos.', ja: '生殖は生き物の最も根本的な本能の一つである。', trivia: 'ラテン語 procreatio（子を産むこと）に由来し、pro-（前へ・出す）＋ creare（創る）の合成語。英語の procreation と同語根で、create（創る）や creature（生き物）も同じ creare に由来する。' },
  'procrear': { es: 'Muchas especies procreaban libremente antes de que el ser humano alterara sus hábitats.', ja: '人間が生息地を変える前は、多くの種が自由に繁殖していた。', trivia: 'ラテン語 procreare（子をなす）に由来し、pro-（産み出す）＋ creare（創造する）の合成語。英語の procreate（生殖する）と同語根で、recreate（再創造する）や creation（創造）も同じ creare に遡る。' },
  'procura': { es: 'La procura de fondos para el proyecto fue una tarea difícil.', ja: 'プロジェクトのための資金調達は難しい作業だった。', trivia: 'ラテン語 procura（世話、管理）に由来し、procurare（pro- 代わりに＋curare 世話をする）から派生した名詞。英語の procurement（調達）や procure（調達する）と同語根で、cure（治療）や curator（学芸員）も同じ curare に由来する英単語である。' },
  'procurador': { es: 'El procurador presentó los documentos necesarios ante el tribunal en nombre de su cliente.', ja: '訴訟代理人は依頼人の代わりに必要な書類を裁判所に提出した。', trivia: 'ラテン語 procurator（管理人、代理人）に由来し、procurare（世話をする、手配する）から来ている。英語の procurator と同語根であり、歴史的には財産管理人を指した。' },
  'procurar': { es: 'Procura llegar a tiempo porque la reunión empieza en punto.', ja: '会議は時間どおりに始まるから、遅れないよう心がけて。', trivia: 'ラテン語 procurare（気を配る、管理する）に由来。英語の procure（調達する）と同語根だが、スペイン語では「努力する・心がける」の意味が中心で、英語よりも意味の幅が広い。' },
  'prodigio': { es: 'Ese niño es un verdadero prodigio: toca el piano con una maestría increíble a sus seis años.', ja: 'あの子は本物の神童だ。6歳にして信じられないほどの巧みさでピアノを弾く。', trivia: 'ラテン語 prodigium（前兆、怪異な出来事）に由来。英語の prodigy と同語根で、スペルも意味もほぼ同じ典型的な国際語彙（インターナショナリズム）の一つ。' },
  'prodigioso': { es: 'La jugadora mostró una habilidad prodigiosa para esquivar a sus rivales durante el partido.', ja: 'その選手は試合中、相手をかわす驚異的な能力を披露した。', trivia: 'prodigio（奇跡）に形容詞語尾 -oso が付いた形で、ラテン語 prodigiosus に由来。英語の prodigious と同語根・同形で、「並外れた」「驚くべき」という意味でともに使われる。' },
  'pródigo': { es: 'El hijo pródigo regresó al hogar después de haber despilfarrado toda su herencia.', ja: '放蕩息子は遺産をすべて浪費した後、家に帰ってきた。', trivia: 'ラテン語 prodigus（浪費する）に由来し、prodigere（前に投げ出す→使い果たす）から来ている。英語の prodigal と同語根で、聖書の「放蕩息子（el hijo pródigo / the prodigal son）」の表現で両言語とも有名。' },
  'producción': { es: 'La producción de automóviles en ese país aumentó un diez por ciento el año pasado.', ja: 'その国の自動車生産量は昨年10パーセント増加した。', trivia: 'ラテン語 productio（引き伸ばすこと、生産）に由来し、producere（前に導く）から来ている。英語の production と同語根で、スペル・意味ともにほぼ一致する典型的な借用語ペアの一つ。' },
  'productiva': { es: 'La reunión de esta mañana fue muy productiva: llegamos a varios acuerdos importantes.', ja: '今朝の会議はとても実りが多く、いくつかの重要な合意に至った。', trivia: 'productivo の女性形で、ラテン語 productivus に由来。英語の productive と同語根であり、「生産的な」という意味でほぼ完全に対応する国際語彙。' },
  'productivo': { es: 'Estudiar idiomas resulta muy productivo si se practica cada día.', ja: '毎日練習すれば、語学の勉強はとても実り多いものになる。', trivia: 'ラテン語 productivus（前に導く性質の）に由来。英語の productive と同語根で、両語とも「成果を生み出す」という意味で広く使われる産業・教育分野の基本語彙。' },
  'productividad': { es: 'Las nuevas tecnologías han mejorado considerablemente la productividad de las empresas.', ja: '新技術が企業の生産性を大幅に向上させた。', trivia: 'productivo に抽象名詞語尾 -idad が付いた形で、ラテン語系統の造語。英語の productivity と同語根・対応形であり、経済・労働分野で両言語ともに頻出する重要語彙。' },
  'productor': { es: 'El productor musical trabajó durante meses para lograr el sonido perfecto del álbum.', ja: 'その音楽プロデューサーはアルバムの完璧なサウンドを実現するために何ヶ月も取り組んだ。', trivia: 'ラテン語 productor（前に導く者）に由来。英語の producer・producer と同語根だが、英語の producer に比べてスペイン語では農業生産者の意味でも日常的に使われる点が異なる。' },
  'proeza': { es: 'Escalar esa montaña en pleno invierno fue una verdadera proeza para el equipo.', ja: '真冬にあの山に登ることは、そのチームにとって真の偉業だった。', trivia: '古フランス語 prouesse（勇猛さ、勇敢な行為）に由来し、さらにラテン語 probus（優れた、誠実な）に遡る。英語の prowess（優れた技量・勇敢さ）と同語源で、スペイン語に入った際に意味が「壮挙・偉業」寄りになった。' },
  'profanación': { es: 'La profanación de ese cementerio histórico causó una gran indignación en la comunidad.', ja: 'その歴史的な墓地の冒涜は、地域社会に大きな憤りを引き起こした。', trivia: 'ラテン語 profanatio（神聖なものを汚す行為）に由来し、profanum（神殿の外、俗なる）から来ている。英語の profanation と同語根で、pro-（前に、外に）と fanum（神殿）の組み合わせが語の背景にある。' },
  'profanar': { es: 'Profanar un lugar sagrado es considerado un acto gravísimo en muchas culturas.', ja: '神聖な場所を冒涜することは、多くの文化できわめて重大な行為とみなされる。', trivia: 'ラテン語 profanare（神聖さを除く、俗物化する）に由来。英語の profane には動詞・形容詞の両用法があり同語根だが、英語では「卑猥な言葉を使う」という意味でも広く使われる点がスペイン語との用法の差異となっている。' },
  'profano': { es: 'Aunque soy profano en la materia, intento aprender los conceptos básicos de la física cuántica.', ja: '私はその分野の素人だが、量子物理学の基本概念を理解しようとしている。', trivia: 'ラテン語 profanus（神殿の外にある→俗なる）に由来し、pro-（外に）と fanum（神殿）から成る。英語の profane と同語根・同形で、両語とも「世俗の」「不敬な」の意味を持つが、スペイン語では「素人」の意味でも日常的に使われる。' },
  'profecía': { es: 'La profecía del anciano se cumplió exactamente como él había predicho.', ja: '老人の予言は彼が予告した通りに的中した。', trivia: 'ギリシャ語 prophēteia（予言）に由来し、pro-（前もって）と phēmi（言う）から成る。英語の prophecy と同語根で、スペルはアクセント記号の有無と -cía/-cy の差だけであり、宗教・文学の両分野で対応して使われる。' },
  'proferir': { es: 'El acusado profirió insultos contra el juez y fue expulsado de la sala.', ja: '被告人は裁判官に向かって侮辱の言葉を発し、法廷から退場させられた。', trivia: 'ラテン語 proferre（前に運ぶ、発する）に由来し、pro-（前に）と ferre（運ぶ）から成る。英語に直接対応する同語根の動詞はなく、英語では utter（発する）や blurt out（思わず言う）が意味的に対応する。' },
  'profesor': { es: 'La profesora de historia explica los temas con tanta pasión que nadie se aburre en su clase.', ja: 'その歴史の先生はとても情熱的に話題を説明するので、授業中に退屈する生徒は誰もいない。', trivia: 'ラテン語 professor（公に告白・宣言する者→教える者）に由来し、profiteri（公に認める）から来ている。英語の professor と同語根だが、英語では大学教授に限定される傾向があるのに対し、スペイン語では中学・高校の教師にも広く使われる点が異なる。' },
  'profesorado': { es: 'El profesorado de la universidad se reunió para debatir los nuevos planes de estudio.', ja: '大学の教員陣は新しいカリキュラムについて議論するために集まった。', trivia: 'profesor に集合名詞・職業を表す語尾 -ado が付いた形で、「教職員全体」や「教師という職」を指す。英語に完全対応する一語はなく、teaching staff や faculty（教員陣）が意味的に近い。英語の professorate は存在するが稀用。' },
  'profeta': { es: 'El profeta advirtió al pueblo de las consecuencias de sus actos.', ja: '預言者は民に自分たちの行いの結果を警告した。', trivia: 'ギリシャ語 prophētēs（神の言葉を語る者）に由来し、pro-（前もって）と phēmi（言う）から成る。英語の prophet と同語根で、語源・意味ともにほぼ完全に対応するが、英語の prophet が男女共用なのに対しスペイン語では女性形 profetisa も存在する。' },
  'profética': { es: 'Sus palabras resultaron ser casi proféticas: todo ocurrió tal como ella había dicho.', ja: '彼女の言葉はほぼ予言的なものだったと判明した。すべてが彼女の言った通りに起きたのだ。', trivia: 'profético の女性形で、ギリシャ語 prophētikos（予言に関する）に由来。英語の prophetic と同語根で、両語とも「予言者の、予言的な」という形容詞として文学・宗教・日常語彙で広く対応して使われる。' },
  'profético': { es: 'El poeta tenía un don profético: sus versos describían eventos que ocurrirían décadas después.', ja: 'その詩人には予言的な才能があった。彼の詩は数十年後に起こる出来事を描写していたのだ。', trivia: 'ギリシャ語 prophētikos に由来する形容詞で、profeta（予言者）と同じ語根を持つ。英語の prophetic と同語根・ほぼ同形であり、「予言的な」という意味で両言語とも宗教的文脈から比喩的用法まで幅広く使われる。' },
  'prófugo': { es: 'El prófugo de la justicia llevaba más de cinco años huyendo por distintos países.', ja: 'その逃亡者はすでに5年以上様々な国を逃げ回っていた。', trivia: 'ラテン語 profugus（逃げ去る者）に由来し、pro-（前へ）と fugere（逃げる）から成る。英語の fugitive と同じ fugere を語根に持つ同語源語で、英語の refuge（避難）や subterfuge（ごまかし）もこの動詞に由来する。' },
  'profundidad': { es: 'La profundidad del lago supera los doscientos metros en su punto más hondo.', ja: 'その湖の深さは最も深い地点で200メートルを超える。', trivia: 'ラテン語 profunditas（深さ）に由来し、profundus（深い：pro-＋fundus「底」）から来ている。英語の profound と同語根で、英語の depth は別語源（古英語 deop）だが、profound の名詞形 profundity も英語に存在し意味的に対応する。' },
  'profundamente': { es: 'Estoy profundamente agradecido por todo el apoyo que me han brindado.', ja: '皆さんが与えてくださったすべての支援に、心から感謝しています。', trivia: 'profundo（深い）に副詞語尾 -mente が付いた形で、ラテン語 profundus に由来。英語の profoundly と同語根・対応形で、どちらも「深く、心から」という意味の強調副詞として感謝・悲しみ・驚きなどの文脈で頻用される。' },
  'profundizar': { es: 'Para entender bien este tema, hay que profundizar en la lectura de las fuentes originales.', ja: 'このテーマをよく理解するには、一次資料を深く読み込む必要がある。', trivia: 'profundo（深い）に動詞化語尾 -izar が付いた形で、ラテン語 profundus（pro-＋fundus「底」）に由来。英語では deepen や delve into が意味的に対応し、同語根の英語動詞 profundize は存在するが現代英語ではほぼ使われない稀語。' },
  'profusión': { es: 'La fiesta estaba decorada con una profusión de flores de todos los colores.', ja: 'パーティーはあらゆる色の花であふれるほど飾られていた。', trivia: 'ラテン語 profusio（注ぎ出すこと）に由来し、pro-（前へ）＋fundere（注ぐ）が語源。英語の profusion と完全に同語根で、「あふれるほど豊富な状態」を表す点も共通する。' },
  'programación': { es: 'La programación de este canal de televisión incluye documentales interesantes los domingos.', ja: 'このテレビ局の番組編成には、日曜日に面白いドキュメンタリーが含まれている。', trivia: 'ラテン語 programma（公示、予告）に由来し、さらにギリシャ語 programma（前もって書かれたもの）が源泉。英語の programming と同語根で、「コンピュータのプログラミング」と「放送の番組編成」の両義を持つ点も英語と共通する。' },
  'programador': { es: 'El programador trabajó toda la noche para corregir el error en el sistema.', ja: 'そのプログラマーはシステムのバグを修正するために一晩中作業した。', trivia: 'programar（プログラムする）の動作主を表す接尾辞 -dor を付けた形。英語の programmer に相当するが、スペイン語では -dor/-dora という形で職業や動作主を表すのが特徴的。' },
  'programar': { es: '¿Has programado ya la lavadora para que empiece a las seis de la mañana?', ja: '朝6時に始まるように洗濯機のタイマーをもうセットしましたか？', trivia: 'ラテン語由来の programa を動詞化したもの。英語の to program と同語根・同義だが、スペイン語では家電のタイマーをセットする日常的な文脈でも広く使われる点が興味深い。' },
  'progre': { es: 'En la reunión había varios progres que proponían reformas sociales bastante radicales.', ja: 'その会議には、かなり急進的な社会改革を提案するリベラル派の人たちが何人かいた。', trivia: 'progresista（進歩主義者）を口語で短縮した形で、やや皮肉やからかいのニュアンスを帯びることが多い。英語に直接の対応語はなく、progressive（進歩主義者）をカジュアルに縮めた感覚に近いが、スペインでは特有の文化的含意を持つ。' },
  'progresión': { es: 'El médico observó una progresión lenta pero constante en la recuperación del paciente.', ja: '医師は患者の回復において、ゆっくりではあるが着実な進行を観察した。', trivia: 'ラテン語 progressio（前進）から来ており、pro-（前へ）＋gradi（歩む）が語根。英語の progression と同語根・同形で、数学的な「等差数列・等比数列」の意味も共有している。' },
  'progresiva': { es: 'El gobierno aplicó una política fiscal progresiva para reducir las desigualdades sociales.', ja: '政府は社会的不平等を縮小するために累進課税政策を導入した。', trivia: 'ラテン語 progressivus（前進する傾向のある）から派生した形容詞の女性形。英語の progressive と同語根・同義で、政治的な「進歩的」と税制の「累進的」の両義も英語と共通する。' },
  'progresivo': { es: 'El deterioro progresivo de su salud preocupaba a toda la familia.', ja: '彼の健康状態の段階的な悪化が家族全員を心配させていた。', trivia: 'ラテン語 progressivus に由来する形容詞の男性形。英語の progressive と同語根で、文法用語の「進行形」（tiempo progresivo）の意味も共有しており、言語学分野では特に英語話者が直感的に理解しやすい語。' },
  'progresivamente': { es: 'La situación económica del país fue mejorando progresivamente durante esa década.', ja: 'その国の経済状況はその10年間で徐々に改善していった。', trivia: '形容詞 progresivo に副詞を作る接尾辞 -mente を付けた形。英語の progressively や gradually に相当し、pro-（前へ）＋gradi（歩む）というラテン語の語根から「一歩一歩前進するように」というイメージが生まれた。' },
  'progreso': { es: 'Los avances tecnológicos han traído un enorme progreso a la humanidad en los últimos siglos.', ja: '技術の進歩はここ数世紀で人類に多大な発展をもたらした。', trivia: 'ラテン語 progressus（前進、発展）から直接来ており、英語の progress と同語根。英語では progress が名詞・動詞の両方に使えるが、スペイン語では progreso は名詞専用で動詞は progresar を使う点が異なる。' },
  'prohibición': { es: 'La prohibición del tabaco en lugares públicos mejoró notablemente la salud de los ciudadanos.', ja: '公共の場所での喫煙禁止は市民の健康を著しく改善させた。', trivia: 'ラテン語 prohibitio（妨げること）に由来し、pro-（前もって）＋habere（持つ、保つ）が語源。英語の prohibition と同語根で、米国の「禁酒法時代（Prohibition Era）」と同じ語を指す点でも馴染み深い。' },
  'prohibir': { es: 'Está prohibido fumar dentro del edificio, así que tendrás que salir si quieres hacerlo.', ja: '建物内での喫煙は禁止されているので、したければ外に出なければならない。', trivia: 'ラテン語 prohibere（妨げる、禁止する）から来ており、英語の prohibit と同語根。活用形でアクセント移動（prohíbo, prohíbe）が生じるのはスペイン語の二重母音回避規則による特徴的な現象。' },
  'prohibitiva': { es: 'El precio prohibitivo de los apartamentos en el centro hace imposible que los jóvenes compren.', ja: '中心部のアパートの法外な価格のせいで、若者が購入するのは不可能に近い。', trivia: 'ラテン語 prohibitivus に由来する形容詞の女性形。英語の prohibitive と同語根・同義で、「価格が法外で手が届かない」という意味も英語と共通する。' },
  'prohibitivo': { es: 'Los costes prohibitivos de la operación obligaron al paciente a buscar alternativas.', ja: '手術の法外なコストのせいで、患者は代替手段を探さざるを得なかった。', trivia: 'ラテン語 prohibitivus（禁止の性質を持つ）に由来する形容詞の男性形。英語の prohibitive と完全に同語根で、「買えないほど高い」という比喩的用法も英語と同様に発達している。' },
  'prole': { es: 'Con tanta prole, esa familia necesita una casa muy grande.', ja: '子供がそんなにたくさんいるので、その家族はとても大きな家が必要だ。', trivia: 'ラテン語 proles（子孫、子供たち）に由来し、pro-（前へ）＋alere（養う）が語源とも言われる。英語に直接の対応語はなく、英語では offspring や progeny（これもラテン語 progenies と同語根）に相当する。' },
  'proletariado': { es: 'Marx analizó el proletariado como la clase social destinada a transformar la historia.', ja: 'マルクスはプロレタリアートを歴史を変革する運命にある社会階級として分析した。', trivia: 'ラテン語 proletarius（国家に子供（proles）だけを提供できる最下層市民）に由来し、英語の proletariat と同語根。古代ローマの国勢調査用語が近代政治語彙に転用されたという興味深い歴史を持つ。' },
  'proletario': { es: 'Durante la revolución industrial, el trabajador proletario vivía en condiciones muy duras.', ja: '産業革命の時代、プロレタリアの労働者は非常に過酷な条件の下で生活していた。', trivia: 'ラテン語 proletarius（子供（proles）だけを国に提供できる市民）に由来し、英語の proletarian と同語根・同義。カール・マルクスがこの語を政治経済学の中心概念として復活させたことで現代語彙に定着した。' },
  'prolijidad': { es: 'La prolijidad de sus explicaciones hacía que las reuniones se extendieran horas.', ja: '彼の説明の冗長さのせいで、会議が何時間も延びた。', trivia: 'ラテン語 prolixus（広がった、流れ出る）に由来し、pro-（前へ）＋liquere（流れる）が語源。英語の prolixity（冗長さ）と同語根だが、英語では prolixity はやや格式ばった語で日常ではほとんど使われない。' },
  'prolijo': { es: 'El informe era tan prolijo que nadie tuvo paciencia para leerlo completo.', ja: 'そのレポートはあまりにも冗長で、最後まで読む忍耐を持つ者は誰もいなかった。', trivia: 'ラテン語 prolixus（広がった、長々とした）に由来し、英語の prolix と同語根。英語の prolix も「話や文章が冗長な」を意味するが、日常会話ではほとんど使われない文語的な語である点が対照的。' },
  'prólogo': { es: 'El prólogo de esa novela explica el contexto histórico en el que se desarrolla la trama.', ja: 'その小説のプロローグは、物語が展開される歴史的背景を説明している。', trivia: 'ギリシャ語 prologos（前口上）に由来し、pro-（前に）＋logos（言葉、語り）が語根。英語の prologue と同語根・同義で、英語では prologue と prolog の両つづりが使われるがスペイン語は prólogo のみ。' },
  'prolongación': { es: 'La prolongación de las negociaciones frustró a ambas partes del conflicto.', ja: '交渉の長期化は紛争の双方を苛立たせた。', trivia: 'ラテン語 prolongatio（引き伸ばすこと）に由来し、pro-（前へ）＋longus（長い）が語源。英語の prolongation と同語根で、英語の long も同じゲルマン語系の語根（印欧語根 *dlonghos）と対応関係にある。' },
  'prolongadamente': { es: 'El orador habló prolongadamente sobre un tema que apenas interesaba al público.', ja: 'その演説者は聴衆がほとんど興味を持たないテーマについて長々と話した。', trivia: '形容詞 prolongado（長引いた）に副詞を作る接尾辞 -mente を付けた形。英語の at length や for a prolonged period に相当し、prolong（英語）と同語根のラテン語 pro- ＋ longus から派生している。' },
  'prolongar': { es: 'Decidieron prolongar las vacaciones una semana más porque el tiempo estaba magnífico.', ja: '天気が素晴らしかったので、彼らは休暇をもう1週間延ばすことにした。', trivia: 'ラテン語 prolongare（引き伸ばす）に由来し、英語の prolong と同語根・同義。英語の long とも遠い印欧語根 *dlonghos（長い）でつながっており、「時間や空間を前（pro-）へ向けて長く（longus）伸ばす」というイメージが語源に込められている。' },
  'promedio': { es: 'El promedio de temperatura en esta ciudad durante julio es de unos treinta grados.', ja: 'この都市の7月の平均気温は約30度だ。', trivia: 'ラテン語 pro medio（中間のために）に由来し、「中間に位置するもの」から「平均」の意味に発展した。英語の average とは語根が異なり（averageはアラビア語 awariya 由来）、むしろ英語の mean（平均）や medium と概念的に近い。' },
  'promesa': { es: 'El político cumplió todas las promesas que había hecho durante la campaña electoral.', ja: 'その政治家は選挙運動中に行ったすべての公約を守った。', trivia: 'ラテン語 promissa（前もって送り出されたもの）に由来し、pro-（前もって）＋mittere（送る）が語源。英語の promise と同語根で、permit、missile、mission なども同じ mittere から派生した英語の仲間である。' },
  'prometedor': { es: 'Este joven investigador tiene un futuro prometedor en el campo de la biotecnología.', ja: 'この若い研究者はバイオテクノロジーの分野で前途有望な未来を持っている。', trivia: 'ラテン語 promittere（前方に送り出す → 約束する）に由来し、英語の promising と同語根。-dor という接尾辞は「〜する性質を持つ」を意味するスペイン語の形容詞語尾で、英語の -ing に相当する形容詞的用法に近い。' },
  'prometer': { es: 'Te prometo que estaré en tu boda sin falta.', ja: '必ず君の結婚式に出席すると約束するよ。', trivia: 'ラテン語 promittere（pro- 前に + mittere 送る）から来ており、英語の promise および promote と同語根。英語 promise は中期英語でラテン語 promissum（約束されたもの）から借用された。' },
  'prominente': { es: 'Es una figura prominente en el mundo de la política latinoamericana.', ja: '彼はラテンアメリカの政界において傑出した人物だ。', trivia: 'ラテン語 prominere（pro- 前に + minere 突き出る）に由来し、英語の prominent と完全に同語根の国際共通語彙。同じ語根から英語 eminent（卓越した）や imminent（差し迫った）も派生している。' },
  'promiscuidad': { es: 'La promiscuidad en las relaciones afectivas puede generar vínculos emocionales complicados.', ja: '感情的な関係における性的奔放さは、複雑な感情的絆を生む可能性がある。', trivia: 'ラテン語 promiscuus（pro- 前に + miscere 混ぜる）に由来し、英語の promiscuity と同語根。英語の mix や miscellaneous も同じ miscere から派生しており、「混合」という原義を共有している。' },
  'promiscuo': { es: 'El texto describía un ambiente promiscuo donde convivían personas de distintas culturas sin distinción.', ja: 'そのテキストは、異なる文化の人々が区別なく共存する混交した環境を描写していた。', trivia: 'ラテン語 promiscuus（無差別に混ざり合った）から来ており、英語の promiscuous と同語根。もともと「無差別に混合した」という中立的な意味があったが、現代では主に性的な文脈で使われる点は英語と共通している。' },
  'promoción': { es: 'La promoción de 1998 organizó una reunión de exalumnos para celebrar el 25 aniversario.', ja: '1998年度の同期生たちが、25周年を祝うために同窓会を開催した。', trivia: 'ラテン語 promotio（pro- 前に + movere 動かす）に由来し、英語の promotion と同語根。スペイン語では「同期・同期卒業生」という意味も持つ点が特徴的で、英語の class（同期生）に相当する独自の用法が発達している。' },
  'promocionar': { es: 'La empresa contrató a una agencia para promocionar su nuevo producto en redes sociales.', ja: 'その会社はSNSで新製品を宣伝するために広告代理店を雇った。', trivia: 'ラテン語 promovere（前進させる）から派生した名詞 promoción に動詞語尾 -ar を付加した形で、英語の promote に相当。英語 promote と異なり、スペイン語では promover（同義語）と promocionar が並立して使われる。' },
  'promontorio': { es: 'Desde el promontorio se podía contemplar toda la bahía con sus barcos de pesca.', ja: '岬からは漁船が浮かぶ湾全体を一望することができた。', trivia: 'ラテン語 promontorium（pro- 前に + mons/montis 山）に由来し、英語の promontory と同語根。英語では地理用語として promontory が使われるが、日常的にはあまり使われず、headland や cape のほうが一般的。' },
  'promotor': { es: 'El promotor inmobiliario presentó un nuevo proyecto de viviendas en las afueras de la ciudad.', ja: 'その不動産開発業者は市郊外の新しい住宅プロジェクトを発表した。', trivia: 'ラテン語 promotor（前進させる者）に由来し、英語の promoter と同語根。スペイン語では不動産開発業者（promotor inmobiliario）という用法が特に一般的で、英語では developer に相当する独自のニュアンスがある。' },
  'promover': { es: 'El gobierno quiere promover el uso de energías renovables en todo el país.', ja: '政府は国全体での再生可能エネルギーの利用を促進したいと考えている。', trivia: 'ラテン語 promovere（pro- 前に + movere 動かす）に由来し、英語の promote と同語根。現在形で語根の -ov- が -uev- に変化する語根母音変化動詞（e→ue）で、英語には見られないスペイン語特有の音変化が起きている。' },
  'promulgación': { es: 'La promulgación de la nueva ley de educación fue recibida con críticas por parte del sector docente.', ja: '新しい教育法の公布は教育関係者から批判をもって受け止められた。', trivia: 'ラテン語 promulgatio（公布、公表）に由来し、英語の promulgation と同語根。語根の mulgare はラテン語で「公に知らせる」を意味し、英語では promulgate という動詞として使われるが、日常会話ではほとんど使われない専門用語。' },
  'promulgar': { es: 'El congreso promulgó una ley que protege los derechos de los trabajadores temporales.', ja: '議会は非正規労働者の権利を保護する法律を公布した。', trivia: 'ラテン語 promulgare（広く知らしめる）に由来し、英語の promulgate と同語根。語根の mulgare の起源は諸説あるが、古ラテン語で「公衆に提示する」を意味したとされる。英語では promulgate は硬い書き言葉で、enact や pass（法律を通過させる）のほうが一般的。' },
  'pronombre': { es: 'En español, el pronombre personal se omite con frecuencia porque la desinencia verbal ya indica la persona.', ja: 'スペイン語では、動詞の語尾が既に人称を示しているため、人称代名詞がしばしば省略される。', trivia: 'ラテン語 pronomen（pro- 名詞の代わりに + nomen 名前）に由来し、英語の pronoun と同語根。英語は -noun（名前）という形を保っているが、スペイン語は -nombre（名前）と変化しており、両言語でラテン語 nomen の末裔が異なる形で生きている。' },
  'prónuba': { es: 'En la antigua Roma, la prónuba era una matrona casada que presidía la ceremonia nupcial.', ja: '古代ローマでは、プロヌバは結婚式を司る既婚の女性（マトロナ）であった。', trivia: 'ラテン語 pronuba（juno pronuba、結婚の女神ユノの別名）に由来し、nubere（嫁ぐ）から派生。英語の nuptial（結婚の）や connubial（婚姻の）と同語根で、現代スペイン語ではほぼ歴史・文学的文脈でのみ使われる稀語。' },
  'pronunciación': { es: 'La pronunciación de la «r» vibrante es uno de los mayores retos para los estudiantes japoneses.', ja: '巻き舌の「r」の発音は、日本人学習者にとって最大の難関の一つだ。', trivia: 'ラテン語 pronuntiatio（pro- 前に + nuntiare 告げる）に由来し、英語の pronunciation と同語根。英語では pronounce（動詞）と pronunciation（名詞）でスペルが変わる不規則さがあるが、スペイン語の pronunciar と pronunciación は規則的に対応している。' },
  'pronunciamiento': { es: 'El pronunciamiento militar de 1936 desencadenó la Guerra Civil Española.', ja: '1936年の軍事クーデターはスペイン内戦を引き起こした。', trivia: 'スペイン語固有の歴史用語で、19世紀のスペイン・ラテンアメリカで頻発した軍事反乱を指す表現として世界的に知られ、英語にも pronunciamiento としてそのまま借用された。語源はラテン語 pronuntiare（公に宣言する）。' },
  'pronunciar': { es: 'El presidente pronunció un discurso emocionante ante miles de personas en la plaza mayor.', ja: '大統領は広場に集まった数千人の前で感動的な演説を行った。', trivia: 'ラテン語 pronuntiare（pro- 公に + nuntiare 告げる）に由来し、英語の pronounce と同語根。英語 announce や denounce も同じ nuntiare から派生しており、「告げる」という語根が共通している。' },
  'pronóstico': { es: 'Según el pronóstico del tiempo, mañana habrá tormenta en toda la costa norte.', ja: '天気予報によると、明日は北岸全域で嵐になるとのことだ。', trivia: 'ギリシャ語 prognōstikon（pro- 前に + gnōsis 知識）に由来し、英語の prognosis および prognosticate と同語根。スペイン語では pronóstico が天気予報・医学的予後・スポーツ予想など幅広く使われるが、英語では prognosis は主に医療用語、forecast が天気予報に一般的に使われる。' },
  'pronosticar': { es: 'Los expertos pronostican que la economía crecerá un tres por ciento el próximo año.', ja: '専門家たちは来年の経済が3%成長すると予測している。', trivia: 'ギリシャ語由来の pronóstico（予測）に動詞語尾 -ar を付加した形で、英語の prognosticate と同語根。英語 prognosticate は主に文語・医療で使われるのに対し、スペイン語の pronosticar は日常的なニュース報道でも頻繁に使われる。' },
  'prontitud': { es: 'Respondió a mi correo electrónico con una prontitud que no esperaba.', ja: '私が予期しないほどの迅速さで私のメールに返信してくれた。', trivia: 'ラテン語 promptitudo（準備のできた状態）に由来し、英語の promptness と同語根。ラテン語 promptus（準備された）は英語の prompt（素早い、促す）にも受け継がれており、スペイン語 pronto（すぐに）とも関連する。' },
  'prontuario': { es: 'La policía consultó el prontuario del sospechoso y encontró varios antecedentes penales.', ja: '警察は容疑者の前科記録を照会し、複数の犯罪歴を見つけた。', trivia: 'ラテン語 promptuarium（貯蔵庫、手の届くところにある場所）に由来し、promptus（手の届く、即座の）から派生。英語の prompt と同語根で、もともとは「すぐ参照できる手引書」という意味から、現代では警察の前科記録という意味でも広く使われるラテンアメリカ特有の用法がある。' },
  'propaganda': { es: 'Durante la Segunda Guerra Mundial, los gobiernos usaron la propaganda para mantener la moral de la población.', ja: '第二次世界大戦中、各国政府は国民の士気を保つためにプロパガンダを利用した。', trivia: 'ラテン語の Congregatio de Propaganda Fide（信仰を広めるための会衆、1622年設立）に由来し、propagare（広める）から派生。英語にも propaganda としてそのままイタリア語経由で借用された。現代スペイン語ではネガティブな「プロパガンダ」だけでなく、チラシや広告の意味でも日常的に使われる点が英語と異なる。' },
  'propagación': { es: 'La rápida propagación del incendio dificultó las labores de extinción de los bomberos.', ja: '火災の急速な拡大が消防士たちの消火活動を困難にした。', trivia: 'ラテン語 propagatio（propagare 广める + -tio 名詞化）に由来し、英語の propagation と同語根。英語では propagation は主に科学・技術用語（波・信号の伝播、植物の繁殖）として使われるが、スペイン語の propagación は病気や火災の「拡散」という文脈でも自然に使われる。' },
  'propagar': { es: 'Las redes sociales propagan las noticias falsas a una velocidad alarmante.', ja: 'SNSは偽情報を驚くべき速さで拡散させる。', trivia: 'ラテン語 propagare（插し木で増やす、広める）に由来し、英語の propagate と同語根。農業用語「插し木する」が転じて「広める」になった語で、英語の propaganda も同じ語根を持つ。現代では生物の繁殖・信号の伝播・情報拡散まで幅広く使われる。' },
  'propasarse': { es: 'En la reunión de trabajo, el jefe se propasó con uno de sus comentarios y tuvo que disculparse.', ja: '職場の会議で、上司が一言行き過ぎた発言をして謝罪せざるを得なかった。', trivia: 'スペイン語の pro-（前に）+ pasar（通る）から構成された再帰動詞で、「一線を越えて通り過ぎる」が原義。英語では go too far や overstep（the line）に相当し、直接対応する英単語はないが、語根の pasar は英語の pass と同語源（ラテン語 passus、一歩）である。' },
  'propensión': { es: 'Tiene una propensión natural a la melancolía que se refleja en su escritura.', ja: '彼は生まれつき憂鬱になりやすい傾向があり、それが彼の文章に表れている。', trivia: 'ラテン語 propensio（傾き、傾向）に由来し、propendere（前に傾く）が語源。英語の propensity と完全に同語根の学術的コグネートで、ほぼ同じ意味で使われる。' },
  'propenso': { es: 'Los niños son más propensos a contraer enfermedades infecciosas en invierno.', ja: '子どもたちは冬に感染症にかかりやすい。', trivia: 'ラテン語 propensus（傾いた、傾向のある）から来た形容詞で、propendere の過去分詞が形容詞化したもの。英語では prone to や liable to に相当し、prone 自体もラテン語 pronus（前かがみの）と近い語根を持つ。' },
  'proponer': { es: 'El director propuso una nueva estrategia para aumentar las ventas.', ja: '部長は売上を伸ばすための新しい戦略を提案した。', trivia: 'ラテン語 proponere（前に置く、提示する）が語源で、pro-（前に）と ponere（置く）の合成語。英語の propose および purpose と同語根であり、いずれも「前に置く＝提案する」という概念を共有している。' },
  'proporción': { es: 'La proporción de estudiantes que aprueban el examen ha aumentado este año.', ja: '今年は試験に合格する学生の割合が増加した。', trivia: 'ラテン語 proportio（釣り合い、比例）に由来し、pro-（〜に対して）と portio（部分）から成る。英語の proportion と完全に同語根の学術的コグネートで、数学・芸術・日常会話まで幅広く用いられる。' },
  'proporcionar': { es: 'El gobierno prometió proporcionar viviendas asequibles a las familias con bajos ingresos.', ja: '政府は低所得世帯に手頃な住宅を提供すると約束した。', trivia: 'proporción から派生した動詞で、「比率を合わせる→供給・提供する」へと意味が拡張した。英語の provide や supply に意味上相当し、proportionate（釣り合った）という英語形容詞とは同語根だが用法は異なる。' },
  'proposición': { es: 'La proposición de paz fue rechazada por ambas partes del conflicto.', ja: '和平提案は紛争双方の当事者に拒否された。', trivia: 'ラテン語 propositio（提示、命題）に由来し、proponer と同語根。英語の proposition と完全に同語根のコグネートで、論理学・言語学での「命題・節」という意味も両言語で共有している。' },
  'propósito': { es: 'Con el propósito de mejorar su nivel, estudia español durante una hora cada día.', ja: 'レベルアップを目的として、彼女は毎日1時間スペイン語を勉強している。', trivia: 'ラテン語 propositus（前に置かれたもの）が語源で、proponer の過去分詞から名詞化した語。英語の purpose と同語根だが、英語では purpose が一般的で proposition や proposal とは少し意味が分かれており、スペイン語の propósito は「意図・目的」により近い。' },
  'propuesta': { es: 'La empresa presentó una propuesta detallada para el proyecto de infraestructura.', ja: 'その企業はインフラプロジェクトの詳細な提案書を提出した。', trivia: 'proponer の女性形過去分詞が名詞として定着した語で、ラテン語 proposita に由来。英語の proposal と同語根のコグネートであり、ビジネス・政治・学術いずれの文脈でも英語の proposal にほぼ対応する。' },
  'propuesto': { es: 'El candidato propuesto por el comité fue aceptado por unanimidad.', ja: '委員会が推薦した候補者は全会一致で承認された。', trivia: 'proponer の不規則過去分詞で、ラテン語 propositus に由来する。英語の proposed と意味・用法とも対応するコグネートで、スペイン語の不規則過去分詞（-puesto）は poner 系の動詞に共通するパターンである。' },
  'propugna': { es: 'La organización propugna una educación igualitaria para todos los niños del país.', ja: 'その組織は国内すべての子どもへの平等な教育を提唱している。', trivia: 'ラテン語 propugnare（守る、戦う）に由来し、pro-（前で）と pugnare（戦う）の合成語。英語の advocate や champion（主義を擁護する）に意味上相当し、英語の pugnacious（好戦的な）と同語根だが「擁護する」という積極的・建設的な意味合いで使われる。' },
  'propulsión': { es: 'El cohete utiliza un sistema de propulsión a base de combustible líquido.', ja: 'そのロケットは液体燃料を使った推進システムを使用している。', trivia: 'ラテン語 propulsio（追い払うこと）に由来し、propellere（前に押す）の名詞形。英語の propulsion と完全に同語根のコグネートで、英語の propel・propellant とも同じ語根を共有している。' },
  'prorrata': { es: 'Los gastos comunes del edificio se pagan a prorrata según los metros cuadrados de cada apartamento.', ja: '建物の共益費は各アパートの平方メートル数に応じて按分して支払われる。', trivia: '中世ラテン語の熟語 pro rata（parte）「比率に応じた（部分）」に由来し、pro（〜に応じて）と ratus（計算された）から成る。英語でも pro rata または prorate として使われる国際的な法律・会計用語で、rate（率）とも同語根である。' },
  'prorratear': { es: 'La empresa decidió prorratear los costes de mantenimiento entre todos los departamentos.', ja: '会社はメンテナンスコストを全部門に按分することを決定した。', trivia: 'prorrata から派生した動詞で、中世ラテン語 pro rata が語源。英語の prorate と完全に対応するコグネートであり、特に保険・会計・不動産の分野で「期間・量に比例して費用を割り当てる」意味で使われる。' },
  'prorrateo': { es: 'El prorrateo del seguro se calculó de forma automática al cancelar la póliza.', ja: '保険の按分計算は保険証券を解約した際に自動的に計算された。', trivia: 'prorratear の動詞名詞形（-eo 語尾による名詞化）で、中世ラテン語 pro rata が語源。英語では proration または prorating と呼ばれ、日本語の「プロラタ計算」という外来語もこの語から来ている。' },
  'prórroga': { es: 'El tribunal concedió una prórroga de quince días para presentar la documentación requerida.', ja: '裁判所は必要書類を提出するために15日間の猶予を認めた。', trivia: 'ラテン語 prorogatio（延長、猶予）に由来し、prorrogare（前に申し出る、延長する）が語源。英語では extension や renewal に相当し、英語に同形の単語はないが、法律・スポーツ双方で「延長」を指す点は英語の overtime や extension と機能的に対応する。' },
  'prorrogar': { es: 'Acordaron prorrogar el contrato de arrendamiento por otros dos años.', ja: '彼らはさらに2年間賃貸契約を延長することで合意した。', trivia: 'ラテン語 prorrogare（前に申し出る、期限を延ばす）に由来し、pro-（前に）と rogare（請う）の合成語。英語の arrogate（横領する）や interrogate（尋問する）と同語根（rogare）を持つが、スペイン語の prorrogar は「期限を延ばす」という中立的な意味で使われる。' },
  'prorrumpir': { es: 'Al escuchar la noticia, el público prorrumpió en aplausos espontáneos.', ja: 'そのニュースを聞いて、聴衆は自然発生的な拍手を一斉に始めた。', trivia: 'ラテン語 prorumpere（飛び出す、突発する）に由来し、pro-（前へ）と rumpere（破る）の合成語。英語の rupture（破裂）や erupt（噴出する）と同語根（rumpere）を持ち、英語の burst out（〜し出す）に意味上相当する表現である。' },
  'prosa': { es: 'Prefiero leer prosa moderna a la poesía clásica, porque me resulta más accesible.', ja: '私は古典詩より現代の散文を読む方が好きだ。なぜならより読みやすく感じるからだ。', trivia: 'ラテン語 prosa（oratio）「まっすぐな（話し方）」に由来し、prosus（まっすぐな）が語源。英語の prose と完全に同語根のコグネートで、詩（poetry）との対比として両言語で全く同様に使われる文学用語である。' },
  'prosaica': { es: 'La vida cotidiana puede parecer prosaica, pero en ella se esconden momentos de belleza.', ja: '日常生活は平凡に見えるかもしれないが、その中には美しい瞬間が隠れている。', trivia: 'prosa から派生した形容詞の女性形で、「散文的な→平凡な」という意味の拡張が起きた語。英語の prosaic と完全に同語根のコグネートであり、両言語とも「詩的でない→退屈な・ありきたりな」という比喩的意味を共有している。' },
  'prosaico': { es: 'El arquitecto criticó el diseño del edificio por ser demasiado prosaico y sin originalidad.', ja: '建築家はそのビルのデザインがあまりにも平凡で独創性に欠けると批判した。', trivia: 'prosaica の男性形で、prosa ＋ 形容詞語尾 -ico から成る。英語の prosaic と語源・意味ともに一致するコグネートで、「詩的でない＝面白みがない」という比喩的用法は英語でも全く同様に見られる。' },
  'prosapia': { es: 'El noble se enorgullecía de su prosapia, que se remontaba a varios siglos atrás.', ja: 'その貴族は数世紀前にさかのぼる自分の家系を誇りにしていた。', trivia: 'ラテン語 prosapia（一族、家系）に由来する古語・文語表現で、語源については諸説あり明確ではない。英語に直接対応するコグネートはなく、英語では lineage や pedigree に相当する；スペイン語でも現代では主に格式ある文学的・皮肉的文脈で用いられる。' },
  'proscenio': { es: 'La actriz se adelantó hasta el proscenio para decir sus últimas palabras antes del telón.', ja: '女優は幕が下りる前の最後の台詞を言うために舞台の前部まで進み出た。', trivia: 'ラテン語 proscaenium、さらにギリシャ語 proskēnion（舞台前、幕前）に由来し、pro-（前に）と skēnē（テント、舞台裏）から成る。英語の proscenium と完全に同語根のコグネートで、英語の scene や scenario もギリシャ語 skēnē と同じ語源を持つ。' },
  'proscribir': { es: 'La ley proscribe el uso de ciertos pesticidas que son dañinos para el medio ambiente.', ja: 'その法律は環境に有害な特定の農薬の使用を禁止している。', trivia: 'ラテン語 proscribere（公示する、追放を宣告する）に由来し、pro-（前に）と scribere（書く）の合成語。英語の proscribe と完全に同語根のコグネートであり、prescribe（処方する、規定する）とは対義語的関係にある点も英語と共通している。' },
  'proscripción': { es: 'La proscripción de ese partido político generó un gran debate sobre las libertades civiles.', ja: 'その政党の禁止措置は市民的自由に関する大きな議論を生んだ。', trivia: 'ラテン語 proscriptio（公示による追放令）に由来し、proscribir の名詞形。英語の proscription と完全に同語根のコグネートで、古代ローマでは反対者の名前を公示して財産没収・処刑を宣告する行為を指した歴史的用語である。' },
  'proscrito': { es: 'El escritor proscrito tuvo que exiliarse en el extranjero para poder publicar sus obras.', ja: '追放された作家は作品を出版するために海外に亡命しなければならなかった。', trivia: 'proscribir の不規則過去分詞が形容詞・名詞として定着した語で、ラテン語 proscriptus に由来する。英語の outlaw（無法者、法外放置）に意味上相当し、英語の proscribed（禁止された）とは同語根のコグネートである。' },
  'prosecución': { es: 'La prosecución del juicio depende de la presentación de nuevas pruebas.', ja: '裁判の続行は、新たな証拠の提出にかかっている。', trivia: 'ラテン語 prosecutio（追跡・続行）に由来し、英語の prosecution（起訴・訴追）と同語根。ただし英語では主に「刑事訴追」の意味で使われるのに対し、スペイン語の prosecución は「継続・遂行」という中立的な意味合いが強い。' },
  'proseguir': { es: 'A pesar de las dificultades, decidieron proseguir con el proyecto.', ja: '困難にもかかわらず、彼らはプロジェクトを続行することに決めた。', trivia: 'ラテン語 prosequi（前へ追う・続ける）に由来し、pro-（前へ）＋ sequi（従う・進む）の合成語。英語の pursue や prosecute と同じ語根 sequi を持ち、英語の continue に相当する使い方をする。' },
  'prosélita': { es: 'La nueva prosélita del partido defendía sus ideas con gran entusiasmo.', ja: 'その党の新たな支持者は、自分の考えを大変な熱意をもって擁護した。', trivia: 'ギリシャ語 prosēlytos（新参者・外来者）に由来し、「よそから来た者」が原義。英語の proselyte と同語根で、宗教的な改宗者を指す言葉として英語・スペイン語ともに使われる。' },
  'proselitismo': { es: 'La organización fue criticada por sus prácticas de proselitismo agresivo.', ja: 'その組織は、積極的な改宗勧誘活動により批判を受けた。', trivia: 'prosélita と同じくギリシャ語 prosēlytos（新参者）を語源とし、英語の proselytism と同語根。宗教的な勧誘活動を指す言葉として、英語・スペイン語ともに中立〜やや否定的なニュアンスで使われることが多い。' },
  'prosista': { es: 'García Márquez es recordado como uno de los mayores prosistas del siglo XX.', ja: 'ガルシア＝マルケスは、20世紀最大の散文家のひとりとして記憶されている。', trivia: 'スペイン語の prosa（散文）にラテン語由来の接尾辞 -ista を加えた語で、prosa はラテン語 prosa oratio（直接的な話し方）に由来する。英語では prose writer または prosist と言い、英語の prose と同語根。' },
  'prospecto': { es: 'Antes de tomar el medicamento, lee bien el prospecto para conocer sus efectos secundarios.', ja: '薬を飲む前に、副作用を知るために添付文書をよく読んでください。', trivia: 'ラテン語 prospectus（見通し・展望）に由来し、pro-（前へ）＋ specere（見る）の合成語。英語の prospectus（目論見書）と同語根で、スペイン語では特に医薬品の説明書の意味で日常的によく使われる。' },
  'prosperar': { es: 'La empresa prosperó gracias a la innovación y el trabajo en equipo.', ja: 'その会社はイノベーションとチームワークのおかげで繁栄した。', trivia: 'ラテン語 prosperare（成功させる）に由来し、prosper（好都合な）が語源。英語の prosper と同語根で形・意味ともによく似ており、スペイン語学習者には分かりやすい対応語（真のコグネート）のひとつ。' },
  'prosperidad': { es: 'El país vivió una época de prosperidad económica en los años noventa.', ja: 'その国は1990年代に経済的な繁栄の時代を経験した。', trivia: 'ラテン語 prosperitas（幸運・繁栄）に由来し、英語の prosperity と同語根。スペルも意味もほぼ同じ真のコグネートで、語尾 -dad がスペイン語で英語の -ty に対応するパターンの典型例。' },
  'próspera': { es: 'Es una región próspera con una economía basada en el turismo y la agricultura.', ja: 'そこは観光と農業を基盤とする経済を持つ、繁栄した地域だ。', trivia: 'próspero の女性形で、ラテン語 prosperus（順調な・幸運な）に由来。英語の prosperous と同語根であり、意味・スペルともに非常に近い真のコグネート。próspero の語頭アクセントに注意。' },
  'próspero': { es: 'Le deseo un próspero año nuevo lleno de salud y felicidad.', ja: '健康と幸福に満ちた、繁栄ある新年をお祈りしています。', trivia: 'ラテン語 prosperus（順調な）に由来し、英語の prosperous と同語根。英語では「Próspero Año Nuevo（明けましておめでとう）」の表現でも知られ、シェイクスピアの『テンペスト』の主人公名 Prospero もこの語と関連する。' },
  'prostitución': { es: 'El debate sobre la legalización de la prostitución divide a la sociedad.', ja: '売春の合法化に関する議論が社会を二分している。', trivia: 'ラテン語 prostitutio（公衆の前に立てること）に由来し、pro-（前へ）＋ statuere（立てる・置く）の合成語。英語の prostitution と同語根で形・意味ともに同じ真のコグネート。' },
  'prostituta': { es: 'La obra de teatro retrata la vida de una prostituta en el Madrid del siglo XIX.', ja: 'その演劇は19世紀マドリードの売春婦の人生を描いている。', trivia: 'ラテン語 prostituta（公衆の前に差し出された女性）に由来し、英語の prostitute と同語根。ラテン語 statuere（立てる）から派生しており、英語の statue（彫像）や constitute（構成する）とも遠い語根を共有する。' },
  'prostituyo / prostituir': { es: 'Algunos artistas sienten que aceptar ese tipo de contratos equivale a prostituir su talento.', ja: 'そのような契約を受け入れることは自分の才能を切り売りすることだと感じるアーティストもいる。', trivia: 'ラテン語 prostituere（公衆の前に差し出す）に由来し、pro-（前へ）＋ statuere（立てる）の合成語。英語の prostitute（動詞）と同語根で、才能や信念を「卑しめる・売り渡す」という比喩的用法は英語と共通する。' },
  'protagonista': { es: 'La protagonista de la novela supera múltiples obstáculos para alcanzar su sueño.', ja: 'その小説の主人公は夢を実現するために数々の障害を乗り越える。', trivia: 'ギリシャ語 prōtagōnistēs（最初の競技者）に由来し、prōtos（最初の）＋ agōnistēs（競技者・役者）の合成語。英語の protagonist と同語根で、英語の first（最初の）に相当するギリシャ語 prōtos は proto-（原始の）という接頭辞でも英語に残る。' },
  'protagonizar': { es: 'El actor protagonizará la nueva serie dramática que se estrenará en otoño.', ja: 'その俳優は秋に公開される新しいドラマシリーズで主役を務める。', trivia: 'protagonista に動詞化接尾辞 -izar を加えた語で、「主人公を演じる」という意味。英語には対応する一語動詞がなく、to star in や to lead などと表現するため、スペイン語の語彙の豊かさが際立つ例のひとつ。' },
  'protección': { es: 'El gobierno anunció nuevas medidas de protección para el medio ambiente.', ja: '政府は環境保護のための新たな措置を発表した。', trivia: 'ラテン語 protectio（覆い・守護）に由来し、pro-（前に）＋ tegere（覆う・守る）の合成語。英語の protection と同語根で、英語の detect（発見する）も同じ tegere が語根であり、スペイン語の -ción が英語の -tion に対応するパターンの典型例。' },
  'proteccionismo': { es: 'El auge del proteccionismo ha generado tensiones entre los principales socios comerciales.', ja: '保護主義の台頭が主要な貿易相手国の間に緊張をもたらしている。', trivia: 'protección＋接尾辞 -ismo から成り、英語の protectionism と同語根。19世紀の経済学の文脈で発展した語で、自由貿易（libre comercio）の対立概念として英語・スペイン語ともに同じ形で使われる。' },
  'protector': { es: 'Mi hermano mayor siempre fue un protector para mí durante nuestra infancia.', ja: '兄は幼い頃、いつも私の守り手だった。', trivia: 'ラテン語 protector（守る者）に由来し、英語の protector と同語根。形・意味ともにほぼ同じ真のコグネートで、英語の detect（発見）や tegument（外皮）も同じ tegere（覆う）を語根に持つ。' },
  'protectorado': { es: 'Marruecos estuvo bajo el protectorado francés y español durante el siglo XX.', ja: 'モロッコは20世紀にフランスとスペインの保護領下に置かれていた。', trivia: 'protector＋接尾辞 -ado（地位・領域を示す）から成り、英語の protectorate と同語根。いずれもラテン語 protegere（守る）に由来する植民地政策の用語で、英語の -ate に対応するスペイン語の -ado は名詞・形容詞を作る。' },
  'proteger': { es: 'Es fundamental proteger a los niños de los peligros en internet.', ja: '子どもたちをインターネット上の危険から守ることは不可欠だ。', trivia: 'ラテン語 protegere（前を覆う・守る）に由来し、pro-（前に）＋ tegere（覆う）の合成語。英語の protect と同語根で、英語の detect（発見する）や integument（外皮）も同じ tegere から派生している。' },
  'proteica': { es: 'Esta enzima tiene una naturaleza proteica y es esencial para la digestión.', ja: 'この酵素はタンパク質性の性質を持ち、消化に不可欠だ。', trivia: 'ギリシャ語 Prōteios（神プロテウスの）に由来し、変幻自在の海神プロテウス（Proteus）の名前から来ている。英語の protean（変幻自在な）と同語根であり、「タンパク質の」という科学的意味と「変幻自在な」という比喩的意味を両方持つ。' },
  'proteína': { es: 'Los atletas necesitan consumir suficiente proteína para mantener su masa muscular.', ja: 'アスリートは筋肉量を維持するために十分なタンパク質を摂取する必要がある。', trivia: 'ギリシャ語 prōteios（最初の・主要な）に由来し、19世紀にオランダの化学者ムルダーが命名した科学用語。英語の protein と同語根で形もほぼ同じ真のコグネートであり、生命に不可欠な「最初の物質」という命名の意図が語源に込められている。' },
  'protesta': { es: 'Miles de personas salieron a las calles en señal de protesta contra la nueva ley.', ja: '何千人もの人々が新法に対する抗議の意を示すために街頭に繰り出した。', trivia: 'ラテン語 protestatio（公に証言すること）に由来し、pro-（前で・公に）＋ testari（証言する）の合成語。英語の protest と同語根で、testari は英語の testify（証言する）や testimony（証言）とも同じ語根 testis（証人）を共有する。' },
  'protestante': { es: 'La reforma protestante del siglo XVI transformó el panorama religioso de Europa.', ja: '16世紀のプロテスタント改革はヨーロッパの宗教的な情景を一変させた。', trivia: 'protestanteは動詞 protestar の現在分詞形から来ており、1529年のシュパイアー帝国議会でカトリック側の決定に「抗議した（protestierten）」諸侯・都市が語源とされる。英語の Protestant と同語根で、形・意味ともに同じ真のコグネート。' },
  'protestar': { es: 'Los trabajadores decidieron protestar frente a la sede de la empresa por los recortes salariales.', ja: '労働者たちは賃金削減に対して会社本社前で抗議することを決めた。', trivia: 'ラテン語 protestari（公に証言する・宣言する）に由来し、pro-（公に）＋ testari（証言する）の合成語。英語の protest（抗議する）と同語根で、ラテン語 testis（証人）は英語の testify、attest、contest などにも見られる共通語根。' },
  'protocolo': { es: 'El equipo médico siguió el protocolo establecido durante toda la intervención quirúrgica.', ja: '医療チームは手術中、定められた手順書に従って行動した。', trivia: 'ラテン語 protocollum（文書の最初の葉）に由来し、さらにギリシャ語 prōtokollon（prōtos「最初の」+ kolla「糊」）に遡る。英語の protocol と完全な同語根であり、外交・IT・医療など多岐にわたる意味の広がり方も両言語で共通している。' },
  'prototipo': { es: 'Los ingenieros presentaron el primer prototipo del nuevo vehículo eléctrico ante los inversores.', ja: 'エンジニアたちは投資家の前で、新しい電気自動車の最初の試作品を披露した。', trivia: 'ギリシャ語 prōtotypon（prōtos「最初の」+ typos「型・印」）に由来し、英語の prototype と全く同じ語源を持つ。「原型」や「典型」を意味するこの語は、デザイン・工学・文学批評など幅広い分野で使われる。' },
  'provecho': { es: 'Espero que te sea de provecho la información que te he enviado.', ja: 'お送りした情報がお役に立てれば幸いです。', trivia: 'ラテン語 profectus（前進、利益）に由来し、動詞 proficere（前に進む）が語源。英語の profit と同じラテン語の根 pro-（前へ）+ facere（作る）を共有している。¡Buen provecho!（召し上がれ）という表現は日本語の「いただきます」に近い慣用句。' },
  'provechoso': { es: 'Asistir a ese seminario fue una experiencia muy provechosa para todos los participantes.', ja: 'そのセミナーへの参加は、全参加者にとって非常に有益な経験だった。', trivia: 'provecho（利益）に形容詞化接尾辞 -oso を加えた語。英語の profitable や beneficial に意味が近いが、英語に provechoso に直接対応する同語根の形容詞はなく、profitable はラテン語 proficere（前に進む）という共通の祖先を持つ遠い親戚と言える。' },
  'proveedor': { es: 'Nuestra empresa cambió de proveedor para reducir los costes de producción.', ja: '我が社は生産コストを削減するためにサプライヤーを変更した。', trivia: '動詞 proveer（供給する）に行為者を示す接尾辞 -dor を付けた語。英語の provider と同語源で、どちらもラテン語 providere（先を見越して用意する）に由来する。インターネット用語「プロバイダー」として日本語にも借用されている。' },
  'proveer': { es: 'El gobierno prometió proveer de materiales escolares a todas las escuelas rurales del país.', ja: '政府は国内の全農村部の学校に学用品を供給すると約束した。', trivia: 'ラテン語 providere（pro-「前に」+ videre「見る」）に由来し、英語の provide と完全に同語根。「将来を見越して準備する」という原義が根底にある。過去分詞が provisto と proveído の二形を持つ不規則動詞でもある。' },
  'proveído': { es: 'El juez dictó un proveído ordenando la suspensión temporal del contrato.', ja: '裁判官は契約の一時停止を命じる裁定を下した。', trivia: '動詞 proveer の規則的な過去分詞形（不規則形は provisto）。法律用語としては「裁判所の決定・命令」を指す名詞としても機能する。英語の provided や provision と同語根（ラテン語 providere）だが、法律的な名詞用法は英語には直接対応する語がなくやや特殊。' },
  'provento': { es: 'Los proventos de la venta de acciones fueron destinados a cubrir las deudas de la empresa.', ja: '株式売却による収益は、会社の負債返済に充てられた。', trivia: 'ラテン語 proventus（結果、収益）に由来し、動詞 provenire（前に出る、生じる）が語源。英語には直接の同語根語は一般的でないが、revenue（歳入）やprofit（利益）と意味が近い。現代スペイン語では法律・金融分野での専門用語として使われる。' },
  'provenir': { es: 'Esta costumbre proviene de una antigua tradición árabe que se extendió por toda Europa.', ja: 'この習慣は、ヨーロッパ全土に広まった古代アラビアの伝統に由来している。', trivia: 'ラテン語 provenire（pro-「前へ」+ venire「来る」）に由来し、英語の come from や stem from に相当する。英語の provenance（出所、来歴）と同語源で、芸術品や文書の「出所」を意味する美術・歴史学用語としても両言語に共通している。' },
  'provenza': { es: 'La lavanda de Provenza es conocida en todo el mundo por su perfume inconfundible.', ja: 'プロヴァンスのラベンダーは、他に類を見ない香りで世界中に知られている。', trivia: 'ラテン語 Provincia（「属州」を意味し、ローマ帝国最初のガリア属州だったことに由来）に直接由来する固有名詞。英語の Provence も同じ語源で、また province（州・県）という一般名詞もこの地名と同根であり、「最も古い属州」という歴史的背景が語源に刻まれている。' },
  'proverbiador': { es: 'Aquel anciano era conocido en el pueblo como un gran proverbiador que siempre tenía un dicho para cada situación.', ja: 'その老人は、どんな状況にも諺を持ち合わせている偉大なことわざ収集家として村で知られていた。', trivia: 'proverbio（諺）に行為者を示す接尾辞 -dor を加えた派生語。英語には proverbiador に直接対応する一般的な語はなく、paroemiologist（諺学者）という専門用語が近い。proverbio 自体はラテン語 proverbium（pro-「前に」+ verbum「言葉」）に由来し、英語の proverb と同語根。' },
  'proverbio': { es: 'Como dice el proverbio, no todo lo que brilla es oro.', ja: '諺にあるように、輝くものすべてが金とは限らない。', trivia: 'ラテン語 proverbium（pro-「前に・公に」+ verbum「言葉」）に由来し、「広く知られた言葉」が原義。英語の proverb と完全に同語根であり、どちらも同じラテン語源から直接派生している。また、旧約聖書の「箴言」はスペイン語で Libro de los Proverbios、英語で Book of Proverbs と呼ばれる。' },
  'providencial': { es: 'Fue providencial que el médico estuviera presente justo cuando ocurrió el accidente.', ja: '事故が起きたまさにその時に医師がその場に居合わせたのは天佑とも言えた。', trivia: 'ラテン語 providentia（先見、摂理）に由来し、キリスト教神学における「神の摂理（神が万物を導く働き）」を指す概念から派生した形容詞。英語の providential と完全に同語根で意味も同じ。「絶好のタイミング」という世俗的な意味でも広く使われる点も両言語共通。' },
  'provincial': { es: 'El periódico provincial informó sobre las elecciones regionales de manera detallada.', ja: '地方紙は、地域選挙について詳細に報道した。', trivia: 'ラテン語 provincia（属州、地方）に由来し、英語の provincial と全く同語根・同意義。「地方的・視野が狭い」というやや否定的なニュアンスも両言語で共通している。カトリック修道会における「管区長（Provincial）」という宗教的な称号としても両言語で使われる。' },
  'provisión': { es: 'Antes de la expedición, el equipo hizo una provisión de alimentos para tres semanas.', ja: '遠征の前に、チームは3週間分の食料を備蓄した。', trivia: 'ラテン語 provisio（providere の名詞形、先を見越して備えること）に由来し、英語の provision と完全に同語根・同形に近い語。複数形 provisiones は「食料・必需品」を指す日常語としても頻繁に使われ、英語の provisions（食糧）と同じ用法を持つ。' },
  'provisional': { es: 'El gobierno estableció un comité provisional para gestionar la crisis económica.', ja: '政府は経済危機に対応するための暫定委員会を設置した。', trivia: 'provisión（供給・備え）から派生した形容詞で、ラテン語 providere（先を見越して準備する）に遡る。英語の provisional と語形・意味ともにほぼ同一で、法律・政治・外交分野で「暫定的な」という意味で広く使われる。「仮免許（carnet provisional）」のような日常的な文脈にも登場する。' },
  'provisionalmente': { es: 'La oficina estará cerrada provisionalmente mientras se realizan las obras de renovación.', ja: '改修工事が行われる間、その事務所は一時的に閉鎖される。', trivia: 'provisional に副詞化接尾辞 -mente を加えた語で、英語の provisionally や temporarily に相当する。-mente 副詞はラテン語 mens（心・精神）の奪格形に由来し、英語の副詞接尾辞 -ly（古英語 -lice）と機能的に対応するが語源は異なる。' },
  'provisto': { es: 'El laboratorio está provisto de los equipos más avanzados del país.', ja: 'その実験室には国内最先端の設備が整っている。', trivia: '動詞 proveer の不規則過去分詞で、ラテン語 provisus（providere の過去分詞）に直接由来する。英語の provided と意味は近いが、英語では provided は規則活用であるのに対し、スペイン語では provisto（不規則）と proveído（規則）の二形が並存するという興味深い違いがある。' },
  'provocación': { es: 'El árbitro expulsó al jugador por responder a una provocación del equipo contrario.', ja: '審判は、相手チームの挑発に応じたとして選手を退場させた。', trivia: 'ラテン語 provocatio（呼び出し、挑戦）に由来し、動詞 provocare（pro-「前へ」+ vocare「呼ぶ」）が語源。英語の provocation と完全に同語根で、「前に呼び出す→挑発する」という原義が共通している。英語の vocation（天職）や invoke（呼び起こす）とも同じ vocare を語根に持つ。' },
  'provocador': { es: 'El político fue acusado de ser un provocador que azuzaba el odio entre grupos sociales.', ja: 'その政治家は、社会集団間の憎しみを煽る扇動者だと非難された。', trivia: '動詞 provocar に行為者を示す接尾辞 -dor を加えた語で、英語の provocateur（フランス語経由）や agitator に相当する。英語でも agent provocateur（扇動者）というフランス語借用表現が使われるが、スペイン語は同じラテン語源からより直接的に派生している。' },
  'provocar': { es: 'El comentario inapropiado del director provocó una reacción inmediata por parte de los empleados.', ja: '取締役の不適切な発言は、従業員側から即座の反応を引き起こした。', trivia: 'ラテン語 provocare（pro-「前へ」+ vocare「呼ぶ」）に由来し、英語の provoke と完全に同語根。「前に呼び出す＝反応を引き出す」という原義から「挑発する」「引き起こす」へと意味が広がった。英語の revoke（取り消す）や evoke（呼び起こす）とも同じ vocare を語根に持つ。' },
  'proximidad': { es: 'La proximidad del aeropuerto al centro de la ciudad es una gran ventaja para los viajeros.', ja: '空港と市中心部との近さは、旅行者にとって大きな利点だ。', trivia: 'ラテン語 proximus（最も近い）の最上級形に由来し、英語の proximity と完全に同語根・同意義。proximus 自体は prope（近くに）の最上級で、英語の approximate（概算の）や proximate（直接の）とも同語根。日本語でも「プロキシサーバー」という形で親しみのある語。' },
  'próxima': { es: 'La próxima reunión del consejo directivo tendrá lugar el martes por la mañana.', ja: '取締役会の次回会議は火曜日の午前中に行われる予定だ。', trivia: 'ラテン語 proximus（最も近い）の女性形。英語の next に意味が近いが、英語の next はゲルマン語系（古英語 niehsta）に由来し、próxima とは語源が全く異なる。一方、英語の proximate や proximity はラテン語 proximus という共通の語根を持つ。' },
  'próximo': { es: 'El próximo lunes es festivo, así que la oficina permanecerá cerrada.', ja: '来週の月曜日は祝日なので、事務所は休業となります。', trivia: 'ラテン語 proximus（最も近い）の男性形で、próxima の男性形。英語の next はゲルマン語系で語源が異なるが、英語の proximity（近接）・approximate（概算の）・proximate（直接の）はいずれも同じラテン語 proximus を語根に持つ近い親戚にあたる。' },
  'proyección': { es: 'La empresa presentó sus proyecciones de ventas para los próximos cinco años.', ja: 'その会社は今後5年間の売上予測を発表した。', trivia: 'ラテン語 proiectio（pro-「前へ」+ iacere「投げる」）に由来し、英語の projection と完全に同語根。「前方に投げる」という原義から「映写」「予測」「影響力の拡大」など多様な意味が派生した。英語の jet（噴射）、inject（注射する）、eject（排出する）も同じ iacere を語根に持つ。' },
  'propugnar': { es: 'La organización propugna los derechos de las personas más vulnerables de la sociedad.', ja: 'その組織は社会で最も弱い立場の人々の権利を擁護している。', trivia: 'ラテン語「propugnare（前面で戦う、防衛する）」に由来し、「pro（前に）＋pugnare（戦う）」の構成。英語の「pugnacious（けんか好きな）」「impugn（異議を唱える）」と同語根で、「拳で戦う」イメージが語根「pugn-」に宿っている。' },
  'proyectar': { es: 'El arquitecto proyectó un edificio moderno que se integra bien con el entorno histórico.', ja: '建築家は歴史的な環境によく溶け込む、モダンな建物を設計した。', trivia: 'ラテン語「proiectare（前に投げる）」に由来し、「pro（前に）＋iacere（投げる）」が語源。英語の「project」「projectile」「inject」「trajectory」はすべて「iacere」を語根に持つ同族語である。' },
  'proyectil': { es: 'Los investigadores analizaron la trayectoria del proyectil para reconstruir los hechos.', ja: '研究者たちは事実を再構成するために弾丸の軌跡を分析した。', trivia: '「proyectar（投げる・発射する）」と同語根のラテン語「proiectilis」に由来する。英語の「projectile」と同語根の典型的なコグネートで、スペルもほぼ同じだが、英語では「プロジェクタイル」と発音するのに対しスペイン語では「プロイェクティル」となる。' },
  'proyector': { es: 'Necesitamos un proyector para presentar las diapositivas en la sala de conferencias.', ja: '会議室でスライドを発表するためにプロジェクターが必要だ。', trivia: 'ラテン語「proiector（前に投げる者）」に由来し、「映像を前方に投射する装置」という意味で技術語として定着した。英語の「projector」と完全に同語根で、語形もほぼ同一の明白なコグネートである。' },
  'prudencia': { es: 'Actuó con prudencia al no tomar una decisión precipitada en una situación tan delicada.', ja: 'こんなにも繊細な状況で、彼は軽率な判断を下さずに慎重に行動した。', trivia: 'ラテン語「prudentia（分別・先見）」に由来し、「providentia（予見）」の短縮形とされ、「pro（前に）＋videre（見る）」が語源。英語の「prudence」と同語根で、中世の四枢要徳（prudentia・iustitia・fortitudo・temperantia）の一つとして哲学的に重要な語。' },
  'prudencial': { es: 'El banco adoptó medidas prudenciales para evitar riesgos financieros innecesarios.', ja: '銀行は不必要な金融リスクを避けるために健全性措置を講じた。', trivia: '「prudencia」と同語根のラテン語由来の形容詞。英語の「prudential」と同語根のコグネートで、現代の金融・規制の文脈では「prudential regulation（健全性規制）」という専門用語として英語でも頻繁に使われる。' },
  'prudente': { es: 'Sería prudente consultar a un médico antes de tomar cualquier medicamento nuevo.', ja: '新しい薬を服用する前に医師に相談するのが賢明だろう。', trivia: 'ラテン語「prudens（先見の明がある・分別ある）」に由来し、「providens」の短縮形。英語の「prudent」と完全に同語根のコグネートで、スペルも語義もほぼ一致するが、英語では「慎重な」ニュアンスが強く、スペイン語でも同様に用いられる。' },
  'prueba': { es: 'La defensa presentó nuevas pruebas que pusieron en duda la culpabilidad del acusado.', ja: '弁護側は、被告の有罪性を疑わせる新たな証拠を提出した。', trivia: 'ラテン語「proba（試み・検証）」、動詞「probare（試す・証明する）」に由来する。英語の「proof」「probe」「approve」「probable」はすべて同語根で、「試して確かめる」というコアイメージを共有している。' },
  'pruina': { es: 'La pruina que cubre la superficie de las uvas les da ese aspecto blanquecino y mate.', ja: 'ブドウの表面を覆うブルームが、あのくすんだ白っぽい外観を生み出している。', trivia: 'ラテン語「pruina（霜・白い粉）」に直接由来する科学・植物学用語。英語でも「pruina」または「bloom（果粉）」と言い、同じラテン語語源だが英語の日常語「frost」とは語源が異なる。植物学・醸造学の専門語として英語・スペイン語ともに同形で使われる。' },
  'prurito': { es: 'El médico le recetó una crema especial para aliviar el prurito causado por la alergia.', ja: '医師はアレルギーによるかゆみを和らげるために特別なクリームを処方した。', trivia: 'ラテン語「pruritus（かゆみ）」、動詞「prurire（かゆい）」に由来する医学用語。英語でも「pruritus」は皮膚科の専門用語としてそのまま使われ、形容詞「prurient（好色な・みだらな）」も同語根で「むずむずする欲求」というイメージを共有する。' },
  'púa': { es: 'Se pinchó el dedo con una púa del rosal mientras podaba las ramas.', ja: '枝を剪定しているとき、バラの棘で指を刺してしまった。', trivia: '語源は諸説あり、ラテン語「puga（先端）」またはゴート語「*sputs」に由来するとも言われるが、確定していない。英語では文脈によって「thorn（植物の棘）」「quill（ヤマアラシの針）」「pick/plectrum（ギターピック）」と使い分けるが、スペイン語の「púa」はこれらをすべて包括する。' },
  'pubertad': { es: 'Durante la pubertad, el cuerpo experimenta cambios físicos y emocionales muy significativos.', ja: '思春期には、身体的にも感情的にも非常に大きな変化を経験する。', trivia: 'ラテン語「pubertas（成熟・毛が生える時期）」に由来し、「pubes（陰毛・恥骨部）」と同語根。英語の「puberty」と同語根の典型的なコグネートで、語形・語義ともにほぼ一致する。' },
  'pubis': { es: 'El médico le diagnosticó una inflamación en la sínfisis del pubis tras el entrenamiento intenso.', ja: '医師は、激しいトレーニングの後に恥骨結合の炎症と診断した。', trivia: 'ラテン語「pubes/pubis（恥部・陰毛・成熟）」に直接由来する解剖学用語。英語でも「pubis」はそのまま解剖学用語として使われ、「pubic（恥骨の）」「puberty（思春期）」と同語根で、「成熟・体毛」のイメージを語根に持つ。' },
  'pública': { es: 'La educación pública debe garantizar el acceso igualitario para todos los ciudadanos.', ja: '公教育はすべての市民に平等なアクセスを保障しなければならない。', trivia: 'ラテン語「publicus（公の・国民の）」に由来し、「populus（民衆）」と同語根とされる。英語の「public」と同語根のコグネートで、語形・語義ともに非常に近いが、スペイン語の「pública」は女性形・名詞的用法（「公立校」の略など）としても機能する。' },
  'públicamente': { es: 'El alcalde se disculpó públicamente por los errores cometidos durante su gestión.', ja: '市長は、自らの任期中に犯した過ちについて公に謝罪した。', trivia: '「público（公の）」＋副詞接尾辞「-mente（〜に）」から成るスペイン語の規則的な副詞形。英語の「publicly」と同語根で、ラテン語「publicus」に由来する。スペイン語の副詞は形容詞の女性形に「-mente」を加えて作るという規則の典型例。' },
  'publicación': { es: 'La publicación de su nuevo libro generó una gran expectativa entre sus lectores habituales.', ja: '彼女の新しい本の出版は、常連読者の間で大きな期待を生み出した。', trivia: 'ラテン語「publicatio（公開・没収）」に由来し、「publicare（公にする）」から派生した名詞。英語の「publication」と同語根の明白なコグネートで、現代では印刷物の「出版」だけでなくSNSの「投稿」という意味でも使われるようになった。' },
  'publicidad': { es: 'La empresa invirtió una gran suma en publicidad para lanzar su nuevo producto al mercado.', ja: 'その企業は新製品を市場に投入するために広告に多額の投資をした。', trivia: 'ラテン語「publicus」に由来するスペイン語固有の派生名詞で、英語の「publicity（知名度・広報）」とは若干語義が異なる。英語の「publicity」は「注目・名声」の意味が強いのに対し、スペイン語の「publicidad」は「広告・コマーシャル」という商業的意味が中心で、英語の「advertising」に近い。' },
  'publicar': { es: 'El gobierno decidió publicar los resultados de la investigación antes de lo previsto.', ja: '政府は予定より早く調査結果を公表することにした。', trivia: 'ラテン語 publicare（公にする）に由来し、これは publicus（公の）から来ている。英語の publish と同語根で意味もほぼ同じだが、スペイン語では SNS への「投稿する」という意味でも日常的に使われる点が現代的な拡張用法として興味深い。' },
  'publicista': { es: 'La publicista diseñó una campaña innovadora que aumentó las ventas en un treinta por ciento.', ja: 'その広報担当者は売り上げを30パーセント伸ばした革新的なキャンペーンを考案した。', trivia: 'ラテン語 publicus を語根とし、英語の publicist と同じ語源・同形の借用語（コグネート）だが、英語では主に「著名人の広報担当」を指すのに対し、スペイン語では広告制作者やコピーライターを指すことが多く、意味のずれがある。' },
  'público': { es: 'El público aplaudió de pie al finalizar el concierto.', ja: 'コンサートが終わると観客は総立ちで拍手を送った。', trivia: 'ラテン語 publicus（人民の、国家の）から直接受け継がれた語で、英語の public と完全に同語根の真のコグネート。形容詞「公の」と名詞「大衆・観客」の両義を持つ点も英語と共通しており、ロマンス語と英語の歴史的つながりを示す好例。' },
  'pucho': { es: 'Encontré un pucho aplastado en el cenicero del balcón.', ja: 'バルコニーの灰皿につぶれたタバコの吸い殻を見つけた。', trivia: '語源は諸説あり、ケチュア語（南米先住民語）の puchu（残り物、かす）に由来するという説が有力。主に南米（アルゼンチン、ウルグアイなど）で使われる口語表現で、スペイン本土や英語には直接対応する同語根語はなく、英語では cigarette butt と言う。' },
  'pudor': { es: 'Le dio pudor hablar de sus sentimientos frente a tanta gente.', ja: '大勢の前で自分の気持ちを話すのが恥ずかしかった。', trivia: 'ラテン語 pudor（恥、羞恥心）から直接受け継がれた語で、動詞 pudere（恥じる）と同根。英語には対応する同語根語はほとんど残っておらず、英語では modesty や shame と言うが、pudor は単なる「恥」というより「恥じらいの美徳」というニュアンスを含む、文化的に深い概念語だ。' },
  'pudorosa': { es: 'Era una chica pudorosa que siempre se ruborizaba cuando la elogiaban.', ja: '彼女は褒められるといつも顔を赤らめる恥ずかしがりやな女の子だった。', trivia: 'pudor（羞恥心）に形容詞語尾 -oso/a が付いた派生語。英語では modest や demure に相当するが、pudoroso/a は「恥じらいをもつことを美徳とする」という肯定的ニュアンスが強く、英語の bashful（消極的なイメージ）よりも品のある内気さを指すことが多い。' },
  'pudoroso': { es: 'El actor, normalmente tan seguro de sí mismo, se mostró pudoroso cuando le preguntaron sobre su vida sentimental.', ja: '普段はとても自信家のその俳優も、恋愛生活について聞かれると恥ずかしそうな様子を見せた。', trivia: 'pudor（羞恥心）から派生した形容詞の男性形で、pudorosa の男性形。ラテン語 pudorosus に由来し、英語には直接の対応語がないが、意味としては modest や shy に近い。英語の impudent（厚かましい）の im- は「否定」、pudent はこの pudor と同根で「恥じている」を意味する。' },
  'pudre': { es: 'La fruta se pudre rápidamente si no la guardas en el refrigerador.', ja: '冷蔵庫に入れておかないと果物はすぐに腐ってしまう。', trivia: '動詞 pudrir（腐る・腐らせる）の三人称単数現在形。ラテン語 putrere（腐る）に由来し、英語の putrid（腐った、腐敗した）と同語根の真のコグネート。英語では rot や decay が一般的だが、putrid という形容詞に原形の面影が残っている。' },
  'puente': { es: 'Vamos a aprovechar el puente de la Constitución para hacer un viaje a Portugal.', ja: '憲法記念日の連休を利用してポルトガルへ旅行しよう。', trivia: 'ラテン語 pons / pontis（橋）に由来し、英語の pontoon（浮橋・ポンツーン）や pontiff（法王、もともと「橋を架ける者」の意）と同語根。スペインでは祝日と週末の間の平日を「橋」と呼んで連休にする習慣があり、英語の bridge と意味が広がった方向が面白い。' },
  'puerca': { es: 'En el cuento, la puerca y sus tres hijos vivían felices en el bosque.', ja: 'その物語では、メスの豚と三匹の子どもたちが森で幸せに暮らしていた。', trivia: 'ラテン語 porca（メスの豚）に由来し、英語の pork（豚肉）と同語根の真のコグネート。英語では生きた豚を pig や sow、食肉を pork と使い分けるが、スペイン語の puerca / puerco は動物としての豚を指し、食材としての豚肉は carne de cerdo という。' },
  'puerco': { es: 'En México se usa la palabra puerco para referirse tanto al animal como a la carne de cerdo.', ja: 'メキシコでは puerco という語が動物としての豚にも豚肉にも使われる。', trivia: 'ラテン語 porcus（豚）に由来し、英語の pork（豚肉）および porpoise（ネズミイルカ、もとは「豚のような魚」の意）と同語根。英語では Norman French 経由で pork が食肉を指すようになったが、スペイン語では puerco が動物と食肉の両方を指せる汎用語として使われる地域もある。' },
  'pueril': { es: 'Sus comentarios pueriles sobre el tema no ayudaron en nada a resolver el problema.', ja: 'そのテーマについての彼の子どもっぽいコメントは、問題解決に何の役にも立たなかった。', trivia: 'ラテン語 puerilis（少年の）に由来し、puer（少年、子ども）が語根。英語の puerile と完全に同語根・同形のコグネートで意味も同じ「幼稚な」。関連語として英語の puerperium（産褥期）も同じ puer を含み、「子どもを生む」を意味するラテン語表現から来ている。' },
  'puerperio': { es: 'Durante el puerperio, es fundamental que la madre descanse y reciba apoyo de su familia.', ja: '産褥期には、母親がしっかり休み、家族のサポートを受けることが非常に大切だ。', trivia: 'ラテン語 puerperium（出産）に由来し、puer（子ども）＋ parere（産む）の合成語。英語では puerperium（産褥期）としてそのままラテン語が医学用語で使われており、形容詞は puerperal（産褥の）。英語の puerperal fever（産褥熱）という歴史的な医学用語にその形が残っている。' },
  'puertorriqueña': { es: 'La escritora puertorriqueña ganó el premio nacional de literatura con su primera novela.', ja: 'そのプエルトリコ人の女性作家は処女作で国家文学賞を受賞した。', trivia: 'Puerto Rico（プエルトリコ）に -eño/a という形容詞語尾が付いた語で、Puerto は「港」（英語の port と同語根）、Rico は「豊かな」（英語の rich と同語根）を意味する。英語では Puerto Rican と言い、スペイン語のまま地名を使うので語源のつながりが透けて見える。' },
  'puertorriqueño': { es: 'El cantante puertorriqueño triunfó en los mercados de habla hispana de todo el mundo.', ja: 'そのプエルトリコ出身の歌手は世界中のスペイン語圏の市場で成功を収めた。', trivia: 'puertorriqueña の男性形。Puerto（港）はラテン語 portus に由来し、英語の port・portal・porthole と同語根。Rico（豊かな）はゲルマン語由来で、英語の rich と同語根という珍しい例——スペイン語の形容詞に英語のゲルマン語系語根が紛れ込んでいる。' },
  'puesto': { es: 'Lleva dos años ocupando el puesto de directora de marketing en esa empresa.', ja: '彼女はその会社でマーケティングディレクターのポストに就いて2年になる。', trivia: '動詞 poner（置く）の過去分詞 puesto が名詞化した語で、ラテン語 positus（置かれた）に由来する。英語の post（地位・郵便）と同語根の真のコグネートで、どちらも「場所に置かれたもの」という概念から「職・地位」の意味に発展した。英語 position も同じラテン語根を持つ。' },
  'pugna': { es: 'Los dos partidos llevan meses en pugna por controlar el ayuntamiento.', ja: '2つの党が市議会の主導権をめぐって数ヶ月間争い続けている。', trivia: 'ラテン語 pugna（戦い、格闘）に由来し、動詞 pugnare（戦う）が語根。英語では pugnacious（好戦的な、けんか腰の）という形容詞に同じ語根が残っており、またボクサーを指す古語 pugilist（ボクサー）も同根。英語 fist（こぶし）はゲルマン語系で語源は異なるが意味が近い。' },
  'pugnar': { es: 'Los activistas pugnan por conseguir mejores condiciones laborales para los trabajadores migrantes.', ja: '活動家たちは移民労働者のためのより良い労働条件を勝ち取ろうと懸命に闘っている。', trivia: 'ラテン語 pugnare（戦う）に由来し、pugna と同語根。英語の pugnacious（好戦的な）、impugn（異議を唱える）、repugn（嫌悪させる）などと同根で、スペイン語でも repugnar（嫌悪させる）という派生語がある。英語 impugn の接頭辞 im-（against）＋ pugnare という構成が語源の面白さを示す。' },
  'puja': { es: 'La puja por el cuadro del artista famoso alcanzó cifras millonarias en la subasta.', ja: '有名画家の絵画をめぐる競りはオークションで数百万の金額に達した。', trivia: '動詞 pujar（競り上げる）の名詞形で、ラテン語 pugiō（短剣）とは無関係で、むしろラテン語 pulsare（押す、打つ）に由来するという説がある。英語では bid（入札）に相当し、auction（オークション）はラテン語 augere（増やす）から来ており語源は異なる。' },
  'pujante': { es: 'La economía pujante del país atrajo a inversores de todo el mundo.', ja: 'その国の活況を呈した経済は世界中から投資家を引き寄せた。', trivia: 'pujar（押し進む、奮闘する）の現在分詞が形容詞化した語。ラテン語 pulsare（押す）に由来するとされ、英語では booming や thriving に相当するが直接の同語根語はない。英語の pulse（脈拍）や propulsion（推進）が同じラテン語根 pellere/pulsare を共有しており、「押し進む力強さ」という概念に通じる。' },
  'pujar': { es: 'Varios coleccionistas empezaron a pujar por la primera edición del libro raro.', ja: '複数のコレクターがその希少な本の初版をめぐって競り始めた。', trivia: '語源はラテン語 pulsare（押す、打つ）に由来するという説がある。英語では bid（入札する）に相当し、意味的には英語の push（押す）と遠い親戚関係にあるかもしれないが、英語の push はフランス語経由でラテン語 pulsare から来ており、pujar と遠い同根語という興味深い関係にある。' },
  'pulga': { es: 'El perro se rascaba sin parar; claramente tenía pulgas.', ja: 'その犬は絶えずかきむしっていた。明らかにノミがいたのだ。', trivia: 'ラテン語 pulex / pulicis（ノミ）に由来し、英語の flea（ノミ）はゲルマン語系で全く語源が異なる。しかし、英語の pulicide（ノミ駆除剤）という技術用語には pulic- という同じラテン語根が使われており、日常語と専門語で語源が分かれる英語の特徴を示す。' },
  'pulgada': { es: 'La pantalla de mi teléfono mide seis punto siete pulgadas de diagonal.', ja: '私のスマートフォンの画面は対角線で6.7インチだ。', trivia: 'pulgar（親指）から派生した語で、元来「親指1本分の幅」を意味した。英語の inch も同様に「親指の太さ」を意味するラテン語 uncia に由来しており、両者は語根は異なるが「親指の幅＝長さの単位」という発想を共有する偶然の一致が興味深い。英語の ounce（オンス）も同じ uncia から来ている。' },
  'pulgar': { es: 'El bebé se chupaba el pulgar mientras dormía profundamente.', ja: '赤ちゃんはぐっすり眠りながら親指をしゃぶっていた。', trivia: 'ラテン語 pollex / pollicis（親指）ではなく、pollicare（親指で押す）から変化したという説もある。英語の thumb はゲルマン語系で全く語源が異なるが、英語には pollex という解剖学用語があり、これが pulgar と遠い同根語にあたる。また pulgada（インチ）は pulgar から派生しており、「親指」が長さの基準になっていた歴史が語に刻まれている。' },
  'pulcritud': { es: 'La pulcritud de su escritorio refleja su forma ordenada de trabajar.', ja: '彼の机の整然さは、几帳面な仕事ぶりを反映している。', trivia: 'ラテン語 pulcher（美しい）に由来し、英語の pulchritude（美しさ、容姿の美）と同語根。英語では pulchritude は主に文語的な「美貌」を指すが、スペイン語の pulcritud は「清潔さ・几帳面さ」に意味がシフトしている点が興味深い。' },
  'pulcro': { es: 'Siempre llega a las reuniones con un aspecto pulcro y bien vestido.', ja: '彼はいつも清潔感があり、きちんとした服装で会議に臨む。', trivia: 'ラテン語 pulcher（美しい、整った）から来ており、英語の pulchritude（美）と同じ語根を持つ。英語では neat や immaculate に相当する概念だが、単独の形容詞として pulcher 由来の語がそのまま一般語として残るのはスペイン語の特徴。' },
  'pulimentar': { es: 'El carpintero pasó horas pulimentando la superficie de madera hasta dejarla perfecta.', ja: '大工は木の表面が完璧になるまで何時間もかけて磨き上げた。', trivia: 'ラテン語 polire（磨く）を基にした pulimentar は、英語の polish と同語根。英語の polish はフランス語経由でラテン語 polire に遡るが、スペイン語では pulir と pulimentar という二つの動詞が「磨く」の意味で共存している。' },
  'pulir': { es: 'Necesito pulir el informe antes de enviárselo al director.', ja: '部長に送る前に報告書を磨き上げる必要がある。', trivia: 'ラテン語 polire（磨く、洗練させる）に直接由来し、英語の polish と完全に同語根。英語で「靴を磨く polish shoes」に相当するのが zapatos pulidos など。口語的に「お金を使い果たす」の意があるのはスペイン語独自の発展。' },
  'pulmón': { es: 'Los bosques tropicales son considerados el pulmón del planeta.', ja: '熱帯雨林は地球の肺と見なされている。', trivia: 'ラテン語 pulmo / pulmonis（肺）に由来し、英語 lung とは語源が異なる（lung はゲルマン語系）。ただし英語には pulmonary（肺の）という形容詞があり、これはラテン語 pulmo と同語根でスペイン語 pulmón と対応する。' },
  'pulmonía': { es: 'La anciana tuvo que ser hospitalizada a causa de una pulmonía grave.', ja: 'その老女は重い肺炎のため入院しなければならなかった。', trivia: 'ラテン語 pulmo（肺）から派生した語で、英語の pneumonia とは語源が異なる（pneumonia はギリシャ語 pneumon 由来）。英語の pulmonary（肺の）が示すようにラテン語系の「肺」を意味する語根は両言語に残っており、スペイン語では pulmonía という形で日常的に使われる。' },
  'pulpa': { es: 'Prefiero el zumo natural con pulpa porque tiene más fibra.', ja: '食物繊維が多いので、果肉入りの天然ジュースの方が好きだ。', trivia: 'ラテン語 pulpa（肉質の部分、果肉）に由来し、英語の pulp と完全に同語根・同形に近い。英語でも「pulp fiction（大衆向けの安っぽい読み物）」という用法があるように、紙パルプや通俗的コンテンツへの転用は英語と共通する意味拡張。' },
  'pulpera': { es: 'La pulpera del mercado reconocía a todos los clientes del barrio por su nombre.', ja: '市場のよろず屋の女将は、近所の客全員を名前で知っていた。', trivia: 'pulpo（タコ）または pulpería（よろず屋）の女性形。ラテンアメリカの歴史的文脈では食料品・酒・日用品を扱う小売商の女主人を指し、英語には直接対応する一語がない。語源的には pulpo（タコ）由来とする説と、pulpería という店名から逆成した説がある。' },
  'pulpería': { es: 'En el siglo XIX, la pulpería era el centro social y comercial de los pueblos rioplatenses.', ja: '19世紀において、プルペリアはリオ・デ・ラ・プラタ地域の町々における社交・商業の中心だった。', trivia: '語源には諸説あり、タコ（pulpo）を売る店とする説や、多くの商品を「タコの足のように」扱う店とする比喩説がある。英語には general store や tavern が近いが、ラテンアメリカ特有の文化的・歴史的意味合いを持つため翻訳困難な語の一つ。' },
  'púlpito': { es: 'El sacerdote subió al púlpito y comenzó su homilía con voz solemne.', ja: '司祭は説教壇に上がり、厳かな声で説教を始めた。', trivia: 'ラテン語 pulpitum（台、演壇）に由来し、英語の pulpit と完全に同語根・同形に近い。両語ともにキリスト教の説教壇を指す宗教語として中世に定着した。英語でも「from the pulpit（説教壇から）」という表現は現在も使われる。' },
  'pulque': { es: 'En los mercados tradicionales de México todavía se puede encontrar pulque fresco.', ja: 'メキシコの伝統的な市場では今でも新鮮なプルケを見つけることができる。', trivia: 'ナワトル語（アステカ語）の poliuhqui（腐った、変質した）またはナワトル語系の語に由来するとされる。英語にも pulque としてそのまま借用されており、maguey（リュウゼツラン）から作る発酵酒として英語圏でも知られるが、英語に対応する独自語はなくスペイン語経由で世界に広まった。' },
  'pulsera': { es: 'Le regalé una pulsera de plata para su cumpleaños.', ja: '誕生日に彼女にシルバーのブレスレットをプレゼントした。', trivia: 'スペイン語 pulso（脈、手首）にラテン語 pulsus（拍動）が語源。「手首に付けるもの」という意味で pulsera が派生した。英語の bracelet はフランス語 bracel（腕）経由だが、英語にも pulse（脈拍）という同語根の語があり、pulsar・pulsation など技術・医学語に残る。' },
  'pulsación': { es: 'El médico registró una pulsación de 72 latidos por minuto.', ja: '医師は1分間72拍の脈拍を記録した。', trivia: 'ラテン語 pulsatio（叩くこと、鼓動）に由来し、英語の pulsation と完全に同語根。英語では pulsation は主に医学・物理学的文脈で使われるが、スペイン語の pulsación はキーボードの「1回のキー押下」という意味でも日常的に使われ、意味の幅がやや広い。' },
  'pulsador': { es: 'Presiona el pulsador rojo para activar la alarma de emergencia.', ja: '非常警報を作動させるには赤いプッシュボタンを押してください。', trivia: 'ラテン語 pulsare（繰り返し叩く）の行為者名詞形で、英語の push button や switch に相当する。英語に pulser という語はあるが日常語ではなく、pulsador の概念は英語では通常 button や switch で表現される。スペイン語では「押す動作をするもの」という意味が語形に明示されている。' },
  'pulsar': { es: 'Pulsa el botón verde para iniciar la descarga del archivo.', ja: '緑のボタンを押してファイルのダウンロードを開始してください。', trivia: 'ラテン語 pulsare（たたく、突く）に由来し、英語の pulse（脈拍）や pulsar（天体の中性子星）と同語根。天体のパルサー（pulsar）という名称は、規則的な電波信号を「脈打つ星」として命名されたもので、スペイン語でもそのまま pulsar と呼ばれる。' },
  'pulso': { es: 'El médico le tomó el pulso y notó que latía con demasiada rapidez.', ja: '医師が脈を測ると、あまりにも速く打っていることに気づいた。', trivia: 'ラテン語 pulsus（叩くこと、拍動）に由来し、英語の pulse と完全に同語根。英語の pulse も医学から音楽・電子工学まで幅広く使われるが、スペイン語の pulso には「手の安定感（a pulso：腕力だけで、じかに）」という身体的な慣用表現があり独自の意味拡張を見せる。' },
  'pulverización': { es: 'La pulverización de pesticidas debe realizarse con equipo de protección adecuado.', ja: '農薬の散布は適切な保護具を着用して行う必要がある。', trivia: 'ラテン語 pulvis / pulveris（粉、塵）に由来し、英語の pulverization と完全に同語根。英語の powder（粉）もフランス語経由で同じラテン語語根に遡る。スペイン語の polvo（埃・粉）も同語根で、pulverizar と polvo が親戚語であることは語学的に興味深い。' },
  'pulverizar': { es: 'El atleta pulverizó el récord mundial de los 100 metros.', ja: 'その選手は100メートルの世界記録を大幅に塗り替えた。', trivia: 'ラテン語 pulvis（粉）から来ており、英語の pulverize と同語根・同形。「粉砕する」が原義で、英語でも pulverize には「徹底的に打ち負かす」という比喩的用法がある点でも共通している。スペイン語・英語ともに比喩的に「記録を粉砕する」という用法が定着している。' },
  'puma': { es: 'El puma es el felino más ágil de las montañas de los Andes.', ja: 'プーマはアンデス山脈で最も俊敏なネコ科動物だ。', trivia: 'ケチュア語（インカ帝国の言語）の puma（ライオン、強力な動物）に由来し、スペイン語を経由して英語にも puma としてそのまま借用された。英語では cougar や mountain lion とも呼ばれるが、puma は学術名・一般名として国際的に通用する。スポーツブランドの「PUMA」もこの動物から命名。' },
  'puna': { es: 'Los viajeros que visitan la puna andina deben hidratarse bien para evitar el mal de altura.', ja: 'アンデスの高原を訪れる旅行者は、高山病を防ぐためしっかり水分を補給する必要がある。', trivia: 'ケチュア語の puna（高地の草原・荒野）に由来し、アンデス地域特有の地形を表す。英語には直接対応する一語がなく、highland plateau や altiplano などで表現される。puna は英語の地理学・生態学の文献にもスペイン語からの借用語としてそのまま使われることがある。' },
  'punción': { es: 'El anestesiólogo realizó una punción lumbar para administrar la epidural.', ja: '麻酔科医は硬膜外麻酔を行うため腰椎穿刺を実施した。', trivia: 'ラテン語 pungere（刺す）の名詞形 punctio に由来し、英語の puncture（パンク、穿孔）や point（点）と同語根。英語の puncture が「タイヤのパンク」にも使われるように、両語とも「刺す・穴を開ける」という基本概念を共有しており、医学専門語では puncion / puncture がほぼ対応する。' },
  'pundonor': { es: 'Un jugador con pundonor nunca abandona aunque vaya perdiendo.', ja: 'プライドのある選手は負けていても絶対に諦めない。', trivia: 'スペイン語の古語表現 punto de honor（名誉の一点）が縮約してできた合成語で、英語に直接対応する一語はない（self-respect, professional pride, honor などで表現）。この種の合成縮約語（contracción）はスペイン語に特有の語形成で、英語への翻訳が難しい文化的概念語の一つ。' },
  'pungente': { es: 'El queso azul tiene un sabor pungente que no le gusta a todo el mundo.', ja: 'ブルーチーズはツンとした風味があり、誰もが好むわけではない。', trivia: 'ラテン語 pungere（刺す、突く）の現在分詞形 pungens に由来し、英語の pungent と完全に同語根・同形に近い。英語の pungent も「ツンとした匂い・味、辛辣な批評」に使われ意味がほぼ一致する。point（点）や puncture（穿孔）、poignant（胸を打つ）も同じラテン語語根を持つ。' },
  'púnica': { es: 'La civilización púnica alcanzó su apogeo con Cartago como capital del Mediterráneo occidental.', ja: 'ポエニ文明は西地中海の首都カルタゴを中心に最盛期を迎えた。', trivia: 'ラテン語 Punicus（フェニキア人の、カルタゴの）に由来し、フェニキア語の自称 Pōnīm から来ているとされる。英語でも Punic（ポエニの）として使われ、「Punic Wars（ポエニ戦争）」はローマとカルタゴの戦争を指す。英語 Punic faith（裏切り）という成句はローマ側の偏見的なカルタゴ観を反映している。' },
  'púnico': { es: 'El idioma púnico se habló en el norte de África hasta bien entrada la era cristiana.', ja: 'ポエニ語はキリスト教時代に入ってもかなりの期間、北アフリカで話され続けた。', trivia: 'ラテン語 Punicus（カルタゴの）から来ており、púnica の男性形。英語の Punic と同語根で、フェニキア語（Phoenician）とも語源的に関連する。英語では Phoenician と Punic を区別することがあり、Punic は特にカルタゴおよびその北アフリカ植民地の文化・言語・歴史を指す場合に用いられる。' },
  'punible': { es: 'El fraude fiscal es un delito punible con hasta cinco años de prisión.', ja: '脱税は最長5年の禁固刑に処せられる犯罪である。', trivia: 'ラテン語 punire（罰する）に形容詞語尾 -ible を付けた語。英語の punishable と同語根で、共通の祖先はラテン語 poena（刑罰）であり、さらに古代ギリシャ語 poinē にさかのぼる。' },
  'punición': { es: 'El tribunal determinó que la punición impuesta era desproporcionada al delito cometido.', ja: '裁判所は、科された刑罰は犯した罪に対して不均衡であると判断した。', trivia: 'ラテン語 punitio（処罰）に由来し、英語の punishment と同語根だが、英語では -ment 派生の punishment が定着した一方、スペイン語では punición という名詞形が法律文書で好まれる。' },
  'punta': { es: 'Saca punta al lápiz antes de empezar el examen.', ja: '試験を始める前に鉛筆を削っておきなさい。', trivia: 'ラテン語 puncta（刺すこと、点）から発展した語で、英語の point と同語根。英語 point もフランス語経由で同じラテン語 punctum に由来し、「先端」「点」「岬」など多義性を共有している。' },
  'puntal': { es: 'Los sindicatos han sido el puntal de los derechos laborales durante décadas.', ja: '労働組合は数十年にわたり、労働者の権利の大黒柱であり続けてきた。', trivia: 'punta（先端、支え）に指小辞または派生語尾 -al を付けた語で、英語の prop や pillar に相当する。英語の point と同語根であるが、puntal は建築・土木の「支柱」や比喩的な「中心的人物」として使われる点が特徴的。' },
  'puntapié': { es: 'El delantero dio un puntapié al balón y marcó el gol del partido.', ja: 'フォワードはボールを蹴り、試合を決めるゴールを決めた。', trivia: 'punta（先端）と pie（足）を組み合わせた合成語で、「足の先で蹴ること」を意味する。英語では kick という全く異なる語源（古ノルド語または未詳）の語が使われるが、スペイン語は身体部位を組み合わせた合成語という独自の形成法を取る。' },
  'puntuar': { es: 'El profesor tardó varios días en puntuar todos los exámenes del curso.', ja: '教授がコースの全ての試験を採点するのに数日かかった。', trivia: 'ラテン語 punctuare（点を打つ）に由来し、英語の punctuate と完全な同語根。英語 punctuate は主に「句読点を打つ」「強調する」の意だが、スペイン語 puntuar は「採点する・得点する」の意味でも日常的に使われる。' },
  'puntear': { es: 'El guitarrista prefiere puntear las cuerdas en lugar de rasguearlas para ese tipo de melodía.', ja: 'そのギタリストはそういうメロディーにはストラムではなくピッキングを好む。', trivia: 'punta（先端）から派生した動詞で、「指先や爪で弦をはじく」という意味。英語では pick や pluck（こちらはゲルマン語系）という別語源の語を使うが、スペイン語は「先端で触れる」という視覚的な動作概念から動詞を形成した。' },
  'puntería': { es: 'Su buena puntería le permitió ganar la competencia de tiro al blanco sin esfuerzo.', ja: '彼女の優れた照準能力のおかげで、射撃競技を難なく制することができた。', trivia: 'puntear（狙う）または punta（先端）から派生し、語尾 -ería は技術・能力・傾向を表す。英語の aim はフランス語経由のロマンス語系だが、puntería は「先端（照星）で合わせる」という具体的な動作概念を語源に持つ点が興味深い。' },
  'puntero': { es: 'El presentador usó un puntero láser para señalar los datos clave en la pantalla.', ja: '発表者はスクリーン上の重要なデータを指し示すためにレーザーポインターを使った。', trivia: 'punta（先端）＋ -ero（道具・人を表す語尾）から成る語で、英語の pointer と完全に対応する。形容詞として「最先端の」の意味にも使われ、技術的文脈では英語 cutting-edge と同義になるという興味深い意味拡張がある。' },
  'puntiaguda': { es: 'La bailarina calzaba zapatillas puntiagudas para ejecutar los pasos en las puntas.', ja: 'バレリーナはトウで踊るステップを実行するために先の尖ったシューズを履いていた。', trivia: 'punta（先端）と agudo（鋭い、ラテン語 acutus 由来）の合成形容詞の女性形で、puntiagudo が男性形。英語の pointed は同様に「先端がある」という意味だが、スペイン語は二語を組み合わせて一語に凝縮した複合形容詞を形成している。' },
  'puntiagudo': { es: 'El mago llevaba un sombrero puntiagudo adornado con estrellas y lunas.', ja: 'その魔法使いは星と月で飾られた先の尖った帽子をかぶっていた。', trivia: 'punta（先端）と agudo（鋭い）の合成形容詞の男性形。英語の pointed や sharp と同義だが、英語 acute も同じラテン語 acutus から来ており、数学や医学で「鋭角・急性」を表す acute と agudo は完全な同語根コグネートである。' },
  'puntilla': { es: 'El vestido de novia estaba adornado con una delicada puntilla en el borde del escote.', ja: 'ウェディングドレスのネックラインの縁には繊細なレースが飾られていた。', trivia: 'punta の指小辞形（-illa）で「小さな先端」が原義。闘牛でとどめを刺す短剣の意味から dar la puntilla（とどめを刺す）という慣用句が生まれた。英語では lace（レース飾り）や coup de grâce（とどめ）と全く異なる語を使う。' },
  'puntillitas': { es: 'Pedimos puntillitas fritas con limón y alioli como aperitivo antes del marisco.', ja: '魚介料理の前に、前菜としてレモンとアリオリ添えのヒイカの唐揚げを注文した。', trivia: 'puntilla の複数形の指小辞形で、「非常に小さな先端を持つもの」が語源的意味。スペイン料理でヒイカ・ホタルイカ類の揚げ物を指す地域語で、英語では tiny squid（小さなイカ）と説明的に言うほかなく、対応する一語の英訳は存在しない。' },
  'puntillo': { es: 'El puntillo detrás de la negra hace que dure un tiempo y medio en vez de uno.', ja: '四分音符の後ろの付点があることで、音符は一拍ではなく一拍半の長さになる。', trivia: 'punta の指小辞形（-illo）で「小さな点」が原義。音楽用語の「付点」としてはラテン語 punctum（点）に直接さかのぼり、英語の dotted note の dot と完全に同語根。比喩的な「ちょっとしたこだわり」の用法はスペイン語独自の意味拡張。' },
  'puntillosa': { es: 'La directora es muy puntillosa con la presentación de los informes y rechaza cualquier error de formato.', ja: 'その部長は報告書の体裁に非常にうるさく、書式のエラーはどんな些細なものでも突き返す。', trivia: 'puntillo（小さなこだわり）＋ -osa（形容詞語尾）の女性形。英語の punctilious と同語根（ラテン語 punctum）で意味も近いが、英語 punctilious は「礼儀・規則に几帳面」というやや肯定的なニュアンスも持つのに対し、スペイン語 puntillosa は批判的なトーンが強い。' },
  'puntilloso': { es: 'Mi jefe es tan puntilloso que revisa cada coma de los contratos antes de firmarlos.', ja: '私の上司は非常に細かくて、契約書に署名する前にコンマ一つ一つまでチェックする。', trivia: 'puntillosa の男性形。英語の punctilious（几帳面な、礼儀に細かい）と同語根（ラテン語 punctum）だが、日常会話では批判的なニュアンスで使われることが多い点がスペイン語の特色。英語では meticulous（ラテン語 metus 由来）も同義で使われる。' },
  'puntuación': { es: 'Olvidó usar la puntuación correcta y el mensaje resultó confuso para los lectores.', ja: '正しい句読点を使うのを忘れたため、そのメッセージは読者には分かりにくいものになってしまった。', trivia: 'ラテン語 punctuatio（点を打つこと）に由来し、英語の punctuation と完全な同語根・同義の対応語（コグネート）。スポーツや試験での「得点・スコア」という意味も持つことが英語との相違点で、英語では scoring や score が別途使われる。' },
  'puntual': { es: 'En Japón es imprescindible ser puntual, ya que los trenes salen al segundo exacto.', ja: '日本では時間を守ることが不可欠で、電車は正確に秒単位で出発する。', trivia: 'ラテン語 punctualis（点に関する）に由来し、英語の punctual と完全な同語根・同義のコグネート。ただしスペイン語では「特定の・ピンポイントの」という用法（una visita puntual＝一度限りの訪問）もあり、英語 punctual にはない多義性を持つ。' },
  'puntualidad': { es: 'La puntualidad es considerada una muestra de respeto hacia los demás en muchas culturas.', ja: '時間厳守は多くの文化で他者への敬意の表れと見なされている。', trivia: 'puntual＋ -idad（抽象名詞語尾）から成り、英語の punctuality と完全な同語根・同義のコグネート。両語ともラテン語 punctum（点）にさかのぼり、「時間の一点を守る」という概念が語源に潜んでいる。' },
  'puntualizar': { es: 'Quiero puntualizar que esa decisión fue tomada antes de que yo asumiera el cargo.', ja: 'その決定は私が就任する以前に下されたものであることを明確にしておきたい。', trivia: 'puntual＋動詞語尾 -izar（英語の -ize に対応）から成る語。英語の to specify や to clarify に相当するが、punctualize という英単語は obsolete（廃語）であり現代英語ではほぼ使われない。英語で最も近いのは to point out（ラテン語 punctum 由来の point を使用）。' },
  'puntualmente': { es: 'El fontanero llegó puntualmente a las nueve de la mañana, lo cual me sorprendió gratamente.', ja: '配管工は午前9時きっかりに到着し、それは嬉しい驚きだった。', trivia: 'puntual に副詞語尾 -mente（ラテン語 mens/mente 由来）を付けた語で、英語の punctually と完全に対応するコグネート。スペイン語では「定期的に・毎回欠かさず」（paga puntualmente sus impuestos＝毎年きちんと税金を払う）という用法もあり、英語 punctually より意味が広い。' },
  'punzada': { es: 'Sintió una punzada de culpa al ver la mirada decepcionada de su madre.', ja: '母親のがっかりした表情を見て、胸に痛みが走るような罪悪感を覚えた。', trivia: 'punzar（刺す）の過去分詞が名詞化した語で、英語の pang や twinge に相当。pang は古英語由来、twinge はゲルマン語系で語源が全く異なるが、スペイン語 punzada はラテン語 punctum（点・刺し傷）の系譜を引く。英語では「良心の呵責」に pang of conscience という表現を使う。' },
  'punzante': { es: 'El crítico escribió un comentario punzante que dejó a la autora sin palabras.', ja: 'その評論家は辛辣なコメントを書き、作家を言葉を失わせた。', trivia: 'punzar の現在分詞が形容詞化した語で、「刺すような」という物理的な痛みから「痛烈な批判」まで広く使われる。英語の piercing や biting（ゲルマン語系）が同義に使われるが、punzante はラテン語 punctum 由来で、英語の puncture（刺し傷、パンク）と同語根。' },
  'punzar': { es: 'El recuerdo de sus palabras seguía punzándole el corazón días después de la discusión.', ja: '口論から数日後も、彼女の言葉の記憶が胸をチクチクと痛め続けていた。', trivia: 'ラテン語 punctiare（点を突く）に由来し、英語の puncture（パンクさせる）や pungent（刺激的な、ピリッとした）と同語根。英語 pungent は「刺すような臭い・味」を表すが、スペイン語 punzar は身体的・心理的な「刺す感覚」の動詞として現役で使われる。' },
  'puñado': { es: 'Añadió un puñado de nueces al yogur para darle un toque crujiente.', ja: '食感のアクセントをつけるためにヨーグルトにひと握りのくるみを加えた。', trivia: 'puño（握りこぶし、ラテン語 pugnus 由来）に指小辞または派生語尾 -ado を付けた語で「拳いっぱい」が原義。英語の handful が hand＋ful（満杯）の合成であるのと同様に、puñado も「拳の中に収まる量」という身体基準の計量表現。英語 pugnacious（好戦的な）も同じ pugnus が語源。' },
  'puñal': { es: 'El asesino ocultaba un puñal bajo la capa cuando entró en el castillo.', ja: '暗殺者は城に入るとき、マントの下に短剣を隠していた。', trivia: 'ラテン語 pugnus（拳）から派生した語で、英語の dagger とは語源が異なる。英語では dagger と言い、同じラテン語語根からは punch（パンチ）や pugnacious（好戦的な）などが生まれている。' },
  'puñalada': { es: 'La noticia del despido fue una puñalada en la espalda que no esperaba.', ja: '解雇の知らせは、予期していなかった背中への一刺しのようだった。', trivia: 'puñal（短剣）に動作・結果を表す接尾辞 -ada を加えた語で、英語の stab に相当する。「背後から刺す」という比喩表現は英語でも stab in the back と言い、裏切りを意味する点でほぼ対応する。' },
  'puñetera': { es: '¡Esta puñetera impresora no funciona justo cuando más la necesito!', ja: '一番必要なときに、このいまいましいプリンターが動かない！', trivia: 'puño（拳）から派生したスペイン口語の罵り語で、puñetero の女性形。英語の bloody や damned に相当するが、文化的ニュアンスはスペインに独特のもの。英語の fist と同根（ラテン語 pugnus）という面白い関係がある。' },
  'puñetero': { es: '¡Qué puñetero tráfico! Llevo una hora atascado en la autopista.', ja: 'なんて忌々しい渋滞だ！高速道路で1時間も詰まっている。', trivia: 'puño（拳）から派生したスペイン口語の強調表現で、英語の bloody や damn に近い。ラテン語 pugnus（拳）は英語の fist とは語源が異なるが、punch（パンチ）や impugn（異議を唱える）の語根と共通している。' },
  'puño': { es: 'El boxeador levantó el puño en señal de victoria al final del combate.', ja: 'ボクサーは試合終了後、勝利のしるしに拳を突き上げた。', trivia: 'ラテン語 pugnus（拳）から来ており、英語の fist とは語源が異なるが、英語の pugil（拳闘士：pugilis から）や impugn（異議を唱える）と同語根。スペイン語では「拳」と「袖口」と「持ち手」がすべて puño と呼ばれるのが特徴的。' },
  'pupa': { es: 'El niño lloraba porque se había hecho una pupa en la rodilla al caerse.', ja: '子どもは転んで膝に傷を作り、泣いていた。', trivia: 'ラテン語 pupa（少女・人形・サナギ）から来ており、英語の pupil、puppet（人形）、pupa（サナギ）と同語根。スペイン語では幼児語として「痛いの」の意味で使われる一方、医学用語として「ヘルペス」、生物学用語として「サナギ」も指す多義語。' },
  'pupila': { es: 'El médico le examinó las pupilas con una linterna para comprobar sus reflejos.', ja: '医師は反射を確認するため、懐中電灯で瞳孔を調べた。', trivia: 'ラテン語 pupilla（小さな少女・人形）から来ており、英語の pupil と完全に同語根。「瞳孔」という意味は、目の中に小さな人形のように自分の姿が映って見えることから生まれたとされる。英語 pupil は「生徒」と「瞳孔」の両方の意味を持つ点もスペイン語と共通。' },
  'pupilaje': { es: 'Durante sus estudios en Madrid, vivió en régimen de pupilaje en casa de una familia local.', ja: 'マドリードでの学生時代、彼は地元の家庭に下宿して生活した。', trivia: 'pupilo（被後見人・寄宿生）にラテン語由来の名詞化接尾辞 -aje（英語の -age に相当）を加えた語。英語には対応する一語がなく、boarding arrangement や tutorship などで訳される。フランス語 pupillage とも関連が深い。' },
  'pupilar': { es: 'La dilatación pupilar puede ser un signo de intoxicación o de ciertas enfermedades.', ja: '瞳孔散大は中毒や特定の疾患のサインとなりうる。', trivia: 'ラテン語 pupilla（瞳孔・被後見人）から派生した形容詞で、英語の pupillary と同語根かつ同義。医学用語として両言語で高い透明度を持つ国際的な術語のひとつ。' },
  'pupilo': { es: 'El entrenador trataba a cada pupilo con un plan de entrenamiento personalizado.', ja: 'コーチはそれぞれの門下生に個別のトレーニング計画を立てていた。', trivia: 'ラテン語 pupillus（孤児・被後見人）から来ており、英語の pupil と完全に同語根。ラテン語 pupus（少年）が語源で、英語では pupil が「生徒」と「被後見人」の両義を持つが、スペイン語では alumno（生徒）と pupilo（門下生・被後見人）が使い分けられる傾向がある。' },
  'pupitre': { es: 'Los alumnos sacaron sus libros y los pusieron sobre el pupitre antes de que llegara el profesor.', ja: '生徒たちは先生が来る前に、本を取り出して学習机の上に置いた。', trivia: 'フランス語 pupitre から借用された語で、フランス語はラテン語 pulpitum（台・演壇）に由来する。英語の pulpit（説教壇）と同語根であり、「台の上に乗せる」という基本概念が共通している。' },
  'purasangre': { es: 'El jockey montó un purasangre de cuatro años que ganó todas las carreras de la temporada.', ja: '騎手は今シーズン全レースを制した4歳のサラブレッドに騎乗した。', trivia: 'スペイン語で「純粋な血」を意味する pura（純粋な）+ sangre（血）の合成語。英語の thoroughbred（サラブレッド）は「徹底的に品種改良された」という意味で、語源的アプローチが全く異なるのが興味深い。英語の purebred とはより直接的に対応する。' },
  'puré': { es: 'Para cenar preparé un puré de patatas con mantequilla y un poco de nuez moscada.', ja: '夕食にバターとナツメグを加えたマッシュポテトを作った。', trivia: 'フランス語 purée から借用された語で、フランス語はラテン語 purare（浄化する・こす）に由来する。英語の purée もフランス語からの借用語であり、スペイン語 puré と英語 purée は同じ語源を持つ姉妹語。スペイン語ではアクセント記号付きの puré と綴る。' },
  'pureza': { es: 'La pureza del agua de manantial de esta región es reconocida en todo el país.', ja: 'この地域の湧き水の純粋さは、全国的に認められている。', trivia: 'ラテン語 puritas から派生した語で、英語の purity と同語根。ラテン語 purus（清潔な・純粋な）が共通の祖先で、英語では pure、purify、puritan なども同系統。スペイン語の -eza 接尾辞は英語の -ity/-ness に相当する抽象名詞化の形。' },
  'purga': { es: 'La purga política de los años treinta dejó al partido sin sus mejores líderes.', ja: '1930年代の政治的粛清により、党は最良の指導者たちを失った。', trivia: 'ラテン語 purgare（清める・取り除く）から来ており、英語の purge と完全に同語根かつ同義。スターリン時代のソ連を指す「大粛清」は英語で Great Purge、スペイン語で Gran Purga と呼ばれ、両語が国際的政治語彙として定着している。' },
  'purgación': { es: 'En la medicina medieval, la purgación del cuerpo se consideraba esencial para recuperar la salud.', ja: '中世医学では、体の浄化は健康を取り戻すために不可欠とされていた。', trivia: 'ラテン語 purgatio（浄化）から来ており、英語の purgation と同語根・同義。医学用語としては現在ほとんど使われないが、宗教的・哲学的文脈では「罪の浄化」の意味で今も用いられる。英語 purge と同じ語根を共有している。' },
  'purgante': { es: 'El médico le recetó un purgante suave para aliviar el estreñimiento que tenía desde hacía días.', ja: '医師は数日前からの便秘を和らげるため、穏やかな下剤を処方した。', trivia: 'ラテン語 purgans（清める・現在分詞）から来ており、英語の purgative と同語根。英語では purgative が形容詞・名詞として使われるのに対し、スペイン語では purgante の方が日常的によく使われる。薬学の国際用語として両言語で透明度が高い。' },
  'purgar': { es: 'Tuvo que purgar una condena de cinco años en prisión por el delito que cometió.', ja: '彼は犯した罪のため、5年間の刑に服さなければならなかった。', trivia: 'ラテン語 purgare（清める・取り除く）から来ており、英語の purge と同語根。英語 purge が主に「粛清する」「除去する」の意で使われるのに対し、スペイン語 purgar は「刑を服する・罪を償う」の意味でも多く使われる点が興味深い。' },
  'purgatorio': { es: 'Dante describió el Purgatorio como un monte con siete terrazas por las que las almas ascienden hacia el Paraíso.', ja: 'ダンテは煉獄を、魂が天国へと昇っていく七つのテラスを持つ山として描いた。', trivia: '中世ラテン語 purgatorium（清める場所）から来ており、英語の purgatory と完全に同語根。カトリック神学の重要概念として両言語に定着しており、比喩的に「長期の苦しみ」を指す表現としても英語・スペイン語ともに使われる。' },
  'purificación': { es: 'La purificación del agua potable es un proceso esencial para garantizar la salud pública.', ja: '飲料水の浄化は、公衆衛生を保証するための不可欠なプロセスである。', trivia: 'ラテン語 purificatio（浄化）から来ており、英語の purification と同語根かつほぼ同形。ラテン語 purus（清潔な）+ facere（作る）の合成が語源で、英語の pure + -fy（-fication）と構造が完全に対応している。' },
  'purificar': { es: 'Para purificar el aire interior, muchas personas colocan plantas en sus casas.', ja: '室内の空気を浄化するために、多くの人が家に植物を置いている。', trivia: 'ラテン語 purificare（清める）から来ており、英語の purify と同語根。ラテン語 purus（清い）+ facere（する）から成り、英語の purify も同じ構造を持つ。スペイン語の -ficar 動詞と英語の -fy 動詞は多くの場合で対応関係にある（例：clarificar/clarify、amplificar/amplify）。' },
  'purista': { es: 'Los puristas del idioma se oponen al uso de anglicismos en el español cotidiano.', ja: '言語の純粋主義者たちは、日常のスペイン語での英語借用語の使用に反対している。', trivia: 'ラテン語 purus（純粋な）に名詞・形容詞化接尾辞 -ista を加えた語で、英語の purist と同語根かつほぼ同義。英語の -ist とスペイン語の -ista は同じラテン語・ギリシャ語の -ista に由来し、両言語で「ある主義・立場を持つ人」を表す生産的な接尾辞として機能している。' },
  'puritana': { es: 'Su abuela era muy puritana y no toleraba que nadie mencionara temas relacionados con el dinero en la mesa.', ja: '祖母は非常に厳格な人で、食卓でお金に関する話題が出ることを誰にも許さなかった。', trivia: '英語の Puritan（清教徒）から借用された語で、ラテン語 purus（純粋な）が語根。17世紀にイングランドで起きた宗教改革運動に由来し、英語と完全に同じ歴史的背景を持つ借用語。現代では宗教的意味を離れ、道徳的に厳格な人を指す形容詞としても使われる点が英語と共通。' },
  'puritano': { es: 'Tiene una actitud puritana hacia el trabajo y nunca mezcla las horas laborales con el ocio.', ja: '彼は仕事に対して非常に厳格な姿勢を持ち、労働時間と余暇を決して混同しない。', trivia: '英語の Puritan から借用された語で、puritana の男性形。17世紀にイングランドのプロテスタント改革運動から生まれた歴史的・宗教的用語であり、英語と語源・歴史を共有している。現在は「道徳的に厳しい・禁欲的な」という含意を持つ形容詞としても広く使われる。' },
  'puro': { es: 'Lo que ocurrió fue puro accidente; nadie tuvo la intención de causarte daño.', ja: '起きたことは全くの偶然だった。誰もあなたを傷つけるつもりはなかった。', trivia: 'ラテン語 purus（清潔な・純粋な）から直接来ており、英語の pure と完全に同語根。「葉巻」という意味は「純粋なタバコの葉だけで作ったもの」というイメージから生まれたとされ、英語では cigar（スペイン語 cigarro から借用）が使われるため、この意味での対応はない。' },
  'púrpura': { es: 'El cardenal llevaba una túnica de color púrpura que destacaba entre la multitud.', ja: '枢機卿は群衆の中でひときわ目立つ紫色の法衣をまとっていた。', trivia: 'ラテン語 purpura（フェニキア起源の貝から採れた染料）に由来し、英語の purple も同語根。古代ローマでは紫色が皇帝や高貴な身分の象徴だったため、「王位」という意味も持つ。' },
  'purpúrea': { es: 'La puesta de sol tiñó el horizonte con una luz purpúrea de gran belleza.', ja: '夕暮れが地平線を美しい紫色の光で染め上げた。', trivia: 'ラテン語形容詞 purpureus に由来する文語的・詩的な語で、英語にも purpureal という詩語があるが現代ではほとんど使われない。스페イン語では文芸作品で好まれる形。' },
  'purpúreo': { es: 'El poeta describió el mar al atardecer con un tono purpúreo y misterioso.', ja: '詩人は夕暮れどきの海を神秘的な紫色の色調で描写した。', trivia: 'purpúrea の男性形で、ラテン語 purpureus（紫の）に直接由来する。英語の purple と同じ語根だが、purpúreo は日常語より文学・詩的文脈で使われる格調ある語。' },
  'purulenta': { es: 'La herida se volvió purulenta y el médico tuvo que drenarla de inmediato.', ja: '傷口が化膿してしまい、医師はすぐに排膿処置を施さなければならなかった。', trivia: 'ラテン語 purulentus（膿だらけの）に由来し、英語の purulent と同語根。pus（膿）という語を内包しており、医学用語として英語・スペイン語ともに広く使われる。' },
  'purulento': { es: 'El cirujano retiró el tejido purulento para evitar que la infección se extendiera.', ja: '外科医は感染が広がらないよう、化膿した組織を除去した。', trivia: 'purulenta の男性形で、ラテン語 purulentus に由来。英語 purulent と完全に同語根であり、医学・解剖学テキストでは英西どちらでも同じ術語として通用する。' },
  'pus': { es: 'La ampolla se infectó y empezó a acumular pus en su interior.', ja: '水ぶくれが感染し、内部に膿が溜まり始めた。', trivia: 'ラテン語 pus（膿）に由来し、英語・スペイン語ともにそのままの形で使われる珍しい例。古代ギリシャ語の pyon とも関連し、「pyogenic（化膿性の）」など英語の医学用語にも痕跡を残す。' },
  'pusilánime': { es: 'No seas tan pusilánime; defiende tu opinión sin miedo a las críticas.', ja: 'そんなに意気地なしにならないで。批判を恐れず自分の意見を主張しなさい。', trivia: 'ラテン語 pusillanimis（pusillus「小さい」＋ animus「魂」）に由来し、英語の pusillanimous と完全に同語根。「小さな魂を持つ人＝臆病者」という語義が語形に透けて見える面白い語。' },
  'pústula': { es: 'El dermatólogo observó una pústula inflamada en la mejilla del paciente.', ja: '皮膚科医は患者の頬に炎症を起こした膿疱を見つけた。', trivia: 'ラテン語 pustula（小さな膨らみ・吹き出物）に由来し、英語の pustule と同語根。pus（膿）と語根を共有しており、天然痘（viruela）の特徴的な症状として医学史上も重要な語。' },
  'puta': { es: 'En la novela, el personaje usa la expresión «¡puta suerte!» para quejarse de su mala fortuna.', ja: '小説の中で登場人物は自分の不運を嘆くために「クソな運だ！」という表現を使っている。', trivia: '起源には諸説あり、ラテン語 puta（考えられる女、または putida「腐った」）から来るという説が有力だが確定していない。英語の whore はゲルマン語由来で語根が異なるが、スラングとして対応する。スペイン語圏では罵倒語・強調語としての用法が極めて広い。' },
  'putativo': { es: 'El padre putativo del niño lo crió con tanto amor como si fuera su hijo biológico.', ja: 'その子の推定上の父親は、実の子と変わらぬ愛情をもって育て上げた。', trivia: 'ラテン語 putativus（putare「考える・推定する」）に由来し、英語の putative と完全に同語根。法律用語として「putative father（推定父）」のように英西両語で使われ、「実際かどうかは分からないが、そうみなされている」という意味を共有する。' },
  'putear': { es: 'Siempre que pierde, se pone a putear a sus compañeros de equipo sin motivo.', ja: '負けるたびに、彼は理由もなくチームメイたちに悪態をつき始める。', trivia: 'puta を動詞化した俗語で、英語には直接対応する同語根の動詞はない。英語では to trash-talk、to harass などが意味的に近い。スペイン語独自の俗語動詞造語パターン（名詞＋-ear）の典型例。' },
  'puterío': { es: 'Ese barrio tenía fama de puterío, pero con el tiempo se rehabilitó completamente.', ja: 'その界隈はかつて風俗街として知られていたが、時を経て完全に再開発された。', trivia: 'puta に集合・場所を表す接尾辞 -ería/-erío が付いた俗語派生語で、英語には直接の同語根語はない。英語では red-light district（性風俗街）や mess（混乱状態）が文脈によって対応する。' },
  'putrefacción': { es: 'El olor a putrefacción indicaba que el cadáver llevaba varios días sin ser descubierto.', ja: '腐敗臭が、遺体が数日間発見されないままだったことを物語っていた。', trivia: 'ラテン語 putrefactio（putrefacere「腐らせる」＜ puter「腐った」＋ facere「する」）に由来し、英語の putrefaction と完全に同語根。英語の "putrid" も同じ puter を語根に持つ。' },
  'putrefacta': { es: 'La fruta putrefacta que encontraron en el almacén atrajo a una nube de moscas.', ja: '倉庫で見つかった腐敗した果物がハエの大群を引き寄せた。', trivia: 'ラテン語 putrefactus（putrefacere の過去分詞）に由来する形容詞の女性形で、英語 putrid と同語根。英語では putrefied も使われ、いずれもラテン語 puter（腐った）に遡る。' },
  'putrefacto': { es: 'Encontraron el cuerpo putrefacto de un animal en el fondo del barranco.', ja: '渓谷の底で、動物の腐敗した死体が見つかった。', trivia: 'putrefacta の男性形で、英語の putrefied や putrid に意味的に対応する。語根のラテン語 puter は英語の "putrid"、"putrefy" と共通しており、腐敗に関する学術語彙の多くはこの語根を共有している。' },
  'putilla': { es: 'En algunas novelas costumbristas del siglo XIX, el término «putilla» aparece como insulto coloquial.', ja: '19世紀の風俗小説の一部では、「putilla」という語が口語的な悪口として登場する。', trivia: 'puta に指小辞 -illa が付いた形で、スペイン語の指小辞は軽蔑・親しみ・小ささなど多様なニュアンスを加える。英語には同語根の直接対応語はなく、英語の形而上学的な侮蔑語は異なるゲルマン語源を持つことが多い。' },
  'puto': { es: 'Ese puto coche no arranca nunca cuando más lo necesito.', ja: 'このクソ車は一番必要なときに限っていつもエンジンがかからない。', trivia: 'puta の男性形で、強調・罵倒の形容詞として英語の fucking や damn に相当する。英語 fucking はゲルマン語由来で語根は全く異なるが、機能的に酷似している。中南米では「男娼」という名詞用法もあり、地域差が大きい語。' },
  'puzle / puzzle': { es: 'Mi abuela pasa las tardes armando un puzle de mil piezas junto a la ventana.', ja: '祖母は午後を窓際で1000ピースのジグソーパズルを組み立てながら過ごしている。', trivia: '英語の puzzle をスペイン語に取り込んだ外来語で、スペイン語では puzle と綴ることが推奨されているが puzzle の綴りも広く使われる。英語 puzzle の語源は不明で、16世紀に突然文献に現れた謎の語とされる。' },
  'Q / q': { es: 'La letra q en español solo aparece en las combinaciones «qu» seguidas de e o i, como en «queso» y «quiero».', ja: 'スペイン語の文字 q は、「queso（チーズ）」「quiero（欲しい）」のように、e や i の前に qu の組み合わせでのみ現れる。', trivia: 'ラテン語のアルファベット Q はフェニキア文字の「qoph（後頭部）」に由来し、英語でも同じ起源を持つ。英語では qu が「クウ」と発音されるのに対し、スペイン語の qu は「k」の音だけを表し u は発音しない点が大きな違い。' },
  'quásar / cuásar': { es: 'Los astrónomos detectaron un quásar a miles de millones de años luz de distancia con el nuevo telescopio.', ja: '天文学者たちは新しい望遠鏡を使って、数十億光年先のクエーサーを検出した。', trivia: '英語の quasar（quasi-stellar radio source＝準恒星状電波源の略）に由来する天文学用語で、1960年代に作られた造語。英語から直接借用されたため英語の quasar と完全に同語根であり、スペイン語式綴りの cuásar も公式に認められている。' },
  'qué': { es: '¡Qué sorpresa tan agradable encontrarte aquí después de tantos años!', ja: 'こんなところで何年ぶりかに会うなんて、なんと嬉しいサプライズだろう！', trivia: 'ラテン語の疑問代名詞 quid／quod に由来し、英語の what や which も同じインド・ヨーロッパ語祖語の語根 *kʷo-（疑問詞語根）を共有する遠い仲間。アクセント記号（tilde）の有無（que／qué）で接続詞と疑問・感嘆詞を区別するスペイン語の特徴がある。' },
  'quebrada': { es: 'Los niños del pueblo bajaban a bañarse en la quebrada cuando hacía calor.', ja: '暑い日には、村の子供たちが涼みに小川へ下りていった。', trivia: 'quebrar（割る・壊す）の過去分詞が名詞化した語で、「割れた地形＝渓谷・川」という意味の発展が見られる。英語の break と同じインド・ヨーロッパ語祖語 *bhreg-（割る）を持つゲルマン語系動詞に対応し、概念的に類似した意味変化をたどった。' },
  'quebradero': { es: 'Los preparativos de la boda se convirtieron en un auténtico quebradero de cabeza para toda la familia.', ja: '結婚式の準備は、家族全員にとって本物の頭痛のタネになった。', trivia: 'quebrar（壊す）＋接尾辞 -dero（場所・道具・手段）から成り、quebradero de cabeza（頭を壊すもの＝悩みのタネ）という慣用句で最もよく使われる。英語の headache が「頭痛」から「悩みのタネ」を意味するのと同様の比喩的意味拡張が見られる。' },
  'quebradiza': { es: 'La figura de porcelana era tan quebradiza que había que manipularla con sumo cuidado.', ja: 'その磁器の人形はとても壊れやすく、扱うには細心の注意が必要だった。', trivia: 'quebrar（壊す）＋形容詞接尾辞 -adizo（〜しやすい傾向がある）から派生した語で、英語の brittle や fragile に意味が対応する。brittle はゲルマン語由来、fragile はラテン語由来と語源は異なるが、quebradiza はスペイン語内部での派生語。' },
  'quebradizo': { es: 'El hielo de la laguna estaba quebradizo y era peligroso caminar sobre él.', ja: '湖の氷はもろくなっており、その上を歩くのは危険だった。', trivia: 'quebradiza の男性形で、quebrar（割る・壊す）に接尾辞 -adizo が付いた語。英語の fragile はラテン語 fragilis に由来し、frangere（壊す）と語根が共通するが、スペイン語の quebrar はラテン語 crepare（割れる）から来ており別系統。' },
  'quebradura': { es: 'El médico confirmó que la quebradura en la muñeca requería inmovilización durante seis semanas.', ja: '医師は手首の骨折が6週間の固定を必要とすると確認した。', trivia: 'ラテン語 *quaerere*（探す）ではなく *crepare*（割れる、砕ける）に由来する語根 *quebrar* から派生。英語の *fracture* はラテン語 *fractura* 由来で語根は異なるが、意味上「折れ目・亀裂」を表す点では並行している。' },
  'quebrantamiento': { es: 'El quebrantamiento de las normas de tráfico puede acarrear sanciones muy graves.', ja: '交通規則の違反は非常に重大な処罰をもたらす可能性がある。', trivia: 'ラテン語後期の *crepantare*（砕く）に由来し、スペイン語の *quebrar* の名詞形。英語では *violation* や *breach* に相当するが、英語の *breach* はゲルマン語系（古英語 *brǣc*）で語根は全く異なる。' },
  'quebrantar': { es: 'Quien quebranta un contrato puede ser demandado por daños y perjuicios.', ja: '契約を破った者は損害賠償で訴えられる可能性がある。', trivia: 'ラテン語俗語 *crepantare*（繰り返し砕く）に由来し、スペイン語の *quebrar* を強意化した動詞。英語の *break* はゲルマン語系（古英語 *brecan*）で語根は異なるが、「法律・約束を破る」という比喩的用法はほぼ完全に対応している。' },
  'quebranto': { es: 'La pérdida de su empresa le causó un quebranto económico del que tardó años en recuperarse.', ja: '会社を失ったことで彼は経済的な大打撃を受け、回復するのに何年もかかった。', trivia: '動詞 *quebrantar* の名詞形で、ラテン語俗語 *crepantare* に由来する。英語に直接対応する単語はなく、*loss*・*grief*・*ruin* を状況に応じて使い分ける必要がある点が特徴的。' },
  'quebrar': { es: 'La empresa no pudo pagar sus deudas y tuvo que quebrar el año pasado.', ja: 'その会社は負債を返済できず、昨年倒産せざるを得なかった。', trivia: 'ラテン語俗語 *crepare*（割れる、砕ける）に由来し、古典ラテン語の *creare*（創る）とは別語。英語の *break* はゲルマン語系で語源は異なるが、「会社が break する＝倒産する」という用法は英語でも同様に使われる興味深い並行性がある。' },
  'queche': { es: 'El queche navegaba silenciosamente por la bahía con sus dos mástiles inclinados al viento.', ja: 'そのケッチは2本のマストを風に傾けながら、静かに湾内を航行していた。', trivia: '英語の *ketch* から借用した語で、17世紀頃にオランダ語 *ketse* または低地ドイツ語 *keutse* を経由して英語に入ったとされる。語源については諸説あり、確定していない。英語とスペイン語でほぼ同じ発音・意味の珍しい借用語の一つ。' },
  'quedada': { es: 'Organizamos una quedada el sábado para vernos todos después de tanto tiempo.', ja: '久しぶりに全員で会うために、土曜日に集まりを企画した。', trivia: '動詞 *quedar* の名詞形で、*quedar* はラテン語 *quietare*（静まる、落ち着く）に由来する。英語では *meetup* や *get-together* に相当するが、英語の *quiet* と同じ語根を持っており、「落ち着く→待ち合わせる→集まる」という意味の変遷が面白い。' },
  'quedito': { es: 'Habla quedito, que el bebé ya se quedó dormido.', ja: '赤ちゃんがもう寝たから、静かに話して。', trivia: '形容詞 *quedo*（静かな）の指小辞形で、*quedo* はラテン語 *quietus* に由来する。英語の *quiet* と完全に同語根であり、英語での「quietly」にあたる表現が *quedito* として親しみやすい指小辞付きで中南米口語に定着した。' },
  'queja': { es: 'Presenté una queja formal al servicio de atención al cliente por el retraso en la entrega.', ja: '配送の遅延について、顧客サービスに正式な苦情を申し立てた。', trivia: '動詞 *quejarse* の名詞形で、*quejarse* の語源はラテン語 *quassare*（激しく揺する、壊す）に由来するとされる。英語の *complaint* はラテン語 *complangere*（嘆く）由来で語根は異なるが、似た意味を持つ *querulous*（愚痴っぽい）は同じ語族と関連している。' },
  'quejarse': { es: 'Los vecinos se quejan constantemente del ruido que hacen los estudiantes por la noche.', ja: '近所の人たちは夜に学生たちが出す騒音について絶えず不満を言っている。', trivia: 'ラテン語 *quassare*（激しく揺さぶる）に由来するとされ、「心を激しく揺さぶられる→嘆く」という意味変化を経た。英語の *complain* とは語根が異なるが、英語形容詞 *querulous*（愚痴っぽい）はラテン語 *queri*（嘆く）由来で *quejarse* と語根的に近い関係にある。' },
  'quejumbrosa': { es: 'Con voz quejumbrosa, la niña pidió que no la llevaran al médico.', ja: 'その女の子は泣き言を言うような声で、病院に連れて行かないでと頼んだ。', trivia: '*queja*（苦情）＋接尾辞 *-umbroso* から形成された形容詞の女性形。英語では *querulous* または *whiny* に相当し、ラテン語 *querulus*（嘆く）と同じ語根を共有している。英語の *quarrel*（口論）も同じ語族に属する。' },
  'quejumbroso': { es: 'Es tan quejumbroso que siempre encuentra algo de lo que lamentarse, aunque todo vaya bien.', ja: '彼はとても愚痴っぽいので、すべてがうまくいっていても必ず何か嘆くことを見つける。', trivia: '*queja* と接尾辞 *-umbroso*（〜の性質を持つ）から派生した形容詞の男性形。英語の *querulous* と同語根（ラテン語 *querulus*）であり、また英語の *quarrel* や *quarrelsome* とも関連する語族で、「不満・嘆き」という意味が共通している。' },
  'quelite': { es: 'En los mercados de Oaxaca se venden distintos tipos de quelites que se usan en la cocina tradicional.', ja: 'オアハカの市場では、伝統料理に使われるさまざまな種類のケリテが売られている。', trivia: 'ナワトル語 *quilitl*（食用野草）に由来するメキシコ先住民語からの借用語。英語には直接対応する語がなく、*wild greens* や *edible herbs* と説明されることが多い。スペイン語の植物語彙にはナワトル語由来のものが多く、*quelite* はその典型例の一つ。' },
  'quemada': { es: 'Salió de la cocina con una quemada en el brazo después de salpicarse con aceite caliente.', ja: '熱い油が飛び散って、腕にやけどを負いながら台所から出てきた。', trivia: '動詞 *quemar*（燃やす）の過去分詞の女性形が名詞化したもの。ラテン語 *cremare*（焼く）に由来し、英語の *cream* とは同語根ではないが、英語で「燃やす」を意味する *cremate*（火葬する）とは同じラテン語語根を共有している。' },
  'quemadero': { es: 'El quemadero de residuos industriales fue clausurado por las autoridades medioambientales.', ja: '産業廃棄物の焼却炉は環境当局によって閉鎖された。', trivia: '*quemar*（燃やす）＋接尾辞 *-dero*（場所・道具を示す）から形成された語。ラテン語 *cremare* に由来する。英語の *crematorium* も同じラテン語語根 *cremare* を持ち、「火葬する」を意味する *cremate* とも直接つながる。歴史的には異端審問の火刑場を指した重い語でもある。' },
  'quemadura': { es: 'Debes aplicar agua fría inmediatamente sobre una quemadura para aliviar el dolor.', ja: 'やけどの痛みを和らげるために、すぐに冷水を当てなければならない。', trivia: '*quemar* の名詞形で、ラテン語 *cremare*（焼く）に由来する。英語の *burn* はゲルマン語系（古英語 *byrnan*）で語源は全く異なる。一方、英語の *cremation*（火葬）は同じラテン語語根 *cremare* を共有しており、より専門的な文脈で対応する。' },
  'quemar': { es: 'Hay que quemar los documentos confidenciales que ya no se necesitan.', ja: 'もう必要のない機密書類は焼却しなければならない。', trivia: 'ラテン語 *cremare*（焼く、火葬する）に由来し、英語の *cremate* と同語根。日常語の英語 *burn* は古英語 *byrnan* というゲルマン語系で語根が異なるが、専門用語レベルでは *quemar* と英語 *cremate* が語源的に兄弟関係にある。' },
  'quemazón': { es: 'Sentí una quemazón intensa en la piel después de estar demasiado tiempo al sol.', ja: '長時間日光に当たった後、肌にひどい灼熱感を感じた。', trivia: '*quemar* に名詞化接尾辞 *-azón* が付いた語で、ラテン語 *cremare* に由来する。英語には「灼熱感・かゆみ」を一語で表す完全な対応語はなく、*burning sensation* と説明するしかない。英語の *cremation* とは同語根だが、日常的な「ヒリヒリ感」から転じた意味が興味深い。' },
  'quepis': { es: 'Los soldados desfilaron con sus quepis perfectamente alineados bajo el sol de verano.', ja: '兵士たちは夏の日差しの下、ケピ帽を完璧に揃えてパレードした。', trivia: 'フランス語 *képi* からの借用語で、フランス語はアルザス方言 *käppi*（小さな帽子）に由来する。英語でも *kepi* または *képi* として同じフランス語から借用されており、スペイン語・英語ともにフランス軍帽文化の影響を受けた共通の借用語である。' },
  'queques': { es: 'Mi abuela preparó unos queques de vainilla deliciosos para la merienda del domingo.', ja: '祖母は日曜日のおやつにおいしいバニラケーキをいくつか作ってくれた。', trivia: '英語 *cake* のスペイン語音写で、中南米（コスタリカ・ペルーなど）とカナリア諸島で使われる口語表現。英語の *cake* 自体は古ノルド語 *kaka* に由来し、スウェーデン語・ノルウェー語の *kaka* と同語根。*queque* は英語音を直接スペイン語表記に転写した珍しい借用語。' },
  'querella': { es: 'El empresario presentó una querella contra el periódico por difamación.', ja: 'その実業家は名誉毀損を理由に新聞社に対して告訴状を提出した。', trivia: 'ラテン語 *querela*（苦情、嘆き）に由来し、*queri*（嘆く）が語根。英語の *quarrel*（口論）も同じラテン語 *querela* に由来する同語根語（コグネート）であり、「嘆き→争い→法的紛争」という意味の分岐が英語とスペイン語で異なる方向に発展した好例。' },
  'querellante': { es: 'El abogado del querellante solicitó que se ampliaran los cargos contra el acusado.', ja: '告訴人の弁護士は被告に対する訴因の拡大を求めた。', trivia: 'ラテン語 *querela*（苦情）＋動詞化接尾辞 *-ar* → *querellar* の現在分詞・名詞形。英語の *complainant*（告訴人）はラテン語 *complangere* 由来で語根は異なるが、英語の *quarrelsome*（口論好きな）は同語根 *querela* に由来し、語族的につながっている。' },
  'querellarse': { es: 'La víctima decidió querellarse contra su empleador por acoso laboral.', ja: '被害者は職場でのハラスメントを理由に雇用主に対して告訴することを決めた。', trivia: 'ラテン語 *querelari*（嘆く、苦情を言う）に由来する再帰動詞。英語の *quarrel*（口論する）は同じラテン語 *querela* を語根とする同語根語で、法的な告訴を意味するスペイン語の用法と日常的な口論を意味する英語の用法とで意味が大きく異なる興味深いコグネート。' },
  'querida': { es: 'La novela narra la historia de una querida que vivía en secreto en el barrio antiguo de la ciudad.', ja: 'その小説は、街の旧市街に密かに暮らす愛人の物語を描いている。', trivia: '動詞 *querer*（愛する、望む）の過去分詞女性形が名詞化したもので、ラテン語 *quaerere*（求める、探す）に由来する。英語の *query*（質問）や *quest*（探求）も同じラテン語語根を持つ同語族語であり、「求める」という根本的な意味が「愛する」へと変化したスペイン語の意味発展が興味深い。' },
  'querido': { es: 'Querido amigo, hace mucho tiempo que no nos vemos y me encantaría quedar contigo pronto.', ja: '親愛なる友よ、しばらく会っていないね、近いうちにぜひ会いたいな。', trivia: 'ラテン語 *quaerere*（求める、探す）に由来する *querer* の過去分詞男性形。英語の *query*（疑問）・*quest*（探求）・*question*（質問）・*acquire*（獲得する）はすべて同じラテン語語根 *quaerere* を共有しており、「求める」という意味から「愛する・大切にする」へと発展したスペイン語独自の意味変化が見られる。' },
  'querubín': { es: 'El niño dormía tan plácidamente que su madre lo miraba como si fuera un querubín.', ja: 'その子はとても穏やかに眠っていたので、母親はまるでケルビムのように見つめていた。', trivia: 'ヘブライ語の「כְּרוּב（kerúv）」に由来し、ラテン語「cherubim」を経てスペイン語に入った。英語の「cherub（可愛い子・天使）」と同語源で、複数形「cherubim」はヘブライ語の原形をほぼそのまま保っている。' },
  'querencia': { es: 'Después de tantos años en el extranjero, sentía una profunda querencia hacia su pueblo natal.', ja: '何年もの海外生活の後、彼は故郷の村に対して深い郷愁を感じていた。', trivia: '動詞「querer（愛する・求める）」から派生し、ラテン語「quaerere（求める）」が語根。英語に直訳できる単語はなく、「a sense of home」や「longing for one\'s birthplace」と説明されることが多い。闘牛用語としての意味が英語圏でも注目され、そのままスペイン語のまま借用されることがある。' },
  'queresa': { es: 'El carnicero desechó la carne porque había encontrado queresa en ella.', ja: '肉屋はその肉にウジが湧いていたため廃棄した。', trivia: '語源は諸説あり、ラテン語の「caries（腐敗）」との関連を指摘する説があるが確定していない。英語では「maggot（ウジ）」や「blowfly egg（ハエの卵）」に相当し、英語の「maggot」自体は古ウェールズ語由来でスペイン語とは系統が異なる。' },
  'quermes': { es: 'El rojo intenso de aquellas telas medievales se obtenía a partir del quermes.', ja: '中世のあの布地の鮮やかな赤色はタマカイガラムシから得られていた。', trivia: 'アラビア語「qirmiz（赤）」に由来し、同じ語がペルシャ語・サンスクリット語を経て英語の「crimson（深紅色）」や「carmine（カーマイン）」の語源にもなっている。この虫から取れる染料はヨーロッパ中世で非常に高価だった。' },
  'queroseno': { es: 'El mechero de queroseno iluminaba la cabaña durante los apagones.', ja: '停電の間、灯油ランプが山小屋を照らしていた。', trivia: 'ギリシャ語「κηρός（kēros、蜜蝋）」に由来し、19世紀に英語で「kerosene」として造語された後、スペイン語に借用された。英語では「kerosene」（北米）または「paraffin」（英国）と呼ぶが、どちらも石油蒸留の産物を指す。' },
  'quersoneso': { es: 'El quersoneso de Crimea ha sido motivo de disputas geopolíticas a lo largo de la historia.', ja: 'クリミア半島は歴史を通じて地政学的な争いの種であり続けてきた。', trivia: '古代ギリシャ語「χερσόνησος（kersónisos）」に由来し、「χέρσος（陸地）＋νῆσος（島）」の合成語で「陸続きの島」を意味する。英語でも「Chersonese」という学術的・歴史的な語が存在し、通常の「peninsula（半島）」よりも古風・格式的なニュアンスを持つ。' },
  'quesadilla': { es: 'Preparamos quesadillas de pollo con guacamole para la cena del viernes.', ja: '金曜日の夕食にグアカモーレ添えのチキンケサディーヤを作った。', trivia: 'スペイン語「queso（チーズ）」に指小辞「-adilla」が付いた語で、「小さなチーズ料理」が原義。英語にはそのまま「quesadilla」として借用されており、メキシコ料理ブームとともに定着した。「queso」自体はラテン語「caseus」由来で、英語の「cheese」とも同語根である。' },
  'quesear': { es: 'En esa región andina, las familias han quesado la leche de llama durante siglos.', ja: 'そのアンデスの地域では、家族たちが何世紀にもわたってリャマの乳でチーズを作ってきた。', trivia: '「queso（チーズ）」を動詞化した語で、ラテン語「caseus」が語根。英語には「to cheese」という動詞も存在するが（主に口語で「やめろ」などの意）、チーズを作るという意味では使われず、対応する英語は「to make cheese」となる。' },
  'quesera': { es: 'La quesera del mercado nos recomendó un manchego curado de doce meses.', ja: '市場のチーズ専門店の女性が12か月熟成のマンチェゴを勧めてくれた。', trivia: '「queso（チーズ）」の派生語で、ラテン語「caseus」に遡る。英語では「cheesemonger（チーズ商人）」や「cheese dish（チーズ皿）」にあたるが、1語で複数の意味（人・容器・形容詞）をこなす点がスペイン語の接尾辞「-era/-ero」の豊かさを示している。' },
  'quesería': { es: 'Visitamos una quesería artesanal donde elaboran quesos de oveja a la manera tradicional.', ja: '伝統的な手法で羊のチーズを作っている手工業のチーズ工房を訪れた。', trivia: '「queso」＋接尾辞「-ería（場所・業種）」の構造で、ラテン語「caseus」が語根。英語では「creamery」や「cheesery」が近いが、「creamery」はバター・クリームも含む広い意味を持ち、スペイン語の「quesería」のようにチーズに特化した語は英語では一般的でない。' },
  'quesero': { es: 'El quesero artesanal lleva más de treinta años elaborando quesos en la misma granja.', ja: 'その職人チーズ職人は30年以上同じ農場でチーズを作り続けている。', trivia: '「queso（チーズ）」＋形容詞・職業を示す接尾辞「-ero」の構造で、ラテン語「caseus」が語根。英語の「cheesemonger」や「cheesemaker」に相当し、「-monger（商人）」というゲルマン語由来の接尾辞を使う英語とは、語形成の戦略が対照的である。' },
  'quetzal': { es: 'El quetzal macho tiene una cola de plumas verdes que puede medir casi un metro.', ja: '雄のケツァールは長さ1メートル近い緑色の尾羽を持っている。', trivia: 'ナワトル語（アステカ語）「quetzalli（美しい羽・尾羽）」に由来し、スペインによる征服後にスペイン語に入った。英語でも「quetzal」とそのまま使われており、グアテマラの通貨単位としても知られる。ケツァールは古代マヤ・アステカで神聖な鳥とされ、捕らえることは死刑に値したという。' },
  'quía': { es: '—¿Crees que va a llover mañana? —¡Quía, con este sol que hace!', ja: '「明日は雨が降ると思う？」「まさか、こんなに晴れているのに！」', trivia: '口語的な間投詞で、語源は諸説あり、「¡qué va!」の変形または独立した感嘆詞とも言われる。英語の「No way!」や「Nonsense!」に近い。「¡qué va!」というフレーズとほぼ同義で用いられ、ラテンアメリカよりもスペイン本土で多く聞かれる表現である。' },
  'quiche': { es: 'De postre no, pero de primer plato sí me apetece una quiche de espinacas y queso de cabra.', ja: 'デザートではなく前菜として、ほうれん草とヤギのチーズのキッシュが食べたい気分だ。', trivia: 'フランス語「quiche」から借用され、フランス語自体はドイツのアルザス・ロレーヌ地方の方言「Küche（ケーキ・焼き菓子）」に由来する。英語にも「quiche」としてそのまま借用されており、スペイン語・英語ともにフランス語経由でゲルマン語の語根を持つ珍しい例といえる。' },
  'quichua': { es: 'Muchas palabras del quichua han pasado al español, como \'papa\', \'cóndor\' o \'llama\'.', ja: '「パパ（ジャガイモ）」「コンドル」「リャマ」など、ケチュア語由来の多くの言葉がスペイン語に取り込まれた。', trivia: 'スペイン語の綴りは「quechua」または「quichua」と表記が揺れ、ケチュア語自身では「Runa Simi（人の言葉）」と呼ばれる。英語でも「Quechua」として知られ、potato（ジャガイモ）、condor（コンドル）、guano（グアノ）など英語に定着した単語もケチュア語由来のものが多い。' },
  'quiebra': { es: 'La empresa no pudo hacer frente a sus deudas y tuvo que declararse en quiebra.', ja: 'その企業は債務を履行できず、倒産を宣言せざるを得なかった。', trivia: '動詞「quebrar（壊れる・折れる）」の名詞形で、ラテン語「crepare（割れる・ひびが入る）」に由来する。英語の「bankruptcy（破産）」はイタリア語「banca rotta（壊れた銀台）」が語源で、「破壊」を意味する点で概念は共通しているが語根は異なる。英語に「quiebra」は借用されていない。' },
  'quiebro': { es: 'El torero ejecutó un quiebro elegante y la multitud estalló en aplausos.', ja: '闘牛士が優雅な身のかわしを見せると、観客は拍手喝采した。', trivia: '動詞「quebrar（折れる・曲がる）」に由来し、ラテン語「crepare」が語根。英語にはこの語に直接対応する借用語はなく、フェイントの動作は「dodge」「sidestep」と言うが、闘牛の文脈では「quiebro」がそのまま使われることがある。音楽用語としての「トリル」の意味は英語の「trill」と概念が近い。' },
  'quien': { es: 'La persona quien me ayudó aquella tarde resultó ser mi futura jefa.', ja: 'あの午後助けてくれた人が、後に私の上司になるとは思ってもみなかった。', trivia: 'ラテン語の関係代名詞「quem（誰を）」に由来し、英語の「who / whom」とは同じラテン語・インド＝ヨーロッパ語族の「kw-」疑問詞語根を共有する遠い親戚関係にある。英語の「who」は古英語「hwā」を経由しており、形は大きく変わっているが語根の「qu-/wh-」の対応は規則的な音変化の結果である。' },
  'quién': { es: '¿Quién te ha dicho que la reunión era a las tres?', ja: '会議が3時だと誰が教えたの？', trivia: 'アクセント記号なしの「quien（関係代名詞）」と同語根だが、アクセント符号（tilde）が付くことで疑問詞・感嘆詞としての用法を区別する。英語では「who」1語が関係代名詞・疑問詞を兼ねるが、スペイン語は文字上の区別を設けた点が特徴的である。語根はインド＝ヨーロッパ祖語の「*kʷo-（疑問詞語根）」に遡る。' },
  'quienquiera': { es: 'Quienquiera que haya dejado las llaves en la puerta, que pase a recogerlas.', ja: '鍵をドアに置いていった方は、取りに来てください。', trivia: '「quien（誰）＋quiera（〜であれ）」の合成語で、英語の「whoever」に完全に対応する構造を持つ。英語の「whoever」も「who＋ever」の合成で、スペイン語と英語が同じ発想で不定関係代名詞を作っている好例である。複数形は「quienesquiera」となり、英語「whoever」には複数形がない点が異なる。' },
  'quietud': { es: 'Después del bullicio de la ciudad, la quietud del campo me resultó absolutamente reconfortante.', ja: '都会の喧騒の後、田舎の静けさが本当に心地よく感じられた。', trivia: 'ラテン語「quies（休息・静けさ）」に由来し、英語の「quiet」「quietude」「requiem（安息の祈り）」と同語根。英語に「quietude」という語も存在するが、やや文語的・詩的で日常では「stillness」や「tranquility」が好まれる。ラテン語「quies」はインド＝ヨーロッパ祖語「*kʷyeh₁-（静まる）」に遡る。' },
  'quijada': { es: 'El dentista le examinó la quijada y determinó que necesitaba un tratamiento de ortodoncia.', ja: '歯科医が顎を診察し、矯正治療が必要だと判断した。', trivia: '語源は諸説あり、ラテン語「capsa（箱）」の変形とする説や、ゴート語（ゲルマン語派）の語根を持つという説がある。英語の「jaw（顎）」は古フランス語「joue（頬）」由来で、スペイン語「quijada」とは系統が異なる。「ドン・キホーテ」の主人公の名「Quijote」はこの語と無関係だが、スペルが似ているため混同されることがある。' },
  'quijote': { es: 'No seas quijote y acepta que no puedes solo con todos los problemas del mundo.', ja: 'ドン・キホーテのように無謀になるのはやめて、世界中の問題を一人で抱えられないことを認めなさい。', trivia: 'セルバンテスの小説『ドン・キホーテ』（1605年）の主人公名から派生した普通名詞で、英語では形容詞「quixotic（非現実的な理想主義の）」が定着している。「Quixote」のXはスペイン語の古い綴りで現在の「j」音に相当し、英語での発音「kwɪˈzɒtɪk」はそのままアルファベット読みしたものである。' },
  'quijotesca': { es: 'Su quijotesca cruzada contra la corrupción le costó el cargo, pero le ganó la admiración del pueblo.', ja: '腐敗に対する彼の無謀な理想主義的な戦いは職を失わせたが、民衆の尊敬を勝ち取った。', trivia: '「quijote（ドン・キホーテ的人物）」の形容詞形で、英語の「quixotic（キホーテ的な・非現実的な）」と完全に対応する。英語の「quixotic」は17世紀末から使われ始めた文学由来の借用語で、スペイン語「quijotesco/quijotesca」と意味・語根・由来がすべて一致する数少ない例の一つである。' },
  'quijotesco': { es: 'Sus ideales quijotescos lo llevaron a luchar contra injusticias que nadie más se atrevía a enfrentar.', ja: '彼のドン・キホーテ的な理想主義が、他の誰も立ち向かおうとしなかった不正義と戦わせた。', trivia: 'スペインの文豪セルバンテスの主人公ドン・キホーテ（Don Quijote）の名から派生した形容詞で、英語でも「quixotic（無謀な理想主義の）」として定着している。スペイン語の「j」が英語で「x」に変わった稀なケース。' },
  'quila': { es: 'En el sur de Chile, los bosques de quila son refugio natural de muchas especies animales.', ja: 'チリ南部では、キラの林が多くの動物種の自然な避難場所となっている。', trivia: 'マプチェ語（南米先住民語）の「kila」に由来するとされ、スペイン語・英語いずれにも対応する語根は存在しない。英語では特定の名称がなく「quila bamboo」や学名 Chusquea quila で呼ばれる。' },
  'quilate': { es: 'Este anillo está hecho con oro de dieciocho quilates, por eso tiene ese brillo tan característico.', ja: 'この指輪は18カラットの金で作られているから、あの独特の輝きがあるのだ。', trivia: 'アラビア語「qīrāṭ（いなご豆の種）」に由来し、その種が重りの基準として使われたことによる。英語の carat（宝石）・karat（金純度）も同語源で、フランス語 carat を経由して伝わった。' },
  'quilombo': { es: 'Cuando llegué a la oficina, había un quilombo total: todos gritaban y nadie sabía qué hacer.', ja: 'オフィスに着いたら大混乱で、みんな叫び合っていて誰も何をすべきかわからない状態だった。', trivia: 'アフリカのキンブンドゥ語（アンゴラ周辺）の「kilombo（野営地）」に由来し、ブラジル・ポルトガル語を経由してリオ・デ・ラ・プラタ地域のスペイン語に入った。英語には直接対応する語がなく、歴史的文脈では「maroon community」と訳される。' },
  'quimera': { es: 'Creer que resolveremos todos nuestros problemas de un día para otro es pura quimera.', ja: '一晩で全問題が解決できると信じるのは、全くの幻想だ。', trivia: 'ギリシャ語「Khímaira（ライオンの頭・ヤギの胴・蛇の尾を持つ怪物）」に由来し、英語の chimera も同語源。生物学では「キメラ（遺伝的に異なる細胞が混在する生物）」を指す用語としても英語・スペイン語共通で使われる。' },
  'quimérica': { es: 'La idea de vivir sin trabajar y viajar por el mundo es quimérica para la mayoría de la gente.', ja: '働かずに世界を旅して暮らすという考えは、ほとんどの人にとって非現実的な夢だ。', trivia: 'quimera（幻想）の形容詞形で、英語の chimerical（非現実的な）と同語源。どちらもギリシャ神話の怪物キマイラから転じており、「実現不可能な空想」を意味する点で英語・スペイン語で用法が一致する。' },
  'quimérico': { es: 'El proyecto de construir una ciudad flotante parece quimérico, pero algunos ingenieros lo estudian en serio.', ja: '浮遊都市を建設するプロジェクトは非現実的に見えるが、一部の技術者は真剣に研究している。', trivia: 'quimérica の男性形で、英語 chimerical と完全に同語源・同意義。ただし英語では chimerical はやや文語的で、日常語では「unrealistic」や「far-fetched」が多用される。' },
  'química': { es: 'Entre ellos hay una química especial que hace que todo el equipo trabaje mejor.', ja: '彼らの間には特別なケミストリーがあって、チーム全体がより良く機能している。', trivia: 'アラビア語「al-kīmiyāʾ（錬金術）」に由来し、さらに古代ギリシャ語またはエジプト語に遡るとされる。英語の chemistry も同語源で、日本語「化学」はこれらの翻訳語。「相性・フィーリング」の比喩的用法は英語・スペイン語共通。' },
  'químicamente': { es: 'Estos dos compuestos son químicamente incompatibles y no deben mezclarse nunca.', ja: 'この2つの化合物は化学的に相容れず、絶対に混ぜてはいけない。', trivia: 'química + -mente（副詞語尾）から成る。英語の chemically と完全に対応し、共にアラビア語由来の錬金術語「al-kīmiyāʾ」を語根に持つ。スペイン語副詞の -mente はラテン語の「mens（心）」に由来する。' },
  'químico': { es: 'El químico pasó años investigando un nuevo tratamiento para la enfermedad antes de publicar sus resultados.', ja: 'その化学者は研究結果を発表する前に、新しい治療法の研究に何年もかけた。', trivia: '英語の chemist（化学者）・chemical（化学的な）と同語源。ただし英語の chemist は英国では「薬剤師」の意味も持つが、スペイン語の químico にはその意味はなく（薬剤師は farmacéutico）、一語で意味が分岐している点が興味深い。' },
  'quimioterapia': { es: 'La quimioterapia es uno de los tratamientos más comunes contra el cáncer, aunque tiene efectos secundarios difíciles.', ja: '化学療法はがんに対する最も一般的な治療法の一つだが、つらい副作用を伴う。', trivia: 'ギリシャ語「khumós（液体・体液）」と「therapeia（治療）」の合成語で、英語の chemotherapy と完全に同語源・同構造。20世紀初頭に医学用語として体系化された比較的新しい語。' },
  'quimo': { es: 'El quimo pasa del estómago al intestino delgado, donde continúa el proceso de digestión.', ja: '食塊は胃から小腸へ移動し、そこで消化プロセスが続く。', trivia: 'ギリシャ語「khumós（液体・ジュース・体液）」に由来し、英語の chyme も同語源。同じく「khumós」から派生した英語 humor（体液）とは姉妹語の関係にあり、中世医学の「四体液説」にも関連する。' },
  'quimono': { es: 'Para la ceremonia del té, ella eligió llevar un quimono de seda con un diseño floral muy delicado.', ja: '茶道の儀式のために、彼女はとても繊細な花柄の絹の着物を着ることにした。', trivia: '日本語「着物（きもの）」の音写で、英語の kimono も同じ日本語起源。スペイン語では「qu-」で始まる綴りになるのは、「ki」の音をスペイン語の正書法規則（keはque、kiはqui）に合わせたため。' },
  'quina': { es: 'La quina fue fundamental en la historia de la medicina porque permitió tratar el paludismo con quinina.', ja: 'キナノキは医学史において重要な役割を果たした。それによってマラリアをキニーネで治療することが可能になったからだ。', trivia: 'ケチュア語（インカ帝国の言語）の「kina（木の皮）」に由来し、17世紀にスペイン語に入った。英語では quinine（キニーネ）として知られ、「キナ」自体は英語で cinchona bark と呼ばれる。トニックウォーターの苦みもキニーネに由来する。' },
  'quince': { es: 'El examen final es el quince de julio, así que hay que prepararse bien desde ahora.', ja: '期末試験は7月15日なので、今から十分に準備しなければならない。', trivia: 'ラテン語「quindecim（quinque＝5 ＋ decem＝10）」に由来し、英語の fifteen も同じ構造（five＋ten）。ただし英語は「五と十」の語順だが、ラテン語系のスペイン語は短縮された合成形を維持している。' },
  'quinceañera': { es: 'La quinceañera de mi prima fue una fiesta enorme con más de doscientos invitados y una orquesta en vivo.', ja: 'いとこのキンセアニェーラは200人以上のゲストと生オーケストラを迎えた大きなパーティーだった。', trivia: 'quince（15）＋ años（歳）＋ -era（名詞・形容詞語尾）から成る。英語に対応する単語はなく、ラテン系文化圏の通過儀礼を指す言葉として英語圏でも「quinceañera」のまま借用されている。' },
  'quinceañero': { es: 'Como quinceañero, todavía tiene mucho por aprender, pero ya muestra una madurez sorprendente.', ja: '15歳の少年として、まだ学ぶべきことがたくさんあるが、すでに驚くほどの成熟さを見せている。', trivia: 'quinceañera の男性形で、英語には直接対応する語がない。英語では「fifteen-year-old（boy）」と表現するしかなく、スペイン語がこの年齢に固有の名詞を持つことは、文化的にその節目を重視していることを示す。' },
  'quincena': { es: 'Me pagan por quincena, así que recibo mi sueldo dos veces al mes.', ja: '給料は半月払いなので、月に2回受け取る。', trivia: 'quince（15）＋ -ena（集合名詞語尾）から成り、15日間の期間を指す。英語の fortnight（14日間）はゲルマン語系で「14夜」の意味だが、スペイン語の quincena はラテン語系で「15日」を基準にしており、わずかに意味がずれる。' },
  'quincenal': { es: 'Tenemos una reunión quincenal de equipo para revisar el avance de los proyectos.', ja: 'プロジェクトの進捗を確認するため、チームの隔週会議がある。', trivia: 'quincena（15日間）＋ -al（形容詞語尾）から成る。英語の biweekly・semimonthly に相当するが、英語の biweekly は「2週ごと」と「週2回」の両義があり曖昧なのに対し、quincenal は「15日ごと」と明確な点で優れている。' },
  'quincenalmente': { es: 'El boletín informativo se publica quincenalmente, el primero y el quince de cada mes.', ja: 'ニュースレターは毎月1日と15日に、半月に一度発行される。', trivia: 'quincenal（15日ごとの）＋ -mente（副詞語尾）から成る。英語では semimonthly や twice a month などで表現するが、単語一語で言い表せるスペイン語の -mente 副詞の造語力の高さが際立つ例。' },
  'quincalla': { es: 'El mercado estaba lleno de puestos que vendían quincalla importada a precios muy bajos.', ja: '市場は安値で輸入雑貨を売る露店でいっぱいだった。', trivia: '語源は諸説あり、フランス語「quincaillerie（金物類）」またはオランダ語「klinken（鳴る）」に由来するとも言われる。英語の knick-knack（小間物）と意味が重なるが直接の語源関係はなく、英語では hardware store（金物屋）や trinkets（安物装飾品）で補って表現する。' },
  'quitamanchas': { es: 'Aplica el quitamanchas directamente sobre la mancha de vino antes de lavar la ropa.', ja: '洋服を洗う前に、ワインのシミに直接シミ抜き剤を塗布してください。', trivia: 'quitar（取り除く）＋ manchas（シミの複数形）から成る複合名詞で、英語の stain remover と構造的に対応する（remove＋stain）。スペイン語では動詞＋名詞の語順が多いが、英語では名詞＋動詞系名詞の語順になる点が興味深い。' },
  'quitanieves': { es: 'El quitanieves trabajó toda la noche para despejar las carreteras antes del amanecer.', ja: '除雪車は夜明け前に道路を開通させるために一晩中働いた。', trivia: 'quitar（取り除く）＋ nieves（雪の複数形）から成る複合名詞で、英語の snowplow（snow＋plow）と意味は同じ。英語が「雪をすき込む」イメージなのに対し、スペイン語は「雪を取り除く」という動詞的な発想で合成されており、両言語の語形成の違いが見える。' },
  'quitaipón': { es: 'Este collar tiene un colgante de quitaipón, así que puedes cambiarlo según tu outfit del día.', ja: 'このネックレスは着脱自在のペンダントトップがついているので、その日のコーデに合わせて取り替えられる。', trivia: '「quita y pon（取って・付けて）」という句が名詞化・一語化したもので、英語では detachable や removable で表現する。このような命令形動詞の反復による合成語はスペイン語に特有の造語パターンで、英語には同構造の対応語がない。' },
  'quitar': { es: '¿Puedes quitarme este clavo de la pared? No tengo las herramientas necesarias.', ja: '壁からこの釘を抜いてもらえる？必要な道具を持っていないんだ。', trivia: 'ラテン語「quietare（静める・解放する）」に由来し、英語の quit（やめる）・quiet（静かな）と同語根。ただし英語の quit は「やめる」、スペイン語の quitar は「取り除く・外す」と意味がずれており、典型的なコグネートの罠（false friends）の例。' },
  'quitasol': { es: 'Mi abuela nunca sale al jardín en verano sin su quitasol de encaje blanco.', ja: '私の祖母は夏に白いレースの日傘なしで庭に出ることは決してない。', trivia: '「quitar（取り除く）」＋「sol（太陽）」の合成語で、英語の「parasol（パラソル）」はフランス語経由のイタリア語 parasole（para=防ぐ + sole=太陽）と構造が同じ。英語では sunshade や parasol に相当する。' },
  'quite': { es: 'El torero ejecutó un quite perfecto para alejar al toro del picador caído.', ja: '闘牛士は倒れたピカドールから牛を遠ざけるため、完璧なキテを繰り出した。', trivia: '動詞 quitar（取り除く）の名詞形で、ラテン語 *quitare（解放する）に由来するとされる。英語 quit（やめる）とは同語根で、もともと「負債・義務から解放する」という意味を共有していた。' },
  'quito': { es: 'Cuando me quito los zapatos en casa, me siento completamente relajado.', ja: '家で靴を脱ぐと、完全にリラックスした気分になる。', trivia: '動詞 quitar の直説法現在1人称単数形。地名の「キト（Quito）」はエクアドルの首都で、ケチュア語で「世界の中心」を意味するとも言われ、動詞 quitar とは語源が異なる。英語 quit と同語根の部分については quite の項目と同様。' },
  'quitrina': { es: 'En el museo de La Habana se exhibe una quitrina del siglo XIX con su toldo de seda original.', ja: 'ハバナの博物館には、19世紀の絹製の幌をそのまま残したキトリーナが展示されている。', trivia: 'キューバなどカリブ地域で18〜19世紀に使われた2輪馬車で、語源は地名「キト（Quito）」に由来するとも言われるが確証はない。英語には直接対応する語はなく、chaise または volante と説明されることが多い。' },
  'quivi': { es: 'Me como un quivi cada mañana porque dicen que tiene mucha vitamina C.', ja: 'ビタミンCが豊富だと言われているので、毎朝キウイを1個食べる。', trivia: '英語の kiwi はマオリ語に由来し、ニュージーランドの飛べない鳥の鳴き声を模した言葉。スペイン語では kiwi と綴ることが多く、quivi は表記揺れ。英語と完全に同語源の借用語である。' },
  'quizá': { es: 'Quizá llegue tarde hoy, así que no me esperes para cenar.', ja: '今日は遅くなるかもしれないから、夕食は待たないでいいよ。', trivia: '中世スペイン語の「qui sabe（誰が知ろうか）」が縮約・融合したものとされ、英語の perhaps（per + haps「運・機会」）や maybe（may + be）とは語源が全く異なる。quizás と末尾に s を付けた形も同義で使われる。' },
  'quórum': { es: 'La reunión no pudo celebrarse porque no se alcanzó el quórum necesario.', ja: '必要な定足数に達しなかったため、会議を開くことができなかった。', trivia: 'ラテン語の関係代名詞 qui の属格複数形 quorum（「彼らのうちの」の意）に由来し、英語の quorum もスペイン語も同一のラテン語から直接借用した完全なコグネート（同源語）である。' },
  'quota': { es: 'El gobierno impuso una quota de importación para proteger a los productores nacionales.', ja: '政府は国内生産者を保護するために輸入割り当てを課した。', trivia: 'ラテン語 quota（pars）「何番目の（部分）」に由来し、英語の quota とスペイン語の cuota（より一般的な綴り）は同語根の双子語。quota は主に書き言葉や外来語的ニュアンスで使われ、cuota が日常的な正書法とされる。' },
  'R': { es: 'La letra R tiene dos sonidos en español: la erre suave y la erre fuerte.', ja: 'スペイン語のR（エレ）には、弱いR音と強いR音の2種類がある。', trivia: 'フェニキア文字の「レシュ（頭）」に由来し、ギリシャ語のロー（Ρ）、ラテン語のRへと受け継がれた。英語でも同じ系統の文字で、スペイン語の巻き舌R（erre）は英語のRとは発音が大きく異なる点が学習者の難所となる。' },
  'rabadilla': { es: 'El médico me explicó que el dolor que sentía era en la rabadilla y no en la espalda.', ja: '医師は私が感じていた痛みは背中ではなく尾骨部分だと説明した。', trivia: '語源は不明確だが、アラビア語起源という説もある。英語では coccyx（ギリシャ語でカッコウの嘴に由来）または rump（臀部）と表現され、スペイン語の rabadilla は特に鳥の腰・上尾筒を指す際にも使われる専門的な語である。' },
  'rabanillo': { es: 'En el huerto, los rabanillos crecen tan rápido que en dos semanas ya están listos para comer.', ja: '家庭菜園では、ハツカダイコンが2週間ほどであっという間に食べ頃になる。', trivia: 'rábano（大根・ラディッシュ）の縮小辞形。rábano はラテン語 raphanus、さらにギリシャ語 raphanos（白いもの）に由来し、英語の radish も同じ語根を持つ。小さいラディッシュを意味する点で英語の radish と意味的に重なる。' },
  'rábano': { es: 'Le importa un rábano lo que piensen los demás; siempre hace lo que le da la gana.', ja: '彼は他人の目なんてどうでもいい。いつも自分の好きなようにする。', trivia: 'ラテン語 raphanus、ギリシャ語 raphanos に由来し、英語の radish と同語根のコグネート。慣用句「importar un rábano（大根一本分しか気にしない＝まったく気にしない）」は英語の「not give a damn」に相当する。' },
  'rabia': { es: 'Me da rabia que siempre llegues tarde sin avisar.', ja: '連絡もなしにいつも遅刻するのは本当に腹が立つ。', trivia: 'ラテン語 rabies（狂気、激怒）に由来し、英語の rabies（狂犬病）と同語源の完全なコグネート。英語では「怒り」の意味は rage や anger が担い、rabies は医学用語として残った。スペイン語 rabia は「怒り」と「狂犬病」の両方を1語で表す点が興味深い。' },
  'rabiar': { es: 'Estaba rabiando de impaciencia mientras esperaba los resultados del examen.', ja: '試験の結果を待ちながら、じっとしていられないほど焦っていた。', trivia: 'rabia（怒り・狂犬病）の動詞形で、ラテン語 rabere（激怒する、狂う）に由来する。英語に直接対応する動詞はないが、rage（動詞）が最も近く、「～したくてたまらない」の意味は英語の long for や be dying to に相当する。' },
  'rabieta': { es: 'El niño tuvo una rabieta en el supermercado porque no le compraron el juguete que quería.', ja: '子どもは欲しかったおもちゃを買ってもらえなくてスーパーでかんしゃくを起こした。', trivia: 'rabia（怒り）の縮小辞・感情的含意形で、英語の tantrum（かんしゃく）に相当する。tantrum の語源は不明確だが、スペイン語 rabieta はラテン語 rabies から連綿と続く語族の一員であり、子ども特有の短い怒りの爆発を指す点が英語と共通する。' },
  'rabina': { es: 'La comunidad eligió a una rabina joven y carismática para dirigir la sinagoga.', ja: 'コミュニティは若くカリスマ性のある女性ラビをシナゴーグの指導者として選んだ。', trivia: 'ヘブライ語 rabbi（私の師・先生、רַבִּי）に由来し、英語の rabbi と同語源。スペイン語では rabino（男性形）と rabina（女性形）で性別を区別するが、英語の rabbi は性別中立で使われるため、female rabbi と説明する必要がある。' },
  'rabínica': { es: 'La literatura rabínica contiene siglos de interpretaciones y debates sobre la ley judía.', ja: 'ラビ文学には、ユダヤ法についての何世紀にもわたる解釈と議論が収められている。', trivia: 'ヘブライ語 rabbi に由来し、英語の rabbinic または rabbinical と同語源のコグネート。形容詞形で「ラビに関する」を意味し、英語では rabbinic literature と言えばタルムードやミドラシュなどを指す。スペイン語でも同様の学術的文脈で使われる。' },
  'rabínico': { es: 'El pensamiento rabínico ha influido profundamente en la filosofía occidental a través de siglos de diálogo.', ja: 'ラビ的思考は数世紀にわたる対話を通じて西洋哲学に深く影響を与えてきた。', trivia: 'rabínica の男性形で、ヘブライ語 rabbi に由来する点は同様。英語の rabbinic と完全なコグネートであり、スペイン語では形容詞が修飾する名詞の性に合わせて -o/-a を使い分ける点が英語との大きな違いである。' },
  'rabino': { es: 'El rabino explicó el significado de la festividad a toda la congregación con gran claridad.', ja: 'ラビは会衆全員にその祭日の意味をとても分かりやすく説明した。', trivia: 'ヘブライ語 rabbi（רַבִּי、「私の師」の意）に由来し、英語の rabbi と同語源の借用語。英語では rabbi がそのまま使われるが、スペイン語では性別形（rabino/rabina）が分化している点が特徴的である。' },
  'rabiosa': { es: 'Salió rabiosa de la reunión porque nadie la escuchó durante toda la discusión.', ja: '議論中ずっと誰にも話を聞いてもらえず、彼女は怒り心頭で会議を後にした。', trivia: 'ラテン語 rabiosus（狂気の、激怒した）の女性形で、英語の rabies と同語根。英語の furious、raging に相当するが、スペイン語では「de moda rabiosa（最先端の流行）」のように「猛烈な、最新の」意味でも使われ、意味の幅が広い。' },
  'rabioso': { es: 'El aficionado rabioso protestó con fuerza contra la decisión del árbitro.', ja: '怒り狂ったファンは審判の判定に激しく抗議した。', trivia: 'ラテン語 rabiosus に由来し、英語の furious、raging と意味が重なるが同語根ではない。英語 rabies と同語源でありながら、英語では「狂犬病」の医学専門語として意味が固定化し、「激怒した」という日常的意味はスペイン語の方が保持している。' },
  'rabo': { es: 'El perro movía el rabo sin parar cada vez que veía a su dueño llegar a casa.', ja: '犬は飼い主が家に帰ってくるたびに尻尾を止めどなく振った。', trivia: '語源は諸説あり、ラテン語 rapum（蕪、根野菜）から派生した可能性や、rapa（茎・根部）との関連が指摘されるが確証はない。英語の tail に相当するが、tail はゲルマン語系（古英語 tægl）でまったく語源が異なる。慣用句「con el rabo entre las piernas（尻尾を股に挟んで）」は英語の「with one\'s tail between one\'s legs」と完全対応する。' },
  'rabón': { es: 'El caballo rabón del rancho parecía menos elegante que los demás, pero corría más rápido.', ja: '牧場の尻尾の短い馬は他の馬より見栄えは劣るが、走りは一番速かった。', trivia: 'rabo（尻尾）＋増大辞・特徴付け接尾辞 -ón の組み合わせだが、意味は逆説的に「尻尾が短い・ない」を表す。英語に対応する1語はなく、bobtailed や dock-tailed と説明される。中南米の口語では「ショートパンツ」の意味でも使われ、rabo（端・裾）の意味の転用による。' },
  'rabona': { es: 'El delantero sorprendió a todos marcando un gol de rabona que nadie esperaba.', ja: 'そのフォワードは誰も予想していなかったラボーナで得点し、全員を驚かせた。', trivia: 'サッカー用語としてのラボーナはアルゼンチン発祥で、1948年に Ricardo Infante 選手がこのトリックキックで有名になったことから広まったとされる。英語でも rabona としてそのまま使われる借用語。中南米の「無断欠勤」の意味は hacer la rabona（無断で逃げる）という慣用表現から来ており、英語の playing hooky に相当する。' },
  'racha': { es: 'Llevamos una buena racha este mes: hemos ganado los últimos cinco partidos seguidos.', ja: '今月は好調が続いている。直近5試合連続で勝っている。', trivia: '語源は諸説あるが、アラビア語またはバスク語に由来するという説がある（確証はない）。英語の streak（連続、勢い）や spell（一時的な期間）に相当し、「una mala racha（ついてない時期）」は英語の「a rough patch」や「a losing streak」にほぼ対応する。' },
  'racimo': { es: 'El viticultor cortó un racimo de uvas maduras y lo colocó cuidadosamente en la cesta.', ja: 'ぶどう農家は熟したブドウの房を切り取り、丁寧にかごに置いた。', trivia: 'ラテン語 racemus（ブドウの房）に由来し、英語の raisin（干しぶどう）も同根。英語で「房」は bunch または cluster と言うが、raisin が「干しぶどう」になった一方、スペイン語では房そのものを指す racimo として残った。' },
  'racionamiento': { es: 'Durante la guerra, el gobierno impuso el racionamiento del pan y del aceite para toda la población.', ja: '戦時中、政府は全国民にパンと油の配給制を課した。', trivia: 'ラテン語 ratio（計算、割り当て）から派生した ración に接尾辞 -miento が付いた形。英語の rationing とまったく同根の借用語であり、第二次世界大戦中に英・西両国で実際に同義で使われた。' },
  'racionar': { es: 'El gobierno tuvo que racionar el agua potable debido a la prolongada sequía.', ja: '政府は長引く干ばつのため、飲料水を配給制にせざるを得なかった。', trivia: 'ラテン語 ratio に由来する動詞形で、英語の to ration と直接の同語根。英語の ration は名詞・動詞両用だが、スペイン語では名詞 ración と動詞 racionar が明確に分化している点が興味深い。' },
  'ración': { es: 'En el bar pidieron dos raciones de calamares para compartir entre los amigos.', ja: 'バルで友人たちとシェアするためにイカのフライを2皿注文した。', trivia: 'ラテン語 ratio（計算、割り当て）から中世ラテン語 ratio / rationem を経て成立。英語の ration と同源で、スペインのバルでは一品料理の一人前サイズを指す独特の食文化的意味も持つ。' },
  'racismo': { es: 'El racismo sigue siendo un problema estructural en muchas sociedades contemporáneas.', ja: '人種差別は今日でも多くの現代社会における構造的問題であり続けている。', trivia: 'フランス語 racisme を経由して広まった比較的新しい語で、19世紀後半に登場。英語の racism と同源・同義の国際的借用語で、語根の race / raza はゲルマン語系とラテン語系の諸説があり語源は未確定。' },
  'racista': { es: 'La organización denunció comentarios racistas en las redes sociales de varios políticos.', ja: 'その団体は複数の政治家のSNS上の人種差別的発言を告発した。', trivia: 'racismo に形容詞・名詞語尾 -ista を付けた形で、英語の racist と構造は異なるが（英語は -ist 語尾）意味は同一。スペイン語の -ista は職業や思想を示す万能語尾で、artista（芸術家）などと同じパターン。' },
  'raciocinio': { es: 'Un buen raciocinio es esencial para resolver problemas filosóficos complejos.', ja: '複雑な哲学的問題を解くには優れた推論能力が不可欠だ。', trivia: 'ラテン語 ratiocinatio（推論、論証）に由来し、英語では reasoning または ratiocination（やや古風・学術的）に相当する。ratiocination は英語でも哲学・論理学の文脈で使われる格調ある語だが、日常ではほぼ使われない点がスペイン語との差異。' },
  'racional': { es: 'Intentemos buscar una solución racional al conflicto sin dejarnos llevar por las emociones.', ja: '感情に流されることなく、合理的な解決策を探してみよう。', trivia: 'ラテン語 rationalis（理性に基づく）から直接派生し、英語の rational と完全に同語根の典型的なラテン語起源の同根語（true cognate）。数学では有理数を número racional と言い、英語の rational number とも対応する。' },
  'racionalidad': { es: 'La racionalidad humana nos permite tomar decisiones basadas en argumentos lógicos.', ja: '人間の合理性によって、論理的な論拠に基づいた意思決定が可能になる。', trivia: 'ラテン語 rationalitas に由来し、英語の rationality と完全な同語根。哲学用語として17世紀以降に体系化された語で、英語・スペイン語ともに啓蒙主義の影響で普及した学術概念語。' },
  'racionalización': { es: 'La racionalización de los procesos de producción permitió reducir costos en la fábrica.', ja: '生産プロセスの合理化により工場のコスト削減が実現した。', trivia: '英語の rationalization と同語根・同義で、産業革命期以降の経営・経済用語として広まった。心理学では「都合のよい言い訳」（防衛機制の一つ）を意味し、英語の rationalization（psychoanalytic defense mechanism）とも完全に対応する。' },
  'racionalizar': { es: 'La empresa decidió racionalizar sus gastos eliminando departamentos poco productivos.', ja: 'その企業は生産性の低い部署を廃止することで支出を合理化することを決めた。', trivia: 'フランス語 rationaliser を通じて広まったとされる動詞で、英語の to rationalize と同語根。英語の rationalize には「言い訳する」という心理的な含意が強いが、スペイン語の racionalizar は経営・業務の「効率化」という文脈でより広く使われる傾向がある。' },
  'racionalmente': { es: 'Para resolver este problema, hay que pensar racionalmente y no dejarse llevar por el miedo.', ja: 'この問題を解決するには、恐怖に流されずに理性的に考えることが必要だ。', trivia: '形容詞 racional に副詞語尾 -mente を付けた形で、英語の rationally に相当する。スペイン語の副詞語尾 -mente はラテン語の mens（心、精神）の奪格形から来ており、「理性的な心で」という原義が語源的に透けて見える。' },
  'racompas': { es: 'El navegante medieval consultaba el racompas para mantener el rumbo durante la travesía.', ja: '中世の航海士は航行中に針路を保つため羅針盤を参照した。', trivia: 'きわめて古風な海事用語で、現代語の brújula（羅針盤）にほぼ置き換えられた。語源は諸説あるが、re- + compás（コンパス）の変形とも考えられており、英語の compass と同根の可能性がある。日常語としてはほぼ死語に近い。' },
  'rada': { es: 'Los barcos pescadores buscaron refugio en la rada ante la llegada del temporal.', ja: '漁船は嵐の接近に備えて錨地に避難した。', trivia: '語源は諸説あり、アラビア語 marsa（港）説とゲルマン語系説が併存する。英語の roadstead（沖合の停泊地）に相当するが、road が「錨地」を意味する古英語用法（現在のロンドン・ロード沿いの地名にその名残がある）はほぼ忘れられており、語の変遷が対照的。' },
  'radar': { es: 'El radar del aeropuerto detectó un objeto no identificado acercándose a la zona de vuelo.', ja: '空港のレーダーが飛行エリアに接近する未確認の物体を探知した。', trivia: '英語の radar は Radio Detection And Ranging の頭字語（acronym）で、第二次世界大戦中（1940年代）にアメリカ海軍が命名した。スペイン語はその英語のまま借用しており、比喩的に「tener radar para algo（何かを察知する能力がある）」という慣用表現にも使われる。' },
  'radiodifusora': { es: 'La radiodifusora local transmitió en directo el discurso del presidente durante toda la tarde.', ja: '地元のラジオ放送局は大統領の演説を午後いっぱい生中継した。', trivia: 'radio（ラテン語 radius「光線・半径」由来）＋ difusor（拡散するもの、ラテン語 diffundere 由来）から成る合成語で、英語では radio station / broadcaster に相当。英語の diffuse とも同語根で、「広く拡散する」という原義が名称に込められている。' },
  'radiofónica': { es: 'La producción radiofónica de aquel drama fue premiada por su excelente calidad sonora.', ja: 'そのドラマのラジオ制作は優れた音質で賞を受けた。', trivia: 'radio＋ -fónico（音に関する、ギリシャ語 phone「声・音」由来）から成る形容詞の女性形。英語の telephonic（電話の）と phone 部分が同語根で、telephone のギリシャ語起源（tele- 遠い＋ phone 声）と同じ要素を共有している。' },
  'radiofónico': { es: 'El equipo técnico preparó el espacio radiofónico para la emisión del programa matutino.', ja: '技術スタッフは朝の番組の放送に向けてラジオ用スペースを準備した。', trivia: 'radiofónica の男性形で、ギリシャ語 phone（声・音）とラテン語 radius の合成語。英語では radio broadcast program や on-air などに相当するが、英語に radiophonic という語もあり（BBC Radiophonic Workshop で有名）、同語根。' },
  'radiografía': { es: 'El médico pidió una radiografía de tórax para descartar cualquier problema pulmonar.', ja: '医師は肺の問題を除外するために胸部X線撮影を依頼した。', trivia: 'radio（放射線）＋ -grafía（書き記すこと、ギリシャ語 graphein 由来）の合成語。英語の X-ray は発見者レントゲンが「未知の放射線」を意味する x を使って命名した一方、スペイン語 radiografía は「放射線で描いた像」という原理的命名であり、命名思想の違いが面白い。' },
  'radiografiar': { es: 'El dentista decidió radiografiar la muela para ver si había alguna caries oculta.', ja: '歯科医は隠れた虫歯がないか確認するために奥歯のX線撮影をすることにした。', trivia: 'radiografía を動詞化した語で、英語では to X-ray が対応する。英語は名詞 X-ray をそのまま動詞転用するが、スペイン語は -ar 動詞語尾を付けて明確に動詞形を作る。比喩的に「社会の実態を丸裸にする」という意味でも使われる点は両言語で共通。' },
  'radiograma': { es: 'El capitán del barco recibió un radiograma urgente desde el puerto antes de zarpar.', ja: '船長は出港前に港から緊急の無線電報を受け取った。', trivia: 'radio（無線）＋ -grama（書かれたもの、ギリシャ語 gramma 由来）の合成語で、英語の radiogram と同語根・同義。英国英語では radiogram がレコードプレーヤー内蔵ラジオを指す時代もあり、語義のずれが生じた。現代では電報・無線いずれの意味も時代遅れになりつつある。' },
  'radiolocalización': { es: 'La radiolocalización permitió a los rescatistas encontrar el barco naufragado en alta mar.', ja: '電波位置測定技術により救助隊は沖合で難破した船を発見することができた。', trivia: 'radio（電波）＋ localización（位置特定、ラテン語 locus「場所」由来）の合成語で、英語の radiolocation に対応する。レーダー（radar）の前身として第二次世界大戦以前に使われた術語で、英語でも radiolocation が RADAR の普及前の公式呼称だった歴史がある。' },
  'radiomedicina': { es: 'Los avances en radiomedicina han permitido detectar tumores en estadios muy tempranos.', ja: '放射線医学の進歩により、非常に早期の段階で腫瘍を発見できるようになった。', trivia: 'radio（放射線）＋ medicina（医学、ラテン語 medicus「医師」由来）の合成語で、英語の nuclear medicine / radiology に相当する分野を包括的に指す。英語の medicine とまったく同語根で、ラテン語 mederi（癒す）に遡る点は両言語で共通している。' },
  'radionavegación': { es: 'Los pilotos de la Segunda Guerra Mundial dependían de la radionavegación para orientarse sobre el océano Atlántico.', ja: '第二次世界大戦のパイロットたちは、大西洋上で方向を確認するために電波航法に頼っていた。', trivia: '「radio-」はラテン語 radius（光線・半径）に由来し、「navegación」はラテン語 navigatio（航行）から来る。英語の radio navigation と完全に対応する複合語で、GPS が普及する以前の航空・海事技術の根幹を成していた。' },
  'radioperiódico': { es: 'Mi abuela no se perdía el radioperiódico de las ocho de la tarde aunque estuviera ocupada.', ja: '祖母は夜8時のラジオニュースを、たとえ忙しくても欠かさず聴いていた。', trivia: '「radio」＋「periódico」（新聞・定期刊行物、ラテン語 periodicus 由来）の合成語で、主にラテンアメリカで使われた古い表現。英語では単に radio news broadcast と言い、スペイン語の radioperiódico に直接対応する一語の英単語は存在しない。' },
  'radioreceptor': { es: 'El técnico reparó el viejo radioreceptor de válvulas que llevaba años sin funcionar.', ja: '技術者は、何年も動いていなかった古い真空管式ラジオ受信機を修理した。', trivia: '「radio」＋ラテン語 receptor（受け取る者、recipere「受け取る」の派生）の合成語。英語の radio receiver と同義で、英語 receiver もラテン語 recipere を共通の語根に持つ。日常会話では単に radio と略されることが多い。' },
  'radioterapia': { es: 'La oncóloga le explicó que la radioterapia se aplicaría en sesiones de veinte minutos durante seis semanas.', ja: '腫瘍専門医は、放射線治療を6週間にわたって1回20分のセッションで行うと説明した。', trivia: '「radio」（放射線）＋ギリシャ語 therapeia（治療・療法）の合成語。英語の radiotherapy と語構成・意味ともに完全一致するインターナショナルな医学用語で、X線発見後の20世紀初頭に造語された。' },
  'radiotransmisor': { es: 'El explorador llevaba un radiotransmisor portátil para comunicarse con el campamento base en caso de emergencia.', ja: '探検家は、緊急時にベースキャンプと連絡を取るために携帯型無線送信機を持っていた。', trivia: '「radio」＋ラテン語 transmittere（向こうへ送る：trans「越えて」＋mittere「送る」）の合成語。英語の radio transmitter と完全対応し、英語の transmit・mission・missile もすべて mittere を語根に持つ同族語群に属する。' },
  'radioyente': { es: 'La emisora pidió a los radioyentes que llamaran para participar en el concurso en directo.', ja: '放送局はリスナーに電話をかけてライブコンテストに参加するよう呼びかけた。', trivia: '「radio」＋「oyente」（聴く者、動詞 oír「聞く」のラテン語 audire 由来の現在分詞形）の合成語。英語では radio listener と2語で表し、oyente に対応する英語の auditor・audience も同じラテン語 audire を語根に持つ。' },
  'radón': { es: 'Las autoridades sanitarias recomiendan ventilar los sótanos para evitar la acumulación de radón.', ja: '保健当局は、ラドンの蓄積を防ぐために地下室を換気するよう勧めている。', trivia: 'ラテン語 radius（光線）から来たラジウム（radium）の名に接尾辞 -on を加えて命名された元素で、1900年にドーン（Dorn）が発見した。英語でも radon と全く同じスペルで、国際的な元素名の慣例に従い両言語で一致している。' },
  'raedura': { es: 'El carpintero barrió las raeduras de madera que se habían acumulado en el suelo del taller.', ja: '大工は工房の床に積もっていた木くずを掃いて片付けた。', trivia: '動詞 raer（削り落とす）に名詞接尾辞 -dura を加えた語で、raer 自体はラテン語 radere（削る・剃る）に由来する。英語の erase・razor もこの radere を共通語根に持ち、剃刀（razor）と消去（erase）が同じ語源をもつことは興味深い。' },
  'raer': { es: 'El arqueólogo usó una espátula fina para raer los restos de barro adheridos a la cerámica.', ja: '考古学者は陶器に付着した泥の残りをこすり落とすために細いへらを使った。', trivia: 'ラテン語 radere（削る・剃る・こする）に直接由来する動詞で、不規則活用を示す。英語の erase（消す）・razor（剃刀）・abrade（磨耗させる）はすべて radere を語根に持つ同族語であり、「こすって消す」という概念を共有している。' },
  'ráfaga': { es: 'Una ráfaga de viento frío me arrancó el sombrero de la cabeza al doblar la esquina.', ja: '角を曲がったとたん、冷たい突風に帽子を飛ばされた。', trivia: '語源は諸説あり、アラビア語 rafaqa（吹く）とする説やラテン語系の語からの変化とする説がある。英語では gust（突風）・burst（連射）・flash（閃光）と文脈によって訳し分けが必要で、一語で対応する英単語がない多義語の好例である。' },
  'rafe': { es: 'El neurocirujano explicó que el rafe mediano separa las dos mitades del cerebro.', ja: '神経外科医は、正中縫線が脳の左右両半球を分けていると説明した。', trivia: 'ギリシャ語 rhaphē（縫い目、rhaptein「縫う」の派生）に由来する解剖学・植物学用語。英語でも raphe と綴り（ギリシャ語のまま）同義に使われ、スペイン語 rafe は英語 raphe の音韻変化した形。「縫い合わせた線」という比喩が語源にある。' },
  'rafia': { es: 'La artesana tejía cestas de rafia con colores vivos que vendía en el mercado local.', ja: '職人は鮮やかな色のラフィアかごを編んで地元の市場で売っていた。', trivia: 'マダガスカル原産のラフィアヤシを指すマラガシー語（またはバンツー語系）の語 rafia に由来するとされる。英語でも raffia と綴りほぼ同形で、麦わら帽子やカゴバッグなどの素材として両言語に広まった熱帯植物由来の借用語である。' },
  'rágula': { es: 'El poeta barroco describió la rágula del héroe derrotado con imágenes de tormenta y caos.', ja: 'バロックの詩人は、敗れた英雄の激しい憤怒を嵐と混沌のイメージで描写した。', trivia: '極めて稀な古語・文語で、語源は明確に確立されておらず、ラテン語 rabula（うるさい弁護士、議論好き）との関連を指摘する説もある。英語には直接対応する借用語はなく、rage（怒り）が意味上の近縁語として挙げられる程度である。' },
  'raicilla': { es: 'La planta de fresa desarrolla pequeñas raicillas que absorben nutrientes directamente del sustrato.', ja: 'イチゴの植物は、培地から直接栄養を吸収する小さな細根を発達させる。', trivia: 'raíz（根）の縮小形で、raíz 自体はラテン語 radix（根）に由来する。英語の radical（根本的な）・radish（ラディッシュ）・eradicate（根絶する）はすべて radix を語根に持ち、「根っこ」という概念が多彩な英語語彙を生んでいることがわかる。' },
  'raído': { es: 'Llevaba un jersey raído pero limpio, lo que delataba su situación económica difícil.', ja: '彼はすり切れているが清潔なセーターを着ており、それが苦しい経済状況を物語っていた。', trivia: '動詞 raer（ラテン語 radere「削る」由来）の過去分詞が形容詞化した語。英語の threadbare と意味が近く、thread（糸）＋bare（むき出し）という合成語で「糸がむき出しになるほど擦り切れた」様子を表す点で、異なる発想から同じ概念に至っている。' },
  'raigal': { es: 'El problema tiene causas raigales que no se resolverán con medidas superficiales.', ja: 'その問題は表面的な対策では解決しない根本的な原因を抱えている。', trivia: 'raíz（根、ラテン語 radix 由来）に形容詞接尾辞 -al を加えた語。英語の radical はラテン語 radicalis（根に関する）から直接来ており、raigal と radical は同じ祖先 radix を持つ「遠い親戚」で、radical が現代英語で「過激な」の意味でも使われるのと好対照をなす。' },
  'raigambre': { es: 'La fiesta del pueblo tiene una raigambre histórica que se remonta al siglo XVI.', ja: 'その村の祭りは16世紀にさかのぼる歴史的な根強い伝統を持っている。', trivia: 'raíz（根、ラテン語 radix）に接尾辞 -ambre を加えた語で、根の張り具合から比喩的に「文化・伝統の根付き」を表す。英語には直訳できる一語がなく、deep roots や strong traditions と表現するが、英語の radical・eradicate と語根 radix を共有する語彙ファミリーの一員である。' },
  'raigo': { es: 'Cuando raigo la pintura vieja de la pared, siempre me aseguro de usar guantes y mascarilla.', ja: '壁の古い塗料を削り落とすとき、私は必ず手袋とマスクを着用するようにしている。', trivia: '動詞 raer（ラテン語 radere「削る・こする」由来）の直説法現在1人称単数形。raer は活用が特殊で、1人称単数で raigo/rayo の両形が並存する稀な動詞。英語の erase・razor・abrasion はいずれも同じ radere を語根に持ち、「こすって落とす」行為を多様な語彙で表している。' },
  'raigón': { es: 'El dentista tuvo que extraer el raigón que quedaba bajo la encía después de la fractura de la corona.', ja: '歯科医は歯冠が折れた後に歯茎の下に残っていた残根を抜歯しなければならなかった。', trivia: 'raíz（根、ラテン語 radix 由来）の増大辞 -ón を加えた形で「大きな根・残根」を意味する。英語では dental root（歯根）と言い、root 自体は古英語 rot（さらに古ノルド語 rót）に由来し、radix とは別系統ながら意味的に同じ概念を担う。' },
  'raíl': { es: 'Un tornillo suelto en el raíl provocó el descarrilamiento del tren de mercancías.', ja: 'レールの緩んだボルトが貨物列車の脱線を引き起こした。', trivia: '英語の rail をスペイン語に音訳した借用語で、rail はフランス語 reille（横木、ラテン語 regula「定規・棒」由来）を経由して英語に入った語。スペイン語 raíl はアクセント記号を伴う形で定着しており、英語 rule・regulate・rail がすべてラテン語 regula を共通語根に持つ興味深い語族を形成している。' },
  'raimiento': { es: 'El cronista medieval reprochó el raimiento de quienes pedían limosna sin vergüenza alguna.', ja: '中世の年代記作者は、恥ずかしげもなく物乞いをする者たちの厚かましさを非難した。', trivia: 'raer（ラテン語 radere「削る・こする」由来）から派生した古語で、「削り落とされた感覚＝羞恥心のなさ・厚顔無恥」という比喩的意味を持つ。英語には直接対応する借用語はなく、impudence（恥知らず）が意味上の対応語。英語 abrasion（擦り傷・摩耗）は同じ radere から来る技術語である。' },
  'reinaldo': { es: 'Reinaldo llegó tarde a la reunión y tuvo que disculparse ante todos los presentes.', ja: 'レイナルドは会議に遅刻し、出席者全員に謝罪しなければならなかった。', trivia: 'ゲルマン語起源の名前で、古高ドイツ語 Raginald（ragin「助言・力」＋wald「支配する」）に由来する。英語の Reginald・Ronald・Reynolds も同じゲルマン語語根を持つ変形で、「賢明に支配する者」という意味合いを共有している。' },
  'reinante': { es: 'El silencio reinante en la biblioteca hacía imposible concentrarse con el ruido del exterior.', ja: '図書館を支配する静寂のせいで、外の騒音がいっそう気になって集中できなかった。', trivia: '動詞 reinar の現在分詞形で形容詞として定着した語。reinar はラテン語 regnare（支配する、rex「王」の派生）に由来し、英語の reigning・reign・regal・royal もすべてラテン語 rex/regnum を語根に持つ同族語群を形成している。' },
  'reinar': { es: 'Tras la tormenta, reinó una calma extraña que puso a todos en alerta.', ja: '嵐が過ぎた後、奇妙な静けさが辺りを支配し、全員が警戒態勢に入った。', trivia: 'ラテン語 regnare（支配する、rex「王」の派生）に由来し、スペイン語 rey（王）・reino（王国）と同じ語族に属する。英語の reign はフランス語 regner を経て同じラテン語 regnum から来ており、スペイン語 reinar と英語 reign は語根を共有する近縁語（cognate）である。' },
  'reincidencia': { es: 'La reincidencia en delitos graves puede resultar en penas de cárcel más largas.', ja: '重大犯罪における再犯は、より長い禁固刑につながることがある。', trivia: 'ラテン語の re-（再び）と incidere（落ちる・起こる）に由来し、「同じ過ちに再び落ちる」という概念を表す。英語の recidivism（再犯）と同語根だが、スペイン語では relapse に近い reincidencia の方が日常的に使われる。' },
  'reincidente': { es: 'El juez tuvo en cuenta que el acusado era reincidente al dictar la sentencia.', ja: '裁判官は判決を下す際に、被告が常習犯であることを考慮した。', trivia: 'ラテン語 re-（再び）＋ incidere（落ちる）の現在分詞形に由来し、「再び同じ過ちを犯す人」を意味する。英語では repeat offender や recidivist と表現するが、recidivist はより専門的・法律的なニュアンスがある。' },
  'reincidir': { es: 'El gobierno quiere crear programas para que los expresos no reincidan en el crimen.', ja: '政府は元受刑者が再び犯罪を繰り返さないためのプログラムを作ろうとしている。', trivia: 'ラテン語の re-（再び）と incidere（落ちる・起こる）を組み合わせた動詞で、「同じ過ちや悪い状態に再び陥る」という意味。英語の relapse（再発する）や commit another offense に相当し、recidivate という英単語とも同語根である。' },
  'reincorporarse': { es: 'Después de la baja por maternidad, María se reincorporó al trabajo con mucha energía.', ja: '産休明けに、マリアは活力あふれる状態で職場復帰した。', trivia: 'ラテン語の re-（再び）＋ in-（中に）＋ corpus（身体・組織）から成り、「組織の中に再び身を置く」というイメージの語。英語の rejoin や return to work に相当し、英語の incorporate（法人化する・組み込む）とも同語根である。' },
  'reincorporación': { es: 'El plan de reincorporación laboral ayuda a quienes llevan tiempo fuera del mercado de trabajo.', ja: '職場復帰プログラムは、長期間労働市場を離れていた人たちを支援する。', trivia: 'ラテン語 re-（再び）＋ incorporatio（身体への組み込み）に由来する名詞。英語の reinstatement（復職）や reintegration（再統合）に相当し、英語でも reincorporation という語が「再組み込み」の意で使われる同語根の単語である。' },
  'reino': { es: 'El reino animal incluye millones de especies distintas distribuidas por todo el planeta.', ja: '動物界には地球全体に分布する何百万もの異なる種が含まれている。', trivia: 'ラテン語の regnum（支配・王国）に由来し、rex（王）と同語根。英語の kingdom はゲルマン語由来（king＋dom）だが、reign（治世・支配する）はラテン語 regnum から英語に入った同語根語であり、reino と深く繋がっている。' },
  'reintegro': { es: 'Solicité el reintegro del importe pagado porque el producto llegó dañado.', ja: '商品が破損した状態で届いたので、支払い金額の返金を申請した。', trivia: 'ラテン語の re-（再び）＋ integer（完全な・手つかずの）から成り、「元の完全な状態に戻す」というニュアンスを持つ。英語の refund や withdrawal に相当し、integer（整数）や integrity（誠実さ・完全性）とも同語根である。' },
  'reír': { es: 'No pude evitar reír cuando vi la cara de susto de mi hermano.', ja: '弟の驚いた顔を見たとき、笑いをこらえることができなかった。', trivia: 'ラテン語の ridere（笑う）に由来し、この語根から英語の ridiculous（滑稽な）や ridicule（あざ笑う）も生まれている。直接「笑う」を表す英単語 laugh はゲルマン語系で語源が異なるが、reír の痕跡は英語の派生語に残っている。' },
  'reiteración': { es: 'La reiteración de los mismos errores demuestra que no se ha aprendido la lección.', ja: '同じミスを何度も繰り返すことは、教訓が身についていないことを示している。', trivia: 'ラテン語の reiteratio（繰り返し）に由来し、iterare（繰り返す）が語根。英語の reiteration と同語根・同形に近く、ほぼ直訳できる国際語的な単語。iter はラテン語で「道・旅」も意味し、「同じ道を何度も行く」イメージが元にある。' },
  'reiterada': { es: 'A pesar de las reiteradas advertencias, siguieron ignorando las normas de seguridad.', ja: '度重なる警告にもかかわらず、彼らは安全規則を無視し続けた。', trivia: 'ラテン語 reiterare（繰り返す）の過去分詞に由来する形容詞で、「何度も繰り返された」を意味する。英語の reiterated（繰り返された）とほぼ同形で意味も同じ国際語的な単語であり、語根の iter は英語の itinerary（旅程）とも共通する。' },
  'reiteradamente': { es: 'Los sindicatos han pedido reiteradamente mejoras en las condiciones laborales.', ja: '労働組合は労働条件の改善を繰り返し求めてきた。', trivia: 'reiterada（繰り返された）に副詞語尾 -mente を付けた副詞で、「何度も・繰り返し」を意味する。英語の repeatedly（繰り返して）に対応するが、スペイン語では reiteradamente の方がよりフォーマルな文脈で好まれる傾向がある。' },
  'reiterar': { es: 'Quisiera reiterar mi agradecimiento a todos los que hicieron posible este evento.', ja: 'このイベントを可能にしてくださったすべての方々へ、改めて感謝を申し上げたい。', trivia: 'ラテン語の reiterare（再び繰り返す）に由来し、re-（再び）＋ iterare（繰り返す）の合成語。英語の reiterate と語源・意味・使い方がほぼ完全に一致する「真のコグネート」の一つ。格式ある表現として両言語で同様のフォーマルな場面で使われる。' },
  'reivindicación': { es: 'Las reivindicaciones de los trabajadores incluyen mejores salarios y más días de vacaciones.', ja: '労働者たちの要求には、より良い賃金と休暇日数の増加が含まれている。', trivia: 'ラテン語の re-（再び）＋ vindicare（要求する・解放する）に由来し、「本来あるべき権利を取り戻す」というニュアンスがある。英語の vindication（名誉回復・正当性の証明）や vindictive（復讐心の強い）と同語根で、「正義を主張する」という概念が共通している。' },
  'reivindicar': { es: 'Los manifestantes salieron a la calle para reivindicar sus derechos laborales.', ja: 'デモ参加者たちは労働権を主張するために街頭に繰り出した。', trivia: 'ラテン語の vindicare（権利を主張する・解放する）に re- を加えた動詞。英語の vindicate（正当性を証明する・名誉を回復する）と同語根だが、スペイン語の reivindicar はより積極的に「権利を要求する」という行動的なニュアンスが強い。' },
  'reja': { es: 'Los vecinos pusieron rejas en las ventanas para mejorar la seguridad de su casa.', ja: '近隣住民たちは家の防犯を高めるために窓に面格子を取り付けた。', trivia: '語源については諸説あり、ラテン語の regula（棒・規則）から来たとする説や、農具の「すきの刃」を意味するラテン語 regula とは別の語源とする説もある。英語では bars（鉄格子）や grate に相当し、同語根の英単語は特定しにくいが、regulate（規制する）と遠い親戚かもしれない。' },
  'rejo': { es: 'El rejo del escorpión puede ser peligroso si no se trata a tiempo.', ja: 'サソリの毒針は、適切に処置しなければ危険なことがある。', trivia: 'ラテン語の rigere（硬直する・突き刺さる）または regere（まっすぐ導く）に由来するとされ、「硬く突き出たもの」というイメージが語根にある。英語では直接の対応語が少ないが、rigid（硬直した）と遠い語根を共有している可能性があり、地域によって意味が大きく異なる多義語である。' },
  'rejuvenecer': { es: 'Unos días de descanso en la montaña bastaron para rejuvenecer su cuerpo y su mente.', ja: '山での数日間の休息で、彼の体と心を若返らせるのに十分だった。', trivia: 'ラテン語の re-（再び）＋ juvenescere（若くなる）に由来し、juvenis（若者）が語根。英語の rejuvenate と語源・意味ともにほぼ完全に一致する国際語的な単語で、juvenile（少年の・未成年の）や英語の young も遠い親戚にあたるインド・ヨーロッパ語族共通の語根 yeu-（活力・若さ）に繋がる。' },
  'rejuvenecimiento': { es: 'El programa de rejuvenecimiento de la ciudad incluye zonas verdes y nuevos espacios culturales.', ja: '都市再活性化プログラムには、緑地帯と新しい文化施設が含まれている。', trivia: 'rejuvenecer（若返る）の名詞形で、ラテン語の juvenis（若者）が語根。英語の rejuvenation と語源・構造ともにほぼ同じ国際語的な単語であり、英語の juvenile（少年の）やスペイン語の joven（若者）とも同じラテン語語根に由来している。' },
  'relacionada': { es: 'Esta decisión está estrechamente relacionada con los cambios económicos del último año.', ja: 'この決定は昨年の経済変化と密接に関連している。', trivia: 'ラテン語の relatio（報告・関係）に由来し、re-（再び）＋ latio（運ぶこと）が語源。英語の related と語源・意味ともに一致する真のコグネートで、relation（関係）、relative（親戚・相対的な）なども同語根。「情報を運び返す」というニュアンスが元の意味にある。' },
  'relacionar': { es: 'Es difícil relacionar estos dos fenómenos sin más datos científicos.', ja: 'より多くの科学的データなしに、この二つの現象を結びつけるのは難しい。', trivia: 'ラテン語の relatio（関係・報告）から派生した動詞で、re-（再び）＋ latio（運ぶこと）が語根。英語の relate（関連させる・話す）と同語根であり、relation、relative、relative などとも繋がる。「互いに関係を運び合う」というイメージが根底にある。' },
  'relajación': { es: 'La relajación muscular es fundamental para recuperarse bien de un entrenamiento intenso.', ja: '筋肉のリラクゼーションは、激しいトレーニングから十分に回復するために不可欠だ。', trivia: 'ラテン語の relaxatio（緩めること）に由来し、re-（元に戻す）＋ laxus（緩い・広い）が語根。英語の relaxation と語源・形ともにほぼ同一の国際語で、lax（ルーズな）や laxative（下剤）も同じラテン語語根 laxus から来ている。' },
  'relajada': { es: 'Después de un largo baño caliente, me sentí completamente relajada.', ja: '長い温浴の後、私は完全にリラックスした気分になった。', trivia: 'ラテン語の relaxatus（緩められた）に由来する過去分詞形容詞で、laxus（緩い）が語根。英語の relaxed とほぼ同語源・同意味の真のコグネートで、英語の lax（ゆるい・不注意な）や laxative（便秘薬）とも同じ語根ファミリーに属する。' },
  'relajar': { es: 'Escuchar música clásica antes de dormir me ayuda a relajar la mente.', ja: '寝る前にクラシック音楽を聴くことは、心をリラックスさせるのに役立つ。', trivia: 'ラテン語の relaxare（緩める・解放する）に由来し、re-（元に）＋ laxare（緩める）が語根。英語の relax と語源・意味ともに一致する典型的なコグネートで、lax（ゆるい）、laxative（緩下剤）、slack（たるむ）なども遠縁にあたるとされる。' },
  'relamerse': { es: 'Al ver el pastel de chocolate en el escaparate, el niño se relamía de anticipación.', ja: 'ショーウィンドウのチョコレートケーキを見て、その子供は期待に口をなめまわした。', trivia: 're-（繰り返し）＋ lamer（なめる）の再帰動詞で、ラテン語の lambere（なめる）が語根。英語の lamb（子羊）とは関係なく、むしろ英語の lap（ぴちゃぴちゃ飲む）が同じインド・ヨーロッパ語族の語根 lab-/lap-（なめる）に由来するとされており、遠い親戚にあたる可能性がある。' },
  'relámpago': { es: 'Un relámpago iluminó el cielo durante unos segundos antes de que empezara la tormenta.', ja: '嵐が始まる前に、稲妻が数秒間空を照らした。', trivia: '語源についてはラテン語の re-（再び）＋ lampas（明かり・松明、ギリシャ語由来）から来たとする説が有力で、「何度も閃く光」というイメージが語源にある。英語の lamp（ランプ）とはギリシャ語 lampas を共通祖先とする同語根語であり、lightning とは全く異なる語源を持つ点が興味深い。' },
  'relance': { es: 'El partido se decidió en un relance afortunado en los últimos segundos del juego.', ja: '試合は試合終了間際の幸運な再プレーで決まった。', trivia: 'ラテン語 lanceare（槍を投げる）から派生したフランス語由来の借用語で、動詞 relanzar の名詞形に近い。英語では「stroke of luck」や「lucky bounce」に相当し、テニスやサッカーの文脈では「replay」とも訳される。' },
  'relanzamiento': { es: 'El relanzamiento del producto con nuevo diseño generó un gran interés entre los consumidores.', ja: '新デザインでの製品の再発売は消費者の間で大きな関心を呼んだ。', trivia: '動詞 relanzar（再び投げる・再発売する）に接尾辞 -miento を付けた名詞。英語の relaunch と同語根で、どちらもラテン語 lanceare（槍を投げる）を起源とし、近代的なビジネス用語として同じ意味で使われる。' },
  'relanzar': { es: 'La empresa decidió relanzar su marca clásica con una campaña moderna en redes sociales.', ja: 'その企業はSNSでの現代的なキャンペーンを通じてクラシックブランドを再発売することにした。', trivia: '接頭辞 re-（再び）＋ lanzar（投げる・発射する）の複合語。英語の relaunch と完全に同語根で、ラテン語 lanceare（槍を投げる）が語源。スペルは異なるが意味・用法ともほぼ一致する好例のコグネート。' },
  'relatar': { es: 'El periodista relató los hechos con gran detalle para que los lectores pudieran entender lo sucedido.', ja: '記者は読者が何が起きたか理解できるよう、出来事を非常に詳しく述べた。', trivia: 'ラテン語 relatum（re-「戻す」＋ latum「運ぶ」の過去分詞）が語源。英語の relate や narrate と同語根で、relate は「関係づける」という意味も持つが、スペイン語の relatar は主に「語る・報告する」の意味に特化している。' },
  'relatada': { es: 'La historia relatada por la abuela emocionó a todos los nietos reunidos alrededor de la chimenea.', ja: '祖母によって語られたその話は、暖炉の周りに集まったすべての孫たちを感動させた。', trivia: '動詞 relatar の過去分詞女性形。ラテン語 relatum（運び返された・伝えられた）が語源で、英語の narrated や told に相当する。形容詞として名詞を修飾する際は性数一致が必要なスペイン語の特徴を示す語。' },
  'relativas': { es: 'Hay medidas relativas a la seguridad vial que deben cumplirse en todo el país.', ja: '国全体で遵守されなければならない道路安全に関する措置がある。', trivia: 'ラテン語 relativus（関係づけられた）が語源で、英語の relative と完全な同語根コグネート。文法用語としての「関係詞」(pronombre relativo) でも使われるが、日常でも「〜に関する」という意味で頻繁に使われる点は英語の relative とやや異なる。' },
  'relativamente': { es: 'El precio de este producto es relativamente bajo en comparación con otros del mercado.', ja: 'この製品の価格は市場の他のものと比べて比較的低い。', trivia: 'relativo に副詞語尾 -mente（英語の -ly に相当）を付けた語。英語の relatively と完全な同語根コグネートで意味・用法もほぼ同一。ラテン語 relativus を共通の祖先に持つ。' },
  'relativo': { es: 'El éxito relativo de la campaña fue suficiente para convencer al equipo de continuar.', ja: 'キャンペーンの相対的な成功はチームに継続を納得させるのに十分だった。', trivia: 'ラテン語 relativus（関係した、比較的な）が語源で、英語の relative と同語根。ただし英語の relative は「親戚」という名詞としても広く使われるのに対し、スペイン語ではその意味では pariente の方が一般的なのが面白い相違点。' },
  'relato': { es: 'El relato de los testigos fue fundamental para resolver el misterio.', ja: '目撃者たちの陳述はミステリーを解決するうえで決定的だった。', trivia: 'ラテン語 relatum（relatum < re- + latus）が語源で、英語の tale や narrative に相当。現代スペインでは政治やメディアの文脈で「ナラティブ」（物語戦略）の意味で使われ、英語の narrative がそのまま借用されることもあるが、relato の方が自然なスペイン語表現。' },
  'relax': { es: 'Después de una semana de trabajo intenso, necesito un poco de relax el fin de semana.', ja: '集中的な一週間の仕事の後、週末は少しリラックスが必要だ。', trivia: '英語 relax（ラテン語 relaxare「緩める」が語源）をそのままスペイン語に取り込んだ借用語。スペイン語でも relajación や relajarse という固有の語があるが、relax は英語の影響で日常会話でカジュアルに使われる現代的な外来語として定着している。' },
  'relevancia': { es: 'La relevancia de este descubrimiento científico no se comprendió hasta años después.', ja: 'この科学的発見の重要性は何年も後になるまで理解されなかった。', trivia: 'ラテン語 relevare（持ち上げる・軽くする）が語源で、英語の relevance と同語根コグネート。英語では「関連性」の意味が強いが、スペイン語の relevancia は「重要性・卓越さ」のニュアンスも強く、tener relevancia で「重要な意味を持つ」という表現でよく使われる。' },
  'relevante': { es: 'Es importante incluir solo la información relevante en el informe final.', ja: '最終報告書には関連性のある情報だけを含めることが重要だ。', trivia: 'ラテン語 relevare（持ち上げる）の現在分詞形 relevantem が語源で、英語の relevant と同語根の完全なコグネート。英語・スペイン語ともに「重要な・関連する」という意味で使われ、ビジネスや学術文書での使用頻度が高い。' },
  'relevo': { es: 'El corredor esperaba el relevo de su compañero para salir disparado en la última vuelta.', ja: 'その走者は最終周回で一気に飛び出すために仲間からのバトンタッチを待っていた。', trivia: 'ラテン語 relevare（持ち上げる・交代させる）が語源で、英語の relief や relay と同語根。スポーツのリレー競技を指す際は relevo de relevos とも言い、英語の relay race に対応する。「世代交代」の比喩的用法（relevo generacional）も現代スペイン語で頻繁に使われる。' },
  'relé': { es: 'El técnico reemplazó el relé defectuoso y el sistema eléctrico volvió a funcionar correctamente.', ja: '技術者は故障したリレーを交換し、電気系統は正常に動作するようになった。', trivia: 'フランス語の relais（中継点・交代所）を経由して英語の relay が電気用語として確立し、それをスペイン語が relé として借用した語。語源は古フランス語 relayer（交代させる）で、電気信号を「受け渡す」機能がその名の由来。' },
  'relicario': { es: 'En el museo vimos un relicario medieval de oro que contenía huesos de un santo.', ja: '博物館で聖人の骨を収めた中世の黄金の聖遺物箱を見た。', trivia: 'ラテン語 reliquiae（残された物・遺物）が語源で、英語の reliquary と同語根。英語では reliquary が「聖遺物容器」の専門用語として使われるが、スペイン語の relicario はアクセサリーのロケット（写真入りペンダント）にも使われる点が興味深い意味の広がりを示している。' },
  'relieve': { es: 'El mapa mostraba el relieve montañoso de la región con gran precisión.', ja: 'その地図は地域の山岳地形を非常に精確に示していた。', trivia: 'ラテン語 relevare（持ち上げる）が語源で、英語の relief と同語根コグネート。英語では「安堵」「救済」の意味が日常的に使われるが、スペイン語の relieve は「地形・起伏」「浮き彫り」の意味が前面に出る。poner en relieve（際立たせる）という慣用表現は英語の highlight に相当する。' },
  'religión': { es: 'La religión ha sido una fuente de inspiración para artistas y filósofos a lo largo de la historia.', ja: '宗教は歴史を通じて芸術家や哲学者にとってインスピレーションの源であり続けた。', trivia: 'ラテン語 religio（義務感・信仰心・崇拝）が語源で、語源については「再び読む」(relegere) と「結びつける」(religare) の二説がある。英語の religion と完全な同語根コグネートで、スペルの唯一の違いはアクセント記号のみ。' },
  'religiosa': { es: 'La hermana religiosa dedicó toda su vida a cuidar a los enfermos en el hospital.', ja: 'その修道女は病院での病人の世話に生涯を捧げた。', trivia: 'ラテン語 religiosus（信心深い）の女性形で、英語の religious と同語根コグネート。名詞として「修道女」を意味する用法はスペイン語の特色で、英語では religious woman や nun と言い換えが必要。形容詞の比喩的用法「几帳面な」は英語の religious attention to detail に通じる。' },
  'religiosidad': { es: 'La religiosidad popular en América Latina se expresa a través de fiestas y procesiones coloridas.', ja: 'ラテンアメリカの民衆の信仰心は色彩豊かな祭りや行列を通じて表現される。', trivia: 'ラテン語 religiositas（敬虔さ）が語源で、英語の religiosity と同語根コグネート。英語の religiosity はやや批判的・過度な信仰を示すニュアンスを持つ場合があるが、スペイン語の religiosidad はより中立的・肯定的に使われることが多い微妙な語感の差がある。' },
  'religioso': { es: 'Él lleva una vida religiosa y asiste a misa todos los domingos sin falta.', ja: '彼は信仰深い生活を送り、毎週日曜日欠かさずミサに参列する。', trivia: 'ラテン語 religiosus（信心深い・誠実な）が語源で、英語の religious と完全な同語根コグネート。名詞として「修道士・聖職者」を意味するのはスペイン語独自の用法で、英語では religious person や monk/friar と言う必要がある点が面白い違い。' },
  'reliquia': { es: 'Esa guitarra es una reliquia familiar que ha pasado de generación en generación.', ja: 'そのギターは世代から世代へと受け継がれてきた家族の形見だ。', trivia: 'ラテン語 reliquiae（残されたもの・遺物）の複数形が単数名詞として定着したもので、英語の relic と同語根コグネート。英語の relic は考古学的遺物やキリスト教の聖遺物を主に指すが、スペイン語の reliquia は「形見・思い出の品」という個人的な意味でも日常的に使われる。' },
  'relojera': { es: 'La relojera experta restauró el viejo reloj de bolsillo con una habilidad impresionante.', ja: 'その熟練した時計職人（女性）は素晴らしい技術で古い懐中時計を修復した。', trivia: 'reloj（時計）＋接尾辞 -ero/-era（職業を示す）の複合語で、reloj 自体はアラビア語 al-rukhāma（大理石の日時計）またはアラビア語 al-rl\'ij（仕掛け時計）が語源とされる。英語の watchmaker に相当するが、英語の watch と clock が区別されるのに対しスペイン語では reloj が両方を指す。' },
  'relojería': { es: 'Llevé mi reloj antiguo a la relojería del centro para que lo repararan.', ja: '古い時計を修理してもらうために繁華街の時計店に持って行った。', trivia: 'reloj（アラビア語起源）に接尾辞 -ería（店・業種を示す）を付けた語で、英語では watchmaker\'s shop や horology shop に相当。英語の horology（時計学）はギリシャ語 hora（時間）＋ logos（学問）が語源であり、語源系統が全く異なる点が興味深い。' },
  'relojero': { es: 'El relojero del barrio conoce todos los mecanismos de los relojes antiguos como la palma de su mano.', ja: '近所の時計職人は古時計の機構をすべて手の平のように知り尽くしている。', trivia: 'reloj（アラビア語起源とされる）に職業接尾辞 -ero を付けた語。英語の clockmaker や watchmaker に相当するが、英語ではこれらを使い分けるのに対しスペイン語では relojero 一語でカバーする。スペイン語の reloj が英語の clock にも watch にも対応する点が語彙の構造の違いを示している。' },
  'reluciente': { es: 'El coche llegó al salón con la carrocería reluciente bajo los focos de la exposición.', ja: '車は展示会のスポットライトの下で車体をぴかぴかに光らせながらショールームに現れた。', trivia: '動詞 relucir（輝く・光る）の現在分詞形で、relucir はラテン語 relucere（re-「再び」＋ lucere「光る」）が語源。英語の gleaming や shining に相当し、英語の lucid（明快な）や translucent（半透明の）と同じラテン語 lux/lucis（光）を共通の語根に持つコグネートの仲間。' },
  'relucir': { es: 'Sus ojos relucían de alegría cuando recibió la noticia.', ja: 'その知らせを受け取ったとき、彼女の目は喜びで輝いていた。', trivia: 'ラテン語 relucēre（再び光る）から派生し、接頭辞 re-（再び）と lucēre（輝く）の合成語。英語の lucid（明晰な）や translucent（半透明の）と同じラテン語根 lux（光）を共有しており、見た目の輝きだけでなく才能の際立ちにも使われる点も英語の shine に近い。' },
  'reluchar': { es: 'Los trabajadores decidieron reluchar por sus derechos tras el fracaso de las primeras negociaciones.', ja: '最初の交渉が失敗に終わった後、労働者たちは権利のために再び戦うことを決意した。', trivia: 're-（再び）と luchar（戦う）の合成語で、ラテン語 luctāri（格闘する・もがく）に由来する。英語の reluctant（気が進まない）も同じラテン語根 luctāri から来ており、「抵抗しながら引きずられる」という原義が共通している点は興味深い。' },
  'relumbrar': { es: 'Los faros del coche relumbraban en la niebla, dificultando la visión de los conductores.', ja: '霧の中で車のヘッドライトがぎらぎら光り、ドライバーたちの視界を妨げていた。', trivia: 're-（強意）と lumbrar（光らせる）の合成語で、ラテン語 luminare（照らす）に由来する。英語の illuminate（照らす）や luminary（著名人・発光体）と同語根であり、比喩的に「一世を風靡する」という意味でも使われるのは英語の shine と平行している。' },
  'relumbre': { es: 'El relumbre de los anuncios de neón me deslumbró al salir del cine.', ja: '映画館を出たとき、ネオン広告のぎらぎらした光に目がくらんだ。', trivia: 'relumbrar の名詞形で、ラテン語 lumen（光）に由来する。英語の glare（まぶしい光）に相当するが、スペイン語では「見せかけの華やかさ」という否定的な比喩的意味でも頻繁に使われ、mucho relumbre y poca sustancia（見かけ倒し）のような慣用句にも登場する。' },
  'remachar': { es: 'El director remachó su punto clave al final de la reunión para que nadie lo olvidara.', ja: '会議の最後に、部長は誰も忘れないように重要な要点を強く念押しした。', trivia: 're-（強意）と machar（叩く・砕く）の合成語で、ラテン語 mattea（打撃を与える棒）に由来するとされる。英語の rivet も同様に「鋲で固定する」と「注意を釘付けにする」の両義を持っており、スペイン語と英語で見事に平行したメタファーの発展が見られる。' },
  'remache': { es: 'El mecánico usó remaches de acero para unir las chapas del fuselaje del avión.', ja: '整備士は航空機の胴体の金属板を接合するために鋼のリベットを使った。', trivia: 'remachar の名詞形で、英語の rivet と意味・用法ともに非常に近い。英語 rivet はフランス語 river（固定する）経由で古フランク語に由来し、スペイン語 remache はラテン語系の machar（叩く）から来ており、語源は異なるが指す物は同一という好例。' },
  'remanso': { es: 'Ese pequeño café es un verdadero remanso de paz en medio del bullicio de la ciudad.', ja: 'その小さなカフェは、都市の喧騒の中にある本当の安らぎの場所だ。', trivia: 'ラテン語 remansum（後に残ったもの）に由来し、re-（後に）と manēre（留まる）の合成語。英語の remain（残る）や mansion（邸宅：もともと「留まる場所」）と同語根であり、「流れが滞って溜まった場所」という物理的な原義から「心の避難所」という比喩へ発展した。' },
  'remanente': { es: 'El remanente del presupuesto municipal se destinará a la construcción de nuevas escuelas.', ja: '市の予算の余剰分は、新しい学校の建設に充てられる予定だ。', trivia: 'ラテン語 remanēre（残る）の現在分詞形 remanēns に由来し、英語の remnant（残り切れ・余剰）と同語源。ただし remnant は主に「端切れ」などの物質的な残余に使われるのに対し、remanente は会計・経済用語として「剰余金・繰越金」の意味で広く使われる点が異なる。' },
  'remar': { es: 'Tuvimos que remar con fuerza para llegar a la otra orilla antes de que oscureciera.', ja: '暗くなる前に対岸に着くために、私たちは力強く漕がなければならなかった。', trivia: 'ラテン語 remus（オール）に由来し、英語の row（漕ぐ）とは語源が異なる（row は古英語 rōwan から）。しかし「逆境に立ち向かって懸命に進む」という比喩的用法はスペイン語・英語ともに共通しており、remar contra la corriente は英語の row against the tide とほぼ対応する表現だ。' },
  'remarcable': { es: 'Su actuación fue remarcable, pero los críticos prefieren usar «notable» en español formal.', ja: '彼女の演技は注目に値するものだったが、評論家たちはフォーマルなスペイン語では «notable» を好んで使う。', trivia: '英語 remarkable およびフランス語 remarquable から直接借用された語で、スペイン語の正書法的には notable や destacable が推奨される。英語 remarkable は re-（再び）+ mark（注目する）+ able から成り、「何度でも注目に値する」という意味合いを持つ典型的な英仏共有語根の単語だ。' },
  'remarcar': { es: 'La profesora remarcó la importancia de revisar el texto antes de entregarlo.', ja: '先生は提出前に文章を見直すことの重要性を強く強調した。', trivia: 're-（再び・強意）と marcar（マークする・印をつける）の合成語で、英語 remark（発言する・注目する）と同語根のゲルマン語 marka（境界・印）に由来する。英語では remark が「発言」の意味で定着したのに対し、スペイン語の remarcar は「強調する」の意味が中心で、語義の分岐が興味深い。' },
  'remate': { es: 'El delantero marcó con un potente remate de cabeza en el último minuto del partido.', ja: 'フォワードは試合の最終分に強烈なヘディングシュートでゴールを決めた。', trivia: 'rematar（仕上げる・とどめを刺す）の名詞形で、ラテン語 mactāre（屠る・犠牲にする）に由来する説とゲルマン語系の mata（殺す）に由来する説がある。スポーツでの「シュート」の意味はスペイン語独自の発展で、英語では finish や shot に相当し、直接対応する一語がない。' },
  'remediar': { es: 'No hay nada que podamos hacer para remediar el daño causado por la tormenta.', ja: '嵐が引き起こした被害を解決するために私たちにできることは何もない。', trivia: 'ラテン語 remediāre（治療する）に由来し、英語の remedy（治療法・改善策）と完全に同語源。スペイン語では no poder remediarlo（どうにもならない）という表現が日常的に使われ、英語の can\'t help it に対応する慣用的な意味合いを持つ。' },
  'remedio': { es: 'No hay remedio para la nostalgia que sientes cuando estás lejos de casa.', ja: '故郷から遠く離れているときに感じるノスタルジアに対する治療法はない。', trivia: 'ラテン語 remedium（治療・救済）に由来し、英語の remedy と完全に同語源。sin remedio（どうしようもなく）や no tener más remedio que...（〜するしかない）のような慣用表現が豊富で、英語の no choice but to... に対応する日常表現として頻繁に使われる。' },
  'remeje': { es: 'El alquimista realizó un remeje cuidadoso de los ingredientes antes de calentarlos.', ja: '錬金術師は材料を加熱する前に丁寧な攪拌を行った。', trivia: '古語・専門用語で、mejer または mecer（揺り動かす・攪拌する）にre-（再び・強意）を付けた語とされ、ラテン語 miscēre（混ぜる）に遡る可能性がある。英語の miscellaneous（雑多な）や mix（混ぜる）と同語根という説もあるが、現代スペイン語ではほぼ廃語であり用例が極めて限られる。' },
  'rememoración': { es: 'La rememoración de los héroes caídos tuvo lugar en la plaza central del pueblo.', ja: '倒れた英雄たちの追悼式が、町の中央広場で執り行われた。', trivia: 'ラテン語 rememorātio（思い出すこと）に由来し、re-（再び）と memorāre（記憶させる）の合成語。英語の remembrance（追憶・記念）や commemoration（記念）と同語根で、いずれも語根 memor（心に留めている）に遡り、英語 memory・memorial とも深くつながっている。' },
  'rememorar': { es: 'Los veteranos se reunieron para rememorar los tiempos difíciles que vivieron juntos en la guerra.', ja: '退役軍人たちは戦争で共に過ごした苦しい時代を追憶するために集まった。', trivia: 'ラテン語 rememorāri（再び思い起こす）に由来し、英語の remember（覚えている）や commemorate（記念する）と同語根。英語では remember が日常語として定着しているのに対し、スペイン語の rememorar はやや格調高い書き言葉的なニュアンスがあり、英語の reminisce や recollect に近い文体的位置にある。' },
  'remendada': { es: 'Llevaba una chaqueta remendada en los codos, pero la lucía con total naturalidad.', ja: '彼女は肘につぎを当てたジャケットを着ていたが、それをごく自然に着こなしていた。', trivia: 'remendar（繕う）の過去分詞の女性形で、ラテン語 ēmendāre（欠点を取り除く・修正する）に由来する。英語の amend（修正する）や emend（校訂する）と同語根であり、「欠点（mendum）を取り除く」という原義から「布を繕う」という具体的な意味に特化したのがスペイン語の特徴だ。' },
  'remendar': { es: 'Mi abuela sabía remendar cualquier prenda con una habilidad que hoy ya casi nadie tiene.', ja: '私の祖母はどんな衣服でも繕う腕前を持っていたが、今日それができる人はほとんどいない。', trivia: 'ラテン語 ēmendāre（欠点を修正する）に由来し、英語の amend（修正する）・emend（校訂する）と同語源。英語の mend（修理する）も同根で、スペイン語 remendar と英語 mend は語形も意味もきわめて近い姉妹語と言える。' },
  'remiendo': { es: 'Ese proyecto de ley es solo un remiendo que no resolverá los problemas de fondo.', ja: 'あの法案は根本的な問題を解決しない、単なる応急処置に過ぎない。', trivia: 'remendar の名詞形および直説法現在1人称単数形の兼用語で、ラテン語 ēmendāre（修正する）に由来する。英語では patch（つぎ・応急処置）が最も近い対応語で、a patch job（その場しのぎの修理）はスペイン語の un remiendo とほぼ同じ比喩的ニュアンスを持つ。' },
  'remesa': { es: 'Las remesas que envían los emigrantes a sus familias son fundamentales para la economía del país.', ja: '移民が家族に送る送金は、その国の経済にとって不可欠なものだ。', trivia: 'ラテン語 remittere（送り返す・ゆるめる）の過去分詞 remissa に由来し、英語の remittance（送金）と完全に同語源。remit（送金する・免除する）も同根で、スペイン語 remesa と英語 remittance は経済・金融用語として国際的に共通の概念を指す緊密なコグネート（同語根語）だ。' },
  'remesón': { es: 'Tras el terremoto principal, una serie de remesones sacudieron la ciudad durante varios días.', ja: '本震の後、一連の余震が数日間にわたって街を揺さぶった。', trivia: 'remesa（発送・揺れ）の指小・強意形 -ón を付けた派生語で、ラテン語 remittere（送り出す・揺るがす）に由来する。チリを中心とした中南米スペイン語での「余震」の意味は地域特有の用法であり、英語では aftershock と言うが、remesón には「社会を揺るがす衝撃」という比喩的用法もある点が興味深い。' },
  'remero': { es: 'El equipo de remeros entrenaba en el río todas las mañanas antes del amanecer.', ja: 'ボート競技のチームは毎朝夜明け前に川で練習していた。', trivia: 'remar（漕ぐ）の派生名詞で、ラテン語 remus（オール）に由来する。英語の rower（漕ぎ手）は古英語 rōwan（漕ぐ）から来ており、スペイン語とは語源が異なる。ただしラテン語 remus は英語でも oar（オール）の概念に影響を与えたとされ、海事語彙として両言語が独自の経路で同じ概念に達した例だ。' },
  'remilgada': { es: 'La jefa era tan remilgada que nunca comía en restaurantes que no tuvieran mantel de tela.', ja: '上司は非常に気取り屋で、布のテーブルクロスがないレストランでは決して食事をしなかった。', trivia: 'remilgo の形容詞・過去分詞形で、語源については諸説あり、ラテン語 mimare（物まねをする・気取る）に由来するという説や、mel（蜂蜜）から来た「甘ったるい」という意味合いとする説がある。英語では prim（お上品ぶった）・squeamish（神経質な）・finicky（えり好みする）などが近い表現で、一語では対応しにくい繊細なニュアンスを持つ。' },
  'remilgo': { es: '¡Deja de hacerte el remilgo y come lo que te han puesto en el plato!', ja: 'もったいつけるのはやめて、皿に盛られたものを食べなさい！', trivia: '語源については確実な説がなく諸説ある。ラテン語 mimare（気取る）から来たとする説や、mime（物まねをする人）と関連づける説などがある。英語では affectation（気取り）・squeamishness（神経質さ）が近いが、remilgo には「過剰な上品ぶり」というやや滑稽なニュアンスがあり、sin remilgos（気取らずに・遠慮なく）という慣用句で「ためらいなく」の意味でもよく使われる。' },
  'reminiscencia': { es: 'Este poema está lleno de reminiscencias de la poesía romántica del siglo XIX.', ja: 'この詩は19世紀ロマン主義の詩の影響に満ちている。', trivia: 'ラテン語 reminisci（思い出す）に由来し、英語の reminiscence と完全に同語根。スペイン語では文学・芸術の「影響の名残」という意味でも使われる点が英語より広い。' },
  'remisión': { es: 'Tras varios meses de tratamiento, el médico confirmó la remisión completa del tumor.', ja: '数か月の治療の後、医師は腫瘍の完全寛解を確認した。', trivia: 'ラテン語 remissio（送り返すこと、ゆるめること）から。英語の remission と同語根で、医学用語「寛解」と宗教用語「罪の赦免」の両方に使われる点も英語と共通している。' },
  'remitente': { es: 'El paquete llegó sin nombre de remitente, así que no sabíamos de quién era.', ja: '荷物は差出人の名前なしで届いたので、誰から来たのか分からなかった。', trivia: 'ラテン語 remittere（送り返す）の現在分詞形が名詞化したもの。英語では sender と言うが、remittent（断続的な）という同語根の英語形容詞が医学用語として残っている。' },
  'remitir': { es: 'Le pido que se remita al artículo tercero del contrato para más detalles.', ja: '詳細については契約書の第3条を参照してください。', trivia: 'ラテン語 remittere（送り返す、緩める）から。英語の remit（送金する、差し戻す）と同語根だが、スペイン語では「痛みが和らぐ」「参照させる」など意味の幅が広い。' },
  'remo': { es: 'Los remeros levantaron los remos al unísono antes de volver a sumergirlos en el agua.', ja: '漕ぎ手たちは一斉にオールを持ち上げ、また水に沈めた。', trivia: 'ラテン語 remus（オール）から直接来ており、英語の oar とは語根が異なる。ただし英語の rowlock（オール受け）の row はゲルマン語系で、ラテン語 remus との語源は別系統とされる。' },
  'remoción': { es: 'La remoción del director fue anunciada por la junta directiva en una reunión de emergencia.', ja: '取締役会は緊急会議で役員の解任を発表した。', trivia: 'ラテン語 remotio（取り除くこと）から。英語の removal と同義で、南米スペイン語では「公職からの解任」という意味で特によく使われる法律・行政用語。' },
  'remojo': { es: 'Deja las lentejas en remojo toda la noche para que se ablanden más rápido.', ja: 'レンズ豆を一晩水に浸けておくと、早く柔らかくなる。', trivia: '動詞 remojar（水に浸す）の名詞形で、remojar 自体はラテン語 mollire（柔らかくする）由来の mojar に接頭辞 re- が付いたもの。英語には soaking という別語根の表現が使われる。' },
  'remolacha': { es: 'La sopa de remolacha, o borscht, es un plato tradicional de Europa del Este.', ja: 'ビーツのスープ、すなわちボルシチは東ヨーロッパの伝統料理だ。', trivia: '語源は諸説あり、アラビア語起源説とラテン語 beta（ビーツ）＋ラッパの意の lacha（異説）の合成説などがある。英語の beetroot とは全く異なる語根で、スペイン語独特の形。' },
  'remolcador': { es: 'El remolcador guió lentamente al buque carguero hasta el puerto.', ja: 'タグボートはゆっくりと貨物船を港へ誘導した。', trivia: '動詞 remolcar（牽引する）から派生した名詞で、remolcar はおそらくゲルマン語起源（古フランク語 mulon や古ノルド語 múla）に関連するとされる。英語の tugboat の tug もゲルマン系で語義は近い。' },
  'remolcar': { es: 'Tuvieron que remolcar el coche averiado hasta el taller más cercano.', ja: '故障した車を最寄りの修理店まで牽引しなければならなかった。', trivia: '語源はゲルマン語系とされ、古フランク語や古ノルド語に関連する可能性が指摘されている。英語の tow（牽引する）とは語根が異なるが、同義。英語 remorse（後悔）の morse- とは無関係。' },
  'remolinar': { es: 'Las hojas secas comenzaron a remolinar con una ráfaga repentina de viento.', ja: '一陣の突風で枯れ葉が渦を巻き始めた。', trivia: '名詞 remolino（渦巻き）から派生した動詞。remolino はラテン語 mola（臼、回転するもの）に由来すると考えられ、英語の mill（製粉所）や maelstrom の mael- と語根が共通する可能性がある。' },
  'remolino': { es: 'El niño tiene un remolino en la parte de atrás de la cabeza que es difícil de peinar.', ja: 'その子は後頭部につむじがあって、髪をとかすのが大変だ。', trivia: 'ラテン語 mola（臼、回転するもの）に接頭辞 re- と指小辞 -ino が加わった形。英語の whirlpool の whirl はゲルマン語系で別語根だが、「回転する」という概念は共通。英語 molar（臼歯）と同語根。' },
  'remolón': { es: 'No seas remolón y levántate de una vez; ya son las once de la mañana.', ja: 'ぐずぐずしないでいい加減に起きなさい、もう朝の11時よ。', trivia: '語源は不明確だが、remolar（だらだらする）という古い動詞との関連が示唆されており、一説にはラテン語 moles（重荷、鈍重さ）との関係も指摘される。英語に直接の同語根語はなく、sluggard や lazybones に相当する。' },
  'remolonear': { es: 'Siempre remolonea antes de hacer los deberes y acaba haciéndolos a última hora.', ja: '彼はいつも宿題をやる前にぐずぐずして、結局ギリギリになってやることになる。', trivia: '形容詞・名詞の remolón から派生した動詞で、-ear 語尾は反復・習慣的行為を表す。英語の dawdle や procrastinate に意味的に相当するが、より口語的・日常的なニュアンスがある。' },
  'remolque': { es: 'El camión llegó con un remolque cargado de naranjas de Valencia.', ja: 'そのトラックはバレンシア産のオレンジを積んだトレーラーを引いてやって来た。', trivia: '動詞 remolcar（牽引する）の名詞形。英語の trailer や tow に相当し、a remolque（引っ張られて、受け身に）という慣用句でも使われる。英語の remorse とは語根が全く異なる。' },
  'remorder': { es: 'Le remordía la conciencia por no haber dicho la verdad cuando tuvo la oportunidad.', ja: '機会があったときに真実を言わなかったことで、良心が痛んだ。', trivia: 'ラテン語 remordere（再び噛む、苛む）から。英語の remorse（良心の呵責）はこの動詞の名詞形 remorsus から来ており、英語話者には remorse の動詞版として分かりやすい。' },
  'remordimiento': { es: 'Sentía un profundo remordimiento por haber tratado tan mal a sus amigos.', ja: '友人たちをひどく扱ったことへの深い罪悪感を覚えた。', trivia: 'ラテン語 remordere（再び噛む）の名詞形。英語の remorse と完全に同語根で、どちらも「良心がかじる（噛む）」という比喩から生まれた表現。英語 remorse はラテン語 remorsus 経由で中英語に入った。' },
  'remota': { es: 'Existe una posibilidad remota de que el proyecto sea aprobado antes del fin de año.', ja: '年内にそのプロジェクトが承認される可能性は極めて低い。', trivia: 'ラテン語 remotus（遠ざけられた）から。英語の remote と完全に同語根の同形コグネートで、現代では「リモートワーク」のような新しい意味でも両言語でほぼ同様に使われる。' },
  'remotamente': { es: 'No se parece ni remotamente a su hermano, ni en el físico ni en el carácter.', ja: '外見も性格も、兄弟とは微塵も似ていない。', trivia: '形容詞 remoto にラテン語由来の副詞語尾 -mente（英語の -ly に相当）が付いた形。英語の remotely と完全に対応し、否定文での「全く〜ない」という強調用法も両言語で共通している。' },
  'remoto': { es: 'Mi abuelo vivía en un pueblo remoto de la sierra donde apenas llegaba la señal de televisión.', ja: '祖父はテレビの電波もほとんど届かない山奥の辺鄙な村に住んでいた。', trivia: 'ラテン語 remotus から。英語の remote と完全な同語根コグネートで、形・意味ともに非常に近い。中南米口語で「リモコン」の意味でも使われる点は英語の remote（リモコン）の用法と平行している。' },
  'remover': { es: 'Remueve bien la salsa para que no se pegue al fondo de la olla.', ja: 'ソースが鍋底につかないように、よくかき混ぜてください。', trivia: 'ラテン語 removere（動かす）から。英語の remove と同語根の「偽友（フォルス・フレンド）」で、英語では「取り除く」が主な意味だが、スペイン語では「かき混ぜる」「攪拌する」が日常的な第一義となっている。' },
  'removimiento': { es: 'El removimiento constante del cemento es necesario para lograr una mezcla homogénea.', ja: '均質な混合物を得るためには、セメントを絶えずかき混ぜることが必要だ。', trivia: '動詞 remover（かき混ぜる）の名詞形で、同義の remoción より技術・工学的文脈で使われることが多い。英語の stirring や agitation に相当し、英語の removal（除去）とは意味がずれた偽友関係にある。' },
  'rempujar': { es: 'La multitud empezó a rempujar para llegar antes a la entrada del estadio.', ja: '群衆はスタジアムの入り口に先に到達しようと押し合いを始めた。', trivia: '接頭辞 re-（再び、強調）＋ empujar（押す）の合成。empujar 自体はラテン語 impulsare から来ており、英語の impulse や push と語源的に関連する。rempujar は押す動作の激しさや繰り返しを強調した口語的表現。' },
  'rempujo': { es: 'Con un rempujo brusco consiguió abrir la puerta atascada.', ja: '乱暴にひと押しして、詰まったドアをこじ開けた。', trivia: '動詞 rempujar（強く押す）の名詞形。建築用語では「アーチの推力」という専門的な意味も持つ。英語の shove や thrust に相当し、英語の impulsion と同語根（ラテン語 impulsus）の遠縁にあたる。' },
  'remuda': { es: 'El vaquero llevaba siempre una remuda de caballos frescos para las largas jornadas.', ja: 'カウボーイは長い一日の仕事に備えて、いつも替え馬を連れていた。', trivia: '動詞 mudar（変える、脱皮する）に接頭辞 re- が付いた remudar の名詞形で、mudar はラテン語 mutare（変える）から。英語の mutation や mutual と同語根であり、英語の cowboy用語 remuda（替え馬の群れ）はスペイン語からの借用語として今も西部劇などで使われる。' },
  'remudar': { es: 'Los pastores remudan el ganado entre los distintos pastos para que la tierra descanse.', ja: '羊飼いたちは土地を休ませるために、家畜を異なる牧草地の間で交代させる。', trivia: 'ラテン語の「mutare（変える）」に接頭辞「re-（再び）」が付いた語で、英語の「mutate」「commute」「permute」と同語根。英語では家畜の交代に特化した動詞はなく「rotate」や「change」で表現する。' },
  'remugada': { es: 'La remugada de los rumiantes es esencial para su digestión.', ja: '反芻動物の反芻は、その消化に不可欠である。', trivia: 'ラテン語「rumigare（反芻する）」に由来し、英語の「ruminate」と同語根。英語の「ruminate」は「深く考える」という比喩的な意味でも広く使われるが、スペイン語のこの語はほぼ廃語に近い専門・古語的表現。' },
  'remuneración': { es: 'La remuneración de los empleados debe ser justa y proporcional al trabajo realizado.', ja: '従業員への報酬は、行われた仕事に対して公正かつ比例したものでなければならない。', trivia: 'ラテン語「remuneratio」に由来し、「munus（贈り物・義務）」が語根。英語の「remuneration」と完全な同語根の借用語で、フォーマルな文書や労働法の文脈で両言語ともに用いられる。' },
  'remunerada': { es: 'Busca una actividad remunerada que también le permita disfrutar de lo que hace.', ja: '報酬をもらいながら、自分のやることを楽しめる仕事を探している。', trivia: '「remunerar」の過去分詞から派生した形容詞で、英語の「remunerated」「paid」に対応する。特に「actividad remunerada（有給の活動）」と「actividad voluntaria（ボランティア活動）」の対比でよく使われる。' },
  'remunerar': { es: 'La empresa decidió remunerar a sus trabajadores con bonificaciones por los resultados obtenidos.', ja: '会社は、達成した業績に対してボーナスで従業員に報いることを決めた。', trivia: 'ラテン語「remunerare」に由来し、「re-（再び）＋munerare（贈り物をする）」の構造。英語の「remunerate」と同語根の国際語で、経済・労働の文脈でスペイン語圏のビジネス文書に頻出する。' },
  'remuneratoria': { es: 'Se estableció una cláusula remuneratoria en el contrato para garantizar compensaciones adicionales.', ja: '追加補償を保証するために、契約書に報酬条項が設けられた。', trivia: 'ラテン語「remuneratorius」に由来する法律・経済用語で、英語の「remunerative」に相当する。英語では「remunerative work（実入りのいい仕事）」のように日常でも使われるが、スペイン語のこの形は主に法的・契約文書で見られる。' },
  'remuneratorio': { es: 'El pacto remuneratorio fue revisado por los asesores legales antes de la firma.', ja: '報酬に関する協定は、署名前に法律顧問によって見直された。', trivia: '「remuneratoria」の男性形で、英語の「remunerative」に対応する法律用語。英語では形容詞の性変化がないため、男女形の区別はスペイン語特有の特徴といえる。' },
  'renacer': { es: 'Con la llegada de la primavera, la naturaleza renace llena de color y vida.', ja: '春の到来とともに、自然は色と生命に満ちて再生する。', trivia: 'ラテン語「renasci（再び生まれる）」に由来し、「re-（再び）＋nasci（生まれる）」の構造。英語の「renaissance（ルネサンス）」と同語根で、イタリア語経由でフランス語に入り英語に借用された。英語では「be reborn」「revive」と動詞句で表現することが多い。' },
  'renacimiento': { es: 'El Renacimiento fue un período de extraordinario florecimiento artístico e intelectual en Europa.', ja: 'ルネサンスは、ヨーロッパにおける芸術的・知的な驚異的開花の時代であった。', trivia: '「renacer（再生する）」の名詞形で、ラテン語「renascimentum」に由来する。英語の「Renaissance」はフランス語経由のイタリア語「Rinascimento」の借用語であり、スペイン語「renacimiento」と同じ語根を持つ文化史上の重要語。' },
  'renacuajo': { es: 'Los niños se agacharon junto al estanque para observar los renacuajos que nadaban entre las algas.', ja: '子供たちは池のそばにしゃがんで、藻の間を泳ぐオタマジャクシを観察した。', trivia: '語源には諸説あるが、「renacer（再生する）」や「rana（カエル）」との関連が指摘されることがある。英語の「tadpole」はゲルマン語系で「toad（ヒキガエル）＋poll（頭）」に由来し、スペイン語とは語源が全く異なる。' },
  'renal': { es: 'El médico le recomendó una dieta especial para proteger su función renal.', ja: '医師は腎臓の機能を守るために特別な食事療法を勧めた。', trivia: 'ラテン語「renalis」（renes＝腎臓）に由来し、英語の「renal」と完全に同語根の医学用語。英語では日常では「kidney（腎臓の）」と言い、「renal」はより専門的・学術的な文脈で使われる点がスペイン語との違い。' },
  'renca': { es: 'Desde el accidente, camina renca y necesita apoyo para subir escaleras.', ja: '事故以来、彼女は足を引きずって歩き、階段を上るのに助けが必要だ。', trivia: '語源は不明瞭で、ラテン語「reinicare」や「hircinius」などの説があるが定説はない。英語の「lame」に相当するが、英語の「lame」はゲルマン語系（古英語「lama」）で語根が異なる。現代英語では「lame」を人に使うのは差別的とされ「mobility-impaired」などが好まれる。' },
  'renco': { es: 'El caballo renco fue retirado de la competencia por precaución.', ja: '足を引きずっていた馬は安全のために競技から退場させられた。', trivia: '「renca」の男性形で、語源は諸説あり不明な点が多い。英語の「lame」（古英語「lama」由来のゲルマン語系）に意味は対応するが語根は異なる。動物（特に馬）の跛行を指す際に今でも使われる実用的な語。' },
  'rencor': { es: 'Después de la discusión, guardó rencor durante meses sin querer hablar con su hermano.', ja: '口論の後、彼は数ヶ月間も恨みを抱き、兄と話そうとしなかった。', trivia: 'ラテン語「rancor（腐敗・腐臭）」に由来し、英語の「rancor（怨恨）」と同語根の直接借用語。英語の「rancor」は主に文語・文学的で、日常では「grudge」「resentment」が一般的。スペイン語の「rencor」は日常会話でも広く使われる。' },
  'rencorosa': { es: 'Es una persona muy rencorosa que nunca olvida las ofensas que le han hecho.', ja: '彼女は非常に根に持つ性格で、受けた侮辱を決して忘れない。', trivia: '「rencor（恨み）」に形容詞語尾「-oso/a」が付いた語で、英語の「rancorous」「resentful」に相当する。英語の「rancorous」は文語的だが、スペイン語の「rencoroso/a」は日常の人物描写でよく使われる実用的な形容詞。' },
  'rencoroso': { es: 'No seas tan rencoroso; todos cometemos errores y debemos aprender a perdonar.', ja: 'そんなに根に持つな。誰でも間違いを犯すし、許すことを学ばなければならない。', trivia: '「rencorosa」の男性形で、「rencor（ラテン語rancor由来）＋接尾辞-oso」の構造。英語「rancorous」と同語根だが、英語では「resentful」「unforgiving」「vindictive」のほうが口語的によく使われる。' },
  'rendición': { es: 'La rendición del ejército enemigo puso fin a meses de conflicto en la región.', ja: '敵軍の降伏により、その地域で数ヶ月続いた紛争に終止符が打たれた。', trivia: '「rendir（降伏する・生み出す）」の名詞形で、ラテン語「reddere（返す・与える）」に由来する。英語の「surrender」はフランス語経由（「sur-＋rendre」）でスペイン語「rendir」と同語根であり、遠い親戚関係にある。' },
  'rendida': { es: 'Llegó a casa rendida después de trabajar doce horas seguidas sin descanso.', ja: '12時間ぶっ通しで働いた後、彼女はクタクタになって家に帰り着いた。', trivia: '「rendir」の過去分詞から派生した形容詞で、ラテン語「reddere」に由来する。英語では「exhausted」「worn out」に相当するが、英語の「rendered（描写された・提出された）」も同語根で意味が大きく異なる好例のコグネート。' },
  'rendidor': { es: 'Este aceite de oliva es muy rendidor; con poca cantidad se puede cocinar bastante.', ja: 'このオリーブオイルは非常にコスパが高く、少量でかなりの料理ができる。', trivia: '「rendir（生み出す・効率よく機能する）」に由来し、中南米スペイン語で特によく使われる実用的な形容詞。英語の「yield」と語根を共有し（ラテン語「reddere」経由）、「good yield」「cost-effective」「economical」に相当するが、英語に直接対応する一語はない。' },
  'rendimiento': { es: 'El rendimiento del equipo mejoró notablemente tras la incorporación del nuevo entrenador.', ja: '新しいコーチが加入した後、チームのパフォーマンスは著しく向上した。', trivia: '「rendir」の名詞形で、ラテン語「reddere（返す）」に由来する。英語の「yield」（農作物の収量・投資の利回り）と意味が重なり、金融文脈では「rendimiento de la inversión」が英語の「return on investment（ROI）」に相当する。' },
  'rendir': { es: 'Este estudiante rinde muy bien bajo presión; sus exámenes siempre son excelentes.', ja: 'この学生はプレッシャーのもとで非常によいパフォーマンスを発揮する。試験はいつも優秀だ。', trivia: 'ラテン語「reddere（返す・与える）」に由来し、英語の「render」と同語根。ただし英語の「render」は「描写する・提供する」の意味が中心で、スペイン語の「降伏する・効率よく産出する」という意味とは大きく乖離した好例の偽友語（faux amis）。' },
  'renegada': { es: 'La comunidad la consideraba una renegada por haber abandonado las tradiciones familiares.', ja: '彼女は家族の伝統を捨てたため、コミュニティから裏切り者と見なされていた。', trivia: '「renegar（信念を捨てる）」の過去分詞から派生した名詞・形容詞で、ラテン語「renegare（否定する）」に由来する。英語の「renegade」はスペイン語「renegado」からの借用語で、16世紀に「キリスト教からイスラム教に改宗した者」を指す語として英語に入った歴史を持つ。' },
  'renegar': { es: 'Nunca renegaría de sus raíces culturales aunque viva en otro país desde hace años.', ja: '何年も他の国に住んでいても、自分の文化的ルーツを決して捨てない。', trivia: 'ラテン語「renegare（完全に否定する）」に由来し、英語の「renege」と同語根。英語の「renege」は主に「約束を破る」という意味で使われるが、スペイン語の「renegar」は「信念・出身を捨てる」や「文句を言う」まで意味が広く、両語の意味範囲は異なる。' },
  'renglón': { es: 'Escribe tu nombre en el primer renglón del formulario y tu dirección en el segundo.', ja: 'フォームの最初の行に名前を、2行目に住所を書いてください。', trivia: '語源には諸説あり、ラテン語「regula（線・規則）」からの派生説や、アラビア語起源説もあるが確定していない。英語の「line」（古フランス語「ligne」・ラテン語「linea」由来）に相当するが、「renglón」は特に紙面の罫線・行という意味合いが強く、商業用語としての「品目」の意味もある点が英語と異なる。' },
  'rengo': { es: 'El perro llegó rengo al refugio, pero después de tratarlo, pudo caminar sin problemas.', ja: 'その犬は足を引きずってシェルターに来たが、治療後は問題なく歩けるようになった。', trivia: 'アルゼンチンやチリなど南米のスペイン語で「renco」と同義語として広く使われ、語源は「renco」と同じく諸説あり不明な点が多い。英語の「lame」（古英語「lama」由来のゲルマン語系）に相当するが全く語根が異なり、また英語では人に対して「lame」を使うことが差別的と見なされるため「disabled」や「has a limp」などが好まれる。' },
  'reniego': { es: 'Cada vez que algo le sale mal, reniego de mi mala suerte en voz alta.', ja: '何かうまくいかないたびに、私は大声で自分の不運を嘆く。', trivia: '動詞 renegar はラテン語 renegare（強く否定する）に由来し、接頭辞 re-（強調）＋ negare（否定する）から成る。英語の renegade（背教者・裏切り者）は同語根で、もとはスペイン語 renegado を経由して英語に入った。' },
  'reno': { es: 'El reno es el animal más asociado con la Navidad en los países del norte.', ja: 'トナカイは北国のクリスマスと最も結びつけられる動物だ。', trivia: 'スペイン語 reno はフランス語 renne を経由し、古フランク語 *hrein（トナカイ）に由来するゲルマン系の語。英語 reindeer の deer（鹿）はゲルマン語 *deuzaz に遡り、語頭の rein- も同じゲルマン語根 *hrainaz から来ている。' },
  'renombrada': { es: 'Alicia es una chef renombrada que ha ganado varios premios internacionales.', ja: 'アリシアは国際的な賞をいくつも受賞した名高いシェフだ。', trivia: 'renombrado は re-（再び）＋ nombre（名前、ラテン語 nomen）の合成語で、「何度も名前を呼ばれる＝有名な」という意味合いを持つ。英語の renowned も古フランス語 renomé（re- ＋ nom「名前」）が源で、ラテン語 nomen を共有する同語根語。' },
  'renombre': { es: 'Este restaurante ha alcanzado renombre internacional gracias a su cocina de vanguardia.', ja: 'このレストランは革新的な料理のおかげで国際的な名声を得た。', trivia: 'renombre は接頭辞 re-（強調）＋ nombre（名前、ラテン語 nomen）から成り、「名前が広く知られた状態」を指す。英語の renown は古フランス語 renon（名声）から来ており、ラテン語 nomen を共通の祖先として持つ同語根語。' },
  'renovación': { es: 'La renovación del pasaporte puede hacerse en línea sin necesidad de acudir a la embajada.', ja: 'パスポートの更新は大使館に行かずにオンラインでできる。', trivia: 'ラテン語 renovatio（renovo の名詞形、re-「再び」＋ novus「新しい」）が語源。英語の renovation と renewal はどちらも同じラテン語根に由来し、renovation はスペイン語形に近い借用語、renewal はゲルマン系の new と接頭辞 re- を組み合わせた並行語。' },
  'renovada': { es: 'Salió de las vacaciones con energía renovada y listo para enfrentar nuevos desafíos.', ja: '彼は休暇から新鮮なエネルギーを持って帰り、新たな挑戦に臨む気満々だった。', trivia: 'renovado はラテン語 renovare（re-「再び」＋ novare「新しくする」、novus「新しい」が語根）の過去分詞。英語の renewed も同一の接頭辞 re- と古英語/ラテン語系 new を組み合わせており、構造が鏡のように対応している。' },
  'renovar': { es: 'Decidimos renovar el contrato de alquiler por otros dos años.', ja: '私たちは賃貸契約をさらに2年間延長することにした。', trivia: 'ラテン語 renovare（re-「再び」＋ novare「新しくする」、形容詞 novus「新しい」が語根）が直接の語源。英語の renew と renovate は両方ともこのラテン語根を持つが、renovate はラテン語形をほぼそのまま借用した学術語で、renew はフランス語経由の古形。' },
  'renta': { es: 'El gobierno introdujo nuevas medidas para gravar las rentas más altas.', ja: '政府は高所得者に課税するための新たな措置を導入した。', trivia: 'ラテン語 reddita（「返されたもの」、reddo の女性形過去分詞）に由来し、「定期的に戻ってくる収入」が原義。英語の rent も同じラテン語源から古フランス語 rente を経て借用されたもので、スペイン語 renta と英語 rent は正真正銘のコグネート。' },
  'rentabilidad': { es: 'Los inversores analizan la rentabilidad de cada proyecto antes de comprometer su capital.', ja: '投資家は資本を投じる前に各プロジェクトの収益性を分析する。', trivia: 'renta（収入）＋接尾辞 -bilidad（能力・性質を表すラテン語 -bilis 由来）から成る。英語に直訳すると rentability となるが、通常は profitability または rate of return が使われる。英語の rent と profit はどちらもラテン語 re-（返す）系語根に関係する。' },
  'rentable': { es: 'Invertir en energía solar se ha vuelto cada vez más rentable en los últimos años.', ja: '太陽エネルギーへの投資はここ数年でますます採算が取れるようになってきた。', trivia: 'renta＋接尾辞 -able（ラテン語 -abilis）から成り、「収入をもたらすことができる」が原義。英語の profitable の pro- は「前に」というラテン語接頭辞で構造は異なるが、rentable の直訳語 rentable は英語でも金融文書で稀に使われる。' },
  'rentar': { es: 'En México es muy común rentar un coche en el aeropuerto para moverse con libertad.', ja: 'メキシコでは空港で車を借りて自由に移動することがとても一般的だ。', trivia: 'renta（収入・賃貸）から派生した動詞で、スペインでは「利益をもたらす」の意が主だが、中南米では英語の rent（賃貸する）の影響を受けて「借りる・貸す」の意でも広く使われる。英語 rent との意味的収束が興味深い。' },
  'renuncio': { es: 'En el partido de cartas, el árbitro detectó un renuncio que invalidó la jugada.', ja: 'カードゲームの試合で、審判がルール違反を検出し、その手が無効となった。', trivia: '名詞 renuncio はトランプ用語で「出せるカードを出さなかった違反」を指し、動詞 renunciar（ラテン語 renuntiare、re-「再び」＋ nuntiare「報告する」＞「撤回する」）の活用形が名詞化したもの。英語の renounce（放棄する）は同じラテン語根の直接借用語。' },
  'renuncia': { es: 'El ministro presentó su renuncia tras el escándalo de corrupción.', ja: '大臣は汚職スキャンダルを受けて辞表を提出した。', trivia: 'ラテン語 renuntiatio（re-「撤回」＋ nuntiare「告げる」）に由来し、「正式に告知して退く」が原義。英語の renunciation はほぼ同形の直接借用語で、resignation（re-「再び」＋ signare「署名する」＞「署名して退く」）とは語根が異なる。' },
  'renunciar': { es: 'Renunció a su cargo sin previo aviso, dejando a todos sorprendidos.', ja: '彼は予告なく職を辞し、全員を驚かせた。', trivia: 'ラテン語 renuntiare（re-「撤回」＋ nuntiare「知らせる」、nuntius「使者」が語根）が語源。英語の renounce（放棄する）は古フランス語 renoncer を介した同語根の借用語。announce（告知する）も同じ nuntius に遡り、接頭辞だけが異なる。' },
  'reñida': { es: 'La final fue tan reñida que el resultado no se decidió hasta el último segundo.', ja: '決勝はとても接戦で、結果は最後の1秒まで決まらなかった。', trivia: 'reñido は動詞 reñir（口論する・争う）の過去分詞で、ラテン語 rignere / ringere（歯をむく・唸る）に由来するとされるが、語源には諸説ある。英語には対応する同語根語がなく、hard-fought や fiercely contested のように迂言的に表現する。' },
  'reñir': { es: 'La profesora riñó a los alumnos por llegar tarde a clase.', ja: '先生は授業に遅刻した生徒たちを叱った。', trivia: '語源については諸説あり、ラテン語 rignere（牙をむく）またはゲルマン語系との接触から生まれた可能性が指摘されている。英語に同語根の語はなく、scold（叱る）や quarrel（口論する）で代替される。語幹が e-ie に変化するという特殊な不規則動詞でもある。' },
  'reo': { es: 'El reo fue declarado culpable por unanimidad por el jurado.', ja: '被告人は陪審員の全員一致で有罪と宣告された。', trivia: 'ラテン語 reus（訴訟の当事者、特に被告）に由来し、古代ローマ法の用語がそのままスペイン語に受け継がれた。英語には reus という形で法律ラテン語として残っており、mens rea（犯意、「有罪の心」）という表現に同じ語根が生きている。' },
  'reojo': { es: 'Miraba de reojo al chico sentado a su lado, sin que él se diera cuenta.', ja: '彼女は気づかれないように、隣に座った男の子をちらちらと横目で見ていた。', trivia: 'reojo は de reojo（横目で）という副詞句の形でのみ使われる名詞で、ojo（目、ラテン語 oculus）に接頭辞 re-（強調または逆方向）を付けた形と考えられる。英語の oculist（眼科医）や monocle も同じラテン語 oculus に遡る同語根語。' },
  'reorganización': { es: 'La reorganización interna de la empresa tardó más de un año en completarse.', ja: '会社の内部再編成は完了するまでに1年以上かかった。', trivia: 're-（再び）＋ organización（組織化）から成り、organización はギリシャ語 organon（道具・器官）に由来する。英語の reorganization はスペイン語と同形の平行借用語で、organ（器官）・organic（有機的な）・organize（組織する）もすべて同語根。' },
  'reorganizar': { es: 'Decidieron reorganizar el departamento para mejorar la eficiencia del equipo.', ja: 'チームの効率を上げるために部署を再編成することにした。', trivia: 're-（再び）＋ organizar（組織する、ギリシャ語 organon 由来）から成る。英語の reorganize とまったく同じ構造を持つ平行語で、スペイン語では -ize が -izar になるという規則的な対応がある。organize / organizar の対応はスペイン語学習者にとって典型的なコグネートペア。' },
  'reorientación': { es: 'La empresa anunció una reorientación estratégica hacia los mercados asiáticos.', ja: '同社はアジア市場に向けた戦略的な方向転換を発表した。', trivia: 're-（再び）＋ orientación（方向付け）から成り、orientación はラテン語 oriens（東、太陽の昇る方向）に由来する。英語の reorientation と同形・同構造の平行語で、orient（東方・方向を定める）・orientation（方向付け）も同語根。' },
  'reorientar': { es: 'Tuvo que reorientar su carrera profesional después de que cerrara la empresa.', ja: '会社が閉鎖された後、彼はキャリアの方向を転換しなければならなかった。', trivia: 're-（再び）＋ orientar（方向付ける、ラテン語 oriens「東・日の出る方向」由来）から成る。英語の reorient と同一構造の平行語。orient は本来「東」を意味し、地図や建物の「方向を合わせる」原義から「(人を)方向付ける」へと意味が広がった。' },
  'repagar': { es: 'El plazo para repagar el préstamo estudiantil es de diez años.', ja: '学生ローンを返済する期間は10年だ。', trivia: 're-（再び・返して）＋ pagar（払う、ラテン語 pacare「宥める・負債を解消する」由来）から成る。英語の repay はフランス語 repayer を経由した同語根語で、ラテン語 pax（平和・和解）に最終的に遡り、pay・peace・appease もすべて関連語。' },
  'repago': { es: 'El banco ofrece distintas opciones de repago adaptadas a la situación de cada cliente.', ja: '銀行は各顧客の状況に合わせたさまざまな返済オプションを提供している。', trivia: 'repagar から派生した名詞で、ラテン語 pacare（宥める・支払う、pax「平和」が語根）に re- を加えた構造。英語の repayment と意味・構造ともに対応するが、repago はやや金融・法律的な書き言葉で好まれる。pay・payment・repayment はすべて同語根。' },
  'repantigarse': { es: 'Después del trabajo, me repantigo en el sofá y no me muevo en toda la tarde.', ja: '仕事の後、私はソファに踏んぞり返り、午後中ぴくりとも動かない。', trivia: '語源については定説がなく、諸説ある。panza（腹、ラテン語 pantex）と関連する可能性が指摘されており、「腹を突き出してくつろぐ」というイメージが原義かもしれない。英語の sprawl や lounge に相当するが、repantigarse には「だらしなく大げさにくつろぐ」というニュアンスがより強く込められている。' },
  'repara': { es: 'Él repara el motor mientras yo reparo el sistema eléctrico.', ja: '彼がエンジンを修理する間、私は電気系統を直す。', trivia: 'ラテン語 reparare（再び準備する）に由来し、re-（再び）＋ parare（準備する）の構成。英語の repair も同じラテン語源を共有しており、スペイン語と英語でほぼ同形の語根コグネート（同語根語）となっている。' },
  'reparable': { es: 'Por suerte, el daño al coche es reparable y no costará demasiado.', ja: '幸い、車の損傷は修理可能で、費用もそれほどかからないだろう。', trivia: 'ラテン語 reparabilis（元に戻せる）に由来。英語の repairable と同語根だが、スペイン語では -able という一語で完結するのに対し、英語では -able と -ible の両形（repairable / reparable）が混在して使われる点が興味深い。' },
  'reparación': { es: 'La empresa ofreció una reparación económica a las víctimas del accidente.', ja: 'その会社は事故の被害者たちに経済的な補償を申し出た。', trivia: 'ラテン語 reparatio（修復、回復）に由来。英語には repair（修理）と reparation（賠償）という二語が存在し、日常の修繕には repair、戦後賠償などの国際政治文脈では reparations（複数形）が用いられる。スペイン語では reparación 一語で両方の意味をカバーする。' },
  'reparada': { es: 'La tubería reparada funciona bien desde hace tres semanas.', ja: '修理されたパイプは3週間前からうまく機能している。', trivia: 'reparar の過去分詞女性形。英語の repaired と直接対応するコグネートで、語形も非常に近い。スペイン語では過去分詞が形容詞として用いられる際に名詞の性・数に合わせて語尾変化する点が英語と異なる。' },
  'reparador': { es: 'Después del largo viaje, disfrutamos de un sueño reparador en el hotel.', ja: '長旅の後、ホテルで心身を回復させる眠りを堪能した。', trivia: 'ラテン語 reparator（修復する者）に由来。英語の restorative（回復力のある）や refreshing（爽快な）に相当するが、英語に reparador に対応する一語のコグネートは存在せず、文脈によって複数の訳語を使い分ける必要がある。' },
  'reparar': { es: 'Nadie reparó en el pequeño error hasta que fue demasiado tarde.', ja: '手遅れになるまで、誰もその小さなミスに気づかなかった。', trivia: 'ラテン語 reparare（再備える）に由来し、英語の repair と同語源。ただしスペイン語の reparar は「気づく」という意味でも頻用される（reparar en～）のに対し、英語の repair にその用法はなく、意味の広がり方が異なる好例のコグネートである。' },
  'reparo': { es: 'No tengo ningún reparo en decirte la verdad, por incómoda que sea.', ja: 'どれほど不快であっても、あなたに真実を告げることにためらいはない。', trivia: 'reparar の名詞形で、ラテン語 reparare に由来。英語の qualm（良心の呵責、ためらい）や objection（異議）に意味が近い。英語の repair が「修理」の意味に特化したのに対し、スペイン語の reparo は「ためらい・異議」という抽象的な意味を強く発展させた点が興味深い。' },
  'repartición': { es: 'La repartición de los recursos entre las distintas regiones fue motivo de debate.', ja: '各地域への資源の配分が議論の的となった。', trivia: 'ラテン語 repartitio（分割）に由来し、re-（再び）＋ partire（分ける）の構成。英語の distribution や partition と同語根であり、partition（分割・仕切り）は特にこの語と意味が近い。中南米では行政の「部局・部署」を指す用法がスペイン本国より一般的。' },
  'repartida': { es: 'La tarea quedó bien repartida entre todos los miembros del equipo.', ja: '仕事はチームの全員にうまく分配された。', trivia: 'repartir の過去分詞女性形。ラテン語 partire（分ける）に由来し、英語の distributed や divided と意味的に対応する。英語の part（部分）や partition（分割）も同語根であり、スペイン語・英語ともに「分ける」という共通の語根概念を持つ。' },
  'repartidor': { es: 'El repartidor llegó tarde porque había mucho tráfico en el centro.', ja: '市内が渋滞していたため、配達員は遅れて到着した。', trivia: 'ラテン語 partire（分ける）＋接尾辞 -dor（行為者）に由来。英語では delivery person や distributor に相当し、共通の語根に由来する英語の distribute（分配する）とは同語源。フードデリバリーの普及でスペイン語圏でもこの語の使用頻度が急増している。' },
  'repartimiento': { es: 'El repartimiento colonial fue un sistema que obligaba a los indígenas a trabajar para los españoles.', ja: '植民地時代のレパルティミエントは先住民にスペイン人のために労働を強制する制度だった。', trivia: 'ラテン語 partire（分ける）に由来し、英語の allotment（割り当て）や distribution に相当。歴史用語としてはスペイン植民地体制下の強制労働制度を指す固有名詞的な用法が国際的に知られており、英語の歴史書でも repartimiento とスペイン語のまま使われることが多い。' },
  'repartir': { es: 'La maestra repartió las hojas de examen entre los alumnos sin hacer ruido.', ja: '先生は音を立てずに生徒たちに試験用紙を配った。', trivia: 'ラテン語 repartire（再び分ける）に由来し、re-（再び）＋ partire（分ける）の構成。英語の distribute、deliver、share はいずれも別語源だが、part（部分）という語根は英語と共有しており、スペイン語の partir（出発する・切る）とも関連する多義的な語族を形成している。' },
  'reparto': { es: 'El reparto de la película contaba con actores de tres países diferentes.', ja: 'その映画のキャストは3か国の俳優たちで構成されていた。', trivia: 'repartir の名詞形で、ラテン語 partire（分ける）に由来。英語では「配達」の意味には delivery、「キャスト」の意味には cast を使い分けるが、スペイン語の reparto は両方を一語でカバーする。英語の cast もラテン語由来だが語根が異なり（castar＜古ノルド語 kasta）、同義の非コグネート語である。' },
  'repasadura': { es: 'La repasadura final del barniz dejó la madera con un brillo perfecto.', ja: 'ニスの最終仕上げチェックにより、木材は完璧な光沢を持った。', trivia: 'repasar（見直す・磨き直す）の名詞形で、ラテン語 passare（通る）に由来する re-（再び）＋ pasar（通る・過ぎる）の構成。英語の pass と同語根であり、英語で言えば re-passing（再び通すこと）に近い概念。現代では職人の口語に残る古風な表現となっている。' },
  'repasar': { es: 'Deberías repasar tus apuntes antes del examen de mañana.', ja: '明日の試験の前にノートを復習すべきだよ。', trivia: 'ラテン語 passare（通る）に由来し、re-（再び）＋ pasar（通る）の構成で「再び通る＝見直す」という意味が生まれた。英語の review（re-＋view）と概念的に並行する造語法を持つが、語根自体は異なる。英語の pass（通る）は同語根のコグネートである。' },
  'repaso': { es: 'Hicimos un repaso rápido de los verbos irregulares antes de empezar la clase.', ja: '授業を始める前に不規則動詞を素早くおさらいした。', trivia: 'repasar の名詞形で、ラテン語 passare（通る）に由来。英語の review や revision に相当するが、スペイン語の repaso は口語で「手厳しい叱責・批判」という比喩的な意味にも使われる点が英語の review とは異なる用法上の広がりを持つ。' },
  'repechar': { es: 'Los ciclistas tuvieron que repechar una cuesta muy pronunciada en la etapa final.', ja: 'サイクリストたちは最終ステージで非常に急な坂を登らなければならなかった。', trivia: 'スペイン語の repecho（急坂）から派生した動詞で、re-＋ pecho（胸）の構成、つまり「胸で押し上げるように登る」というイメージに由来するとされる。英語に直接対応するコグネートはなく、英語では to climb a steep slope と表現するほかない。語源についてはpecho（ラテン語 pectus）との関係が有力視されている。' },
  'repecho': { es: 'Al final del camino había un repecho que nos dejó sin aliento.', ja: '道の終わりに急坂があって、私たちは息が上がってしまった。', trivia: 're-＋ pecho（胸・ラテン語 pectus）の構成で、「胸を使って踏ん張る坂」というイメージから「急坂」の意味が生まれたとされる。英語の pectoral（胸の）や expect（期待する＜ラテン語 ex-＋spectare だが pectus とは別）とは語源が異なり、英語には直接対応する一語のコグネートが存在しない。' },
  'repeler': { es: 'Este tejido especial repele el agua y mantiene la ropa seca.', ja: 'この特殊な生地は水を弾き、衣服を乾いた状態に保つ。', trivia: 'ラテン語 repellere（押し返す）に由来し、re-（反対）＋ pellere（打つ・押す）の構成。英語の repel は完全なコグネートで形も意味もほぼ同一。さらに英語の pulse（脈動）、propel（推進する）、compel（強制する）なども同じ pellere 語根を共有している。' },
  'repelente': { es: 'No olvides llevar repelente de mosquitos si vas a la selva.', ja: 'ジャングルに行くなら蚊除けスプレーを忘れずに持っていって。', trivia: 'ラテン語 repellens（押し返すもの）の現在分詞形に由来。英語の repellent と完全なコグネートで語形も意味（虫除け・嫌悪感を抱かせる）も一致する。口語では生意気な子どもを指して「repelente」と呼ぶ用法がスペイン語圏で広く使われる点が興味深い。' },
  'repellar': { es: 'Antes de pintar la fachada, hay que repellar las grietas de la pared.', ja: '外壁を塗装する前に、壁のひび割れにモルタルを塗らなければならない。', trivia: '語源は諸説あるが、pellar（皮を剥ぐ・スペイン語方言）またはアラビア語由来の説が指摘されている。英語の plaster（漆喰を塗る）に相当するが語根は異なり、直接のコグネートは存在しない。中南米の建設業界で特によく使われる実務的な動詞である。' },
  'repello': { es: 'El repello de las paredes exteriores protege el edificio de la humedad.', ja: '外壁のモルタル下塗りは建物を湿気から守る。', trivia: 'repellar の名詞形で、語源については諸説あり確定していない。英語の plastering（漆喰塗り）や render（壁の下地塗り）に相当するが、英語の repel とは語根が異なる可能性が高く、同綴りに見えても非コグネートである点に注意が必要。中南米（特に中米）での建築用語として定着している。' },
  'repentina': { es: 'La muerte repentina del director dejó a todo el equipo en estado de shock.', ja: '社長の突然の死はチーム全員をショック状態に陥れた。', trivia: 'ラテン語 repentinus（突然の）に由来し、re-＋ pente（突然に）の構成。英語の sudden は古英語 soden（急いで煮る）に由来し全く別語源だが、英語には repentant（後悔している）という語があり、こちらはスペイン語の repentir（後悔する）とは同語根でも repentino とは無関係という紛らわしい関係がある。' },
  'repentinamente': { es: 'Repentinamente, el cielo se oscureció y empezó a llover con fuerza.', ja: '突然、空が暗くなり激しい雨が降り始めた。', trivia: 'repentino（突然の）に副詞接尾辞 -mente（英語の -ly に相当）を付けた形で、ラテン語 repentinus に由来。英語の suddenly とは語根が全く異なるが機能的には完全に対応する。スペイン語では形容詞の女性形（repentina）に -mente を付けるという規則的な副詞形成法が英語の -ly 付加と並行構造をなしている。' },
  'repentino': { es: 'Un cambio repentino de temperatura puede ser peligroso para la salud.', ja: '突然の気温の変化は健康に危険をもたらすことがある。', trivia: 'ラテン語 repentinus（不意の、突然の）に由来。英語の abrupt（突然の）はラテン語 abruptus（断ち切られた）に由来し語根が異なる。スペイン語の repentir（後悔する）とは語根が異なるため「後悔」との意味的つながりはなく、英語話者が repentant（後悔している）と混同しやすい点に注意が必要。' },
  'repercusión': { es: 'Las medidas económicas del gobierno tuvieron una gran repercusión en los mercados internacionales.', ja: '政府の経済措置は国際市場に大きな影響を与えた。', trivia: 'ラテン語 repercussio（跳ね返り、反響）に由来し、re-（再び）+ percutere（打つ）の合成語。英語の repercussion と同語源で意味もほぼ同じ。「波及効果」という比喩的用法も両言語で共通する。' },
  'repercutir': { es: 'El aumento del precio del petróleo repercute directamente en el coste del transporte.', ja: '石油価格の上昇は輸送コストに直接影響を及ぼす。', trivia: 'ラテン語 repercutere（打ち返す）から来ており、re-（再び）+ percutere（打つ）の構成。英語には repercute という動詞形は現代英語ではほぼ使われず、代わりに have repercussions on や impact などで表現する点が興味深い。' },
  'repertorio': { es: 'La orquesta amplió su repertorio con obras de compositores latinoamericanos.', ja: 'そのオーケストラはラテンアメリカの作曲家の作品でレパートリーを広げた。', trivia: 'ラテン語 repertorium（発見物の一覧、目録）に由来し、reperire（再び見つける）から派生。英語の repertoire はフランス語経由で同じラテン語源を持つ。スペイン語 repertorio と英語 repertoire は同語根だが、綴りと発音が異なる典型的な借用語の例。' },
  'repesca': { es: 'Gracias a la repesca, varios estudiantes pudieron recuperar la asignatura en septiembre.', ja: '追試のおかげで、複数の学生が9月に科目を挽回することができた。', trivia: 'フランス語の repêchage（引き上げ、救済）に由来し、pêcher（釣る）から来ている。英語圏でもスポーツの敗者復活戦を指して repechage という語が使われ（特にボート競技や柔道で）、フランス語からの借用語として定着している。' },
  'repescar': { es: 'El entrenador decidió repescar a un jugador veterano para la semifinal.', ja: '監督は準決勝に向けてベテラン選手を復帰させることを決めた。', trivia: 're-（再び）+ pescar（釣る）の合成語で、「もう一度釣り上げる」という具体的なイメージから「救済・復活させる」という比喩的意味が生まれた。英語では fish out や bring back で表現し、この動詞に対応する単一の英単語は存在しない。' },
  'repeso': { es: 'El boxeador no superó el repeso y fue descalificado de la competición.', ja: 'そのボクサーは検量をパスできず、大会から失格となった。', trivia: 're-（再び）+ peso（重さ、計量）から成る合成語。英語では reweigh（動詞）または reweighing（名詞）に相当するが、スペイン語の repeso はボクシングや市場での「再計量・検量」という専門的文脈で特に定着している。' },
  'repetición': { es: 'La repetición constante de los ejercicios es clave para dominar un idioma.', ja: 'エクササイズを絶えず繰り返すことが言語を習得する鍵だ。', trivia: 'ラテン語 repetitio（繰り返し）に由来し、repetere（再び求める、繰り返す）から派生。英語の repetition と同語根で形も意味もほぼ同一の親戚語（コグネート）。修辞技法としての「反復法（anaphora）」も両言語で類似した概念として用いられる。' },
  'repetidamente': { es: 'Le he pedido repetidamente que llegue a tiempo, pero nunca me hace caso.', ja: '時間通りに来るよう何度も繰り返し頼んだが、彼はまったく聞く耳を持たない。', trivia: 'repetido（繰り返された）の副詞形で、-mente という接尾辞はラテン語の mens（心）に由来し、形容詞を副詞化する。英語の repeatedly と意味・用法がほぼ一致し、どちらも「何度も」という強意的なニュアンスで使われる。' },
  'repetidor': { es: 'Mi sobrino es repetidor de segundo de bachillerato y este año tiene que aprobar todas las asignaturas.', ja: '私の甥は高校2年の留年生で、今年は全科目に合格しなければならない。', trivia: 'ラテン語 repetere（繰り返す）に -dor（行為者）を付けた派生語。英語では repeater と同語源だが、英語の repeater は主に「繰り返す人・物」や「連発銃」を指すのに対し、スペイン語の repetidor は「留年生」や「通信中継器」の意味でより広く使われる点が異なる。' },
  'repique': { es: 'El repique de las campanas de la catedral se escuchaba por todo el pueblo.', ja: '大聖堂の鐘の連打音が村中に響き渡っていた。', trivia: 'repicar（鐘を連打する）の名詞形で、re-（再び・強意）+ picar（突く、鳴らす）の構成。英語では peal of bells（鐘の連打）や chime に相当するが、直接対応する単一語はない。picar はラテン語 *piccare に由来し、英語の pick とも遠い語根上のつながりが指摘される。' },
  'repizcar': { es: 'La abuela solía repizcar las mejillas de los niños cuando estaban traviesos.', ja: '祖母はいたずらっ子の子どもたちの頬をよくつまんでいた。', trivia: 'スペイン語方言・古語的な動詞で、pizcar や pellizcar（つまむ、つねる）の強意形または異形。語源は諸説あり定説はないが、ラテン語またはゲルマン語起源の可能性がある。英語では pinch に相当し、pellizcar と pinch は意味的に対応するが語源的なつながりは明確でない。' },
  'repizco': { es: 'Le dio un repizco en el brazo para que se despertara sin hacer ruido.', ja: '音を立てずに起こそうと、彼の腕をつまんだ。', trivia: 'repizcar（つまむ）の名詞形で、pellizco（つまみ、ひとつまみ）とほぼ同義の方言・古語的表現。英語の pinch と意味的に対応し、料理での「ひとつまみ」も a pinch of salt のように同じ概念を共有する。スペイン語では pellizco の方がより広く使われる。' },
  'repleción': { es: 'Después del banquete, sintió una sensación de repleción que le impedía moverse.', ja: '宴会の後、体が動けないほどの満腹感を覚えた。', trivia: 'ラテン語 repletio（充満）に由来し、replere（いっぱいにする）から派生。英語の repletion と同語源で、どちらも「胃が満たされた状態、過食感」という医学的・文語的な意味を持つ。日常表現では英語の fullness、スペイン語の saciedad の方が普通に使われる。' },
  'replegada': { es: 'Las tropas replegadas esperaban nuevas órdenes en una posición defensiva.', ja: '退却した部隊は防御陣地で新たな命令を待っていた。', trivia: 'replegar の過去分詞・形容詞形。replegar はラテン語 replicare（折り返す）から来ており、re-（再び）+ plicare（折る）の構成。英語の fold と reply はどちらも plicare に由来するが、「退却する」という軍事的意味はスペイン語で特に発達した用法。' },
  'replegar': { es: 'El comandante ordenó replegar las fuerzas hacia la línea de defensa secundaria.', ja: '司令官は部隊を第二防衛線に向けて退却させるよう命令した。', trivia: 'ラテン語 replicare（再び折る）に由来し、re-（再び）+ plicare（折る）の構成。英語の reply も同じ replicare から来ており、元々は「折り返し答える」という意味だった。replegar の「折りたたむ・退却する」と reply の「返答する」は、同じ語源から異なる意味に分岐した好例。' },
  'réplica': { es: 'El museo expone una réplica exacta del casco original del gladiador romano.', ja: 'その博物館はローマ剣闘士のオリジナルのヘルメットの精密な複製を展示している。', trivia: 'ラテン語 replicare（折り返す、繰り返す）の名詞形に由来。英語の replica と同語源で意味も「複製・模造品」として共通するが、スペイン語では「法的反論」「余震」という意味でも使われる点が幅広い。英語の reply も同じ語根から来ており、意味の広がりが興味深い。' },
  'replicación': { es: 'La replicación del ADN es un proceso fundamental para la reproducción celular.', ja: 'DNAの複製は細胞分裂にとって根本的なプロセスだ。', trivia: 'ラテン語 replicare（折り返す、繰り返す）の名詞形。英語の replication と同語源で、生物学・情報技術での「データや遺伝情報を複製するプロセス」という意味でほぼ同一の使われ方をする現代科学用語の典型例。' },
  'replicar': { es: 'Cuando el jefe le llamó la atención, ella replicó con calma que había seguido todas las instrucciones.', ja: '上司に注意されたとき、彼女はすべての指示に従ったと落ち着いて言い返した。', trivia: 'ラテン語 replicare（折り返す、繰り返す）に由来し、re-（再び）+ plicare（折る）の構成。英語の reply と replica はどちらも同じ語根から来ており、「言い返す」という意味では reply に近いが、スペイン語の replicar は「反論する」という若干強いニュアンスを持つことが多い。' },
  'repoblación': { es: 'El proyecto de repoblación forestal busca restaurar los bosques destruidos por el incendio.', ja: '森林再生プロジェクトは山火事で失われた森を回復させることを目指している。', trivia: 're-（再び）+ población（人口、集落）の合成語で、poblar（定住させる）から派生。英語の repopulation や reforestation に意味的に対応する。ラテン語 populus（人々）が語根で、英語の people や popular も同語源。森林再生（repoblación forestal）はスペイン・ラテンアメリカで特に重要な環境政策用語。' },
  'repoblar': { es: 'Las autoridades decidieron repoblar el río con miles de alevines de trucha.', ja: '当局は数千匹のマス稚魚を川に放流することを決めた。', trivia: 're-（再び）+ poblar（定住させる、生息させる）の合成語。poblar はラテン語 populare（人を住まわせる）から来ており、英語の populate と同語源。repoblar は英語では repopulate や restock（魚の場合）に相当し、環境保全や生態系回復の文脈で現代的な重要性を持つ動詞。' },
  'repollo': { es: 'La ensalada de repollo morado con zanahoria es muy popular en los mercados locales.', ja: '紫キャベツと人参のサラダは地元の市場でとても人気がある。', trivia: '語源は諸説あるが、ラテン語 replum（結合部）または rapulum（かぶ）から派生したとも言われ、「芽が再び丸まって育つ」イメージと結びついた可能性がある。英語の cabbage はフランス語 caboche（頭）に由来し、スペイン語 repollo とは語源が異なる。「丸い頭のような野菜」という発想は両言語で共通する。' },
  'reponer': { es: 'Tardé varios meses en reponerme del todo tras la operación.', ja: '手術後に完全に回復するのに数か月かかった。', trivia: 'ラテン語 reponere（元の場所に戻す）に由来し、re-（再び）+ ponere（置く）の構成。英語の replace や restock の意味に相当するが、単一の英語動詞には対応しにくい多義語。英語 postpone の post- + ponere と同じ ponere を語根に持ち、「置く」という基本動作から多彩な意味が派生している。' },
  'reportación': { es: 'La reportación de operaciones en el mercado de dinero requiere documentación muy precisa.', ja: 'マネーマーケットの取引の報告には非常に精密な書類が求められる。', trivia: 'reportar（報告する、自制する）の名詞形で、金融文脈（特にメキシコ）では「レポ取引（現先取引）」を指す専門用語として使われる。英語の report と同じラテン語 reportare（持ち帰る）に由来。古い用法では「自制・耐忍」の意味もあり、語義の幅広さが興味深い。' },
  'reportada': { es: 'La cifra reportada de contagios fue mucho mayor de lo esperado.', ja: '報告された感染者数は予想をはるかに上回るものだった。', trivia: 'reportar（報告する）の過去分詞・形容詞形。reportar はラテン語 reportare（持ち帰る、報告する）から来ており、英語の report と完全に同語源。スペイン語では再帰形 reportarse に「自制する」という意味もあり、英語の report にはないニュアンスが存在する点が対照的。' },
  'reportado': { es: 'El incidente fue reportado a las autoridades competentes de inmediato.', ja: 'その事件はすぐに担当当局に報告された。', trivia: 'reportar の過去分詞・形容詞形（男性形）。ラテン語 reportare（持ち帰る、報告する）に由来し、re-（再び）+ portare（運ぶ）の構成。英語の reported と同語根で意味も同一。porter（荷物を運ぶ人）や transport も同じ portare を語根に持つファミリー語。' },
  'reportar': { es: 'El periodista tuvo que reportar los hechos con objetividad, aunque la situación era muy tensa.', ja: 'ジャーナリストは状況が非常に緊迫していたにもかかわらず、客観的に事実を報道しなければならなかった。', trivia: '英語の report と同語源で、ラテン語 reportare（持ち帰る、伝達する）に由来する。re-（再び）+ portare（運ぶ）の構成で、英語 transport や portable とも語根を共有する。' },
  'reporte': { es: 'El jefe de departamento pidió un reporte detallado sobre las ventas del trimestre.', ja: '部門長は四半期の売上に関する詳細な報告書を求めた。', trivia: '英語の report と同語源で、ラテン語 reportare 由来。スペイン語では動詞 reportar から派生した名詞形だが、informe（報告書）とほぼ同義で使われ、中南米では特に口語でよく用いられる。' },
  'reportera': { es: 'La reportera llegó al lugar del accidente antes que ningún otro medio de comunicación.', ja: 'その女性記者は他のどのメディアよりも先に事故現場に到着した。', trivia: '英語の reporter と同語源で、ラテン語 reportare（伝達する）に由来する職業名詞。英語では性別を区別しないが、スペイン語では reportero（男性）/ reportera（女性）と語尾で区別するのが特徴。' },
  'reportero': { es: 'El reportero entrevistó al alcalde sobre las nuevas medidas de seguridad en la ciudad.', ja: 'その記者は市の新しい治安対策について市長にインタビューした。', trivia: '英語の reporter と同語源で、ラテン語 reportare（持ち帰る・伝達する）に由来する職業名詞。英語の reporter が性別中立であるのに対し、スペイン語では語尾 -o / -a で性別を表す。' },
  'reposada': { es: 'Con voz reposada, la maestra explicó el problema a los alumnos que se sentían nerviosos.', ja: '先生は落ち着いた声で、緊張している生徒たちに問題を説明した。', trivia: '動詞 reposar（休む）の過去分詞が形容詞化したもので、ラテン語 repausare に由来する。英語の repose（休息、静けさ）と同語根だが、英語では形容詞として reposeful というやや格式張った語が対応する。' },
  'reposar': { es: 'El médico le indicó que debía reposar al menos una semana después de la operación.', ja: '医師は手術後少なくとも1週間は安静にしているよう指示した。', trivia: 'ラテン語 repausare（再び止まる）に由来し、英語の repose（休息する）と同語根。英語の pause も同じ系譜で、ギリシャ語 pausis（停止）が起点となっている。' },
  'reposición': { es: 'La cadena de televisión anunció la reposición de la serie más vista de los últimos años.', ja: 'そのテレビ局は近年最も視聴された連続ドラマの再放送を発表した。', trivia: 'ラテン語 repositio（元に戻すこと）に由来し、英語の repositioning や replenishment と語根を共有する。英語では文脈によって rerun（再放送）、restocking（補充）など複数の語が対応し、スペイン語の reposición が多義的であることが分かる。' },
  'reposo': { es: 'El atleta necesitaba un período de reposo para recuperarse completamente de la lesión.', ja: 'その選手は怪我から完全に回復するために休養期間が必要だった。', trivia: 'ラテン語 repausare に由来し、英語の repose と同語根。repose は現代英語では「静けさ」「安らぎ」という文学的・格式的なニュアンスを持つのに対し、スペイン語の reposo は医療文脈（安静）でも日常的に広く使われる。' },
  'repostería': { es: 'Mi abuela aprendió repostería en una escuela francesa y sus tartas son extraordinarias.', ja: '祖母はフランスの学校で製菓を学んだので、彼女のタルトは素晴らしい。', trivia: 'スペイン語 reposta（貯蔵品、食料庫）に由来し、もともとは食料品保管の場所を指していた語が転じて菓子製造の意味になった。英語の pastry や confectionery に相当するが、英語に直接対応する同語根の語はない。' },
  'repreguntar': { es: 'El abogado defensor empezó a repreguntar al testigo para poner en duda su declaración.', ja: '弁護士は証人の証言に疑念を生じさせるために反対尋問を始めた。', trivia: 're-（再び）+ preguntar（質問する）の合成語で、ラテン語 percontari（尋ねる）に由来する preguntar を強調・反復する形。英語の cross-examine に意味が近いが、英語には対応する同語根の一語がなく、スペイン語の造語力を示す例といえる。' },
  'represa': { es: 'La construcción de la represa generó controversia entre los ecologistas y el gobierno.', ja: 'そのダムの建設は環境保護論者と政府の間で論争を引き起こした。', trivia: '動詞 represar（せき止める）の名詞形で、ラテン語 reprehendere（捉え戻す）に由来する。英語の dam とは語源が異なり、英語では reprise（取り戻すこと）が同語根の語に当たるが、意味は大きく異なる。' },
  'represalia': { es: 'El gobierno amenazó con tomar represalias económicas si el acuerdo no se cumplía.', ja: '政府は協定が履行されなければ経済的報復措置を取ると脅した。', trivia: '中世ラテン語 represalia に由来し、イタリア語 rappresaglia を経由してスペイン語に入った。英語の reprisal も同じ語源を持つ直接の同源語（コグネート）で、どちらも「取り戻す」という概念が根底にある。' },
  'represar': { es: 'Las autoridades decidieron represar el río para abastecer de agua a la región durante el verano.', ja: '当局は夏の間に地域に水を供給するため、その川をせき止めることを決定した。', trivia: 'ラテン語 reprehendere（引き戻す・捉える）に由来し、re-（戻す）+ prehendere（つかむ）の構成。英語の reprehend（非難する）や comprehend とも語根 prehendere を共有するが、意味の変遷は大きく異なる。' },
  'representación': { es: 'La representación teatral del clásico obtuvo una ovación de pie al final de la obra.', ja: 'その古典作品の演劇上演は終幕にスタンディングオベーションを得た。', trivia: 'ラテン語 repraesentatio（目の前に提示すること）に由来し、英語の representation と完全に同語源の同源語（コグネート）。re-（再び）+ praesens（目の前にある）の構成で、英語 present（提示する、現在の）とも深く関係する。' },
  'representada': { es: 'La parte representada en el contrato debe dar su consentimiento explícito antes de firmar.', ja: '契約において被代理人は署名前に明示的な同意を示さなければならない。', trivia: '動詞 representar の過去分詞が名詞・形容詞化したもので、ラテン語 repraesentare に由来する。英語の represented と同語源だが、スペイン語では法律用語として「被代理人」という名詞的用法が特に発達している。' },
  'representante': { es: 'El representante sindical negoció mejores condiciones laborales para todos los empleados.', ja: '組合の代表者はすべての従業員のためにより良い労働条件を交渉した。', trivia: 'ラテン語 repraesentare の現在分詞形に由来し、英語の representative と同語源。英語の representative が形容詞・名詞の両用であるのと同様に、スペイン語の representante も「代表者」という名詞と「代表する」という形容詞的用法を持つ。' },
  'representar': { es: 'Esta empresa nos representa en los mercados internacionales desde hace más de diez años.', ja: 'この企業は10年以上前から国際市場で私たちの代理をしている。', trivia: 'ラテン語 repraesentare（目の前に示す）に由来し、re-（再び）+ praesentare（提示する）の構成。英語の represent と完全に同語源で、present（贈り物・現在・提示する）ファミリーの語根 praesens を共有する。' },
  'representativa': { es: 'Esta muestra no es representativa de la población total, por lo que los resultados pueden ser sesgados.', ja: 'このサンプルは全母集団を代表するものではないため、結果が偏っている可能性がある。', trivia: 'ラテン語 repraesentativus に由来し、英語の representative と同語源の同源語。英語では名詞・形容詞が同形だが、スペイン語では representativo / representativa と性によって語尾が変化するのが特徴。' },
  'representativo': { es: 'El flamenco es un ejemplo representativo de la cultura española que fascina al mundo entero.', ja: 'フラメンコはスペイン文化の代表的な例であり、全世界を魅了している。', trivia: 'ラテン語 repraesentativus に由来し、英語の representative（代表的な、典型的な）と同語源。英語の representative democracy（代議民主主義）に対応するスペイン語は democracia representativa で、語順が逆になるのが特徴。' },
  'represión': { es: 'La represión política durante la dictadura dejó heridas profundas en la sociedad.', ja: '独裁政権下の政治的弾圧は社会に深い傷を残した。', trivia: 'ラテン語 repressio（押し戻すこと）に由来し、英語の repression と完全に同語源。心理学用語としての「抑圧」はフロイトの概念を通じて英語 repression からスペイン語に逆輸入された面もある。' },
  'represora': { es: 'La figura represora del régimen utilizaba el miedo para controlar a la población.', ja: 'その政権の弾圧的な人物は恐怖を使って国民を支配していた。', trivia: 'ラテン語 reprimere（押し戻す）の能動行為者名詞に由来し、英語の repressor と同語源。生物学・分子生物学では repressor protein（リプレッサータンパク質）としてよく知られる英語用語と同じ語根を持つ。' },
  'represor': { es: 'El nuevo gobierno identificó a los principales represores de la época y los llevó a juicio.', ja: '新政権はその時代の主要な弾圧者たちを特定し、裁判にかけた。', trivia: 'ラテン語 reprimere（抑え込む）の行為者名詞に由来し、英語の repressor と同語源。分子生物学では遺伝子発現を抑制するタンパク質を英語でも repressor と呼び、スペイン語でも represor として用いる。' },
  'reprimenda': { es: 'El director le dio una reprimenda severa al empleado por llegar tarde repetidamente.', ja: '所長は度々遅刻した社員に厳重な叱責を与えた。', trivia: '入力行には「deprimente / reprimenda」と記されているが、ここでは reprimenda を取り上げる。ラテン語 reprimenda（抑えられるべきもの）に由来し、英語の reprimand と同語源。英語 reprimand はフランス語経由で入った借用語で、スペイン語と語源を共有する。' },
  'reprimida': { es: 'Llevaba una vida reprimida y, finalmente, decidió expresar sus emociones sin miedo.', ja: '彼女は抑圧された生活を送っていたが、ついに恐れずに感情を表現することを決意した。', trivia: '動詞 reprimir の過去分詞が形容詞化したもので、ラテン語 reprimere（押し戻す）に由来する。英語の repressed と同語源で、心理学的文脈での「抑圧された（感情・欲求）」という用法は英語 repressed からの影響を受けている。' },
  'reprimir': { es: 'Tuvo que reprimir las ganas de reír durante la reunión para no parecer poco profesional.', ja: 'プロフェッショナルに見えないよう、会議中に笑いたい気持ちを抑えなければならなかった。', trivia: 'ラテン語 reprimere（押し戻す・抑え込む）に由来し、re-（戻す）+ premere（押す）の構成。英語の repress と完全に同語源で、press（押す）、compress（圧縮する）、impress（印象を与える）など多くの英語語彙と語根 premere を共有する。' },
  'reprobación': { es: 'La reprobación del proyecto por parte del comité fue una gran decepción para el equipo.', ja: '委員会によるプロジェクトの否決は、チームにとって大きな失望だった。', trivia: 'ラテン語 reprobatio（否認・非難）に由来し、re-（再び・逆に）＋ probare（証明する・認める）が合わさった語。英語の reprobation と同語根で、「神に見放された者」という宗教的意味でも使われる。' },
  'reprobada': { es: 'María llegó a casa llorando porque salió reprobada en el examen de matemáticas.', ja: 'マリアは数学の試験で不合格になったため、泣きながら家に帰ってきた。', trivia: '動詞 reprobar の過去分詞から形成された形容詞・名詞で、女性形。中南米のスペイン語では「落第した」という教育文脈で特に頻繁に使われ、英語の flunked に相当する口語的ニュアンスを持つ。' },
  'reprobado': { es: 'El alumno reprobado tendrá que repetir el curso el año que viene.', ja: '不合格になった生徒は来年また同じ授業を繰り返さなければならない。', trivia: 'reprobada の男性形で、動詞 reprobar（ラテン語 reprobare）の過去分詞。英語では flunked / failed student に相当し、中南米では「落第生」を指す名詞としても広く使われる。スペインでは suspenso の方が一般的。' },
  'reprobar': { es: 'El profesor tuvo que reprobar a varios estudiantes que no entregaron los trabajos finales.', ja: '教授は最終レポートを提出しなかった数人の学生を不合格にしなければならなかった。', trivia: 'ラテン語 reprobare（不承認とする・退ける）に由来し、re-（逆に）＋ probare（認める）の構成。英語の reprove（非難する）と同語根だが、英語では flunk または fail を使う教育的な「落第させる」という意味は reprobar 特有のスペイン語（特に中南米）用法。' },
  'reprobatoria': { es: 'El juez lanzó una mirada reprobatoria al acusado que no mostraba ningún arrepentimiento.', ja: '裁判官は、何の反省も示さない被告に非難の眼差しを向けた。', trivia: 'ラテン語 reprobare に由来する形容詞で、女性形。英語では reproving または disapproving に相当し、同根の reprobatory という英語形も存在するが極めてまれで、日常では disapproving が一般的。' },
  'reprobatorio': { es: 'El tono reprobatorio de su voz dejó claro que no estaba de acuerdo con la decisión.', ja: '彼の声の非難めいたトーンは、その決定に賛成していないことを明確に示していた。', trivia: 'reprobatoria の男性形。英語の disapproving / reproving に相当する形容詞で、ラテン語 reprobare から派生。英語の reprobatory は文語的・法律的文脈でのみ使われ、日常会話ではほぼ用いられない点でスペイン語より用途が狭い。' },
  'reprochar': { es: 'Mi madre me reprochó haber llegado tarde sin avisar.', ja: '母は、連絡もせずに遅刻したことを私に責めた。', trivia: '古フランス語 reprochier（近づけて非難する）を経由し、ラテン語の re-＋ prope（近くに）が語源とされる。英語の reproach と同語根で形・意味ともほぼ同じだが、スペイン語では「根に持って繰り返し責める」ニュアンスが強い。' },
  'reproche': { es: 'Sus reproches continuos terminaron por cansar a todos los que lo rodeaban.', ja: '彼の絶え間ない非難は、周りの人々をついに疲弊させてしまった。', trivia: 'フランス語 reproche を介してスペイン語に入った語で、英語の reproach と同源。英仏スペインで形・意味が非常に近い珍しい例で、いずれもラテン語 repropiare（近づけて突き返す）に由来すると考えられている。' },
  'reproducción': { es: 'La reproducción de obras de arte sin permiso del autor constituye una violación de los derechos de autor.', ja: '著者の許可なく芸術作品を複製することは著作権侵害に当たる。', trivia: 'ラテン語 re-（再び）＋ productio（産出）に由来し、「再び生み出すこと」が原義。英語の reproduction と完全に同語根・同形で意味も共通する典型的なコグネート。生物学的「繁殖」と技術的「再生・複製」の両義を持つ点も両言語で一致する。' },
  'reproducciones': { es: 'El museo vende reproducciones de cuadros famosos a precios asequibles en su tienda.', ja: 'その美術館はショップで有名な絵画の複製品を手頃な価格で販売している。', trivia: 'reproducción の複数形。英語の reproductions と同語根・同形で、絵画・文書などの「複製品」から音楽・映像の「再生」まで幅広く使われる。ラテン語 reproductio から派生した真のコグネートで、英語学習者にとって覚えやすい語。' },
  'reproductiva': { es: 'La salud reproductiva de la mujer es un tema central en las políticas de salud pública.', ja: '女性の生殖に関する健康は、公衆衛生政策における中心的なテーマだ。', trivia: 'ラテン語 reproducere（再び産み出す）の形容詞形・女性形。英語の reproductive と同語根で意味も形もほぼ同一の典型的コグネート。reproductive rights（生殖の権利）などの表現は国際的議論で英西語ともに共通して用いられる。' },
  'reproductivo': { es: 'El ciclo reproductivo de muchos insectos está influenciado por los cambios de temperatura.', ja: '多くの昆虫の生殖サイクルは気温の変化に影響される。', trivia: 'reproductiva の男性形で、英語の reproductive に対応する。ラテン語 reproducere に由来し、英語と同語根・同義のコグネート。生物学・医学・農業など専門分野で英西語ともに頻繁に使われる国際語的な語彙。' },
  'reproductor': { es: 'Compré un reproductor de música portátil para escuchar podcasts mientras hago ejercicio.', ja: '運動中にポッドキャストを聴くために、携帯型の音楽プレーヤーを買った。', trivia: 'ラテン語 reproductor（再び生み出す者）に由来し、英語の player や reproducer に相当。英語では player が圧倒的に一般的だが、スペイン語では「再生機」の意味で reproductor が標準語として定着しており、英語の reproduce と同語根。' },
  'reproductora': { es: 'La yegua reproductora fue seleccionada cuidadosamente por sus características genéticas superiores.', ja: 'その繁殖用の牝馬は、優れた遺伝的特性によって慎重に選ばれた。', trivia: 'reproductor の女性形で、主に生物学・畜産の文脈で「繁殖用の雌」を指す。英語では breeding female または brood mare（馬の場合）などと表現し、reproducer という英語形は現代ではまれ。ラテン語 reproducere に共通の語源を持つ。' },
  'reproducir': { es: 'Este software permite reproducir vídeos en alta definición sin necesidad de conexión a internet.', ja: 'このソフトウェアはインターネット接続なしで高画質の動画を再生できる。', trivia: 'ラテン語 reproducere（re- 再び＋ ducere 導く・産む）に由来し、英語の reproduce と完全に同語根のコグネート。意味は「再生する」「複製する」「繁殖する」と英語の reproduce と一致するが、スペイン語では再帰形 reproducirse で「（問題が）再発する」という用法も発達している。' },
  'reptar': { es: 'La serpiente reptó lentamente entre las rocas en busca de calor.', ja: 'ヘビは暖かさを求めて、岩の間をゆっくりと這い進んだ。', trivia: 'ラテン語 reptare（這う・creep する）に由来し、reptil（爬虫類）と同語根。英語の creep や crawl に意味が相当するが、英語で「這う」を表す直接の同語根語はない。ラテン語 reptans（這うもの）は reptile の語源にもなっており、動詞 reptar と名詞 reptil は姉妹語。' },
  'reptil': { es: 'El cocodrilo es el reptil más grande que habita en los ríos de África.', ja: 'ワニはアフリカの川に生息する最大の爬虫類だ。', trivia: 'ラテン語 reptilis（這うもの）に由来し、英語の reptile と完全に同語根・同義のコグネート。どちらもラテン語 repere（這う）から派生し、英語では -ile 語尾を保持しているのに対し、スペイン語では脱落している点が形態上の違い。' },
  'república': { es: 'Francia es una república laica cuya Constitución garantiza la separación entre la Iglesia y el Estado.', ja: 'フランスは世俗共和国であり、その憲法は政教分離を保障している。', trivia: 'ラテン語 res publica（公共のもの・公の事柄）に由来し、英語の republic と同語根。英語では中間の「s」が消えた形になっているが、意味・語源は完全に共通。キケロが『国家論』でこの語を哲学的に深化させ、近代の共和主義概念の基礎となった。' },
  'republicana': { es: 'La candidata republicana ganó las elecciones por un margen muy estrecho.', ja: '共和党の女性候補は僅差で選挙に勝利した。', trivia: 'ラテン語 res publica から派生した形容詞・名詞の女性形。英語の republican と同語根のコグネートで、アメリカの共和党（Republican Party）を指す場合も含め意味がほぼ一致する。スペイン語圏では米共和党員だけでなく「共和制を支持する人」という一般的意味でも使われる。' },
  'republicano': { es: 'El partido republicano presentó su programa electoral centrado en la reforma fiscal.', ja: '共和党は税制改革を中心とした選挙綱領を発表した。', trivia: 'republicana の男性形で、英語の republican と同語根のコグネート。ラテン語 res publica（公共のもの）に由来し、17世紀以降ヨーロッパの政治思想の中で定着した語。英語では大文字 Republican でアメリカ共和党を、小文字で「共和主義者」を区別するが、スペイン語では文脈で判断する。' },
  'repudiación': { es: 'La repudiación de la deuda externa por parte del nuevo gobierno generó una crisis financiera internacional.', ja: '新政府による対外債務の拒絶は、国際的な金融危機を引き起こした。', trivia: 'ラテン語 repudiatio（拒絶・離縁）に由来し、re-（逆に）＋ pudere（恥ずる）または pudium（拒否する）が語源とされる（諸説あり）。英語の repudiation と同語根で形・意味ともほぼ同一のコグネート。国際法では債務不履行の宣言を指す専門用語として両言語で共通に使われる。' },
  'repudiar': { es: 'La comunidad internacional repudió los ataques contra la población civil con un comunicado conjunto.', ja: '国際社会は共同声明で民間人への攻撃を強く拒絶した。', trivia: 'ラテン語 repudiare（退ける・離縁する）に由来し、英語の repudiate と同語根のコグネート。イスラム法における離婚形式「タラーク」の歴史的文脈でも使われた語で、現代では「(遺産・条約・発言などを)拒否する」という広い意味を持ち、英語 repudiate と用法が一致する。' },
  'repudio': { es: 'Su repudio de las ideas extremistas fue aplaudido por los miembros del partido.', ja: '極端な思想への彼の拒絶は、党員たちから拍手を受けた。', trivia: 'ラテン語 repudium（離縁・拒絶）に由来し、英語の repudiation に相当するが、スペイン語では名詞形として repudio がより簡潔で日常的に使われる。英語には repudiation という形が主流で repudio に対応する短縮形はなく、この点がスペイン語の特徴といえる。' },
  'repuesta': { es: 'Tras meses de rehabilitación, la atleta llegó repuesta y más fuerte que nunca a la competición.', ja: '数か月のリハビリを経て、そのアスリートは回復し、これまで以上に強くなって大会に臨んだ。', trivia: '動詞 reponer（再び置く・回復する）の不規則過去分詞の女性形で、ラテン語 reponere（re- 再び＋ ponere 置く）に由来する。英語の replace や restore と同語根の概念を持ち、英語では recovered / spare に相当。中南米の一部では「体格の良い・ふっくらした」という独特の意味でも使われる。' },
  'repuesto': { es: 'El mecánico tardó una semana en conseguir el repuesto necesario para reparar el motor.', ja: '整備士はエンジンを修理するのに必要な交換部品を手に入れるのに1週間かかった。', trivia: 'repuesta の男性形で、動詞 reponer（ラテン語 reponere：re- 再び＋ ponere 置く）の不規則過去分詞から名詞化。英語の spare part や replacement part に相当し、英語の repose（休息・置き直す）と同語根。「de repuesto（予備の・スペアの）」というフレーズはスペイン語で頻繁に使われる定型表現。' },
  'repugnancia': { es: 'Sentía una repugnancia profunda al ver las condiciones en que vivían los animales de la granja.', ja: 'その農場で動物たちが生活している状況を見て、深い嫌悪感を覚えた。', trivia: 'ラテン語 repugnantia（抵抗・対立）から来ており、re-（反して）＋pugnare（戦う）が語根。英語 repugnance と完全な同語根で、どちらも「生理的・道徳的な嫌悪」を意味するが、スペイン語では身体的な吐き気のニュアンスがより強い。' },
  'repugnante': { es: 'El olor que salía de la basura acumulada era tan repugnante que nadie quería acercarse.', ja: '積み上げられたゴミから漂う臭いはあまりにも不快で、誰も近づこうとしなかった。', trivia: 'ラテン語 repugnans（抵抗する・相容れない）の現在分詞形が形容詞化したもの。英語の repugnant も同じ経路で、今日では「道徳的に受け入れがたい」に使われることが多いが、スペイン語ではより直接的に「吐き気を催すほど不快」なものを指すことが多い。' },
  'repugnar': { es: 'Me repugna la idea de mentirle a alguien que confía en mí.', ja: '自分を信頼している人に嘘をつくという考えが、私には受け入れがたい。', trivia: 'ラテン語 repugnare（抵抗する・戦い返す）から派生し、re-（反して）＋pugnare（戦う）が語根で、英語 pugnacious（好戦的な）や impugn（異議を申し立てる）と同じ pugnare を共有する。英語では repugn という動詞もあるが現代ではほぼ廃語で、代わりに disgust や revolt を用いる。' },
  'repulsa': { es: 'La propuesta del gobierno recibió una repulsa inmediata por parte de los sindicatos.', ja: '政府の提案は、労働組合からただちに強い拒絶を受けた。', trivia: 'ラテン語 repulsa（撃退・拒絶）から直接来ており、repellere（押し返す）の過去分詞 repulsus が語根。英語の repulse（撃退する・拒絶する）と同語根だが、英語では動詞用法が中心なのに対し、スペイン語では名詞 repulsa として「強い社会的・政治的拒絶」の意味で多く用いられる。' },
  'repulsión': { es: 'Entre los polos iguales de dos imanes existe una fuerza de repulsión que los mantiene separados.', ja: '二つの磁石の同じ極の間には、それらを引き離しておく斥力が存在する。', trivia: 'ラテン語 repulsio（押し返すこと）から来ており、英語 repulsion と完全な同語根かつ意味も同じ。物理学では「斥力」、心理学・日常語では「嫌悪・反感」の両方に使われる点も英語と共通しているが、英語 repulsion には「強い嫌悪」のニュアンスがより強く残っている。' },
  'repulsiva': { es: 'La actitud repulsiva del personaje principal hace que sea difícil simpatizar con él.', ja: '主人公の嫌悪感を催す態度のせいで、彼に共感するのが難しい。', trivia: 'ラテン語 repulsivus の女性形で、英語 repulsive と完全な同語根。英語の repulsive も「嫌悪感を与える」と「反発する（物理）」の両義を持ち、スペイン語とほぼ同じ用法で使われる典型的なコグネート（cognate）ペアのひとつ。' },
  'repulsivo': { es: 'El comportamiento repulsivo del acusado quedó documentado en las grabaciones de seguridad.', ja: '被告の嫌悪感を催す行動は、防犯カメラの録画に記録されていた。', trivia: 'repulsiva の男性形。ラテン語 repulsivus から来ており、英語 repulsive と完全な同語根・同義。物理学の「斥力の」と日常語の「ぞっとするほど不快な」の両方に使われる点も英語と同様で、形容詞としての用法はほぼ対応している。' },
  'reputación': { es: 'Una sola mala decisión puede arruinar la reputación que una empresa ha construido durante décadas.', ja: 'たった一つの誤った決断が、企業が何十年もかけて築いてきた評判を台無しにしてしまうことがある。', trivia: 'ラテン語 reputatio（考え直すこと・評価）から来ており、re-（再び）＋putare（考える・計算する）が語根。英語 reputation と完全な同語根・同義であり、dispute（論争）や compute（計算する）も同じ putare を共有する。つまり「評判」とは「人々が繰り返し考え評価したもの」というのが語源的な意味。' },
  'reputada': { es: 'Esta universidad es muy reputada por la calidad de sus programas de posgrado.', ja: 'この大学は大学院プログラムの質の高さで非常に高い評判を得ている。', trivia: 'reputado の女性形で、ラテン語 reputatus（評価された）の過去分詞から派生した形容詞。英語の reputable（評判の良い）と同語根だが、英語 reputed（～と言われている）は必ずしも肯定的なニュアンスを持たない点が異なる。スペイン語 reputada はほぼ常に「定評ある・高名な」という肯定的な意味で使う。' },
  'reputado': { es: 'El cirujano reputado fue convocado para una consulta de segunda opinión.', ja: 'その定評ある外科医がセカンドオピニオンのための相談に呼ばれた。', trivia: 'ラテン語 reputatus（繰り返し考えられた・評価された）の過去分詞形が形容詞化したもの。英語の reputed は「～と言われている（が実際は不確か）」という留保を含む場合があるのに対し、スペイン語の reputado はほぼ肯定的な「定評ある・高名な」を意味する点でニュアンスが異なる。' },
  'requebradura': { es: 'El alfarero notó una requebradura en el borde de la vasija antes de meterla al horno.', ja: '陶芸家は窯に入れる前に、壺のふちにひび割れを見つけた。', trivia: 'quebrar（割る・ひびを入れる）に接頭辞 re-（繰り返し）を付けた requebrar から派生した名詞で、「繰り返し割れること・ひびが入ること」を指す。英語には直接の対応語がなく、crack や fracture で言い換えるが、語根の quebrar はラテン語 crepare（割れる・鳴る）に由来し、英語 crevice（亀裂）や creak（きしむ）とも遠縁にあたる。' },
  'requebrar': { es: 'El galán no perdía oportunidad de requebrar a la joven con versos improvisados.', ja: 'その伊達男は、即興の詩で若い女性を口説く機会を逃さなかった。', trivia: 'quebrar（壊す・折る）に re- を加えた動詞で、もともと「声を細かく震わせる」という歌唱技法を指し、そこから「甘い言葉で口説く」という意味へ転じた。英語では flatter や court に相当するが、この音楽的な転義の経緯は英語にはなく、スペイン語ならではの語彙史を持つ。' },
  'requemada': { es: 'La carne requemada que sacaron del horno no tenía ningún sabor agradable.', ja: 'オーブンから取り出した焦げすぎた肉には、おいしい味が全くなかった。', trivia: 'quemar（燃やす）に re-（過剰・繰り返し）を付けた requemar の過去分詞の女性形。英語では overcooked や charred に相当し、直接の対応語はないが、quemar はラテン語 cremare（焼く）に由来し、英語 cremate（火葬する）と同語根。re- が「やりすぎ」を示す用法は英語の over- と対応する。' },
  'requemado': { es: 'Llegué a casa completamente requemado después de una semana de trabajo sin descanso.', ja: '休みなく一週間働いた後、完全に燃え尽きた状態で帰宅した。', trivia: 'requemada の男性形。ラテン語 cremare（燃やす）に由来する quemar に re-（過剰）を加えた形で、英語の burned out（燃え尽きた）と比喩的用法が重なる。英語 cremate（火葬する）と同語根で、cremation（火葬）とも関係する。' },
  'requenense': { es: 'Un chef requenense presentó en Madrid los platos más representativos de su tierra.', ja: 'レケナ出身のシェフがマドリードで、故郷を代表する料理を披露した。', trivia: '地名 Requena（スペイン・バレンシア州、またはペルーの都市）から作られた住民形容詞（gentilicio）で、-ense は地名から形容詞・名詞を作るラテン語由来の接尾辞。英語で言えば -an や -ian に相当し（New Yorker, Londoner）、ラテン語 -ensis も同じ機能を持っていた。Requena のワインは D.O.（原産地呼称）に認定されている。' },
  'requeñón': { es: 'El abuelo partió un requeñón de pan del día anterior para acompañar la sopa.', ja: '祖父は前日のパンの大きな塊を割って、スープに添えた。', trivia: '語源は不明確で、queño という語根も標準スペイン語には存在せず、地方語・古語の域に属する。英語には直接の対応語がなく hunk of bread と言い換えるしかない。queña / quena（アンデスの笛）とは無関係で、単に「大きな固まり」を指す地域限定の表現と考えられる。' },
  'requesón': { es: 'El requesón es un queso fresco ideal para preparar postres ligeros o rellenos de pasta.', ja: 'レケソンはデザートや軽いパスタの詰め物を作るのに最適なフレッシュチーズだ。', trivia: '語源は諸説あるが、再び（re-）凝固させた（queso＝チーズ）という意味が有力で、ラテン語 caseus（チーズ）が語根。英語 cheese も caseus に由来するとする説とゲルマン語 kasjus に由来する説がある。イタリア語 ricotta（再び煮たもの）と製法・語義の発想が似ており、英語では ricotta または cottage cheese で代用される。' },
  'requiebro': { es: 'Le dedicó un requiebro tan ingenioso que ella no pudo evitar sonreír.', ja: '彼はとても機知に富んだほめ言葉を贈ったので、彼女は思わず微笑んだ。', trivia: 'requebrar（口説く）の直説法現在1人称単数形が名詞にもなった語。語根の quebrar は「壊す・折る」だが、音声を細かく「折る」ように使う比喩から「甘い言葉で心を溶かす」という意味に転じた。英語では compliment や flattery に相当するが、この詩的・音楽的な転義の経緯は英語語彙にはなく、スペイン語独自の語彙の深みを示す。' },
  'requintar': { es: 'El músico tuvo que requintar la guitarra para alcanzar las notas del solista.', ja: 'ミュージシャンはソリストの音に合わせるために、ギターを5度高く調弦しなければならなかった。', trivia: 'quinto（5番目）に re-（繰り返し・強調）を加えた動詞で、「5度（音程）分を再調整する」という音楽専門用語。英語の fifth（5番目）と quinto はともにラテン語 quintus から来ており、quintuplets（五つ子）や quintet（五重奏）も同語根。中南米では「きつく縛る・激しく罵る」という口語的な意味でも使われる。' },
  'requinto': { es: 'En la música tradicional mexicana, el requinto lleva la melodía principal mientras la guitarra hace el acompañamiento.', ja: 'メキシコの伝統音楽では、レキントが主旋律を担当し、ギターが伴奏を行う。', trivia: 'quinto（5番目・5分の1）から来た名詞で、標準ギターより5度高く調弦された小型ギターを指す。英語では requinto guitar と呼ばれそのままスペイン語が使われる。ラテン語 quintus（5番目）を語根に持ち、英語 quintet（五重奏）や quint（5度音程）と同語根。中南米では「激しい叱責」という派生義もある。' },
  'requisa': { es: 'Durante el conflicto, las autoridades militares ordenaron la requisa de vehículos privados.', ja: '紛争中、軍当局は民間車両の徴発を命じた。', trivia: 'ラテン語 requisitus（求められたもの）から派生し、requirere（要求する）が語根。英語の requisition（徴発・要求）と同語根で、require（必要とする）や request（要求する）とも関係する。英語では requisition が名詞・動詞を兼ねるが、スペイン語は名詞 requisa と動詞 requisar を分けて使う。' },
  'requisar': { es: 'La policía aduanera requisó varios paquetes sospechosos en el puerto de entrada.', ja: '税関警察は入港地点で複数の不審な荷物を差し押さえた。', trivia: 'ラテン語 requirere（再び求める・要求する）から来た動詞で、名詞 requisa と同語根。英語の requisition（徴発する）と同義で、require や request とも語根を共有する。require が「必要とする」という穏やかな意味なのに対し、スペイン語 requisar は公権力による強制的な没収・差し押さえを指す点でニュアンスが異なる。' },
  'requisito': { es: 'Uno de los requisitos para obtener la visa es presentar un certificado de antecedentes penales.', ja: 'ビザを取得するための要件の一つは、犯罪歴証明書を提出することだ。', trivia: 'ラテン語 requisitus（求められたもの）から来ており、requirere（要求する）が語根。英語 requisite（必要条件・必須の）と完全な同語根で、prerequisite（前提条件）も同じ系列。英語では requirement が最も一般的だが、スペイン語 requisito は書類上の「必要条件・資格要件」を指すフォーマルな語として頻繁に使われる。' },
  'res': { es: 'En el mercado local se vendían más de cien reses antes del amanecer.', ja: '地元の市場では夜明け前に100頭以上の家畜が売られていた。', trivia: 'ラテン語 res（もの・事物）から来ており、もともとは「財産・家畜」を意味していた。英語では直接の対応語はなく head of cattle や livestock で言い換えるが、英語の real（現実の）やスペイン語の real（王の・現実の）はともにこの res に由来する点が興味深い。また英語法律用語の res（当該事物）はラテン語をそのまま借用したもの。' },
  'resabiar': { es: 'Vivir demasiado tiempo en ambientes hostiles puede resabiar a cualquier persona.', ja: '敵対的な環境に長く生き続けると、誰でも擦れてひねくれてしまうことがある。', trivia: 'saber（知る・味がする）に re-（繰り返し・強化）を加えた動詞で、「悪い癖・知恵をつけさせる」が本来の意味。語根の saber はラテン語 sapere（味わう・知る）に由来し、英語 sage（賢者・セージ）や savvy（知恵のある）と同語根。英語に直接対応する動詞はなく、corrupt や jaded にするしかない点がスペイン語独自の語彙の豊かさを示す。' },
  'resabio': { es: 'Ese vino barato dejó un resabio amargo que no podía quitarme de la boca.', ja: 'その安いワインは口の中から消えない嫌な後味を残した。', trivia: 'ラテン語 re-（再び）＋ sapere（味わう・知る）に由来し、「悪い経験の残り香」という意味が派生した。英語の aftertaste や、知識を意味する savvy（スペイン語 saber から）と同語根で、「味・知覚」を核に持つ単語群につながる。' },
  'resaca': { es: 'Después de la fiesta de anoche, me levanté con una resaca terrible y no pude ir al trabajo.', ja: '昨晩のパーティーの後、ひどい二日酔いで目が覚めて仕事に行けなかった。', trivia: 're-（戻る）＋ sacar（引き出す）から成り、元々は「波が引くこと（引き波）」を指していた。英語の hangover は「ぶら下がった状態が残る」という別の比喩だが、undertow（引き波）は resaca の本義と完全に対応する。' },
  'resalada': { es: 'La profesora era tan resalada que todos los estudiantes querían asistir a su clase.', ja: 'その先生はとても愛嬌があり、すべての学生が彼女の授業に出たがっていた。', trivia: 're-（強調の接頭辞）＋ salada（塩辛い）の構成で、「塩が効きすぎた」が転じてスペインの口語では「ひときわ魅力的な」という意味になった。英語 salty には「皮肉な・むっとした」という現代スラング的な意味もあり、同じ「塩」でも比喩の方向が対照的で興味深い。' },
  'resalado': { es: 'El vendedor era tan resalado que convencía a cualquiera de comprar su producto.', ja: 'その売り子はとても愛嬌があり、誰をでも商品を買わせてしまうほどだった。', trivia: 'resalada の男性形で、語源・用法は同じ。re-（強調）＋ salado（塩辛い）から「魅力的・お茶目」という意味に発展した点は、英語の sharp（鋭い→機知がある）のように感覚語が肯定的な人物評価に転じるパターンと共通する。' },
  'resaltar': { es: 'El director decidió resaltar los puntos más importantes del informe con color amarillo.', ja: '部長は報告書の最重要点を黄色でハイライトすることにした。', trivia: 're-（再び・強調）＋ saltar（跳ぶ）の合成で、「飛び出して見える→目立つ」という意味に発展した。英語の result はラテン語 resultare（跳ね返る）に由来し、resaltar と同語根を持つ。どちらも「跳び出す」というイメージが核にある。' },
  'resalte': { es: 'El resalte en el pavimento obliga a los conductores a reducir la velocidad en esa zona.', ja: '路面の減速帯により、その区間では運転者はスピードを落とさなければならない。', trivia: '動詞 resaltar（目立つ、跳ね返る）の名詞形で、「突出した部分」を意味する。英語でスピードバンプは speed bump と言い、bump（こぶ、凸部）は「ドスン」という擬音が語源とされるゲルマン系語で、ラテン系の resalte とは全く異なる由来を持つ。' },
  'resalto': { es: 'El arquitecto diseñó un resalto en la fachada para romper la monotonía del edificio.', ja: '建築家はビルの外観の単調さを打ち破るために壁面の突出部をデザインした。', trivia: '動詞 saltar（跳ぶ）のラテン語祖先 saltare は英語の assault（突撃）や result（結果）などにも受け継がれている。建築用語としての resalto（壁面の突出部）に対応する英語は projection または pilaster で、それぞれギリシャ語・ラテン語由来の建築語彙となっている。' },
  'resaludar': { es: 'Cuando la anciana lo saludó desde la ventana, él la resaludó levantando la mano.', ja: '老婦人が窓から挨拶すると、彼は手を上げて挨拶を返した。', trivia: 're-（返す）＋ saludar（挨拶する）の構成。saludar はラテン語 salutare（健康を祈る）に由来し、英語の salute（敬礼する）と直接の同語源語。英語に greet back に相当する単語はなく、複数語で表現するしかない点で、スペイン語の接頭辞 re- の語彙生産性の高さが際立つ。' },
  'resaludo': { es: 'Su resaludo fue tan cálido que ella se sintió bienvenida de inmediato.', ja: '彼の返礼の挨拶がとても温かく、彼女はすぐに歓迎されていると感じた。', trivia: '動詞 resaludar の名詞形。語源はラテン語 salus（健康・安寧）で、英語の salutation（挨拶・敬称）と同語根。英語では返礼の挨拶を表す一語は存在せず、return greeting などと言うため、resaludo はスペイン語ならではの簡潔な表現である。' },
  'resalva': { es: 'Los madereros respetaron la resalva marcada por el guarda forestal para mantener el bosque.', ja: '木材業者たちは森林を維持するために森林警備員が指定した残存木を尊重した。', trivia: 're-（再び）＋ salvar（救う・残す）に由来する林業専門用語で、「次世代の森のために残す木」を指す。英語の save と salvar は共通のラテン語語根 salvare（救う）を持ち、silva（森）という別のラテン語とは異なる由来だが、森林という文脈で混同されやすい。' },
  'resalvo': { es: 'El guarda forestal indicó cuáles eran los resalvos que no debían cortarse bajo ningún concepto.', ja: '森林警備員はどの残存木をいかなる場合も伐ってはならないかを指示した。', trivia: 'resalva の男性形で、林業における「伐採後に意図的に残す親木」を指す専門語。英語では seed tree または reserve tree と呼ばれ、持続可能な林業管理の概念と結びついている。スペイン語では re-＋salvar（救う）の構造から「救い残された木」という意味が自然に生まれた。' },
  'resanar': { es: 'Antes de pintar la habitación, hay que resanar todas las grietas de las paredes.', ja: '部屋を塗装する前に、壁のひび割れをすべて補修しなければならない。', trivia: 're-（再び・完全に）＋ sanar（癒す・健全にする）の構成で、物理的な「穴埋め・修繕」から医学的な「完全治癒」まで幅広く使う。英語の sanity（正気）、sanitary（衛生的な）と同語根のラテン語 sanus（健全な）を持ち、「健全な状態に戻す」という概念が共通する。' },
  'resano': { es: 'El obrero aplicó el resano con una espátula y lo dejó secar durante toda la noche.', ja: '作業員はへらで補修剤を塗り、一晩中乾かしておいた。', trivia: '動詞 resanar の名詞形で、「壁の補修・パテ埋め」を指す建設・内装用語。英語の patching compound や spackle に相当するが、spackle はドイツ語 Spachtel（へら）に由来し、ラテン語系の resano とは全く異なる語源をたどる。' },
  'resarcimiento': { es: 'La empresa ofreció un resarcimiento económico a los clientes afectados por el retraso en la entrega.', ja: 'その会社は配送遅延により影響を受けた顧客に金銭的な補償を提供した。', trivia: 'ラテン語 resarcire（縫い直す・修繕する）に由来し、布の破れを繕うイメージから「損害の修復・賠償」へと意味が広がった。英語の compensation はラテン語 compensare（重さで釣り合わせる）に由来し、比喩の出発点が「縫い合わせ」か「天秤」かという点でスペイン語と英語の発想の違いが見える。' },
  'resarcir': { es: 'La compañía de seguros prometió resarcir todos los daños causados por el incendio.', ja: '保険会社は火災によって生じたすべての損害を賠償することを約束した。', trivia: 'ラテン語 resarcire（縫い直す）に由来し、-ir 活用の動詞として不規則な yo 形（resarzo）を持つ。英語に同語根の直接的な対応語はないが、古英語 sear（縫い目）などとの遠い関連を指摘する語源学者もおり、「繕う」という核義は広くインド・ヨーロッパ語族に共通する。' },
  'resbaladiza': { es: 'La situación política era tan resbaladiza que ningún partido quería pronunciarse claramente.', ja: '政治状況はあまりにもデリケートで、どの政党もはっきり発言しようとしなかった。', trivia: 'resbalar（滑る）に形容詞を作る接尾辞 -adizo を加えた形。英語の slippery も比喩的に「捕まえどころのない・信用できない」という意味を持ち、「滑らかなもの＝頼りにならない」という比喩は日英西語に共通するが、slippery の語源は北欧語・低地ドイツ語系で全く別の系統である。' },
  'resbaladizo': { es: 'El suelo del baño está muy resbaladizo cuando está mojado; ten cuidado de no caerte.', ja: '浴室の床は濡れているととても滑りやすいので、転ばないように気をつけて。', trivia: 'resbaladiza の男性形で、語義・語源は同じ。英語 slippery に対応し、物理的な「滑りやすさ」と比喩的な「曖昧さ・扱いにくさ」の両義を持つ点が共通する。ちなみに英語の slope（斜面）もゲルマン系で「滑る面」という概念が原義にある。' },
  'resbalador': { es: 'Los niños hacían cola para bajar por el resbalador del parque una y otra vez.', ja: '子供たちは公園の滑り台を何度も何度も滑るために列を作っていた。', trivia: 'resbalar（滑る）＋行為者接尾辞 -dor の構成。英語の slider は同じ構造（slide＋-er）で形成されており、「動作をする人・物」を表す語形成パターンが英西語でほぼ並行している。なお、中南米ではこの語が「滑り台」の一般的な呼称として使われ、スペインの tobogán と使い分けられる。' },
  'resbaladura': { es: 'La resbaladura en la escalinata mojada le costó una fractura en la muñeca.', ja: '濡れた階段で足を滑らせたせいで、手首を骨折してしまった。', trivia: 'resbalar（滑る）＋名詞接尾辞 -dura の構成で、「滑った行為・結果」を指す。英語の slip はゲルマン系（中期低地ドイツ語 slippen）に由来し、ラテン語系の resbaladura とは語源が異なるが、「足を滑らせる→道徳的な過ち」という比喩の拡張は両言語で完全に平行している。' },
  'resbalar': { es: 'Me resbalé en el hielo y caí de bruces en plena calle, delante de todo el mundo.', ja: '氷の上で滑って、大勢の人の前で大通りでうつぶせに転んでしまった。', trivia: '語源は諸説あり、ラテン語 labi（滑る）の派生語との説や、擬音的起源を指摘する説もある。英語の slip、slide はゲルマン系で別の系統。口語表現「me resbala」（どうでもいい）は英語の it slides off me に近いが、英語では it doesn\'t faze me などが一般的で、面白い表現の差異がある。' },
  'resbalón': { es: 'Un pequeño resbalón en la entrevista arruinó sus posibilidades de conseguir el trabajo.', ja: '面接での小さなしくじりが、仕事を得るチャンスを台無しにしてしまった。', trivia: 'resbalar（滑る）＋増大・強調の接尾辞 -ón で、「大きな滑り・大失敗」を表す。英語の blunder（大失敗）はゲルマン系（古ノルド語 blundra）で全く別の系統だが、比喩的な「しくじり」という意味では resbalón と対応する。またドアの「ラッチボルト」という機械的な意味も持ち、語義の広がりが興味深い。' },
  'rescatada': { es: 'La niña rescatada del pozo fue recibida con aplausos por los vecinos del barrio.', ja: '井戸から救出された少女は、近所の人々に拍手で迎えられた。', trivia: 'rescatar（救出する）の女性過去分詞形。rescatar はゴート語（ゲルマン系）の wrakjan（追い立てる）またはラテン語 excaptare との混合起源が有力とされる。英語の rescue は古フランス語 rescourre（引き離す）に由来し、スペイン語 rescatar とは別経路でラテン系の「引き出す」概念を共有している。' },
  'rescatador': { es: 'El rescatador arriesgó su vida para sacar a los mineros atrapados bajo tierra.', ja: '救助者は地下に閉じ込められた鉱夫たちを救出するために命がけで作業した。', trivia: 'rescatar＋行為者接尾辞 -dor の構成で、英語の rescuer と完全に対応する構造を持つ。英語 rescuer の rescue はラテン語 recusare（跳ね返す）や古フランス語 rescourre に由来するとされ、スペイン語 rescatar のゴート語・ラテン語混合起源とは異なる経路をたどっている。' },
  'rescatar': { es: 'Los bomberos lograron rescatar a tres personas que estaban atrapadas en el edificio en llamas.', ja: '消防士たちは燃え盛るビルに取り残されていた3人を救出することに成功した。', trivia: '語源はゴート語 us-skatjan（追い出す）またはラテン語 excaptare との混合とされ、「捕囚状態から引き離す」が原義。英語の rescue（古フランス語 rescourre 由来）と意味は一致するが語源経路が異なり、同じ「救出」概念がゲルマン語・ラテン語・ロマンス語を経由して並行進化した好例である。' },
  'rescate': { es: 'La familia tuvo que pagar un enorme rescate para que los secuestradores liberaran a su hija.', ja: '誘拐犯が娘を解放するよう、家族は莫大な身代金を支払わなければならなかった。', trivia: '動詞 rescatar の名詞形で、「救出・身代金」の両義を持つ。英語の ransom はラテン語 redemptio（贖い）に由来し、rescue とは別語源だが、スペイン語では rescate が救出と身代金の両方をカバーする。金融用語としての bailout（救済）に対応する使い方も現代スペイン語で一般的になっている。' },
  'rescindir': { es: 'El juez ordenó rescindir el contrato porque una de las partes no había cumplido con sus obligaciones.', ja: '裁判官は、一方の当事者が義務を果たしていなかったため、契約を解除するよう命じた。', trivia: 'ラテン語 rescindere（切り離す、取り消す）に由来し、re-（逆）＋ scindere（切る）の合成語。英語の rescind も同語根で、法律用語として「（法令・合意を）廃止する」を意味する。' },
  'rescisión': { es: 'La rescisión del contrato de arrendamiento fue acordada de mutuo acuerdo entre el propietario y el inquilino.', ja: '賃貸契約の解除は、家主と借主の合意のもとで取り決められた。', trivia: 'ラテン語 rescissio（取り消し）から来ており、rescindir の名詞形。英語 rescission も同語根で、契約法においてよく使われる法律用語。日本語の「解除」に最も近い概念。' },
  'rescisoria': { es: 'El abogado presentó una cláusula rescisoria que permitía anular el acuerdo en caso de incumplimiento.', ja: '弁護士は、不履行の場合に契約を無効にできる解除条項を提示した。', trivia: 'ラテン語 rescissorius（取り消しの）に由来する形容詞。英語では rescissory に相当するが、日常語としてはほぼ使われず、主に法律文書に登場する点はスペイン語と共通している。' },
  'rescisorio': { es: 'El tribunal aplicó el efecto rescisorio al contrato firmado bajo coacción.', ja: '裁判所は、脅迫のもとで締結された契約に解除効果を適用した。', trivia: 'rescisoria の男性形で、法律用語として「解除の効力を持つ」を意味する。英語の rescissory と語根は同じで、ともにラテン語 rescindere（切り取る）に遡る。' },
  'resco': { es: 'El montañero perdió el equilibrio cerca del resco y tuvo que aferrarse a las rocas para no caer.', ja: '登山者は断崖の近くでバランスを崩し、落ちないように岩にしがみつかなければならなかった。', trivia: 'risco（切り立った岩、断崖）の古い異体字または方言形とされ、語源は諸説あるが、ゲルマン語系の可能性も指摘されている。英語に直接の同語根語はなく、cliff や crag に意味が近い。' },
  'rescoldo': { es: 'Cuando volvimos al campamento al día siguiente, aún quedaban rescoldos en la hoguera apagada.', ja: '翌日キャンプ場に戻ったとき、消えた焚き火にはまだ残り火がくすぶっていた。', trivia: '語源は諸説あり、ラテン語 re-（再び）＋ caldus（熱い）の合成語とする説や、ゴート語起源説もある。英語の embers（残り火）に意味が近く、比喩的に「くすぶる感情」を表す点も両言語で共通している。' },
  'rescontrar': { es: 'El contador tuvo que rescontrar los libros para verificar que las cuentas estuvieran equilibradas.', ja: '経理担当者は、勘定が釣り合っているか確認するために帳簿を照合しなければならなかった。', trivia: 'イタリア語の riscontrare（照合する、確認する）からの借用語とされる商業・簿記用語で、re-（再び）＋ encontrar（出会う、突き合わせる）の構造を持つ。英語では to reconcile accounts や to cross-check がほぼ同義。' },
  'rescripto': { es: 'El rescripto imperial dejaba claro que ningún ciudadano podía apelar esa decisión.', ja: 'その皇帝の勅令は、いかなる市民もその決定に異議申し立てできないことを明示していた。', trivia: 'ラテン語 rescriptum（書き返されたもの）に由来し、re-（返して）＋ scribere（書く）の合成語。英語の rescript も同語根で、古代ローマ法および教皇庁の文書用語として歴史的に重要な単語。' },
  'rescuentro': { es: 'El rescuentro de las cuentas reveló una diferencia de mil euros entre los dos registros.', ja: '帳簿の照合により、2つの記録の間に1000ユーロの差異があることが判明した。', trivia: 'rescontrar の直説法現在1人称単数形であり、語幹が変化する不規則動詞（e→ue）。語自体はイタリア語 riscontro（照合）からの借用語で、英語では account reconciliation に相当する会計用語。' },
  'reseca': { es: 'Después de caminar horas bajo el sol, tenía la garganta reseca y los labios agrietados.', ja: '何時間も炎天下を歩いた後、喉はカラカラで唇はひび割れていた。', trivia: 'resecar（ひどく乾燥させる）の過去分詞・形容詞形で、re-（強意）＋ secar（乾かす）から成る。英語の parched と意味が近く、secar はラテン語 siccare（乾かす）由来で、英語 desiccate とも同語根。' },
  'resecación': { es: 'La resecación del suelo durante el verano afectó gravemente la cosecha de este año.', ja: '夏の間の土壌の過度な乾燥が、今年の収穫に深刻な影響を与えた。', trivia: 'ラテン語 siccare（乾かす）に由来する resecar の名詞形で、中南米では特に「過乾燥」の意味でよく使われる。英語の desiccation（乾燥）と同語根で、医学用語の「切除」を意味する resección（英: resection）とのスペルの混同に注意。' },
  'resecar': { es: 'El viento seco del desierto tiende a resecar la piel en pocos minutos.', ja: '砂漠の乾いた風は、数分で肌をカサカサにしてしまう傾向がある。', trivia: 'ラテン語 siccare（乾かす）に re-（強意の接頭辞）を加えた動詞で、英語の to parch や to dry out に相当。同語根の英語 desiccate（乾燥させる）は de-＋ siccare から来ており、接頭辞が異なるが語根は共通。' },
  'reseco': { es: 'El desierto de Atacama es uno de los paisajes más resecos del planeta.', ja: 'アタカマ砂漠は地球上で最も乾燥した景観のひとつだ。', trivia: 'reseca の男性形で、re-（強意）＋ seco（乾いた）から成る合成形容詞。seco 自体はラテン語 siccus に由来し、英語の siccative（乾燥剤）や desiccate と語根を共有する。' },
  'resección': { es: 'El cirujano realizó una resección del tumor sin dañar los tejidos circundantes.', ja: '外科医は周囲の組織を傷つけることなく腫瘍の切除手術を行った。', trivia: 'ラテン語 resectio（切り取ること）に由来し、re-（再び）＋ secare（切る）の合成語。英語の resection も同語根で、secant（割線）や section（断面）、さらには scissors（はさみ）も同じラテン語 secare に遡る大きな語族に属する。' },
  'reseda': { es: 'La reseda fue muy popular en los jardines europeos del siglo XIX por su fragancia suave y duradera.', ja: 'モクセイソウは、その穏やかで長続きする香りのため、19世紀のヨーロッパの庭園で大変人気を博した。', trivia: 'ラテン語 reseda（植物名）に由来し、語源についてはプリニウスが reseda morbus（病気を癒す）に関連づけたと伝えられるが確証はない。英語でも reseda と呼ばれ、薄い黄緑色を指す色名としても使われる点は両言語で共通。' },
  'reseña': { es: 'Escribí una reseña detallada del restaurante en la aplicación porque el servicio fue excepcional.', ja: 'サービスが格別だったので、そのレストランについてアプリに詳細な口コミを書いた。', trivia: 'ラテン語の resignare（印をつける、記録する）に由来するとされ、re-＋ signum（印・標識）の構造を持つ。英語の review と意味が完全に一致し、sign や signal とも同語根。現代では特にオンラインの「レビュー・口コミ」の意味で頻繁に使われる。' },
  'reseñada': { es: 'La novela reseñada por el crítico literario se convirtió en un éxito de ventas al día siguiente.', ja: 'その文芸評論家にレビューされた小説は、翌日ベストセラーになった。', trivia: 'reseñar の過去分詞・形容詞の女性形で、「レビューされた・批評された」の意味。英語の reviewed と対応し、語根の signum（印）はラテン語に遡る。英語 sign、signal とも遠い親戚にあたる。' },
  'reseñar': { es: 'Me pidieron reseñar el nuevo álbum de la banda para la revista musical más importante del país.', ja: '国内最大の音楽誌のために、そのバンドの新アルバムをレビューするよう依頼された。', trivia: 'ラテン語 resignare（印をつける）を語源とし、re-＋ signum（印）の構造を持つ。英語の to review や to write up に相当し、sign、signal、signature などとも語根を共有する。現代では「口コミ・評価を書く」という意味で日常的に使われる。' },
  'resentida': { es: 'Ella seguía resentida porque nunca recibió el reconocimiento que merecía por su trabajo.', ja: '彼女は自分の仕事に対して当然受けるべき評価を一度も得られなかったことで、いまだに根に持っていた。', trivia: 'resentir の過去分詞・形容詞の女性形で、re-（再び）＋ sentir（感じる）から成る。英語の resentful と完全に対応し、両言語ともラテン語 sentire（感じる）を語根とする。英語 sense、sentiment、sensitive も同じ語族に属する。' },
  'resentidamente': { es: 'Le respondió resentidamente sin querer escuchar ninguna explicación.', ja: '彼女はいかなる説明も聞こうとせず、根に持った様子で言い返した。', trivia: 'resentido に副詞語尾 -mente を付けた形で、「恨みがましく」の意。英語の resentfully と完全対応し、語根はラテン語 sentire（感じる）。-mente はラテン語 mens（心）に由来し、英語の -ly に相当するスペイン語副詞語尾。' },
  'resentido': { es: 'Desde el despido injustificado, quedó muy resentido con la empresa y sus antiguos compañeros.', ja: '不当解雇以来、彼は会社と元同僚に深い恨みを抱いたままだった。', trivia: 'resentida の男性形で、re-（再び）＋ sentir（感じる）に由来する。英語の resentful と対応し、ラテン語 sentire（感じる）を共通語根とする。哲学者ニーチェが使った「ルサンチマン」（フランス語 ressentiment）も同語根で、広く普及した概念。' },
  'resentimiento': { es: 'El resentimiento que acumuló durante años finalmente estalló en una discusión familiar.', ja: '長年にわたって蓄積した恨みが、ついに家族の口論の中で爆発した。', trivia: 'ラテン語 sentire（感じる）に由来し、英語の resentment と完全に対応する語。ニーチェが『道徳の系譜』で論じた「ルサンチマン」（フランス語由来）も同根で、スペイン語 resentimiento で哲学的文脈においても使われる。' },
  'resentir': { es: 'La economía comenzó a resentirse tras varios meses de incertidumbre política en el país.', ja: '国内で数か月にわたる政治的不安が続いた後、経済は悪影響を受け始めた。', trivia: 'ラテン語 re-（再び）＋ sentire（感じる）に由来し、英語の to feel the effects of や to suffer から意味が近い。英語 resent（憤る）と同語根だが、スペイン語では「再帰動詞として痛みや影響が再発する」という意味で使われることが多く、微妙なニュアンスの違いがある。' },
  'resepe': { es: 'El botánico identificó un resepe poco común entre los arbustos del valle.', ja: '植物学者は谷間の低木の中にあまり見られないレセペを同定した。', trivia: '極めて希少な植物学の古語・地方語で、語源は明確でなく諸説ある。英語に相当する直接の対訳語はなく、shrub（低木）や thicket（茂み）で代替される。現代スペイン語の一般語彙ではほとんど使われない。' },
  'reserva': { es: 'Hice una reserva en el restaurante con dos semanas de antelación porque siempre está lleno.', ja: 'そのレストランはいつも満席なので、2週間前に予約を入れた。', trivia: 'ラテン語 reservare（取っておく）に由来し、re-（再び・保持して）＋ servare（守る、保つ）の合成語。英語の reservation / reserve と同語根で、conserve（保存する）や preserve（保護する）も同じ servare を語根とする大きな語族に属する。' },
  'reservación': { es: 'Hice una reservación en el restaurante para esta noche.', ja: '今夜のレストランを予約した。', trivia: 'ラテン語 reservare（取っておく）から派生した英語 reservation と同語根。スペイン本国では reserva が一般的だが、中南米では reservation を直接取り込んだ reservación が広く使われる。' },
  'reservado': { es: 'Es una persona muy reservada que no habla mucho de su vida personal.', ja: '彼女はとても控えめな人で、プライベートなことをあまり話さない。', trivia: '動詞 reservar の過去分詞で、「取っておかれた」が原義。英語の reserved（席・人物とも「控えめな」）と完全に同じ二重の意味を持つ国際的なコグネート。' },
  'reservar': { es: 'Deberías reservar el vuelo con anticipación para conseguir un buen precio.', ja: 'いい値段で取れるように、早めにフライトを予約しておいたほうがいい。', trivia: 'ラテン語 reservare（re＝再び + servare＝保存する）が語源で、英語の reserve および book（予約する）に相当する。英語の preserve（保存する）も同じ servare から来ており、共通の語根を持つ。' },
  'reservataria': { es: 'Como reservataria, ella tiene derecho a recibir la legítima de la herencia.', ja: '遺留分権利者として、彼女は相続財産の法定相続分を受け取る権利を持つ。', trivia: 'ラテン語 reservare に法律上の代理人を示すサフィックス -ario/-aria を付けた造語で、スペイン語・ポルトガル語圏の相続法に特有の術語。英語の legal heir や forced heir に相当するが、英語には完全対応の単一語がない。' },
  'reservatario': { es: 'El reservatario debe presentar los documentos necesarios ante el notario.', ja: '遺留分権利者は公証人の前に必要書類を提出しなければならない。', trivia: 'reservataria の男性形。ラテン語 reservare から派生した法律用語で、英語には forced heir や compulsory heir という表現はあるが reservatario に対応する一語は存在せず、英語圏とのスペイン語圏の相続法体系の違いを反映している。' },
  'reservista': { es: 'Los reservistas fueron convocados para participar en las maniobras militares.', ja: '予備役兵たちが軍事演習に参加するために召集された。', trivia: 'reservar（取っておく）に職業・所属を示す接尾辞 -ista を付けた語で、英語の reservist と同語根のコグネート。-ist/-ista はギリシャ語由来で、英語・スペイン語ともに多くの職業名に使われる共通のパターン。' },
  'resfriadera': { es: 'El tabernero ponía el vino en la resfriadera para servirlo bien frío.', ja: '酒場の主人はワインをよく冷えた状態で出すために冷却容器に入れていた。', trivia: '動詞 resfriar（冷やす）に道具・場所を示す接尾辞 -dera を付けた古風な語。英語の cooler や ice bucket に相当するが、現代スペイン語ではほぼ使われない地方語・古語で、英語に直接対応するコグネートは存在しない。' },
  'resfriado': { es: 'Me quedé en casa porque tengo un resfriado bastante fuerte.', ja: 'かなりひどい風邪を引いているので家にいた。', trivia: 'resfriar（冷やす、冷える）の過去分詞が名詞化した語で、「体が冷えた状態」が原義。英語の cold（風邪）も「冷たい」から転じた意味で、概念の発展が英語とスペイン語でほぼ平行している興味深い例。' },
  'resfriadura': { es: 'La resfriadura que sufrió en invierno lo tuvo en cama varios días.', ja: '冬に引いた風邪で彼は数日間寝込んだ。', trivia: 'resfriar に抽象名詞を作る接尾辞 -dura を付けた語で、resfriado よりも古風・文語的。英語の cold や common cold に相当するが、英語では -ure（closure, fracture など）が同様の役割を持つ接尾辞として機能している。' },
  'resfriamiento': { es: 'Se observa un resfriamiento en las relaciones diplomáticas entre los dos países.', ja: '両国間の外交関係の冷え込みが見られる。', trivia: 'resfriar に動作・結果を示す接尾辞 -miento を付けた語。英語の cooling や chilling に相当し、英語の -ment（冷却→ cooling）と同じ役割をスペイン語では -miento が担う。物理的・比喩的両方の冷却に使える点も英語と共通。' },
  'resfriar': { es: 'Sal a la calle abrigado o te vas a resfriar con este frío.', ja: 'この寒さで風邪を引くから、暖かくして外に出なさい。', trivia: 'ラテン語 refrigerare（re＋frigus＝冷たさ）が変化した語で、英語の refrigerate（冷蔵する）と同じ語根 frigus を共有している。refrigerator（冷蔵庫）の語源でもあり、resfriar との関係を知ると単語の見え方が変わる。' },
  'resguardar': { es: 'Se refugiaron bajo el árbol para resguardarse de la lluvia.', ja: '雨をしのぐために木の下に避難した。', trivia: 're＋es＋guardar（守る）の複合語で、guardar はゲルマン語 wardōn（見張る）が語源。英語の guard および ward（病棟・後見人）と同語根のコグネートで、guard がラテン語を経由せずにロマンス諸語に入った珍しい例の一つ。' },
  'resguardo': { es: 'El cajero me dio un resguardo con el número de operación de la transferencia.', ja: '窓口係が振込みの取引番号が記載された控えを渡してくれた。', trivia: 'resguardar の派生名詞で、「保護」と「領収書・控え」という二つの意味を持つ。英語の receipt（領収書）はラテン語 recipere 由来で語根は異なるが、voucher や shelter などの概念に対応する。ゲルマン語系の guard と同語根。' },
  'residencia': { es: 'Los estudiantes extranjeros pueden vivir en la residencia universitaria durante el primer año.', ja: '外国人学生は1年目の間、大学の寮に住むことができる。', trivia: 'ラテン語 residere（re＋sedere＝座る・落ち着く）が語源で、英語の residence・residency と完全なコグネート。英語の sedentary（座りがちな）や sediment（堆積物）も同じ sedere から来ており、「腰を落ち着ける」という原義を共有している。' },
  'residencial': { es: 'Buscan una vivienda en una zona residencial tranquila a las afueras de la ciudad.', ja: '彼らは都市郊外の静かな住宅地に住居を探している。', trivia: '英語の residential とほぼ同形のコグネートで、ラテン語 residere 由来。-al/-ial という形容詞語尾はラテン語起源で、英語・スペイン語ともに広く使われる（commercial/comercial、national/nacional など）。' },
  'residenciar': { es: 'En la época colonial, los virreyes podían ser residenciados al final de su mandato.', ja: '植民地時代には、副王は任期終了後に職務について審査されることがあった。', trivia: 'スペイン植民地行政に特有の法的手続き「residencia（査問）」を動詞化した語。英語には audit（監査する）や impeach（弾劾する）が部分的に相当するが、この植民地行政上の手続きに対応する英単語はなく、スペイン語法制史の固有概念を示す。' },
  'residente': { es: 'Los residentes del barrio se reunieron para hablar del nuevo proyecto de construcción.', ja: '住民たちが新しい建設プロジェクトについて話し合うために集まった。', trivia: 'ラテン語 residere の現在分詞形が語源で、英語の resident と完全なコグネート。医学の文脈では「研修医」を意味する点も英語の resident（医学研修医）と共通で、両言語が同じ意味拡張を経験した例。' },
  'residir': { es: 'El secreto del éxito reside en la constancia y el trabajo duro.', ja: '成功の秘訣は粘り強さと努力の中にある。', trivia: 'ラテン語 residere（re＋sedere＝座る）が語源で、英語の reside と同語根のコグネート。「本質がそこに宿る」という比喩的用法も英語の reside in と完全に対応しており、英語学習者にとって覚えやすい語の一つ。' },
  'residual': { es: 'Hay que tener en cuenta los efectos residuales del medicamento antes de conducir.', ja: '運転する前に薬の残留効果を考慮しなければならない。', trivia: 'ラテン語 residuum（残り）から派生した英語 residual と同形・同義のコグネート。統計学での「残差」という意味も英語・スペイン語で共通して使われており、学術分野での国際的な語彙の共有を示す例。' },
  'residuo': { es: 'Las fábricas deben gestionar correctamente los residuos industriales.', ja: '工場は産業廃棄物を適切に管理しなければならない。', trivia: 'ラテン語 residuum（残ったもの）が語源で、英語の residue と同語根のコグネート。数学の「余り」という意味も両言語で共通する。英語の residue が主に化学・法律で使われるのに対し、スペイン語の residuo は廃棄物全般にも幅広く使われる。' },
  'resignación': { es: 'Aceptó la derrota con resignación y felicitó a su rival.', ja: '彼は諦めを持って敗北を受け入れ、対戦相手を祝福した。', trivia: 'ラテン語 resignare（re＋signare＝印を消す→権利を手放す）が語源で、英語の resignation（辞任・諦め）と同語根のコグネート。「職を辞する」と「諦める」という二重の意味が英語・スペイン語で平行して発展した。' },
  'resignada': { es: 'Ella estaba resignada a perder el trabajo y empezó a buscar nuevas oportunidades.', ja: '彼女は仕事を失うことを受け入れ、新たなチャンスを探し始めた。', trivia: 'resignar の女性形過去分詞で形容詞として使われる。英語の resigned（諦めた・辞した）と同語根のコグネートで、「印を消す＝権利を放棄する」というラテン語の原義が「諦める」に転じた経緯は英語・スペイン語で共通している。' },
  'resignadamente': { es: 'Suspiró resignadamente y aceptó que no había nada más que hacer.', ja: '彼はため息をついて諦めたように、もう何もできないことを受け入れた。', trivia: 'resignado に副詞語尾 -mente を付けた語で、英語の resignedly に相当するコグネート。英語の -ly に対応するスペイン語の -mente はラテン語 mens（心・精神）に由来し、「諦めた心持ちで」という原義が生きている。' },
  'resignado': { es: 'El empleado parecía resignado a trabajar horas extra sin paga.', ja: 'その従業員は残業代なしで残業することを甘んじて受け入れているようだった。', trivia: 'resignar の男性形過去分詞で形容詞として用いられる。英語の resigned と同語根のコグネートで、ラテン語 resignare（印を消す→権利を放棄する）が語源。英語では resigned は「辞任した」という職務上の意味でも頻繁に使われる点がスペイン語と異なる。' },
  'resignar': { es: 'Tuve que resignarme a cancelar las vacaciones por el trabajo.', ja: '仕事のせいで休暇をキャンセルするしかなかった。', trivia: 'ラテン語 resignare（re＋signare＝印を消す・封印を解く）が語源で、英語の resign と同語根のコグネート。「自分自身に～を受け入れさせる」という再帰動詞の用法が最も一般的で、英語の resign oneself to に対応する。' },
  'resina': { es: 'Los pinos producen resina que se usa para fabricar barnices y productos industriales.', ja: '松の木は樹脂を産出し、ニスや工業製品の製造に使われる。', trivia: 'ラテン語 resina に由来し、英語の resin と完全に同語源の国際的な語。古代から船の防水や楽器の弦用松脂として利用されてきた。' },
  'resinosa': { es: 'La madera resinosa del pino es difícil de pintar porque el barniz no adhiere bien.', ja: '松の樹脂を含んだ木材は、ニスがうまく密着しないので塗装が難しい。', trivia: 'ラテン語 resinosus（樹脂の多い）に由来し、英語の resinous と同語根。スペイン語では女性形 resinosa・男性形 resinoso と語尾が変化する点が英語との違い。' },
  'resinoso': { es: 'El aroma resinoso del bosque de pinos me resulta muy relajante.', ja: '松林の樹脂っぽい香りはとてもリラックスできる。', trivia: 'ラテン語 resinosus に由来し、英語の resinous に対応する男性形形容詞。英語では性の区別がないが、スペイン語では修飾する名詞の性に合わせて resinoso / resinosa と変化する。' },
  'resistencia': { es: 'Los atletas de fondo entrenan la resistencia durante meses para preparar un maratón.', ja: '長距離選手たちはマラソンに備えて、何か月もかけてスタミナを鍛える。', trivia: 'ラテン語 resistentia に由来し、英語の resistance と同語源。フランス語を経由して英語にも入った語で、第二次大戦中の「レジスタンス運動」として両言語で同じ意味で使われた歴史的背景がある。' },
  'resistente': { es: 'Este tejido resistente al agua es ideal para hacer ropa de senderismo.', ja: 'この防水性の高い生地はハイキングウェアを作るのに最適だ。', trivia: 'ラテン語現在分詞 resistens に由来し、英語の resistant と同語根。英語では -ant で終わるのに対し、スペイン語は -ente となる点は、ラテン語第三活用動詞の分詞語尾の違いを反映している。' },
  'resistible': { es: 'Ese olor a chocolate recién hecho no es resistible para nadie.', ja: '焼きたてのチョコレートの香りは誰にも我慢できない。', trivia: 'ラテン語 resistere（抵抗する）＋接尾辞 -ible に由来し、英語の resistible と同語根。実際には irresistible（抵抗できない）の形で使われることの方がはるかに多く、英語でも同様の傾向がある。' },
  'resistidero': { es: 'Durante el resistidero de agosto, los lugareños prefieren no salir a la calle hasta que cae la tarde.', ja: '8月の猛烈な暑さの時間帯、地元の人たちは夕方になるまで外に出ないようにしている。', trivia: 'スペインの方言語彙で、resistir（耐える）から派生した語。英語には直接対応する単語がなく、dog days（canícula）や heat of the day で表現される。地中海性気候特有の生活感覚が反映された地域色豊かな語。' },
  'resistir': { es: 'No pude resistir la tentación de comerme el último trozo de tarta.', ja: 'ケーキの最後のひとかけを食べる誘惑に抵抗できなかった。', trivia: 'ラテン語 resistere（re-「反対に」＋sistere「立つ」）に由来し、英語の resist と同語源。ラテン語 sistere はギリシャ語 histanai（立たせる）とも関連し、英語の assist、consist、persist なども同じ語根をもつ。' },
  'resistón': { es: 'El niño es muy resistón y nunca quiere irse a la cama a su hora.', ja: 'その子はとても頑固で、決まった時間に寝ようとしない。', trivia: 'resistir（耐える・抵抗する）に口語的な増大接尾辞 -ón を加えた派生語。英語では stubborn や headstrong に相当するが、スペイン語の -ón 接尾辞は「やたら〜する人・物」という口語ニュアンスを加える点が特徴的。' },
  'resma': { es: 'Necesitamos comprar tres resmas de papel para la impresora de la oficina.', ja: 'オフィスのプリンター用に紙を3連（1500枚）買う必要がある。', trivia: 'アラビア語 rizma（束）に由来し、スペイン語を経由して英語の ream（紙の連）として借用された語。英語の ream がスペイン語から来ているという点で、逆輸入的な関係が興味深い。' },
  'resobrar': { es: 'Después de la fiesta, resobraba comida por todas partes y no sabíamos qué hacer con ella.', ja: 'パーティーの後、食べ物があちこちに山ほど余っていて、どうすればいいか分からなかった。', trivia: 'sobrar（余る）に強意の接頭辞 re- を加えた語で「余りに余る」という意味を強調する。英語には直接対応する動詞はなく、be left over in abundance などで表現する。re- の強意用法はスペイン語の口語によく見られる。' },
  'resol': { es: 'El resol de la tarde me impedía ver bien la pantalla del móvil.', ja: '午後の照り返しがひどくて、スマホの画面がよく見えなかった。', trivia: 'スペイン語の sol（太陽）に接頭辞 re-（反射・繰り返し）を加えた合成語と考えられる。英語では sun glare や reflected sunlight に相当するが、一語で表す語がない点でスペイン語の語彙の豊かさが光る。' },
  'resoplada': { es: 'Con una resoplada de impaciencia, el jefe cerró la carpeta y salió de la reunión.', ja: '上司は苛立ちのあまり大きく息を吐いてファイルを閉じ、会議室を出て行った。', trivia: 'resoplar（荒く息をする）の過去分詞から派生した名詞・形容詞。英語の snort や puff に相当するが、英語では動詞が主で対応する名詞形は複数ある（snort, puff, huff）。スペイン語では -ada 接尾辞が「一回の行為」を表す点が特徴。' },
  'resoplar': { es: 'El caballo resopló y sacudió la cabeza antes de comenzar la carrera.', ja: '馬はレースが始まる前に鼻を鳴らして頭を振った。', trivia: 'soplar（吹く）に強意の re- を加えた語。英語の snort（鼻を鳴らす）、pant（ぜいぜい息をする）、puff（ふうふう言う）に相当するが、スペイン語 resoplar は一語でこれらの意味を兼ねる多義的な動詞。' },
  'resoplido': { es: 'Se oyó el resoplido del motor cuando el camión comenzó a subir la cuesta.', ja: 'トラックが坂を上り始めたとき、エンジンのうなり声が聞こえた。', trivia: 'resoplar の派生名詞で、英語の snort や puff に相当する。-ido という接尾辞はスペイン語で音や行為を名詞化する際によく使われ（ladrido「吠え声」、silbido「口笛」など）、英語には対応する規則的な接尾辞がない点が興味深い。' },
  'resolana': { es: 'Los ancianos del pueblo se reunían en la resolana de la plaza para charlar por las tardes.', ja: '村の老人たちは夕方になると、広場の日当たりの良い場所に集まって雑談していた。', trivia: 'sol（太陽）と接頭辞 re-（反射）から形成されたと考えられる語で、resol と同語族。英語には glare や sunny spot でしか表せない概念を一語で表す。地中海地域の生活文化を映した語彙の一つ。' },
  'resolar': { es: 'Llevaré estos zapatos al zapatero para que los resole, porque todavía están en buen estado.', ja: 'この靴はまだ状態が良いので、靴職人に靴底を張り替えてもらいに持って行く。', trivia: 'suela（靴底）に由来し、英語の sole（靴底）と同語根のラテン語 solea から来ている。英語では resole という動詞も存在し、スペイン語と英語でほぼ同じ構造の語が使われている点が面白い。' },
  'resoluble': { es: 'El conflicto parecía complicado, pero resultó ser perfectamente resoluble mediante el diálogo.', ja: 'その対立は複雑に見えたが、対話によって十分解決可能であることが分かった。', trivia: 'ラテン語 resolvere（解く・ほどく）＋接尾辞 -ible に由来し、英語の resolvable や soluble と同語根。英語では resoluble は化学用語に限定されることが多く、一般的には resolvable を用いる点が異なる。' },
  'resolución': { es: 'La resolución de la cámara nueva es tan alta que puedo ver cada detalle con claridad.', ja: '新しいカメラの解像度はとても高く、細部までくっきり見える。', trivia: 'ラテン語 resolutio（解くこと）に由来し、英語の resolution と完全に同語源。英語の New Year\'s resolution（新年の誓い）に相当するスペイン語は propósito de Año Nuevo だが、resolución も同義で使える。' },
  'resolutiva': { es: 'Necesitamos una persona resolutiva que sepa tomar decisiones rápidas bajo presión.', ja: 'プレッシャーの下で素早く判断を下せる、決断力のある人材が必要だ。', trivia: 'ラテン語 resolutivus に由来し、英語の resolute（断固とした）と同語根。英語では resolute が形容詞として定着しているのに対し、スペイン語では resuelto / resuelta がより口語的に「決断力がある」の意で使われることも多い。' },
  'resolutivo': { es: 'Un buen médico debe ser resolutivo y saber actuar con rapidez en situaciones de emergencia.', ja: '優れた医師は決断力があり、緊急時に迅速に対応できなければならない。', trivia: 'ラテン語 resolutivus の男性形に由来し、英語の resolute や decisive に対応する。英語 resolute がラテン語 resolutus（解き放たれた）から来ているように、両語は同じ語根 resolvere を共有している。' },
  'resolutoria': { es: 'El contrato incluye una cláusula resolutoria que permite cancelarlo en caso de incumplimiento.', ja: 'その契約には、不履行の場合に解除できる解除条件条項が含まれている。', trivia: 'ラテン語 resolutorius に由来する法律用語で、英語の resolutory または defeasance clause に相当する。英語の法律用語では resolutory condition（解除条件）として使われ、スペイン語法学との共通の語源をもつ。' },
  'resolutorio': { es: 'El juez aplicó el plazo resolutorio establecido en el contrato para declarar su nulidad.', ja: '裁判官は契約に定められた解除期限を適用して、契約の無効を宣言した。', trivia: 'ラテン語 resolutorius の男性形に由来する法律専門用語。英語では resolutory として使われることがあるが、一般的には終了条件（termination clause）や解除条件（defeasance）で表現することが多い。' },
  'resollar': { es: 'Después de subir corriendo las escaleras, el anciano tuvo que parar un momento para resollar.', ja: '階段を駆け上がった後、老人はぜいぜいと息をつくために一瞬立ち止まらなければならなかった。', trivia: 'ラテン語 re-（再び）＋sufflare（吹く）に由来すると考えられ、英語の breathe heavily や pant に相当する。英語の insufflate（息を吹き込む）と遠い親戚関係にあり、どちらも「吹く」を意味するラテン語 flare を語根にもつ。' },
  'resollo': { es: 'Se oía el resollo del corredor al acercarse a la meta tras varios kilómetros de carrera.', ja: '数キロを走った後、ゴールに近づくランナーの荒い息づかいが聞こえた。', trivia: 'resollar（荒く息をする）から派生した名詞で、英語の heavy breathing や panting に相当する。英語では一語で表現する日常語が乏しく、breath や pant を使うが、スペイン語の resollo はその音まで想起させる音象徴的なニュアンスをもつ。' },
  'resonancia': { es: 'El discurso del presidente tuvo una enorme resonancia en toda la sociedad.', ja: '大統領の演説は社会全体に大きな反響を呼んだ。', trivia: 'ラテン語 resonantia（響き返すこと）に由来し、英語の resonance と同語根。医学用語 resonancia magnética（MRI）は英語の magnetic resonance imaging に対応する。' },
  'resonante': { es: 'El equipo logró una victoria resonante que nadie esperaba.', ja: 'チームは誰も予想していなかった輝かしい勝利を収めた。', trivia: 'ラテン語 resonans（鳴り響く）が語源で、英語の resonant と同語根。英語では resounding victory（目覚ましい勝利）という表現もよく使われる。' },
  'resonar': { es: 'Las palabras de su abuela aún resonaban en su memoria años después.', ja: '祖母の言葉は何年も経った後も彼の記憶の中で響き続けていた。', trivia: 'ラテン語 resonare（re-「再び」＋ sonare「鳴る」）が語源で、英語の resonate・resound と同語根。語幹母音変化を起こす二重母音化動詞で、o→ue と変化する（resueno）。' },
  'resorber': { es: 'El organismo es capaz de resorber ciertos tejidos dañados de forma natural.', ja: '生体は損傷した組織の一部を自然に再吸収する能力を持っている。', trivia: 'ラテン語 resorbere（re-「再び」＋ sorbere「吸い込む」）が語源で、英語の resorb と同語根の医学・科学用語。英語の absorb（吸収する）も同じ sorbere に由来する。' },
  'resorción': { es: 'La resorción ósea excesiva puede provocar osteoporosis con el tiempo.', ja: '過剰な骨の再吸収は時間の経過とともに骨粗しょう症を引き起こす可能性がある。', trivia: 'ラテン語 resorbere の名詞形 resortio に由来し、英語の resorption と同語根の医学術語。骨代謝の文脈で頻出し、英語でも bone resorption（骨吸収）という形でよく使われる。' },
  'resorte': { es: 'El mecánico ajustó el resorte del mecanismo para que funcionara correctamente.', ja: '整備士はメカニズムのバネを調整して正常に動作するようにした。', trivia: 'フランス語 ressort（バネ、手段）を経由して中世ラテン語に遡る語で、英語の resort（手段、リゾート）と同語根だが意味が異なる好例のコグネート。英語で spring や resort と訳し分ける必要がある。' },
  'respaldar': { es: 'El gobierno decidió respaldar económicamente a las pequeñas empresas afectadas.', ja: '政府は影響を受けた中小企業を経済的に支援することを決定した。', trivia: 'スペイン語 espalda（背中）＋ re- に由来し、「背中を支える」が原義。英語では support・back up・endorse と訳されるが、英語の back（背中）も同様に「後ろから支える」という動詞義を持つ点が共通している。' },
  'respaldo': { es: 'El proyecto avanzó gracias al respaldo financiero de varios inversores.', ja: 'そのプロジェクトは複数の投資家からの財政的支援のおかげで前進した。', trivia: 'espalda（背中）と同語根で「背もたれ」「後ろ盾」が基本義。英語の backing（後ろ盾）と発想が共通しており、IT分野では backup の意味でも使われる。英語 spine（背骨）とは語根が異なる。' },
  'respectar': { es: 'En lo que respecta a la educación, el país ha hecho grandes avances.', ja: '教育に関して言えば、その国は大きな進歩を遂げた。', trivia: 'ラテン語 respectare（振り返る、考慮する）が語源で、英語の respect と同語根。ただし現代スペイン語では en lo que respecta a...（〜に関しては）という定型句で主に三人称のみ使われる点が特徴的。' },
  'respectiva': { es: 'Los dos equipos volvieron a sus respectivas ciudades después del torneo.', ja: 'トーナメントが終わり、2チームはそれぞれの都市へ戻った。', trivia: 'ラテン語 respectivus に由来し、英語の respective と同語根。英語でも Spanish and English are spoken in their respective countries（それぞれの国でスペイン語と英語が話される）のように使い方が非常に似ている。' },
  'respectivamente': { es: 'El primero y el segundo lugar los ocuparon Ana y Carlos, respectivamente.', ja: '1位と2位はそれぞれアナとカルロスが占めた。', trivia: 'ラテン語 respectivus＋-mente（副詞語尾）から形成され、英語の respectively と語源・用法ともにほぼ同一。英語・スペイン語ともにリストを対応させて示す際の定番表現として使われる。' },
  'respectivo': { es: 'Cada alumno se sentó en su respectivo lugar al comenzar el examen.', ja: '試験が始まると各生徒はそれぞれの席に座った。', trivia: 'respectiva の男性形で、ラテン語 respectivus（考慮された、それぞれの）が語源。英語の respective と完全な同語根であり、スペリングも非常に近い。' },
  'respecto': { es: 'Con respecto a tu pregunta, te responderé mañana con más detalle.', ja: 'あなたの質問に関しては、明日もっと詳しくお答えします。', trivia: 'ラテン語 respectus（振り返ること、配慮）が語源で、英語の respect と同語根。ただし現代スペイン語では単独で「尊敬」の意味では使わず、con respecto a（〜に関して）という前置詞句の形で主に使われる。' },
  'respetabilidad': { es: 'Su larga trayectoria profesional le otorgó una gran respetabilidad en el sector.', ja: '長い職業的キャリアが彼に業界での高い品格を与えた。', trivia: 'ラテン語 respectare＋-bilitas から形成され、英語の respectability と同語根・同構造。英語でも「社会的に認められた品格・地位」を指し、ヴィクトリア朝的な道徳観と結びついて使われることが多い。' },
  'respetable': { es: 'El cantante se presentó ante un respetable público que llenó el teatro.', ja: '歌手は劇場を埋め尽くした大勢の観客の前でパフォーマンスを披露した。', trivia: 'ラテン語 respectare＋-bilis に由来し、英語の respectable と同語根。スペイン語では名詞的に「観客・聴衆」の意味でも使われる点が英語と異なる独特の用法。' },
  'respetada': { es: 'Es una profesora muy respetada por todos sus estudiantes y colegas.', ja: '彼女はすべての学生と同僚から非常に尊敬されている先生だ。', trivia: 'respetar の過去分詞の女性形で、ラテン語 respectare に由来。英語の respected と同語根・同用法で、形容詞として「定評のある、重んじられている」の意味を持つ。' },
  'respetado': { es: 'El médico es un profesional respetado en toda la comunidad.', ja: 'その医師はコミュニティ全体で尊敬されている専門家だ。', trivia: 'respetada の男性形で、英語の respected と同語根。ラテン語 respectare（re-「再び」＋ spectare「見る」）が語源で、文字どおり「振り返って見られる人物」が原義。' },
  'respetar': { es: 'Es fundamental respetar las normas de convivencia en los espacios públicos.', ja: '公共の場では共存のルールを守ることが不可欠だ。', trivia: 'ラテン語 respectare（振り返る、配慮する）が語源で、英語の respect と同語根。英語では respect は名詞・動詞兼用だが、スペイン語では名詞 respeto と動詞 respetar が形の上でも明確に区別される。' },
  'respetuosa': { es: 'Siempre ha mantenido una actitud respetuosa hacia las personas mayores.', ja: '彼女はいつも年長者に対して礼儀正しい態度を保ってきた。', trivia: 'ラテン語 respectuosus に由来し、英語の respectful と同語根。英語では -ful 語尾を使うのに対し、スペイン語では -uoso/-uosa という接尾辞が用いられる点が対照的。' },
  'respetuosamente': { es: 'Le pido respetuosamente que reconsidere su decisión.', ja: '恐れながら、あなたの決定を再考されることをお願い申し上げます。', trivia: 'respetuoso＋-mente（副詞語尾）から形成され、英語の respectfully と同語根・同用法。英語のフォーマルなメール締め文句 Respectfully yours に対応するスペイン語表現としても使われる。' },
  'respetuoso': { es: 'Es importante ser respetuoso con las costumbres del país que visitas.', ja: '訪れる国の習慣を尊重することが大切だ。', trivia: 'respetuosa の男性形で、英語の respectful と同語根。英語 -ful に対してスペイン語 -oso という形容詞語尾の対応は、careful/cuidadoso、powerful/poderoso など多くの語で見られるパターン。' },
  'respeto': { es: 'El respeto mutuo es la base de cualquier relación sana.', ja: '相互の敬意は健全な関係の基盤である。', trivia: 'ラテン語 respectus（振り返ること、配慮）が語源で、英語の respect と同語根かつほぼ同形。ただし英語の respect には「尊重する」という動詞用法もあるが、スペイン語では動詞は respetar と別語形になる。' },
  'réspice': { es: 'El jefe le dio un réspice delante de todos por llegar tarde otra vez.', ja: '上司は彼がまた遅刻したことで皆の前でひどく叱責した。', trivia: 'ラテン語の命令形 respice（「見よ、顧みよ」re-＋ specere「見る」）がそのまま語彙化したもので、英語には対応する直接の借用語はない。「鏡を見ろ」という戒めの含意から「手厳しい一喝」の意味に転じた。' },
  'respiración': { es: 'Los ejercicios de respiración ayudan a reducir el estrés y la ansiedad.', ja: '呼吸の練習はストレスや不安を軽減するのに役立つ。', trivia: 'ラテン語 respiratio（re-「繰り返し」＋ spirare「息をする」）が語源で、英語の respiration と同語根。spirare はスペイン語 espíritu（精神）や英語 spirit（魂、気概）とも同語根で、「息・命」と「精神」が古来結びついていた。' },
  'respiradero': { es: 'El sótano no tenía ventanas, pero un pequeño respiradero en la pared permitía que entrara algo de aire fresco.', ja: '地下室には窓がなかったが、壁の小さな通気孔から新鮮な空気が少し入ってきた。', trivia: 'ラテン語 respirare（息をする）に由来し、接尾辞 -dero が「場所・道具」を表す。英語の vent や air vent に相当するが、英語 respire（呼吸する）も同じ語根を持つ。' },
  'respirador': { es: 'Los médicos que trataban a los pacientes graves en la UCI usaban respirador y gafas de protección en todo momento.', ja: 'ICUで重症患者を治療する医師たちは、常に人工呼吸器と保護メガネを着用していた。', trivia: 'ラテン語 respirare から派生。英語の respirator と同語根の国際語で、スペイン語でも医療機器（ventilator）と防護マスクの両方を指せる点が英語と共通している。' },
  'respiradora': { es: 'La máscara respiradora que llevaba el operario lo protegía de los vapores tóxicos en la fábrica.', ja: '作業員が装着していた防塵マスクが、工場内の有毒蒸気から彼を守っていた。', trivia: 'respirador の女性形で、主に形容詞として「呼吸に関する・呼吸を助ける」という意味で使われる。英語の respiratory と同語根で、ラテン語 spirare（息をする）が共通の起源。' },
  'respirar': { es: 'Cuando supo que había aprobado el examen, respiró aliviada y se le escapó una sonrisa.', ja: '試験に合格したとわかったとき、彼女はほっと息をつき、思わず笑みがこぼれた。', trivia: 'ラテン語 respirare（re-「再び」+ spirare「息をする」）から直接来ており、英語の breathe とは語根が異なる。英語では respire という同語根の語もあるが、日常ではほぼ breathe を使う。' },
  'respiratoria': { es: 'El médico le diagnosticó una infección respiratoria leve y le recetó reposo durante una semana.', ja: '医師は彼女に軽い呼吸器感染症と診断し、1週間の安静を処方した。', trivia: 'ラテン語 respiratorius（呼吸に関する）に由来。英語の respiratory と完全に同語根の国際的な医学用語で、スペイン語・英語ともに医療分野でそのまま使われる。' },
  'respiratorio': { es: 'El sistema respiratorio humano está formado por los pulmones, la tráquea y los bronquios.', ja: '人間の呼吸器系は、肺、気管、気管支から構成されている。', trivia: 'respiratoria の男性形。英語 respiratory と同一の語根（ラテン語 respirare）を持ち、スペルも非常に似ているため医学・生物学の分野では国際的に通じやすいコグネートである。' },
  'resplandor': { es: 'El resplandor del sol al atardecer tiñó el cielo de tonos anaranjados y rojizos.', ja: '夕暮れ時の太陽の輝きが、空をオレンジや赤みがかった色に染めた。', trivia: 'ラテン語 resplendere（re-「再び」+ splendere「輝く」）に由来する。英語 splendor と同語根で、英語には resplendence という形もある。英語の glow（温かい光）に対し、resplandor はより強い・眩しい光のニュアンスを持つ。' },
  'resplandeciente': { es: 'La novia entró al salón resplandeciente, con un vestido blanco bordado que capturaba todas las miradas.', ja: '花嫁は白い刺繍のドレスをまとい、輝くように会場に入ってきて、全員の視線を引き付けた。', trivia: '動詞 resplandecer の現在分詞形から来た形容詞。英語の resplendent（華やかに輝く）と同語根で、ラテン語 splendere（輝く）が共通の起源。英語でも resplendently という副詞形で使われる。' },
  'resplandecer': { es: 'Sus ojos resplandecían de alegría cuando vio a su familia reunida después de tantos años.', ja: '長年ぶりに家族が集まったのを見て、彼の目は喜びで輝いていた。', trivia: 'ラテン語 resplendere に由来し、英語の resplend（ほとんど使われない）よりも shine や gleam に相当する。英語 splendid（素晴らしい）と同語根で、「輝き＝素晴らしさ」というメタファーを共有している。' },
  'respondida': { es: 'Todas las preguntas del cuestionario fueron respondidas correctamente por el alumno más aplicado de la clase.', ja: 'アンケートの全質問は、クラスで最も勤勉な生徒によって正確に回答された。', trivia: '動詞 responder（答える）の過去分詞女性形。ラテン語 respondere（re-「再び」+ spondere「約束する」）に由来し、英語の respond・response・responsible はすべて同語根の兄弟語である。' },
  'respondido': { es: 'Todavía no ha respondido a mi correo electrónico, aunque ya han pasado tres días.', ja: 'もう3日が経つのに、彼はまだ私のメールに返信していない。', trivia: 'responder の過去分詞男性形で、スペイン語の複合時制（haber + 過去分詞）で使われる。英語の responded と同語根で、ラテン語 spondere（誓う・保証する）が共通の起源。' },
  'respondona': { es: 'La profesora regañó a la niña respondona porque no paraba de contestar mal a sus compañeros.', ja: '先生は口答えばかりする女の子を叱った。彼女はクラスメートに失礼な言い返しをやめなかったからだ。', trivia: 'responder（答える）に強調の接尾辞 -ón/-ona が加わった形で、「過度に言い返す人」という否定的なニュアンスを持つ。英語に直訳できる同語根語はなく、cheeky や mouthy に相当するが、語構造としては英語の respondent（回答者）と同根。' },
  'respondón': { es: 'Mi hermano pequeño siempre ha sido muy respondón; jamás acepta una crítica sin contestar.', ja: '弟はいつも口答えばかりで、批判を言い返さずに受け入れたことがない。', trivia: 'responder の派生語で、拡大・強調の接尾辞 -ón がついた男性形。英語には直接の対応語がなく、argumentative や lippy（英俗）が近い。ラテン語 respondere（re- + spondere）が語源。' },
  'responsabilidad': { es: 'Asumir la responsabilidad de los propios errores es una señal de madurez personal y profesional.', ja: '自分のミスに対して責任を持つことは、個人的・職業的な成熟の証である。', trivia: 'ラテン語 responsabilis（答えることのできる）に由来し、英語の responsibility と完全に同語根のコグネート。スペルの違いは語尾だけで（-dad vs. -ty）、ロマンス語と英語でほぼ同一の概念を担っている。' },
  'responsabilizar': { es: 'No es justo responsabilizar a un solo empleado por el fracaso de todo el proyecto.', ja: 'プロジェクト全体の失敗の責任を1人の従業員だけに負わせるのは公平ではない。', trivia: 'responsabilidad に動詞化接尾辞 -izar を加えた形で、英語の hold responsible や blame に相当する。英語には *responsibilize という動詞は存在せず、この点でスペイン語のほうが語形成の柔軟性が高い。' },
  'responsable': { es: 'El responsable del departamento de recursos humanos organizó una reunión urgente para tratar el conflicto.', ja: '人事部の責任者は、その対立に対処するための緊急会議を開いた。', trivia: 'ラテン語 responsabilis から来ており、英語の responsible と同語根の典型的なコグネート。スペイン語では名詞としても「担当者・責任者」を意味し、英語の responsible person のように名詞的に使える点が特徴。' },
  'responso': { es: 'El sacerdote rezó un responso junto a la tumba del difunto antes de que la familia se marchara.', ja: '家族が立ち去る前に、神父は故人の墓のそばで死者のための祈りを唱えた。', trivia: 'ラテン語 responsorium（交唱・応唱）に由来し、カトリックの典礼用語。英語の responsory と同語根で、中世の礼拝で聖職者と会衆が交互に唱えた祈りの形式を指す。口語では「長々としたお説教」の意味にも転じる。' },
  'resquebrajadura': { es: 'Las resquebrajaduras en la pared del edificio antiguo indicaban que la estructura podría estar en peligro.', ja: '古い建物の壁のひび割れは、構造が危険な状態にある可能性を示していた。', trivia: '動詞 resquebrajar（ひびが入る）に名詞化接尾辞 -ura が加わった形。語源は不明瞭だが、resquebrajar 自体は quebrajar（割れる）の強意形と考えられ、英語の fracture・crack と意味的に近いが語根は異なる。' },
  'resquebrajar': { es: 'El calor extremo del verano hizo que la pintura de la fachada se resquebrajara en varios puntos.', ja: '夏の猛暑により、建物のファサードの塗装が数か所でひびが入った。', trivia: 'quebrajar（砕く、割る）の強意形 re- 付加形で、英語の crack や split に相当する。英語の quebrar 系統の語は存在しないが、ラテン語 crepare（割れる音を立てる）が英語 crack の間接的な語源として共通している可能性がある。' },
  'resquebrajo': { es: 'Encontré un pequeño resquebrajo en la taza favorita de mi abuela después de lavarla.', ja: '洗った後、祖母のお気に入りのカップに小さなひび割れを見つけた。', trivia: 'resquebrajar の名詞形で、英語の crack に相当する。英語には resquebrajo に対応する同語根語はなく、crack・fissure・crevice などが文脈によって訳し分けられる。スペイン語特有の語形成（動詞語幹 + -o）の典型例。' },
  'resquicio': { es: 'Aunque la situación parecía desesperada, todavía había un resquicio de esperanza al que aferrarse.', ja: '状況は絶望的に見えたが、それでもまだしがみつけるわずかな希望の隙間があった。', trivia: '語源については諸説あり、ラテン語 *requissicium や quercia（樫の木）との関連が指摘されることもあるが定説はない。英語の chink（隙間）や loophole（抜け穴）に相当し、chink in the armor（鎧の隙間＝弱点）というイディオムと意味的に重なる。' },
  'resta': { es: 'Mi hija aprendió la resta antes que la multiplicación.', ja: '娘は掛け算より先に引き算を覚えた。', trivia: 'ラテン語 restare（残る）に由来し、英語の rest（残り）と同語根。数学用語としての「引き算」は英語では subtraction と言い、resta とは形が大きく異なるが、「残余」の意味では英語の remainder と意味的に対応する。' },
  'restada': { es: 'La cantidad restada del total fue mayor de lo esperado.', ja: '合計から差し引かれた金額は予想以上に大きかった。', trivia: 'restar（引き算する）の過去分詞女性形。restar はラテン語 restare から派生し、英語の subtract に相当するが、動詞形は英語の subtracted と形が全く異なる。スペイン語では過去分詞が形容詞として性数一致する点が英語と大きく異なる。' },
  'restado': { es: 'El número restado era incorrecto, así que el resultado final falló.', ja: '差し引かれた数が誤っていたため、最終結果が間違った。', trivia: 'restar の過去分詞男性形。英語では subtracted という一形式しかないが、スペイン語では形容詞として使う場合に restada（女性）/ restado（男性）と性が変化する。ラテン語 restare（留まる・残る）が語根。' },
  'restallar': { es: 'El látigo restallaba en el aire mientras el domador controlaba a los leones.', ja: '調教師がライオンたちを制御する間、ムチが空気を切り裂いてパチーンと鳴り響いた。', trivia: '語源については諸説あり、ラテン語の crackling を表す音象徴語に由来するとも、restallare という中世ラテン語形に遡るとも言われる。英語では crack や snap に相当し、ムチの音を表す点で共通するが、restallar はより詩的・文学的な文脈でも使われる。' },
  'restar': { es: 'No restes importancia a lo que me estás diciendo, porque es muy serio.', ja: 'あなたが言っていることの重要性を軽視しないでください、とても深刻なことだから。', trivia: 'ラテン語 restare（留まる・後に残る）から派生し、英語の rest（残り）と同語根。数学的な「引き算する」の意味は英語の subtract に相当するが、restar には「重要性を損なう」「残っている」という意味もあり、意味の幅が英語より広い。' },
  'restauración': { es: 'La restauración del cuadro tardó tres años debido a los daños causados por la humedad.', ja: '湿気による損傷のため、その絵画の修復には3年かかった。', trivia: 'ラテン語 restauratio（再建・回復）に由来し、英語の restoration と語源・形ともにほぼ同一のコグネート。英語では「王政復古」に Restoration（大文字）を使うが、スペイン語でも la Restauración と大文字で歴史的な王政復古期を指す用法がある。' },
  'restauradora': { es: 'La restauradora examinó cuidadosamente cada grieta del fresco antes de comenzar su trabajo.', ja: '修復家は作業を始める前に、フレスコ画のひび割れを一つひとつ丁寧に調べた。', trivia: 'restaurar（修復する）の行為者名詞女性形。ラテン語 restaurator に遡り、英語の restorer と同語根・同形の対応語。英語では性別による語形変化がないが、スペイン語では restauradora（女性）/ restaurador（男性）と区別される。' },
  'restaurador': { es: 'El restaurador utilizó técnicas especiales para recuperar los colores originales de la escultura.', ja: '修復家は彫刻の元の色を取り戻すために特殊な技法を用いた。', trivia: 'ラテン語 restaurator（再建者）に由来し、英語の restorer と同語根。英語の restorer が「元の状態に戻す人・物」を幅広く指すのと同様、スペイン語の restaurador も美術品の修復家から制度の復活者まで幅広い意味を持つ。' },
  'restaurar': { es: 'El gobierno decidió restaurar el antiguo palacio para convertirlo en museo nacional.', ja: '政府は古い宮殿を修復して国立博物館にすることを決定した。', trivia: 'ラテン語 restaurare（再び整える・修復する）に由来し、英語の restore と語源・意味ともに非常に近いコグネート。「レストラン（restaurant）」も同語根で、もともと「体力を回復させる場所」という意味だった点が興味深い。' },
  'riga': { es: 'El barco encalló en una riga oculta que no aparecía en las cartas náuticas.', ja: '船は海図に載っていない隠れた砂堆に座礁した。', trivia: '語源は不明・諸説あり、ポルトガル語や古いスペイン語の航海用語に由来するとも言われる。英語では sandbank や shoal に相当し、浅瀬や隠れ礁を指す地理的専門用語。ラトビアの首都 Riga とは語源が異なる別語。' },
  'restinga': { es: 'Los pescadores conocían bien la restinga que rodeaba la pequeña isla.', ja: '漁師たちは小さな島を囲む浅瀬をよく知っていた。', trivia: '語源は諸説あり、ポルトガル語・スペイン語の古い航海用語 restinga（砂嘴・砂堆）に由来するとされる。英語では reef や sandbank に相当し、英語のコグネートは明確ではない。ブラジルやカナリア諸島の地名にも使われる地理用語。' },
  'restituible': { es: 'El depósito es restituible si devuelves el equipo en buen estado.', ja: '機器を良好な状態で返却すれば、保証金は返還可能です。', trivia: 'ラテン語 restituere（元の場所に戻す）に由来する形容詞。英語には直接の対応語がなく、refundable や returnable で表現する。法律・経済分野でよく使われる術語で、英語の restitution（restituible の名詞形 restitución と同語根）と密接に関連する。' },
  'restitución': { es: 'El tribunal ordenó la restitución de los bienes confiscados al propietario original.', ja: '裁判所は没収された財産を元の所有者に返還するよう命じた。', trivia: 'ラテン語 restitutio（返還・回復）に由来し、英語の restitution と語源・形ともにほぼ同一の完全なコグネート。英語でも法律用語として損害賠償や財産返還の意味で広く使われ、スペイン語と用法がほぼ一致する。' },
  'restituir': { es: 'La empresa se comprometió a restituir las pérdidas causadas por el error contable.', ja: '会社は会計上のミスによって生じた損失を弁済することを約束した。', trivia: 'ラテン語 restituere（re-「再び」+ statuere「置く・立てる」）に由来し、英語の restore や restitute と同語根。英語には restitute という動詞も存在するが現代英語ではほぼ使われず、代わりに restore や return が一般的に使われる点でスペイン語の restituir と用法が異なる。' },
  'restitutoria': { es: 'Se presentó una acción restitutoria para recuperar los documentos robados.', ja: '盗まれた書類を取り戻すために原状回復訴訟が提起された。', trivia: 'ラテン語 restitutor（返還者）に由来する法律用語の形容詞女性形。英語では restitutive や restitutory という対応語が存在するがほとんど使われず、通常は restitution claim や restoration order などの表現で代替される専門的な用語。' },
  'restitutorio': { es: 'El juez aplicó el principio restitutorio para compensar al demandante.', ja: '裁判官は原告を補償するために原状回復の原則を適用した。', trivia: 'ラテン語 restitutor に由来する形容詞男性形。英語の restitutory に相当するが、現代英語では restitutory よりも restitution-based や restorative という表現の方が一般的で、スペイン語の restitutorio はより法律文書で保持されている形式的な術語。' },
  'resto': { es: 'Guardé el resto del pastel para compartirlo con mis compañeros al día siguiente.', ja: '翌日に同僚たちと分けるために、ケーキの残りを取っておいた。', trivia: 'ラテン語 restare（残る）の名詞形に由来し、英語の rest（残り）と同語根の明確なコグネート。英語の rest が「休息」と「残り」の2つの意味を持つのに対し、スペイン語の resto は「残り・残余」の意味に特化しており、「休息」には descanso を使う点が異なる。' },
  'restregada': { es: 'La restregada del suelo dejó las baldosas completamente limpias.', ja: '床をごしごし擦ったおかげでタイルが完全にきれいになった。', trivia: 'restregar（強く擦る）の過去分詞女性形で、名詞としても使われる。restregar はラテン語 re-（繰り返し）+ fricare（こする）に由来するとされ、英語の friction（摩擦）と同語根の fricare から来ている点が興味深い。英語では rubbing や scrubbing に相当する。' },
  'restregamiento': { es: 'El restregamiento constante de la pared acabó dañando la pintura.', ja: '壁を繰り返しごしごし擦ったせいで、ペンキが傷んでしまった。', trivia: 'restregar（擦る）の動名詞的名詞形。ラテン語 fricare（こする）に由来するとされ、英語の friction（摩擦）と同語根。英語では rubbing や scrubbing に相当するが、比喩的に「失敗を見せつける行為」という意味でも使われ、この点では英語の rubbing it in に近い表現。' },
  'restregar': { es: 'Hay que restregar bien las manchas con un cepillo antes de lavar la ropa.', ja: '服を洗う前に、ブラシで汚れをよくごしごし擦らなければならない。', trivia: 'ラテン語 re-（繰り返し）+ fricare（こする）に由来するとされ、英語の friction（摩擦）や frictional と同語根。比喩的な「失敗を嫌みたらしく見せつける」用法は英語の to rub something in（塩を塗り込む）という慣用句に意味・用法ともに対応する。' },
  'restrego': { es: 'Cada mañana le doy un buen restrego al suelo de la cocina.', ja: '毎朝、台所の床をよくごしごしと擦り洗いする。', trivia: 'restregar の直説法現在1人称単数形であると同時に、名詞として「強くこする行為」も意味する。ラテン語 fricare（こする）に由来し、英語の friction と同語根。英語では動詞 rub の活用形 rub / I rub と動名詞 rubbing で同じ概念を表す。' },
  'restricción': { es: 'Las nuevas restricciones de tráfico reducirán la contaminación en el centro de la ciudad.', ja: '新しい交通制限により、市中心部の汚染が減少するだろう。', trivia: 'ラテン語 restrictio（縛り・制限）に由来し、英語の restriction とほぼ完全に同一形のコグネート。語根の stringere（縛る・締める）は英語の strict（厳格な）、strain（緊張）、constrict（収縮させる）にも共通しており、「締め付ける」という原義が現代の意味に引き継がれている。' },
  'restrictiva': { es: 'La nueva política es demasiado restrictiva y dificulta la innovación.', ja: '新しい方針はあまりにも制限的で、イノベーションを妨げている。', trivia: 'ラテン語 restrictivus に由来し、英語の restrictive と語源・形ともにほぼ同一のコグネート。英語文法でも restrictive clause（制限節）という用語があるように、言語学でも使われる形容詞。語根の stringere（縛る）は英語の strict とも共通する。' },
  'restrictivo': { es: 'El uso del teléfono móvil en clase está sujeto a un reglamento bastante restrictivo.', ja: '授業中の携帯電話の使用は、かなり制限的な規則に従っている。', trivia: 'ラテン語 restrictivus に由来する形容詞男性形で、英語の restrictive と同語根の完全なコグネート。ラテン語 stringere（縛る）を語根に持ち、英語の strict（厳格な）、restrict（制限する）、constrict（収縮させる）とも同語族に属する。' },
  'restringible': { es: 'El acceso a esa información es perfectamente restringible bajo la ley vigente.', ja: 'その情報へのアクセスは現行法の下で十分に制限可能である。', trivia: 'restringir（制限する）＋ 接尾辞 -ible（可能）から成る形容詞。restringir はラテン語 restringere（縛り直す）に由来し、英語の restrict と同語根。英語に restrictable という語もあるが一般的ではなく、英語では usually able to be restricted のように言い換えることが多い。' },
  'restringida': { es: 'El acceso a esa zona es restringida para el público en general.', ja: 'その区域への立ち入りは一般市民に対して制限されている。', trivia: 'ラテン語 restringere（再び縛る）に由来し、re-（再）＋ stringere（締める・縛る）が語源。英語の restricted と完全な同語根であり、string（紐）や strict（厳格な）とも同じ語根を持つ。' },
  'restringidamente': { es: 'El presupuesto se usó restringidamente para cubrir solo los gastos esenciales.', ja: '予算は必要不可欠な経費だけをまかなうために限定的に使われた。', trivia: 'restringido（制限された）に副詞語尾 -mente を付けた形で、英語の restrictively に相当する。ラテン語 stringere（縛る）に由来し、英語の strictly や stringent とも語根を共有する。' },
  'restringido': { es: 'El horario de visitas está restringido a dos horas por día.', ja: '面会時間は一日二時間に制限されている。', trivia: 'ラテン語 restringere の過去分詞 restrictus に由来し、英語の restricted と同じ語根。英語では -ct- の音が残っているが、スペイン語では -ng- に変化した点が音韻上の興味深い違い。' },
  'restringir': { es: 'El gobierno decidió restringir las importaciones para proteger la industria nacional.', ja: '政府は国内産業を守るために輸入を制限することを決定した。', trivia: 'ラテン語 restringere（再び縛りつける）に直接由来し、英語の restrict と同語根。英語では restrict（動詞）／restriction（名詞）だが、スペイン語では restringir／restricción と -ct- が -ng- に変化している。' },
  'restrinjir': { es: '（警告）「restrinjir」という綴りは誤りであり、正しくは restringir です。', ja: '（注意）「restrinjir」というつづりは間違いで、正しくは restringir です。', trivia: 'これは restringir の誤った綴りとして流通することがある非標準形で、辞書に存在しない。スペイン語の -gir 動詞は yo 形で -jo となるため（restrinjo）、綴りの混乱が生じやすい。英語では restrict に相当する。' },
  'restriñimiento': { es: 'El médico le recomendó tomar más fibra para aliviar el restriñimiento.', ja: '医師は便秘を和らげるためにもっと食物繊維を摂るよう勧めた。', trivia: '標準的なスペイン語では estreñimiento が一般的であり、restriñimiento は古語・方言的な形。「縛る・締める」を意味するラテン語 stringere が語源で、英語では constipation と言うが、語源的にはラテン語 constipare（詰め込む）に由来し別系統。' },
  'restriñir': { es: 'En la medicina antigua, ciertas hierbas se usaban para restriñir el flujo de sangre.', ja: '古代医学では、血流を止めるために特定の薬草が使われていた。', trivia: 'ラテン語 restringere（縛る・制限する）に由来するが、スペイン語では estreñir が標準形として定着しており、restriñir は古語または文語的表現。英語では constipate（便秘にさせる）または stanch（血を止める）に相当し、いずれも異なる語源を持つ。' },
  'resubida': { es: 'Después de solucionar el error, hice una resubida del archivo corregido.', ja: 'エラーを修正した後、修正済みのファイルを再アップロードした。', trivia: 're-（再び）＋ subida（上げること・アップロード）から成る新造語で、インターネット時代に生まれたIT口語表現。英語の reupload に相当し、英語と同様に re- 接頭辞で「繰り返し」を表す点は共通しているが、スペイン語では subir（上げる）という方向性のある動詞を使う点が興味深い。' },
  'resubido': { es: 'El vídeo resubido ya tiene más visitas que el original.', ja: '再アップロードされた動画は、もうオリジナルより多くの視聴回数を得ている。', trivia: 'resubir（再アップロードする）の過去分詞形。IT口語として生まれた新語で、英語の reuploaded に相当する。スペイン語の subir はもともと「上へ行く」という空間的な意味を持ち、そこからデータを「アップ（上）ロード」する意味へ転義した点が面白い。' },
  'resubir': { es: 'Tuve que resubir el documento porque el original estaba corrupto.', ja: '元のファイルが壊れていたので、ドキュメントを再アップロードしなければならなかった。', trivia: 're-（再び）＋ subir（上がる・アップロードする）から成るインターネット時代の新造語。英語の reupload に相当し、upload と同様に「上へ（up）」という方向を内包するが、スペイン語では sub-（下から）が逆説的に「上げる」意味になった点が語源的に興味深い。' },
  'resucitada': { es: 'La tradición resucitada por los jóvenes artistas atrajo mucha atención.', ja: '若い芸術家たちによって復活させられたその伝統は多くの注目を集めた。', trivia: 'ラテン語 resuscitare（再び呼び起こす）に由来し、re-（再び）＋ suscitare（目覚めさせる）が語源。英語の resuscitated（蘇生させられた）と同語根だが、宗教的文脈では英語では resurrected（復活した）が好まれる。' },
  'resucitador': { es: 'El paramédico usó el resucitador para mantener la respiración del paciente.', ja: '救急隊員は患者の呼吸を維持するために蘇生器（アンブバッグ）を使用した。', trivia: 'ラテン語 resuscitare（蘇らせる）に由来し、英語の resuscitator（蘇生器）と完全な同語根。医療用の手動蘇生器はスペイン語でも英語でも同じ語根から派生した語が使われており、科学・医学用語の国際的な統一性を示す良い例。' },
  'resucitar': { es: 'Según la Biblia, Jesucristo resucitó al tercer día de su muerte.', ja: '聖書によれば、イエス・キリストは死後三日目に復活した。', trivia: 'ラテン語 resuscitare（再び呼び起こす）に由来し、英語の resuscitate（蘇生させる）と同語根。英語では宗教的な「復活」には resurrect を使い、医療的な「蘇生」には resuscitate を使い分けるが、スペイン語では resucitar が両方の意味を担う。' },
  'resudación': { es: 'La resudación de las paredes es un problema común en los sótanos sin ventilación.', ja: '換気のない地下室では壁の結露が一般的な問題だ。', trivia: 'ラテン語 sudare（汗をかく）に re-（再び・強調）を加えた語で、英語の sudation（発汗）と同語根。英語では sweating や exudation が一般的に使われ、sudation は専門用語にとどまるが、どちらもラテン語 sudor（汗）を共有している。' },
  'resudar': { es: 'Las paredes del sótano empezaron a resudar con la lluvia de ayer.', ja: '昨日の雨で地下室の壁がじわじわと湿気を帯び始めた。', trivia: 'ラテン語 sudare（汗をかく）に re-（強調）を加えた語で、英語の sweat や exude と意味は近いが語根はやや異なる。sudare はラテン語として英語の sudorific（発汗を促す）に残っており、スペイン語の sudor（汗）と直接つながっている。' },
  'resudo': { es: 'Con el calor del verano, un resudo leve le cubría la frente.', ja: '夏の暑さで、うっすらとした汗が額を覆っていた。', trivia: 'ラテン語 sudor（汗）に由来し、英語の sweat とは語根が異なる（sweat は古英語 swætan 由来）。ラテン語 sudor は英語では sudor という専門用語として残るほか、sudorific（発汗剤の）などの派生語に痕跡を残している。' },
  'resueltamente': { es: 'Resueltamente, la directora tomó la decisión de cerrar la fábrica.', ja: '所長は断固として工場を閉鎖する決断を下した。', trivia: 'resolver（解決する・決意する）の過去分詞 resuelto に副詞語尾 -mente を付けた形で、英語の resolutely に相当する。英語の resolute・resolution と同語根であり、どちらもラテン語 resolvere（解き放つ）に由来する。' },
  'resuelta': { es: 'Ella es una mujer resuelta que nunca duda antes de actuar.', ja: '彼女は行動する前に決して迷わない、決然とした女性だ。', trivia: 'ラテン語 resolvere（解き放つ、解決する）の過去分詞 resolutus に由来し、英語の resolute（決然とした）と同語根。英語では resolved と resolute が別々の語として存在するが、スペイン語では resuelto が両方の意味を持つ多義語として機能している。' },
  'resuelto': { es: 'Con un gesto resuelto, el líder anunció el inicio de la nueva campaña.', ja: '指導者は毅然とした身振りで新しいキャンペーンの開始を宣言した。', trivia: 'ラテン語 resolvere（解き放つ）の過去分詞に由来し、英語の resolved（決意した）・resolute（断固とした）と同語根。スペイン語では「解決された」と「決意の固い」という二つの意味を一語で担うが、英語では文脈に応じて使い分けが必要な点が異なる。' },
  'resuello': { es: 'Después de subir las escaleras corriendo, llegó sin resuello.', ja: '階段を駆け上がった後、彼は息も絶え絶えに到着した。', trivia: '動詞 resollar（荒い息をする）の名詞形で、ラテン語 sufflare（吹く）または折衷語源とされる。英語では breath や panting に相当するが、resuello は特に疲労や苦しさからくる荒い息遣いに使われる表現で、英語の wheeze とニュアンスが近い場合もある。' },
  'resultada': { es: 'La situación resultada del conflicto fue más compleja de lo esperado.', ja: 'その紛争から生じた状況は予想以上に複雑だった。', trivia: 'resultar（結果として生じる）の過去分詞女性形で、ラテン語 resultare（跳ね返る・反響する）に由来する。英語の result と同語根であり、どちらも re-（再び）＋ saltare（跳ぶ）から成り、「跳ね返ってくるもの」が転じて「結果」を意味するようになった。' },
  'resultando': { es: 'El equipo trabajó durante meses, resultando en un producto de alta calidad.', ja: 'チームは何ヶ月も取り組み、結果として高品質な製品が生まれた。', trivia: 'resultar の現在分詞（ジェルンディオ）形で、英語の resulting に相当する。ラテン語 resultare（跳ね返る）に由来し、英語の result・resultant と同語根。英語の resultant（結果として生じる）は科学用語として残っており、スペイン語の resultante と形も意味も酷似している。' },
  'resumen': { es: 'Al final del informe, incluye un resumen de los principales hallazgos.', ja: '報告書の末尾に主な発見事項の要約を含めてください。', trivia: '動詞 resumir（要約する）の名詞形で、ラテン語 resumere（再び取り上げる）に由来する。英語の resume（履歴書・再開する）と同語根だが、英語では résumé（仏語経由）が「履歴書」の意味で定着しており、スペイン語の resumen（要約・概要）とは意味が分岐している点が興味深い。' },
  'resumidamente': { es: 'Te lo explico resumidamente: el proyecto se canceló por falta de fondos.', ja: 'かいつまんで説明すると、資金不足でプロジェクトは中止された。', trivia: 'resumido（要約された）に副詞語尾 -mente を加えた形で、英語の briefly や in summary に相当する。ラテン語 resumere（再び取り上げる）に由来し、英語の summarily（手短に・即座に）とは語根が異なるが、summary はラテン語 summa（合計・要点）に由来する別系統の語。' },
  'resumida': { es: 'La profesora entregó una versión resumida del texto para los alumnos.', ja: '先生は生徒たちに本文の要約版を配布した。', trivia: 'resumir（要約する）の過去分詞女性形で、ラテン語 resumere（再び取り上げる）に由来する。英語の summarized に相当するが、英語では summary（名詞）と summarize（動詞）が別の語根（ラテン語 summa）から来ており、スペイン語の resumen／resumir とは語源が異なる点が注目される。' },
  'resumido': { es: 'El profesor nos dio un resumen muy resumido de toda la historia medieval.', ja: '先生は中世の歴史全体について、とても簡潔なまとめを教えてくれた。', trivia: 'ラテン語 resumere（再び取る・再開する）に由来し、英語の resume（履歴書・再開する）と同語根。ただし英語の resume は「再開する」意味が主で「要約する」とは使い方が異なる点に注意。' },
  'resumir': { es: '¿Podrías resumir los puntos principales de la reunión en un párrafo?', ja: '会議の主要な点を1段落にまとめてもらえますか？', trivia: 'ラテン語 resumere（re- 再び＋sumere 取る）から派生し、英語の summarize や sum up に意味的に対応する。英語にも resume（再開する）として残っているが、「要約する」意味は summary という別語が担っており、スペイン語の resumir とは用法が分岐している。' },
  'resupinada': { es: 'La seta tenía la superficie resupinada, pegada directamente sobre la corteza del árbol.', ja: 'そのキノコは子実体が倒旋していて、直接樹皮の上に張り付いていた。', trivia: 'ラテン語 resupinus（仰向けの・裏返した）に由来し、英語の resupinate と同語源の学術語。英語の supine（仰向けの・無気力な）とも関連しており、体勢・方向の逆転を表す接頭辞 re- の用法が共通する。' },
  'resupinado': { es: 'El hongo resupinado crecía extendido sobre la madera sin formar sombrero visible.', ja: 'その倒旋菌は傘を形成せず、木材の上に平たく広がって育っていた。', trivia: 'ラテン語 resupinus の過去分詞形から来た形容詞で、英語の resupinate と完全に同語根。植物学・菌類学の専門用語として両言語で使われ、「通常と向きが逆になった」構造を指す。' },
  'resurrección': { es: 'La resurrección del interés por el vinilo sorprendió a toda la industria musical.', ja: 'ビニールレコードへの関心の復活は音楽業界全体を驚かせた。', trivia: 'ラテン語 resurrectio（re- 再び＋surgere 立ち上がる）に由来し、英語の resurrection と完全に同語根・同形の借用語。英語の insurgent（反乱者）や surge（急増）とも同じ語根 surgere を共有している。' },
  'resurtida': { es: 'La resurtida de mercancía llegó justo cuando los estantes estaban casi vacíos.', ja: '商品の再入荷は棚がほぼ空になった頃にちょうど届いた。', trivia: '動詞 resurtir（re-＋surtir 補充する）の過去分詞が名詞化したもので、英語の restock や replenishment に対応する。surtir 自体はアラビア語由来とも言われるが語源は諸説あり、中南米の商業・流通の文脈で広く使われる実務語。' },
  'resurtido': { es: 'El encargado verificó el resurtido de todos los productos antes de abrir la tienda.', ja: '担当者は開店前に全製品の再入荷を確認した。', trivia: '動詞 resurtir の過去分詞が名詞化したもので、英語の restock や replenishment に相当。中南米、特にメキシコの小売・流通業界で日常的に使われる語で、スペインではあまり一般的でない地域差がある。' },
  'resurtir': { es: 'El proveedor prometió resurtir el inventario antes del fin de semana.', ja: '納入業者は週末前に在庫を補充すると約束した。', trivia: 're-（再び）＋surtir（供給する・噴き出す）から成り、英語の restock や replenish に意味的に対応する。surtir はおそらくラテン語 surgere（立ち上がる）に由来するとされるが語源は定かでなく、英語の surge とも遠縁の可能性がある。' },
  'retablo': { es: 'El retablo mayor de la catedral es una obra maestra del arte barroco español.', ja: 'その大聖堂の主祭壇装飾はスペイン・バロック芸術の傑作だ。', trivia: 'ラテン語 retro（後ろ）＋tabula（板）に由来し、「祭壇の後ろに立てる板絵」を意味する。英語では reredos や altarpiece と言い、retablo はスペイン語からそのまま英語に借用されることもある美術用語。' },
  'retacería': { es: 'En el mercado de telas encontramos una tienda que vendía retacería a muy buen precio.', ja: '布地市場で、はぎれをとてもお得な値段で売っている店を見つけた。', trivia: 'retaco（短く切った布切れ）＋指小辞・集合名詞接尾辞 -ería から成る語で、英語の remnants や fabric scraps に相当。中南米で特によく使われ、手芸・パッチワーク文化と結びついた実用語。英語に直接の同語根語はない。' },
  'retachar': { es: 'La pelota retachó contra la pared y golpeó al árbitro sin querer.', ja: 'ボールが壁に跳ね返り、うっかり審判に当たってしまった。', trivia: '語源は諸説あるが、メキシコ口語で「跳ね返る・強制送還される」という意味を持つ独特の動詞。英語の bounce back や rebound に意味的に対応し、移民文脈では「国境から送り返される」を意味する生々しいスラングとしても機能する。' },
  'retacho': { es: 'El balón dio un retacho inesperado y entró en la portería.', ja: 'ボールが予想外に跳ね返り、ゴールに入った。', trivia: '動詞 retachar（跳ね返る）から派生した名詞で、メキシコ口語に特有の語。英語の rebound や bounce に相当し、スポーツや日常会話で使われるが、メキシコ国境地帯では「強制送還・国外追放」の比喩的意味も持つ社会的に重みのある語。' },
  'retador': { es: 'El joven boxeador se mostró muy retador desde el primer asalto del combate.', ja: '若いボクサーは試合の第1ラウンドから非常に挑戦的な姿勢を見せた。', trivia: '動詞 retar（挑戦する）＋行為者接尾辞 -dor から成り、英語の challenger や challenging と意味的に対応する。retar はラテン語 reputare（再び考える・論争する）に由来するとされ、英語の repute（評判）とも遠縁の可能性がある。' },
  'retadora': { es: 'La actitud retadora de la nueva directora transformó la cultura de la empresa.', ja: '新しい女性社長の挑戦的な姿勢が会社の文化を変えた。', trivia: 'retador の女性形で、形容詞としては「挑戦的な・やりがいのある」を意味する。英語の challenging に最もよく対応し、empresas con visión retadora（挑戦的なビジョンを持つ企業）のようにビジネス文脈でも多用される。' },
  'retaguardia': { es: 'Las tropas de retaguardia protegían el flanco sur mientras avanzaba el grueso del ejército.', ja: '主力部隊が前進する間、後衛部隊が南側面を守った。', trivia: 'スペイン語 retaguardia は re-（後ろ）＋guardia（警護）から成り、英語の rearguard と同じ構造（rear＋guard）を持つ並行的な語形成の好例。guardia はゲルマン語 *wardōn（見張る）に由来し、英語の guard とも同語根。' },
  'retahíla': { es: 'El niño soltó una retahíla de excusas para no ir al colegio.', ja: 'その子は学校に行かないために言い訳を次々と並べ立てた。', trivia: '語源は諸説あり、re-＋hilo（糸）の派生とも、アラビア語由来ともされるが不明な点が多い。英語では litany（長々とした列挙）や string of... に相当し、否定的なニュアンスで使われることが多い点が英語の litany とよく似ている。' },
  'retajar': { es: 'El calígrafo tuvo que retajar la pluma de caña para seguir escribiendo.', ja: '書道家は書き続けるために葦ペンを削り直さなければならなかった。', trivia: 're-（再び）＋tajar（切る）から成り、「切り直す・削り直す」を基本義とする。tajar はラテン語 taliare（切る）に由来し、英語の tailor（仕立て屋）と同語根。英語で「ペンを削る」は cut or trim a quill と言い直接対応語はない。' },
  'retajo': { es: 'El sastre guardó cada retajo de tela para usarlo en remiendos futuros.', ja: '仕立て屋は将来の補修用に布の切れ端を全て保管した。', trivia: '動詞 retajar（切り直す）から派生した名詞で、英語の scrap や remnant に相当。ラテン語 taliare（切る）に遡る語根を持ち、英語の tailor（仕立て屋）や detail（詳細・切り分けたもの）とも同語根でつながっている。' },
  'retal': { es: 'Con varios retales de diferentes colores, la abuela cosió una manta de patchwork.', ja: '祖母はさまざまな色のはぎれを使ってパッチワークの毛布を縫い合わせた。', trivia: 'ラテン語 taliare（切る）に由来する語根から派生し、英語の remnant や scrap に相当。英語の retail（小売）は同語根 tailler（切り分ける）から来ており、「切り分けて少量ずつ売る」が本来の意味であることと意味的に通底している。' },
  'retallo': { es: 'Tras podar el árbol en invierno, en primavera brotaron numerosos retallos.', ja: '冬に木を剪定した後、春には多くのひこばえが芽吹いた。', trivia: 're-（再び）＋tallo（茎・芽）から成り、「切り株や根本から再び出る新芽」を意味する。tallo はラテン語 thallus に由来し、英語の thallus（葉状体）と同語根。英語では sucker や shoot、sprout と言い換えられる植物学的な語。' },
  'retama': { es: 'Los campos andaluces se cubren de retama amarilla a principios de primavera.', ja: 'アンダルシアの野原は春先に黄色いエニシダで覆われる。', trivia: 'アラビア語 ratam（エニシダの一種）に由来するアラビズモ（アラビア語借用語）で、レコンキスタ時代のアラビア語の影響を示す語の一つ。英語では broom や Spanish broom と呼ばれ、直接の英語同語根語は存在しない。' },
  'retardación': { es: 'La retardación del proyecto se debió a problemas con los permisos municipales.', ja: 'プロジェクトの遅延は市の許可取得に関する問題によるものだった。', trivia: 'ラテン語 retardatio（re-＋tardus 遅い）に由来し、英語の retardation と完全に同語根・同形の学術語。英語の tardy（遅刻した）やイタリア語音楽用語 ritardando（だんだん遅く）とも同じ語根 tardus を共有している。' },
  'retardador': { es: 'Se añadió un retardador al cemento para prolongar el tiempo de fraguado en climas cálidos.', ja: '温暖な気候での硬化時間を延ばすために、セメントに遅延剤が添加された。', trivia: 'ラテン語 tardus（遅い）に由来し、英語の retarder と同語根。化学・建設・自動車工学など工業分野で広く使われる専門語で、英語でも retarder（遅延剤・リターダー）としてそのまま借用される国際的な技術語。' },
  'retardamiento': { es: 'El retardamiento de las obras causó pérdidas millonarias a la empresa constructora.', ja: '工事の遅延は建設会社に数百万ドルの損失をもたらした。', trivia: 'retardar＋名詞化接尾辞 -miento から成り、retardación と類義だが、より行為のプロセスに焦点を当てたニュアンスを持つ。英語の delay や postponement に対応し、英語の tardy（遅刻）と同じラテン語語根 tardus を共有する。' },
  'retardar': { es: 'Las malas condiciones climáticas retardaron la llegada de los vuelos varias horas.', ja: '悪天候により、フライトの到着が数時間遅れた。', trivia: 'ラテン語 retardare（re-＋tardare 遅らせる）に由来し、英語の retard と完全に同語根。英語の retard はかつて「遅らせる」という中立的な技術語として広く使われていたが、現代英語では差別的な言葉として忌避されるようになった一方、スペイン語の retardar は今も日常的に使用される。' },
  'retardo': { es: 'El retardo en la señal de audio arruinó la sincronización con el vídeo durante la transmisión en directo.', ja: '音声信号の遅延が、ライブ配信中に映像との同期を台無しにした。', trivia: 'ラテン語 retardare（遅くする）に由来し、re-（再び）＋ tardare（遅れる）の合成。英語の retard と同語根だが、英語では人を指す侮辱語としての用法が問題視されており、「遅延」の技術用語としては delay が主流。' },
  'retasa': { es: 'Tras la crisis económica, se solicitó una retasa de los bienes inmuebles para ajustar los impuestos.', ja: '経済危機の後、税金を調整するために不動産の再査定が求められた。', trivia: 're-（再び）＋ tasa（税率・査定額）の構成で、tasa 自体はアラビア語 tassa（杯、量）を経由したとされる。英語の reappraisal に相当するが、英語には tasa に直接対応する同語根の日常語はなく、税率を意味する tax はラテン語 taxare 経由の別系統。' },
  'retasación': { es: 'La retasación del terreno fue imprescindible para determinar el precio justo de venta.', ja: '土地の再査定は、適正な売却価格を決定するために不可欠だった。', trivia: 'retasar（再査定する）の行為名詞形で、接尾辞 -ción はラテン語 -tionem に由来する典型的な名詞化パターン。英語の reappraisal や reassessment に対応するが、assessment 自体はラテン語 assidere（傍らに座る＝補佐する）から来ており、語根が異なる。' },
  'retasar': { es: 'El perito fue contratado para retasar el cuadro después de que se descubriera su verdadera autoría.', ja: '真の作者が判明した後、その絵画を再査定するために鑑定士が雇われた。', trivia: 're-（再び）＋ tasar（査定する・値をつける）の合成動詞。英語の revalue や reappraise に相当し、appraise はアングロノルマン語経由でラテン語 appretiare（価値を置く）に遡るが、スペイン語の tasar とは語根が異なる。' },
  'retazo': { es: 'Con los retazos de tela sobrantes, la modista hizo una colorida colcha de patchwork.', ja: '残った布のはぎれを使って、仕立て屋は色鮮やかなパッチワークの掛け布団を作った。', trivia: '語源は諸説あり、retal（切れ端）の派生とも、ラテン語 rete（網）関連とも言われる。英語の remnant や scrap に相当し、scrap は古ノルド語 skrap（削りかす）に由来する。比喩的に「記憶の断片」として使われる点は英語の fragment と用法が重なる。' },
  'retejar': { es: 'Después del fuerte temporal, tuvieron que retejar toda la nave del almacén.', ja: '激しい嵐の後、倉庫の建物全体の屋根瓦を葺き替えなければならなかった。', trivia: 're-（再び）＋ tejar（瓦を葺く）の合成で、teja（瓦）はラテン語 tegula（屋根を覆うもの）に由来。英語の tile と同語根で、tile もラテン語 tegula から来ており、英語で「屋根を直す」は re-tile や re-roof と言う。' },
  'retejo': { es: 'El presupuesto para el retejo del edificio histórico superó el millón de euros.', ja: 'その歴史的建物の屋根瓦葺き替えの見積もりは100万ユーロを超えた。', trivia: 'retejar（屋根を葺き替える）の行為名詞。teja（瓦）はラテン語 tegula に由来し、英語の tile と同語根。英語には re-roofing または re-tiling に相当するが、単一の名詞として retejo に直接対応する語はなく、「葺き替え工事」は roof repair や retiling と表現する。' },
  'retén': { es: 'Un retén de policías permanecía apostado en la entrada del estadio durante el partido.', ja: '試合の間、警官の待機部隊がスタジアムの入り口に配置されていた。', trivia: 'retener（保持する・留める）の派生名詞で、ラテン語 retinere に遡る。英語の retain と同語根で、技術的な「留め金・オイルシール」の用法では英語も retainer や seal と言う。スペイン語では警察・消防の「常駐待機班」という独自の用法が発達しており、英語の detachment に近い。' },
  'retenida': { es: 'La retenida del mástil evitó que la grúa se inclinara demasiado durante la operación.', ja: 'マストの控え綱のおかげで、作業中にクレーンが傾きすぎるのを防ぐことができた。', trivia: 'retener（保持する）の過去分詞の女性形が名詞化したもので、ラテン語 retinere（引き留める）に由来。英語の guys wire（控え綱）や stay に相当し、retain と同語根。英語の retain は法律・人材分野でよく使われるが、スペイン語の retenida は建築・船舶用語としての物理的「控え綱」という意味が際立つ。' },
  'retenido': { es: 'El importe retenido en concepto de IRPF aparece desglosado en la nómina mensual.', ja: '所得税として源泉徴収された金額は、毎月の給与明細に内訳として記載されている。', trivia: 'retener（保持する・源泉徴収する）の過去分詞男性形で、ラテン語 retinere に由来。英語の withheld（withhold の過去分詞）に相当し、英語の retain と同語根だが、税務用語として「天引き」を意味する場合は withheld や deducted が使われる。' },
  'retención': { es: 'La retención en carretera se extendía varios kilómetros debido a las obras en la autopista.', ja: '高速道路の工事のため、道路の渋滞が数キロメートルにわたって続いていた。', trivia: 'ラテン語 retentio（保持、抑制）に直接由来し、retinere（引き留める）の名詞形。英語の retention と完全な同語根・同形のコグネートで、記憶保持・水分貯留・源泉徴収など意味の幅も共通する。ただし「交通渋滞」の意味は英語の retention にはなく、スペイン語独自の用法拡張。' },
  'retener': { es: 'El banco está obligado a retener una parte del salario para pagar el impuesto sobre la renta.', ja: '銀行は所得税を支払うために給与の一部を源泉徴収する義務がある。', trivia: 'ラテン語 retinere（re- ＋ tenere「保持する」）に直接由来する。英語の retain と完全な同語根のコグネートで、スペルも意味も非常に近い。ただし英語の retain は主に「維持・保持」に重点があり、「源泉徴収」には withhold、「拘留」には detain を使い分けるのに対し、スペイン語の retener は一語でこれらすべてをカバーする。' },
  'reteñir': { es: 'Decidió reteñir la chaqueta de cuero para devolverle el color oscuro original.', ja: '元の濃い色を取り戻すために、革のジャケットを染め直すことにした。', trivia: 're-（再び）＋ teñir（染める）の合成動詞で、teñir はラテン語 tingere（染める・浸す）に由来。英語の tint、tinge、stain などと同語根で、英語の re-dye に相当する。自動詞として「音が鳴り響く」という用法もあり、この場合はラテン語の「響く」という意味合いが転用されたもの。' },
  'reticencia': { es: 'Aceptó el proyecto con cierta reticencia, pues no confiaba del todo en el equipo.', ja: 'チームを完全には信頼していなかったため、彼はある種の消極的な態度でプロジェクトを受け入れた。', trivia: 'ラテン語 reticentia（沈黙、口を閉じること）に由来し、reticere（re- ＋ tacere「黙る」）の名詞形。英語の reticence と完全な同語根・同形のコグネート。ただし英語の reticence は「口数が少ない性格」という恒常的な特性を指すことが多いのに対し、スペイン語の reticencia は特定の場面での「ためらい・含み」というニュアンスが強い。' },
  'reticente': { es: 'Los inversores se mostraban reticentes a comprometer fondos en un mercado tan inestable.', ja: '投資家たちは、これほど不安定な市場に資金を投じることに難色を示していた。', trivia: 'ラテン語 reticens（黙っている、控えている）の現在分詞形に由来。英語の reticent と完全な同語根のコグネート。英語では reticent は「口数が少ない、無口な」という性格描写が中心だが、スペイン語の reticente は「〜に消極的・難色を示す」という意味で英語の reluctant に近い用法が一般的で、使用頻度・文脈が異なる。' },
  'reticular': { es: 'La estructura reticular de la membrana celular permite el intercambio selectivo de sustancias.', ja: '細胞膜の網状構造は、物質の選択的な交換を可能にする。', trivia: 'ラテン語 reticulum（小さな網）の形容詞形 reticularis に由来し、rete（網）が語根。英語の reticular と完全な同語根のコグネートで、医学・生物学用語として「網状の」を意味する。英語では reticular formation（脳幹の網様体）などの専門用語で用いられ、日本語の「レチクル（光学部品）」も同じ語源を持つ。' },
  'reticulada': { es: 'La superficie reticulada del tejido muscular favorece la circulación del oxígeno.', ja: '筋肉組織の網目状の表面が酸素の循環を促進する。', trivia: 'reticular（網状にする）の過去分詞女性形で、ラテン語 reticulum（小さな網）に由来。英語の reticulated と同語根のコグネートで、「網目模様の」を意味する。英語では reticulated python（アミメニシキヘビ）のように動植物の模様の描写に使われることがあり、スペイン語でも同様の用法が存在する。' },
  'reticulado': { es: 'El reticulado de hierro del puente le confería una gran resistencia estructural.', ja: '橋の鉄格子構造はそれに高い構造的耐久性を与えていた。', trivia: 'reticular の過去分詞男性形で、名詞として「格子構造・網目組み」を意味する。ラテン語 reticulum（小さな網）に由来し、英語の reticulated や grid に相当する。建築・デザインの文脈では英語の lattice（格子）に近く、lattice はフランス語 lattis（桟）経由でゲルマン語系の語根に由来し、語源は異なる。' },
  'retícula': { es: 'El diseñador utilizó una retícula de doce columnas para organizar el contenido de la revista.', ja: 'デザイナーは雑誌のコンテンツを整理するために12列のグリッドを使用した。', trivia: 'ラテン語 reticula（小さな網）の縮小形に直接由来し、rete（網）が語根。英語の reticle（光学機器の十字線）と同語根のコグネートで、印刷・デザイン用語の「グリッド」としては英語も grid（古英語 gridel：鉄格子）や reticle を使い分ける。日本語の「レチクル」も同語源。' },
  'retina': { es: 'La degeneración de la retina puede provocar una pérdida gradual e irreversible de la visión.', ja: '網膜の変性は、徐々に進む不可逆的な視力喪失を引き起こす可能性がある。', trivia: '中世ラテン語 retina に由来し、ラテン語 rete（網）の派生語。眼球の「網膜」が網状の構造を持つことからこの名がついた。英語の retina と完全に同形・同語根のコグネートで、生物学・医学の国際的な術語として両言語で共有されている。英語に同化した時期は15世紀頃とされる。' },
  'retinte': { es: 'Sus palabras tenían un retinte de ironía que nadie en la sala supo ignorar.', ja: '彼の言葉には部屋の誰もが無視できないような皮肉の含みがあった。', trivia: 're-（再び）＋ tinte（染め・色合い）の合成で、tinte はラテン語 tinctus（染められた）に由来。英語の tint や tinge と同語根のコグネートで、比喩的な「色合い・ニュアンス」の用法は英語の tinge（a tinge of irony）と平行している。「染め直し」という本義と「言葉の含み」という比喩義を併せ持つ点がユニーク。' },
  'retintín': { es: 'Respondió con un retintín en la voz que dejó claro que no estaba de acuerdo.', ja: '彼女は同意していないことを明らかにするような皮肉なトーンで答えた。', trivia: '金属音の擬音語的な重複形（tintín）に re- を加えた語で、チリンチリンという音の繰り返しを表す。英語の tinkle や jingle に相当するが、これらはゲルマン語系の擬音語由来で語源系統が異なる。「皮肉な口調」という比喩義は英語の sarcastic tone に対応し、音の響きから態度・語調へと意味が拡張した珍しい例。' },
  'retiñir': { es: 'Las campanas de la catedral retiñían en la tarde fría, llenando la plaza de su eco.', ja: '大聖堂の鐘は冷たい夕方にキンキンと鳴り響き、広場をその残響で満たした。', trivia: 're-（再び・強調）＋ tiñir（鳴り響く）の合成で、tiñir はラテン語 tinnire（鳴る、響く）に由来。英語の tinnitus（耳鳴り）と同語根で、これは医学用語として英語でも広く使われる。また英語の tinkle もこの語根と関連するとされ、金属音を表す語根がラテン語から英語・スペイン語両方に受け継がれている。' },
  'retirada': { es: 'La retirada de las tropas fue negociada tras semanas de conflicto.', ja: '数週間の紛争の後、軍の撤退が交渉によって決まった。', trivia: 'ラテン語の「retirare（引き戻す）」に由来し、接頭辞 re-（再び）＋ tirare（引く）から成る。英語の retreat や withdrawal に相当し、英語の retire も同じ語根を持つ。' },
  'retiradamente': { es: 'Tras jubilarse, vivía retiradamente en un pequeño pueblo de montaña.', ja: '退職後、彼は山あいの小さな村に人目を避けて暮らしていた。', trivia: 'retirar（引退する）の過去分詞 retirado に副詞語尾 -mente を付けた形。英語には直訳の副詞はなく、「in retirement」「in seclusion」と表現される。' },
  'retirada / retirado': { es: 'Vive en una casita retirada del pueblo, rodeada de naturaleza.', ja: '彼女は村から離れた、自然に囲まれた小さな家に住んでいる。', trivia: 'ラテン語 retirare の過去分詞形。英語の retired（退職した）と同語根であり、「人里離れた・奥まった」という空間的意味でも使われる点が興味深い。' },
  'retirado': { es: 'Mi abuelo es un militar retirado que ahora disfruta de la jardinería.', ja: '祖父は退役軍人で、今は庭いじりを楽しんでいる。', trivia: '英語の retired と完全に対応する同語根語。スペイン語では retirada（女性形）と retirado（男性形）で性が変わるが、英語の retired は変化しない。' },
  'retirar': { es: 'Necesito retirar dinero del cajero antes de salir de viaje.', ja: '旅行に出かける前にATMでお金を引き出す必要がある。', trivia: 'ラテン語 re-（後ろへ）＋ tirare（引く）に由来し、フランス語経由で「引き退かせる」という意味を獲得した。英語の withdraw（with＋draw）とは語根が異なるが意味が重なる。' },
  'retiro': { es: 'El retiro espiritual en el monasterio le ayudó a encontrar la paz interior.', ja: '修道院でのスピリチュアル・リトリートが、彼が内なる平和を見つける助けになった。', trivia: 'ラテン語 retirare に由来し、英語の retreat と同語根。英語でも宗教や自己啓発の文脈で「retreat」と言うが、スペイン語の retiro はそのまま英語に「retreat」として借用されている側面もある。' },
  'retito / reto': { es: 'Ese problemita era solo un retito comparado con los desafíos reales.', ja: 'その小さな問題は、本当の課題と比べればほんのちっぽけな挑戦に過ぎなかった。', trivia: 'reto（挑戦）の縮小形・古語的用法。reto 自体はラテン語 ruptum（破られたもの）に由来するとも、retar（挑む）の名詞形とも言われ、語源には諸説ある。英語の challenge に相当するが同語根語はない。' },
  'reto': { es: 'Aprender un idioma nuevo siempre es un reto, pero vale la pena.', ja: '新しい言語を学ぶことは常に挑戦だが、やる価値がある。', trivia: '語源については諸説あり、ラテン語 ruptum（破る）から来るという説や、retar（挑む）から派生した名詞とする説がある。英語の challenge とは語根が異なるが意味は近い。' },
  'retocada / retocado': { es: 'La foto retocada en la portada de la revista no refleja la realidad.', ja: '雑誌の表紙のレタッチされた写真は現実を反映していない。', trivia: 'retocar（修正する）の過去分詞。英語の retouched と同語根で、どちらも re-（再び）＋ touch/tocar（触れる）から成る。tocar 自体はラテン語 toccare に由来する。' },
  'retocado': { es: 'El cuadro fue restaurado y ligeramente retocado por un experto en arte.', ja: 'その絵画は美術専門家によって修復され、わずかに手直しされた。', trivia: '英語 retouched の直接の対応語。スペイン語 tocar とフランス語 toucher、英語 touch はいずれもゲルマン語またはラテン語の同一語根を共有するとされる。' },
  'retocar': { es: 'El fotógrafo tuvo que retocar algunas imágenes antes de publicarlas.', ja: 'カメラマンは公開前にいくつかの画像を修正しなければならなかった。', trivia: 're-（再び）＋ tocar（触れる）の組み合わせ。英語の retouch と完全に同語根・同構造で、どちらもフランス語 retoucher を経由している可能性が高い。' },
  'retoñar': { es: 'Después del invierno, los árboles vuelven a retoñar con la llegada de la primavera.', ja: '冬の後、春の訪れとともに木々は再び新芽を出す。', trivia: 'retoño（新芽）から派生した動詞。retoño 自体の語源は不明確で、諸説あるが、ラテン語 autumnus に関連するという説もある。英語では sprout や shoot forth と表現し、同語根の英単語はない。' },
  'retoño': { es: 'El jardinero estaba encantado al ver los primeros retoños del rosal.', ja: '庭師はバラの木に最初の新芽が出たのを見て喜んだ。', trivia: '語源は諸説あり、ラテン語またはゲルマン語系と考えられているが確定していない。英語の sprout や shoot に相当するが同語根語はなく、「愛児・末っ子」という比喩的意味でも使われる点がユニーク。' },
  'retoque': { es: 'Solo necesito dar unos últimos retoques al informe antes de enviarlo.', ja: '送る前にレポートに最後のいくつかの手直しをするだけでいい。', trivia: 'retocar の名詞形で、英語の retouch と同じ構造。特にメイクアップや写真加工の文脈でよく使われ、英語でも「final touches」や「touch-ups」と言うが、「retouch」の名詞形は英語でも同様に使われる。' },
  'retorcedura': { es: 'Sufrió una retorcedura de tobillo durante el partido y tuvo que abandonar.', ja: '試合中に足首をねじり、退場しなければならなかった。', trivia: 'retorcer（ねじる）から派生した名詞で、torcedura とも言う。ラテン語 torquere（ねじる）に由来し、英語の torque（トルク）、torture（拷問）、torch（松明）なども同じ語根を持つ。' },
  'retorcer': { es: 'Retorció la ropa mojada para escurrir el agua.', ja: '彼女は水を絞り出すために濡れた衣服をねじった。', trivia: 'ラテン語 torquere（ねじる）に re-（再び）を付けた形。英語の twist や wring に相当するが、同語根の英単語は torque（回転力）、torture（拷問）など。「言葉を曲解する」という比喩的用法も豊か。' },
  'retorcida / retorcido': { es: 'El villano de esa novela tenía una mente muy retorcida y peligrosa.', ja: 'その小説の悪役は非常にひねくれた危険な心の持ち主だった。', trivia: 'retorcer の過去分詞。英語の twisted と意味・用法がほぼ一致し、性格の歪みを表す比喩としても両言語で平行して使われる。語根のラテン語 torquere は英語 torture とも繋がる。' },
  'retorcido': { es: 'Es un personaje retorcido que no puedes predecir lo que hará a continuación.', ja: '彼は次に何をするか予測できないひねくれたキャラクターだ。', trivia: '英語 twisted の対応語として機能する。どちらもラテン語 torquere（ねじる）を語根に持ち、物理的な「ねじれ」から心理的な「歪み」への意味拡張が両言語で並行して起きている。' },
  'retórica': { es: 'Su discurso estaba lleno de retórica vacía que no convencía a nadie.', ja: '彼のスピーチは誰も納得させることのできない空虚なレトリックに満ちていた。', trivia: 'ギリシャ語 rhētorikē（弁論術）に由来し、ラテン語 rhetorica を経てスペイン語に入った。英語の rhetoric と完全に同語根で、どちらもアリストテレスの「弁論術（Rhetorica）」に遡る。' },
  'retóricamente': { es: '«¿Acaso no es obvio?», preguntó retóricamente, sin esperar respuesta.', ja: '「これって明らかじゃないの？」と彼は返事を期待せず反語的に言った。', trivia: 'retórica に副詞語尾 -mente を付けた形。英語の rhetorically と完全に対応し、どちらも「答えを期待しない問い（修辞疑問）」を指す文脈で頻繁に使われる。' },
  'retórico': { es: 'La pregunta retórica es una figura literaria muy efectiva en los discursos políticos.', ja: '反語的な問いは政治的なスピーチで非常に効果的な修辞表現だ。', trivia: 'ギリシャ語・ラテン語 rhetoricus に由来し、英語の rhetorical と同語根。英語では rhetorical question（反語的質問）という表現が定着しており、スペイン語でも pregunta retórica と全く同じ構造で使われる。' },
  'retornable': { es: 'Por favor, devuelve las botellas retornables al supermercado para reciclarlas.', ja: 'リサイクルするためにリターナブルボトルをスーパーに返してください。', trivia: 'retornar（戻す）＋ -able（可能を示す接尾辞）から成る。英語の returnable と完全に同語根・同構造で、ラテン語 tornare（旋盤で回す→回転して戻る）が共通の語根。環境文脈でよく使われる。' },
  'retornada / retornado': { es: 'Los ciudadanos retornados del extranjero tuvieron que pasar por varios controles sanitarios.', ja: '海外から帰国した市民たちはいくつかの衛生検査を受けなければならなかった。', trivia: 'retornar の過去分詞。英語の returnee（帰還者）と意味が近いが、英語では returned より returnee が名詞として好まれる。語根のラテン語 tornare は英語の turn（回る）とも繋がる。' },
  'retornado': { es: 'El emigrante retornado trajo consigo nuevas perspectivas y experiencias del extranjero.', ja: '帰国した移民は、海外からの新たな視点と経験を持ち帰った。', trivia: '英語の returned（帰還した）に対応するが、名詞用法では英語の returnee により近い。ラテン語 tornare（回す）を語根に持ち、英語 turn、tournament（トーナメント）なども同系列の語。' },
  'retornar': { es: 'Después de años viviendo en el extranjero, decidió retornar a su tierra natal.', ja: '何年も海外で生活した後、彼は故郷に戻ることを決意した。', trivia: 'ラテン語 tornare（旋盤で回す）から re-（再び）＋ tornare で「元に戻る」という意味になった。英語の return と同語根であり、turn（回る）や tournament（馬上槍試合・選手が入れ替わる）も同じ語根に由来する。' },
  'retorno': { es: 'El retorno de los emigrantes a su tierra natal es un momento muy emotivo.', ja: '移民たちが故郷に帰還する瞬間は、とても感動的なものだ。', trivia: 'ラテン語 retornare（再び回る）を起源とし、英語の return と同語根。経済用語「リターン（収益率）」としても両言語で使われるが、スペイン語では「折り返し地点」という道路標識の意味でも日常的に使われる点が英語と異なる。' },
  'retorta': { es: 'El químico calentó el líquido en una retorta de vidrio para obtener el destilado.', ja: '化学者はガラスのレトルトで液体を加熱し、蒸留物を得た。', trivia: '中世ラテン語 retorta（ねじれたもの）に由来し、英語でも retort（レトルト、蒸留器）と全く同じ形をとる同語根語。英語の retort は「反論する」という動詞の意味でも使われるが、その語源も同じ「ねじり返す」イメージから来ている。' },
  'retortijón': { es: 'Después de comer esa comida en mal estado, me entraron unos retortijones terribles.', ja: 'あの傷んだ食べ物を食べた後、ひどい腹痛に襲われた。', trivia: '動詞 retorcer（ねじる）から派生し、ラテン語 torquere（ねじる）を語根とする。英語の cramp や torque も同じラテン語 torquere に由来しており、「ねじられるような痛み」というイメージが共通している。' },
  'retostada': { es: 'La carne quedó retostada por fuera pero jugosa por dentro.', ja: '肉は外側はこんがりと焼けていたが、中はジューシーだった。', trivia: '接頭辞 re-（過度に）＋ tostar（焼く）から成り、ラテン語 torrere（焼く、干す）を語根とする。英語の toast も同じラテン語語根から来ており、「こんがり焼いたパン」を指す toast と同じ系譜。過度を示す re- の用法はスペイン語特有の口語的強調表現。' },
  'retostado': { es: 'El pan quedó retostado porque me olvidé de sacarlo de la tostadora a tiempo.', ja: 'トースターから取り出すのを忘れてしまったので、パンは焼きすぎてしまった。', trivia: 'retostada の男性形で、語根はラテン語 torrere（焼く）。英語の toast と同語根であり、「over-toasted（焼きすぎた）」に相当するが、英語では一語で表すよりも burnt toast などと表現することが多い。' },
  'retozar': { es: 'Los cachorros retozaban en el jardín sin parar durante toda la tarde.', ja: '子犬たちは午後中ずっと庭で飛び回って遊んでいた。', trivia: '語源は諸説あり、古スペイン語の擬音語的な表現から来た可能性があるが定説はない。英語の frolic や gambol に相当するが、英語に直接の同語根語はない。frolic はオランダ語起源、gambol はフランス語経由のイタリア語起源と、それぞれ全く異なる経路をたどっている。' },
  'retozo': { es: 'El retozo de los niños en la playa llenó de alegría la tarde veraniega.', ja: '浜辺で子供たちがはしゃいで遊ぶ様子が、夏の午後を喜びで満たした。', trivia: '動詞 retozar から派生した名詞で、語源は不確かだが擬音語・擬態語的な起源が疑われる。英語の frolic（名詞・動詞）に意味が近いが、frolic はオランダ語 vrolijk（陽気な）に由来し、スペイン語 retozo とは全く語源が異なる。' },
  'retozón': { es: 'El gatito retozón no paraba de perseguir su propio rabo por toda la habitación.', ja: 'じゃれん坊の子猫は、部屋中で自分の尻尾を追いかけるのをやめなかった。', trivia: 'retozar の形容詞派生形で、語尾 -ón は「その性質を強く持つ者」を意味するスペイン語典型の接尾辞。英語では playful や frisky に相当するが、frisky はノルウェー語起源とされており、スペイン語の retozón とは語源的なつながりはない。' },
  'retozona': { es: 'La yegua retozona era la favorita de todos los niños de la granja.', ja: 'その遊び好きな牝馬は、農場の子供たち全員のお気に入りだった。', trivia: 'retozón の女性形。スペイン語では動物や人を形容する際、性別に応じて形容詞を変化させる。英語の playful や frisky は性別変化がなく、この点がロマンス語と英語の大きな違いのひとつ。' },
  'retracción': { es: 'La retracción del mercado inmobiliario afectó gravemente a muchas familias.', ja: '不動産市場の縮小は、多くの家族に深刻な影響を与えた。', trivia: 'ラテン語 retractio（引き戻すこと）に由来し、英語の retraction と同語根・同形に近い。医学では筋肉や組織の「収縮」を指し、経済学では「市場の縮小・冷え込み」を意味するなど、両言語で専門分野をまたいで使われる点が共通している。' },
  'retractación': { es: 'El político tuvo que hacer una retractación pública por sus declaraciones ofensivas.', ja: 'その政治家は、侮辱的な発言について公の場で撤回声明を出さなければならなかった。', trivia: 'ラテン語 retractatio（再検討・撤回）に由来し、英語の recantation や retractation に相当する。retracción（収縮）と混同されやすいが、retractación は「言葉・約束の撤回」に限定される点が重要な違い。英語でも retraction と recantation はほぼ同義だが、recantation は宗教的・思想的撤回に使われることが多い。' },
  'retractar': { es: 'El testigo se retractó de su declaración inicial ante el juez.', ja: '証人は裁判官の前で最初の証言を撤回した。', trivia: 'ラテン語 retractare（再び引く、再考する）に由来し、英語の retract と同語根。英語の retract は「(爪などを)引っ込める」という物理的な意味と「(発言を)撤回する」の両方で使われるが、スペイン語では retractar は主に「発言の撤回」に使い、物理的な収縮には retraer を使う傾向がある。' },
  'retráctil': { es: 'Las garras retráctiles del gato le permiten mantenerlas afiladas en todo momento.', ja: '猫の引っ込み式の爪は、常に鋭く保つことを可能にする。', trivia: 'ラテン語 retractilis に由来し、英語の retractable にほぼ対応する技術・生物学用語。航空機の「格納式降着装置（引き込み脚）」も retractable landing gear（英）/ tren de aterrizaje retráctil（西）と表現され、両語の対応が非常に明確な専門語のひとつ。' },
  'retractilidad': { es: 'La retractilidad de los tendones es esencial para la movilidad articular.', ja: '腱の収縮性は、関節の可動性にとって不可欠だ。', trivia: 'retráctil に接尾辞 -idad（英語の -ity に相当）を加えた抽象名詞で、英語では retractility と言う。生物学や材料工学で使われる専門用語で、スペイン語・英語ともに語形成の規則に従った「教科書的な」派生語といえる。' },
  'retractor': { es: 'El cirujano utilizó un retractor para mantener abierta la incisión durante la operación.', ja: '外科医は手術中に切開部を開いたままにするため、開創器を使用した。', trivia: 'ラテン語 retractor（引き戻す者）に由来し、英語でも全く同じ retractor という形で医療器具を指す。外科手術で切開部や臓器を引き開けて視野を確保する器具で、英語・スペイン語双方の医学用語として国際的に統一された形を持つ例。' },
  'retractora': { es: 'La pinza retractora fue diseñada específicamente para cirugía laparoscópica.', ja: 'その牽引鉗子は腹腔鏡手術のために特別に設計された。', trivia: 'retractor の女性形で、形容詞として使う際に名詞の性別に合わせる形。英語では retractor に男女の形態変化はないが、スペイン語の形容詞・名詞の性別一致という文法体系がロマンス語の大きな特徴のひとつ。' },
  'retraer': { es: 'La timidez lo llevaba a retraerse cada vez que intentaba hablar en público.', ja: '内気さのせいで、人前で話そうとするたびに引きこもってしまう。', trivia: 'ラテン語 retrahere（引き戻す）に由来し、英語の retract および withdraw と同語根。英語の withdraw（with-＋draw）がゲルマン語的な「引く」イメージで同じ意味を表すのに対し、retraer はラテン語系の接頭辞 re-＋trahere（引く）の組み合わせで、両語の語形成の違いが語源の違いを鮮明に示している。' },
  'retraída': { es: 'Siempre fue una persona retraída, pero tenía una inteligencia excepcional.', ja: '彼女はいつも内向的な人だったが、並外れた知性の持ち主だった。', trivia: 'retraer の過去分詞から派生した形容詞の女性形で、英語の withdrawn や introverted に相当。英語の withdrawn はもともと「引き出された」という過去分詞が形容詞化したもので、スペイン語の retraída（引き戻された→内向的な）と全く同じ意味変化のプロセスをたどっている点が興味深い。' },
  'retraído': { es: 'El niño retraído tardó varios meses en adaptarse a la nueva clase.', ja: 'その内向的な男の子が新しいクラスに馴染むのに数か月かかった。', trivia: 'retraída の男性形。英語の introverted は intro-（内側へ）＋vert（向ける）というラテン語由来の構造を持ち、スペイン語の retraído（re-「戻す」＋traído「引かれた」）とは別の語根だが、「内向き」という同じ心理的概念を表している。' },
  'retraimiento': { es: 'Su retraimiento social le impedía disfrutar de las reuniones con amigos.', ja: '社会的な引きこもりの傾向が、友人との集まりを楽しむことを妨げていた。', trivia: 'retraer に接尾辞 -miento（英語の -ment に相当）を加えた名詞で、英語では withdrawal または introversion に相当。withdrawal はもともと「引き出し」という行為を指す名詞で、ゲルマン語系。一方 introversion はラテン語 intro-（内側）＋vertere（向く）から来ており、スペイン語 retraimiento とは語根が異なる。' },
  'retranca': { es: 'Habla con tanta retranca que nunca sabes si va en serio o si te está tomando el pelo.', ja: 'あの人は含みのある言い方をするから、本気なのか冗談なのか全くわからない。', trivia: '語源は不確かで、馬具の「尻がい（britch, breaching）」から転じた可能性が高い。英語に直接対応する単語はなく、ironical understatement や dry wit が近い。スペイン語（特にガリシア地方や中南米）でのみ通じる文化的に深い表現で、英語化された概念では完全に置き換えられない語のひとつ。' },
  'retrancar': { es: 'El orador retrancó su crítica con tanta sutileza que pocos en el público se dieron cuenta.', ja: '演説者は批判をあまりにも巧みに皮肉に包んだので、聴衆の多くは気づかなかった。', trivia: 'retranca から派生した動詞で、語源は馬車の制動装置（尻がい）にさかのぼる。英語では to hint ironically や to speak with tongue in cheek などの表現に相当するが、これほど一語で「含みを持たせて話す」を表す動詞は英語には存在せず、スペイン語の語彙の豊かさを示す例といえる。' },
  'retranco': { es: 'El retranco que usó en su discurso confundió a más de uno entre el público.', ja: '演説で使った含みのある表現が、聴衆の中の何人かを混乱させた。', trivia: 'retranca の男性形で、地域によって使い分けられる。ラテンアメリカでは「ブレーキ・障害」の意味が強く、スペイン本土では「皮肉・裏のある言葉」として使われる。英語の brake はゲルマン語起源で全く語源が異なり、スペイン語の retranco（馬具起源）とは語源的なつながりはない。' },
  'retrasada': { es: 'La entrega del proyecto quedó retrasada debido a problemas técnicos inesperados.', ja: '予期しない技術的な問題のため、プロジェクトの納品が遅れた。', trivia: 'retrasar（遅らせる）の過去分詞の女性形で、ラテン語 trans-（向こうへ）が語根のひとつ。英語の delayed と意味が対応するが、delayed は古フランス語 delaier から来ており語源は異なる。なお、名詞的な用法の一部は現代では差別的とみなされており、discapacidad intelectual（知的障害）という表現が推奨される。' },
  'retrasado': { es: 'El tren llegó retrasado por culpa de las obras en la vía.', ja: '線路工事のせいで電車が遅れて到着した。', trivia: 'retrasada の男性形で、retrasar（re-＋atrasar「遅らせる」）の過去分詞から来る形容詞。英語の delayed はフランス語経由で中期英語に入った語で、スペイン語の retrasar とは語源的なつながりはない。名詞的用法の一部は現代では不適切とされており、使用する文脈に注意が必要。' },
  'retrasar': { es: 'Han decidido retrasar el lanzamiento del producto hasta el próximo trimestre.', ja: '彼らは製品の発売を来四半期まで延期することを決定した。', trivia: 'ラテン語 \'retro-\'（後ろへ）と \'tractus\'（引く）を組み合わせた語で、英語の \'delay\' や \'postpone\' に相当する。英語の \'retrace\'（引き返す）とは語根が近いが意味が異なる点に注意。' },
  'retraso': { es: 'El retraso en la entrega del pedido causó serios problemas a la empresa.', ja: '注文品の配送の遅延が会社に深刻な問題を引き起こした。', trivia: 'ラテン語 \'retro-\'（後ろへ）を語根に持ち、英語の \'delay\' に相当する名詞。英語には同語根の \'retrace\' があるが「遅延」の意味はなく、スペイン語の \'delay\' の借用語はほぼ使われない。' },
  'retratada': { es: 'La protagonista se ve retratada en el cuadro con una expresión solemne y distante.', ja: '主人公は、厳粛で遠い表情をした絵の中に描かれている。', trivia: 'ラテン語 \'retrahere\'（引き戻す・描き出す）の過去分詞形で、英語の \'portrayed\' に対応する。英語 \'portray\' はフランス語経由のラテン語 \'protrahere\'（前に引き出す）に由来し、スペイン語 \'retratar\' とは微妙に語根が異なる。' },
  'retratador': { es: 'El retratador del siglo XIX captaba la esencia de sus clientes con maestría.', ja: '19世紀の肖像画家は、その巧みさで依頼人の本質を捉えていた。', trivia: 'ラテン語 \'retrahere\'（描き出す）＋スペイン語の行為者接尾辞 \'-ador\' から成り、現代では \'retratista\' が一般的。英語の \'portraitist\' に相当し、\'portray\' と同じくラテン語 \'trahere\'（引く）が共通の語根だ。' },
  'retratar': { es: 'El fotógrafo logró retratar perfectamente el ambiente festivo de la ciudad.', ja: 'カメラマンは街の祭りの雰囲気を完璧に写し撮ることに成功した。', trivia: 'ラテン語 \'retrahere\'（再び引く・描き出す）に由来し、英語の \'portray\' や \'photograph\' に相当する。英語 \'portray\' はフランス語 \'portraire\' 経由だが、同じラテン語の \'trahere\'（引く）を語根とする点でスペイン語 \'retratar\' と遠縁にあたる。' },
  'retrato': { es: 'El retrato de la abuela presidía la sala desde hacía décadas.', ja: '祖母の肖像画は何十年もの間、居間の上座に飾られていた。', trivia: 'ラテン語 \'retrahere\'（引き戻す・描き出す）の名詞形で、英語の \'portrait\' に対応する。英語 \'portrait\' はフランス語 \'portrait\' 経由のラテン語由来で、スペイン語 \'retrato\' とは同じ概念を指しながらも形が異なる同義語的コグネートだ。' },
  'retribuible': { es: 'Las horas extra realizadas durante el fin de semana son retribuibles según el convenio.', ja: '週末に行った残業は、労働協定に基づいて報酬が支払われる対象となる。', trivia: 'ラテン語 \'retribuere\'（返す・報いる）＋形容詞接尾辞 \'-ible\' から成る。英語では \'remunerable\' や \'compensable\' に相当し、同語根の英単語 \'retributive\'（応報的な）とは意味が大きく異なる点に注意が必要だ。' },
  'retribución': { es: 'La retribución de los empleados se revisará a principios del próximo año.', ja: '従業員の報酬は来年初頭に見直される予定だ。', trivia: 'ラテン語 \'retributio\'（返すこと・報いること）に由来し、英語の \'remuneration\' や \'reward\' に相当する。英語 \'retribution\'（天罰・報い）は同語根だが、スペイン語 \'retribución\' が中立的な「報酬」を意味するのに対し、英語は否定的な「懲罰」の意味合いが強い好例のフォルスフレンドだ。' },
  'retribuir': { es: 'Es importante retribuir adecuadamente el esfuerzo de todos los trabajadores.', ja: 'すべての労働者の努力に対して適切に報酬を支払うことが大切だ。', trivia: 'ラテン語 \'retribuere\'（返す・報いる）に由来し、英語の \'remunerate\' や \'reward\' に相当する。英語の \'retribute\' という動詞はほぼ廃語だが、派生語の \'retributive\'（応報的な）は生きており、意味の重心がスペイン語より懲罰側に偏っている。' },
  'retributoria': { es: 'El nuevo sistema retributorio premiará el rendimiento individual de cada empleado.', ja: '新しい報酬制度は各従業員の個人的なパフォーマンスを報奨する。', trivia: 'ラテン語 \'retribuere\'（返す・報いる）＋接尾辞 \'-torio/a\' から成り、英語の \'remunerative\' に相当する。英語の \'retributory\' は「応報的な」という意味合いが強く、スペイン語の中立的な「報酬に関する」とは微妙にニュアンスが異なる。' },
  'retributorio': { es: 'El comité debatió los criterios del sistema retributorio para el personal docente.', ja: '委員会は教員の給与制度の基準について議論した。', trivia: 'ラテン語 \'retribuere\'（返す・報いる）に接尾辞 \'-torio\' を付けた形容詞で、英語の \'remunerative\'（報酬の）に対応する。英語の \'retributory\' は同語根だが「応報・懲罰」の意味で使われ、スペイン語の「報酬関係」という用法とは意味がずれているフォルスフレンドだ。' },
  'retroalimentación': { es: 'La retroalimentación de los clientes es esencial para mejorar el servicio.', ja: 'サービスを向上させるために顧客からのフィードバックは不可欠だ。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'alimentare\'（養う・供給する）から成るスペイン語的な造語で、英語の \'feedback\' を直訳した概念語。英語 \'feedback\' は電子工学から生まれた語だが、スペイン語では英語借用語 \'feedback\' も日常的に使われる。' },
  'retroalimentar': { es: 'Los errores cometidos retroalimentan el proceso de aprendizaje si se analizan bien.', ja: '犯したミスは、よく分析すれば学習プロセスにフィードバックされる。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'alimentare\'（養う）を組み合わせたスペイン語由来の動詞で、英語の \'to feed back\' に相当する。英語では動詞として \'feedback\' を使うことは少なく、スペイン語のほうが動詞化を完成させた点で語彙の体系が英語と異なる。' },
  'retrocarga': { es: 'Los fusiles de retrocarga revolucionaron la táctica militar en el siglo XIX.', ja: '元込め式ライフルは19世紀に軍事戦術に革命をもたらした。', trivia: 'ラテン語 \'retro-\'（後ろ）＋スペイン語 \'carga\'（積荷・装填）から成る複合語で、英語の \'breech-loading\'（後装式）に相当する。英語 \'breech\'（銃の尾部）はゲルマン語系で語根が異なり、スペイン語はラテン語系の \'retro-\' で同じ概念を表している。' },
  'retroceder': { es: 'El ejército tuvo que retroceder ante el ataque sorpresa del enemigo.', ja: '軍は敵の奇襲攻撃を前に後退せざるを得なかった。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'cedere\'（進む・退く）から成り、英語の \'recede\' や \'retreat\' に相当する。英語 \'recede\' も同じラテン語 \'cedere\' を語根とし、接頭辞だけが異なる（re- vs retro-）近縁の語だ。' },
  'retrocesión': { es: 'La retrocesión de los territorios ocupados fue exigida por el tratado de paz.', ja: '占領地域の返還は、平和条約によって要求された。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'cessio\'（譲渡）に由来し、英語の \'retrocession\' と形・意味ともにほぼ一致するコグネートだ。保険業界では「再々保険」を指す専門用語として英西両語で使われており、ラテン語由来の国際的な法律・金融用語の典型例といえる。' },
  'retroceso': { es: 'La economía experimentó un grave retroceso durante los años de la pandemia.', ja: '経済はパンデミックの期間中に深刻な後退を経験した。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'cessus\'（進んだこと）から成り、英語の \'setback\'・\'recession\'・\'recoil\' に相当する多義語。英語 \'recession\'（景気後退）とは同語根で意味も重なるが、スペイン語 \'retroceso\' のほうが「銃の反動」など物理的な用法も持つ点で広い。' },
  'retrogradación': { es: 'La retrogradación del almidón explica por qué el pan se endurece al enfriarse.', ja: 'デンプンの老化現象が、パンが冷えると硬くなる理由を説明している。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'gradus\'（歩み）から成り、英語の \'retrogradation\' とほぼ同形のコグネートだ。天文学では惑星の「逆行」を指すが、食品科学では澱粉の「老化」も意味し、同じ語が分野によって異なる概念に転用されている。' },
  'retrogradar': { es: 'Marte comienza a retrogradar en octubre, lo que algunos relacionan con cambios de humor.', ja: '火星は10月に逆行し始めるが、それを気分の変化と結びつける人もいる。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'gradari\'（歩む）から成る動詞で、英語の \'retrograde\'（動詞・形容詞）に対応する。英語 \'retrograde\' は形容詞・動詞・名詞の三役をこなすが、スペイン語では動詞 \'retrogradar\' と形容詞 \'retrógrado\' が分かれているのが特徴だ。' },
  'retrógrada': { es: 'Su actitud retrógrada respecto a la igualdad de género sorprendió a todos los presentes.', ja: 'ジェンダー平等に関する彼女の時代遅れな態度は、出席者全員を驚かせた。', trivia: 'ラテン語 \'retrogradus\'（後ろへ歩く）に由来し、英語の \'retrograde\' と形・意味ともに対応するコグネートだ。英語 \'retrograde\' は主に天文学用語や医学用語として使われるが、スペイン語 \'retrógrado/a\' は「保守的・反動的な人」という政治・社会的な意味でより頻繁に用いられる。' },
  'retrógrado': { es: 'Los sectores más retrógrados de la sociedad se opusieron a la reforma educativa.', ja: '社会の最も保守的な層が教育改革に反対した。', trivia: 'ラテン語 \'retrogradus\'（後方へ歩む）に由来し、英語の \'retrograde\' と同語源・同義のコグネートだ。英語では \'retrograde\' が主に科学・医学で使われるのに対し、スペイン語 \'retrógrado\' は日常会話でも「時代遅れな人」という意味で広く使われる。' },
  'retroproyector': { es: 'El profesor usó el retroproyector para mostrar los esquemas del tema a los alumnos.', ja: '先生はオーバーヘッドプロジェクターを使って、生徒たちにその単元の図解を見せた。', trivia: 'ラテン語 \'retro-\'（後ろへ）＋ \'proiectare\'（投影する）から成るスペイン語の複合語で、英語の \'overhead projector\'（OHP）に相当する。英語が機器の位置（頭上）で命名したのに対し、スペイン語は光が「後ろから前へ」投影される仕組みを名前に込めた点で命名の発想が異なる。' },
  'retrospectiva': { es: 'El museo organiza una retrospectiva de los cuadros más famosos del artista para conmemorar su centenario.', ja: '美術館は芸術家の生誕百周年を記念して、その最も有名な絵画の回顧展を企画している。', trivia: 'ラテン語 retrospicere（retro「後ろに」+ specere「見る」）に由来し、英語の retrospective とまったく同じ語源を持つ。IT・アジャイル開発でも「ふりかえり」の意味で retrospective（英）/ retrospectiva（西）が国際的に使われる。' },
  'retrospectivamente': { es: 'Retrospectivamente, aquel pequeño error de cálculo fue el inicio de todos nuestros problemas.', ja: '振り返ってみると、あの小さな計算ミスがすべての問題の始まりだった。', trivia: 'retrospectivo に副詞語尾 -mente を付けた形で、英語の retrospectively と一対一で対応する。ラテン語 retrospicere（後ろを見る）を共通の祖先に持ち、英語・スペイン語ともに形容詞に-lyまたは-menteを付けて副詞化するパターンが一致する。' },
  'retrospectivo': { es: 'El informe anual incluye un análisis retrospectivo de los logros y fracasos del año pasado.', ja: '年次報告書には昨年の成果と失敗についての回顧的な分析が含まれている。', trivia: 'ラテン語 retrospectus（後ろを見ること）の形容詞形で、英語の retrospective と同じ語根。英語では retrospective は形容詞にも名詞にも使えるが、スペイン語では名詞用法は主に女性形 retrospectiva が担う点が異なる。' },
  'retrucar': { es: 'Cuando el jefe le criticó el informe, ella retrucó con datos concretos que demostraban su trabajo.', ja: '上司がレポートを批判したとき、彼女は自分の仕事を証明する具体的なデータで即座に言い返した。', trivia: '語源には諸説あるが、フランス語 retrucquer（カードを切り返す）や truco（切り札、策略）と関連するとみられる。中南米では「口答えする」の意味で日常的に使われ、英語の retort や talk back に相当するが、英語に直接の同語根語はない。' },
  'retruco': { es: 'Su retruco fue tan ingenioso que dejó a todos los presentes sin palabras.', ja: '彼の即座の言い返しはあまりにも巧みで、その場にいた全員を言葉に詰まらせた。', trivia: '動詞 retrucar の名詞形。アルゼンチン・ウルグアイの伝統的なカードゲーム「Truco」でのルール用語としても有名で、相手の賭けを倍にする意味を持つ。英語の retort や counter に相当するが、ゲーム文化に根ざした独特のニュアンスがある。' },
  'retruécano': { es: 'El poeta usó un retruécano brillante: «¿Siempre se ha de sentir lo que se dice? ¿O se ha de decir lo que se siente?»', ja: '詩人は見事な倒置反復法を用いた。「常に感じることを言わねばならないのか？それとも感じることを言わねばならないのか？」', trivia: '語源はラテン語 retrucare（押し返す）とされ、単語や句の要素を入れ替えることで意味を反転させる修辞技法。英語の chiasmus（交差配列法）や pun に相当するが、retruécano は特に語句の転倒を伴う駄洒落・言葉遊びを指す点でより限定的な用語である。' },
  'retumbante': { es: 'El orador pronunció un discurso retumbante que llenó de emoción a todo el auditorio.', ja: 'その弁士は会場全体を感動で満たす鳴り響くような演説を行った。', trivia: 'retumbar（轟く）の現在分詞形で形容詞として使われる。英語の resounding や booming と意味が重なり、「resounding success（大成功）」のように比喩的な用法も共通する。ラテン語 tympanum（鼓膜・太鼓）と同じ語族と考える説もある。' },
  'retumbar': { es: 'Los truenos retumbaban en el valle mientras la tormenta se acercaba a la ciudad.', ja: '嵐が町に近づく中、雷鳴が谷に轟き渡った。', trivia: '語源は不明確だが、re-（再び・強意）+ tumbar（倒す・響く）の合成語とする説が有力。英語の resound や rumble に相当し、rumble はゲルマン語系でスペイン語とは語族が異なるが、音の響きが似た擬音的な語として興味深い対比をなす。' },
  'retumbo': { es: 'Se escuchó un retumbo profundo bajo la tierra justo antes del temblor.', ja: '地震の直前、大地の下から深い地響きが聞こえた。', trivia: '動詞 retumbar の名詞形。英語の rumble や boom に対応し、特に低周波の轟音を指す。rumble はゲルマン語系で語族は異なるが、どちらも低くくぐもった音を表す擬音語的性格を持つ点が共通している。' },
  'reuma': { es: 'Mi abuela sufre de reuma y en los días fríos le duelen mucho las manos.', ja: '祖母はリウマチを患っており、寒い日には手がとても痛む。', trivia: 'ギリシャ語 rheuma（流れるもの、体液）に由来し、古代医学では「悪い体液が関節に流れ込む」と考えられていたことから命名された。英語の rheumatism も同じ語根で、スペイン語では reumatismo の短縮形として reuma が口語的に広く使われる。' },
  'reumático': { es: 'El médico le recomendó ejercicio moderado al paciente reumático para mantener la movilidad articular.', ja: '医師はリウマチ患者に関節の可動性を保つために適度な運動を勧めた。', trivia: 'ギリシャ語 rheumatikos（体液に関する）に由来し、英語の rheumatic と同語根の典型的なコグネート。英語でも「rheumatic pain（リウマチの痛み）」のように形容詞・名詞両用で使われる点がスペイン語と共通している。' },
  'reumatismo': { es: 'El reumatismo puede afectar no solo las articulaciones, sino también otros tejidos del cuerpo.', ja: 'リウマチは関節だけでなく、体の他の組織にも影響を与えることがある。', trivia: 'ギリシャ語 rheuma（流れ）+ 接尾辞 -ismos に由来し、英語の rheumatism とまったく同語根の完全なコグネート。現代医学では「リウマチ性疾患」の総称として使われ、英語・スペイン語ともに同じ概念をほぼ同形の単語で表す。' },
  'reumatólogo': { es: 'El reumatólogo solicitó una serie de análisis de sangre para confirmar el diagnóstico de artritis reumatoide.', ja: 'リウマチ科医は関節リウマチの診断を確定するために一連の血液検査を指示した。', trivia: 'ギリシャ語 rheuma（体液・流れ）+ logos（学問）に由来する reumatología（リウマチ学）の専門家を指す語。英語の rheumatologist とほぼ同語根で、医学分野では英語・スペイン語間でこうした並行的な造語パターンが多く見られる。' },
  'reunión': { es: 'La reunión de equipo de los lunes nos sirve para organizar las tareas de la semana.', ja: '月曜日のチームミーティングは週の業務を整理するのに役立っている。', trivia: 'ラテン語 reunire（re-「再び」+ unire「一つにする」）に由来し、英語の reunion と同語根の完全なコグネート。ただし英語では reunion は主に「再会」の意味で使われるのに対し、スペイン語の reunión は「会議・ミーティング」の意味で日常的に幅広く使われる点が異なる。' },
  'reunido': { es: 'Con todo el equipo reunido en la sala, el director presentó los resultados del trimestre.', ja: 'チーム全員が会議室に集まり、部長が四半期の結果を発表した。', trivia: '動詞 reunir の過去分詞で形容詞として機能する。英語の gathered や assembled に相当し、ラテン語 unire（一つにする）を語根に持つ。英語の united（団結した）も同じ語根 unire から派生しており、「一つに集める」という共通のイメージが語源に反映されている。' },
  'reunir': { es: 'Para solicitar la beca, tienes que reunir todos los documentos requeridos antes del plazo.', ja: '奨学金を申請するには、期限前に必要書類をすべて揃えなければならない。', trivia: 'ラテン語 reunire（re-「再び」+ unire「一つにする」）に由来し、英語の reunite と同語根。ただし英語 reunite は「再会させる」のニュアンスが強いのに対し、スペイン語 reunir は「集める・条件を満たす」など意味の幅が広く、偽コグネートに近い使い分けが必要。' },
  'reválida': { es: 'Aprobó la reválida de medicina con una de las notas más altas de su promoción.', ja: '彼女は医師免許認定試験を学年最高点の一つで合格した。', trivia: 'ラテン語 revalidare（再び有効にする）に由来し、スペインでは20世紀中頃まで中等・高等教育の修了を国家が認定する統一試験を指した。英語の revalidation examination に相当するが、英語に同形の口語的な一語は存在せず、スペイン語ならではの教育文化的な語彙といえる。' },
  'revalidación': { es: 'Para ejercer como médico en este país, es necesaria la revalidación del título obtenido en el extranjero.', ja: 'この国で医師として働くには、海外で取得した学位の認定が必要だ。', trivia: 'ラテン語 re-（再び）+ validus（強い・有効な）から派生した revalidar の名詞形。英語の revalidation と完全なコグネートで、valid（有効な）は英語でも同じ語根を持つ。資格・免許の国際的な流動性が高まる現代で特に重要な語となっている。' },
  'revalidar': { es: 'El campeón logró revalidar su título al ganar la final por segundo año consecutivo.', ja: 'チャンピオンは2年連続で決勝を制し、タイトル連覇を果たした。', trivia: 'ラテン語 re-（再び）+ validare（有効にする）に由来し、英語の revalidate と同語根の完全なコグネート。スポーツ文脈では「タイトルを防衛する」という意味で頻繁に使われ、英語の defend（a title）に相当するが、スペイン語では revalidar という一語でより端的に表現できる。' },
  'revancha': { es: 'El equipo perdedor exigió una revancha para demostrar que el resultado anterior no fue justo.', ja: '負けたチームは前回の結果が公平でなかったことを証明するために再試合を要求した。', trivia: 'フランス語 revanche（報復・仕返し）に由来し、さらにフランク語系ゲルマン語の wranken（曲げる・返す）が語源とされる。英語の revenge も同じくフランス語経由でラテン語 vindicare（主張する）に遡るが、revancha と revenge は意味は近くても語根が異なる偽コグネートに近い関係にある。' },
  'revanchista': { es: 'El partido revanchista prometió recuperar los territorios perdidos en la guerra anterior.', ja: 'その復讐主義的な政党は、前の戦争で失った領土を取り戻すと約束した。', trivia: 'フランス語 «revanche»（復讐・リベンジ）から来た借用語で、普仏戦争後にフランスがアルザス＝ロレーヌ奪還を目指した政治思想を指す言葉として広まった。英語でも «revanchist» がほぼ同形・同義で使われ、政治・外交の文脈で頻出する国際語となっている。' },
  'revendedora': { es: 'La revendedora compró cien entradas para el concierto y las vendió al triple del precio original.', ja: 'その転売屋はコンサートのチケットを100枚買い、定価の3倍で売りさばいた。', trivia: '«re-» （再び）＋ «vender»（売る）から派生した名詞で、ラテン語 «vendere»（売る）が語根。英語の «reseller» や «scalper»（チケット転売屋）に対応し、同語根の英単語には «vend»（自販機で売る）や «vendor» がある。' },
  'revendedor': { es: 'El revendedor de entradas fue multado por las autoridades durante el partido de fútbol.', ja: 'そのチケット転売屋はサッカーの試合中に当局から罰金を科された。', trivia: '«re-» ＋ «vender»（ラテン語 «vendere» 由来）から派生した男性名詞形。英語の «vendor» や «vend» と同語根であり、英語では «reseller» または非公式に «scalper» と言う。' },
  'revender': { es: 'Muchos jóvenes compran ropa de segunda mano para revenderla con ganancia en internet.', ja: '多くの若者がネットで利益を得るために古着を買って転売している。', trivia: 'ラテン語 «re-» （再び）＋ «vendere»（売る）が語源で、英語の «resell» と構造も意味もほぼ同じ。英語の «sell» もゲルマン語系なので語根は異なるが、接頭辞 «re-» は共通のラテン語由来。' },
  'revenida': { es: 'El pan revenido del día anterior ya no estaba bueno para comer.', ja: '前日の湿気ったパンはもう食べられる状態ではなかった。', trivia: '動詞 «revenir»（戻る・なる）の過去分詞で、「しっとりしすぎた状態に戻った」というニュアンスから「しけった・湿気った」を意味する。英語に直接対応する同語根語はないが、金属の「焼き戻し」の意味では英語の «tempering» に相当する技術用語として使われる。' },
  'revenido': { es: 'El acero revenido es más flexible y resistente que el acero simplemente endurecido.', ja: '焼き戻しされた鋼は、単に硬化させた鋼よりも柔軟で耐久性が高い。', trivia: '«revenir»（再び来る・戻る）の過去分詞男性形で、金属加工では「焼き戻し（tempering）」を意味する専門用語。英語の «tempered steel» に相当し、«re-» ＋ラテン語 «venire»（来る）が語根で、英語の «convene»・«advent» とも遠縁の関係にある。' },
  'reventadero': { es: 'Ese trabajo en la mina era un verdadero reventadero; nadie aguantaba más de tres meses.', ja: 'あの鉱山の仕事は本当に過酷な職場で、3か月以上続く人は誰もいなかった。', trivia: '«reventar»（破裂する・疲れ果てる）に場所を示す接尾辞 «-dero» を付けた名詞で、「人がはち切れるほど消耗する場所」を意味する。英語に直接対応する1語はなく、«breakpoint» や «grueling workplace» で表現する。ラテン語 «rumpere»（破る）系の語ではなく、語源は諸説あり不明瞭な部分もある。' },
  'reventar': { es: 'Me revienta que la gente no respete el turno en la cola.', ja: '列に並ぶ順番を守らない人には本当にうんざりする。', trivia: '語源は諸説あり、ラテン語 «re-» ＋ «ventus»（風）から「風圧で破裂する」説や別語源説もある。英語では «burst»・«pop»・«explode» が基本義に対応し、口語で「激怒させる」意味は英語の «drives me crazy» や «annoys me to death» に近い。' },
  'reventón': { es: 'Tuve un reventón en la autopista y tuve que llamar a la grúa.', ja: '高速道路でパンクして、レッカー車を呼ばなければならなかった。', trivia: '«reventar» の名詞形（接尾辞 «-ón» は「大きな〜・強烈な〜」を示す増大辞）。英語では「タイヤのパンク」を «blowout» と言い、意味・イメージが非常に近い表現同士。メキシコ口語で「大パーティー」を指す用法は、英語の «blowout party» とも重なる興味深い意味の一致がある。' },
  'reventona': { es: 'La fiesta estuvo reventona; llegaron más de doscientas personas.', ja: 'そのパーティーは大盛況で、200人以上が来た。', trivia: '«reventón» の女性形・形容詞形で、中米口語で「大ヒット・大盛り上がり」を意味する。英語に直接対応する語はないが、«packed» や «sold-out» に近い感覚。«reventar» 自体の語源は諸説あるが、破裂・爆発のイメージが「大盛況」という肯定的意味に転じた興味深い意味変化の例。' },
  'reverberación': { es: 'La reverberación en esa catedral dura varios segundos y hace que la música suene etérea.', ja: 'あの大聖堂の残響は数秒間続き、音楽を幻想的に響かせる。', trivia: 'ラテン語 «reverberare»（打ち返す）＝ «re-»（再び）＋ «verberare»（打つ・鞭打つ）が語源で、英語 «reverberation» と同語根の完全なコグネート。音楽制作では英語圏でも «reverb» と略されるが、スペイン語でも «reverb» が口語で使われることがある。' },
  'reverberar': { es: 'El sonido del trueno reverberaba entre las montañas durante varios minutos.', ja: '雷の音は数分間、山々の間に響き渡った。', trivia: 'ラテン語 «reverberare»（跳ね返す・反響させる）が語源で、英語 «reverberate» と同語根の完全コグネート。«verberare» はラテン語で「打つ」を意味し、英語の «verbal》（言葉の）とは語根が異なる別語族。音響・建築の専門用語として日英両語で使われる。' },
  'reversa': { es: 'Pon el coche en reversa para salir del estacionamiento.', ja: '駐車場から出るために、車をバックギアに入れて。', trivia: 'ラテン語 «reversus»（戻った）が語源で、英語 «reverse》と同語根の完全コグネート。ラテン語 «re-» ＋ «vertere»（向ける・回す）から派生し、英語の «revert》・«diverse》・«convert》なども同じ «vertere》 を共有する大きな語族を形成している。' },
  'revistar': { es: 'El general revistó a las tropas antes de que partieran hacia la frontera.', ja: '将軍は部隊が国境へ向けて出発する前に閲兵を行った。', trivia: '«re-» ＋ «vistar》（見る）、さらにラテン語 «videre》（見る）が語根で、英語 «review》・«visit》・«vision》と同語族。英語の «inspect》（ラテン語 «inspicere》）とは語根は異なるが意味が近く、軍事文脈では «review troops》に対応する。' },
  'revista': { es: 'Compro esa revista de ciencias cada mes porque los artículos son muy interesantes.', ja: '記事がとても面白いので、私は毎月その科学雑誌を買っている。', trivia: 'ラテン語 «re-» ＋ «videre》（見る）が語源で、英語 «review》と同語根のコグネート。「雑誌」の意味では英語 «magazine》に対応するが、語源は全く異なり «magazine》はアラビア語 «makhāzin》（倉庫）由来。スペイン語では «revista》が「雑誌」の標準語として定着した。' },
  'sábado': { es: 'El sábado por la tarde me gusta dar un paseo largo por el parque.', ja: '土曜日の午後は公園をゆっくり散歩するのが好きだ。', trivia: 'ヘブライ語 «shabbat》（安息日）がギリシャ語・ラテン語を経由して伝わった言葉。英語の «Saturday》はゲルマン神話の土星神サトゥルヌス（Saturn）に由来しており、同じ曜日を指しながらまったく異なる語源を持つ対照的なペア。英語 «Sabbath》（安息日）はスペイン語 «sábado》と同じヘブライ語 «shabbat》が語源。' },
  'sabandija': { es: 'Ese sabandija me robó la cartera mientras yo miraba el escaparate.', ja: 'あのクズ野郎はショーウィンドウを見ていた私の財布を盗んだ。', trivia: '語源は不明・諸説あり、一説ではラテン語 «sub》（下）＋ «anguis》（蛇）に由来するとも言われる。英語に直接対応する同語根語はなく、意味的には «pest》・«creep》・«scoundrel》で表現される。もともと「小さな不快な生き物」を指す言葉が人への強い侮蔑語に転じた点が面白い。' },
  'sábana': { es: 'Después del lavado, tendí las sábanas al sol para que se secaran bien.', ja: '洗濯の後、シーツをよく乾かすために日光の下に広げた。', trivia: 'ラテン語 «sabana》（亜麻布）が語源とされ、元はカリブ先住民語由来の «sabana》（大草原）とはアクセント位置で区別される（sábana＝シーツ vs sabana＝サバンナ）。英語 «sheet》はゲルマン語系で語源が異なるが、英語 «savanna/savannah》はスペイン語 «sabana》を経由して入った借用語。' },
  'sabanear': { es: 'Los vaqueros sabaneaban el ganado desde el amanecer hasta el atardecer en los llanos.', ja: 'カウボーイたちは夜明けから夕暮れまで平原で家畜を見回っていた。', trivia: '«sabana》（サバンナ・大草原）に動詞化接尾辞 «-ear》を付けた中南米固有の動詞。英語に直訳できる対応語はなく、「サバンナで働く」行為を «herd cattle on the savanna》などと説明するしかない。«sabana》自体がタイノ語（カリブ先住民語）由来で、英語 «savanna》もスペイン語を経由した借用語。' },
  'sabanero': { es: 'El cantante sabanero interpretó una canción típica de los llanos colombianos.', ja: 'そのサバンナ出身の歌手はコロンビアの大平原の典型的な歌を歌った。', trivia: '«sabana》（サバンナ、タイノ語由来）＋形容詞・名詞接尾辞 «-ero》から派生した語。英語に直接対応する語はなく、「サバンナのカウボーイ」を指す場合は «plainsman》や «llanero》（別のスペイン語）で表現される。英語 «savanna》はスペイン語 «sabana》を経由した借用語であるため、間接的に同語族と言える。' },
  'sabanilla': { es: 'La enfermera colocó una sabanilla limpia sobre la camilla antes de que entrara el paciente.', ja: '看護師は患者が入る前に診察台に清潔な使い捨てシーツを敷いた。', trivia: '«sábana》（シーツ）の指小辞形（«-illa》で「小さな〜」を表す）で、医療現場では使い捨て防水シーツを指す。英語では «disposable sheet》や «exam table paper》と説明的に訳すしかなく、対応する1語がない。«sábana》はラテン語 «sabana》（亜麻布）が語源とされ、英語 «sheet》はゲルマン語系で語根は異なる。' },
  'sabihonda': { es: 'La sabihonda de la clase siempre interrumpía al profesor para demostrar que lo sabía todo.', ja: 'クラスの知ったかぶり屋はいつも、何でも知っていることを見せようと先生の話を遮った。', trivia: '«saber》（知る）＋ «-hondo/-honda》（深い、ラテン語 «profundus》由来）が合わさった合成語で、「知識が深い（つもりの）人」が皮肉に転じた。英語の «know-it-all》と意味・ニュアンスが非常に近く、英語にも «wiseacre》という似た意味の古語があるが現在は «know-it-all》が一般的。' },
  'sabihondo': { es: 'No seas sabihondo y deja que los demás también opinen sobre el tema.', ja: '知ったかぶりをやめて、他の人たちにも意見を言わせてあげなさい。', trivia: '«saber》（知る、ラテン語 «sapere》由来）＋ «hondo》（深い）の合成語の男性形。英語の «know-it-all》に対応し、同じ «sapere》語根からは英語 «sapient》（賢明な）・«sage》（賢者）なども派生している。皮肉な意味合いを持つ点では英語 «wiseacre》や «smarty-pants》にも近い。' },
  'sabiduría': { es: 'La sabiduría no se adquiere solo con los libros, sino también con las experiencias de la vida.', ja: '知恵は本だけでなく、人生の経験からも身につくものだ。', trivia: 'ラテン語 sapidus（知恵のある）から派生し、スペイン語の動詞 saber（知る）と同語根。英語の wisdom とは語根が異なるが、英語では knowledge（知識）や wisdom（英知）に相当し、同語根の英単語としては sapient（賢明な）や sage（賢者）が挙げられる。' },
  'sabio': { es: 'El sabio maestro nos enseñó que escuchar es más importante que hablar.', ja: 'その賢明な先生は、話すよりも聞くことの方が大切だと教えてくれた。', trivia: 'ラテン語 sapius（賢い）から来ており、英語の sage（賢者、セージ）と同語根。英語で wise に相当するが、英語 wise はゲルマン語系（古英語 wīs）で語源が異なる点が興味深い。' },
  'sablar': { es: 'Ese tipo siempre intenta sablarte cuando anda sin dinero.', ja: 'あいつはお金がないとき、いつも君にたかろうとする。', trivia: 'sable（サーベル）という名詞から派生した動詞で、「刃物で脅して金を奪う」という含意がある。英語の saber または sabre と同語根で、これらはフランス語 sabre 経由でドイツ語やスラブ語系統の語に遡るとされる。' },
  'sable': { es: 'El oficial desenvainó el sable durante la ceremonia militar.', ja: 'その将校は軍の式典でサーベルを鞘から抜いた。', trivia: 'フランス語 sabre 経由で中高ドイツ語 sabel、またはハンガリー語・スラブ語系統の語に遡るとされる。英語でも saber（米）または sabre（英）として使われ、スペイン語の sable と同じ語源を共有する兄弟語。' },
  'sablear': { es: 'No me gusta salir con él porque siempre intenta sablearme cuando llegamos a la caja.', ja: '彼とは外出したくない。会計になるといつも私にたかろうとするから。', trivia: 'sablar と同じく sable（サーベル）から派生した動詞で、sablar の同義語または変形として用いられる。英語に直接対応する同語根語はないが、to sponge off someone（たかる）が意味的に近い表現。' },
  'sabotaje': { es: 'El sabotaje de la maquinaria paralizó la producción durante varios días.', ja: '機械へのサボタージュにより、生産が数日間停止した。', trivia: 'フランス語 sabotage から直接借用された語で、フランス語の sabot（木靴）に由来するとされる。英語の sabotage もフランス語から同じルートで借用しており、スペイン語・英語ともに語源・スペルがほぼ同一の国際語。' },
  'sabotear': { es: 'Intentaron sabotear las negociaciones de paz filtrando información confidencial a la prensa.', ja: '機密情報をマスコミにリークすることで、和平交渉を妨害しようとした。', trivia: '名詞 sabotaje（サボタージュ）から派生した動詞。英語の to sabotage と完全に同じ意味・語源を持ち、フランス語 saboter（木靴で踏みつける）が原形。語形もほぼ同じ典型的な国際語。' },
  'saboteadora': { es: 'La saboteadora fue detenida antes de poder inutilizar el generador eléctrico.', ja: 'その女性破壊工作員は発電機を壊す前に拘束された。', trivia: 'sabotear の行為者名詞で、英語の saboteur に相当する。英語 saboteur はフランス語から直接借用されたのに対し、スペイン語では動詞 sabotear に -dor/-dora の接尾辞を付けて派生させており、語形成の方法が異なる。' },
  'saboteador': { es: 'Las autoridades sospechan que el saboteador actuó desde dentro de la empresa.', ja: '当局は、破壊工作員が会社内部から行動したと疑っている。', trivia: 'saboteadora の男性形。英語では性別区別なく saboteur を使うのに対し、スペイン語では -dor（男性）/-dora（女性）と性による区別がある。英語 saboteur 同様、フランス語由来の語族に属する。' },
  'sabrosamente': { es: 'El pollo estaba sabrosamente condimentado con especias de la región.', ja: 'その鶏肉は地域の香辛料で風味豊かに味付けされていた。', trivia: '形容詞 sabroso（美味しい）に副詞語尾 -mente を付けた語で、ラテン語 sapor（味）に由来する。英語の savor（風味）や savory（風味のある）と同語根であり、「味わう」を意味する系統の語族を共有している。' },
  'sabrosa': { es: 'Esta salsa picante es muy sabrosa y va perfecta con el arroz.', ja: 'この辛いソースはとても美味しくて、ご飯によく合う。', trivia: 'ラテン語 sapor（風味、味）から派生しており、英語の savory（風味豊かな）と同語根。英語 tasty や delicious はそれぞれゲルマン系・フランス系語源で別語族だが、savory だけがスペイン語 sabroso と共通の語根を持つ近縁語。' },
  'sabroso': { es: 'En el Caribe dicen que la música sabrosa te hace mover el cuerpo sin querer.', ja: 'カリブ海では、ノリの良い音楽は思わず体を動かしてしまうと言われている。', trivia: 'ラテン語 sapidus（風味のある）から来ており、英語の sapid（味の良い）と同語根。英語では「美味しい」を tasty や delicious と言うが、sabroso の持つ「音楽・雰囲気がノリ良い」という中南米的用法は英語には直接対応する単語がなく興味深い。' },
  'sabueso': { es: 'El sabueso siguió el rastro del fugitivo durante horas sin perder la pista.', ja: 'その警察犬は逃走者の足跡を何時間も見失わずに追い続けた。', trivia: '語源は不明・諸説あり、ラテン語 Sagax（鋭い嗅覚を持つ）またはゲルマン系語との混合という説がある。英語では bloodhound（猟犬）や sleuth（探偵）に相当し、sleuth はもともとノルウェー語で「足跡」を意味していたのとは対照的に、sabueso は嗅覚に焦点を当てた語とされる。' },
  'saca': { es: 'El cartero llegó con una gran saca llena de paquetes navideños.', ja: '郵便配達員がクリスマスの荷物でいっぱいの大きな郵袋を持ってやってきた。', trivia: '動詞 sacar（取り出す）から派生した名詞で、ラテン語 saccus（袋）に遡るとされる。英語の sack（袋）と同語根であり、両語ともにギリシャ語 sakkos 経由でセム語族に遡る古い借用語。' },
  'sacabocado': { es: 'El técnico utilizó un sacabocado para hacer los agujeros en la correa de cuero.', ja: '技術者は革ベルトに穴を開けるためにポンチを使った。', trivia: 'sacar（取り出す）と bocado（一口、穴）を組み合わせた複合語で、「一口分を抜き取る道具」という意味合いを持つ。英語の punch（穴あけ器）とは全く語源が異なり、英語 punch はラテン語 punctum（刺す）に由来する。' },
  'sacabocados': { es: 'El zapatero sacó su sacabocados para ajustar el cinturón al cliente.', ja: '靴職人は客のベルトのサイズを合わせるためにポンチを取り出した。', trivia: 'sacabocado と同義の複数形固定名詞（単複同形）。sacar（取り出す）＋bocados（一口ずつ）という構成で、英語の hole punch や leather punch に相当するが、英語ではこのような複合動詞型の命名はあまり見られない。' },
  'sacacorchos': { es: '¿Tienes un sacacorchos? No consigo abrir esta botella de vino.', ja: 'コルク抜きを持っていない？このワインのボトルがどうしても開けられないんだけど。', trivia: 'sacar（取り出す）＋corchos（コルクの複数形）からなる複合語で、「コルクを引き抜く道具」を指す。英語の corkscrew（コルク抜き）は cork＋screw（ねじ）の複合語で、動作の描写方法が異なる。スペイン語は「何を取り出すか」、英語は「どうやって抜くか（螺旋状に）」に着目している点が興味深い。' },
  'sacadinero': { es: 'Ese parque de atracciones es un sacadinero: pagas una fortuna por nada.', ja: 'あの遊園地は金食い虫だ。何もないのに大金を払わされる。', trivia: 'sacar（取り出す）＋dinero（お金）の複合語で、「金をむしり取るもの」という意味。英語の money pit（際限なく金がかかるもの）や rip-off（ぼったくり）に相当するが、英語にこの語根の同形語はなく、スペイン語独自の複合語命名スタイルを反映している。' },
  'sacadineros': { es: 'No compres esa aplicación; es un sacadineros que te cobra por cada función básica.', ja: 'そのアプリは買わない方がいい。基本機能のひとつひとつに課金してくるぼったくりだ。', trivia: 'sacadinero の単複同形バリアント。sacar＋dineros という複合動詞名詞型の造語で、英語では nickel-and-dime（細かくぼったくる）や cash cow（金のなる木）が部分的に近いが、ネガティブニュアンスを持つ完全な同義語はない。' },
  'sacadura': { es: 'La sacadura de los fondos del banco requirió la firma de dos directivos.', ja: '銀行からの資金引き出しには、2名の役員の署名が必要だった。', trivia: 'sacar（取り出す）に名詞接尾辞 -dura を付けた語で、ラテン語 saccāre に遡るとされる。英語の extraction（抽出）はラテン語 extrahere（引き出す）由来で語根が異なる。-dura 接尾辞（cf. costura 縫い目、rotura 破れ）は英語の -ure（cf. closure, fracture）に対応するロマンス系接尾辞の典型例。' },
  'sacafilásticas': { es: 'El artillero usó la sacafilásticas para limpiar el oído del cañón antes del disparo.', ja: '砲兵は発射前に大砲の火門を掃除するため、クリーニング針を使った。', trivia: 'sacar（取り出す）＋filástica（麻縄のほつれ、フィラスティカ）から成る複合語で、大砲の点火孔に詰まった燃焼残滓を取り除く専用工具を指す歴史的・軍事的用語。英語に直接対応する同語根の語はなく、vent pick や priming wire と呼ばれる。' },
  'sacaliña': { es: 'Con sus sacaliñas y halagos, logró sonsacarle el secreto a su amigo.', ja: 'お世辞やおだてを駆使して、友人から秘密を聞き出すことに成功した。', trivia: '語源は諸説あり明確ではないが、sacar（取り出す）と関連するとも言われる口語・方言的な語。英語では wheedling（おだてて聞き出すこと）や coaxing（甘言）に近いが、同語根の英単語は存在しない。中米では「ゆすり」の意味でも使われる地域差が大きい語。' },
  'sacamanchas': { es: 'Este sacamanchas en spray es muy efectivo para quitar las manchas de vino tinto.', ja: 'このスプレータイプのシミ抜き剤は、赤ワインのシミを落とすのにとても効果的だ。', trivia: 'sacar（取り出す）＋manchas（シミの複数形）から成る複合語。英語の stain remover に相当するが、英語は「除去剤（remover）」という名詞型なのに対し、スペイン語は「シミを取り出すもの」という動詞型の命名で発想が異なる。' },
  'sacamiento': { es: 'El sacamiento de los archivos secretos fue ordenado por el tribunal.', ja: '機密ファイルの引き出しは、裁判所によって命じられた。', trivia: 'sacar（取り出す）に名詞接尾辞 -miento を付けた語で、行為そのものを表す。英語の extraction や removal に相当するが、-miento 接尾辞（cf. pensamiento 思考、movimiento 動き）は英語の -ment（cf. movement, treatment）に対応するロマンス系語形成の典型例。' },
  'sacamuelas': { es: 'El sacamuelas de la plaza vendía su jarabe milagroso a los incautos turistas.', ja: '広場のいかさま医者は、騙されやすい観光客に奇跡の薬を売りつけていた。', trivia: 'sacar（抜く）＋muelas（臼歯の複数形）から成る複合語で、もともとは歯を抜く行商人・流しの歯医者を指した。英語では quack（やぶ医者）や charlatan（ペテン師）に相当し、charlatan 自体もイタリア語 ciarlatano（大声で売り込む行商人）に由来する国際的な語。' },
  'sacanete': { es: 'En la novela histórica, los caballeros jugaban al sacanete en las tabernas de Madrid durante el siglo XVII.', ja: '歴史小説の中で、騎士たちは17世紀のマドリードの居酒屋でサカネテ（トランプゲーム）に興じていた。', trivia: 'sacaneteはフランス語のlanquenetまたはlancquenetに由来し、ドイツ語のLandsknecht（傭兵）が語源とされる。英語でもlansquenetという名で同様のカードゲームが知られており、ヨーロッパ各地の傭兵文化とともに広まった賭けカードゲームである。' },
  'sacapotras': { es: 'No le hagas caso a ese sacapotras; mejor busca un médico de verdad antes de que te haga daño.', ja: 'あのヤブ医者の言うことは聞かないで。怪我をさせられる前に本物の医者を探した方がいい。', trivia: 'sacapotrasはsacar（取り出す）とpotras（若い牝馬、転じて内臓）の合成語で「内臓を引き出す者」という皮肉な意味を持つ。英語のquack（インチキ医者）はオランダ語のquacksalver（水銀軟膏を売る者）に由来し、語源は全く異なるが、社会的な機能は同じである。' },
  'sacapuntas': { es: '¿Me prestas tu sacapuntas? Se me ha roto el mío y necesito afilar el lápiz antes del examen.', ja: '鉛筆削りを貸してもらえますか？私のが壊れてしまって、試験前に鉛筆を削らなければならないんです。', trivia: 'sacapuntasはsacar（取り出す・引き出す）とpuntas（先端の複数形）を組み合わせた複合語で「先端を出す道具」という意味。英語ではpencil sharpenerと言い、sharpener（鋭くするもの）という発想であるのに対し、スペイン語では「先を引き出す」という発想の違いが興味深い。' },
  'sacarina': { es: 'El médico le recomendó usar sacarina en lugar de azúcar para controlar su nivel de glucosa en sangre.', ja: '医師は血糖値を管理するために砂糖の代わりにサッカリンを使うよう勧めた。', trivia: 'sacarinはラテン語のsaccharum（砂糖）に由来し、これはギリシャ語のsakkharon、さらにサンスクリット語のśarkarā（砂糖、砂利）が語源。英語のsaccharinも同語根であり、日本語の「砂糖」という言葉もこの語系統と間接的に関係する。' },
  'sacarino': { es: 'El sabor sacarino de ese refresco artificial me resulta desagradable comparado con el jugo natural.', ja: 'その人工飲料の砂糖っぽい甘さは、天然ジュースと比べると私には不快に感じられる。', trivia: 'sacarino（糖分の、砂糖のような）はラテン語saccharum（砂糖）から派生した形容詞。英語のsaccharine（甘ったるい、過度に甘い）は転じて「ぞっとするほど甘い、嘘っぽい感傷的な」という比喩的意味でも使われ、スペイン語でも同様のニュアンスが生じつつある。' },
  'sacarosa': { es: 'La sacarosa es el azúcar de mesa común, formada por una molécula de glucosa y una de fructosa unidas.', ja: 'スクロース（ショ糖）は一般的な食卓塩で、グルコース1分子とフルクトース1分子が結合したものである。', trivia: 'sacarosaはラテン語saccharum（砂糖）とギリシャ語の化学接尾辞-oseから成る。英語ではsucroseと言い、こちらはフランス語sucre（砂糖）に由来する別経路の語形である。同じ物質でも、スペイン語はギリシャ・ラテン語系、英語はフランス語経由と語源ルートが異なる。' },
  'sacasillas': { es: 'No seas sacasillas y deja que ellos resuelvan sus problemas sin tu intervención constante.', ja: 'お節介を焼くのはやめて、あなたの絶え間ない介入なしに彼らが自分の問題を解決できるようにしてあげなさい。', trivia: 'sacasillasはsacar（引き出す、追い出す）とsillas（椅子の複数形）の合成語で、もともと劇場の座席案内係を指したが、転じて「出しゃばり」という否定的な意味になった。英語のbusybodyは「忙しい体」というイメージで、スペイン語とは全く異なる発想から同じ概念を表す。' },
  'sacatinta': { es: 'El sacatinta que utilizaba mi abuela para corregir errores de escritura era muy eficaz, aunque ya nadie lo usa.', ja: '祖母が書き間違いを修正するために使っていたインク消しはとても効果的だったが、今ではもう誰も使わない。', trivia: 'sacatintaはsacar（取り出す・消す）とtinta（インク）の合成語で「インクを消すもの」という意味。英語ではink eraserと言い、eraserはラテン語eradere（根こそぎにする）に由来する。「消す」という概念をスペイン語は「取り出す」、英語は「根こそぎにする」という異なる比喩で表現している。' },
  'sacatintas': { es: 'En esa oficina anticuada todavía guardaban un sacatintas en el cajón, aunque nadie escribía ya con pluma.', ja: 'あの時代遅れの事務所では、誰も万年筆で書かなくなったというのに、まだ引き出しにインク消しをしまっていた。', trivia: 'sacatintasはsacar（取り出す）とtintas（インクの複数形）から成る複合名詞。英語ではink eraserまたはink removerと呼び、removerはラテン語removere（取り除く）が語源。この語は比喩的に「高利貸し」や「採血医」の意味にも転用されたが、英語には対応する多義語は存在しない。' },
  'sacatrapos': { es: 'Ese periodista es un verdadero sacatrapos: siempre consigue sonsacarle los secretos a cualquier político.', ja: 'あのジャーナリストは本物の「秘密を引き出す名人」で、どんな政治家からもいつも秘密を聞き出してしまう。', trivia: 'sacatrapossはsacar（引き出す）とtrapos（ぼろ布）の合成語で、もとは大砲の銃身からぼろ布を抜く軍事道具を指した。英語ではworm（虫、掃除棒）という意外な名称でこの道具を呼んでおり、「虫のように穿通する」というイメージが語の背景にある。' },
  'sacerdotal': { es: 'El vestido sacerdotal de ese religioso era tan elaborado que impresionó a todos los visitantes del templo.', ja: 'その聖職者の祭服はとても精巧で、神殿を訪れたすべての人を感嘆させた。', trivia: 'sacerdotalはラテン語sacerdotalis（司祭の）に由来し、sacerdos（司祭）はsacer（聖なる）とdare（与える）から成る「聖なるものを捧げる者」という意味。英語のsacerdotalも同語根の借用語であり、priestlyよりも格式ある書き言葉として用いられる。' },
  'sacerdote': { es: 'El sacerdote pronunció unas palabras de consuelo para los familiares del difunto durante la misa fúnebre.', ja: '司祭は葬儀ミサの間、故人の家族に慰めの言葉をかけた。', trivia: 'sacerdoteはラテン語sacerdos（聖なるものを捧げる者）に由来し、sacer（聖なる）とdare（与える・行う）の合成語。英語のpriestはゲルマン語源でラテン語presbyter（長老）に由来し、語源が全く異なる。ただし英語でもsacerdoteという借用語が存在し、主にカトリックや古代宗教の文脈で使われる。' },
  'sacerdotisa': { es: 'La sacerdotisa de Atenea guardaba celosamente el fuego sagrado en el templo de la acrópolis.', ja: 'アテナの女性神官はアクロポリスの神殿で神聖な火を熱心に守っていた。', trivia: 'sacerdotisaはラテン語sacerdotissa（女性司祭）に由来し、sacerdos（司祭）の女性形。英語のpriessはpriestに女性接尾辞-essを付けたもので、発想は同じだが語幹が全く異なる。現代では宗教的な文脈で特に古代多神教の女性神官を指すことが多い。' },
  'saciada': { es: 'Después de comer tanto en la fiesta, me fui a casa completamente saciada y sin ganas de cenar.', ja: 'パーティーでたくさん食べた後、完全に満腹になって夕食を食べる気なしに家に帰った。', trivia: 'saciada（満ち足りた、の女性形）は動詞saciar（満たす）の過去分詞で、ラテン語satiare（満足させる）に由来する。英語のsatiatedも同語根のラテン語借用語であり、satis（十分）という語幹はsatisfy（満足させる）やsatisfaction（満足）にも含まれる。' },
  'saciado': { es: 'El niño dejó el plato a medias porque ya se sentía saciado después del postre tan abundante.', ja: '子供はとても豊かなデザートの後でもう満腹だと感じたため、皿を半分残した。', trivia: 'saciadoはラテン語satiatus（satiate の過去分詞）に由来し、satis（十分、満足して）が語根。英語のsatisfied（満足した）もsatisを含むが、サテ（sate）もしくはsatiateの方がより直接的な語源上の兄弟語であり、語義も「食欲などを完全に満たす」という点で近い。' },
  'saciante': { es: 'El médico me recomendó comer alimentos saciantes como legumbres y cereales integrales para perder peso.', ja: '医師は体重を減らすために豆類や全粒穀物といった腹持ちの良い食べ物を食べるよう勧めてくれた。', trivia: 'sacianteはsaciar（満たす）の現在分詞形で形容詞として使われ、「満腹感を与える」という意味。英語のsatiating（食欲を満足させる）は同語根のラテン語satiareに由来し、現代の栄養学・ダイエット文脈では英西ともにこの語系統の語が多用される。' },
  'saciar': { es: 'Después de correr diez kilómetros bajo el sol, no lograba saciar mi sed por más agua que bebía.', ja: '太陽の下で10キロ走った後、どれだけ水を飲んでも喉の渇きを癒やすことができなかった。', trivia: 'saciarはラテン語satiare（十分に満たす）に由来し、satis（十分）が語根。英語のsatiate、satisfy、satedはすべてこの語根を共有する「コグネート群」であり、渇き・空腹・欲望を「満たす」という意味でスペイン語と英語は同一の概念を同一語源の語で表している。' },
  'saciedad': { es: 'Comer despacio ayuda a alcanzar la saciedad antes, lo que puede ser muy útil para controlar el peso.', ja: 'ゆっくり食べることで早めに満腹感を得やすくなり、体重管理に非常に役立つ場合がある。', trivia: 'saciedadはラテン語satietas（満足、充足感）に由来し、satis（十分）が語根。英語のsatiety（満腹感、飽和）も同語根の借用語であり、特に栄養学・心理学の文脈でよく使われる。日常英語ではfullnessの方が一般的で、satietyはやや専門的な語として位置づけられる。' },
  'saco': { es: 'El agricultor llenó varios sacos de patatas recién cosechadas para llevarlas al mercado del pueblo.', ja: '農家は村の市場に持っていくために、採れたてのジャガイモをいくつかの袋に詰めた。', trivia: 'sacoはラテン語saccus（袋）に由来し、これはギリシャ語sakkos、さらにセム語起源（ヘブライ語śaq）とされる。英語のsackも同語根で、「解雇する」という意味の英語get the sackは「袋に荷物を詰めて追い出される」というイメージに由来し、スペイン語にも類似した慣用表現が存在する。' },
  'sacra': { es: 'La música sacra de Bach todavía se interpreta en muchas catedrales europeas durante la Semana Santa.', ja: 'バッハの宗教音楽はイースター期間中、今でもヨーロッパの多くの大聖堂で演奏される。', trivia: 'sacra（神聖な、の女性形）はラテン語sacer（神聖な、禁じられた）に由来する。英語のsacred（神聖な）も同語根であり、sacrilege（冒涜）、sacrifice（犠牲）、sanctuary（聖域）なども同じ語幹sacr-を持つ。また「禁じられた」という元の意味はtabooの概念とも重なる。' },
  'sacramental': { es: 'El acto sacramental del bautismo es uno de los ritos más importantes dentro del catolicismo.', ja: '洗礼というサクラメントの行為は、カトリックの中で最も重要な儀式の一つである。', trivia: 'sacramentalはラテン語sacramentum（誓い、秘跡）に由来し、sacer（聖なる）が語根。英語のsacramental（聖礼典の）も同語根の直接借用語であり、軍事用語としてのラテン語sacramentum（兵士の忠誠の誓い）が宗教的意味に転用されたという歴史的変遷が興味深い。' },
  'sacramentalmente': { es: 'El contrato fue firmado sacramentalmente ante notario, siguiendo todos los formalismos legales requeridos.', ja: '契約は必要なすべての法的形式に従い、公証人の前で厳粛に署名された。', trivia: 'sacramentalmente（秘跡的に、儀礼に則って）はsacramental（秘跡の）に副詞語尾-menteを加えた形で、ラテン語sacramentum（誓い）が語根。英語ではsacramentally（秘跡的に）という対応語があるが、日常使用では極めてまれで、主に神学・法律文書に限られる点が両言語で共通している。' },
  'sacramentarse': { es: 'El anciano enfermo decidió sacramentarse antes de la operación para estar en paz espiritual.', ja: '病気の老人は精神的な平和を得るために、手術の前に聖礼典を受けることにした。', trivia: 'sacramentarseはsacramento（秘跡）から派生した再帰動詞で「秘跡を受ける」という意味。英語にはこれに対応する単一動詞はなく、receive the sacraments（秘跡を受ける）という句で表現する。ラテン語sacramentumはもとは軍事的な忠誠の誓いを意味し、それがキリスト教に転用された歴史がある。' },
  'sacramento': { es: 'En la tradición católica, el matrimonio es considerado un sacramento que une a dos personas ante Dios.', ja: 'カトリックの伝統では、結婚は二人を神の前で結び合わせる秘跡（サクラメント）とみなされている。', trivia: 'sacramentoはラテン語sacramentum（誓い、保証、秘跡）に由来し、sacer（聖なる）が語根。英語のsacrament（秘跡）も同語根の直接借用語。アメリカのカリフォルニア州都Sacramento（サクラメント）はこの語に由来する地名で、スペイン植民地時代に命名された。' },
  'sacratísima': { es: 'El obispo invocó el nombre de la Sacratísima Virgen al iniciar la ceremonia solemne en la catedral.', ja: '司教は大聖堂での厳粛な式典を始める際に、至聖なる聖母マリアの御名を唱えた。', trivia: 'sacratísimaはsacro/sacra（神聖な）の絶対最上級女性形で、ラテン語sacratissimus（最も神聖な）に直接対応する。英語ではmost sacredという分析的な表現を用い、合成された最上級語形はない。ラテン語からスペイン語には最上級接尾辞-ísimoが継承されたが、英語はゲルマン語的な分析的表現に移行した点が対照的である。' },
  'sacratísimo': { es: 'Este lugar es sacratísimo para los fieles de toda la región.', ja: 'この場所はその地域全体の信者にとって最も神聖な場所です。', trivia: 'ラテン語 sacer（神聖な）の最上級形 sacratissimus に由来し、英語の sacred や sacrament と同語根。英語では「most sacred」と言うが、スペイン語はラテン語直系の最上級語尾 -ísimo を保持している。' },
  'sacre': { es: 'El sacre es un ave rapaz muy valorada en la cetrería tradicional.', ja: 'サーカーハヤブサは伝統的な鷹狩りで非常に珍重された猛禽類です。', trivia: 'アラビア語 ṣaqr（鷹）に由来するとされ、中世ヨーロッパに鷹狩り文化とともに伝わった語。英語でも saker falcon と呼ばれ、同じアラビア語由来の単語が使われている。' },
  'sacrificada': { es: 'Ella llevó una vida sacrificada, dedicando cada hora a su familia.', ja: '彼女は家族のために毎時間を捧げた、自己犠牲的な人生を送りました。', trivia: 'ラテン語 sacrificium（供犠）の動詞形 sacrificare の過去分詞で、英語の sacrificial や self-sacrificing に相当。英語 sacrifice もラテン語 sacer（神聖）+ facere（行う）の合成語で、まったく同じ語根を共有する。' },
  'sacrificador': { es: 'El sacerdote actuaba como sacrificador en las ceremonias religiosas antiguas.', ja: 'その司祭は古代の宗教的儀式において生贄を捧げる者として役割を担っていました。', trivia: 'ラテン語 sacrificare（供犠を行う）＋行為者接尾辞 -dor から成り、英語では sacrificer または sacrificial priest に相当する。英語に直接対応する1語はなく、スペイン語の語形成の豊かさが際立つ例である。' },
  'sacrificadora': { es: 'La sacerdotisa sacrificadora presidía los ritos en el templo de la diosa.', ja: '女性の生贄執行者である女司祭は、女神の神殿での儀式を主宰していました。', trivia: 'sacrificador の女性形で、ラテン語の行為者接尾辞 -tor/-trix の性別対応をスペイン語が -dor/-dora として継承した例。英語では性別中立的な sacrificer が一般的で、スペイン語のように文法的性別が形に表れない。' },
  'sacrificar': { es: 'Los jugadores tuvieron que sacrificar su tiempo libre para ganar el campeonato.', ja: '選手たちは選手権を勝ち取るために自由な時間を犠牲にしなければなりませんでした。', trivia: 'ラテン語 sacrificare（sacer「神聖」＋ facere「する」）に直接由来し、英語の to sacrifice とほぼ同一の語源・意味を持つ。宗教的な「生贄を捧げる」から「何かを諦める」という抽象的意味への拡張も英語とスペイン語で平行している。' },
  'sacrificio': { es: 'Criar a tres hijos sola requirió muchos sacrificios de su parte.', ja: '3人の子どもを一人で育てることは、彼女の側で多くの犠牲を必要としました。', trivia: 'ラテン語 sacrificium（sacer「神聖」＋ facere「する」）の直系継承語で、英語の sacrifice も同じ語源。英語では動詞・名詞ともに sacrifice 1語で済むが、スペイン語は動詞 sacrificar と名詞 sacrificio を明確に使い分ける。' },
  'sacrilegio': { es: 'Para los amantes del arte, destruir ese cuadro sería un sacrilegio imperdonable.', ja: '芸術愛好家にとって、あの絵を破壊することは許しがたい冒涜でしょう。', trivia: 'ラテン語 sacrilegium（sacer「神聖」＋ legere「拾う・盗む」）に由来し、本来は「神聖なものを盗む行為」を意味した。英語の sacrilege も同語根で、フランス語経由で中世英語に入った。比喩的に「とんでもない行為」を指す用法は英語でも同様。' },
  'sacrílega': { es: 'La actitud sacrílega del visitante escandalizó a todos los presentes en la catedral.', ja: 'そのカテドラルで居合わせた全員が、訪問者の冒涜的な態度に衝撃を受けました。', trivia: 'ラテン語 sacrilegus（神聖なものを盗む者）の形容詞形で、英語の sacrilegious と同語根。英語 sacrilegious の発音は -reli- の部分が「レリ」となりアクセントも異なるが、スペイン語 sacrílego はラテン語の強勢位置をそのまま保つ点が特徴的。' },
  'sacrílego': { es: 'Pintarrajear ese monumento histórico es un acto sacrílego e inaceptable.', ja: 'その歴史的記念碑に落書きをすることは冒涜的で受け入れがたい行為です。', trivia: 'sacrílega の男性形で、ラテン語 sacrilegus から直接継承された語。英語では sacrilegious（形容詞）/ sacrilege（名詞）と区別されるが、スペイン語の sacrílego は形容詞としても名詞（冒涜者）としても使える点で英語より多機能である。' },
  'sacristán': { es: 'El sacristán preparó el altar antes de que llegara el párroco.', ja: '堂守は主任司祭が到着する前に祭壇を準備しました。', trivia: '中世ラテン語 sacristanus（聖具を管理する者）に由来し、英語の sacristan と完全に同語根。英語では sexton（セクストン）という別の語も使われるが、こちらはラテン語 sacristanus が縮約された形でやはり同じ語根を持つ。' },
  'sacristana': { es: 'La sacristana se encargaba de lavar y guardar los ornamentos sagrados.', ja: '女性堂守は聖なる祭服を洗って保管する役割を担っていました。', trivia: 'sacristán の女性形で、中世ラテン語 sacristanus に -a 語尾をつけたスペイン語形。英語では sacristan が性別中立的に使われるため、女性専用形が存在しないのと対照的。スペイン語の職名は文法的性別で男女を区別する伝統が根強い。' },
  'sacristía': { es: 'El cura guardaba los cálices y las vestiduras en la sacristía.', ja: '司祭は聖杯と祭服を聖具室に保管していました。', trivia: '中世ラテン語 sacristia（聖具を保管する場所）に由来し、英語の sacristy と同語根。英語では -y 語尾の sacristy だが、スペイン語は -ía のアクセント付き語尾を持ち、ラテン語の構造をより忠実に保持している。' },
  'sacro': { es: 'El monte sacro era considerado intocable por las comunidades indígenas.', ja: 'その聖なる山は先住民コミュニティによって不可侵のものとみなされていました。', trivia: 'ラテン語 sacer（神聖な）から直接来ており、英語の sacred、sacrament、sacrifice などすべてこの語根を共有する。また解剖学用語として「仙骨」を意味する sacro（英 sacrum）も同じ語で、古代ローマで仙骨を神聖な骨とみなしたことに由来する。' },
  'sacrosanta': { es: 'Para él, la privacidad familiar es una cuestión sacrosanta que nadie debe violar.', ja: '彼にとって、家族のプライバシーは誰も侵してはならない絶対不可侵のことです。', trivia: 'ラテン語 sacrosanctus（sacer「神聖」＋ sanctus「清められた」）に由来し、英語の sacrosanct と完全に同語根。英語の sacrosanct は現在では比喩的に「絶対に変えてはならない」という意味で政治・議論の文脈でよく使われるが、スペイン語でも同じ比喩的拡張が見られる。' },
  'sacrosanto': { es: 'Los derechos fundamentales son sacrosantos y no pueden ser vulnerados por ningún gobierno.', ja: '基本的権利は絶対不可侵であり、いかなる政府によっても侵害されることはできません。', trivia: 'sacrosanta の男性形で、ラテン語 sacrosanctus の直系継承語。英語の sacrosanct はこのスペイン語形（男性形）とほぼ同一の形を保っており、英語とスペイン語でまれに見る見た目のそっくりな借用語の一例である。' },
  'sacudida': { es: 'Una fuerte sacudida sísmica despertó a todos los habitantes de la ciudad a medianoche.', ja: '強い地震の揺れが真夜中に市内の住民全員を起こしました。', trivia: '動詞 sacudir（揺さぶる）の過去分詞が名詞化したもので、sacudir 自体の語源はラテン語 succutere（sub「下から」＋ quatere「振る」）に由来する。英語の concussion（脳震盪）や percussion（打楽器・打撃）も同じ -cutere/-quatere 語根を持つ親戚語である。' },
  'sacudidamente': { es: 'El tren avanzaba sacudidamente por las vías deterioradas del viejo ramal.', ja: '列車は古い支線の傷んだ線路の上を激しく揺れながら進んでいました。', trivia: 'sacudida（揺れ）に副詞語尾 -mente を付けた形で、ラテン語 succutere 由来。英語に対応する1語の副詞は存在せず「joltingly」や「with violent shaking」と言い換えるしかなく、スペイン語の -mente 副詞形成の柔軟性が際立つ例。' },
  'sacudidor': { es: 'Mi abuela usaba un sacudidor de plumas para limpiar los muebles cada semana.', ja: '祖母は毎週羽のはたきを使って家具を掃除していました。', trivia: 'sacudir（揺さぶる・はたく）＋行為者・道具接尾辞 -dor から成り、ラテン語 succutere に由来する。英語ではほこり払いの道具を duster や feather duster と呼び、「shaker」とは言わない点がスペイン語と異なる。' },
  'sacudidora': { es: 'La empresa fabricaba una sacudidora industrial para limpiar alfombras grandes.', ja: 'その会社は大型カーペットを掃除するための工業用揺さぶり機を製造していました。', trivia: 'sacudidor の女性形・女性名詞形で、機械や装置を指す場合にも使われる。英語では shaker（シェーカー）が類似概念を指すが、産業用の「揺さぶり清掃機」には対応する一般的な英単語がなく、文脈に応じて描写的に説明することが多い。' },
  'sacudidura': { es: 'Con una sacudidura enérgica del mantel, los restos de comida cayeron al suelo.', ja: 'テーブルクロスを力強くはたくと、食べ残しが床に落ちました。', trivia: 'sacudir に名詞化接尾辞 -dura を付けた語で、行為の結果や行為そのものを指す。英語では shaking や dusting に相当するが、-dura 接尾辞はラテン語 -tura（行為・結果を示す）に由来し、英語の -ture（例：gesture、texture）と同語根である。' },
  'sacudimiento': { es: 'El sacudimiento provocado por la explosión se sintió a varios kilómetros de distancia.', ja: '爆発によって引き起こされた揺れは数キロ先まで感じられました。', trivia: 'sacudir＋名詞化接尾辞 -miento から成り、sacudida や sacudidura とほぼ同義だが、より精神的・比喩的な「衝撃」を指すことが多い。英語の -ment（movement、shakeup）もラテン語 -mentum に由来し、スペイン語 -miento と共通の語根を持つ。' },
  'sacudir': { es: 'Sacude bien la botella antes de abrir el jugo para mezclar el contenido.', ja: 'ジュースの中身を混ぜるために、開ける前によく瓶を振ってください。', trivia: 'ラテン語 succutere（sub「下から」＋ quatere「打つ・振る」）に由来し、英語の shake に意味的に相当する。shake 自体はゲルマン語起源で語源は異なるが、英語の concussion（脳震盪）や percussion はラテン語の -cutere 語根を共有する親戚語である。' },
  'sádica': { es: 'La directora tenía una actitud sádica, disfrutando del sufrimiento ajeno.', ja: 'その女性監督はサディスティックな態度を持ち、他人の苦しみを楽しんでいました。', trivia: '18世紀フランスの作家マルキ・ド・サド（Marquis de Sade）の名前に由来する固有名詞からの派生語で、英語の sadistic も全く同じ語源。フランス語経由でヨーロッパ各言語に広まり、人名から一般形容詞になった「エポニム」の典型例である。' },
  'sádico': { es: 'El personaje sádico de la novela disfrutaba provocando dolor en los demás.', ja: 'その小説のサディスティックな登場人物は他人に苦痛を与えることを楽しんでいました。', trivia: 'sádica の男性形で、マルキ・ド・サドの名前（Sade）に由来する国際的エポニム。英語の sadist・sadistic・sadism もすべて同じ語源で、フランス語を経由してヨーロッパ言語全体に広まった。心理学用語 sadomasochism（S&M）はサドとマゾッホ（Sacher-Masoch）の両人名の合成語。' },
  'sadismo': { es: 'El sadismo no es solo un concepto psicológico, sino también un tema recurrente en la literatura del siglo XIX.', ja: 'サディズムは単なる心理学的概念ではなく、19世紀文学において繰り返し登場するテーマでもある。', trivia: 'フランスの貴族作家マルキ・ド・サド（Marquis de Sade、1740〜1814）の名前に由来し、19世紀末にドイツの精神科医クラフト＝エービングが術語として確立した。英語・スペイン語ともに sadism / sadismo と同形で、語源・形態ともに完全に一致する国際語である。' },
  'saeta': { es: 'En Semana Santa, los cantaores lanzan saetas desde los balcones mientras pasan las procesiones por las calles de Sevilla.', ja: '聖週間には、歌い手たちがセビリャの街を行列が通る間、バルコニーからサエタを歌い上げる。', trivia: 'ラテン語 sagitta（矢）に由来し、英語の arrow とは語源が異なる（arrow は古英語 arwe から）。ただし英語の Sagittarius（射手座）は同じラテン語 sagitta と同語根であり、スペイン語の sagitario と対応する。' },
  'saetada': { es: 'El héroe cayó de rodillas tras recibir una saetada en el hombro durante la batalla.', ja: '英雄は戦いの最中、肩に矢傷を受けて膝をついた。', trivia: 'saeta（矢）＋ -ada（動作・結果を示す接尾辞）から成る派生語。英語では arrow wound と説明的に表現するしかなく、一語に対応する語彙が存在しない。ラテン語 sagitta が祖語である点は saeta と同じ。' },
  'saetía': { es: 'Las saetías mediterráneas eran embarcaciones ligeras y rápidas que los corsarios usaban para sorprender a sus enemigos.', ja: '地中海のサエティアは、海賊が敵を奇襲するために使った軽快で素早い船だった。', trivia: '中世ラテン語または古カタルーニャ語経由で、やはり sagitta（矢）に由来するとされる。矢のように速く走る船というイメージからの命名。英語には直接対応する単語がなく、xebec や felucca などの別の地中海船を指す借用語で代替される。' },
  'saetilla': { es: 'La saetilla del reloj de la iglesia marcaba lentamente los minutos mientras esperaba su llegada.', ja: '教会の時計の小針が、彼女の到着を待つ間ゆっくりと分を刻んでいた。', trivia: 'saeta の指小辞形（-illa）で「小さな矢」の意。時計の針を矢にたとえた命名で、英語では hand（時計の針）と呼ぶのとは発想が対照的。英語の hand は「手」からの比喩であり、スペイン語の矢の比喩との文化的差異が興味深い。' },
  'saetín': { es: 'El agua caía con fuerza por el saetín del molino, haciendo girar la rueda sin cesar.', ja: '水は水車の導水路を勢いよく流れ落ち、車輪を絶えず回し続けた。', trivia: '語源については二説あり、①矢（saeta）のように水が勢いよく流れることから、②アラビア語またはペルシャ語起源の「サテン」を意味する語が転用されたとも言われる。英語の satin（サテン）はアラビア語 zaytūnī（中国の港町泉州の意）に由来するとされ、スペイン語の satén と同語源。' },
  'safena': { es: 'El cirujano extirpó la vena safena de la pierna del paciente para utilizarla como injerto coronario.', ja: '外科医は冠動脈バイパス術に使うため、患者の脚から大伏在静脈を摘出した。', trivia: 'アラビア語 sāfin（「隠れた」「明白な」の両義を持つ）に由来するとされる。英語の saphenous vein と同語源で、医学用語としてラテン語 vena saphena を経由して欧州各語に伝わった国際的な術語。' },
  'sáfico': { es: 'El metro sáfico, con su ritmo característico de once sílabas, fue adoptado por poetas latinos como Horacio.', ja: '11音節の独特なリズムを持つサッフォー詩体は、ホラティウスなどローマの詩人たちに採り入れられた。', trivia: '古代ギリシャの女性詩人サッフォー（Sappho、紀元前7〜6世紀頃、レスボス島出身）の名に由来。英語の Sapphic と完全に対応する。「レスビアン（lesbian）」という語も彼女の出身地レスボス島（Lesbos）に由来しており、sáfico の古い意味と連動している。' },
  'sáfica': { es: 'La estrofa sáfica consta de tres endecasílabos y un adónico final, siguiendo el modelo de Safo de Lesbos.', ja: 'サッフォー詩体の連節は、レスボスのサッフォーの様式に従い、三行の11音節詩と最後のアドーニス行から成る。', trivia: 'sáfico の女性形。詩律用語として estrofa sáfica（サッフォー詩体の詩節）という形で使われる。英語では Sapphic stanza と呼び、古代ギリシャ・ラテン文学の韻律論において重要な概念である。' },
  'safira': { es: 'Encontraron una safira de gran tamaño entre las joyas del antiguo tesoro real.', ja: '古い王家の宝物の中から、大きなサファイアが見つかった。', trivia: 'zafiro の異形で、ヘブライ語 sappir またはギリシャ語 sappheiros に由来し、アラビア語 safīr を経由してスペイン語に入ったとされる。英語の sapphire と同語源で、ラテン語 sapphirus を通じて欧州各語に広まった。現代スペイン語では zafiro が標準形。' },
  'safor': { es: 'La comarca del Safor, situada en la provincia de Valencia, es conocida por sus naranjos y su costa mediterránea.', ja: 'バレンシア県に位置するサフォル郡は、オレンジ畑と地中海沿岸で知られている。', trivia: 'バレンシア語・カタルーニャ語の地名で、語源はアラビア語に遡るとも言われるが詳細は諸説ある。英語との直接の関係はないが、地中海を挟んで文化的・歴史的にアラブ世界と深くつながったバレンシア地方の地名の典型例。' },
  'safra': { es: 'Durante la safra, miles de trabajadores llegan a los cañaverales para participar en la cosecha de caña de azúcar.', ja: 'サトウキビの収穫期には、何千人もの労働者がサトウキビ畑に収穫のためにやって来る。', trivia: 'zafra の異形で、アラビア語 safra\'（黄色、または収穫）に由来するとされる。ブラジルやキューバなどスペイン語・ポルトガル語圏の中南米で広く使われる農業用語。英語には直接対応する単語がなく、sugar cane harvest season と説明的に訳す。' },
  'saga': { es: 'La saga de Star Wars ha fascinado a generaciones de espectadores desde su estreno en 1977.', ja: 'スター・ウォーズのサーガは、1977年の公開以来、何世代もの観客を魅了してきた。', trivia: '古ノルド語 saga（「語られた物語」を意味する動詞 segja の派生語）に由来し、英語の say や see とも遠い語根上のつながりがあるとされる。英語の saga と完全に同形・同義で、映画・文学の「シリーズ大作」の意味は20世紀以降の意味拡張。' },
  'sagacidad': { es: 'La sagacidad del detective le permitió resolver el caso en cuestión de horas, cuando todos los demás habían fracasado.', ja: '探偵の鋭い洞察力のおかげで、他の者が全員失敗した中、数時間で事件を解決することができた。', trivia: 'ラテン語 sagacitas（鋭さ、鋭敏さ）から来ており、動詞 sagire（鋭く感じ取る）が語根。英語の sagacity と同語源で形も意味もほぼ同じ。また sage（賢者）とも同じ語根から来ており、「嗅ぎ分ける」能力が原義とされる。' },
  'sagaz': { es: 'Era una mujer sagaz que sabía leer entre líneas y anticipar las intenciones de sus adversarios.', ja: '彼女は行間を読み、敵の意図を先読みすることのできる、鋭い洞察力を持つ女性だった。', trivia: 'ラテン語 sagax（鋭い、特に嗅覚・直感が鋭い）に由来し、英語の sagacious と同語源。英語の sage（賢者、またはセージというハーブ）とも語根が共通するとされ、「賢く感じ取る」という原義が底流にある。' },
  'sagazmente': { es: 'El negociador actuó sagazmente al escuchar más de lo que hablaba, obteniendo así información valiosa.', ja: '交渉担当者は話すよりも聞くことに徹するという機転を利かせた行動をとり、その結果貴重な情報を得た。', trivia: 'sagaz の副詞形（-mente）。英語の shrewdly または sagaciously に対応する。英語の shrewdly はもともとシュリュー（トガリネズミ）の「噛む・鋭い」意から来ており、発想は異なるが意味の収束が面白い。' },
  'sagita': { es: 'En geometría, la sagita es la distancia entre el punto medio de un arco y el punto medio de su cuerda.', ja: '幾何学において、サジタとは弧の中点とその弦の中点との間の距離である。', trivia: 'ラテン語 sagitta（矢）から直接来ており、弧から弦への垂線が矢のように見えることからこの名がついた。英語の mathematical term sagitta と同じ語で、天文学では Sagitta（や座）という星座名にもなっている。英語の arrow とは語源が異なる。' },
  'sagital': { es: 'El médico le mostró al paciente un corte sagital del cerebro en la resonancia magnética para explicarle el diagnóstico.', ja: '医師は診断を説明するため、MRI画像で脳の矢状断面を患者に示した。', trivia: 'ラテン語 sagitta（矢）＋ -alis（形容詞語尾）から成り、頭蓋骨の矢状縫合（sutura sagitalis）が矢のように前後に走ることから名付けられた。英語の sagittal と完全に同語源・同形で、医学・解剖学の国際共通術語として広く使われている。' },
  'sagitalmente': { es: 'El cerebro fue cortado sagitalmente para observar las estructuras internas con mayor detalle.', ja: '内部構造をより詳細に観察するため、脳は矢状面に沿って切断された。', trivia: 'sagital の副詞形（-mente）。英語では sagittally に対応するが、この副詞形は英語でもスペイン語でも医学文献以外ではほとんど使われない専門語。語根のラテン語 sagitta（矢）はサジタリウス（射手座）とも同じ語源。' },
  'sagitario': { es: 'Mi mejor amiga es sagitario y siempre dice que su signo explica su espíritu aventurero e independiente.', ja: '親友は射手座で、自分の星座がその冒険的で自立した精神を説明していると常々言っている。', trivia: 'ラテン語 sagittarius（弓兵、弓を射る者）から来ており、sagitta（矢）が語根。英語の Sagittarius と完全に同語源・ほぼ同形。英語の archer（弓兵）とは語源が異なり、archer は古フランス語 archier から来ている。' },
  'sagrada': { es: 'Para muchas culturas indígenas, la tierra es sagrada y debe ser protegida de la explotación industrial.', ja: '多くの先住民文化にとって、大地は神聖なものであり、産業による搾取から守られなければならない。', trivia: 'ラテン語 sacratus（sacro の過去分詞、「聖別された」の意）に由来し、英語の sacred と同語源。英語の sacrifice（犠牲）、sacrament（秘跡）、sanctuary（聖域）なども同じ語根 sacer（神聖な）を共有しており、宗教語彙の豊かな一族を形成している。' },
  'sagrado': { es: 'El respeto a la familia es considerado sagrado en muchas culturas mediterráneas, algo que va más allá de las costumbres.', ja: '家族への敬意は多くの地中海文化において神聖なものと見なされており、単なる習慣を超えた何かである。', trivia: 'sagrada の男性形。ラテン語 sacratus に由来し、英語の sacred と同語源。英語の sacred は形容詞のみだが、スペイン語の sagrado は名詞としても使われ「聖域・避難所」を意味する点が異なる。中世には教会が犯罪者の避難所（sagrado）として機能した。' },
  'sagradamente': { es: 'Prometió sagradamente que nunca revelaría el secreto que le habían confiado sus amigos.', ja: '友人たちから打ち明けられた秘密を決して明かさないと、彼は固く誓った。', trivia: 'sagrado の副詞形（-mente）。英語では sacredly または religiously に対応するが、「厳格に・欠かさず」という比喩的な強調の意味で使われることが多い。英語の religiously も「信心深く」の他に「きっちりと」の比喩的意味を持ち、意味の発展が並行している。' },
  'sagrario': { es: 'El sacerdote depositó la custodia con cuidado en el sagrario después de la celebración de la misa.', ja: '司祭はミサの式典の後、聖体顕示台を丁寧に聖体庵に安置した。', trivia: 'ラテン語 sacrarium（聖なる場所、神殿の内庭）に由来し、sacer（神聖な）が語根。英語の tabernacle（タバナクル）とは語源が異なるが、指示対象は同じカトリックの聖体を収める箱。英語では sanctuary とも訳されるが、sacrarium という英語の専門語も存在する。' },
  'sagú': { es: 'El sagú es un ingrediente esencial en muchos postres asiáticos y se obtiene del interior del tronco de ciertas palmeras.', ja: 'サゴは多くのアジアのデザートに欠かせない食材で、特定のヤシの幹の内部から採取される。', trivia: 'マレー語 sagu に由来し、ポルトガル語を経由してスペイン語・英語に入った。英語の sago と完全に同語源・ほぼ同形で、両語ともマレー語からの借用語である。東南アジア原産の食材らしく、マレー語・インドネシア語系の語彙が欧州語に入った典型例。' },
  'sahína': { es: 'En algunas regiones de España, la sahína se cultivaba junto al mijo para alimentar al ganado.', ja: 'スペインの一部の地域では、モロコシは家畜の飼料として粟と一緒に栽培されていた。', trivia: 'zahína（サイナ）の異形で、アラビア語 al-dhurra（ソルガム）に由来するとされる。英語の sorghum はラテン語 Syricum（シリアの）を経由しており、スペイン語形とは語源ルートが異なる。' },
  'sahumada': { es: 'La carne sahumada con hierbas aromáticas tenía un sabor incomparable en aquella región andina.', ja: 'ハーブの香煙で燻されたその肉は、アンデスのその地域では比類ない味わいだった。', trivia: '動詞 sahumar（香煙で燻す）の過去分詞から派生した形容詞・名詞で、ラテン語 sub-（下に）＋ fumare（煙る）の合成が語源。英語の perfume も同じく per-（通して）＋ fumare に由来し、煙の概念を共有する。' },
  'sahumado': { es: 'El ambiente del templo estaba sahumado con incienso de cedro desde horas antes de la ceremonia.', ja: '神殿の空気は、式典の数時間前からヒスイ柏の乳香香煙で燻されていた。', trivia: 'sahumar の過去分詞男性形で、sahumada と対をなす。ラテン語 sub-fumare に由来し、英語の smoked（煙製の）に意味的には近いが、スペイン語では特にお香・宗教的薫香のニュアンスを帯びることが多い。' },
  'sahumador': { es: 'El sacerdote balanceaba el sahumador de plata mientras entonaba las oraciones rituales.', ja: '司祭は儀礼の祈りを唱えながら、銀製の香炉を揺り動かしていた。', trivia: 'sahumar（香煙で燻す）＋ 道具を示す接尾辞 -dor から成る。英語の censer（香炉）はラテン語 incendere（燃やす）に由来しており、スペイン語の incensario と同じ語根だが、sahumador は動作の主体（燻す器具）として独立した語形成をとっている。' },
  'sahumadura': { es: 'La sahumadura de la habitación con romero y lavanda era una costumbre para ahuyentar los malos espíritus.', ja: 'ローズマリーとラベンダーで部屋を香煙で清めることは、悪霊を払う風習だった。', trivia: 'sahumar に動作の結果・過程を示す接尾辞 -dura を加えた名詞で、sahumerio・sahumo とほぼ同義。英語では fumigation（くん蒸）や incensing に相当するが、宗教的・民俗的な浄化の意味合いが強い点でニュアンスが異なる。' },
  'sahumar': { es: 'Antes de comenzar la ceremonia, sahuman el espacio con copal para purificarlo.', ja: '式典を始める前に、場を清めるためにコパル樹脂の香煙でその空間を燻す。', trivia: 'ラテン語 sub-（下に・緩やかに）＋ fumare（煙を出す）に由来し、スペイン語独自の語形 sahumar に変化した。英語の fume、perfume と同語根であり、中世ヨーロッパでは医療・宗教両方の場で煙による治療や浄化が行われていた背景がある。' },
  'sahumerio': { es: 'El sahumerio de palo santo llena el ambiente de un aroma cálido y espiritual.', ja: 'パロサントのお香は、暖かく霊的な香りで空間を満たす。', trivia: 'sahumar から派生した名詞で、接尾辞 -erio は動作・場所・結果を表すラテン語的な形。英語の incense はラテン語 incendere（火をつける）に由来し、語根が異なるが指示対象は重なる。現代中南米では copal や palo santo を用いる sahumerio が先住民の儀礼と結びついて広く行われている。' },
  'sahumo': { es: 'El curandero usó el sahumo de hierbas medicinales para aliviar los males del enfermo.', ja: '呪術師は病人の苦しみを和らげるために薬草のお香による燻しを用いた。', trivia: 'sahumerio の短縮形・通俗形で、同様にラテン語 sub-fumare に由来する。英語では fumigation または smoke treatment に相当し、現代医学の fumigation（害虫駆除のくん蒸）と語義が部分的に重なるが、スペイン語の sahumo は民間医療・儀礼的文脈で使われることが多い。' },
  'saín': { es: 'El saín de cerdo se usaba antiguamente para impermeabilizar las botas de cuero.', ja: '豚の脂身は、かつて革靴を防水するために使われていた。', trivia: '語源は諸説あるが、ラテン語 sagina（肥育、脂肪）に由来する可能性が高い。英語の lard（ラード）はフランス語を経由したラテン語 lardum に由来し、saín とは語根が異なる別系統の語。中世スペインでは saín は照明用油や皮革手入れにも使われた実用的な語だった。' },
  'sainete': { es: 'El sainete del Siglo de Oro español retrataba la vida cotidiana del pueblo con humor y picardía.', ja: 'スペイン黄金世紀のサイネーテは、ユーモアと機知で民衆の日常生活を描いていた。', trivia: 'saín（脂身・旨み）から派生した語で、もとは「美味なソース・風味」を意味し、転じて「味のある短い演し物」を指すようになった。英語には直接の対応語はなく、one-act farce や comic interlude と説明される。ラモン・デ・ラ・クルスが18世紀に大成した典型的なスペイン民衆演劇のジャンルである。' },
  'sainetista': { es: 'Ramón de la Cruz fue el sainetista más prolífico del siglo XVIII español.', ja: 'ラモン・デ・ラ・クルスは18世紀スペインで最も多作なサイネーテ劇作家だった。', trivia: 'sainete に人を示す接尾辞 -ista を加えた語。英語では farceur や comic playwright などと訳されるが、sainetista はスペイン・中南米の特定演劇ジャンルの書き手という文化的固有性が強く、英語に一語対応の訳語が存在しない。' },
  'saja': { es: 'El médico hizo una saja superficial para drenar el absceso sin anestesia general.', ja: '医師は全身麻酔なしに膿瘍を排出するため、浅い切開を行った。', trivia: '動詞 sajar（切開する）の名詞形で、ラテン語 sagitta（矢）または古代ギリシャ語 sazein（切る）との関連が指摘されるが語源は確定していない。英語の scarification（乱切）はギリシャ語 skariphasthai に由来し、意味的には近いが語根は異なる。' },
  'sajadura': { es: 'La sajadura practicada en la planta del pie permitió extraer la astilla profunda.', ja: '足の裏に行われた切開で、深く刺さった棘を取り出すことができた。', trivia: 'sajar に結果・動作を示す接尾辞 -dura を加えた名詞で、saja とほぼ同義。英語の lancet（メス・ランセット）はラテン語 lancea（槍）に由来し、切開の「道具」を指す語として sajadura（切開の行為・結果）とは品詞的位置づけが異なる。' },
  'sajar': { es: 'El cirujano sajó la herida infectada con cuidado para evitar dañar los tejidos sanos.', ja: '外科医は健康な組織を傷つけないよう、注意深く感染した傷を切開した。', trivia: '語源は諸説あるが、古フランス語 sachier や後期ラテン語形との関連が示唆されている。英語の lance（切開する）はラテン語 lancea（槍）に由来し意味的に近く、scarify（乱切する）はギリシャ語系と語根が異なる。外科的切開の技術は古代ローマの軍医に遡ることができる。' },
  'sajón': { es: 'El influjo sajón en el inglés moderno es evidente en el vocabulario cotidiano más básico.', ja: '現代英語におけるサクソン語の影響は、最も基本的な日常語彙に明らかに見られる。', trivia: 'ラテン語 Saxo（サクソン人）に由来し、ゲルマン民族の部族名が語源。英語の Saxon と同語根の明確な借用語であり、Anglo-Saxon（アングロサクソン）という複合語も両言語で共有されている。スペイン語では anglosajón という形も広く使われ、英語圏文化全体を指す場合がある。' },
  'sajona': { es: 'La cultura sajona dejó una huella profunda en las tradiciones jurídicas de los países angloparlantes.', ja: 'サクソン文化は、英語圏の法律的な伝統に深い痕跡を残した。', trivia: 'sajón の女性形で、ラテン語 Saxo に由来する同じ語根を持つ。英語の Saxon は性別を形態で区別しないが、スペイン語は -o/-a で男女を区別する。歴史的にはサクソン人はエルベ川下流域に起源を持ち、イングランド征服を通じて英語の文法骨格を形成した。' },
  'sala': { es: 'La sala de espera del hospital estaba llena de pacientes nerviosos aguardando su turno.', ja: '病院の待合室は、順番を待つ不安そうな患者で溢れかえっていた。', trivia: 'ゲルマン語（フランク語）の sala（広間・ホール）に由来し、古フランス語を経てスペイン語に入った。英語の hall、saloon も同じゲルマン語根を共有し、saloon はスペイン語 salón（大広間）とも同語根。現代スペイン語では多義語として「リビング・法廷・映画館・病室」など幅広い文脈で使われる。' },
  'salacidad': { es: 'La obra fue censurada por su salacidad y sus referencias explícitas a temas prohibidos.', ja: 'その作品は好色さと禁じられたテーマへの露骨な言及を理由に検閲された。', trivia: 'ラテン語 salax（好色な）に由来し、さらに語根は salire（跳ぶ・交尾する）に遡る。英語の salacious（わいせつな）と salacity は全く同じラテン語語根を持つ直接の同語根語（コグネート）であり、意味・形ともに酷似している。' },
  'salada': { es: 'La sopa estaba tan salada que nadie pudo terminarla.', ja: 'そのスープはあまりにも塩辛くて、誰も飲み干すことができなかった。', trivia: 'sal（塩）に形容詞接尾辞 -ado/-ada を加えた語で、ラテン語 sal（塩）が語源。英語の salty、salted と同語根であり、sauce（ソース）、salad（サラダ）、salary（給与）もすべてラテン語 sal に由来する大家族。古代ローマでは兵士への給与が塩で支払われたことが salary の語源として有名。' },
  'salado': { es: 'Este chico es muy salado; siempre sabe cómo animar la reunión con sus comentarios graciosos.', ja: 'この子はとてもチャーミングで、いつも冗談で場を和ませることができる。', trivia: 'salada の男性形で、ラテン語 sal（塩）が語源。スペイン語では「塩辛い」という文字通りの意味から「高い（値段）」「お茶目・魅力的」という比喩的な意味に広がった。英語の salty は近年スラングで「腹立たしい・皮肉な」という意味を持ち、スペイン語の salado とは比喩的拡張の方向が逆向きで興味深い。' },
  'saladero': { es: 'En el siglo XIX, los saladeros del Río de la Plata exportaban carne salada a Europa y Cuba.', ja: '19世紀、ラプラタ川流域のサラデロはヨーロッパとキューバに塩漬け牛肉を輸出していた。', trivia: 'sal（塩）＋ -adero（場所・施設を示す接尾辞）から成る語で、ラテン語 sal が語源。英語には直接対応する一語がなく、salting house や meat-salting plant と説明される。アルゼンチンの歴史ではサラデロは19世紀の主要輸出産業を支えた施設として経済史上重要な位置を占めている。' },
  'saladura': { es: 'La saladura del bacalao permite conservarlo durante meses sin necesidad de refrigeración.', ja: 'タラの塩蔵は、冷蔵なしに何ヶ月も保存を可能にする。', trivia: 'salar（塩漬けにする）に動作の結果・過程を示す接尾辞 -dura を加えた語で、ラテン語 sal（塩）が語源。英語の salting（塩漬け）と同語根。中南米（特にチリ）では「不運・縁起の悪さ」という意味でも使われ、「塩を撒く（≒不運を招く）」という民俗的な概念と結びついている点が興味深い。' },
  'salamandra': { es: 'La salamandra común puede regenerar sus extremidades perdidas, lo que la convierte en objeto de estudio científico.', ja: 'イモリは失った手足を再生できるため、科学研究の対象となっている。', trivia: 'ギリシャ語 salamandra に由来し、ラテン語を経てスペイン語・英語に入った。英語の salamander と全く同形の借用語（コグネート）。中世の伝説では火の中でも生き続ける生き物とされ、錬金術の象徴でもあった。現在の salamander は英語料理用語で「上火強火焼き器」としても使われ、スペイン語も同様の用法がある。' },
  'salame': { es: 'En la pizzería pedimos una pizza de salame con aceitunas negras y mozzarella.', ja: 'ピッツェリアで、ブラックオリーブとモッツァレラ入りのサラミピザを注文した。', trivia: 'イタリア語 salame（複数: salami）に由来し、さらにラテン語 sal（塩）が語源で「塩漬けにしたもの」を意味する。英語でも salami としてイタリア語から直接借用されており、スペイン語も同形で使われる。アルゼンチン口語で「バカ・まぬけ」を意味する点は、イタリア系移民が多い文化的背景を反映している。' },
  'salamis': { es: 'En la charcutería había una gran variedad de salamis artesanales de diferentes regiones.', ja: 'デリカテッセンには、さまざまな地域の手作りサラミが豊富に揃っていた。', trivia: 'salami（またはスペイン語では salame）の複数形で、イタリア語起源・ラテン語 sal（塩）に遡る。英語でも salami の複数形は salami または salamis と表記され、スペイン語と同形。古代フェニキアの都市サラミス（キプロス島）とは語源的に無関係だが、同音異義として知られる。' },
  'salami': { es: 'Me gusta preparar una tabla de embutidos con salami, queso manchego y aceitunas.', ja: 'サラミとマンチェゴチーズ、オリーブを使って盛り合わせプレートを作るのが好きだ。', trivia: 'イタリア語 salame（塩漬け肉）の複数形 salami が英語・スペイン語に入った語で、ラテン語 sal（塩）に由来する。英語でも salami とそのままの形で使われ、同語根の英単語 salt や salary と親戚関係にある。' },
  'salar': { es: 'Hay que salar la carne antes de asarla para que quede más jugosa.', ja: '肉を焼く前に塩をふると、よりジューシーに仕上がる。', trivia: 'ラテン語 salare（塩をふる）に由来し、英語の salt と同語根。スペイン語では動詞としての「塩をふる」のほか、名詞として「塩湖・塩原」（ボリビアのウユニ塩湖 Salar de Uyuni が有名）の意味も持つ。' },
  'salariada': { es: 'Como trabajadora salariada, tiene derecho a vacaciones pagadas y seguro médico.', ja: '給与雇用者として、彼女は有給休暇と医療保険を受ける権利がある。', trivia: 'スペイン語 salario（給与）から派生した形容詞・名詞で、ラテン語 salarium に遡る。英語の salaried（給与制の）と同語根で、英語 salary もこの系譜に属する。古代ローマで兵士に塩（sal）が報酬として支給されたという説があるが、これには異論もある。' },
  'salariado': { es: 'El número de trabajadores salariados ha aumentado en el sector tecnológico durante los últimos años.', ja: 'ここ数年でテクノロジー分野の給与雇用者の数が増加している。', trivia: 'ラテン語 salarium を語源とする salario の派生語。英語の salaried employee と同じ概念を表し、salary・salaried と共通の語根を持つ。中世では「salt money（塩代）」が賃金の一形態だったことに由来するとも言われる。' },
  'salario': { es: 'El gobierno anunció un aumento del salario mínimo interprofesional para el próximo año.', ja: '政府は来年の最低賃金（最低職種間賃金）の引き上げを発表した。', trivia: 'ラテン語 salarium に由来し、英語の salary と全く同語根の語。語源は sal（塩）で、古代ローマの兵士が塩や塩を買うための金銭を報酬として受け取っていたことに由来するとされる（英語の「worth one\'s salt」もこれを反映）。' },
  'salazón': { es: 'En las costas españolas, la salazón del bacalao ha sido una tradición culinaria durante siglos.', ja: 'スペインの沿岸地方では、タラの塩漬けが何世紀もの間、料理の伝統となってきた。', trivia: 'sal（塩）＋接尾辞 -azón からなるスペイン語固有の派生語で、ラテン語 sal に遡る。英語では salting または curing と言い、salt との語根の共通性は明らか。「salting」としての意味は英語の salt と完全に対応する。' },
  'salbanda': { es: 'El geólogo identificó una salbanda arcillosa a lo largo de la falla principal del yacimiento.', ja: '地質学者は鉱床の主断層に沿って粘土質の断層ガウジを確認した。', trivia: 'ドイツ語 Salband（断層帯の縁）に由来する地質・鉱山用語で、英語では salband または gouge（断層ガウジ）と呼ばれる。語源はドイツ語 Saum（縁・へり）と Band（帯）の合成とも、sal との関連はなく専門術語として借入された語とも言われる。' },
  'salchicha': { es: 'Los niños pidieron salchichas a la parrilla con patatas fritas para la cena del sábado.', ja: '子どもたちは土曜日の夕食にグリルしたソーセージとフライドポテトをリクエストした。', trivia: 'イタリア語 salsiccio（塩漬け肉の腸詰め）に由来し、ラテン語 salsus（塩漬けの）が語根。英語の sausage もフランス語 saucisse を経て同じラテン語語根に行き着き、サルシッチャ・ソーセージ・サルチーチャはすべて遠い親戚関係にある。' },
  'salchichería': { es: 'Compramos el jamón y el chorizo en una salchichería artesanal del mercado central.', ja: '中央市場の手工業的な加工肉専門店でハモンとチョリソを買った。', trivia: 'salchicha（ソーセージ）＋接尾辞 -ería（店・業）からなる派生語。英語では delicatessen（デリカテッセン）や charcuterie（シャルキュトリー）に相当するが、これらはドイツ語・フランス語由来で語根が異なる。英語に salchichería に直接対応する一語はない。' },
  'salchichero': { es: 'El salchichero del pueblo prepara sus embutidos siguiendo una receta familiar de tres generaciones.', ja: '村のソーセージ職人は、三世代に渡って受け継がれた家族のレシピで加工肉を作っている。', trivia: 'salchicha（ソーセージ）に職業を表す接尾辞 -ero を加えた語で、英語では sausage maker または charcutier（フランス語由来）に相当する。英語の -er 接尾辞と同様に、スペイン語の -ero も職業・担当者を表す点で共通の発想を持つ。' },
  'salchichón': { es: 'En la fiesta pusieron una bandeja de salchichón ibérico con pan tostado y tomate.', ja: 'パーティーでイベリコ産サルチチョンをトーストとトマトと一緒に並べた。', trivia: 'salchicha の指大辞（大きい・立派なの意）で、接尾辞 -ón を付けた形。英語では salami や summer sausage に近いが、スペイン・イベリア半島特有の乾燥熟成タイプを指す固有語であり、英語にはそのまま salchichón として借用されることもある。' },
  'salcochar': { es: 'En muchos países latinoamericanos se suele salcochar la yuca antes de freírla.', ja: '中南米の多くの国では、ユカ芋は揚げる前に塩水で下茹でするのが一般的だ。', trivia: 'sal（塩）と cochar（古形：煮る、ラテン語 coquere に由来）の合成語とみられ、英語の salt と cook が合わさったような発想の語。英語 cook・cuisine・culinary はすべてラテン語 coquere を共通の語源に持つ。中南米では sancochar という形も広く使われる。' },
  'saldar': { es: 'Finalmente pudimos saldar todas las deudas con el banco antes de que terminara el año.', ja: '年が終わる前に、ついに銀行との全ての負債を完済することができた。', trivia: 'イタリア語 saldare（固める・決済する）に由来し、ラテン語 solidare（固くする）が語根。英語の consolidate・solid・soldier も同じラテン語語根 solidus に遡る同族語で、「固める→借金を固定して清算する」という意味の発展が興味深い。' },
  'saldo': { es: 'Revisé el saldo de mi cuenta bancaria y vi que tenía menos dinero del que pensaba.', ja: '銀行口座の残高を確認したら、思っていたより少ないことがわかった。', trivia: 'イタリア語 saldo（確固とした、決済）に由来し、ラテン語 solidus が語根。英語の balance（残高）や clearance（在庫一掃）に相当するが、語源的には英語の solid・soldier と同じ系譜に属する。スペイン語の「rebajas y saldos」（バーゲンセール）としても日常的に使われる。' },
  'saledizo': { es: 'El saledizo de madera sobre la puerta principal protege la entrada de la lluvia.', ja: '玄関ドアの上に張り出した木製の庇が、雨から入口を守っている。', trivia: '動詞 salir（出る・突き出る）の派生語で、接尾辞 -edizo（しやすい、そういう傾向がある）を伴う。英語では overhang（張り出し）や projection に相当するが、語根の salir はラテン語 salire（跳ぶ・飛び出す）に由来し、英語の sally（突撃）や salient（突出した）と同語根。' },
  'saleroso': { es: 'La profesora de flamenco tiene un estilo muy saleroso que encanta a todos los alumnos.', ja: 'フラメンコの先生はとてもチャーミングなスタイルで、全生徒を魅了している。', trivia: 'salero（塩入れ、または愛嬌・粋な魅力）の派生形容詞で、「塩味が効いた→ぴりっとした魅力がある」という意味の転換が起きた語。英語では charming・witty・vivacious に相当するが、英語の salty には「辛辣な・口が悪い」という否定的なニュアンスも生じており、対照的な意味の広がりが興味深い。' },
  'salero': { es: 'Pasame el salero, por favor; la sopa necesita un poco más de sal.', ja: '塩入れを取ってください。スープにもう少し塩が必要です。', trivia: 'sal（塩）＋接尾辞 -ero（容器・担当者）からなる語で、ラテン語 salarium に通じる。英語では salt shaker または salt cellar に相当するが、スペイン語 salero はさらに「愛嬌・粋な魅力」という比喩的意味も持つ点がユニーク。英語の salt cellar の cellar はラテン語 cellarium から来ており語根が異なる。' },
  'sales': { es: 'El médico recomendó tomar sales minerales para recuperarse más rápido tras el ejercicio intenso.', ja: '医師は激しい運動後の回復を早めるため、ミネラル塩を摂取することを勧めた。', trivia: 'sal（塩）の複数形で、化学・医学用語としては「塩類」を意味する。英語の salts（塩類）と完全に対応し、salt・salary・sauce・sausage など広い語族を形成するラテン語 sal に遡る。「smelling salts（嗅ぎ塩）」という英語表現も同語根。' },
  'saleta': { es: 'Los invitados esperaron en la saleta mientras se terminaba de preparar el salón principal.', ja: 'メインのサロンの準備が整うまで、招待客は小広間で待った。', trivia: 'sala（広間・ホール）の指小辞で、接尾辞 -eta を付けた形。sala 自体はゲルマン語（フランク語 sala：広間）に由来し、英語の hall や salon（フランス語経由）と遠い親戚関係にある。英語でも parlour（応接間）の代わりに anteroom（控えの間）と呼ぶ空間に相当する。' },
  'salgada': { es: 'La comida quedó demasiado salgada porque añadimos sal dos veces por equivocación.', ja: '間違えて塩を二度加えてしまったので、料理がしょっぱくなりすぎた。', trivia: 'ポルトガル語・ガリシア語で「塩辛い」を意味する salgado/salgada に相当し、スペイン語標準形 salado/salada とは異なるが同語源（ラテン語 salsus）。英語の salty と同語根で、スペイン語 salado・ポルトガル語 salgado・英語 salty はすべてラテン語 sal の派生語として一致する。' },
  'salina': { es: 'Las salinas de Torrevieja producen miles de toneladas de sal marina cada año.', ja: 'トレビエハの塩田は毎年何千トンもの海塩を生産している。', trivia: 'ラテン語 salinae（塩田）の複数形に由来し、sal（塩）が語根。英語では salt flat・salt pan・salt works に相当するが、英語に salina という語も存在し（塩湖・塩田の意味で）そのままスペイン語から借用されている。米国カリフォルニア州の Salinas 市名もこれに由来する。' },
  'salílica': { es: 'El ácido salílica es una forma antigua de referirse al compuesto activo del sauce.', ja: '「ácido salílica」はヤナギの活性成分を指す古い表現です。', trivia: '「salicílico」の異綴り（スペイン語圏の一部で見られる変形）。語源はラテン語 salix（ヤナギ）で、英語の salic acid や salicylic acid と同語根。英語では「サリチル酸」を salicylic acid と呼ぶ。' },
  'salicílico': { es: 'El ácido salicílico se usa en cremas para tratar el acné y las verrugas.', ja: 'サリチル酸はニキビやいぼを治療するクリームに使われる。', trivia: 'ラテン語 salix（ヤナギ）に由来し、ヤナギの樹皮から初めて単離された物質。英語の salicylic（acid）と完全に同語根で、アスピリンの前身物質としても知られる。' },
  'salicor': { es: 'El salicor crece en suelos salinos cerca de la costa y se usa en la elaboración de sosa.', ja: 'アツケシソウは海岸沿いの塩性土壌に育ち、ソーダ製造に使われる。', trivia: 'ラテン語 sal（塩）を語根とし、塩分の多い環境に生きる植物の名。英語では glasswort や marsh samphire と呼ばれ、かつてガラス製造用のソーダ灰（potash）を得るために燃やされた。' },
  'salida': { es: 'No encontramos una salida al problema hasta que llegó el nuevo director con ideas frescas.', ja: '新しい所長が新鮮なアイデアを持って来るまで、私たちはその問題の解決策を見つけられなかった。', trivia: 'ラテン語 salire（跳ぶ、出る）に由来し、英語の exit や outlet に相当する多義語。英語の sally（突撃、機知あふれる発言）とも同語根で、どちらも「外へ飛び出す」イメージを共有している。' },
  'salidizo': { es: 'El salidizo de la fachada protege la entrada principal de la lluvia.', ja: 'ファサードの張り出しが正面玄関を雨から守っている。', trivia: '動詞 salir（出る）＋ 指小辞的接尾辞から派生した建築用語。英語では overhang や projection と呼ばれる概念で、同根語 saledizo の異形として用いられる。英語の salient（突出した）と同じ語根 salire を持つ。' },
  'salido': { es: 'El balcón está un poco salido de la pared y da muy buenas vistas al mar.', ja: 'バルコニーは壁から少し張り出しており、海の素晴らしい眺めが楽しめる。', trivia: 'salir（出る）の過去分詞で形容詞化したもの。ラテン語 salire（跳ぶ）が語源。英語の salient や protruding と同語根だが、口語では「発情した」という意味にもなる俗語的用法があり、文脈に注意が必要。' },
  'saliente': { es: 'La ministra saliente hizo un discurso emocionante en su último día en el cargo.', ja: '退任する大臣は在任最終日に感動的なスピーチを行った。', trivia: 'ラテン語 salire（跳ぶ、出る）の現在分詞形に由来。英語の salient と完全に同語根で、軍事用語では「突出部」を意味する。英語で outgoing minister と言う場面に相当する「退任する」の用法はスペイン語独自のニュアンス拡張。' },
  'salificación': { es: 'La salificación del ácido clorhídrico con hidróxido de sodio produce sal de mesa.', ja: '塩酸と水酸化ナトリウムの塩形成反応により食塩が生成される。', trivia: 'ラテン語 sal（塩）＋ -ficación（〜化）から成る化学用語。英語の salification と完全に対応し、酸と塩基の中和反応で塩が生じる過程を指す。英語の salt（塩）と同語根で、ゲルマン語と共通のインド＝ヨーロッパ語祖語 *sal- に遡る。' },
  'salificar': { es: 'Para salificar el ácido, hay que añadir la base lentamente mientras se agita la solución.', ja: '酸を塩化するには、溶液をかき混ぜながら塩基をゆっくり加える必要がある。', trivia: 'ラテン語 sal（塩）＋ facere（作る）に由来。英語の salify と同語根で、化学反応によって酸を塩（えん）に変える操作を指す。英語の satisfy（満足させる）も -fy 接尾辞を持つが語根は異なる。' },
  'salinera': { es: 'La empresa salinera local lleva más de cien años produciendo sal artesanal.', ja: '地元の製塩会社は100年以上にわたって伝統的な塩を製造し続けている。', trivia: 'ラテン語 sal（塩）に由来する形容詞・名詞。英語には salt-making や salt industry に相当する単語があるが、salinera のように製塩業者・製塩工場を一語で表す専用語は少なく、スペイン語の語彙の豊富さを示す例。' },
  'salinero': { es: 'El salinero trabajaba desde el amanecer recogiendo la sal cristalizada en las piscinas.', ja: '製塩業者は夜明けから池で結晶化した塩を収穫していた。', trivia: 'ラテン語 sal（塩）＋ -ero（職業を表す接尾辞）から構成。英語では salt worker や salter に相当し、中世英語の salter（塩製造者・塩商人）と語根を共有する。英語の salary（給料）も同語根で、ローマ時代に兵士が塩で支払いを受けたことに由来する。' },
  'salinidad': { es: 'La salinidad del Mar Muerto es tan alta que es imposible hundirse en él.', ja: '死海の塩分濃度はとても高く、沈むことができない。', trivia: 'ラテン語 sal（塩）＋ 抽象名詞接尾辞 -idad から成る。英語の salinity と完全に対応し、どちらもインド＝ヨーロッパ語祖語 *sal-（塩）に遡る。英語の salary（給料）やラテン語 salarium とも同語根で、塩が古代の交易・報酬の基盤だったことを示す。' },
  'salinización': { es: 'La salinización del suelo es uno de los principales problemas ambientales en zonas áridas.', ja: '土壌の塩類集積は乾燥地帯における主要な環境問題の一つだ。', trivia: 'ラテン語 sal（塩）＋ -ización（化）から成り、英語の salinization と対応する。農業用の過剰灌漑によって土壌に塩分が蓄積する現象を指し、英語では soil salinization または soil salination と言う。' },
  'salinizar': { es: 'El riego excesivo puede salinizar los campos y volverlos estériles en pocos años.', ja: '過剰な灌漑は数年で農地を塩性化させ、不毛にしてしまうことがある。', trivia: 'ラテン語 sal（塩）＋ 動詞化接尾辞 -izar（英語の -ize に相当）から成る。英語の salinize と同語根で、土壌や水に塩分を蓄積させるプロセスを表す。英語の -ize 接尾辞はギリシャ語起源で、スペイン語 -izar との対応は明快。' },
  'salino': { es: 'El médico le administró suero salino para rehidratarlo después del episodio de vómitos.', ja: '医師は嘔吐発作の後、彼を水分補給するために生理食塩水を投与した。', trivia: 'ラテン語 salinus（塩の）に由来し、英語の saline と完全に同語根。英語でも saline solution（生理食塩水）として医療現場で頻用される。インド＝ヨーロッパ語祖語 *sal- は英語の salt、ドイツ語の Salz とも共通する古い語根。' },
  'salitrada': { es: 'Las paredes del sótano estaban cubiertas de salitrada blanca por la humedad.', ja: '地下室の壁は湿気で白い塩の結晶に覆われていた。', trivia: 'salitre（硝石）から派生した語で、壁や土壌に浮き出た塩の白い付着物を指す。英語には effloresence（塩の花）や saltpeter deposit が対応するが、スペイン語の salitrada ほど日常的な語はない。語根のラテン語 sal（塩）は英語 salt と同源。' },
  'salitral': { es: 'Atravesamos un extenso salitral donde el suelo blanco brillaba bajo el sol.', ja: '広大な硝石地帯を横断した。白い土が太陽の下で輝いていた。', trivia: 'salitre（硝石）＋ 場所を示す接尾辞 -al から成る。英語では salt flat や nitrate deposit に相当し、南米（チリ・アルゼンチン）では硝石を豊富に含む土地の呼称として広く使われた。19世紀のチリ硝石産業（Guerra del Salitre）の文脈でも重要な語。' },
  'salitre': { es: 'El salitre que se acumula en las fachadas de los edificios costeros acelera el deterioro del material.', ja: '沿岸部の建物のファサードに蓄積する硝石は建材の劣化を加速させる。', trivia: 'ラテン語 sal（塩）＋ petra（岩）に由来すると考えられており、英語の saltpeter（硝石）と同語根。中世ヨーロッパでは火薬の原料として珍重され、英語 saltpeter の peter はラテン語 petra（岩）＝ 英語 Peter（ペテロ）と同じ語根を持つ。' },
  'salitrera': { es: 'Las antiguas salitreras del norte de Chile son hoy Patrimonio de la Humanidad.', ja: 'チリ北部の旧硝石工場は現在、世界遺産に登録されている。', trivia: 'salitre（硝石）＋ 場所・施設を表す -era から成る。英語では nitrate works や saltpeter refinery に相当。19世紀後半から20世紀初頭にかけてチリの硝石（nitrato）産業は世界経済を左右するほどの重要性を持ち、「salitreras」という語はその時代の歴史的証人でもある。' },
  'salitrero': { es: 'El suelo salitrero de la región hace difícil el cultivo de cualquier planta.', ja: 'その地域の硝石質の土壌は、どんな植物の栽培も困難にしている。', trivia: 'salitre（硝石）から派生した形容詞・名詞で、「硝石の多い」または「硝石産業に関わる人」を意味する。英語では nitrate や saltpeter を用いた複合語（saltpeter worker, nitrate miner）に相当。語根のラテン語 sal は英語 salt と同じインド＝ヨーロッパ語祖語 *sal- に由来。' },
  'salitrosa': { es: 'La tierra salitrosa de la llanura hacía imposible cultivar trigo o maíz.', ja: '平原の硝石質の土は小麦やトウモロコシの栽培を不可能にしていた。', trivia: 'salitre（硝石）＋ 形容詞接尾辞 -osa（豊富に〜を含む）から成る。英語では nitrous や saline に近いが、salitrosa はより「硝石や塩が表面に浮き出た」イメージを持つ。英語の nitrous も窒素・硝石系化合物を形容するが語源はギリシャ語 nitron（炭酸ナトリウム）で、sal 系語根とは異なる。' },
  'salitroso': { es: 'El ambiente salitroso de la costa deteriora rápidamente las estructuras metálicas.', ja: '沿岸の塩気の強い環境は金属構造物を急速に劣化させる。', trivia: 'salitrosa の男性形。salitre（硝石・塩分）＋ -oso（〜に富む）から成り、英語の nitrous や salty に近い概念。英語で saline または salt-laden と表現される環境を指す場合も多い。語根のラテン語 sal は英語 salt、ドイツ語 Salz と共通の古い語根。' },
  'saliva': { es: 'La saliva contiene enzimas que comienzan a descomponer los carbohidratos desde el momento en que comemos.', ja: '唾液には、食べた瞬間から炭水化物を分解し始める酵素が含まれている。', trivia: 'ラテン語 saliva（唾液）に直接由来し、英語の saliva と完全に同語根・同語形。これはラテン語からほぼそのまま英語とスペイン語の両方に入ったケースで、語源については諸説あるが、sal（塩）との関連を示唆する説もある。英語の口語では spit や spittle が日常的に使われる。' },
  'salivación': { es: 'La salivación excesiva puede ser un síntoma de náuseas o de ciertas enfermedades neurológicas.', ja: '過剰な唾液分泌は吐き気や一部の神経疾患の症状である可能性がある。', trivia: 'ラテン語 salivatio（唾液分泌）に由来し、英語の salivation と完全に対応する。パブロフの条件反射実験（犬の唾液分泌）で世界的に知られるようになった概念で、英語の salivate（よだれを垂らす・強く欲する）も同語根。口語的に「よだれが出るほど欲しい」という意味でも使われる点は英語・スペイン語共通。' },
  'salival': { es: 'Las glándulas salivales producen cerca de un litro de saliva al día.', ja: '唾液腺は1日に約1リットルの唾液を産生します。', trivia: 'ラテン語 saliva（唾液）に形容詞語尾 -al がついた派生語。英語の salivary gland（唾液腺）と同語根で、英語では形容詞形 salivary が一般的だが、スペイン語では salival と salivar（形容詞用法）が併用される。' },
  'salivar': { es: 'Solo con ver el pastel de chocolate, empecé a salivar sin poder evitarlo.', ja: 'チョコレートケーキを見ただけで、思わずよだれが出てきてしまった。', trivia: 'ラテン語 saliva（唾液）を動詞化したもので、英語の salivate と完全な同語根。パブロフの犬の実験で有名な「条件反射のよだれ」を表す際にも使われ、比喩的に「食欲をそそられる」という意味でも用いられる。' },
  'salivazo': { es: 'El jugador fue sancionado por escupir un salivazo al árbitro durante el partido.', ja: 'その選手は試合中に審判につばを吐きかけたとして制裁を受けた。', trivia: 'saliva（唾液）に増大・強意を表す接尾辞 -azo を加えた語。英語には対応する一語がなく「a big spit」や「a glob of spit」と表現する。-azo はスペイン語特有の接尾辞で、「強い一撃」も意味する（golpazo など）。' },
  'salivera': { es: 'La abuela siempre decía que tenerle salivera a un buen jamón ibérico era completamente normal.', ja: 'おばあさんはいつも、上質なイベリコハムに食指が動くのは当然のことだと言っていた。', trivia: 'saliva に集合・傾向を表す語尾 -era がついた口語表現。英語では drooling（よだれを垂らすこと）や mouth-watering（よだれが出るほど美味しそうな）が近いが、「物欲」という比喩的意味まで含む一語はなく、スペイン語特有のニュアンスを持つ。' },
  'salmonada': { es: 'Eligieron una pintura salmonada para las paredes del salón, que daba un ambiente cálido y acogedor.', ja: '彼らはリビングの壁にサーモンピンクの塗料を選んだ。温かく居心地の良い雰囲気が生まれた。', trivia: '魚のサーモン（salmón）を語源とし、その身の色を形容する語。英語でも salmon pink または salmon-colored と表現し、色名としてのサーモンはスペイン語・英語ともに魚の名前がそのまま色名になった珍しい例。' },
  'salmonado': { es: 'El carpintero encontró una trucha de color salmonado en el río de montaña.', ja: '大工はその山の川でサーモンピンク色のマスを見つけた。', trivia: 'salmonada の男性形で、形容詞として名詞の性に合わせて変化する。英語の salmon-hued や salmon-colored に相当し、色だけでなく「サケのような風味」の意味でも使われる点が英語と異なる用法の広がりを持つ。' },
  'salmonete': { es: 'En el restaurante de la costa pedimos un salmonete a la plancha con limón y hierbas aromáticas.', ja: '海辺のレストランで、レモンとハーブを添えた鉄板焼きのヒメジを注文した。', trivia: 'ラテン語 mullus（ヒメジ）ではなく、salmón（サーモン）の縮小形として形成されたスペイン語固有の語で、その赤みがかった体色がサケを連想させることに由来する。英語では red mullet（地中海）または goatfish（大西洋・太平洋）と呼ばれ、語根は全く異なる。' },
  'salmorejo': { es: 'En verano, el salmorejo cordobés bien frío es uno de los platos más refrescantes de la cocina española.', ja: '夏には、よく冷えたコルドバ風サルモレホがスペイン料理で最も爽やかな一皿のひとつだ。', trivia: '語源には諸説あり、ラテン語 sal（塩）と muria（塩水）の複合語説と、アラブ系語源説がある。ガスパチョと混同されることがあるが、サルモレホはパンと油が多くより濃厚。英語圏でも salmorejo とそのまま使われ、定着しつつあるスペイン料理の固有名詞。' },
  'salmódica': { es: 'La recitación salmódica del monje llenaba la capilla de una atmósfera de profunda serenidad.', ja: '修道士の賛美歌調の朗唱が礼拝堂を深い静けさの雰囲気で満たしていた。', trivia: 'ギリシャ語 psalmōidia（詩篇の歌）に由来し、ラテン語 psalmodia を経てスペイン語に入った。英語の psalmodic と同語根で、psalm（詩篇）はギリシャ語 psalmos（竪琴を弾く音）から来ている。比喩的に「単調でお経のような」という否定的ニュアンスでも使われる点は英語でも共通。' },
  'salmódico': { es: 'Su tono salmódico al leer el informe hizo que varios colegas se quedaran dormidos en la reunión.', ja: '報告書を読む彼の単調で眠気を誘う口調のせいで、会議中に居眠りする同僚が何人も出た。', trivia: 'salmódica の男性形。ギリシャ語 psalmos（竪琴の音）と ōidē（歌）の複合語が語源で、英語 psalm の p は発音されないがスペイン語では salmo と p を落として取り込んだ。「単調」という比喩的用法は宗教的な詠唱が持つ反復性から生まれた。' },
  'salmodiar': { es: 'El coro comenzó a salmodiar los versículos sagrados al ritmo pausado del órgano.', ja: '合唱団はオルガンのゆっくりしたリズムに合わせて聖句を詠唱し始めた。', trivia: 'ギリシャ語 psalmōidia を語源とするラテン語 psalmodiare から派生。英語では psalmodize という動詞があるが、ほとんど使われず「chant psalms」と言い換えることが多い。比喩的に「ぶつぶつ繰り返す」という意味でも使える点はスペイン語の豊かな表現力を示す。' },
  'salmodio': { es: 'El salmodio interminable del sacerdote adormecía a los feligreses más mayores.', ja: '司祭の果てしない詠唱は年配の信者たちを眠気に誘った。', trivia: 'ラテン語 psalmodium（詩篇詠唱）に由来し、英語の psalmody と同語根。英語では psalmody の p を発音しないが、スペイン語は -lm- で取り込んだ。宗教音楽の文脈だけでなく、日常会話で「単調な繰り言」を指す比喩的用法が発達している。' },
  'salmo': { es: 'El coro interpretó el salmo 23 con una melodía antigua y conmovedora durante la misa.', ja: '聖歌隊はミサの中で古く心を打つ旋律で詩篇23篇を歌い上げた。', trivia: 'ギリシャ語 psalmos（竪琴の弦を弾く音、詩篇）に由来し、ラテン語 psalmus を経てスペイン語に入った。英語の psalm と同語根だが、英語では語頭の p を保持（ただし黙字）しているのに対し、スペイン語は ps を s に簡略化した。旧約聖書の詩篇はヘブライ語では「テヒリーム（賛美の書）」と呼ばれる。' },
  'salmuera': { es: 'Las aceitunas se conservan en salmuera durante semanas para que adquieran el sabor adecuado.', ja: 'オリーブは適切な風味を得るために数週間塩水に漬けられる。', trivia: 'ラテン語 sal（塩）と muria（塩水）の複合語に由来する。英語の brine と意味は同じだが語源は異なり、brine は古英語 bryne に由来する。食品保存の手法として古代から使われ、英語 pickle（ピクルス）の漬け汁とほぼ同義に使われることもある。' },
  'salmuerarse': { es: 'El queso necesita salmuerarse durante al menos doce horas para tener el punto de sal correcto.', ja: 'チーズはちょうどよい塩加減にするために少なくとも12時間は塩水に漬けられる必要がある。', trivia: 'salmuera（塩水）を動詞化した再帰形で、食品加工の専門用語的表現。英語では「be brined」や「soak in brine」と表現し、対応する一語の動詞はない。スペインの食文化においてチーズやオリーブの塩漬け処理は伝統的に重要な工程。' },
  'salobral': { es: 'La laguna salobral al sur del pueblo es refugio de una gran variedad de aves migratorias.', ja: '村の南にある塩性の湿地は、多種多様な渡り鳥の避難所となっている。', trivia: 'ラテン語 sal（塩）に由来し、salobre に場所・集合を表す接尾辞 -al が加わった語。英語では brackish land（汽水域の土地）や salt flat と表現し、対応する一語はない。スペイン・イベリア半島南部には天然の塩性湿地が多く、フラメンコの語 salero（塩気・魅力）も同語根。' },
  'salobre': { es: 'El agua salobre del estuario es hogar de especies que no viven ni en el mar ni en ríos de agua dulce.', ja: '河口の汽水は、海にも淡水の川にも生息しない生物の住処となっている。', trivia: 'ラテン語 salobris（塩分を含む）に由来し、英語の brackish と意味が一致するが語源は全く異なる。brackish はオランダ語 brak（塩辛い）に由来する。「塩気はあるが海水ほどではない」という汽水の概念は、河口・マングローブ生態系を理解する上で重要。' },
  'salobridad': { es: 'Los científicos midieron la salobridad del río para evaluar el impacto del vertido industrial.', ja: '科学者たちは工業排水の影響を評価するため川の塩分濃度を測定した。', trivia: 'salobre に抽象名詞語尾 -idad がついた語で、英語の brackishness や salinity に相当する。英語 salinity はラテン語 sal（塩）から来ており salobre と同語根だが、salobridad は「完全な塩水ではないほのかな塩気」という微妙なニュアンスを持ち、英語の saline とは区別される。' },
  'salomónica': { es: 'La jueza adoptó una solución salomónica que dejó a ambas partes parcialmente satisfechas.', ja: '女性裁判官は双方が部分的に納得できるソロモン的な解決策を採った。', trivia: '旧約聖書のソロモン王（ヘブライ語 Shlomoh）に由来し、英語の Solomonic と完全に同語根。「赤ちゃんを二つに分ける」という有名な裁きから「知恵ある公平な判断」を意味するようになった。建築では「ソロモン神殿の柱」を模したねじれ柱（columna salomónica）を指す専門用語でもある。' },
  'salomónico': { es: 'El acuerdo salomónico entre las dos empresas rivales sorprendió a todos los analistas del sector.', ja: 'ライバル2社間のソロモン的合意は業界アナリスト全員を驚かせた。', trivia: 'salomónica の男性形。ヘブライ語の人名 Shlomoh がギリシャ語 Solomōn、ラテン語 Salomon を経てスペイン語に入った。英語では Solomonic judgment（ソロモンの審判）という表現が使われる。バロック建築のねじれ柱は英語でも Solomonic column と呼ばれる国際的な建築用語。' },
  'salpa': { es: 'La salpa es un animal marino transparente que forma largas cadenas flotantes en el océano abierto.', ja: 'サルパは透明な海洋動物で、外洋に長い浮遊連鎖を形成する。', trivia: 'ラテン語 salpa、ギリシャ語 salpē（一種の魚）に由来し、魚のヒメジとプランクトン様尾索動物の2つの全く異なる生物に同じ名が使われる珍しいケース。英語の salp（尾索動物）と saupe（魚）は区別されており、スペイン語 salpa はその両方を指す。' },
  'salpicadura': { es: 'La salpicadura de barro en el coche nuevo me molestó mucho después de conducir por el camino sin asfaltar.', ja: '未舗装の道を走った後、新車に泥はねがついていてとても気になった。', trivia: '動詞 salpicar（はねる、飛び散る）の名詞形で、-ura は結果・状態を表す接尾辞。salpicar の語源はラテン語 sal（塩）と picar（刺す、突く）の複合語説があるが諸説ある。英語の splash や splatter に相当するが、「スキャンダルの飛び火」という比喩的用法はスペイン語ならではの豊かな表現。' },
  'salpicón': { es: 'De primero pedimos un salpicón de marisco con gambas, mejillones y cangrejos aliñados con vinagre.', ja: '前菜として、酢で和えたエビ・ムール貝・カニのサルピコンを注文した。', trivia: 'salpicar（飛び散らせる）に増大接尾辞 -ón がついた語で、「様々なものが散らばった」イメージから料理名になった。英語圏では salpicon とそのまま借用されており、フランス料理用語としても salpicon と綴る。英語で「ごちゃ混ぜ」を意味する medley や hodgepodge が対応するが、料理名としては固有名詞として使われる。' },
  'salpimentar': { es: 'Antes de poner la carne en la sartén, hay que salpimentarla bien por ambos lados.', ja: '肉をフライパンに入れる前に、両面にしっかり塩コショウをしなければならない。', trivia: 'sal（塩）と pimienta（コショウ）を動詞化した複合語で、英語の「season with salt and pepper」を一語で表した実用的な表現。英語には対応する一語の動詞がなく、スペイン語の料理語彙の簡潔さを示す好例。pimienta はラテン語 pigmentum（染料・スパイス）に由来し、英語の pigment と同語根という意外な関係がある。' },
  'salpique': { es: 'El médico advirtió que no salpique la herida con agua sucia para evitar infecciones.', ja: '医師は、感染を防ぐために汚れた水を傷口に飛ばさないよう警告した。', trivia: 'salpicarの接続法現在1・3人称単数形。動詞 salpicar はラテン語の sal（塩）と picar（突く・刺す）の合成語に由来するとも、ゲルマン系の擬音語起源とも言われる。英語の splash や splatter に意味が近いが、語源的な直接の親戚ではない。' },
  'salpicar': { es: 'El camión pasó a toda velocidad y nos salpicó de barro a todos.', ja: 'トラックがものすごいスピードで通り過ぎ、私たちみんなに泥を跳ね飛ばした。', trivia: 'ラテン語の sal（塩・液体）と picar（刺す・はじく）の合成に由来するとされ、「液体をはじき飛ばす」という感覚を持つ。英語では splash や splatter が対応するが、これらはゲルマン系の擬音語起源であり、salpicar とは語源が異なる。' },
  'salpresar': { es: 'En esta región, aún se acostumbra salpresar el bacalao para conservarlo durante el invierno.', ja: 'この地方では、冬の保存のためにタラを塩漬けにして重石でプレスする習慣が今も残っている。', trivia: 'sal（塩、ラテン語 sal）と presar（圧力をかける、ラテン語 pressare）の合成語。英語の salt-press（塩蔵脱水）に直訳でき、英語の preserve（保存する）とも presar を通じて語根を共有している。' },
  'salpuga': { es: 'La salpuga es una araña grande que vive en zonas áridas y puede causar una picadura muy dolorosa.', ja: 'ヒヨケムシは乾燥地帯に生息する大型のクモで、非常に痛い刺し傷を引き起こすことがある。', trivia: 'ラテン語 salpuga（毒グモの一種）に由来し、古代ローマ時代からその存在が記録されている。英語では solifuge または sun spider と呼ばれ、クモ目ではあるがクモとは別の目（ヒヨケムシ目）に分類される。' },
  'salpullido': { es: 'Al niño le salió un salpullido en el brazo después de jugar en el jardín.', ja: 'その子どもは庭で遊んだ後、腕に発疹が出た。', trivia: 'sal（塩、転じて「粒状のもの」）と pullido（皮膚の状態）に由来するとされ、皮膚に粒が出る状態を表す。英語の rash（発疹）に意味が対応するが、語源は異なる。sarpullido とも言われ、地域によって綴りが揺れる。' },
  'salsamentaria': { es: 'Compramos jamón serrano y chorizo en una salsamentaria del centro de la ciudad.', ja: '市内中心部の加工肉専門店でハモン・セラーノとチョリソを買った。', trivia: 'ラテン語 salsamentum（塩蔵食品、特に魚や肉の加工品）に由来し、古代ローマの食品用語が現代まで生き残った珍しい例。英語の salami や sausage もラテン語 sal（塩）を共通の祖先に持つ。' },
  'salsera': { es: 'La salsera de porcelana estaba llena de salsa verde hecha con hierbas frescas.', ja: '磁器のソース入れには、新鮮なハーブで作ったサルサ・ベルデがたっぷり入っていた。', trivia: 'salsa（ソース、ラテン語 salsa「塩味のもの」）の派生語で、ソースを入れる容器や、サルサ音楽・ダンスを愛する人を指す多義語。英語の sauce（ソース）と同語根であり、どちらもラテン語 sal（塩）に遡る。' },
  'salsero': { es: 'Mi primo es un salsero apasionado que lleva diez años bailando en concursos internacionales.', ja: '私のいとこは情熱的なサルサダンサーで、10年間国際大会で踊り続けている。', trivia: 'salsa（ラテン語 salsa に由来）に接尾辞 -ero（「〜に関わる人・もの」）を付けた語。英語には salsa dancer / salsa musician という表現があるが、salsero のように1語で表す名詞はない。また接尾辞 -ero は英語の -er に対応することが多い（panadero → baker など）。' },
  'salsifí': { es: 'El salsifí es una raíz blanca con sabor suave que se usa mucho en la cocina francesa.', ja: 'バラモンジンは淡白な味の白い根で、フランス料理でよく使われる。', trivia: 'イタリア語 sassefrica またはフランス語 salsifis に由来し、さらにラテン語の saxum（岩）と fricare（こする）の合成語説もある。英語でも salsify と呼ばれ、スペルがほぼ同じ珍しいケース。日本では「西洋ゴボウ」の名で知られる。' },
  'saltabardales': { es: 'Mi hermano menor era un saltabardales que siempre llegaba a casa lleno de rasguños.', ja: '弟は怖いもの知らずのやんちゃ者で、いつもひっかき傷だらけで帰ってきた。', trivia: 'saltar（飛び越える）と barda/bardal（垣根、茨の生垣）の合成語で、「垣根を飛び越える者」という生き生きとした造語。英語に対応する1語はなく、daredevil や rascal が近い意味を持つ。saltar 自体はラテン語 saltare（踊る・跳ぶ）に由来する。' },
  'saltabarrancos': { es: 'Solo un saltabarrancos como él se atrevería a cruzar ese desfiladero sin equipo de seguridad.', ja: '彼のような向こう見ずな人間だけが、安全装備なしであの峡谷を渡ろうとするだろう。', trivia: 'saltar（跳ぶ、ラテン語 saltare）と barranco（峡谷・崖）の合成語で、「崖を飛び越える人」という比喩的表現。英語の daredevil（命知らず）や thrill-seeker に相当するが、より地形的・農村的なイメージを持つ。' },
  'saltacharcos': { es: 'Llegó a la reunión con unos saltacharcos que le quedaban ridículamente cortos.', ja: '彼は滑稽なほど丈の短いズボンをはいて会議に現れた。', trivia: 'saltar（跳ぶ）と charco（水たまり）の合成語で、「水たまりを飛び越えるくらい短い」ズボンを指すユーモラスな表現。英語では flood pants や high-water pants と呼ばれ、「洪水が来ても大丈夫」という同様のユーモアが込められている。' },
  'saltadero': { es: 'Los niños se turnaban para tirarse desde el saltadero al río durante todo el verano.', ja: '子どもたちは夏の間ずっと、飛び込み台から川へ交代で飛び込んだ。', trivia: 'saltar（ラテン語 saltare「跳ぶ」）に場所を示す接尾辞 -dero を付けた語で、「跳ぶための場所」を意味する。英語の springboard（跳躍台）や diving board に対応し、接尾辞 -dero は英語の -ery や -ing place に相当する機能を持つ。' },
  'saltadiza': { es: 'La pintura saltadiza del techo empezó a caerse tras las lluvias intensas.', ja: '天井の剥がれやすい塗装が、激しい雨の後から落ちはじめた。', trivia: 'saltar（跳ぶ・はじける、ラテン語 saltare）に形容詞接尾辞 -adizo（「〜しやすい傾向がある」）を付けた語。英語の flaky（剥がれやすい）や brittle（もろい）に近い意味を持ち、接尾辞 -adizo は英語の -prone や -able に対応することがある。' },
  'saltadizo': { es: 'Este tipo de roca caliza es saltadizo y puede desprenderse sin previo aviso.', ja: 'このタイプの石灰岩は剥離しやすく、予告なく崩れ落ちることがある。', trivia: 'saltadiza の男性形。saltar（ラテン語 saltare「跳ぶ・はじける」）と形容詞接尾辞 -adizo の組み合わせで、「はじけやすい・剥がれやすい」傾向を示す。英語では spalling（石材の剥離）という専門用語があり、建築・地質学でよく使われる。' },
  'saltador': { es: 'El saltador de pértiga batió el récord nacional con un salto de seis metros.', ja: '棒高跳びの選手が6メートルの跳躍で国内記録を更新した。', trivia: 'saltar（ラテン語 saltare「踊る・跳ぶ」）に行為者を示す接尾辞 -dor を付けた語。英語の jumper や vaulter に対応し、-dor は英語の -er と同様に「〜する人」を意味する接尾辞。ラテン語 saltare は英語の assault（突撃）や somersault（宙返り）にも影響を与えている。' },
  'saltadora': { es: 'La saltadora de longitud entrenó durante años para clasificarse para los Juegos Olímpicos.', ja: '走り幅跳びの女性選手はオリンピック出場資格を得るために何年も練習を続けた。', trivia: 'saltador の女性形。ラテン語 saltare（踊る・跳ぶ）に由来し、英語の jumper / vaulter の女性版に相当する。英語では性別を区別する接尾辞がないが、スペイン語では -or/-ora で男女を区別するのが一般的。' },
  'saltadura': { es: 'El alfarero notó una saltadura en el esmalte de la vasija antes de ponerla a la venta.', ja: '陶芸家は販売前に、壺の釉薬に欠けがあることに気づいた。', trivia: 'saltar（はじける・欠ける）に名詞接尾辞 -adura を付けた語で、「はじけた結果・欠けた箇所」を指す。英語の chipping や spalling に対応し、接尾辞 -adura は英語の -ure や -age に相当する機能を持つ（例：pintura→painting、rotura→rupture）。' },
  'saltambanco': { es: 'El saltambanco animó a la multitud con sus acrobacias y trucos de magia callejeros.', ja: 'その大道芸人は路上での曲芸とマジックで群衆を沸かせた。', trivia: 'イタリア語 saltimbanco（「ベンチに飛び乗る者」、salti+in+banco）に由来し、市場の台の上で芸を披露する大道芸人を指す。英語の mountebank（ペテン師・大道売薬師）と同語源であり、どちらも「台に飛び乗る」というイタリア語の合成語から来ている。' },
  'saltante': { es: 'El escudo heráldico de la familia mostraba un león saltante sobre un fondo rojo.', ja: 'その家の紋章は、赤い地に跳躍するライオンが描かれていた。', trivia: 'saltar（ラテン語 saltare「跳ぶ」）の現在分詞形から派生した形容詞。英語の heraldry（紋章学）用語 salient（「跳躍する姿勢の」）と同語根であり、どちらもラテン語 salire（跳ぶ）に由来する。英語の salient（顕著な・重要な）もこの語根から転義したもの。' },
  'saltaparedes': { es: 'La policía atrapó al saltaparedes cuando intentaba escalar la tapia de una joyería.', ja: '警察は、宝石店の塀をよじ登ろうとしているところを泥棒を捕まえた。', trivia: 'saltar（跳ぶ）と pared（壁、ラテン語 paries）の合成語で、「壁を飛び越える者」を意味する。英語の cat burglar（忍び込み泥棒）に概念が近く、「猫のように壁を越える」という比喩は両言語で共通している。小鳥のミソサザイ（wren）も壁を素早く移動することからこの名で呼ばれる。' },
  'saltarelo': { es: 'La orquesta tocó un saltarelo animado que hizo levantarse a bailar a toda la audiencia.', ja: 'オーケストラが演奏した活気あるサルタレロで、観客全員が立ち上がって踊り出した。', trivia: 'イタリア語 saltarello（「小さく跳ぶもの」）に由来し、saltar（ラテン語 saltare「踊る・跳ぶ」）の指小辞形。英語でも saltarello とほぼ同じスペルで通じる国際的な音楽用語。メンデルスゾーンの「イタリア交響曲」第4楽章でも有名になった。' },
  'saltarín': { es: 'El niño saltarín no podía estar quieto ni un momento durante la clase.', ja: 'その飛び跳ねてばかりいる子どもは、授業中一瞬たりじっとしていられなかった。', trivia: 'saltar（ラテン語 saltare「跳ぶ・踊る」）に強調の接尾辞 -ín を付けた語で、「よく跳ね回る」傾向を指す。英語の bouncy や restless に対応するが、1語で表す形容詞は少ない。熱帯の鳥マイコドリ（manakin）もこの名で呼ばれ、英語の manakin も同語源のオランダ語経由。' },
  'saltarina': { es: 'La saltarina llegó a los diez años al club de gimnasia y ganó su primer trofeo al siguiente mes.', ja: 'その跳躍の得意な女の子は10歳で体操クラブに入り、翌月には初めてのトロフィーを獲得した。', trivia: 'saltarín の女性形。ラテン語 saltare（踊る・跳ぶ）に由来し、英語では bouncy girl や little jumper に相当するが、スペイン語のように1語で性別も示せる便利な形。接尾辞 -ín/-ína は指小・愛称的なニュアンスも持つ。' },
  'saltatrás': { es: 'En los documentos coloniales, el término saltatrás se usaba para clasificar a las personas según su origen racial.', ja: '植民地時代の文書では、サルタトラスという言葉が人々を人種的出自によって分類するために使われていた。', trivia: 'saltar（跳ぶ）と atrás（後ろへ）の合成語で、「先祖返り」「後戻り」を意味する。スペイン植民地時代のカースト制度（sistema de castas）における混血分類の一つで、英語では throwback や atavism が語義的に近く、生物学的な「先祖返り」を指す atavism もラテン語 atavus（先祖）に由来する。' },
  'pudrir': { es: 'Si dejas la fruta demasiado tiempo, empieza a pudrirse por dentro.', ja: '果物を長く放置しすぎると、内側から腐り始める。', trivia: 'ラテン語「putrere（腐る）」に由来し、「putridus（腐敗した）」とも関連する。英語の「putrid（腐った）」「putrefy（腐敗する）」と同源で、有機物の腐敗を表す語族に属している。' },
  'pura sangre': { es: 'El jinete montaba un pura sangre de origen árabe en la carrera de hoy.', ja: '騎手は今日のレースでアラブ系のサラブレッドに乗っていた。', trivia: '「puro（純粋な）＋sangre（血）」の合成語で、「純血」を意味する。英語の「thoroughbred」は「完全に育てられた」という意味だが、スペイン語では「血統の純粋さ」に焦点を当てており、馬の品種を指す場合の文化的視点の違いが興味深い。' },
  'quepí': { es: 'Los soldados desfilaron con su quepí perfectamente ajustado bajo el sol de verano.', ja: '兵士たちは夏の太陽の下、きちんと調整されたケピ帽をかぶって行進した。', trivia: 'フランス語「képi」から借用された語で、もともとドイツ語の「Käppi（小さな帽子）」に由来する。英語でも「kepi」または「képi」と呼ばれ、ナポレオン時代のフランス軍を通じて世界各国の軍帽として広まった。' },
  'queque': { es: 'Mi abuela preparó un queque de chocolate para celebrar mi cumpleaños.', ja: '祖母は私の誕生日を祝うためにチョコレートケーキを作ってくれた。', trivia: '英語の「cake」がスペイン語圏（特に中南米やカナリア諸島）に音写借用された語で、「cake→keike→queque」という経路で定着した。標準スペイン語の「pastel」や「tarta」とは異なる地域変種であり、植民地期の英語接触の証拠でもある。' },
  'querosén': { es: 'En muchas zonas rurales, la gente sigue usando querosén para las lámparas de aceite.', ja: '多くの農村地域では、人々は今でも石油ランプに灯油を使い続けている。', trivia: 'ギリシャ語「keros（蝋）」に由来し、19世紀にカナダの地質学者エイブラハム・ゲスナーが商品名として「kerosene」を作った。英語の「kerosene」と完全に同源で、蝋燭の代替燃料として普及した歴史的背景を持つ。' },
  '¡qué va!': { es: '— ¿Crees que va a llover hoy? — ¡Qué va! Hace un sol espléndido.', ja: '「今日は雨が降ると思う？」「まさか！ 素晴らしい晴れだよ。」', trivia: '「qué（何）」と「va（行く＝vamos の三人称）」から成る慣用表現で、「どこへ行くというのだ！」という反語的な否定が転じた。英語の「No way!」に相当し、スペインのくだけた会話で頻繁に使われる感嘆的否定表現。' },
  'quechua': { es: 'El quechua es el idioma indígena más hablado de América del Sur, con millones de hablantes.', ja: 'ケチュア語は南米で最も話されている先住民族の言語で、数百万人の話者がいる。', trivia: 'ケチュア語自身の呼び名「Qhichwa（温暖な谷）」に由来し、インカ帝国の公用語として広まった。英語でも「Quechua」と呼ばれ、「コンドル」「ジャガイモ（papa）」「コカ」など多くの語がケチュア語を経由して世界中に伝わっている。' },
  'quita y pon': { es: 'Este forro de sofá es de quita y pon, así que puedes lavarlo fácilmente cuando quieras.', ja: 'このソファーカバーは着脱自在なので、好きなときに簡単に洗濯できる。', trivia: '「quitar（取る）」と「poner（置く）」という反義語を組み合わせた複合語で、スペイン語特有の動詞対称表現。英語では「removable（取り外し可能な）」や「detachable」と訳されるが、スペイン語の表現は動作の往復性をユーモラスに表している。' },
  'rafi': { es: 'Las cestas tejidas con rafi son resistentes y muy apreciadas en artesanía.', ja: 'ラフィアで編まれたかごは丈夫で、工芸品として高く評価されている。', trivia: 'ラフィアはマダガスカル原産のラフィアヤシ（Raphia farinifera）の葉から採れる天然繊維で、その名はマダガスカル語に由来する。英語の raffia と同語源で、世界中で籠編みや帽子の素材として使われている。' },
  'incorporarse': { es: 'Después de la baja por maternidad, se reincorporó al trabajo con mucha energía.', ja: '産休が明けた後、彼女はエネルギーに満ちて職場に復帰した。', trivia: 're-（再び）と incorporarse（合流する・加わる）が合わさった動詞で、incorporarse 自体はラテン語 corpus（体・組織）に由来する。英語の rejoin や return to work に相当し、incorporate（組み入れる）とも同語根。' },
  'relamer': { es: 'El perro se relamía los bigotes después de comerse todo el hueso.', ja: '犬は骨を全部食べ終えた後、ひげをなめ回していた。', trivia: 're-（繰り返し）と lamer（なめる）が合わさった動詞で、lamer 自体はラテン語 lambere（なめる）に由来する。英語の lap（液体をなめる）も同じ語根を持ち、再帰形 relamerse は「舌なめずりをする」や「期待でほくそ笑む」という比喩的な意味でも使われる。' },
  'responsoria': { es: 'El coro cantó la responsoria durante la misa solemne.', ja: '合唱団は荘厳ミサの間、交唱を歌った。', trivia: 'ラテン語 responsorium（応答歌）に由来するカトリック典礼用語で、聖職者と会衆または二つの合唱団が交互に歌う形式を指す。英語の responsory と同根で、gregorio聖歌（グレゴリオ聖歌）の重要な要素の一つ。' },
  'restregado': { es: 'El suelo quedó completamente restregado después de tanto frotar.', ja: 'あれだけごしごし擦った後、床はすっかりきれいになった。', trivia: '動詞 restregar（強く擦る）の過去分詞で、ラテン語 fricare（擦る）の変形語 *restricare に由来するとも言われる。英語の scrubbed（こすり洗いされた）に対応し、中南米では「当てこすり・嫌味」という比喩的意味でも使われる。' },
  'resucitado': { es: 'Según los Evangelios, Jesús resucitado se apareció a sus discípulos.', ja: '福音書によると、復活したイエスが弟子たちの前に現れた。', trivia: '動詞 resucitar（生き返る・復活する）の過去分詞で、英語の resurrected や revived に対応する。ラテン語 resuscitare（再び目覚めさせる）に由来し、英語の resuscitate（蘇生させる）と同語源。' },
  'retenimiento': { es: 'El retenimiento de los documentos por parte de la empresa fue declarado ilegal.', ja: '会社による書類の保持は違法と宣告された。', trivia: '*retener*（保持する）＋*-miento*（行為・状態を表す接尾辞）から成る古風な名詞で、現代では *retención* の方が一般的。ラテン語 *retinēre* を語源とし、英語の *retention* と同じ概念を古い形式で表している。' },
  'reumática': { es: 'Mi abuela reumática tiene dificultades para subir las escaleras en los días de frío.', ja: 'リウマチを患っている祖母は、寒い日に階段を上るのが大変だ。', trivia: 'ギリシャ語の「rheûma（流れ、体液の流れ）」に由来し、古代医学では体液の異常な流れが関節の痛みを引き起こすと考えられていた。英語の rheumatic と同語源で、現代医学でも広く使われる。' },
  'reumatóloga': { es: 'La reumatóloga le recomendó ejercicio moderado para aliviar los síntomas de la artritis.', ja: 'リウマチ科医は、関節炎の症状を和らげるために適度な運動を勧めた。', trivia: '「rheûma（体液の流れ）＋ logos（学問）＋ -ista/-loga（専門家）」というギリシャ語の複合語から来ており、英語の rheumatologist と同語源。スペイン語では女性専門医を指す場合 -a 語尾を使う。' },
  'reunida': { es: 'La familia reunida alrededor de la mesa celebró el fin de año con mucha alegría.', ja: 'テーブルを囲んで集まった家族は、とても楽しく年末を祝った。', trivia: 'ラテン語の「re-（再び）＋ unire（一つにする）」に由来し、英語の reunite や reunion と同じ語根を持つ。過去分詞が形容詞として使われる典型的なスペイン語の用法。' },
  'saldis': { es: 'Con el descuento de fin de temporada, encontramos varios artículos en saldis a precios increíbles.', ja: 'シーズン末のセールで、信じられないほどの価格でいくつかの品物を処分品として見つけた。', trivia: '動詞 saldar（精算する・バランスをとる）の古形・派生形で、イタリア語 saldo（残高・バランス）に由来する。英語の sale（セール）と語源的に近く、「残高を清算すること＝値引き販売」という意味の転換が見られる。' },
  'salera': { es: 'La abuela guardaba la salera de cerámica en el centro de la mesa para condimentar los guisos.', ja: '祖母は煮込み料理に味付けするため、陶器の塩入れを食卓の中央に置いていた。', trivia: 'sal（塩）に場所・容器を表す接尾辞 -era を付けた語で、salero（塩入れ、男性形）の女性形または地域変異形。英語の salt cellar / saltshaker に対応し、スペイン語では salero が「ユーモアのセンス」を意味する俗語にもなっている。' },
  'salerosa': { es: 'La actriz tenía una forma salerosa de contar sus anécdotas que hacía reír a todos los presentes.', ja: 'その女優は、その場にいる全員を笑わせる愛嬌たっぷりのエピソードの語り方をしていた。', trivia: 'salero（ユーモア・魅力）に形容詞化接尾辞 -oso/-osa を付けた語で、「塩味が効いている＝ウィットがある」という比喩から生まれた。英語には直訳しにくいが、charming・witty に近く、スペイン南部アンダルシア文化の陽気さを体現する言葉とされる。' },
  'salteado': { es: 'Pedí un salteado de verduras con tofu en el restaurante vegetariano del barrio.', ja: '近所のベジタリアンレストランで豆腐入り野菜炒めを注文した。', trivia: 'saltear（強火で炒める）の過去分詞が名詞・形容詞として定着した語で、フランス語 sauté と同じく「跳ばす・飛び跳ねさせる」という動作に由来する。英語の sautéed や stir-fried に相当し、「とびとびの・不規則な」という比喩的意味も持つ多義語である。' },
  'salteador': { es: 'En el siglo XIX, los salteadores de caminos aterrorizaban a los viajeros en los pasos de montaña.', ja: '19世紀、追いはぎたちは山道の峠で旅人を恐怖に陥れていた。', trivia: 'saltear（不意打ちして襲う）＋動作主接尾辞 -ador から成り、「道端で旅人を急襲する強盗」を指す歴史的語彙。英語の highwayman や bandit に相当し、スペイン・中南米の盗賊ロマン文学（ピカレスク小説）でも頻出する語である。' },
  'salteadora': { es: 'La leyenda cuenta que una salteadora valiente robaba a los ricos para dárselo a los pobres.', ja: '伝説によれば、ある勇敢な女追いはぎが富者から奪い貧者に与えたとされている。', trivia: 'salteador の女性形で、「道端で不意打ちして旅人を襲う女性の強盗」を意味する。英語では female bandit や brigand と言うほかなく、スペイン語の文法的性の体系が職業・役割の性別を一語で示せる特徴をよく表している。' },
  'saltear': { es: 'Para hacer este plato, hay que saltear los champiñones con ajo y perejil a fuego vivo.', ja: 'この料理を作るには、マッシュルームをニンニクとパセリと一緒に強火でソテーしなければならない。', trivia: 'フランス語 sauter（跳ぶ・ソテーする）からの借用語で、「食材を高温で手早く炒める」という料理法を表す。英語の sauté も同じフランス語起源であり、また「順序を飛ばす」「不意打ちして襲う」という全く異なる意味も持つ多義動詞である。' },
  'salterio': { es: 'El monje cantaba los salmos acompañándose de un salterio medieval de cuerdas.', ja: '修道士は中世の弦楽器サルテリーを奏でながら詩篇を歌っていた。', trivia: 'ギリシャ語 psaltérion（弦を弾く楽器）に由来するラテン語 psalterium から派生した語。英語の psaltery（楽器）および psalter（詩篇集）と同語源であり、聖書の「詩篇の書」を指す宗教的意味と、中世の箱型撥弦楽器を指す音楽的意味の両方を持つ。' },
  'saltillo': { es: 'El niño dio un saltillo de alegría al ver los regalos debajo del árbol de Navidad.', ja: '少年はクリスマスツリーの下にプレゼントを見つけて喜びの小躍りをした。', trivia: 'salto（跳躍）の指小辞形 saltillo（小さな跳躍）で、日常語としては「ちょっとした跳び上がり」を表す。言語学ではナワトル語や他のメソアメリカ語言語における声門破裂音を表す記号名としても使われ、メキシコ北部の都市サルティーヨの名前の由来にもなっている。' },
  'saltimbanqui': { es: 'El saltimbanqui recorría los pueblos de feria en feria, asombrando al público con sus acrobacias.', ja: '大道芸人は祭りから祭りへと村々を渡り歩き、曲芸で観衆を驚かせていた。', trivia: 'イタリア語 saltimbanco（saltar＝跳ぶ＋in＋banco＝台・長椅子）に由来し、「台の上に跳び乗って見せ物をする人」が原義。英語の mountebank（ペテン師・大道薬売り）と同語源であり、転じて「信念のない日和見主義者」を皮肉る比喩表現としても使われる。' },
  'salto': { es: 'El atleta dio un salto impresionante para superar la valla.', ja: 'その選手はハードルを越えるために印象的なジャンプをした。', trivia: 'ラテン語 saltus（跳躍）に由来し、英語の assault（突撃）や somersault（宙返り）にも同じ語根が見られる。スペイン語では「滝」（cascada の代わりに）や「急激な上昇」など比喩的な意味でも広く使われる。' },
  'salubre': { es: 'El médico recomendó mudarse a un ambiente más salubre para mejorar su salud.', ja: '医師は健康を回復するために、より衛生的な環境への引っ越しを勧めた。', trivia: 'ラテン語 salubris（健康に良い）に由来し、salus（健康）が語根。英語の salubrious と同語源で、どちらも「爽やかで健康に良い気候・環境」を指す形式ばった表現として使われる。' },
  'salubridad': { es: 'Las autoridades trabajan para mejorar la salubridad en las zonas rurales.', ja: '当局は農村部の公衆衛生を向上させるために取り組んでいる。', trivia: 'ラテン語 salubritas（健康的な状態）から派生した名詞で、英語の salubrity に対応する。スペイン語圏では特に行政用語として「公衆衛生」の意味で頻繁に用いられる。' },
  'salud': { es: 'Brindar por la salud de todos los presentes es una tradición muy común.', ja: 'その場にいる全員の健康を祝って乾杯するのは、非常に一般的な慣習だ。', trivia: 'ラテン語 salus（健康、安全、福祉）に直接由来し、英語の salvation（救済）や safe（安全）とも同じ印欧語根 *sol-（全体・無傷）を共有する。くしゃみをした人に「¡Salud!」と言う習慣は英語の「Bless you!」に相当する。' },
  'saludable': { es: 'Seguir una dieta saludable y hacer ejercicio regularmente es fundamental para el bienestar.', ja: '健康的な食事をとり、定期的に運動することは、幸福のために不可欠だ。', trivia: 'salud（健康）＋形容詞化接尾辞 -able から成り、英語の healthy や wholesome に相当する。英語の salutary（有益な、ためになる）とも語根を共有しており、どちらも「心身に良い」という意味合いを持つ。' },
  'saludablemente': { es: 'Es importante alimentarse saludablemente desde una edad temprana.', ja: '幼い頃から健康的な食事をとることが重要だ。', trivia: 'saludable（健康的な）に副詞化接尾辞 -mente を付けた語で、英語の healthily に対応する。スペイン語の -mente 副詞は形容詞の女性形に付くというラテン語 mente（精神・心）の痕跡を残した構造を持つ。' },
  'saludador': { es: 'El saludador del pueblo era conocido por su don para calmar a los enfermos.', ja: 'その村の祈祷治癒師は病人を癒す才能で知られていた。', trivia: 'saludar（挨拶する）の動作主名詞で、中世スペインでは狂犬病などを祈りや息で癒すと信じられた「奇跡治癒師」を指す特別な意味でも使われた。英語には対応する一語がなく、faith healer などと説明される。' },
  'saludadora': { es: 'La saludadora del barrio siempre tenía una sonrisa para cada vecino.', ja: 'その地区の愛想よく挨拶して回る女性は、近所の全員に笑顔を向けていた。', trivia: 'saludador の女性形で、スペイン語では職業・役割を表す名詞に -a を付けて女性形を作る規則に従う。英語では greeter などに相当するが、性別を明示するこうした形態論はスペイン語の名詞性（género）体系の特徴だ。' },
  'saludar': { es: 'Cuando llegué a la oficina, saludé a mis compañeros con un apretón de manos.', ja: 'オフィスに着いたとき、私は同僚たちと握手で挨拶した。', trivia: 'ラテン語 salutare（健康を祈る、挨拶する）に由来し、英語の salute と同語源。英語の salute は軍の敬礼を指すことが多いが、スペイン語の saludar はより日常的な挨拶全般に使われる点が異なる。' },
  'saludo': { es: 'Al final del correo electrónico, añadió un cordial saludo dirigido a toda la empresa.', ja: 'メールの末尾に、彼は会社全体に向けた丁寧な挨拶の言葉を添えた。', trivia: 'saludar の名詞形で、ラテン語 salutatio（挨拶）と同じ語根を持つ。英語のビジネスメールで使う「Kind regards」や「Best wishes」に当たる表現として、スペイン語では「Un cordial saludo」や「Saludos cordiales」が定番だ。' },
  'salumbre': { es: 'El antiguo texto describía la salumbre de la vida del marinero como algo inevitable.', ja: '古い文書は、船乗りの生活の苦難を避けられないものとして描いていた。', trivia: 'ラテン語 sal（塩）と umbra（影）または amarus（苦い）を語源とする説があり、「塩気＝海・苦難」という比喩的連想を持つ古語。現代スペイン語ではほとんど使われず、英語にも直接対応する語はない。' },
  'salutación': { es: 'El discurso comenzó con una breve salutación al público asistente.', ja: 'スピーチは出席した聴衆への簡潔な挨拶の言葉で始まった。', trivia: 'ラテン語 salutatio（挨拶、表敬訪問）に直接由来し、英語の salutation と同語源。英語のメールや手紙で冒頭の「Dear Mr. Smith」のような書き出しを「salutation」と呼ぶのと同様に、スペイン語でも公式文書の書き出しに使われる改まった表現だ。' },
  'salutífera': { es: 'El médico destacó las propiedades salutíferas del agua de manantial de esa región.', ja: '医師はその地域の湧き水の健康に良い特性を強調した。', trivia: 'ラテン語 salus（健康）＋ ferre（運ぶ・もたらす）から成る合成語で、「健康をもたらす」という意味。英語の salutary（ためになる、有益な）と語根を共有し、やや文語的・詩的なニュアンスを持つ形容詞だ。' },
  'salutífero': { es: 'El clima salutífero de las montañas atraía a muchos enfermos en busca de recuperación.', ja: '山岳地帯の健康に良い気候は、回復を求める多くの病人を引き付けた。', trivia: 'salutífera の男性形で、ラテン語 salutifer（健康をもたらす）に直接由来する。19世紀ヨーロッパでは山岳地帯や温泉地の空気を「salutífero」と称してサナトリウムが建設されたが、英語の salubrious とほぼ同義だ。' },
  'salva': { es: 'Al llegar el presidente, los soldados dispararon una salva de veintiún cañonazos.', ja: '大統領が到着すると、兵士たちは21発の礼砲を発射した。', trivia: 'ラテン語 salva（安全の保証）に由来し、中世では「安全であることを証明するための試食（毒見）」を意味した。英語の salvo（一斉射撃、喝采）と同語源で、どちらも「一斉に」という意味合いを持つ。' },
  'salvable': { es: 'Aunque el proyecto tenía muchos problemas, el equipo creía que la situación era salvable.', ja: 'プロジェクトには多くの問題があったが、チームは状況を挽回できると信じていた。', trivia: 'salvar（救う）＋形容詞化接尾辞 -able から成り、英語の salvageable に対応する。英語の salvage（引き揚げる、回収する）はノルマン・フランス語経由でラテン語 salvare（救う）に由来し、スペイン語の salvar と同じ語根を持つ。' },
  'salvación': { es: 'La llegada del equipo de rescate fue la salvación de los mineros atrapados.', ja: '救助隊の到着は、閉じ込められた鉱山作業員たちの救いとなった。', trivia: 'ラテン語 salvatio（救済）に由来し、英語の salvation と同語源。キリスト教神学における「魂の救済」という意味で中世から使われ続けており、英語の Salvation Army（救世軍）の salvation もこの語と全く同じ語根だ。' },
  'salvachías': { es: 'El marinero aseguró el cabo con una salvachías para evitar que se deslizara.', ja: '船乗りはロープが滑らないよう、サルバチアで固定した。', trivia: '船舶用語で、salvar（守る・防ぐ）と chía（索具の一種）が組み合わさった合成語とされる。英語では stopper や deck stopper に相当し、甲板上でロープの動きを止めるために使われる専門的な索具を指す。' },
  'salvadera': { es: 'En el escritorio del notario había una antigua salvadera de plata junto a los documentos.', ja: '公証人の机には、書類の傍に古い銀製の砂振り器が置いてあった。', trivia: 'salvar（保護する・乾かす）から派生した歴史的な道具名で、インクを速乾させる砂を入れる容器を指す。英語では sandbox や pounce box と呼ばれ、吸取り紙（blotting paper）が普及する前の17〜18世紀のオフィスには欠かせない文房具だった。' },
  'salvado': { es: 'El pan integral tiene un alto contenido de salvado, lo que lo hace más nutritivo.', ja: '全粒粉パンはふすまを多く含んでいるため、より栄養価が高い。', trivia: 'ラテン語 salvatus（救われた）の過去分詞だが、「ふすま（小麦の外皮）」という名詞としても独立して使われる。英語の bran（ふすま）はゲルマン語由来で語源が異なるが、「saved（残された）穀物の皮」という発想から salvado の名詞用法が生まれたとされる。' },
  'salvador': { es: 'El bombero fue considerado el salvador de la familia al rescatarlos del incendio.', ja: 'その消防士は火災から家族を救い出し、救済者とみなされた。', trivia: 'ラテン語 salvator（救済者）に由来し、英語の savior（または saviour）と同語源。キリスト教の伝播とともにスペイン語圏に広まり、El Salvador（エルサルバドル）という国名も「救世主（キリスト）の国」という意味を持つ。' },
  'salvadora': { es: 'La enfermera fue la auténtica salvadora del paciente durante la crisis médica.', ja: 'その看護師は医療危機の間、患者にとって真の救済者だった。', trivia: 'salvador の女性形で、ラテン語 salvatrix（女性の救済者）に相当する。英語では savior に性別形がないが、スペイン語では名詞の性が文法的に区別されるため、女性の救済者を指すときは salvadora が自然に使われる。' },
  'salvaguarda': { es: 'El acuerdo internacional incluye salvaguardas para proteger los derechos humanos.', ja: 'その国際協定には、人権を守るための保護措置が含まれている。', trivia: 'salvar（守る）＋ guardar（守る）という二重の「守る」が組み合わさった複合語で、英語の safeguard と同じ構造（safe＋guard）を持つ。貿易分野では「セーフガード条項（緊急輸入制限）」という国際経済用語としても頻繁に使われる。' },
  'salvaguardar': { es: 'El gobierno tiene la obligación de salvaguardar los intereses de todos los ciudadanos.', ja: '政府はすべての市民の利益を守る義務がある。', trivia: 'salvaguarda（保護）の動詞形で、英語の safeguard（動詞）と完全に対応する。国際法・外交・IT セキュリティの文脈で「権利・データ・安全を死守する」という意味で使われ、proteger よりも公式・法律的なニュアンスが強い。' },
  'salvajada': { es: 'Quemar ese bosque fue una salvajada que condenó toda la comunidad.', ja: 'あの森を焼いたことは、地域全体が非難した野蛮な暴挙だった。', trivia: 'ラテン語 silva（森・野）を語源とする salvaje に派生し、-ada という行為・結果を表す接尾辞が付いた名詞。英語の atrocity や outrage に近い意味を持ち、口語では「とんでもない量」という誇張的な意味でも使われる。' },
  'salvaje': { es: 'El leopardo es un animal salvaje que caza en solitario por la noche.', ja: 'ヒョウは夜に単独で狩りをする野生動物だ。', trivia: 'ラテン語 silvaticus（森に属する）が語源で、英語の savage や sylvan と同じ語根 silva（森）に由来する。中世には「文明化されていない者」という否定的な意味で使われ、現代では「野生の」という中立的な意味でも広く用いられる。' },
  'salvajemente': { es: 'El equipo local ganó salvajemente al visitante en los últimos minutos del partido.', ja: '地元チームは試合終了間際に相手チームを圧倒的に打ち負かした。', trivia: '形容詞 salvaje に副詞を作る接尾辞 -mente が付いた語で、英語の wildly や savagely に対応する。口語では「猛烈に・すさまじく」という強調の意味でも使われ、スペイン語の日常会話で誇張表現によく登場する。' },
  'salvajismo': { es: 'El salvajismo de los combates dejó marcas profundas en todos los sobrevivientes.', ja: '戦闘の野蛮さはすべての生存者に深い傷跡を残した。', trivia: 'salvaje に抽象名詞を作る接尾辞 -ismo が付いた語で、英語の savagery に対応する。19世紀の人類学・社会学では「文明化以前の状態」を指す学術的な概念として使われた歴史があるが、現代では差別的なニュアンスから批判的に扱われる語でもある。' },
  'salvamento': { es: 'El equipo de salvamento llegó al lugar del accidente en menos de diez minutos.', ja: '救助チームは10分以内に事故現場に到着した。', trivia: '動詞 salvar（救う）に行為・結果を表す接尾辞 -mento が付いた名詞。英語の salvage はフランス語経由でラテン語 salvare（救う）に由来し、スペイン語の salvamento と同じ語源を共有している。海難救助や遭難時の救出活動を指す正式な語として使われる。' },
  'salvante': { es: 'Todos estuvieron de acuerdo, salvante el director, que prefirió abstanerse.', ja: '棄権を好んだ所長を除き、全員が賛成した。', trivia: '動詞 salvar の現在分詞形に由来する前置詞で、「～を除いて」という意味では salvo と同義。法律文書や公式な書き言葉に多く見られ、英語の saving（法律用語で「～を除き」）に対応する古風な用法でもある。' },
  'salvapantallas': { es: 'He configurado un salvapantallas con fotos de mis vacaciones en la computadora.', ja: 'パソコンに休暇の写真を使ったスクリーンセーバーを設定した。', trivia: 'salvar（保護する）と pantalla（画面）を合成した複合名詞で、英語の screensaver を直訳した造語。コンピューター技術の普及とともに生まれた現代スペイン語の例で、複数形も同形（los salvapantallas）という複合名詞特有のルールに従う。' },
  'salvapartidos': { es: 'El delantero marcó el salvapartidos en el minuto noventa y dos.', ja: 'フォワードは92分に試合を救うゴールを決めた。', trivia: 'salvar（救う）と partido（試合）を合成したスポーツ用語で、英語の game-saver や match-winner に相当する。スペイン語では動詞の原形＋名詞複数形という構造の複合名詞が多く作られ、salvavidas や salvoconducto と同じパターンに属する。' },
  'salvapersonas': { es: 'El salvapersonas instalado en la fábrica alertó a tiempo cuando el obrero cayó.', ja: '工場に設置された救命装置は、作業員が転倒したときに適時に警報を発した。', trivia: 'salvar（救う）と personas（人々）を組み合わせた複合名詞で、安全装置や人命救助器具全般を指す。英語の life-saving device に対応し、技術・安全管理の分野で使われる比較的専門性の高い語彙。複数形も salvapersonas と同形。' },
  'salvapisas': { es: 'El ingeniero revisó el estado del salvapisas antes de iniciar las operaciones en la pista.', ja: 'エンジニアは滑走路での作業を開始する前に保護設備の状態を確認した。', trivia: 'salvar（保護する）と pista（滑走路・トラック）を組み合わせた専門用語で、航空・土木分野の特殊インフラに関する語。英語では runway protection equipment などと表現される。日常会話ではほとんど使われない技術用語の一例。' },
  'salvar': { es: 'Los bomberos lograron salvar a toda la familia del incendio sin sufrir ninguna baja.', ja: '消防士たちは一人の犠牲者も出すことなく、家族全員を火事から救い出すことに成功した。', trivia: 'ラテン語 salvare（安全にする・救う）に由来し、英語の save と全く同じ語源を持つ。コンピューター用語で「データを保存する」という意味でも使われるようになったのは20世紀後半で、英語の save をそのままスペイン語の動詞活用に取り込んだ意味拡張の好例。' },
  'salvarratas': { es: 'El capitán ordenó instalar salvarratas en todos los cabos de amarre para evitar infestaciones.', ja: '船長はネズミの侵入を防ぐため、すべての係留索に防鼠板を取り付けるよう命じた。', trivia: 'salvar（防ぐ）と ratas（ネズミ）を組み合わせた船舶用語で、英語の rat guard に対応する。係留索を伝ってネズミが船に侵入するのを防ぐ円盤状の金具を指し、かつての長距離航海では防疫上の重要な設備だった。' },
  'salvavidas': { es: 'El guardacostas lanzó un salvavidas al marinero que había caído al agua.', ja: '海上保安官は海に転落した船員に救命浮き輪を投げた。', trivia: 'salvar（救う）と vidas（命、vida の複数形）を組み合わせた複合名詞。英語の lifesaver や life jacket と同様の合成語で、物（ライフジャケット・浮き輪）と人（ライフセーバー）の両方を指す。比喩的には「窮地を救うもの・人」という意味でも広く使われる。' },
  '¡salve!': { es: 'Al entrar el rey, la guardia gritó «¡salve!» en señal de respeto.', ja: '国王が入場すると、衛兵は敬意を表して「万歳！」と叫んだ。', trivia: 'ラテン語の命令形 salve（健やかであれ・ごきげんよう）に由来し、古代ローマの挨拶として使われた。英語の salute や salvation と同語源で、カトリックの祈祷文「サルベ・レジーナ（Salve Regina）」はこの語で始まる聖母への讃歌として現在も歌われる。' },
  'salvoconducto': { es: 'El periodista obtuvo un salvoconducto para entrar en la zona de conflicto.', ja: '記者は紛争地帯に入るための通行許可証を取得した。', trivia: 'ラテン語 salvus conductus（安全に導かれた）に由来する複合名詞で、中世ヨーロッパで敵地を安全に通行するために発行された公式文書を指す。英語の safe-conduct も同じラテン語から来ており、外交・軍事の文脈で今も使われる歴史的な語。' },
  'salvo': { es: 'Todo el equipo aprobó la propuesta, salvo uno que pidió más tiempo para decidir.', ja: 'もっと時間が必要と求めた一人を除き、チーム全員が提案を承認した。', trivia: 'ラテン語 salvus（無事な・安全な）に由来し、英語の safe と同語源。前置詞「～を除いて」としての用法は中世ラテン語の「salvo eo（それを安全に除いて）」という法律表現が起源とされ、英語の save（古語で「～を除いて」）と全く並行した意味の発展を遂げた語。' },
  'salvedad': { es: 'Aceptó el contrato con la salvedad de que tendría derecho a revisar las condiciones cada año.', ja: '毎年条件を見直す権利を持つという留保付きで、彼は契約を受け入れた。', trivia: 'ラテン語 salvus（安全な）に派生した salvedad は、法律・外交の文脈で「例外条項・留保事項」を表す。英語の reservation や qualification に対応し、契約書や議会での採決など正式な場面で「ただし～は除く」と条件を付け加えるときに多用される語。' },
  'salvia': { es: 'La salvia se usa en la cocina mediterránea para aromatizar carnes y salsas.', ja: 'セージは地中海料理で肉料理やソースに香りをつけるために使われる。', trivia: 'ラテン語 salvia（治癒する草）に由来し、動詞 salvare（救う・治す）と同語源。英語の sage（ハーブのセージ）は古フランス語を経由した同じラテン語からの借用語で、古代・中世ヨーロッパでは万能薬として珍重された薬草だった。' },
  'samaria': { es: 'La región de Samaria fue escenario de importantes eventos en la historia bíblica.', ja: 'サマリア地方は聖書の歴史における重要な出来事の舞台となった。', trivia: '古代ヘブライ語の Shomron（見張り台の意）に由来する地名サマリアから派生した形容詞・名詞。英語でも Samaria / Samaritan として使われ、「善きサマリア人」の寓話（ルカ10章）を通じて世界的に知られる名称となった。' },
  'samaritana': { es: 'Actuó como una auténtica samaritana al ayudar al desconocido herido en la calle.', ja: '彼女は路上で傷ついた見知らぬ人を助け、本物の善きサマリア人のように振る舞った。', trivia: '聖書の「善きサマリア人」の寓話から転じて、見返りを求めずに他者を助ける人を指す言葉として定着した。英語の Good Samaritan も同じ比喩的用法を持ち、多くの国で「善意の第三者を法的に保護する法律」を Good Samaritan Law と呼ぶ。' },
  'samaritano': { es: 'Fue un verdadero samaritano: recogió al anciano caído y lo llevó al hospital.', ja: '彼は本物の善きサマリア人だった。転倒した老人を拾い上げ、病院まで連れて行った。', trivia: 'samaritana の男性形で、聖書のルカ10:25-37に登場する「善きサマリア人」の寓話に由来する比喩的表現。英語でも Samaritan が「慈悲深い人」を意味し、イギリスの自殺防止電話相談機関「Samaritans」の名称にも使われている。' },
  'samario': { es: 'El samario se utiliza en la fabricación de imanes permanentes de alta potencia.', ja: 'サマリウムは高性能永久磁石の製造に使用される。', trivia: '1879年にフランスの化学者ポール・エミール・ルコック・ド・ボワボードランが発見し、鉱物 samarskita（ロシアの鉱山技師 V.E. Samarsky-Bykhovets に因む）にちなんで命名された元素。英語でも samarium と呼ばれ、人名に由来する元素名の最初の例の一つとされる。' },
  'samba': { es: 'La samba es el ritmo más reconocido del carnaval de Río de Janeiro en todo el mundo.', ja: 'サンバはリオデジャネイロのカーニバルで世界中に最も知られるリズムだ。', trivia: 'アフリカ・バンツー系言語の semba（へその突き出し・腰の動き）に由来するとされ、アフリカからブラジルに連れてこられた奴隷の文化から生まれた音楽・ダンス。英語でも samba としてそのまま使われ、19世紀末にブラジルで発展し20世紀初頭にリオで都市的な様式に洗練された。' },
  'sambenito': { es: 'Desde ese escándalo, lleva el sambenito de deshonesto aunque ya fue absuelto.', ja: 'あのスキャンダル以来、すでに無罪になったにもかかわらず、彼は不正直というレッテルを貼られ続けている。', trivia: '中世スペインの異端審問（Inquisición）で罪人に着せた黄色い贖罪衣に由来する語で、San Benito（聖ベネディクト）の習慣服に似ていたことからその名が付いた。英語でも sambenito として借用されることがあり、「一度貼られたら剥がれない不名誉の印」という強烈な比喩として現代でも使われる。' },
  'sambo': { es: 'En algunos documentos históricos coloniales, el término sambo se usaba para clasificar a los descendientes de africanos e indígenas.', ja: '一部の植民地時代の歴史文書では、samboという用語はアフリカ人と先住民の子孫を分類するために使われていた。', trivia: 'スペイン語圏ラテンアメリカの植民地時代に使われた人種分類語で、アフリカ系と先住民の混血を指した。語源については諸説あり、アフリカの言語に由来するとも、スペイン語の zambo（内股）に由来するとも言われる。英語の sambo は現在では侮辱語とされており、歴史的文脈以外での使用は避けられる。' },
  'samio': { es: 'El filósofo Pitágoras era samio, nacido en la isla de Samos.', ja: '哲学者ピタゴラスはサモス島出身のサモス人だった。', trivia: 'ラテン語 Samius（サモス島の）に由来し、古代ギリシャの島サモスを指す形容詞・名詞。英語でも Samian という形が使われ、「Samian ware（サモス式陶器）」などの表現が残っている。' },
  'samovar': { es: 'En la mesa rusa tradicional no falta un samovar humeante para preparar el té.', ja: 'ロシアの伝統的な食卓には、お茶を淹れるための湯気の立つサモワールが欠かせない。', trivia: 'ロシア語の «самовар»（samovar）から直接借用された語で、「само（自ら）+ варить（煮る）」を意味する。英語でも samovar としてそのまま使われ、ロシア文化を象徴する器具の名として世界に広まった。' },
  'samurái': { es: 'Las películas de Akira Kurosawa presentan al samurái como un guerrero con un código de honor estricto.', ja: '黒澤明の映画は、侍を厳格な名誉の掟を持つ戦士として描いている。', trivia: '日本語の「侍（さむらい）」がポルトガル語を経由してスペイン語に入ったとされる。英語の samurai と同形で、日本の武士道文化を指す国際的な語として世界中で通用する。' },
  'san': { es: 'San Francisco de Asís es conocido como el patrón de los animales y del medio ambiente.', ja: 'アッシジの聖フランシスコは動物と自然環境の守護聖人として知られている。', trivia: 'ラテン語 Sanctus（聖なる）を起源とし、Santo の語末音節が脱落した短縮形。英語の Saint（St.）に対応し、男性の聖人名の前にのみ置かれ、「Santo Tomás」など t・d で始まる名前の前では短縮されない。' },
  'sanable': { es: 'El médico explicó que la herida era completamente sanable con el tratamiento adecuado.', ja: '医師は、適切な治療を行えば傷は完全に治癒可能だと説明した。', trivia: 'ラテン語の sanabilis（治癒できる）に由来し、動詞 sanar（治る・治す）に形容詞化接尾辞 -able が付いた形。英語の curable や healable に相当し、医療文脈だけでなく「修復可能な関係」など比喩的にも使われる。' },
  'sanación': { es: 'Después de años de terapia, experimentó una profunda sanación emocional.', ja: '何年もの療法の後、彼女は深い感情的な癒しを経験した。', trivia: 'ラテン語 sanatio（治癒）に由来し、動詞 sanar から派生した名詞。英語の healing や cure に対応するが、スペイン語の sanación は近年、身体的な治癒だけでなくスピリチュアルや心理的な「ヒーリング」の意味でも広く使われるようになっている。' },
  'sanalotodo': { es: 'El político prometió una nueva ley como sanalotodo para los problemas económicos del país.', ja: 'その政治家は、国の経済問題に対する特効薬として新しい法律を約束した。', trivia: '「sana（治す）+ lo（それを）+ todo（すべて）」が合成した複合語で、直訳すると「すべてを治すもの」。英語の cure-all や panacea に相当し、スペイン語では万能薬への過信を皮肉る文脈でよく用いられる。' },
  'sanamente': { es: 'Es importante competir sanamente en el deporte, respetando siempre las reglas y al rival.', ja: 'スポーツでは常にルールと相手を尊重しながら、健全に競い合うことが大切だ。', trivia: 'ラテン語 sanus（健康な、健全な）から派生した形容詞 sano に副詞化接尾辞 -mente が付いた形。英語の healthily や wholesomely に対応し、身体的な健康だけでなく、公明正大・誠実さを表す道徳的な意味でも使われる。' },
  'sanandresana': { es: 'La comunidad sanandresana mantiene viva su cultura caribeña y el idioma creole.', ja: 'サン・アンドレス島の人々はカリブ海の文化とクレオール語を生き続けさせている。', trivia: 'コロンビア領のカリブ海に浮かぶサン・アンドレス島（Isla de San Andrés）の形容詞・名詞形で、女性形が sanandresana、男性形が sanandresano。この島はかつてイギリス植民地だったため、住民は英語系クレオール語を話す独自の文化を持つ。' },
  'sanandresano': { es: 'El acento sanandresano refleja la mezcla entre el español colombiano y el inglés caribeño.', ja: 'サン・アンドレス島出身者のアクセントは、コロンビアのスペイン語とカリブ海英語の混合を反映している。', trivia: 'コロンビア本土から約750kmも離れたカリブ海に位置するサン・アンドレス島の住民を指す男性形形容詞・名詞。英語と深い歴史的つながりを持つため、島の公用語は実質上スペイン語と英語系クレオール語（Islander Creole）の両方である。' },
  'sanar': { es: 'Con tiempo y apoyo emocional, las heridas del corazón también pueden sanar.', ja: '時間と感情的なサポートがあれば、心の傷も癒えることができる。', trivia: 'ラテン語 sanare（健康にする）に由来し、英語の heal や cure と語源を共有する印欧語族の系譜を引く。自動詞（傷が治る）・他動詞（傷を治す）・再帰動詞（sanarse：自分が回復する）の三つの用法を持つ多機能な動詞。' },
  'sanativa': { es: 'Las propiedades sanativas de la miel han sido reconocidas desde la antigüedad.', ja: '蜂蜜の治癒効果は古来より認められてきた。', trivia: 'ラテン語 sanativus（治癒的な）に由来し、sanar（治す）と同語根。英語では curative や healing として表現されるが、スペイン語の sanativo/a は自然療法や伝統医学の文脈で特によく使われる形容詞である。' },
  'sanativo': { es: 'El médico destacó el efecto sanativo del descanso y la buena alimentación.', ja: '医師は、休息と良い食事の治癒効果を強調した。', trivia: 'ラテン語 sanativus（治癒的な）を語源とし、sanar と同じ語根 san-（健康）を持つ形容詞の男性形。英語 curative に相当し、薬や治療法が「治癒をもたらす性質を持つ」ことを表す科学的・医学的な語感がある。' },
  'sanatorio': { es: 'El sanatorio privado contaba con las últimas tecnologías para el diagnóstico y tratamiento.', ja: 'その私立療養所は診断と治療のための最新技術を備えていた。', trivia: 'ラテン語 sanare（治す）から派生した sanatorium がスペイン語に入った語で、英語の sanatorium と同形・同語源。19世紀には結核患者の療養施設を指したが、現代のスペイン語圏では「私立病院・専門クリニック」の意味で広く使われる。' },
  'sancochar': { es: 'Antes de freír las papas, la abuela las sancochaba para que quedaran más suaves por dentro.', ja: 'じゃがいもを揚げる前に、祖母は中がより柔らかくなるよう下茹でしていた。', trivia: 'スペイン語の sancochar は「半分（semi-）+ 煮る（cocer）」の合成に由来するとされ、英語の parboil（par- は「部分的に」の意）と発想が非常に似ている。中南米料理において下ごしらえの基本技法として欠かせない動詞である。' },
  'sancocho': { es: 'El sancocho colombiano, preparado con pollo, yuca y plátano, es el plato perfecto para compartir en familia.', ja: '鶏肉、キャッサバ、バナナで作るコロンビアのサンコーチョは、家族で囲む完璧な料理だ。', trivia: '動詞 sancochar（下茹でする）から派生した名詞で、コロンビア・ベネズエラ・ドミニカ共和国など中南米各地に独自バリエーションがある国民食。各国で食材や味付けが異なり、日本のカレーライスのように地域のアイデンティティと深く結びついている。' },
  'sangradura': { es: 'La enfermera limpió la sangradura del codo después de la extracción de sangre.', ja: '看護師は採血の後、肘のくぼみを拭き取った。', trivia: '動詞 sangrar（出血させる・瀉血する）から派生した名詞で、解剖学的には「肘窩（cubital fossa）」を指す。歴史的に静脈血を取り出す瀉血（bloodletting）が行われた部位であることから、この名称がついた。英語の cubital fossa に相当するが、語源は血液（sangre）に直結している。' },
  'sangrar': { es: 'La herida seguía sangrando a pesar de la presión que ejercía sobre ella.', ja: '傷は圧迫を加えてもなお出血し続けていた。', trivia: 'ラテン語 sanguinare（血を流す）に由来し、英語の bleed と意味は同じだが語根が異なる。英語 bleed は古英語 blēdan から来ており、ゲルマン系。一方 sangrar はラテン系で、blood（英）と sangre（西）の語源的距離を示す好例。印刷用語「インデント」の意味も持つ珍しい動詞。' },
  'sangraza': { es: 'La sangraza que brotaba de la herida infectada indicaba que necesitaba atención médica urgente.', ja: '感染した傷口から滲み出る濁った血は、緊急の医療処置が必要であることを示していた。', trivia: 'sangre（血）に増大・粗野さを表す接尾辞 -aza が付いた拡大語（aumentativo）で、「汚い血・濁った血」を意味する。スペイン語では同じ接尾辞が「大きい・ひどい」という含意を加え、英語にはこうした増大形を造る語形変化の仕組みがない点でスペイン語らしい表現形式。' },
  'sangredo': { es: 'Los textos medievales mencionan el sangredo como práctica médica habitual para equilibrar los humores.', ja: '中世の文書では、体液のバランスを整えるための一般的な医療行為として瀉血が言及されている。', trivia: '古スペイン語で「出血・瀉血」を意味した歴史的・古語的な語で、現代では sangría に取って代わられた。英語の bloodletting や bleeding に相当し、四体液説（humorism）に基づく中世ヨーロッパ医学を語る際に用いられる考古学的な語彙。' },
  'sangría': { es: 'En la terraza del bar pedimos una jarra de sangría bien fría para combatir el calor del verano.', ja: 'バルのテラスで、夏の暑さをしのぐためによく冷えたサングリアのピッチャーを注文した。', trivia: 'sangre（血）から派生した語で、ワインの深紅色が「血の色」を連想させることからこの名がついた。英語でも sangria としてそのまま借用されており、スペイン語起源の飲み物名として世界で最も広く知られた語の一つ。印刷・タイポグラフィ用語の「インデント（字下げ）」という全く異なる意味も持つ多義語。' },
  'sangrienta': { es: 'La batalla fue sangrienta y dejó miles de víctimas en ambos bandos.', ja: 'その戦闘は血なまぐさく、双方に数千人の犠牲者を出した。', trivia: 'sangre（血）に形容詞化接尾辞 -iento/a が付いた語で、「血にまみれた」を意味する。英語の bloody や gory に相当し、bloody はゲルマン系、gory はノルマン系と語源が異なる。スペイン語では -iento が「充満した・その性質を帯びた」という含意を持つ生産的な接尾辞として機能する。' },
  'sangriento': { es: 'El conflicto sangriento duró décadas y marcó profundamente la historia del país.', ja: 'その血みどろの紛争は数十年間続き、その国の歴史に深い傷跡を残した。', trivia: 'sangre（血）＋形容詞接尾辞 -iento の男性形。英語の bloody（古英語由来）とは異なり、ラテン語の sanguis（血）を語根に持つロマンス語系の表現。英語で「blood（血）」と「sangria（サングリア）」が全く別語源に見えるのは、前者がゲルマン系、後者がラテン系であるためで、sangriento はそのラテン系の系譜を示す。' },
  'sanguaza': { es: 'La sanguaza que goteaba de la carne mal conservada era señal de que no era apta para el consumo.', ja: '保存状態の悪い肉から滲み出る血混じりの液体は、食用に適さないサインだった。', trivia: 'sangre（血）に接尾辞 -aza が付いた語で、「血や体液が混じった汚濁した液体」を指す。英語では serum（漿液）や bloody discharge などと訳されるが一語で対応する語はなく、スペイン語の語彙の豊かさを示す例。植物の文脈ではサトウキビなどの搾り汁を指す地域用法もある。' },
  'sarguera': { es: 'La sarguera se usaba antiguamente para extraer sangre de los pacientes como tratamiento médico.', ja: 'サルゲラはかつて治療として患者から血液を採取するために使われていた。', trivia: 'ラテン語 sanguis（血）に由来し、瀉血（しゃけつ）用の器具や灌漑用水路の分水口を指す言葉として地域によって意味が広がった。英語には直接対応する語がなく、医療史の文脈では bloodletting instrument と説明される。' },
  'sangüeñal': { es: 'El sangüeñal florece a principios de primavera en los bosques húmedos de la región.', ja: 'サンゲニャルは地域の湿った森で春の初めに花を咲かせる。', trivia: 'スペイン語 sangre（血）と関連し、樹皮や実が血のような赤みを帯びることからこの名がついたとされる。英語の dogwood（ミズキ）に相当し、コルヌス属（Cornus）の植物を指す方言的な呼び名である。' },
  'sanguificación': { es: 'La sanguificación es un proceso vital que ocurre principalmente en la médula ósea de los huesos largos.', ja: '造血作用は主に長骨の骨髄で起こる生命維持に不可欠なプロセスだ。', trivia: 'ラテン語 sanguis（血）＋ facere（作る）から成る医学術語で、現代では hematopoyesis（英語 hematopoiesis）という語に置き換えられることが多い。英語にも sanguification という対応語が存在するが、現在ではほとんど使われない古語扱いである。' },
  'sanguificar': { es: 'El hierro en la dieta ayuda a sanguificar correctamente los nutrientes absorbidos por el intestino.', ja: '食事中の鉄分は腸で吸収された栄養素を適切に血液に変えるのを助ける。', trivia: 'ラテン語 sanguis（血）と facere（作る・変える）を組み合わせた学術的動詞で、英語の sanguify に直接対応する。現代医学では hematopoiesis（造血）という語が使われるため、この語はやや古風な響きを持つ。' },
  'sanguijuela': { es: 'Mi jefe es una sanguijuela que se aprovecha del trabajo de todos sin dar nada a cambio.', ja: '私の上司は何も返さずに皆の仕事を搾取する寄生虫だ。', trivia: 'ラテン語 sanguisuga（血を吸うもの、sanguis＋sugere）に由来し、医療用ヒルとして古代から現代医療まで使われてきた。英語の leech とほぼ同じ比喩的用法（搾取者・強欲な人）を持つ点が興味深い。' },
  'sanguinaria': { es: 'La sanguinaria es una planta cuya raíz produce un jugo rojizo que los nativos americanos usaban como tinte.', ja: 'サンギナリアは根から赤い汁を出す植物で、アメリカ先住民が染料として使っていた。', trivia: 'ラテン語 sanguis（血）に由来し、根を切ると血のような赤い液体が出ることから血根草とも呼ばれる。英語でも bloodroot あるいは sanguinaria として知られ、北米原産のケシ科植物である。' },
  'sanguinariamente': { es: 'El tirano gobernó sanguinariamente durante décadas, sin mostrar ninguna compasión por su pueblo.', ja: 'その独裁者は数十年にわたって民衆に一切の慈悲を示すことなく残虐に支配した。', trivia: '形容詞 sanguinario（血に飢えた）にスペイン語の副詞語尾 -mente を付けた派生語で、英語の bloodthirstily や ruthlessly に相当する。-mente 副詞の中でも特に凄惨なニュアンスを持つ部類に属する。' },
  'sanguinario': { es: 'El sanguinario dictador ordenó la ejecución de miles de civiles inocentes durante el régimen.', ja: 'その残虐な独裁者は政権期間中に何千人もの無実の市民の処刑を命じた。', trivia: 'ラテン語 sanguinarius（血に関係する、残酷な）から来ており、英語の bloodthirsty や murderous と対応する。同じ語根から英語の sanguine（楽観的・血色の良い）も派生しており、同じ「血」の語源が正反対のニュアンスを持つことが面白い。' },
  'sanguínea': { es: 'La presión sanguínea debe medirse con regularidad para detectar problemas cardiovasculares a tiempo.', ja: '心臓血管系の問題を早期に発見するために血圧は定期的に測定されなければならない。', trivia: 'ラテン語 sanguineus（血の、血に関する）の女性形で、英語の sanguine や sanguineous に対応する。医学用語として血液に関連する語句（presión sanguínea＝血圧、grupo sanguíneo＝血液型）によく用いられる。' },
  'sanguinolento': { es: 'Los médicos examinaron el vendaje sanguinolento y decidieron llevar al herido inmediatamente al quirófano.', ja: '医師たちは血まみれの包帯を調べ、負傷者をすぐに手術室に運ぶことを決めた。', trivia: 'ラテン語 sanguinolentus（血に満ちた）から来ており、英語の sanguinolent や bloody に相当する。文学や医学報告書で好まれる語で、単なる sangriento より学術的・古典的な響きを持つ。' },
  'sanguíneo': { es: 'El médico pidió un análisis sanguíneo completo para diagnosticar la causa de la fatiga crónica del paciente.', ja: '医師は患者の慢性的な疲労の原因を診断するために完全な血液検査を指示した。', trivia: 'ラテン語 sanguineus（血の）に由来し、英語の sanguine と同語源。中世ヨーロッパの四体液説では「多血質（sanguíneo）」は社交的・楽観的な気質を指しており、英語で sanguine が「楽観的」を意味するのもこの伝統による。' },
  'sanguinoso': { es: 'El campo de batalla presentaba un aspecto sanguinoso que heló el corazón de los soldados supervivientes.', ja: '戦場は生き残った兵士たちの心を凍り付かせるほど血なまぐさい光景を呈していた。', trivia: 'ラテン語 sanguinosus から派生し、sangriento や sanguinolento とほぼ同義だが、より文学的・詩的な文体で用いられることが多い。英語には bloody や gory が対応し、やはり文脈によって使い分けられる。' },
  'sanícula': { es: 'La sanícula era muy valorada en la medicina herbal medieval por sus propiedades cicatrizantes y antiinflamatorias.', ja: 'サニキュラは傷の治癒作用と抗炎症作用から中世のハーブ医学で非常に重宝されていた。', trivia: 'ラテン語 sanare（癒す）に由来し、その薬効から命名された植物で、英語では sanicle と呼ばれる。中世ヨーロッパでは「この植物があれば外科医も要らない」とまで言われたほど万能薬として重視されていた。' },
  'sanidad': { es: 'El gobierno destinó un presupuesto récord a la sanidad pública para mejorar la atención a los ciudadanos.', ja: '政府は市民への医療ケアを改善するために公衆衛生に過去最高の予算を配分した。', trivia: 'ラテン語 sanitas（健康、正常な状態）に由来し、英語の sanity（正気）と health（健康）の両方の意味を内包している。スペインでは sanidad は主に「医療制度・保健行政」を指すのに対し、英語の sanitation は「衛生設備」に限定されることが多い。' },
  'sanie': { es: 'El médico observó que la herida comenzaba a secretar sanie, signo de una posible infección bacteriana.', ja: '医師は傷口が血膿を分泌し始めており、細菌感染の可能性があるサインだと観察した。', trivia: 'ラテン語 sanies（血膿、傷口からの分泌物）がそのままスペイン語に入った医学術語で、英語でも sanies として使われる。ギリシャ神話のイコール（神々の血）と概念的に関連付けられることもある古い医学用語である。' },
  'sanioso': { es: 'El cirujano describió la herida como saniosa y ordenó un tratamiento antibiótico de inmediato.', ja: '外科医は傷口を血膿性と診断し、ただちに抗生物質による治療を指示した。', trivia: 'ラテン語 saniosus（血膿を伴う）に由来する医学的形容詞で、英語の sanious に直接対応する。臨床医学の記述でのみ使われる専門語であり、日常会話ではほぼ用いられない。' },
  'sanisidro': { es: 'Durante el sanisidro, miles de madrileños acuden a la pradera a disfrutar de las verbenas y las rosquillas.', ja: 'サン・イシドロ祭の間、何千人ものマドリード市民が野外の宴や揚げドーナツを楽しみに草原に集まる。', trivia: 'マドリードの守護聖人イシドロ・ラブラドール（San Isidro Labrador、農夫の聖イシドロ）の名に由来し、毎年5月15日前後に開催される。ゴヤの絵画「サン・イシドロの草原」（1788年）でも描かれた伝統的な祭りで、英語圏では Madrid Fiesta として紹介されることが多い。' },
  'sanitarista': { es: 'El sanitarista diseñó un plan de vacunación masiva para controlar el brote de sarampión en la región.', ja: 'その公衆衛生専門家は地域での麻疹の発生を抑制するための集団接種計画を策定した。', trivia: 'スペイン語 sanitario（衛生の）に職業を示す接尾辞 -ista を加えた比較的新しい語で、英語の public health specialist や sanitarian に対応する。ラテンアメリカの公衆衛生分野で特によく使われる語である。' },
  'sanitario': { es: 'Los sanitarios trabajaron sin descanso durante la pandemia para atender a los pacientes más graves.', ja: '医療従事者たちはパンデミックの間、最も重症の患者たちを診るために休みなく働いた。', trivia: 'ラテン語 sanitarius（健康に関する）に由来し、英語の sanitary と同語源。スペインでは名詞として「医療従事者」を指すほか、「衛生陶器（トイレ・洗面台）」の意味でも使われる二重の用法が興味深い。' },
  'sanitización': { es: 'La sanitización de los equipos médicos es obligatoria antes de cada operación quirúrgica.', ja: '外科手術の前に医療機器の衛生化（サニタイズ）が義務付けられています。', trivia: 'ラテン語 sanitas（健康）に由来し、英語の sanitization をスペイン語化した比較的新しい語。IT分野では「データの無害化」を指すため、衛生と情報セキュリティの両方の文脈で使われる現代的な多義語です。' },
  'sanitizar': { es: 'Es fundamental sanitizar las superficies de la cocina para evitar la proliferación de bacterias.', ja: '細菌の繁殖を防ぐために、台所の表面を消毒することが基本です。', trivia: '英語の sanitize と同語源で、ラテン語 sanitas（健康）から派生。スペイン語では従来 desinfectar や higienizar が使われてきたが、特にIT・食品衛生の分野では sanitizar が定着しつつある英語借用動詞です。' },
  'sano': { es: 'Llevar una dieta sana y hacer ejercicio regularmente son los pilares de una vida larga.', ja: '健康的な食事をとり、定期的に運動することが長寿の柱です。', trivia: 'ラテン語 sanus（健全な、正気の）から直接受け継がれた語で、英語の sane（正気の）や sanitary（衛生的な）と同じ語根を持ちます。「sano y salvo」（無事に）という慣用句でも頻出します。' },
  'sanjuanada': { es: 'Durante la sanjuanada, los jóvenes saltan sobre las hogueras en la playa para celebrar el inicio del verano.', ja: 'サン・フアンの祝祭（夏至祭）の間、若者たちは夏の始まりを祝ってビーチのかがり火を飛び越えます。', trivia: '聖ヨハネ（San Juan Bautista）の祝日である6月24日の前夜祭に由来する語。スペイン各地で火を使う祭りが行われ、ガリシアの「Noite de San Xoán」などが有名で、ケルトの夏至祭の習慣と融合した民俗行事です。' },
  'sanjuanera': { es: 'La sanjuanera es una canción tradicional que se entona durante las fiestas de San Juan en algunas regiones.', ja: '「サンフアネーラ」とは、一部の地域で聖ヨハネ祭の期間中に歌われる伝統的な歌のことです。', trivia: '形容詞・名詞としてサン・フアン祭に関連するものを指し、特にスペイン北部のアストゥリアスやガリシアで聖ヨハネ祭の伝統歌やダンスを指す地域色の強い語です。英語に直接対応する語はありません。' },
  'sanjuanero': { es: 'El ambiente sanjuanero llena las calles de música y hogueras cada noche del 23 de junio.', ja: '6月23日の夜になると、聖ヨハネ祭の雰囲気が音楽とかがり火で街を満たします。', trivia: 'sanjuanera の男性形で、聖ヨハネ（San Juan）に関連する事物や人を指す形容詞・名詞。コロンビアでは「sanjuanero huilense」という民族舞踊が国民文化として知られています。' },
  'sanjuanina': { es: 'La industria vitivinícola sanjuanina es una de las más importantes de Argentina.', ja: 'サン・フアン州のワイン産業はアルゼンチンで最も重要な産業の一つです。', trivia: 'アルゼンチン中西部のサン・フアン州（Provincia de San Juan）の住民・文化を表す地域形容詞。この州はアルゼンチン第2のワイン産地として知られ、メンドーサ州と並ぶ「太陽のワイン（vinos del sol）」の産地です。' },
  'sanjuanino': { es: 'Los sanjuaninos se enorgullecen de su tradición vitícola y de sus veranos soleados.', ja: 'サン・フアン州の人々は、ブドウ栽培の伝統と日当たりの良い夏を誇りに思っています。', trivia: 'sanjuanina の男性形で、アルゼンチンのサン・フアン州出身者を指します。同州は哲学者・教育者のドミンゴ・F・サルミエントの出身地としても有名で、彼はアルゼンチンの紙幣（旧50ペソ）にも描かれていました。' },
  'sanluqueña': { es: 'La manzanilla sanluqueña es un vino fino y seco muy apreciado en toda Andalucía.', ja: 'サンルーカル産のマンサニーリャは、アンダルシア全土で高く評価されているすっきりとした辛口ワインです。', trivia: 'スペイン・アンダルシアのカディス県にあるサンルーカル・デ・バラメーダ（Sanlúcar de Barrameda）の住民・文化を指す形容詞。コロンブスやマゼランの出港地として歴史的に重要で、マンサニーリャ産地として世界的に知られています。' },
  'sanluqueño': { es: 'El pescado sanluqueño tiene fama de ser especialmente fresco gracias a su ubicación costera.', ja: 'サンルーカルの魚は、海岸沿いの立地のおかげで特に新鮮であることで有名です。', trivia: 'sanluqueña の男性形。サンルーカル・デ・バラメーダはマゼランが1519年に世界一周に出発した港町として歴史的に名高く、その住民を指すこの語は独自の文化的アイデンティティを担っています。' },
  'sanmarquina': { es: 'La comunidad sanmarquina celebra cada año el aniversario de la fundación de su universidad.', ja: 'サン・マルコス大学の関係者たちは毎年、大学創立記念日を祝います。', trivia: 'ペルーのリマにある国立サン・マルコス大学（Universidad Nacional Mayor de San Marcos）の学生・卒業生を指す語。1551年創立の同大学は「アメリカ大陸最古の大学」として知られ、英語圏でも the oldest university in the Americas と紹介されます。' },
  'sanmarquino': { es: 'Los sanmarquinos han dado grandes aportes a la literatura y la ciencia del Perú.', ja: 'サン・マルコス大学の卒業生たちは、ペルーの文学と科学に大きく貢献してきました。', trivia: 'sanmarquina の男性形。同大学はノーベル賞作家マリオ・バルガス＝リョサも一時在籍したことで知られ、ラテンアメリカの学術・文化史において象徴的な存在です。' },
  'sanmiguelense': { es: 'El turismo sanmiguelense atrae a artistas y visitantes de todo el mundo gracias a su arquitectura colonial.', ja: '植民地時代の建築のおかげで、サン・ミゲルの観光業は世界中からアーティストや観光客を引き寄せています。', trivia: 'メキシコのグアナフアト州にあるサン・ミゲル・デ・アジェンデ（San Miguel de Allende）に関係する人・文化を指す形容詞。同市は2008年にユネスコ世界文化遺産に登録され、英語圏でも San Miguel と略されて国際的な芸術の街として名を馳せています。' },
  'sannyasi': { es: 'El sannyasi viaja sin posesiones materiales, dedicando su vida entera a la búsqueda espiritual.', ja: 'サンニヤーシンは物質的な所有物を持たずに旅をし、生涯を霊的探求に捧げます。', trivia: 'サンスクリット語の sannyāsa（放棄）に由来するヒンドゥー教の概念で、英語でも sannyasi / sannyasin と表記されます。人生の四住期（āśrama）における最終段階「遁世期」の修行者を指し、すべての世俗的義務を捨てた出家者です。' },
  'sanrafaelina': { es: 'La producción agrícola sanrafaelina destaca por sus viñedos y olivares en el sur de Mendoza.', ja: 'サン・ラファエルの農業生産は、メンドーサ南部のブドウ畑とオリーブ畑で際立っています。', trivia: 'アルゼンチン・メンドーサ州南部の都市サン・ラファエル（San Rafael）の住民・文化を指す地域形容詞。同市はアルゼンチン国内でも重要なワイン産地の一つで、アンデスの雪解け水を使ったかんがい農業が発達しています。' },
  'sanrafaelino': { es: 'Los sanrafaelinos disfrutan de un paisaje de montañas y ríos que favorece el turismo de aventura.', ja: 'サン・ラファエルの人々は、アドベンチャーツーリズムに適した山と川の景観を楽しんでいます。', trivia: 'sanrafaelina の男性形。サン・ラファエルはアルゼンチンの「スポーツと自然の都市」として知られ、カヤック・ラフティング・ハイキングなど野外活動が盛んで、国内外から観光客が訪れます。' },
  'sanroqueña': { es: 'La cultura sanroqueña muestra la influencia histórica del peñón de Gibraltar en la zona del Estrecho.', ja: 'サン・ロケの文化は、ジブラルタル海峡地域におけるジブラルタルの岩山の歴史的影響を示しています。', trivia: 'スペイン・アンダルシアのカディス県にある都市サン・ロケ（San Roque）の住民・文化を指す形容詞。同市はジブラルタル近郊に位置し、18世紀にジブラルタルから避難したスペイン人が建設した歴史的背景を持ちます。' },
  'sanroqueño': { es: 'Los sanroqueños mantienen viva la memoria de la fundación de su ciudad por los refugiados de Gibraltar.', ja: 'サン・ロケの人々は、ジブラルタルからの避難民による市の創設の記憶を大切に守り続けています。', trivia: 'sanroqueña の男性形。サン・ロケはイギリス領ジブラルタルのすぐ北側に位置し、英西の文化・言語的摩擦と融合の最前線として独特のアイデンティティを持つ都市です。' },
  'sanscritista': { es: 'La sanscritista explicó cómo muchas palabras del español derivan del sánscrito a través del latín.', ja: 'そのサンスクリット学者は、スペイン語の多くの単語がラテン語を経由してサンスクリット語から派生していることを説明しました。', trivia: 'サンスクリット語（sánscrito）の研究者を指す名詞で、語尾 -ista は英語の -ist に相当するロマンス語系の接尾辞。サンスクリットとスペイン語はともに印欧語族に属し、padre（父）と英語 father が同語根であるなど多くの類縁語を持ちます。' },
  'sanscrito': { es: 'El sanscrito es una de las lenguas más antiguas del mundo y sigue siendo lengua oficial de la India.', ja: 'サンスクリット語は世界最古の言語の一つで、インドでは現在も公用語の一つとなっています。', trivia: 'サンスクリット語自身の名称 saṃskṛta（「完全に整えられた（言語）」の意）に由来します。アクセント記号ありの sánscrito が標準的な綴りで、英語の Sanskrit と同語源。印欧語族の原形を最もよく保った言語として比較言語学の基盤となっています。' },
  'sansirolé': { es: 'No seas sansirolé y presta atención a lo que te están explicando.', ja: 'ぼんやりしていないで、説明していることをちゃんと聞きなさい。', trivia: 'スペインの口語表現で、間抜けやのろまを指す俗語。語源には諸説あり、イタリア語の San Sirolè（架空の聖人名）や演劇の道化キャラクターに由来するとも言われます。英語に直接の対応語はなく、airhead や nincompoop がニュアンス的に近いです。' },
  'sansón': { es: 'Ese hombre es un verdadero sansón; levantó él solo el coche para sacar al perro atrapado.', ja: 'あの男は本物の怪力の持ち主だ。閉じ込められた犬を助けるために、一人で車を持ち上げてしまった。', trivia: '旧約聖書の英雄サムソン（Sansón / Samson）に由来する比喩的転用語。英語でも a Samson と言えば「怪力の人物」を指すことがあります。ヘブライ語 Shimshon（「太陽のような」の意）が語源で、怪力と脆弱性を併せ持つ象徴的人物です。' },
  'santa': { es: 'La iglesia está dedicada a Santa Teresa de Ávila, patrona de los escritores españoles.', ja: 'その教会はスペインの作家の守護聖人であるアビラの聖テレサに捧げられています。', trivia: 'ラテン語 sancta（神聖な）の女性形に由来し、英語の saint と同語根。スペイン語では地名にも多用され（Santa Cruz、Santa Fé など）、女性聖人名の前置称号として不可欠な語です。' },
  'santabárbara': { es: 'Un descuido en la santabárbara del buque de guerra provocó una explosión catastrófica.', ja: '軍艦の火薬庫での不注意が壊滅的な爆発を引き起こしました。', trivia: '大砲の守護聖人である聖バルバラ（Santa Bárbara）に由来する語で、英語の powder magazine に相当します。雷を司る聖人として火薬を扱う場所の守護者とされたことから、艦艇の弾薬庫を指すようになった歴史的経緯を持ちます。' },
  'santafecina': { es: 'La gastronomía santafecina combina la herencia italiana con los ingredientes del río Paraná.', ja: 'サンタ・フェの料理は、イタリアの食文化とパラナ川の食材を組み合わせています。', trivia: 'アルゼンチンのサンタ・フェ州（Provincia de Santa Fe）の住民・文化を指す地域形容詞。santafesina / santafesino というバリエーションも存在し、表記揺れが見られます。同州はアルゼンチン農業の中心地で、大豆・トウモロコシの一大産地として知られています。' },
  'santafecino': { es: 'Mi compañero de trabajo es santafecino y nos habla mucho de las tradiciones de Santa Fe.', ja: '私の同僚はサンタ・フェ出身で、サンタ・フェの伝統についてよく話してくれる。', trivia: '「Santa Fe（サンタ・フェ）」はスペイン語で「聖なる信仰」を意味し、スペイン語圏に同名の都市が複数存在する。形容詞接尾辞 -cino はラテン語 -cinus に由来し、英語の -cine（例: canine）と同語源である。' },
  'santafereña': { es: 'La cocina santafereña tiene influencias indígenas y españolas que la hacen única.', ja: 'ボゴタの料理は先住民とスペインの影響を受けており、独自の風味を持っている。', trivia: '「santafereño/a」はコロンビアの首都ボゴタの旧称「Santa Fe de Bogotá」に由来し、特に植民地時代の文化や建築様式を指す際に用いられる。英語では「Bogotano」と呼ぶことが多い。' },
  'santafereño': { es: 'El barrio La Candelaria conserva el ambiente santafereño del periodo colonial.', ja: 'ラ・カンデラリア地区は植民地時代のボゴタの雰囲気を今に伝えている。', trivia: '「santafereño」はコロンビアの旧首都名「Santa Fe de Bogotá」から派生した形容詞・名詞で、特に歴史的・文化的な文脈でボゴタっ子を指す。英語では「Bogotano」に対応する。' },
  'santafesina': { es: 'La ganadería santafesina es una de las más importantes de Argentina.', ja: 'サンタ・フェ州の畜産業はアルゼンチンで最も重要な産業の一つだ。', trivia: 'アルゼンチンのサンタ・フェ州（Provincia de Santa Fe）はラ・プラタ川流域に広がる農業・牧畜の中心地で、「santafesino/a」はその出身者を指す。形容詞接尾辞 -sino はラテン語 -ensis に起源を持つ。' },
  'santafesino': { es: 'El dialecto santafesino tiene características propias dentro del español rioplatense.', ja: 'サンタ・フェ州のスペイン語方言はリオ・プラタ地方のスペイン語の中でも独自の特徴を持っている。', trivia: '「santafesino」はアルゼンチンのサンタ・フェ州出身者・同州に関するものを指す。同名の都市・州が複数存在するため、文脈によって「santafecino（サンタ・フェ市：メキシコ等）」と区別される。' },
  'santiamén': { es: 'Lo terminé en un santiamén porque era una tarea muy sencilla.', ja: 'とても簡単な作業だったので、あっという間に終わらせた。', trivia: '「santiamén」はカトリックの典礼文「In saecula saeculorum, Amen（世々に至るまで、アーメン）」が縮約されたとされ、「amen（アーメン）」が英語にも同形で存在する。英語の「in a jiffy（あっという間に）」に相当する口語表現。' },
  'santiago': { es: 'Santiago es la ciudad más poblada de Chile y su capital desde el siglo XVI.', ja: 'サンティアゴは16世紀以来チリの首都であり、最も人口の多い都市だ。', trivia: '「Santiago」はヘブライ語の「Yaʿakov（ヤコブ）」がラテン語 Sanctus Iacobus（聖ヤコブ）を経てスペイン語化したもので、英語の「Saint James（セント・ジェームズ）」に対応する。中世ヨーロッパ最大の巡礼地「サンティアゴ・デ・コンポステーラ」の語源でもある。' },
  'santiaguera': { es: 'La música santiaguera, especialmente el son cubano, ha influido en todo el mundo.', ja: 'サンティアゴ（キューバ）の音楽、特にソン・クバーノは世界中に影響を与えてきた。', trivia: '「santiaguera/o」はキューバやドミニカ共和国など複数の「サンティアゴ」出身者を指すが、特にキューバのサンティアゴ・デ・クーバに関連して用いられることが多い。英語では「Santiagan」と表記される場合がある。' },
  'santiaguero': { es: 'El carnaval santiaguero de Cuba es reconocido como Patrimonio Cultural de la Humanidad.', ja: 'キューバのサンティアゴのカーニバルはユネスコの人類無形文化遺産に認定されている。', trivia: '「santiaguero」の接尾辞 -ero はラテン語 -arius に由来し、英語の -er や -ary（例: military, necessary）と同語源。職業・出身地を表す多目的な語尾で、スペイン語に広く用いられる。' },
  'santiaguina': { es: 'La vida santiaguina es agitada, pero la ciudad también ofrece muchos parques y espacios culturales.', ja: 'サンティアゴっ子の生活は忙しいが、この都市には多くの公園や文化施設もある。', trivia: '「santiaguino/a」はチリの首都サンティアゴの市民を指す最も一般的な形で、「santiaguero/a」より正式な響きを持つ。接尾辞 -ino はラテン語 -inus に由来し、英語の -ine（例: masculine, marine）と同語源。' },
  'santiaguino': { es: 'El santiaguino promedio pasa más de una hora al día en transporte público.', ja: '平均的なサンティアゴ市民は1日1時間以上を公共交通機関で過ごす。', trivia: '「santiaguino」はチリで最も広く使われるサンティアゴ市民の呼称で、チリのスペイン語における地域的アイデンティティを強く示す語。英語では「Santiagoan」または「resident of Santiago」と訳される。' },
  'santiaguista': { es: 'Los santiaguistas del siglo XII juraban defender la fe cristiana en la Península Ibérica.', ja: '12世紀のサンティアゴ騎士団員たちはイベリア半島でキリスト教信仰を守ることを誓った。', trivia: '「santiaguista」は中世スペインの軍事修道会「Orden de Santiago（サンティアゴ騎士団）」の団員を指し、接尾辞 -ista は英語の -ist（例: artist, nationalist）と同語源のギリシャ語 -istēs に由来する。' },
  'santificable': { es: 'Según la teología católica, toda persona está en condición santificable por la gracia divina.', ja: 'カトリック神学によれば、すべての人は神の恵みによって聖化され得る存在である。', trivia: '「santificable」はラテン語 sanctificare（神聖にする）に能力・可能性を表す接尾辞 -able（ラテン語 -abilis）が付いたもので、英語の「sanctifiable」に直接対応する。' },
  'santificación': { es: 'La santificación del domingo tiene raíces tanto en la tradición judía del sábado como en el cristianismo primitivo.', ja: '日曜日の聖化は、ユダヤ教の安息日の伝統と初期キリスト教の両方に根ざしている。', trivia: '「santificación」はラテン語 sanctificatio（清めること）に由来し、英語の「sanctification」と同語源。宗教改革においても「聖化（霊的成長のプロセス）」として重要な神学的概念であった。' },
  'santificadamente': { es: 'Vivían santificadamente, dedicando cada día a la oración y al servicio de los demás.', ja: '彼らは毎日を祈りと隣人への奉仕に捧げながら、敬虔に生きていた。', trivia: '「santificadamente」は形容詞「santificado（神聖化された）」に副詞語尾 -mente（ラテン語 mente：精神・様式で）が付いた語で、英語の -ly 副詞（例: holily）に相当する。スペイン語の副詞形成の典型的なパターンを示す。' },
  'santificadora': { es: 'La gracia santificadora es, según el catecismo, el don de Dios que hace al alma partícipe de su vida divina.', ja: 'カテキズムによれば、聖化の恩寵とは魂を神の命に参与させる神の賜物である。', trivia: '「santificadora」はラテン語 sanctificare に行為者接尾辞 -dor/-dora が付いた語で、英語の「sanctifier」に対応する。カトリック神学では「gracia santificadora（聖化の恩寵）」という表現で頻繁に用いられる。' },
  'santificador': { es: 'El Espíritu Santo es considerado el santificador de las almas en la tradición cristiana.', ja: 'キリスト教の伝統では、聖霊は魂を聖化するものと見なされている。', trivia: '「santificador」はラテン語 sanctificator に由来し、英語の「sanctifier」に直接対応する。ラテン語 sanctus（聖なる）は英語の saint、sanctum、sanctuary などの語源でもある。' },
  'santificar': { es: 'La Iglesia santifica el domingo como día de descanso y oración en memoria de la Resurrección.', ja: '教会は復活の記念として、日曜日を休息と祈りの日として聖化している。', trivia: '「santificar」はラテン語 sanctificare（sanctus「聖なる」＋facere「する」）に由来し、英語の「sanctify」と同語源。英語の sacred、saint、sanctuary もすべて同じラテン語の根 sanctus を共有している。' },
  'santiguada': { es: 'Al entrar al hospital, la abuela hizo una santiguada y murmuró una oración.', ja: '病院に入るとき、おばあさんは十字を切り、小声で祈りをつぶやいた。', trivia: '「santiguada」は動詞 santiguar の名詞化形で、十字を切る一連の動作を指す。ラテン語 Sanctus Iacobus（聖ヤコブ）に由来するという説があり、英語の「blessing」に意味的に近い。' },
  'santiguador': { es: 'En los pueblos rurales de Andalucía, el santiguador era consultado para curar el mal de ojo.', ja: 'アンダルシアの農村では、邪視（evil eye）を治すために祈祷師に相談することがあった。', trivia: '「santiguador」は民間信仰に根差した呼称で、十字を切りながら祈祷（きとう）して病気や呪いを治すとされた人物を指す。英語の「faith healer」や「folk healer」に相当し、スペインやラテンアメリカの民俗医療の伝統を体現する語。' },
  'santiguadora': { es: 'La santiguadora del barrio era respetada por su capacidad de curar sustos y males del cuerpo.', ja: 'その地区の女性祈祷師は、驚き症や体の不調を治す力で人々から敬われていた。', trivia: '「santiguadora」は女性の民間治療師を指し、主に「susto（突然の驚きによる病気）」や「mal de ojo（邪視）」を祈祷と十字によって治すとされた。英語の「healer」に近いが、より宗教・民俗的な含意を持つ。' },
  'santiguamiento': { es: 'El santiguamiento ante una imagen religiosa es una práctica común entre los católicos devotos.', ja: '聖像の前で十字を切ることは、信心深いカトリック信者の間で一般的な習慣だ。', trivia: '「santiguamiento」は動詞 santiguar に名詞化接尾辞 -miento（ラテン語 -mentum）が付いた形で、英語の -ment（例: movement, treatment）と同語源。行為・結果を表すスペイン語の典型的な名詞形成パターン。' },
  'santiguar': { es: 'Al escuchar la mala noticia, se santiguó instintivamente y cerró los ojos.', ja: 'その悪い知らせを聞いて、彼は本能的に十字を切り、目を閉じた。', trivia: '「santiguar」はラテン語 Sanctus Iacobus（聖ヤコブ）に由来するという説が有力で、英語の「cross oneself」または「bless」に相当する。再帰形 santiguarse で「自分で十字を切る」、他動詞として「（他者に）祝福を与える・祈祷する」の意味になる。' },
  'santiguo': { es: 'El santiguo era una práctica ancestral para proteger a los recién nacidos de las malas energías.', ja: 'サンティグオは新生児を悪いエネルギーから守るための先祖代々の儀式だった。', trivia: '「santiguo」は名詞として民間信仰の祈祷儀式を指すが、動詞 santiguar の直説法現在1人称単数（yo santiguo）とも同形。ラテン語 Sanctus（聖なる）を語根とし、英語の「saint」「sanctify」と同じ語族に属する。' },
  'santillana': { es: 'El libro de texto de Santillana que usamos en clase tiene ejercicios muy bien diseñados para aprender gramática.', ja: '授業で使っているサンティリャーナの教科書は、文法を学ぶのに非常によく設計された練習問題が入っている。', trivia: 'Santillana はスペイン・カンタブリア州にある中世の美しい村の名に由来する教育出版グループで、世界最大規模のスペイン語教科書ブランドの一つ。英語圏でも Spanish language textbooks として広く知られ、ラテンアメリカ全域の学校教育で採用されている。' },
  'santimonia': { es: 'Su santimonia no engañó a nadie; todos sabían que solo actuaba para quedar bien.', ja: '彼の偽善的な信心深さは誰も欺かなかった。皆、彼がよく見られるために演じているだけだと分かっていた。', trivia: 'ラテン語 sanctimonia（神聖さ）から派生し、英語の sanctimony と同語源。現代スペイン語では主に皮肉的な文脈で「聖人ぶること」を指し、英語でも sanctimonious（偽善的な）という形容詞が日常的に使われる。' },
  'santiscario': { es: 'El niño se tiró al suelo por su santiscario cuando no le compraron el juguete.', ja: 'おもちゃを買ってもらえなかった子どもは、自分の我を通そうと床に転がった。', trivia: 'スペイン口語の表現で、「santo」（聖）と関連するとも、単純な俗語的派生ともいわれ語源は不明確。英語には直訳しにくく、stubbornness（頑固さ）や whim（気まぐれ）で近い意味を表す。' },
  'santísima': { es: 'El sacerdote elevó la santísima forma durante la misa y los fieles se arrodillaron en silencio.', ja: '司祭はミサの最中に御聖体を高く掲げ、信徒たちは静かにひざまずいた。', trivia: 'ラテン語 sanctissimus（最も神聖な）に由来する santo の絶対最上級形で、英語の most holy に相当。カトリック用語では「la Santísima Trinidad」（至聖三位一体）や「la Santísima Virgen」（聖母マリア）の形で頻繁に用いられる。' },
  'santísimo': { es: 'Los peregrinos se acercaron con reverencia al santísimo expuesto en el altar mayor.', ja: '巡礼者たちは、主祭壇に安置された御聖体に畏敬の念を持って近づいた。', trivia: 'ラテン語 sanctissimus の男性形に由来し、「el Santísimo」はカトリックでは御聖体（聖体拝領のパン）を指す固有名詞的な用法もある。英語では the Blessed Sacrament に相当し、スペイン語圏のカトリック文化に深く根付いた語。' },
  'santista': { es: 'Como santista apasionado, no se pierde ningún partido del Santos FC aunque viva lejos de Brasil.', ja: '熱烈なサントスFCファンとして、彼はブラジルから遠く離れていてもサントスFCの試合を一試合も見逃さない。', trivia: 'ブラジルの名門サッカークラブ「Santos FC」の名前に由来し、ペレが所属したことで世界的に有名。英語でもサッカー文脈では santista がそのまま使われることがあり、ポルトガル語の影響を受けたスペイン語スポーツ用語の一例。' },
  'santo': { es: 'El guardia exigió la contraseña y el soldado respondió con el santo correcto para poder pasar.', ja: '衛兵は合言葉を要求し、兵士は通過するために正しい合言葉を答えた。', trivia: 'ラテン語 sanctus（神聖な）に由来し、英語の saint、sanctuary、sanction なども同じ語根を持つ。スペイン語では「santo y seña」（合言葉・パスワード）という成句でも使われ、宗教的意味から軍事・日常用語まで幅広く活用される語。' },
  'santón': { es: 'El santón del barrio daba consejos a todos, pero en privado llevaba una vida muy diferente.', ja: 'その街の大物ぶった偽善者は皆に助言を与えていたが、私生活ではまったく異なる暮らしをしていた。', trivia: 'スペイン語 santo（聖人）に指小・強調の接尾辞 -ón を加えた形で、もとは北アフリカのイスラム聖者（マラブー）を指した。英語には直訳する単語がなく、bigot や false prophet で意味を近似することが多い。' },
  'santona': { es: 'La vecina actuaba como una santona, criticando a los demás mientras ella misma hacía lo mismo.', ja: 'その隣人は聖人ぶった女のように振る舞い、自分も同じことをしながら他人を批判していた。', trivia: 'santón の女性形で、スペイン語の職業・特徴を表す名詞が -ona という女性形をとる典型的な例。英語では female bigot や sanctimonious woman に相当し、宗教的偽善を皮肉る文脈で用いられる。' },
  'santoral': { es: 'Según el santoral católico, hoy celebramos la festividad de san Juan de la Cruz.', ja: 'カトリックの聖人暦によれば、今日は十字架の聖ヨハネの祝日を祝う。', trivia: 'ラテン語 sanctus（聖なる）に由来し、英語の calendar of saints や hagiography（聖人伝）に相当する概念。スペインやラテンアメリカでは誕生日と同じくらい「santo（名前の日）」が重視される文化があり、santoral はその礎となる暦。' },
  'santuario': { es: 'Miles de turistas visitan cada año el santuario de la Virgen de Guadalupe en México.', ja: '毎年何千人もの観光客がメキシコのグアダルーペの聖母の聖堂を訪れる。', trivia: 'ラテン語 sanctuarium（聖なる場所）に由来し、英語の sanctuary と完全な同語源語。宗教的な聖地・避難所の意味から、現代では野生動物の保護区（santuario de animales）や比喩的な「心の拠り所」にも使われる多義語。' },
  'santucho': { es: 'No soporto a ese santucho que predica virtudes que él mismo no practica.', ja: '自分自身は実践しない美徳を説いているあの偽善者に我慢できない。', trivia: 'santo（聖人）に口語的な指小・軽蔑の接尾辞 -ucho を加えた形で、「なんちゃって聖人」というニュアンスを持つ。英語の hypocrite や goody-goody に近く、スペイン口語に多い接尾辞 -ucho は軽蔑や侮りを表す特徴がある。' },
  'santucha': { es: 'En el pueblo la llamaban la santucha porque iba a misa todos los días pero murmuraba de todos.', ja: '村では彼女を「偽善女」と呼んでいた。毎日ミサに行くくせに皆の悪口を言っていたからだ。', trivia: 'santucho の女性形で、スペイン語の -ucho/-ucha という接尾辞は軽蔑や卑下を示す典型的な派生語パターン。英語には対応する単語がなく、sanctimonious woman などと説明するしかない文化的に興味深い語。' },
  'sanzala': { es: 'La sanzala era el centro comunitario donde los habitantes del pueblo se reunían para celebrar sus tradiciones.', ja: 'サンスアラは住民が伝統を祝うために集まるコミュニティの中心地だった。', trivia: 'アンゴラなどのバントゥー系言語に由来するアフリカ起源の語で、ポルトガル語経由でスペイン語に入った。英語では village compound や traditional settlement に相当し、植民地時代の歴史的文脈でアフリカの集落構造を指す民俗学的な語。' },
  'sapa': { es: 'Los ingenieros abrieron una sapa para acercarse a las murallas enemigas sin ser vistos.', ja: '工兵たちは見つからないように敵の城壁に近づくための塹壕を掘った。', trivia: 'フランス語 sape（塹壕、掘削作業）を経由してスペイン語に入った軍事用語で、英語の sap（塹壕）と同語源。sapeur（工兵）という語も同じ根を持ち、南米スラングでは「詮索好きな人」という全く異なる意味でも使われる。' },
  'sapada': { es: 'Con esa sapada descubrió quién estaba detrás del chisme que circulaba por el barrio.', ja: 'その詮索によって、街に流れていた噂の背後に誰がいるかを突き止めた。', trivia: '南米口語で sapo（カエル・密告者）から派生した語で、「カエルのような行動」つまり「覗き見・詮索」を意味する。英語には直訳する語がなく、snooping や nosiness に近い。sapo が密告者を指す比喩はラテンアメリカ各国で広く共有されている。' },
  'sapenco': { es: 'En el jardín había un sapenco enorme que asustó a los niños cuando salió de entre las piedras.', ja: '庭には巨大なヒキガエルがいて、石の間から現れたとき子どもたちを驚かせた。', trivia: 'スペイン語の sapo（ヒキガエル）に接尾辞 -enco を加えた口語形で、「大きくて不格好なヒキガエル」を指す。英語の toad に相当するが、-enco という接尾辞が「大きくて醜い」という軽蔑的なニュアンスを加えるスペイン口語の特徴的な語形成。' },
  'sapear': { es: 'En el barrio todos sabían que ese chico sapeaba a sus amigos ante la policía por dinero.', ja: 'その街では、あの男がお金のために友人たちを警察に密告していることを皆が知っていた。', trivia: 'sapo（カエル・密告者）から派生した動詞で、カエルが口を大きく開ける様子が「密告する・喋る」という比喩に繋がったとされる。英語の snitch や rat（on someone）に相当し、ラテンアメリカのスラングで広く使われる口語表現。' },
  'sapidez': { es: 'El chef explicó que la sapidez de un buen caldo depende de la calidad de los ingredientes y el tiempo de cocción.', ja: 'シェフは、良いだし汁の風味は食材の質と調理時間にかかっていると説明した。', trivia: 'ラテン語 sapidus（味のある）に由来し、英語の sapidity と同語源。食品科学では味の有無や強度を示す技術用語として使われ、英語でも sapid（風味豊かな）や insipid（味気ない）という対になる単語が同じ語根から生まれている。' },
  'sápida': { es: 'La conferencia resultó ser muy sápida gracias a los ejemplos concretos y el humor del ponente.', ja: '具体的な例と講演者のユーモアのおかげで、その講演はとても面白く知的な刺激に富むものだった。', trivia: 'ラテン語 sapidus（風味のある、味のある）の女性形に由来し、英語の sapid と同語源。転じて「知的に興味深い」という比喩的用法も持ち、その反義語 insípida（味気ない、つまらない）は日常的によく使われる。' },
  'sápido': { es: 'El periodista escribió un artículo sápido que combinaba datos históricos con anécdotas personales muy entretenidas.', ja: 'その記者は、歴史的データと非常に面白い個人的なエピソードを組み合わせた知的で興味深い記事を書いた。', trivia: 'ラテン語 sapidus（味のある）の男性形で、英語の sapid（風味豊かな、興味深い）と完全な同語源語。sapientia（知恵）や英語の sapient（賢明な）とも同じ印欧語根 *sap-（味わう、知る）に由来する点が興味深い。' },
  'sapiencia': { es: 'La sapiencia de los ancianos del pueblo es un tesoro que no debe perderse.', ja: '村の長老たちの深い知恵は、失ってはならない宝だ。', trivia: 'ラテン語 sapientia（知恵）に由来し、動詞 sapere（味わう、知る）が語源。英語の sapience や sapient と同根で、いずれも「賢明さ」を意味する。' },
  'sapiencial': { es: 'Los libros sapienciales del Antiguo Testamento incluyen los Proverbios y el Eclesiastés.', ja: '旧約聖書の知恵文学には、箴言や伝道の書が含まれる。', trivia: 'ラテン語 sapientialis から派生した形容詞で、英語の sapiential と同形・同義。聖書学では「知恵文学（sapiential literature）」という専門用語として使われる。' },
  'sapiente': { es: 'Un gobernante sapiente escucha a su pueblo antes de tomar decisiones importantes.', ja: '賢明な指導者は、重要な決断を下す前に民の声に耳を傾ける。', trivia: 'ラテン語の現在分詞 sapiens（知る・味わう者）が語源で、英語の sapient と同じ語根。学名 Homo sapiens（ホモ・サピエンス）の sapiens もここから来ている。' },
  'sapillo': { es: 'Los niños encontraron un sapillo escondido entre las piedras del jardín.', ja: '子どもたちは庭の石の間に隠れていた小さなカエルを見つけた。', trivia: 'sapo（ヒキガエル）の指小辞形（-illo）で「小さなカエル」を意味する。医学用語としての「ガマ腫（らん下嚢胞）」という用法は、舌の下にできる腫れがガマガエルのように見えることから来ている。' },
  'sapina': { es: 'La sapina crece en terrenos salinos donde pocas plantas pueden sobrevivir.', ja: 'サピナは、ほとんどの植物が生育できない塩性土地に育つ。', trivia: 'アカザ科（Chenopodiaceae）の塩生植物で、学名は Salsola vermiculata など。塩分の多い土壌に適応したこの植物は、かつて灰から炭酸ナトリウム（ソーダ）を採取するために使われた。' },
  'sapino': { es: 'El sapino es un árbol característico de los bosques de montaña en la región pirenaica.', ja: 'サピノはピレネー地方の山岳森林に特徴的な樹木だ。', trivia: 'ヨーロッパモミ（Abies alba）の地方名または異称で、マツ科の常緑針葉樹。スペインのアラゴン地方などで用いられる方言語であり、英語の fir（モミ）に相当する。' },
  'sapo': { es: 'Mi vecino es un sapo que siempre está escuchando las conversaciones ajenas.', ja: '隣の人は、いつも他人の会話を盗み聞きしているような詮索好きだ。', trivia: 'イベリア語起源とも前ラテン語起源ともされる古い語で、英語の toad に対応する。中南米スラングでは「密告者・スパイ」の意味で広く使われ、「sapo」と呼ばれることは大きな侮辱になる。' },
  'saponaria': { es: 'La saponaria se usaba antiguamente para lavar ropa gracias a la espuma que producen sus raíces.', ja: 'サボンソウはかつて、根が泡立てる性質のおかげで洗濯に使われていた。', trivia: 'ラテン語 sapo（石鹸）に由来し、英語では soapwort（ソープワート）と呼ばれる。根や葉にサポニンを含み、水と混ぜると泡立つため、古代から天然洗剤として利用されてきた。' },
  'saponificable': { es: 'Solo las grasas saponificables pueden utilizarse para fabricar jabón en el proceso industrial.', ja: '工業的な石鹸製造工程では、ケン化可能な油脂しか使用できない。', trivia: 'ラテン語 sapo（石鹸）＋ facere（作る）から派生した化学用語で、英語の saponifiable と同語源。油脂がアルカリと反応して石鹸と glycerol（グリセロール）に分解できる性質を指す。' },
  'saponificación': { es: 'La saponificación es el proceso químico mediante el cual se transforma el aceite en jabón.', ja: 'ケン化とは、油脂を石鹸に変換する化学プロセスのことだ。', trivia: 'ラテン語 sapo（石鹸）＋ facere（作る）＋接尾辞 -ción から成る化学術語で、英語の saponification と同形・同義。法医学では長期間土中に埋まった遺体が脂肪酸アンモニウム塩に変化する現象（死体蝋化）も同じ語で表す。' },
  'saponificar': { es: 'Al saponificar el aceite de oliva con hidróxido de sodio, obtenemos un jabón natural de calidad.', ja: 'オリーブオイルを水酸化ナトリウムでケン化すると、高品質の天然石鹸が得られる。', trivia: 'ラテン語 sapo（石鹸）と facere（作る）の合成語で、英語の saponify と同語源。化学式的には油脂（トリグリセリド）が強アルカリと加水分解反応を起こす過程を表す動詞。' },
  'saponina': { es: 'La saponina presente en la quinoa le da ese sabor amargo que desaparece al lavarla bien.', ja: 'キノアに含まれるサポニンが、よく洗うと消える苦みの原因だ。', trivia: 'ラテン語 sapo（石鹸）から派生した化学名で、英語でも saponin と呼ばれる。植物が自衛のために合成する苦味成分であり、水に溶けると界面活性作用で泡立つ性質を持つ。' },
  'saporífera': { es: 'Las especias tienen propiedades saporíferas que enriquecen cualquier receta.', ja: '香辛料はあらゆる料理を豊かにする風味付けの特性を持っている。', trivia: 'ラテン語 sapor（味）＋ ferre（運ぶ・もたらす）の合成語で、英語の saporiferous と同語源。「味や風味をもたらすもの」という意味で、形容詞の女性形として使われる。' },
  'saporífero': { es: 'El comino es un ingrediente saporífero fundamental en la cocina del norte de África.', ja: 'クミンは北アフリカ料理に欠かせない風味付けの食材だ。', trivia: 'ラテン語 sapor（味）＋ ferre（運ぶ・もたらす）の合成語で、英語の saporiferous と同語源。saporífera の男性形であり、「風味を与える・おいしくする」という意味の科学・料理用語として使われる。' },
  'saque': { es: 'El tenista falló dos saques seguidos y perdió el primer set por un margen mínimo.', ja: 'テニス選手は連続で2本サービスエラーを犯し、わずかな差でファーストセットを落とした。', trivia: '動詞 sacar（取り出す、出す）の活用形（現在接続法1・3人称）と同形だが、スポーツ用語としては「サーブ、キックオフ」を指す名詞。英語の serve と意味が重なり、日本語の「酒（sake）」もこの語で表記されることがある。' },
  'saqueador': { es: 'Los saqueadores aprovecharon el caos tras el terremoto para robar tiendas y almacenes.', ja: '略奪者たちは地震後の混乱に乗じて、商店や倉庫を荒らした。', trivia: '動詞 saquear（略奪する）に行為者接尾辞 -dor を加えた派生語で、英語の looter や plunderer に相当。「saco（袋）」を語根に持ち、「袋に詰めて奪い去る者」というイメージが語源的に宿っている。' },
  'saqueadora': { es: 'La saqueadora fue detenida mientras intentaba escapar con mercancía robada.', ja: '女性略奪者は盗んだ商品を持って逃げようとしたところで逮捕された。', trivia: 'saqueador（略奪者）の女性形。スペイン語では職業・行為者名詞の多くが -dor/-dora の性区別を持ち、英語では looter の一語で男女両方を表すのと対照的な特徴がある。' },
  'saquear': { es: 'Las tropas saquearon la ciudad durante tres días antes de que llegaran los refuerzos.', ja: '援軍が到着するまでの3日間、軍隊は街を略奪し続けた。', trivia: 'saco（袋）を語源とし、「袋に入れて奪い去る」というイメージから「略奪する」の意味に発展した。英語の sack（略奪する）とも語源を共有しており、ゲルマン語系の影響が見られる。' },
  'saqueo': { es: 'El saqueo del museo fue una pérdida cultural irreparable para todo el país.', ja: '博物館の略奪は、国全体にとって取り返しのつかない文化的損失だった。', trivia: '動詞 saquear から派生した名詞で、英語の looting や sacking に対応する。歴史的には戦争や自然災害後に発生する組織的な略奪行為を指し、「saco（袋）に詰めて奪う行為」という語源的意味を保持している。' },
  'saquetera': { es: 'La saquetera del mercado medieval cosía y vendía bolsas de cuero para los viajeros.', ja: '中世の市場の女袋職人は、旅人向けに革袋を縫って売っていた。', trivia: 'saco（袋）＋職業接尾辞 -tero/-tera から成る語で、袋を作る・運ぶ職人を指す歴史的な職業名詞。英語の sack（袋）と語源を共有しており、ラテン語 saccus（袋）が共通の祖先。' },
  'saquetero': { es: 'El saquetero llevaba granos desde los molinos hasta los almacenes del señor feudal.', ja: '袋運び職人は、製粉所から封建領主の倉庫まで穀物を運んでいた。', trivia: 'saquetera（女性形）に対応する男性形の職業名詞。saco（袋）を語根とし、中世の穀物流通を担った職種を表す。英語の sack（麻袋）とラテン語 saccus（袋）を共通の語源に持つ。' },
  'saquilada': { es: 'El molinero midió la harina por saquiladas antes de distribuirla entre los aldeanos.', ja: '製粉業者は農村民に配分する前に、袋単位で小麦粉を量った。', trivia: 'saquillo（小袋）の派生語で、製粉機に一度に投入できる穀物の量という農業・製粉業の計量単位として使われた。スペイン農村社会の伝統的な計量慣行を反映した語彙である。' },
  'sarama': { es: 'Esta habitación está llena de sarama; hay que limpiarla de una vez.', ja: 'この部屋はゴミだらけだ。いい加減に掃除しなければならない。', trivia: 'スペイン語の方言・古語で「ゴミ、塵、価値のないもの」を意味し、標準語の basura に相当する。地域によって使われる表現で、ラテンアメリカの一部地域でも同様の意味で残存している。' },
  'sarampión': { es: 'Gracias a la vacuna, el sarampión ha sido casi erradicado en muchos países desarrollados.', ja: 'ワクチンのおかげで、はしかは多くの先進国でほぼ根絶されている。', trivia: '語源は諸説あり、アラビア語 haṣba（発疹）またはラテン語からの変形とされる。英語の measles に相当し、比喩的には「誰もが若い頃に一度はかかる流行り」（例：恋愛）という用法でも使われる興味深い表現。' },
  'sarán': { es: 'Cubrieron los cultivos con sarán para protegerlos del sol intenso del verano.', ja: '強烈な夏の日差しから守るために、農作物に遮光ネットをかぶせた。', trivia: '英語の Saran（商標名、塩化ビニリデン系ポリマー素材）に由来する借用語で、スペイン語圏では主に農業・園芸用の遮光ネット・シェードネットを指す。英語の Saran Wrap（サランラップ）と同じ商標から派生している。' },
  'sarao': { es: 'La familia organizó un sarao elegante para celebrar el compromiso de su hija.', ja: 'その家族は娘の婚約を祝うために優雅な夜会を開いた。', trivia: 'スペイン語 sarao はアラビア語起源とも、イタリア語の sera（夜）から派生したとも言われる。英語の soirée（フランス語経由）と同様に「夜の集まり」を意味するが、スペイン語では口語的に「どんちゃん騒ぎ」のニュアンスでも使われる。' },
  'saratoga': { es: 'El viajero llegó al hotel con una saratoga llena de trajes y sombreros.', ja: 'その旅行者はスーツや帽子でいっぱいのサラトガトランクを持ってホテルに到着した。', trivia: 'saratoga（サラトガトランク）はアメリカのニューヨーク州サラトガ・スプリングスに由来する大型旅行トランクで、19世紀の上流社会で人気を博した。地名としてのサラトガは先住民語に由来し、英語でもそのまま Saratoga と呼ばれる。' },
  'sarcasmo': { es: 'Su comentario lleno de sarcasmo no pasó desapercibido entre los presentes.', ja: '彼の皮肉に満ちたコメントは、居合わせた人々の目に留まらないはずがなかった。', trivia: 'ラテン語 sarcasmus、ギリシャ語 sarkasmós（σαρκασμός）に由来し、語根の sarx は「肉」を意味する。つまり「肉を噛み切る」ようなするどい言葉という語源を持ち、英語の sarcasm と全く同源の国際的な学術語でもある。' },
  'sarcásticamente': { es: '—¿Qué gran ayuda la tuya! —respondió sarcásticamente mientras recogía los papeles del suelo.', ja: '「あなたってほんとうに役立つわね！」と彼女は皮肉っぽく言いながら、床に散らばった書類を拾い集めた。', trivia: '形容詞 sarcástico に副詞を作る接尾辞 -mente を付けた派生語で、英語の sarcastically と構造的に完全に対応する。スペイン語の副詞は -mente 一語でできており、英語の -ly と機能が同じである。' },
  'sarcástica': { es: 'Hizo una observación sarcástica que dejó a todos incómodos.', ja: '彼女は皮肉な指摘をして、みなを気まずい気分にさせた。', trivia: 'sarcástico / sarcástica はギリシャ語の sarkasmós（肉を噛み切る）に由来し、英語の sarcastic と同源。スペイン語では形容詞が修飾する名詞の性に合わせて語尾が変化するため、女性名詞には -a 形が用いられる。' },
  'sarcástico': { es: 'El periodista es conocido por su estilo sarcástico al comentar la política.', ja: 'そのジャーナリストは政治を評論する皮肉なスタイルで知られている。', trivia: 'ギリシャ語の sarx（肉）＋asm（動作）から来ており、英語の sarcastic と全く同じ語源を持つ。古代ギリシャでは「歯をむき出しにして笑う」様子を指し、そこから辛辣な嘲りの表現へと意味が広がった。' },
  'sarcófago': { es: 'Los arqueólogos descubrieron un sarcófago de mármol en las ruinas romanas.', ja: '考古学者たちはローマ遺跡で大理石の石棺を発見した。', trivia: 'ギリシャ語の sarx（肉）＋ phagein（食べる）から成り、英語の sarcophagus と完全に同源。古代ギリシャでは特定の石灰石が遺体を急速に分解すると信じられ「肉を食べる石」と呼ばれたことが語源とされる。チェルノブイリの遮蔽構造物にも比喩的に使われる。' },
  'sarcoma': { es: 'El médico explicó que el sarcoma de tejidos blandos requiere tratamiento urgente.', ja: '医師は軟部組織の肉腫は緊急治療が必要だと説明した。', trivia: 'ギリシャ語の sarx（肉）＋ -oma（腫瘍・塊）から成る医学用語で、英語の sarcoma と完全に同源の国際的学術語。-oma という接尾辞はギリシャ語起源の医学用語に広く使われ、carcinoma（癌腫）などにも共通する。' },
  'sarcoplasma': { es: 'El sarcoplasma es el citoplasma de las células musculares y contiene glucógeno.', ja: '筋形質は筋細胞の細胞質であり、グリコーゲンを含んでいる。', trivia: 'ギリシャ語の sarx（肉）＋ plasma（形成されたもの）から成り、英語の sarcoplasm と同源の解剖学・生理学用語。plasma 自体もギリシャ語 plassein（形作る）に由来し、英語の plasma（血漿、プラズマ）とも語根を共有する。' },
  'sardinel': { es: 'El ayuntamiento renovó los sardineles de las calles del centro histórico.', ja: '市役所は旧市街の街路の縁石を改修した。', trivia: 'スペイン語固有の建築・土木用語で、英語の curb（縁石）や rowlock brickwork（小端積みレンガ）に相当するが、語源はサルディーニャ島（Sardinia）との関連を指摘する説もある。中南米では都市整備の文脈で頻繁に用いられる語彙である。' },
  'sardónica': { es: 'La actriz esbozó una sonrisa sardónica antes de abandonar la sala de prensa.', ja: 'その女優は記者会見場を去る前に冷笑的な笑みを浮かべた。', trivia: '古代ギリシャ語の sardónios（σαρδόνιος）に由来し、サルディーニャ島（Sardinia）で生育する植物を食べると顔がひきつるような表情になるという伝説から生まれた語。英語の sardonic と完全に同源で、「不敵な、皮肉な笑い」を指す国際語である。' },
  'sardónico': { es: 'Su humor sardónico no siempre era bien comprendido por sus compañeros.', ja: '彼の皮肉な笑いのユーモアは仲間にいつも理解されるとは限らなかった。', trivia: 'サルディーニャ（Sardinia）島に自生する植物の毒が引き起こす顔の痙攣に由来するとされ、英語の sardonic と同語源。古代ギリシャの詩人ホメロスもこの表現を使ったとされ、「作り笑い」「冷笑」の含意を持つ歴史ある形容詞である。' },
  'sarga': { es: 'El traje estaba confeccionado en sarga de lana de alta calidad.', ja: 'そのスーツは高品質のウールサージで仕立てられていた。', trivia: 'ラテン語の serica（絹製品・絹織物）またはフランス語の serge を経由してスペイン語に入った語で、英語の serge と同源。斜めに走る畝（うね）が特徴の綾織り（ツイル）の一種で、現代でもビジネスウェアや制服に広く使われる素材名である。' },
  'sargento': { es: 'El sargento ordenó a la tropa que se preparara para el ejercicio de madrugada.', ja: '軍曹は部隊に夜明け前の訓練に備えるよう命令した。', trivia: 'ラテン語の servire（奉仕する）から派生した serviens を経由し、英語の sergeant と完全に同源。中世フランス語 sergent を通じてヨーロッパ各語に広まった軍事用語で、日本語の「サージェント」もこの系統の借用語である。' },
  'sarmentosa': { es: 'La planta sarmentosa trepaba por toda la pared del jardín.', ja: 'そのつる性の植物は庭の壁全体を覆うように伸びていた。', trivia: 'スペイン語の sarmiento（ブドウの細枝）から派生した形容詞で、英語の sarmentose と同源のラテン語 sarmentum（切り枝）に由来する。植物学用語として「つるや巻きひげで伸びる」性質を指し、比喩的に細く筋張った手足の描写にも使われる。' },
  'sarmiento': { es: 'Los viticultores queman los sarmientos después de la poda para abonar la tierra.', ja: 'ブドウ農家は土壌を肥やすために剪定後の枝を燃やす。', trivia: 'ラテン語の sarmentum（切り枝、枝払いした細枝）に由来し、英語では直接対応する一般語はなく vine shoot や vine cutting と訳される。スペインでは有名な作家・教育者ドミンゴ・ファウスティーノ・サルミエント（Sarmiento）の姓としても知られる。' },
  'sarna': { es: 'El veterinario diagnosticó sarna en varios perros del refugio.', ja: '獣医は保護施設の数頭の犬に疥癬の診断を下した。', trivia: 'ラテン語の scabies（かき傷、疥癬）と関連するとも、別の語根に由来するとも言われるが、英語の scabies（疥癬）や mange（ヒゼンダニ症）に相当する。「sarna con gusto no pica（好きでやる苦労は苦にならない）」というスペイン語のことわざにも登場する日常語。' },
  'sarpullido': { es: 'El niño salió con un sarpullido en los brazos tras jugar en el jardín.', ja: '子どもは庭で遊んだあと、腕に発疹が出た。', trivia: 'スペイン語独自の語で、語源は sal（塩）＋ pullido（細かい粒）という説や、動詞 salpullar から来るという説がある。英語の rash や hives に相当し、salpullido という異形も存在する口語的な医療・日常語である。' },
  'sarrapia': { es: 'El perfumista utilizó extracto de sarrapia para crear una fragancia cálida y almendrada.', ja: '調香師は温かみのあるアーモンドのような香りを作るためにトンカマメのエキスを使った。', trivia: '南米原産のマメ科植物トンカノキ（Dipteryx odorata）の種子（トンカビーン）から採れる香料素材で、英語では tonka bean と呼ばれる。クマリンを含む独特の甘い香りを持ち、欧州ではかつて食品香料として使用されたが、過剰摂取の懸念から現在は規制対象となっている国もある。' },
  'sarta': { es: 'El vendedor ofreció una sarta de excusas cuando le preguntaron por el retraso.', ja: '遅延について尋ねられると、販売員は言い訳を連発した。', trivia: 'スペイン語の動詞 sartar（串に刺す）またはラテン語 serta（つなぎ合わせたもの）に由来し、英語の string（ひと連なり）や series（連続）に概念的に対応する。「una sarta de mentiras（嘘の連発）」のような比喩的用法が日常会話で頻繁に見られる。' },
  'sartén': { es: 'Calienta un poco de aceite en la sartén antes de añadir las verduras.', ja: '野菜を加える前にフライパンに少し油を熱してください。', trivia: 'ラテン語の sartago（フライパン）に由来し、英語の frying pan や skillet に相当するが、英語との直接的な語源的つながりは薄い。「tener la sartén por el mango（フライパンの柄を持つ＝主導権を握る）」というスペイン語の慣用句は日本語の「さじを持つ」に近い表現である。' },
  'sastrería': { es: 'Encargó un traje a medida en una antigua sastrería del barrio.', ja: '彼は近所の老舗テーラーでオーダーメードのスーツを注文した。', trivia: 'スペイン語の sastre（仕立て師）＋接尾辞 -ería（店・業）から成る語で、sastre はラテン語 sartor（縫う人）に由来し、英語の tailor（仕立て師）とは語源は異なる（tailor はフランス語 tailleur から）。接尾辞 -ería は panadería（パン屋）などにも共通して使われる。' },
  'satélite': { es: 'El satélite artificial fue lanzado con éxito para monitorear el cambio climático.', ja: '人工衛星は気候変動を監視するために無事に打ち上げられた。', trivia: 'ラテン語の satelles（従者、護衛）に由来し、17世紀にケプラーが木星の衛星を説明するために使ったことで天文用語として定着した。英語の satellite と完全に同源で、現代では人工衛星・衛星都市・系列企業など比喩的用法も広い国際語である。' },
  'satén': { es: 'El vestido de satén brillaba bajo las luces de la sala de baile.', ja: 'サテンのドレスが舞踏場の照明の下で輝いていた。', trivia: 'アラビア語の zaytūnī（中国の港町・泉州に関連するという説がある）またはフランス語の satin を経由してスペイン語に入り、英語の satin と同源。光沢のある朱子織りの生地で、中世ヨーロッパでは中国絹の代名詞として贅沢品の象徴であった。' },
  'sátira': { es: 'La obra es una sátira brillante de la corrupción política contemporánea.', ja: 'その作品は現代の政治腐敗を鋭く風刺した傑作だ。', trivia: 'ラテン語の satira または satura（混合物、寄せ集め）に由来し、古代ローマで社会批評を混在させた文学ジャンルとして発展した。英語の satire と完全に同源で、ギリシャ神話の半獣神サテュロス（Satyr）と語源が混同されることもあるが、現代の語源学ではラテン語 satura が有力とされる。' },
  'satírica': { es: 'La revista publicó una columna satírica que criticaba duramente las decisiones del gobierno.', ja: 'その雑誌は政府の決定を厳しく批判する風刺的なコラムを掲載した。', trivia: 'ラテン語 satira（混合物、諷刺詩）に由来し、英語の satirical と同語源。古代ローマで発達した文学ジャンル「サトゥラ」がその起源で、様々な題材を混ぜ合わせた詩形式だった。' },
  'satírico': { es: 'El escritor era conocido por su estilo satírico y su habilidad para ridiculizar a los poderosos.', ja: 'その作家は風刺的な文体と権力者を嘲笑する才能で知られていた。', trivia: 'ラテン語 satira に由来し、英語 satirical と同語源。古代ローマの詩人ホラティウスやユウェナリスが代表的な風刺詩人として知られ、スペイン文学ではケベードが風刺文学の巨匠とされている。' },
  'satisfacción': { es: 'Terminar el proyecto con éxito le dio una gran satisfacción personal.', ja: 'プロジェクトを成功裏に完了させることで、彼は大きな個人的満足感を得た。', trivia: 'ラテン語 satisfacere（十分にする）から派生した名詞で、英語の satisfaction と同語源。「satis（十分に）＋facere（する）」という構造は英語の satisfy にもそのまま受け継がれており、法律用語としての「債務履行」の意味も両言語で共通している。' },
  'satisfactoria': { es: 'Los resultados del examen fueron satisfactorios y el profesor quedó contento con los alumnos.', ja: '試験の結果は満足のいくものであり、先生は生徒たちに満足していた。', trivia: 'ラテン語 satisfactorius に由来し、英語の satisfactory と同語源。ビジネスや学術評価において「合格基準を満たす」という意味合いは英語とスペイン語でほぼ同一であり、国際的なビジネス文書でも対応関係が明確な語だ。' },
  'satisfactorio': { es: 'El médico confirmó que el estado de salud del paciente era satisfactorio tras la operación.', ja: '医師は手術後の患者の健康状態は良好であると確認した。', trivia: 'ラテン語 satisfactorius に由来し、英語の satisfactory と同語源。「十分に（satis）行う（facere）」という語義から、要求を満たすという概念が両言語に共通して残っている。' },
  'satisfacer': { es: 'Es difícil satisfacer las necesidades de todos los clientes al mismo tiempo.', ja: 'すべての顧客のニーズを同時に満たすことは難しい。', trivia: 'ラテン語 satisfacere（satis「十分」＋facere「する」）に直接由来し、英語の satisfy と同語源。スペイン語では hacer（する）に由来する不規則動詞で、現在形の satisfago など hacer 型の活用を引き継いでいる点が特徴的だ。' },
  'saturación': { es: 'La saturación del mercado laboral hace que sea difícil encontrar trabajo para los recién graduados.', ja: '労働市場の飽和状態により、新卒者が仕事を見つけることは難しくなっている。', trivia: 'ラテン語 saturare（満たす）から派生した名詞で、英語の saturation と同語源。色彩理論での「彩度」という意味は英語と共通しており、デジタル画像処理や写真編集でも saturation／saturación として両言語で同義に使われる。' },
  'saturar': { es: 'El trabajo excesivo empezó a saturar al equipo y la productividad cayó notablemente.', ja: '過剰な業務がチームの処理能力を超え始め、生産性が著しく低下した。', trivia: 'ラテン語 saturare（十分に満たす、飽き飽きさせる）に由来し、英語の saturate と同語源。化学では溶液が溶質を限界まで溶かした状態を指し、英語・スペイン語ともに「飽和溶液」は solución saturada／saturated solution と表現する。' },
  'saucedal': { es: 'Caminamos por un saucedal a orillas del río para disfrutar de la sombra en verano.', ja: '夏の木陰を楽しもうと、私たちは川岸のヤナギ林を歩いた。', trivia: 'sauce（ヤナギ）に場所を示す接尾辞 -al または -eda が付いた派生語で、「ヤナギが群生する場所」を意味する。英語に直接対応する単語はなく、willow grove や willow thicket と言い換えるが、スペイン語はこうした植物群生地を一語で表す接尾辞が豊富だ。' },
  'sauce': { es: 'El sauce llorón junto al estanque reflejaba sus ramas largas en el agua tranquila.', ja: '池のほとりのシダレヤナギが、その長い枝を静かな水面に映していた。', trivia: 'ラテン語 salix（ヤナギ）に由来し、英語の willow とは語源が異なる（willow は古英語 welig に由来）。sauce llorón（泣くヤナギ）はシダレヤナギを指し、その垂れ下がる枝が涙を連想させることからこの名が付いた。' },
  'sauna': { es: 'Después del partido, los jugadores se relajaron en la sauna del estadio.', ja: '試合の後、選手たちはスタジアムのサウナでリラックスした。', trivia: 'フィンランド語 sauna がそのまま世界中の言語に借用された語で、スペイン語も英語も形・意味ともに同一。スペイン語では女性名詞として扱うことが多いが、男性名詞としても使われる珍しい語で、実際の会話では性が揺れることがある。' },
  'savia': { es: 'En primavera, la savia comienza a circular por los tallos y los árboles recuperan su vigor.', ja: '春になると樹液が茎を流れ始め、木々は活力を取り戻す。', trivia: 'ラテン語 sapa（煮詰めた果汁、新しい汁）に由来するとされ、英語の sap と同語源。「新鮮な血（人材）」を意味する比喩的用法 nueva savia は、英語の new blood とほぼ同じ概念で使われ、組織の若返りを表す際に両言語で平行的に用いられる。' },
  'saxofón': { es: 'El saxofón sonó con fuerza en el solo de jazz que emocionó a todo el público.', ja: 'ジャズのソロでサックスが力強く鳴り響き、観客全員を感動させた。', trivia: '19世紀のベルギー人楽器製作者アドルフ・サックス（Adolphe Sax）の名前に由来する比較的新しい語で、英語の saxophone と同語源かつ同発明家の名前を持つ。スペイン語では saxo と略されることも多く、口語では奏者自身を指す場合もある。' },
  'saxofonista': { es: 'La saxofonista interpretó un solo brillante que fue aplaudido por todos los asistentes.', ja: 'そのサックス奏者は見事なソロを演奏し、参加者全員から拍手を受けた。', trivia: 'saxofón に職業・行為者を示す接尾辞 -ista が付いた語で、英語の saxophonist と同語源の構造を持つ。-ista は男女同形（la saxofonista／el saxofonista）であり、英語の -ist に相当するスペイン語の代表的な接尾辞だ。' },
  'saxón': { es: 'El rey anglosaxón gobernó Inglaterra con sabiduría durante décadas.', ja: 'そのアングロサクソンの王は何十年もの間、知恵をもってイングランドを治めた。', trivia: 'ラテン語 Saxo（サクソン人）に由来し、英語の Saxon と同語源。サクソン人は現在のドイツ北部を発祥とするゲルマン民族で、5世紀以降ブリテン島に移住してアングロサクソン文化を形成した。スペイン語では anglosajon（アングロサクソン）の形でも頻用される。' },
  'saxona': { es: 'La escritora sajona fue una de las primeras mujeres en publicar novelas históricas en el siglo XIX.', ja: 'そのサクソン人の女性作家は、19世紀に歴史小説を出版した最初期の女性の一人だった。', trivia: 'saxón の女性形で、英語の Saxon（female）に相当。sajón／sajona という綴り揺れもあり、これはアラビア語を経由したスペイン語独自の音韻変化によるもので、英語 Saxon とは語形が異なる点が興味深い。' },
  'saya': { es: 'En el museo, pudimos ver una saya medieval muy bien conservada con bordados elaborados.', ja: '博物館では、精巧な刺繍が施された保存状態の良い中世のガウンを見ることができた。', trivia: 'ラテン語 saga または Celtic 起源とされ、中世ヨーロッパで広く着用された上衣を指す。英語には直接対応する単語がなく、歴史文書では tunic や gown と訳されることが多い。現代スペイン語では一部のラテンアメリカ地域でロングスカートを指す方言的用法も残っている。' },
  'sayal': { es: 'Los monjes vestían sayal como símbolo de humildad y renuncia a los bienes materiales.', ja: '修道士たちは謙虚さと物質的な富への放棄の象徴として粗布の衣をまとっていた。', trivia: '語源は不明確だが、アラビア語起源とも考えられる中世スペイン語由来の語。英語に直接対応する単語はなく、sackcloth や coarse woolen cloth と説明される。中世の托鉢修道士や清貧を象徴する衣として文学作品にもしばしば登場する。' },
  'sayo': { es: 'El campesino llevaba un sayo desgastado que le había servido durante muchos inviernos.', ja: 'その農民は何度もの冬を乗り越えてきた使い古した外套をまとっていた。', trivia: 'ラテン語 sagum（ローマ兵の外套）に由来し、中世スペインで広く使われた上衣を指す。英語の sagum や smock と語源的に関連するとされる。「hacer de su capa un sayo（自分のマントから外套を作る）」という慣用句は「自分の裁量で行動する」という意味で今も使われる。' },
  'sazón': { es: 'Añade la sal a la sazón adecuada para que la carne quede en su punto.', ja: '肉がちょうどよい仕上がりになるよう、適切なタイミングで塩を加えてください。', trivia: 'ラテン語 satio（種まき、時節）に由来し、英語の season と同語源。英語の season が「季節」「調味する」の両義を持つように、スペイン語の sazón も「熟し頃」「調味」「絶好のタイミング」という意味を持ち、農業社会における「適切な時節」という概念が料理にも転用されたことがわかる。' },
  'sazonada': { es: 'La carne sazonada con hierbas aromáticas desprendía un aroma irresistible durante la cocción.', ja: '香草で味付けされた肉は、調理中に抗いがたい香りを放っていた。', trivia: 'sazonar の過去分詞形容詞で、英語の seasoned に相当。英語でも seasoned は「味付けされた」と「経験豊富な（a seasoned professional）」の二義を持つが、スペイン語の sazonado も「洗練された・時宜を得た」という比喩的用法が存在し、両言語で意味の広がり方が類似している。' },
  'sazonado': { es: 'El pollo sazonado con pimentón y ajo resultó ser el plato estrella de la cena.', ja: 'パプリカとニンニクで味付けされた鶏肉は、その夕食の目玉料理となった。', trivia: 'sazonar の過去分詞形容詞（男性形）で、英語の seasoned と同語源・同構造。「経験を積んだ」という比喩的意味でも使われる点は英語の seasoned veteran（ベテラン）と対応しており、料理から人間の成熟・円熟へと意味が拡張した例として興味深い。' },
  'sazonador': { es: 'El sazonador de hierbas italianas que compramos en el mercado mejoró mucho el sabor de la pizza.', ja: '市場で買ったイタリアンハーブのシーズニングで、ピザの味がぐんと良くなった。', trivia: 'sazonar に行為者・道具を示す接尾辞 -dor が付いた名詞で、英語の seasoning や condiment に相当。英語の -er/-or と同様に、スペイン語の -dor は動詞から「行為をするもの・道具」を作る生産的な接尾辞で、調理道具や料理用語に多く見られる。' },
  'sazonar': { es: 'Es importante sazonar la pasta con sal antes de cocerla para que quede más sabrosa.', ja: 'パスタをより美味しく仕上げるために、茹でる前に塩で味付けすることが大切です。', trivia: 'ラテン語 satio（時節）に由来し、英語の season（調味する）と同語源。英語では「to season a dish（料理に味付けする）」と表現するように、スペイン語も同じ農業的な時節の概念から「食材を適切に整える」という意味が生まれた。規則的な -ar 動詞として活用するため学習者に比較的扱いやすい語だ。' },
  'se': { es: 'Cuando los amigos se vieron después de años, se abrazaron con emoción.', ja: '何年かぶりに友人たちが再会すると、感動しながら抱き合った。', trivia: 'ラテン語の再帰代名詞 se に由来し、英語の himself／herself／itself／themselves に相当するが、スペイン語の se はこれら全てを一語でカバーする。さらに受身文・無人称文・相互動作・間接目的語代替と多機能を持ち、英語と異なりスペイン語では受身表現に be 動詞を使わず se を使うことが多い点が大きな文法的特徴だ。' },
  'sebo': { es: 'El sebo de vaca se usaba tradicionalmente para hacer velas y jabón.', ja: '牛の脂は昔からろうそくや石鹸を作るために使われていた。', trivia: 'ラテン語 sebum（脂肪）に由来し、英語の sebum（皮脂）や tallow（タロー）と同根。医学用語 seborrea（脂漏症）もこの語根から派生している。' },
  'seborrea': { es: 'El médico le diagnosticó seborrea y le recetó un champú especial.', ja: '医師は彼に脂漏症と診断し、特別なシャンプーを処方した。', trivia: 'sebo（脂）＋ラテン語 -rrhea（流れる）の合成語で、英語の seborrhea と同形。皮脂腺が過剰に機能する状態を指し、フケ症の一因にもなる。' },
  'seborreica': { es: 'La dermatitis seborreica es una afección crónica de la piel que causa enrojecimiento y descamación.', ja: '脂漏性皮膚炎は皮膚の慢性疾患で、赤みやフケを引き起こす。', trivia: 'seborrea に形容詞語尾 -ico/a を付けた派生語で、英語の seborrheic に対応。主に医学・皮膚科学の文脈で用いられる。' },
  'seborreico': { es: 'El cuero cabelludo seborreico necesita cuidados especiales con productos adecuados.', ja: '脂漏性の頭皮は適切な製品による特別なケアが必要だ。', trivia: 'seborreica の男性形。ラテン語 sebum（脂）とギリシャ語 rhoia（流れ）を組み合わせた学術用語で、英語 seborrheic と同源である。' },
  'seca': { es: 'La seca que azotó la región durante tres años arruinó la mayoría de los cultivos.', ja: '3年間その地域を襲った干ばつにより、ほとんどの農作物が壊滅した。', trivia: 'ラテン語 siccus（乾いた）に由来し、形容詞 seco の女性形でもある。英語 dry や drought と語義が重なるが、名詞として「干ばつ」を指す用法はスペイン語独自の展開。' },
  'secamente': { es: '—No me interesa —respondió ella secamente sin levantar la vista.', ja: '「興味ありません」と彼女は目も上げずぶっきらぼうに答えた。', trivia: 'seco（乾いた・そっけない）に副詞語尾 -mente を加えた派生語。英語 dryly と意味・構造ともに対応しており、「乾燥した」から「冷淡な」への意味拡張も両言語で共通している。' },
  'secadal': { es: 'En ese secadal apenas crecen algunas plantas xerófilas adaptadas al clima extremo.', ja: 'その乾燥地には極端な気候に適応した乾生植物がわずかに生えているだけだ。', trivia: 'seco（乾いた）に集合・場所を示す接尾辞 -al を付けた語。英語に直訳する対応語はなく「dry land」などと言い換える。スペインの半乾燥地帯を描写する文学や農業文書に見られる。' },
  'secadero': { es: 'Los tomates se colocan en el secadero para deshidratarse bajo el sol de agosto.', ja: 'トマトは8月の太陽の下で乾燥させるために乾燥場に並べられる。', trivia: 'secar（乾かす）＋場所・器具を示す接尾辞 -dero の合成語。英語の drying room や smokehouse に相当し、ハモン・セラーノなどスペインの食文化と深く結びついている。' },
  'secadillo': { es: 'En la pastelería tradicional andaluza, los secadillos se preparan con almendras y miel.', ja: 'アンダルシアの伝統菓子店では、セカディーリョスはアーモンドとはちみつで作られる。', trivia: 'secado（乾燥）の指小辞形。焼いた後に乾燥させる製法に由来する名前で、英語には直接対応する語がない。スペイン南部、特にアンダルシア地方の郷土菓子として知られる。' },
  'secado': { es: 'El secado al aire libre de la ropa tarda más tiempo en invierno.', ja: '冬は衣類の外干し乾燥により時間がかかる。', trivia: '動詞 secar の過去分詞が名詞化したもの。英語の drying や dehydration に対応する。食品保存技術としての乾燥（secado solar など）はスペイン語圏の農業・食品加工で重要な概念。' },
  'secadora': { es: 'Metí las sábanas en la secadora porque iba a llover toda la tarde.', ja: '午後中ずっと雨が降りそうだったので、シーツを乾燥機に入れた。', trivia: 'secar（乾かす）に行為者・器具を示す接尾辞 -dora（女性形）を付けた語。英語の dryer/drier に意味・構造が対応する。スペインでは洗濯機（lavadora）とセットで語られることが多い家電。' },
  'secador': { es: 'Usé el secador para secarme el pelo antes de salir a la reunión.', ja: '会議に出かける前に髪をドライヤーで乾かした。', trivia: 'secar に行為者・器具を示す接尾辞 -dor（男性形）を付けた語で、英語の hair dryer に相当。secadora（乾燥機）と同根だが、日常的には「ヘアドライヤー」を指すことが多い。' },
  'secafirmas': { es: 'En la oficina antigua había un secafirmas en cada escritorio para absorber la tinta de las cartas.', ja: '昔の事務所では、手紙のインクを吸い取るために各机に吸い取り紙が置いてあった。', trivia: 'secar（乾かす）＋firmas（署名）の複合語で「署名を乾かすもの」の意。英語の blotter や sand shaker に対応する。万年筆が主流だった時代の必需品で、デジタル化以前の文書文化を映す語。' },
  'secamuelle': { es: 'Ese secamuelle pasaba los días jugando a las cartas en el muelle en lugar de buscar trabajo.', ja: 'そのゴロツキは仕事を探す代わりに、波止場でトランプをして日々を過ごしていた。', trivia: 'secar（乾かす）＋muelle（波止場）の複合語で、字義通りには「波止場を乾かす者」。アルゼンチンの口語表現で、英語の dock loafer や layabout に相当する。港湾労働文化の中で生まれた皮肉的な俗語。' },
  'secano': { es: 'En esta zona de Castilla, los agricultores cultivan trigo de secano sin sistemas de riego.', ja: 'カスティーリャのこの地区では、農家が灌漑なしに乾地農法で小麦を栽培している。', trivia: 'ラテン語 siccanus（乾いた土地）に由来する語で、英語の dryland や rainfed land に相当。スペインは国土の多くが半乾燥気候のため、secano（乾地）と regadío（灌漑地）の区別は農業政策上きわめて重要。' },
  'secante': { es: 'El profesor dibujó una secante al círculo para explicar el teorema de las cuerdas.', ja: '教師は弦の定理を説明するために円に割線を引いた。', trivia: 'ラテン語 secare（切る）の現在分詞 secans に由来し、英語の secant と同源。数学では「円を2点で切る直線」を指し、三角関数の正割（1/cos）も同じ語で表す。' },
  'secansa': { es: 'La secansa del verano dejó los campos sin una brizna de hierba verde.', ja: '夏の乾燥が野原から緑の草の一本一本まで奪い去った。', trivia: 'seco（乾いた）に抽象名詞語尾 -anza を付けた古語で、現代語の sequedad に相当。英語 dryness に対応するが、現代スペイン語ではほとんど使われない古風な表現として残っている。' },
  'secanza': { es: 'La secanza prolongada obligó a los pastores a mover el ganado hacia tierras más húmedas.', ja: '長引く乾燥により、牧人たちは家畜をより湿潤な土地へ移動させざるを得なかった。', trivia: 'secansa の表記上のバリアントで、同じくラテン語 siccus（乾いた）に由来する古語。中世スペイン語文書に見られる語で、現代英語に直接対応する語はなく「dryness, drought」で言い換える。' },
  'secaplatos': { es: 'Coloca los vasos en el secaplatos después de lavarlos para que se escurran bien.', ja: 'グラスを洗った後、よく水気が切れるように水切りラックに置いてください。', trivia: 'secar（乾かす）＋platos（皿）の複合語で「皿を乾かすもの」の意。英語の dish rack や drying rack に対応する。スペイン語では台所用品に動詞＋名詞の複合語が多く、escurreplatos とも言う。' },
  'secar': { es: 'Después de bañar al perro, hay que secarlo bien con una toalla para que no tenga frío.', ja: '犬を入浴させた後は、寒くならないようにタオルでよく乾かしてやらなければならない。', trivia: 'ラテン語 siccare（乾かす）に由来し、英語の dry や wipe と意味が重なる。再帰形 secarse で「乾く・乾かす」となり、比喩的に「才能が枯渇する」意味でも使われる点が英語 dry up と対応する。' },
  'sección': { es: 'La sección de deportes del periódico ofrece un análisis detallado del partido de ayer.', ja: '新聞のスポーツ欄は昨日の試合の詳細な分析を提供している。', trivia: 'ラテン語 sectio（切断）に由来し、英語の section と同源・同義。secare（切る）という動詞語根を共有しており、「切り取った部分」という原義が組織の「部門」や図学の「断面」へと拡張した。' },
  'seccionable': { es: 'Este armario modular es completamente seccionable y se adapta a cualquier espacio.', ja: 'このモジュール式クローゼットは完全に分割可能で、どんな空間にも対応できる。', trivia: 'seccionar（分割する）に可能を示す形容詞語尾 -able を付けた派生語で、英語の sectionable や divisible に相当。建築・家具業界でモジュール設計を説明する際によく用いられる。' },
  'seccional': { es: 'La seccional del sindicato convocó una asamblea de emergencia para tratar el conflicto laboral.', ja: '労働組合の支部は労働争議を協議するために緊急総会を招集した。', trivia: 'sección に形容詞語尾 -al を付けた語で、英語の sectional に対応する。ラテンアメリカでは「地区支部」「分署」の意味で名詞としても頻繁に使われ、英語の branch office に相当する用法が発達した。' },
  'seccionar': { es: 'El cirujano tuvo que seccionar el tendón dañado para reparar la lesión correctamente.', ja: '外科医は損傷を正しく修復するために傷ついた腱を切断しなければならなかった。', trivia: 'ラテン語 secare（切る）に由来する動詞で、英語の section（動詞用法）や dissect に対応する。医学・工学の両分野で使われ、「切断する」という具体的な動作と「区分する」という抽象的な意味を兼ねる。' },
  'seccionamiento': { es: 'El seccionamiento de la red eléctrica permitió aislar el área afectada por la avería.', ja: '電気網の遮断により、故障の影響を受けた地域を孤立させることができた。', trivia: 'seccionar に名詞化語尾 -miento を付けた語で、英語の sectioning や isolation に相当。電気工学では回路の一部を切り離す操作を指し、ラテン語 secare（切る）を語根とする技術用語族の一員。' },
  'seco': { es: 'El verano pasado fue tan seco que los ríos se quedaron casi sin agua.', ja: '去年の夏はとても乾燥していて、川がほぼ干上がってしまった。', trivia: 'ラテン語 siccus（乾いた）に由来し、英語の desiccate（乾燥させる）と語源を共有する。ワインの「辛口」を意味する sec（フランス語）も同じ語根から来ており、スペイン語でも辛口ワインは vino seco と言う。' },
  'secreta': { es: 'La secreta se rezaba en voz baja por el sacerdote durante la misa.', ja: 'ミサの間、司祭は密祷を低い声で唱えた。', trivia: 'ラテン語 secreta（隠されたもの）に由来し、英語の secret と同語源。カトリック典礼用語としての「密祷」のほか、口語では私服警官を指す隠語としても使われた歴史がある。' },
  'secretamente': { es: 'Los dos se reunieron secretamente para planear la sorpresa.', ja: '二人はサプライズを計画するために密かに会った。', trivia: 'secreto（秘密の）にラテン語由来の副詞語尾 -mente を付けた語で、英語の secretly に直接対応する。語根はラテン語 secretus（分けられた、隠された）から来ており、secernere（分離する）と関連する。' },
  'secretaría': { es: 'Tienes que presentar tu solicitud en la secretaría del departamento.', ja: '学科の事務局に申請書を提出しなければならない。', trivia: '中世ラテン語 secretarius（秘密を保持する者）に由来し、英語の secretariat と同語源。もともと「秘密を預かる場所」という意味を持ち、やがて行政機関の事務室全体を指すようになった。' },
  'secretariado': { es: 'Ella estudió secretariado para poder trabajar en una empresa internacional.', ja: '彼女は国際企業で働けるよう秘書養成コースを学んだ。', trivia: 'secretario に集合・職能を表す接尾辞 -ado を加えた語で、英語の secretariat や secretaryship に相当する。国連などの国際機関では事務局全体を指す重要な行政用語として使われる。' },
  'secretaria': { es: 'La secretaria organizó todas las reuniones del director con mucha eficiencia.', ja: '秘書は取締役のすべての会議を非常に効率よく手配した。', trivia: 'ラテン語 secretarius（秘密の保持者）の女性形で、英語の secretary と同語源。中世ヨーロッパでは主君の秘密文書を管理する職を指し、現代では行政の女性書記官や秘書官も含む幅広い語となっている。' },
  'secretario': { es: 'El secretario general de la ONU convocó una reunión de emergencia.', ja: '国連事務総長は緊急会合を招集した。', trivia: 'ラテン語 secretarius に由来し、英語の secretary と完全に同語源。英語では Secretary of State が外務大臣または国務長官を意味するように、スペイン語の secretario も国際機関や政府の高位職に用いられる。' },
  'secretear': { es: 'Los niños estaban secreteando en el rincón y no querían que los adultos los oyeran.', ja: '子供たちは隅でひそひそ話をしていて、大人に聞かれたくなかった。', trivia: 'secreto（秘密）に反復・継続を示す接尾辞 -ear を加えた派生動詞で、英語には直接対応する一語がなく whisper や talk secretly と訳される。スペイン語らしい口語的表現で、特にラテンアメリカで広く使われる。' },
  'secreteo': { es: 'Había tanto secreteo entre los empleados que el jefe se puso nervioso.', ja: '従業員の間でひそひそ話が絶えず、上司は不安になった。', trivia: '動詞 secretear の名詞形で、英語には対応する一語がなく whispering や gossip に近い。スペイン語では -eo という接尾辞が動詞の反復的行為を名詞化する際によく使われ、manoseo（手でいじること）などと同じパターンを持つ。' },
  'secreter': { es: 'El antiguo secreter de madera estaba lleno de cartas y documentos personales.', ja: '古い木製のライティングデスクは手紙や個人的な書類でいっぱいだった。', trivia: 'フランス語 secrétaire（書き物机）を経由して英語 escritoire や secretaire と同様に普及した語で、もとはラテン語 secretarius に由来する。鍵のかかる引き出しや蛇腹の天板を持つこの家具は、文字通り「秘密を守る机」として貴族社会で愛用された。' },
  'secreto': { es: 'Guarda este secreto con cuidado porque nadie más debe saberlo.', ja: 'これは誰も知ってはいけない秘密なので、しっかり守ってください。', trivia: 'ラテン語 secretus（分けられた、隠された）に由来し、英語の secret と完全に同語源。語根の se-（分離）＋ cernere（ふるい分ける）という構造から、「人々から選り分けられて隠された情報」という本来の意味が透けて見える。' },
  'secretor': { es: 'El tejido secretor de las glándulas salivales produce enzimas digestivas.', ja: '唾液腺の分泌組織は消化酵素を産生する。', trivia: 'ラテン語 secretus（分離された）＋ 行為者接尾辞 -or から成り、英語の secretory と同語源。生理学・医学用語として腺や細胞が物質を分泌する性質を表し、日本語の「分泌性の」に対応する専門語。' },
  'secretoria': { es: 'La función secretoria del páncreas regula los niveles de glucosa en la sangre.', ja: '膵臓の分泌機能は血糖値を調節する。', trivia: 'secretor の女性形で、ラテン語 secretorius（分泌に関する）に由来する。英語の secretory と同語源であり、主に女性名詞（glándula 腺、función 機能など）と組み合わせて医学・生物学文献で使用される。' },
  'secreción': { es: 'La secreción de adrenalina aumenta cuando el cuerpo percibe una amenaza.', ja: '体が脅威を感知すると、アドレナリンの分泌が増加する。', trivia: 'ラテン語 secretio（分離、分泌）に由来し、英語の secretion と同語源。語根 secernere（分けて出す）から来ており、もとは「分離する行為」を意味していたが、医学の発展とともに「腺や細胞が物質を放出する過程」を指す専門用語として定着した。' },
  'secta': { es: 'Algunos jóvenes vulnerables son captados por sectas que los manipulan psicológicamente.', ja: '脆弱な若者の中には、心理的に操られるカルト集団に引き込まれる者もいる。', trivia: 'ラテン語 secta（追随する道、派）に由来し、英語の sect と同語源。語根は sequi（従う）で、英語の sequence や sequel とも遠縁にある。もとは哲学・宗教の「学派」を中立的に指したが、現代では否定的なニュアンスが強い。' },
  'sectarismo': { es: 'El sectarismo político impide el diálogo entre los diferentes grupos sociales.', ja: '政治的党派主義が、異なる社会集団間の対話を妨げている。', trivia: 'secta（宗派）に形容詞語尾 -ario と抽象名詞語尾 -ismo を組み合わせた語で、英語の sectarianism と同構造・同意味を持つ。もとは宗教的分派主義を指したが、現代では政治・イデオロギー領域での排他的態度全般を表すようになった。' },
  'sectaria': { es: 'Su actitud sectaria le impedía escuchar opiniones distintas a las de su grupo.', ja: '彼女の党派的な態度が、自分のグループ以外の意見を聞くことを妨げていた。', trivia: 'secta（宗派）に由来し、英語の sectarian と同語源。ラテン語 sectarius（派に属する者）から来ており、もとは宗教的文脈で使われたが、現在は政治や社会運動における排他的・狂信的な立場を指して幅広く使われる。' },
  'sectario': { es: 'Los líderes sectarios suelen aislar a sus seguidores del mundo exterior.', ja: 'セクト主義的な指導者は、信者を外の世界から孤立させる傾向がある。', trivia: 'sectaria の男性形で、ラテン語 sectarius に由来する。英語の sectarian と同語源であり、宗教・政治を問わず「閉じた集団に帰属し外部を排除する者」を指す。現代社会では特にカルト問題の文脈でよく登場する語。' },
  'sector': { es: 'El sector tecnológico ha crecido enormemente en los últimos diez años.', ja: 'テクノロジー部門はここ10年で飛躍的に成長した。', trivia: 'ラテン語 sector（切る者）に由来し、英語の sector と同語源。語根は secare（切る）で、英語の section や insect（虫＝「切り込まれたもの」）とも親戚関係にある。数学の「扇形」も同じ語で表す。' },
  'sectorial': { es: 'El gobierno anunció una política sectorial para apoyar a la industria turística.', ja: '政府は観光産業を支援するための業界別政策を発表した。', trivia: 'sector に形容詞語尾 -al を加えた語で、英語の sectoral と同語源・同構造。経済・行政の文脈で「特定分野に特化した」という意味で使われ、política sectorial（業界別政策）や análisis sectorial（セクター分析）などのコロケーションが頻出する。' },
  'secuaz': { es: 'El villano fue arrestado junto con todos sus secuaces.', ja: '悪役はすべての手下とともに逮捕された。', trivia: 'ラテン語 sequax（追い従う者）に由来し、語根は sequi（従う）。英語の henchman に意味が近いが、語源的には sequence（順序）や sequel（続編）と同じ根を持つ。スペイン語では男女同形の名詞で、否定的な含意を強く持つ語。' },
  'secuela': { es: 'Muchos pacientes sufren secuelas neurológicas después de haber tenido COVID-19.', ja: '多くの患者がCOVID-19に罹患した後、神経系の後遺症に苦しんでいる。', trivia: 'ラテン語 sequela（続くもの）に由来し、英語の sequel と同語源。映画・小説の「続編」という意味を持つと同時に、医学用語として病気や事故の「後遺症」を指す点が特徴的で、英語 sequel が主に娯楽分野で使われるのとは異なる用法が発達している。' },
  'secuencia': { es: 'La maestra explicó la secuencia de pasos necesarios para resolver el problema.', ja: '先生は問題を解くために必要な手順の流れを説明した。', trivia: '中世ラテン語 sequentia（続くこと）に由来し、英語の sequence と同語源・ほぼ同形。語根の sequi（従う、続く）は英語の sequel、consequence、obsequious（従順な）などとも共通する豊かな語族を形成している。' },
  'secuenciación': { es: 'La secuenciación del genoma humano fue un logro científico histórico.', ja: 'ヒトゲノムの塩基配列解読は歴史的な科学的成果だった。', trivia: 'secuencia に動詞化語尾 -ar（secuenciar）と名詞語尾 -ción を加えた語で、英語の sequencing と同語源・同構造。ゲノム解析の普及とともに生物学の最重要用語となり、次世代シーケンシング（secuenciación de nueva generación）という形でも広く使われる。' },
  'secuencial': { es: 'El procesador ejecuta las instrucciones de forma secuencial, una tras otra.', ja: 'プロセッサは命令を順次、一つひとつ実行する。', trivia: 'ラテン語 sequentia（続くこと）に由来し、英語 sequential と同語源。情報技術や論理学で「順番通りに処理する」という意味で広く使われる。' },
  'secuencialmente': { es: 'Las tareas deben completarse secuencialmente para evitar errores en el sistema.', ja: 'システムのエラーを避けるため、タスクは順番に完了させなければならない。', trivia: 'secuencial（形容詞）に副詞語尾 -mente を付けた派生語で、英語 sequentially に対応する。ラテン語 sequi（続く）を語根とする。' },
  'secuestradora': { es: 'La secuestradora exigió un rescate millonario a la familia de la víctima.', ja: '女性誘拐犯は被害者の家族に高額の身代金を要求した。', trivia: '動詞 secuestrar から派生した行為者名詞で、ラテン語 sequestrare（預ける、没収する）が語源。英語 kidnapper とは異なり、ハイジャックや法的差し押さえの行為者も指す。' },
  'secuestrador': { es: 'El secuestrador fue capturado por la policía después de dos días de búsqueda.', ja: '誘拐犯は2日間の捜索の末、警察に捕まった。', trivia: 'secuestradora の男性形。英語 kidnapper はラテン語由来だが、secuestrador はラテン語 sequestrare（仲介者に預ける）という法律用語から犯罪用語へと転じた歴史を持つ。' },
  'secuestrar': { es: 'Los piratas intentaron secuestrar el barco para pedir un rescate.', ja: '海賊たちは身代金を要求するために船をハイジャックしようとした。', trivia: 'ラテン語 sequestrare（仲裁人に物を預ける）が語源で、英語 sequester と同語源。「誘拐する」「差し押さえる」両方の意味を持つ点が英語 kidnap とは異なる。' },
  'secuestro': { es: 'El secuestro del empresario conmocionó a toda la ciudad.', ja: 'その実業家の誘拐事件は街全体に衝撃を与えた。', trivia: 'ラテン語 sequestratio（差し押さえ）を語源とし、英語 sequestration と同根。スペイン語では誘拐・拉致・ハイジャックまで幅広く使える多義語である。' },
  'secular': { es: 'La educación secular garantiza que las escuelas no promuevan ninguna religión.', ja: '世俗教育は学校がいかなる宗教も推進しないことを保証する。', trivia: 'ラテン語 saeculum（時代、世紀）が語源で、英語 secular と完全に同語源・同義。「百年に一度の」という原義から「宗教と切り離された」という意味に発展した。' },
  'secularidad': { es: 'La secularidad del Estado es uno de los principios fundamentales de la democracia moderna.', ja: '国家の世俗性は現代民主主義の基本原則の一つである。', trivia: 'secular に名詞語尾 -idad を付けた抽象名詞で、英語の secularity に対応する。政教分離が憲法上保障されている国家のあり方を指す法律・政治用語として使われる。' },
  'secularización': { es: 'La secularización de la sociedad europea ocurrió gradualmente durante los siglos XIX y XX.', ja: 'ヨーロッパ社会の世俗化は19〜20世紀にかけて徐々に進んだ。', trivia: 'ラテン語 saeculum を語根とし、英語 secularization と同語源・同形。宗教社会学の重要概念で、近代化に伴い宗教的権威が社会的影響力を失う過程を指す。' },
  'secularizar': { es: 'El gobierno decidió secularizar los cementerios y las escuelas en el siglo XIX.', ja: '政府は19世紀に墓地と学校を世俗化することを決定した。', trivia: '英語 secularize と同語源・同形で、ラテン語 saeculum（世代、世俗）から派生。スペインでは19世紀の自由主義改革で教会財産の国有化（desamortización）と連動して使われた歴史的文脈がある。' },
  'secundar': { es: 'Los trabajadores decidieron secundar la huelga convocada por el sindicato.', ja: '労働者たちは労働組合が呼びかけたストライキに呼応することを決めた。', trivia: 'ラテン語 secundare（助ける、支持する）が語源で、英語の動詞 second（提案を支持する）と同語源。会議での「動議を支持する」という意味での英語 second と用法が類似している。' },
  'secundaria': { es: 'Mi hija terminó la secundaria con excelentes calificaciones y quiere estudiar medicina.', ja: '娘は優秀な成績で中等学校を卒業し、医学を学びたいと思っている。', trivia: 'ラテン語 secundarius（二番目の）に由来し、英語 secondary school と同語源。スペイン語圏では Educación Secundaria Obligatoria（ESO）と呼ばれる12〜16歳の義務教育段階を指す。' },
  'secundariamente': { es: 'El cansancio aparece secundariamente como efecto del medicamento, no como síntoma principal.', ja: '疲労は主症状としてではなく、薬の副次的な効果として現れる。', trivia: 'secundario に副詞語尾 -mente を付けた形で、英語 secondarily に対応する。ラテン語 secundus（二番目の）を語根とし、「優先順位が二番目に」というニュアンスを持つ。' },
  'secundario': { es: 'El actor recibió un premio por su papel secundario en la película.', ja: 'その俳優は映画での助演により賞を受賞した。', trivia: 'ラテン語 secundarius（二番目の）が語源で、英語 secondary と同語源。映画・演劇用語として「脇役」を意味する papel secundario は、英語の supporting role に相当する表現として広く使われる。' },
  'seda': { es: 'El vestido de seda brillaba suavemente bajo las luces de la fiesta.', ja: '絹のドレスはパーティーの照明の下でやわらかく輝いていた。', trivia: 'ラテン語 saeta（剛毛、繊維）が語源で、英語 silk はゲルマン語系（古英語 seoloc）のため語源は異なる。「como la seda（絹のように）」は「なめらかに、순調に」を意味する慣用句として頻出する。' },
  'sedación': { es: 'El médico aplicó sedación ligera al paciente antes de realizar la operación menor.', ja: '医師は小手術を行う前に患者に軽い鎮静を施した。', trivia: 'ラテン語 sedare（静める、落ち着かせる）に由来し、英語 sedation と同語源・同形。同じ語根から sedar（鎮静剤を投与する）や sedante（鎮静剤）も派生した医学用語群を形成する。' },
  'sedante': { es: 'El médico recetó un sedante suave para ayudar al paciente a dormir mejor.', ja: '医師は患者がよく眠れるように軽い鎮静剤を処方した。', trivia: 'ラテン語 sedare（静める）の現在分詞形に由来し、英語 sedative と同語源。形容詞・名詞両方で使える点も英語と共通しており、música sedante（安らぎを与える音楽）のように比喩的にも使われる。' },
  'sedar': { es: 'El veterinario tuvo que sedar al animal para poder examinarlo con seguridad.', ja: '獣医は安全に診察するために動物に鎮静剤を投与しなければならなかった。', trivia: 'ラテン語 sedare（静める、落ち着かせる）が語源で、英語 sedate と同語源・同形。このラテン語動詞は sedeo（座る）とも関連し、「静止させる」という基本的なイメージを共有する。' },
  'sede': { es: 'La sede de la empresa está ubicada en el centro de Madrid.', ja: 'その会社の本社はマドリード中心部に位置している。', trivia: 'ラテン語 sedes（座席、居場所）が語源で、英語 see（司教座）と同語源。Holy See（ローマ教皇庁）の See がまさにこの語に相当し、スポーツ・イベントの「開催地」にも使われる多義語である。' },
  'sedentarismo': { es: 'El sedentarismo es uno de los principales factores de riesgo para las enfermedades cardiovasculares.', ja: '座りがちな生活様式は心血管疾患の主要リスク因子の一つである。', trivia: 'ラテン語 sedere（座る）に由来し、英語 sedentary lifestyle に対応するが、スペイン語では名詞形 sedentarismo が日常的に使われる。英語では sedentariness より sedentary lifestyle という表現が一般的で、スペイン語の方が語彙化が進んでいる。' },
  'sedentaria': { es: 'Ella lleva una vida sedentaria desde que trabaja desde casa todo el día.', ja: '彼女は一日中在宅勤務をしていて、座りがちな生活を送っている。', trivia: 'ラテン語 sedentarius（座っている人）が語源で、英語 sedentary と同語源。古代ローマでは「座って仕事をする職人」を指す言葉だったが、現代では運動不足の生活様式を指す医学・健康分野の用語として定着した。' },
  'sedentario': { es: 'Los trabajos de oficina tienden a ser muy sedentarios, lo que puede afectar la salud.', ja: 'オフィスワークは非常に座りがちになる傾向があり、健康に影響を与えることがある。', trivia: 'sedentaria の男性形で、英語 sedentary と同語源のラテン語 sedentarius から来ている。歴史的には遊牧民（nómada）の対義語として「定住者」を意味し、農耕文明の発展とともに定住生活を指す語として使われてきた。' },
  'sediento': { es: 'Llegamos al refugio sedientos y exhaustos tras horas de caminata por el desierto.', ja: '砂漠を何時間も歩いた後、私たちは喉が渇いて疲労困憊した状態で避難所に到着した。', trivia: 'ラテン語 sitiens（渇いている）の俗ラテン語形 *seditientem から変化したとされ、英語 thirsty とは異なりゲルマン語系ではなくラテン語由来。「sediento de poder（権力に飢えた）」のように比喩的に使われる表現も豊富である。' },
  'sedimentación': { es: 'La sedimentación de partículas en el río formó un delta en su desembocadura.', ja: '川での粒子の堆積により、河口にデルタが形成された。', trivia: 'ラテン語 sedimentum（沈殿物）に由来し、英語 sedimentation と同語源・同形。地質学・化学・生物学にまたがる重要な科学用語で、土壌形成や化石の埋積など自然現象の説明に不可欠な概念である。' },
  'sedimentar': { es: 'Las partículas de arena tardaron siglos en sedimentarse en el fondo del lago.', ja: '砂の粒子が湖底に堆積するまでに何世紀もかかった。', trivia: 'ラテン語 sedimentum（沈殿物）＋動詞語尾 -ar から成り、英語 sediment（動詞用法）と同語源。再帰形 sedimentarse で「自然に沈殿する」を表し、比喩的に「知識や経験が積み重なる」という意味でも使われる点が興味深い。' },
  'sedimento': { es: 'El vino tinto de larga crianza suele dejar sedimento en el fondo de la botella.', ja: '長期熟成の赤ワインは、瓶の底に沈殿物を残すことが多い。', trivia: 'ラテン語 sedimentum（「座ること、沈殿」）に由来し、動詞 sedere（「座る」）と同根。英語の sediment と直接対応し、地質学・醸造学など多くの分野で共通して使われる国際語である。' },
  'seducción': { es: 'La seducción de los colores brillantes en el escaparate logró atraer a muchos clientes.', ja: 'ショーウィンドウの鮮やかな色彩の魅力が、多くの客を引き寄せることに成功した。', trivia: 'ラテン語 seductio（「引き離すこと」）から来ており、se-（離れて）＋ ducere（「導く」）が語源。英語の seduction と同語源で、もとは「誤った道へ引き込む」という否定的な含意が強かったが、現代では中立的・肯定的な「魅了」の意味でも広く使われる。' },
  'seducir': { es: 'La oferta de trabajo me sedujo desde el principio por sus condiciones tan favorables.', ja: 'その仕事のオファーは、非常に有利な条件ゆえに最初から私を惹きつけた。', trivia: 'ラテン語 seducere（「わきへ連れ去る」）が語源で、se-＋ducere（「導く」）から成る。英語の seduce と同根であり、現代スペイン語では「誘惑する」だけでなく「（提案などが）魅力的に感じる」という軽い意味でも日常的に用いられる。' },
  'seductora': { es: 'La música de ese compositor tiene una melodía seductora que es difícil de olvidar.', ja: 'その作曲家の音楽には、忘れがたい魅惑的なメロディーがある。', trivia: 'seducir（誘惑する）の語幹に -tor/-tora という行為者を表すラテン語接尾辞が付いた形容詞・名詞。英語の seductive（形容詞）や seducer（名詞）に相当し、男性形は seductor、女性形は seductora となる。' },
  'seductor': { es: 'Ese actor tiene un papel de seductor en la nueva serie de televisión.', ja: 'その俳優は新しいテレビシリーズで誘惑者の役を演じている。', trivia: 'ラテン語 seductor（「誘惑者」）に由来し、英語の seducer と同語源。スペイン語では形容詞としても名詞としても機能し、「魅力的な人」や「口説き上手な人」という意味で用いられる。' },
  'segable': { es: 'El trigo ya está segable; habrá que empezar la cosecha esta semana.', ja: '小麦はもう刈り取れる状態だ。今週中に収穫を始めなければならないだろう。', trivia: '動詞 segar（刈る）に形容詞を作る接尾辞 -able が付いた語で、「刈り取ることができる」を意味する。英語に直接対応する一般語はなく、reapable や mowable で表現されるが、農業語彙として古くからスペイン語に存在する。' },
  'segador': { es: 'El segador pasó toda la mañana cortando la hierba del campo con su guadaña.', ja: '刈り手は午前中ずっと鎌で野原の草を刈り続けた。', trivia: 'segar（刈る）＋行為者接尾辞 -dor から成り、英語の reaper や mower に相当する。「死神（la Muerte con la guadaña）」のイメージと結びつき、カタルーニャ独立運動の歌「Els Segadors（刈り手たち）」はカタルーニャの国歌にもなっている。' },
  'segar': { es: 'Un accidente de tráfico segó la vida de un joven músico lleno de talento.', ja: '交通事故が、才能にあふれた若い音楽家の命を早すぎる時期に摘み取った。', trivia: 'ラテン語 secare（「切る」）に由来し、英語の section や scissors と同語根。現代スペイン語では農業的な「草刈り」の意味だけでなく、「才能や命を若くして断つ」という比喩的表現でも頻繁に使われる。' },
  'tábano': { es: 'Un tábano enorme picó al caballo y lo puso muy nervioso durante todo el paseo.', ja: '大きなアブが馬に刺し、散歩の間中ずっと馬を酷く苛立たせた。', trivia: 'ラテン語 tabanus（「アブ」）がそのまま受け継がれた語で、英語では horsefly または gadfly に相当する。古代ギリシャの哲学者ソクラテスは自分を「アテネという馬に取り付くアブ」に例えたが、スペイン語でも gadfly（gadfly＝社会をチクチク刺す批判者）と同様の比喩的用法がある。' },
  'tabaquería': { es: 'Entré en la tabaquería para comprar un encendedor y unas postales.', ja: 'ライターと絵葉書を買うためにタバコ屋に入った。', trivia: 'tabaco（タバコ）＋場所・店を表す接尾辞 -ería から成る。英語では tobacconist\'s や tobacco shop に相当するが、スペインやラテンアメリカの tabaquería は切手・宝くじ・文具なども扱う小さなキオスクを指すことが多く、英語圏の専門店とはやや異なる。' },
  'tabaquero': { es: 'La industria tabaquera de Cuba es reconocida mundialmente por la calidad de sus puros.', ja: 'キューバのタバコ産業は葉巻の品質において世界的に知られている。', trivia: 'tabaco＋形容詞・職業人接尾辞 -ero/-era から成り、英語の tobacco（形容詞的用法）や cigar maker に相当する。キューバやドミニカ共和国の手巻き葉巻職人（torcedor）は tabaquero とも呼ばれ、その技術はユネスコの無形文化遺産にも登録されている。' },
  'tabaquismo': { es: 'El tabaquismo sigue siendo una de las principales causas de enfermedades cardiovasculares en todo el mundo.', ja: 'タバコ依存症は依然として、世界中で心血管疾患の主な原因の一つであり続けている。', trivia: 'tabaco＋状態・病態を表すギリシャ語由来の接尾辞 -ismo から成る医学用語で、英語では tobacco dependence や nicotinism に相当する。20世紀後半の公衆衛生運動とともに普及した比較的新しい語である。' },
  'tabardillo': { es: 'En el siglo XIX, el tabardillo causó estragos en muchas ciudades europeas con malas condiciones sanitarias.', ja: '19世紀、発疹チフスは衛生状態の悪い多くのヨーロッパの都市に壊滅的な被害をもたらした。', trivia: '中世スペイン語の tabardo（「マント、外套」）の縮小形から派生しており、高熱と皮膚の発疹をマントのように体を覆うものに例えた命名とされる。英語の typhus（発疹チフス）とは語源が異なり、スペイン語独自の民間医学的呼称として歴史に残る。' },
  'tabasco': { es: 'Añadí unas gotas de tabasco a la sopa para darle un toque picante.', ja: 'スープに辛さを加えるためにタバスコを数滴垂らした。', trivia: 'メキシコ南東部のタバスコ州（Estado de Tabasco）の名称に由来し、この地方原産のトウガラシから作られるホットソースの商標名として世界に広まった。英語の Tabasco も同じ地名由来で、ナワトル語で「湿った大地」を意味するとされる。' },
  'taberna': { es: 'Los amigos quedaron en la taberna del barrio para tomar unas tapas después del trabajo.', ja: '友人たちは仕事の後で地元の居酒屋でタパスをつまもうと待ち合わせた。', trivia: 'ラテン語 taberna（「小屋、商店、酒場」）がそのまま継承された語で、英語の tavern と完全に同語源。古代ローマの taberna は食料品店から酒場まで多様な小売店を指したが、現代スペイン語では主に庶民的な居酒屋・バルを意味する。' },
  'tabernero': { es: 'El tabernero conocía los gustos de cada cliente y servía las bebidas sin necesidad de pedirlas.', ja: '居酒屋の主人は客それぞれの好みを知っており、注文されなくても飲み物を出していた。', trivia: 'taberna（居酒屋）＋職業人接尾辞 -ero/-era から成り、英語の tavern keeper や innkeeper に相当する。古代ローマの tabernarius（商店主）と同語根であり、中世ヨーロッパでは宿の経営者も兼ねることが多かった。' },
  'tabique': { es: 'Decidieron derribar el tabique entre la cocina y el salón para crear un espacio más amplio.', ja: 'より広い空間を作るために、キッチンとリビングの間の間仕切り壁を取り壊すことにした。', trivia: 'アラビア語 al-tashbīk（「格子細工、編み組み」）に由来するとされ、スペイン語のアラブ語借用語の一つ。英語では partition wall（建築）や nasal septum（解剖学）と複数の語で表されるが、スペイン語の tabique は両方の意味を一語でカバーする。' },
  'tabla': { es: 'El carpintero midió cuidadosamente cada tabla antes de clavarla en el suelo del porche.', ja: '大工はポーチの床に打ち付ける前に、板一枚一枚を丁寧に測った。', trivia: 'ラテン語 tabula（「板、平らな面」）に由来し、英語の table と同語源。table は「食卓」の意味に特化したが、スペイン語の tabla は「木板」「データ表」「波乗りボード」「舞台」など原義の幅広さを現代まで保持している点が興味深い。' },
  'tablado': { es: 'Los bailaores de flamenco subieron al tablado entre los aplausos del público entusiasmado.', ja: 'フラメンコの踊り手たちは熱狂した観客の拍手の中、舞台へ上がった。', trivia: 'tabla（板）＋集合・場所を表す接尾辞 -ado から成り、「板を張ったステージ」を原義とする。フラメンコ公演の舞台は tablao（tablado の口語短縮形）とも呼ばれ、踊り手が足で床を打ち鳴らす zapateado の音が木の床板に共鳴することから、tablado という語が特に重要な文化的意味を持つ。' },
  'tablaje': { es: 'El tablaje de esta embarcación clásica fue restaurado con maderas nobles de alta calidad.', ja: 'このクラシックな船の外板は、高品質な銘木で修復された。', trivia: 'tabla（板）＋集合名詞を作る接尾辞 -aje（フランス語 -age 由来）から成る語で、英語の planking や boarding に相当する。かつては賭博場の意味もあったが、現代では主に建築・造船分野の専門用語として使われる。' },
  'tablajero': { es: 'El tablajero del mercado recomendó un corte de carne ideal para preparar el asado del domingo.', ja: '市場の肉屋が日曜日のロースト用に最適な肉の部位を勧めてくれた。', trivia: 'tabla（板）＋職業人接尾辞 -jero から成るが、「肉屋」の意味はもともと「まな板（tabla）を使う職人」から派生したとされる。英語の butcher に相当し、ラテンアメリカ（特にアルゼンチン・ウルグアイ）で広く使われる一方、スペイン本国では carnicero の方が一般的。' },
  'tablazo': { es: 'El barco navegó durante horas sobre un tablazo de aguas calmas hasta llegar al archipiélago.', ja: '船は群島に到着するまで、何時間も穏やかな平水区域の上を航行した。', trivia: 'tabla（板）＋強調・打撃を表す増大接尾辞 -azo から成る語で、「板でひどく叩く」という意味と「板のように平らな広大な地形」の両方を指す。英語には直接対応する一語がなく、文脈により blow with a board や vast flatland と訳し分ける必要がある。' },
  'tableta': { es: 'El médico recetó una tableta de ibuprofeno cada ocho horas para reducir la inflamación.', ja: '医師は炎症を抑えるために8時間ごとにイブプロフェンを1錠服用するよう処方した。', trivia: 'tabla（板）の縮小形 tableta は、「小さな板」が原義で、英語の tablet と同語源のラテン語 tabella に遡る。現代では医薬品の「錠剤」、食品の「板チョコ」、ITの「タブレット端末」と全く異なる三分野で同じ語が使われる点がスペイン語の特徴。' },
  'tablilla': { es: 'El médico colocó una tablilla en el dedo roto para inmovilizarlo durante la recuperación.', ja: '医師は回復中に固定するため、折れた指に副木を当てた。', trivia: 'tabla（板）の縮小形で、英語の splint（副木）や tablet（粘土板）に相当する。古代メソポタミアの楔形文字が刻まれた粘土板も tablilla de arcilla と呼ばれ、考古学・歴史学の文脈でも重要な語である。英語の tablet（石板・粘土板）とも同語源（ラテン語 tabella）を共有する。' },
  'tablón': { es: 'El ayuntamiento colocó un tablón de anuncios en la entrada del edificio para informar a los vecinos.', ja: '市役所は住民に知らせるために、建物の入口に掲示板を設置した。', trivia: 'ラテン語 tabula（板）に指小辞ではなく増大辞 -ón が付いた形で「大きな板」が原義。英語の table や tablet と同語源であり、tabula rasa（白紙状態）という表現でも共有されている。' },
  'tabú': { es: 'En muchas culturas, hablar sobre la muerte sigue siendo un tema tabú en las reuniones familiares.', ja: '多くの文化において、死について語ることは家族の集まりでは依然タブーな話題であり続けている。', trivia: 'ポリネシア語（トンガ語）の tapu（聖なる、禁じられた）に由来し、18世紀にジェームズ・クック船長の航海記を通じてヨーロッパ各言語に広まった。英語の taboo と同一の借用語源を持つ。' },
  'tacaño': { es: 'Mi vecino es tan tacaño que apaga las luces del pasillo para ahorrar electricidad.', ja: '私の隣人はとてもケチで、電気代を節約するために廊下の照明を消してしまう。', trivia: '語源には諸説あり、アラビア語起源説とラテン語 attaccare（くっつける）から転じた説がある。英語の stingy や mean に相当するが、スペイン語では mezquino（卑劣なケチ）よりも日常的な表現として広く使われる。' },
  'táctica': { es: 'El entrenador explicó la táctica del equipo antes de comenzar el partido de fútbol.', ja: '監督はサッカーの試合が始まる前にチームの戦術を説明した。', trivia: 'ギリシャ語 taktikē（配置・整列の技術）に由来し、軍事用語として中世ラテン語 tactica を経て諸言語に入った。英語の tactics と同語源で、どちらも「戦略（strategy）」よりも具体的・短期的な手段を指す点も共通している。' },
  'táctico': { es: 'El general tomó una decisión táctica para rodear al enemigo por el flanco derecho.', ja: '将軍は右翼から敵を包囲するために戦術的な決断を下した。', trivia: 'táctica（名詞）の形容詞形で、ギリシャ語 taktikós（配置に関する）が語源。英語の tactical と完全に対応しており、軍事・スポーツ・ビジネスいずれの文脈でも同様の意味で使われる。' },
  'tacto': { es: 'Hay que tener mucho tacto al comunicar malas noticias a alguien que está pasando por un momento difícil.', ja: 'つらい時期を過ごしている人に悪い知らせを伝えるときは、大いに気配りが必要だ。', trivia: 'ラテン語 tactus（触れること）に由来し、動詞 tangere（触れる）の派生語。英語の tact（機転）も同じ語根から来ており、「触れ方＝人との接し方の巧みさ」という比喩的意味は両言語で並行して発展した。' },
  'talco': { es: 'La madre aplicó talco en la piel del bebé después del baño para evitar irritaciones.', ja: '母親は肌荒れを防ぐために、お風呂の後で赤ちゃんの肌にベビーパウダーを塗った。', trivia: 'アラビア語 talq（滑石）に由来し、スペイン語・英語ともにこのアラビア語借用語をほぼそのまま受け継いだ。化学式 Mg₃Si₄O₁₀(OH)₂ で表される鉱物で、モース硬度スケールの最低値 1 の代表例としても知られる。' },
  'talento': { es: 'Su talento para los idiomas le permitió aprender chino mandarín en solo dos años.', ja: '言語に対する彼の才能のおかげで、わずか2年で標準中国語を習得することができた。', trivia: 'ギリシャ語 talanton（天秤・重さの単位・貨幣）に由来し、聖書の「タラントのたとえ話」（マタイ25章）を通じて「神から授かった能力」という意味に転じた。英語の talent も同じ経緯をたどった同語源語である。' },
  'talentosa': { es: 'La joven pianista es extremadamente talentosa y ya ha ganado varios premios internacionales.', ja: 'その若いピアニストは非常に才能があり、すでにいくつかの国際賞を受賞している。', trivia: 'talento に形容詞接尾辞 -oso/-osa が付いた形で「才能に満ちた」を意味する。英語の talented に相当するが、スペイン語の -oso は「〜を豊富に持つ」というニュアンスが強く、同様の構造が famoso（有名な）や poderoso（力強い）にも見られる。' },
  'talentoso': { es: 'El escritor talentoso publicó su primera novela a los veinte años y recibió elogios de la crítica.', ja: 'その才能ある作家は20歳で初の小説を出版し、批評家から称賛を受けた。', trivia: 'talentosa の男性形。スペイン語では形容詞が修飾する名詞の性に一致して語尾が変化するため、talentoso（男性）と talentosa（女性）は同一の語彙エントリとして扱われる。英語には性変化がないため talented 一語で両方をカバーする。' },
  'talón': { es: 'El corredor sintió un dolor agudo en el talón después de correr diez kilómetros sin calentar.', ja: 'そのランナーはウォームアップなしに10キロ走った後、かかとに鋭い痛みを感じた。', trivia: 'ラテン語 talo（かかと）に由来し、ギリシャ神話の英雄アキレスの唯一の弱点「アキレス腱（talón de Aquiles）」という表現でも知られる。英語の heel とは語源が異なるが、「小切手の控え」という意味は英語の counterfoil に相当し、フランス語経由で商業用語として定着した。' },
  'talonario': { es: 'El contador le pidió al gerente que firmara el talonario de cheques antes de fin de mes.', ja: '経理担当者は月末までに小切手帳に署名するよう部長に求めた。', trivia: 'talón（小切手の半券・控え）に集合・帳簿を表す接尾辞 -ario が付いた語で「控えが綴じられた帳面」が原義。英語の checkbook に相当するが、スペイン語では領収書や処方箋の冊子にも広く使われる点が異なる。' },
  'taller': { es: 'Asistí a un taller de escritura creativa que duró todo el fin de semana y aprendí mucho.', ja: '週末を通じて行われた創作ライティングのワークショップに参加し、多くを学んだ。', trivia: 'フランス語 atelier（工房・アトリエ）に由来し、スペイン語では語頭の a- が脱落して taller となった。英語の workshop に相当し、現代では自動車修理工場から教育ワークショップまで幅広い意味で使われる点は両言語に共通している。' },
  'tamaño': { es: 'No me importa el tamaño del apartamento, sino la ubicación y la calidad de vida del barrio.', ja: 'アパートの広さより、立地と近隣の生活の質のほうが重要だ。', trivia: 'ラテン語 tam magnus（それほど大きい）が縮約した形で、「どれほどの大きさか」という比較の概念が語源に埋め込まれている。英語の size はフランス語・古英語経由の別語源だが、「問題の規模（the size of the problem）」という比喩的用法はスペイン語の tamaño del problema と並行している。' },
  'tambalear': { es: 'El gobierno comenzó a tambalearse después de que salió a la luz el escándalo de corrupción.', ja: '汚職スキャンダルが明るみに出た後、政府は揺らぎ始めた。', trivia: '擬音語・擬態語的な起源を持つとされ、不安定な動きを表す音象徴性が強い語。英語の stagger や wobble に意味が近いが、スペイン語では tambalearse（再帰形）として政権・企業・信念などの「比喩的な揺らぎ」にも頻繁に用いられる点が特徴的。' },
  'tándem': { es: 'El dúo cómico formaba un tándem perfecto: uno serio y el otro extrovertido.', ja: 'そのコメディデュオは完璧なコンビを形成していた。一方は真面目で、もう一方は外向的だった。', trivia: 'ラテン語 tandem（ついに、やがて）が「縦一列に並んで」という意味で英語に転用され、2頭立て馬車や2座席自転車を指すようになった。英語・スペイン語ともに同じ形で借用され、現代ではビジネスの「コンビ・連携」を指す比喩表現として広く定着している。' },
  'tangible': { es: 'Los beneficios de la nueva política educativa no son tangibles todavía, pero los expertos son optimistas.', ja: '新しい教育政策の恩恵はまだ目に見える形では現れていないが、専門家たちは楽観的だ。', trivia: 'ラテン語 tangibilis（触れることができる）に由来し、動詞 tangere（触れる）を語根とする。英語の tangible と同語源・同形であり、tacto（触覚）や contact（接触）も同じ語根から派生した仲間である。' },
  'tanque': { es: 'El tanque de agua del edificio tiene capacidad para diez mil litros y abastece a todos los pisos.', ja: 'そのビルの貯水タンクは1万リットルの容量があり、全フロアに給水している。', trivia: '英語 tank の借用語で、英語自体はポルトガル語 tanque（水槽）またはインドの方言語を経由したとされる。第一次世界大戦で登場した装甲車両を「tank」と呼んだのは機密保持のための偽装コードネームで、スペイン語もこの軍事用語をそのまま取り入れた。' },
  'tanto': { es: 'No esperaba que la mudanza fuera tan difícil; había tanto que empacar y organizar.', ja: '引っ越しがこんなに大変だとは思っていなかった。梱包して整理するものがとてもたくさんあった。', trivia: 'ラテン語 tantus（それほど大きい・多い）に由来し、量・程度の大きさを表す指示語として古くから使われてきた。英語の so much や as much に相当するが、スペイン語では「tanto… como…」（〜と同じくらい）という比較構文や、サッカーなどのスポーツで「得点（un tanto）」を指す名詞としても機能する多義語である。' },
  'tapa': { es: 'Pedimos varias tapas para compartir mientras esperábamos la mesa en el restaurante.', ja: 'レストランでテーブルが空くのを待ちながら、シェアするためにタパスをいくつか注文した。', trivia: '動詞 tapar（覆う）から派生した語で、「蓋」が原義。スペインでは飲み物にグラスの蓋として小皿料理を出す習慣から「おつまみ」の意味が生まれたとされる。英語圏でも tapa / tapas としてそのまま借用されており、スペイン食文化を代表する国際語となっている。' },
  'tapar': { es: 'La empresa intentó tapar el escándalo, pero los periodistas descubrieron la verdad.', ja: 'その会社はスキャンダルを隠蔽しようとしたが、ジャーナリストたちが真実を突き止めた。', trivia: '語源には複数の説があり、ゲルマン語の tappa（栓）またはラテン語 operire（覆う）との関連が指摘されている。英語の cover up（隠蔽する）に対応する比喩的用法が発達しており、政治・ジャーナリズムの文脈でも頻繁に使われる。' },
  'tapicería': { es: 'Llevé el sofá a una tapicería para que le cambiaran la tela y lo dejaran como nuevo.', ja: 'ソファを内装工房に持ち込んで布を張り替えてもらい、新品同様にしてもらった。', trivia: 'tapiz（タペストリー）に職業・場所・技術を表す接尾辞 -ería が付いた語。英語の upholstery はオランダ語 upholster（支える・詰め物をする）に由来し語源は異なるが、「家具の布張り・内装」という意味では完全に対応する。フランスのゴブラン織工房もこの職業名に連なる伝統を持つ。' },
  'tapiz': { es: 'En el museo medieval colgaba un enorme tapiz que representaba una escena de caza del siglo XV.', ja: 'その中世博物館には、15世紀の狩猟場面を描いた巨大なタペストリーが掛かっていた。', trivia: 'フランス語 tapis（敷物・布）に由来し、さらにギリシャ語 tapētion（小さな絨毯）に遡る。英語の tapestry も同じ語根から来ており、中世ヨーロッパでは城や聖堂の壁を飾る手織り布が外気を遮断する実用品でもあったため、権力と芸術の象徴として重要な位置を占めていた。' },
  'tapón': { es: 'El tapón de tráfico en la autopista duró más de dos horas debido a un accidente.', ja: '事故のため、高速道路の渋滞は2時間以上続いた。', trivia: 'tapar（覆う・塞ぐ）に増大辞 -ón が付いた語で「大きな栓」が原義。英語の stopper や plug に相当するが、スペイン語では交通渋滞（tapón de tráfico）やバスケットボールのブロック（tapón）など比喩的用法が豊富。コルク栓を指す場合は tapón de corcho と言い、ワイン文化とも深く結びついている。' },
  'taquilla': { es: 'Hicieron cola durante una hora frente a la taquilla para comprar las entradas del concierto.', ja: 'コンサートのチケットを買うために、窓口の前で1時間並んだ。', trivia: '語源には taca（小さな棚・引き出し）から派生したという説があり、「小さな仕切り付きの窓口」が原義とされる。英語の box office（興行収入の窓口）は「ボックス席の料金所」に由来し語源が異なるが、現代では映画・演劇の興行収入を taquilla と表現する点はスペイン語の独自の発展といえる。' },
  'tardar': { es: 'El tren tardó más de una hora en llegar a causa del mal tiempo.', ja: '悪天候のため、電車が到着するのに1時間以上かかった。', trivia: 'ラテン語 tardare（遅らせる）に由来し、英語の tardy（遅刻した）と同じ語根を持つ。スペイン語では「〜するのに時間がかかる」を tardar + en + 不定詞で表現する点が特徴的。' },
  'tarea': { es: 'Los estudiantes tienen que entregar la tarea antes del viernes.', ja: '学生たちは金曜日までに課題を提出しなければならない。', trivia: 'アラビア語 tariha（仕事・苦労）に由来するとされ、スペイン語に入ったのはアラブ支配の時代。英語の task も同じアラビア語起源という説があり、両語は遠い親戚にあたる。' },
  'tarifa': { es: 'La tarifa del metro ha subido un cinco por ciento este año.', ja: '今年、地下鉄の運賃が5パーセント値上がりした。', trivia: 'スペインの港湾都市タリファ（Tarifa）の地名に由来するとも、アラビア語 ta\'rifa（お知らせ）から来るとも言われる。英語の tariff（関税）は同じ語源で、16〜17世紀に貿易用語として普及した。' },
  'tarjeta': { es: '¿Puedo pagar con tarjeta de crédito o solo aceptan efectivo?', ja: 'クレジットカードで支払えますか、それとも現金のみですか？', trivia: 'フランス語 targette（小さな盾）またはラテン語 targa に由来し、「小さな板・札」を意味したのが起源。英語の card はラテン語 charta（紙）から来ており語源は異なるが、現代では同じ意味で使われる。' },
  'tasa': { es: 'La tasa de desempleo en el país ha bajado notablemente en los últimos meses.', ja: 'ここ数か月で、その国の失業率は著しく低下した。', trivia: 'ラテン語 taxare（評価する・課税する）に由来し、英語の tax（税）と同じ語根を持つ。スペイン語では「率・割合」という抽象的な意味に加え、行政手数料や金利にも広く用いられる多義語。' },
  'tasación': { es: 'El banco exige una tasación oficial del inmueble antes de aprobar la hipoteca.', ja: '銀行は住宅ローンを承認する前に、不動産の公式査定を要求する。', trivia: 'tasar（査定する）の名詞形で、ラテン語 taxatio（評価・課税）に直接つながる。英語の taxation（課税）と同語源だが、スペイン語では主に不動産や資産の「評価・鑑定」という意味で専門的に使われる。' },
  'tasar': { es: 'Un perito fue contratado para tasar las joyas heredadas por la familia.', ja: '一家が相続した宝石類を査定するために、専門家が雇われた。', trivia: 'ラテン語 taxare（触れる・評価する・非難する）に由来し、英語の tax（課税する）と同じ語根。古代ローマでは「手で触れて品質を確かめること」が原義で、そこから「価値を評価する」の意味に発展した。' },
  'taxi': { es: 'Pedimos un taxi desde la aplicación porque llovía mucho.', ja: '雨がひどく降っていたので、アプリでタクシーを呼んだ。', trivia: 'taxímetro（料金メーター付き乗り物）の短縮形で、taxímetro 自体はフランス語 taximètre に由来する。英語の taxi も同じ語源で、20世紀初頭に自動車が普及する中で国際的に定着した言葉。' },
  'taxista': { es: 'El taxista nos recomendó un restaurante típico cerca de la plaza mayor.', ja: 'タクシー運転手が、広場の近くにある地元らしいレストランを勧めてくれた。', trivia: 'taxi に職業を表すスペイン語接尾辞 -ista を付けた語で、男女同形（el taxista / la taxista）なのが特徴。英語では taxi driver と二語で表すが、スペイン語は一語で完結する。' },
  'teatro': { es: 'Esta noche vamos al teatro a ver una obra de Federico García Lorca.', ja: '今夜、フェデリコ・ガルシア・ロルカの戯曲を観に劇場へ行く。', trivia: 'ギリシャ語 theatron（見る場所）に由来し、英語の theater / theatre と完全に同語源。「大げさな態度・演技」という比喩的な意味でも使われ、¡Qué teatro! は「なんて大げさな！」という慣用表現。' },
  'techado': { es: 'El mercado techado protege a los vendedores del sol y de la lluvia.', ja: '屋根付きの市場は、売り手たちを日差しや雨から守っている。', trivia: 'techo（屋根）に過去分詞・形容詞化の -ado を付けた語で、「屋根で覆われた状態」を表す。英語では roofed や covered と訳されるが単一の対応語はなく、ラテン語 tectum（覆うもの）が共通の語源。' },
  'techo': { es: 'Los precios de los pisos han llegado a su techo y empezarán a bajar.', ja: 'マンションの価格は天井に達し、これから下がり始めるだろう。', trivia: 'ラテン語 tectum（覆うもの・屋根）に由来し、英語の detect（de- + tegere「覆いを取る」）とも遠縁にあたる。「価格・数量の上限」という比喩的意味は英語の ceiling と完全に対応し、経済・政策用語でよく使われる。' },
  'técnico': { es: 'El técnico reparó el ordenador en menos de una hora.', ja: '技術者は1時間足らずでコンピューターを修理した。', trivia: 'ギリシャ語 technikos（技術・芸術に関する）に由来し、英語の technical / technician と完全に同語源。ギリシャ語 techne（技術・芸術）はさらに「木を大工する」を意味する語根まで遡れ、人間の「作る能力」を表す古い概念。' },
  'tecnología': { es: 'La tecnología ha cambiado profundamente la manera en que nos comunicamos.', ja: 'テクノロジーは私たちのコミュニケーションの方法を根本から変えた。', trivia: 'ギリシャ語 technologia（技術の体系的研究）に由来し、英語の technology と完全に同語源。17世紀のヨーロッパで科学的な技術論を指す学術語として生まれ、20世紀に「先端技術全般」を指す一般語へと意味が拡大した。' },
  'tecnológico': { es: 'El avance tecnológico ha creado nuevas oportunidades de empleo en todo el mundo.', ja: '技術的な進歩は、世界中で新たな雇用機会を生み出している。', trivia: 'tecnología に形容詞化接尾辞 -ico を付けた語で、英語の technological と対応する。ギリシャ語 -logos（学問・論理）が -logía という名詞形と -lógico という形容詞形の両方に引き継がれており、語形成の規則性が際立つ。' },
  'teclear': { es: 'Teclea tu contraseña y pulsa enter para iniciar sesión.', ja: 'パスワードを入力してエンターを押し、ログインしてください。', trivia: 'tecla（鍵盤・キー）に動詞化接尾辞 -ear を付けた語で、英語には直接対応する動詞がなく to type や to press keys と表現する。tecla 自体はラテン語 textila（織物）に由来し、「鍵のように操作する」から「タイピングする」へと意味が転じた。' },
  'tela': { es: 'Esta tela es de muy buena calidad; es perfecta para hacer un vestido de verano.', ja: 'この生地はとても品質が良く、夏のドレスを作るのに最適だ。', trivia: 'ラテン語 tela（織物・蜘蛛の巣）に由来し、英語の textile（テキスタイル）と同語源。スペインの口語では「大金・カネ」という意味にも使われ、「¡Tiene tela!」は「すごいお金だ！」や「大変だ！」という感嘆表現になる。' },
  'telefonear': { es: 'Te telefoneé ayer por la tarde, pero no contestaste.', ja: '昨日の午後、あなたに電話したが、出なかった。', trivia: 'teléfono に動詞化接尾辞 -ear を付けた語。英語では to phone / to call と短い動詞で済ますが、スペイン語では名詞から規則的に動詞を派生させる -ear が非常に生産的な接尾辞で、技術語の動詞化によく使われる。' },
  'telefónico': { es: 'La empresa ofrece un servicio de atención telefónica disponible las veinticuatro horas.', ja: 'その会社は24時間対応の電話サポートサービスを提供している。', trivia: 'teléfono に形容詞接尾辞 -ico を付けた語で、英語の telephonic に相当する。ギリシャ語 tele-（遠く）+ phone（音・声）という構成は英語・スペイン語共通で、電話の発明者グラハム・ベルが1876年に命名した。' },
  'teléfono': { es: 'Apaga el teléfono durante la reunión para no molestar a los demás.', ja: '他の人の邪魔にならないよう、会議中は電話を切っておいてください。', trivia: 'ギリシャ語 tele-（遠く）+ phone（音・声）から成る合成語で、英語の telephone と完全に同語源。グラハム・ベルが1876年に特許を取得した際に命名し、世界中の言語に音訳・借用された国際語の代表例。' },
  'telescopio': { es: 'Con este telescopio podemos ver los cráteres de la luna con gran claridad.', ja: 'この望遠鏡を使えば、月のクレーターをとても鮮明に見ることができる。', trivia: 'ギリシャ語 tele-（遠く）+ skopein（見る）から成る合成語で、英語の telescope と完全に同語源。1611年にガリレオの装置をラテン語に訳す際に造語され、科学ラテン語から各国語に広まった近世の国際学術語の好例。' },
  'televisión': { es: 'Mis padres solían ver el telediario todas las noches después de cenar.', ja: '私の両親は夕食後、毎晩テレビニュースを見ていた。', trivia: 'ギリシャ語 tele-（遠く）+ ラテン語 visio（見ること）という異なる言語を組み合わせた混成語で、英語の television も全く同じ構成。純粋主義者からは「文化的混血語」と批判されたが、20世紀に世界共通語として定着した。' },
  'televisor': { es: 'El televisor nuevo tiene una pantalla de cincuenta pulgadas y resolución 4K.', ja: '新しいテレビ受像機は50インチの画面と4K解像度を持っている。', trivia: 'televisión に行為者・装置を表すラテン語接尾辞 -or を付けた語で、「映像を受像する機器」という物理的実体を指す点が televisión（放送・業界・媒体）と異なる。英語では両者を television set と区別するが、口語では TV で統一される傾向がある。' },
  'tema': { es: 'El tema principal de su novela es la búsqueda de la identidad personal.', ja: 'その小説の主なテーマは、個人のアイデンティティの探求だ。', trivia: 'ギリシャ語 thema（置かれたもの・命題）に由来し、英語の theme と同語源。-ma で終わるギリシャ語由来の名詞はスペイン語では男性名詞になる（el tema, el problema, el programaなど）という規則があり、女性形と間違えやすい代表例として知られる。' },
  'temperamento': { es: 'Tiene un temperamento muy tranquilo y rara vez se enfada con los demás.', ja: '彼女はとても穏やかな気質で、他人に怒ることはほとんどない。', trivia: 'ラテン語 temperamentum（適度な混合・調和）に由来し、英語の temperament と完全に同語源。古代の四体液説（血液・粘液・黒胆汁・黄胆汁の「混合比率」）が人の性格を決めるという考え方から生まれた語で、音楽用語「平均律」にもこの「調和・均等配分」の概念が引き継がれている。' },
  'temperatura': { es: 'La temperatura bajó varios grados durante la noche y tuvimos que sacar mantas adicionales.', ja: '夜の間に気温が数度下がり、毛布を追加で出さなければならなかった。', trivia: 'ラテン語 temperatura（混合、調節）に由来し、英語の temperature と同語源。古代ローマでは体液の「適切なバランス」を指す言葉だった。' },
  'tempestad': { es: 'La tempestad sorprendió a los pescadores en alta mar y tuvieron que regresar al puerto con urgencia.', ja: '嵐が漁師たちを沖合で不意打ちし、彼らは急いで港に戻らなければならなかった。', trivia: 'ラテン語 tempestas（天候、嵐）から来ており、英語の tempest と同語源。シェイクスピアの劇『The Tempest（テンペスト）』はこの語と同じ語根を持つ。' },
  'templado': { es: 'El clima templado de esa región mediterránea atrae a muchos jubilados europeos cada invierno.', ja: 'その地中海地方の温暖な気候が、毎冬多くのヨーロッパの退職者を引き付けている。', trivia: 'ラテン語 temperare（調節する、和らげる）を語源とし、英語の temperate（温暖な、節度ある）と同語源。金属加工の「焼き入れ」の意味もあり、英語の tempered steel（焼き入れ鋼）に対応する。' },
  'templo': { es: 'Los turistas visitaron el antiguo templo griego y admiraron la perfección de sus columnas de mármol.', ja: '観光客たちは古代ギリシャの神殿を訪れ、大理石の柱の完璧さに感嘆した。', trivia: 'ラテン語 templum（聖なる区画、神殿）に由来し、英語の temple と同語源。古代ローマでは augur（占い師）が天空を区切って鳥占いをおこなう「神聖な空間」を指した。' },
  'temporal': { es: 'El contrato temporal que firmé se convirtió en un puesto fijo después de demostrar mis habilidades.', ja: '私が署名した一時的な契約は、自分のスキルを証明した後に正規のポストに変わった。', trivia: 'ラテン語 temporalis（時間に関する）から来ており、英語の temporary と同語源。名詞として「暴風雨」の意味も持つため、形容詞・名詞の両方として機能する多義語として知られる。' },
  'temporada': { es: 'La temporada de lluvias en esta zona dura aproximadamente cuatro meses, desde junio hasta septiembre.', ja: 'この地域の雨季はおよそ4か月間、6月から9月まで続く。', trivia: 'temporal（時間的・季節的なもの）から派生した名詞で、英語の season に相当するが、英語の season がラテン語 satio（種まき）から来るのとは対照的に、スペイン語側はあくまで「時間」を軸にした語源を持つ。' },
  'tender': { es: 'Ella tiende a preocuparse demasiado por los detalles cuando trabaja bajo presión.', ja: '彼女はプレッシャーの下で仕事をするとき、細かいことを気にしすぎる傾向がある。', trivia: 'ラテン語 tendere（伸ばす、向かう）に由来し、英語の tend（傾向がある）や tender（差し伸べる）と同語源。現在形では語幹母音が変化し tiendo となる二重母音化（e→ie）の典型的な例。' },
  'R / r': { es: 'La letra R tiene dos sonidos en español: la erre suave y la erre fuerte.', ja: 'スペイン語のR（エレ）には、弱いR音と強いR音の2種類がある。', trivia: 'フェニキア文字の「レシュ（頭）」に由来し、ギリシャ語のロー（Ρ）、ラテン語のRへと受け継がれた。英語でも同じ系統の文字で、スペイン語の巻き舌R（erre）は英語のRとは発音が大きく異なる点が学習者の難所となる。' },
  'alto / resalto': { es: 'Ese edificio es el más alto de la ciudad.', ja: 'あの建物は街で一番高いです。', trivia: 'ラテン語 altus（高い・深い）から。英語の altitude（高度）や altar（祭壇、高い台）と同語根です。' },
  'deprimente / reprimenda': { es: 'El director le dio una reprimenda severa al empleado por llegar tarde repetidamente.', ja: '所長は度々遅刻した社員に厳重な叱責を与えた。', trivia: '入力行には「deprimente / reprimenda」と記されているが、ここでは reprimenda を取り上げる。ラテン語 reprimenda（抑えられるべきもの）に由来し、英語の reprimand と同語源。英語 reprimand はフランス語経由で入った借用語で、スペイン語と語源を共有する。' },
  'incorporarse / reincorporarse': { es: 'Después de la baja por maternidad, se reincorporó al trabajo con mucha energía.', ja: '産休が明けた後、彼女はエネルギーに満ちて職場に復帰した。', trivia: 're-（再び）と incorporarse（合流する・加わる）が合わさった動詞で、incorporarse 自体はラテン語 corpus（体・組織）に由来する。英語の rejoin や return to work に相当し、incorporate（組み入れる）とも同語根。' },
  'morder / remorder': { es: 'El perro me mordió en la mano cuando intenté acariciarlo.', ja: 'なでようとしたら犬に手を噛まれた。', trivia: 'ラテン語 mordere（噛む）に由来し、英語の remorse（後悔、良心の呵責）はこの語根 mord-「噛む」から来ており、「良心に噛みつかれる」という比喩的意味を持つ。英語で「噛む」は bite で語根は異なる。' },
  'pauto / pautar': { es: 'Es necesario pautar bien el proceso de evaluación para garantizar la equidad.', ja: '公平性を確保するために評価プロセスの基準をきちんと定めることが必要だ。', trivia: '名詞 pauta（指針、基準）から派生した動詞。英語では to set guidelines や to standardize に相当し、直接対応する英単語はない。pauta 自体の語源については諸説あり、ラテン語 pacta 由来という説が有力。' },
  'período / periodo': { es: 'Durante el período de la guerra civil, muchas familias tuvieron que emigrar.', ja: '内戦の時期には、多くの家族が移住せざるを得なかった。', trivia: 'ラテン語 «periodus» を経て、ギリシャ語 «períodos»（周回・循環；peri「周り」＋ hodos「道」）に遡る。英語の period と完全に同語根であり、綴りも意味も非常に近いが、スペイン語では «período» と «periodo» の二形が共存している。' },
  'poliza / póliza': { es: 'El seguro de vida cubre los gastos según lo estipulado en la póliza.', ja: '生命保険は、保険証券に定められた条件に従って費用をカバーする。', trivia: 'イタリア語 polizza（証書）を経由し、さらに中世ラテン語 apodissa、ギリシャ語 apódeixis（証明・領収書）に遡るとされる。英語には直接の同語根語はなく、英語では policy（保険証券）が対応するが、英語の policy（政策）とはギリシャ語の別々の語源を持つ同音語である。' },
  'portugues / portugués': { es: 'Mi vecina es portuguesa y me enseña algunas palabras en portugués de vez en cuando.', ja: '隣人はポルトガル人で、時々ポルトガル語の単語を教えてくれる。', trivia: '地名 Portugal に由来し、Portugal 自体はラテン語 Portus Cale（カレの港）に由来する地名。英語の Portuguese と同語根で同義のコグネートであり、スペイン語とポルトガル語は語彙の約89%を共有するという点でも興味深い隣接言語の関係にある。' },
  'precio / precio': { es: 'El precio del alquiler en las ciudades grandes ha subido mucho este año.', ja: '今年は大都市の家賃がかなり上がった。', trivia: 'ラテン語 pretium（価値、価格、報酬）に由来。英語の price はノルマン・フランス語 pris を経由して同じラテン語源に遡るが、スペイン語 precio の方がラテン語の形により近い。また precious（貴重な）とも同語根である。' },
  'propugna / propugnar': { es: 'La organización propugna una educación igualitaria para todos los niños del país.', ja: 'その組織は国内すべての子どもへの平等な教育を提唱している。', trivia: 'ラテン語 propugnare（守る、戦う）に由来し、pro-（前で）と pugnare（戦う）の合成語。英語の advocate や champion（主義を擁護する）に意味上相当し、英語の pugnacious（好戦的な）と同語根だが「擁護する」という積極的・建設的な意味合いで使われる。' },
  'proveído / proveído': { es: 'El juez dictó un proveído ordenando la suspensión temporal del contrato.', ja: '裁判官は契約の一時停止を命じる裁定を下した。', trivia: '動詞 proveer の規則的な過去分詞形（不規則形は provisto）。法律用語としては「裁判所の決定・命令」を指す名詞としても機能する。英語の provided や provision と同語根（ラテン語 providere）だが、法律的な名詞用法は英語には直接対応する語がなくやや特殊。' },
  'pubes / pubis': { es: 'El médico le diagnosticó una inflamación en la sínfisis del pubis tras el entrenamiento intenso.', ja: '医師は、激しいトレーニングの後に恥骨結合の炎症と診断した。', trivia: 'ラテン語「pubes/pubis（恥部・陰毛・成熟）」に直接由来する解剖学用語。英語でも「pubis」はそのまま解剖学用語として使われ、「pubic（恥骨の）」「puberty（思春期）」と同語根で、「成熟・体毛」のイメージを語根に持つ。' },
  'pudor / pudor': { es: 'Le dio pudor hablar de sus sentimientos frente a tanta gente.', ja: '大勢の前で自分の気持ちを話すのが恥ずかしかった。', trivia: 'ラテン語 pudor（恥、羞恥心）から直接受け継がれた語で、動詞 pudere（恥じる）と同根。英語には対応する同語根語はほとんど残っておらず、英語では modesty や shame と言うが、pudor は単なる「恥」というより「恥じらいの美徳」というニュアンスを含む、文化的に深い概念語だ。' },
  'pudre / pudrir': { es: 'La fruta se pudre rápidamente si no la guardas en el refrigerador.', ja: '冷蔵庫に入れておかないと果物はすぐに腐ってしまう。', trivia: '動詞 pudrir（腐る・腐らせる）の三人称単数現在形。ラテン語 putrere（腐る）に由来し、英語の putrid（腐った、腐敗した）と同語根の真のコグネート。英語では rot や decay が一般的だが、putrid という形容詞に原形の面影が残っている。' },
  'puesto / puesto': { es: 'Lleva dos años ocupando el puesto de directora de marketing en esa empresa.', ja: '彼女はその会社でマーケティングディレクターのポストに就いて2年になる。', trivia: '動詞 poner（置く）の過去分詞 puesto が名詞化した語で、ラテン語 positus（置かれた）に由来する。英語の post（地位・郵便）と同語根の真のコグネートで、どちらも「場所に置かれたもの」という概念から「職・地位」の意味に発展した。英語 position も同じラテン語根を持つ。' },
  'puntar / puntuar': { es: 'El profesor tardó varios días en puntuar todos los exámenes del curso.', ja: '教授がコースの全ての試験を採点するのに数日かかった。', trivia: 'ラテン語 punctuare（点を打つ）に由来し、英語の punctuate と完全な同語根。英語 punctuate は主に「句読点を打つ」「強調する」の意だが、スペイン語 puntuar は「採点する・得点する」の意味でも日常的に使われる。' },
  'puntea / puntear': { es: 'El guitarrista prefiere puntear las cuerdas en lugar de rasguearlas para ese tipo de melodía.', ja: 'そのギタリストはそういうメロディーにはストラムではなくピッキングを好む。', trivia: 'punta（先端）から派生した動詞で、「指先や爪で弦をはじく」という意味。英語では pick や pluck（こちらはゲルマン語系）という別語源の語を使うが、スペイン語は「先端で触れる」という視覚的な動作概念から動詞を形成した。' },
  'purasangre / pura sangre': { es: 'El jockey montó un purasangre de cuatro años que ganó todas las carreras de la temporada.', ja: '騎手は今シーズン全レースを制した4歳のサラブレッドに騎乗した。', trivia: 'スペイン語で「純粋な血」を意味する pura（純粋な）+ sangre（血）の合成語。英語の thoroughbred（サラブレッド）は「徹底的に品種改良された」という意味で、語源的アプローチが全く異なるのが興味深い。英語の purebred とはより直接的に対応する。' },
  'quejar / quejarse': { es: 'Los vecinos se quejan constantemente del ruido que hacen los estudiantes por la noche.', ja: '近所の人たちは夜に学生たちが出す騒音について絶えず不満を言っている。', trivia: 'ラテン語 *quassare*（激しく揺さぶる）に由来するとされ、「心を激しく揺さぶられる→嘆く」という意味変化を経た。英語の *complain* とは語根が異なるが、英語形容詞 *querulous*（愚痴っぽい）はラテン語 *queri*（嘆く）由来で *quejarse* と語根的に近い関係にある。' },
  'quepis / quepí': { es: 'Los soldados desfilaron con sus quepis perfectamente alineados bajo el sol de verano.', ja: '兵士たちは夏の日差しの下、ケピ帽を完璧に揃えてパレードした。', trivia: 'フランス語 *képi* からの借用語で、フランス語はアルザス方言 *käppi*（小さな帽子）に由来する。英語でも *kepi* または *képi* として同じフランス語から借用されており、スペイン語・英語ともにフランス軍帽文化の影響を受けた共通の借用語である。' },
  'queques / queque': { es: 'Mi abuela preparó unos queques de vainilla deliciosos para la merienda del domingo.', ja: '祖母は日曜日のおやつにおいしいバニラケーキをいくつか作ってくれた。', trivia: '英語 *cake* のスペイン語音写で、中南米（コスタリカ・ペルーなど）とカナリア諸島で使われる口語表現。英語の *cake* 自体は古ノルド語 *kaka* に由来し、スウェーデン語・ノルウェー語の *kaka* と同語根。*queque* は英語音を直接スペイン語表記に転写した珍しい借用語。' },
  'querella / querella': { es: 'El empresario presentó una querella contra el periódico por difamación.', ja: 'その実業家は名誉毀損を理由に新聞社に対して告訴状を提出した。', trivia: 'ラテン語 *querela*（苦情、嘆き）に由来し、*queri*（嘆く）が語根。英語の *quarrel*（口論）も同じラテン語 *querela* に由来する同語根語（コグネート）であり、「嘆き→争い→法的紛争」という意味の分岐が英語とスペイン語で異なる方向に発展した好例。' },
  'querellar / querellarse': { es: 'La víctima decidió querellarse contra su empleador por acoso laboral.', ja: '被害者は職場でのハラスメントを理由に雇用主に対して告訴することを決めた。', trivia: 'ラテン語 *querelari*（嘆く、苦情を言う）に由来する再帰動詞。英語の *quarrel*（口論する）は同じラテン語 *querela* を語根とする同語根語で、法的な告訴を意味するスペイン語の用法と日常的な口論を意味する英語の用法とで意味が大きく異なる興味深いコグネート。' },
  'queroseno / querosén': { es: 'El mechero de queroseno iluminaba la cabaña durante los apagones.', ja: '停電の間、灯油ランプが山小屋を照らしていた。', trivia: 'ギリシャ語「κηρός（kēros、蜜蝋）」に由来し、19世紀に英語で「kerosene」として造語された後、スペイン語に借用された。英語では「kerosene」（北米）または「paraffin」（英国）と呼ぶが、どちらも石油蒸留の産物を指す。' },
  'quichua / quechua': { es: 'Muchas palabras del quichua han pasado al español, como \\\'papa\\\', \\\'cóndor\\\' o \\\'llama\\\'.', ja: '「パパ（ジャガイモ）」「コンドル」「リャマ」など、ケチュア語由来の多くの言葉がスペイン語に取り込まれた。', trivia: 'スペイン語の綴りは「quechua」または「quichua」と表記が揺れ、ケチュア語自身では「Runa Simi（人の言葉）」と呼ばれる。英語でも「Quechua」として知られ、potato（ジャガイモ）、condor（コンドル）、guano（グアノ）など英語に定着した単語もケチュア語由来のものが多い。' },
  'quitaipón / quita y pon': { es: 'Este collar tiene un colgante de quitaipón, así que puedes cambiarlo según tu outfit del día.', ja: 'このネックレスは着脱自在のペンダントトップがついているので、その日のコーデに合わせて取り替えられる。', trivia: '「quita y pon（取って・付けて）」という句が名詞化・一語化したもので、英語では detachable や removable で表現する。このような命令形動詞の反復による合成語はスペイン語に特有の造語パターンで、英語には同構造の対応語がない。' },
  'quite / quitar': { es: 'El torero ejecutó un quite perfecto para alejar al toro del picador caído.', ja: '闘牛士は倒れたピカドールから牛を遠ざけるため、完璧なキテを繰り出した。', trivia: '動詞 quitar（取り除く）の名詞形で、ラテン語 *quitare（解放する）に由来するとされる。英語 quit（やめる）とは同語根で、もともと「負債・義務から解放する」という意味を共有していた。' },
  'quito / quitar': { es: 'Cuando me quito los zapatos en casa, me siento completamente relajado.', ja: '家で靴を脱ぐと、完全にリラックスした気分になる。', trivia: '動詞 quitar の直説法現在1人称単数形。地名の「キト（Quito）」はエクアドルの首都で、ケチュア語で「世界の中心」を意味するとも言われ、動詞 quitar とは語源が異なる。英語 quit と同語根の部分については quite の項目と同様。' },
  'quivi / kiwi': { es: 'Me como un quivi cada mañana porque dicen que tiene mucha vitamina C.', ja: 'ビタミンCが豊富だと言われているので、毎朝キウイを1個食べる。', trivia: '英語の kiwi はマオリ語に由来し、ニュージーランドの飛べない鳥の鳴き声を模した言葉。スペイン語では kiwi と綴ることが多く、quivi は表記揺れ。英語と完全に同語源の借用語である。' },
  'quizá / quizás': { es: 'Quizá llegue tarde hoy, así que no me esperes para cenar.', ja: '今日は遅くなるかもしれないから、夕食は待たないでいいよ。', trivia: '中世スペイン語の「qui sabe（誰が知ろうか）」が縮約・融合したものとされ、英語の perhaps（per + haps「運・機会」）や maybe（may + be）とは語源が全く異なる。quizás と末尾に s を付けた形も同義で使われる。' },
  'quota / cuota': { es: 'El gobierno impuso una quota de importación para proteger a los productores nacionales.', ja: '政府は国内生産者を保護するために輸入割り当てを課した。', trivia: 'ラテン語 quota（pars）「何番目の（部分）」に由来し、英語の quota とスペイン語の cuota（より一般的な綴り）は同語根の双子語。quota は主に書き言葉や外来語的ニュアンスで使われ、cuota が日常的な正書法とされる。' },
  'quía / ¡qué va!': { es: '—¿Crees que va a llover mañana? —¡Quía, con este sol que hace!', ja: '「明日は雨が降ると思う？」「まさか、こんなに晴れているのに！」', trivia: '口語的な間投詞で、語源は諸説あり、「¡qué va!」の変形または独立した感嘆詞とも言われる。英語の「No way!」や「Nonsense!」に近い。「¡qué va!」というフレーズとほぼ同義で用いられ、ラテンアメリカよりもスペイン本土で多く聞かれる表現である。' },
  'racionamiento / racionamiento': { es: 'Durante la guerra, el gobierno impuso el racionamiento del pan y del aceite para toda la población.', ja: '戦時中、政府は全国民にパンと油の配給制を課した。', trivia: 'ラテン語 ratio（計算、割り当て）から派生した ración に接尾辞 -miento が付いた形。英語の rationing とまったく同根の借用語であり、第二次世界大戦中に英・西両国で実際に同義で使われた。' },
  'ración / ración': { es: 'En el bar pidieron dos raciones de calamares para compartir entre los amigos.', ja: 'バルで友人たちとシェアするためにイカのフライを2皿注文した。', trivia: 'ラテン語 ratio（計算、割り当て）から中世ラテン語 ratio / rationem を経て成立。英語の ration と同源で、スペインのバルでは一品料理の一人前サイズを指す独特の食文化的意味も持つ。' },
  'rafi / rafie': { es: 'Las cestas tejidas con rafi son resistentes y muy apreciadas en artesanía.', ja: 'ラフィアで編まれたかごは丈夫で、工芸品として高く評価されている。', trivia: 'ラフィアはマダガスカル原産のラフィアヤシ（Raphia farinifera）の葉から採れる天然繊維で、その名はマダガスカル語に由来する。英語の raffia と同語源で、世界中で籠編みや帽子の素材として使われている。' },
  'raigo / raer': { es: 'Cuando raigo la pintura vieja de la pared, siempre me aseguro de usar guantes y mascarilla.', ja: '壁の古い塗料を削り落とすとき、私は必ず手袋とマスクを着用するようにしている。', trivia: '動詞 raer（ラテン語 radere「削る・こする」由来）の直説法現在1人称単数形。raer は活用が特殊で、1人称単数で raigo/rayo の両形が並存する稀な動詞。英語の erase・razor・abrasion はいずれも同じ radere を語根に持ち、「こすって落とす」行為を多様な語彙で表している。' },
  'raíl / rail': { es: 'Un tornillo suelto en el raíl provocó el descarrilamiento del tren de mercancías.', ja: 'レールの緩んだボルトが貨物列車の脱線を引き起こした。', trivia: '英語の rail をスペイン語に音訳した借用語で、rail はフランス語 reille（横木、ラテン語 regula「定規・棒」由来）を経由して英語に入った語。スペイン語 raíl はアクセント記号を伴う形で定着しており、英語 rule・regulate・rail がすべてラテン語 regula を共通語根に持つ興味深い語族を形成している。' },
  'reiterada / reiterado': { es: 'A pesar de las reiteradas advertencias, siguieron ignorando las normas de seguridad.', ja: '度重なる警告にもかかわらず、彼らは安全規則を無視し続けた。', trivia: 'ラテン語 reiterare（繰り返す）の過去分詞に由来する形容詞で、「何度も繰り返された」を意味する。英語の reiterated（繰り返された）とほぼ同形で意味も同じ国際語的な単語であり、語根の iter は英語の itinerary（旅程）とも共通する。' },
  'relacionada / relacionado': { es: 'Esta decisión está estrechamente relacionada con los cambios económicos del último año.', ja: 'この決定は昨年の経済変化と密接に関連している。', trivia: 'ラテン語の relatio（報告・関係）に由来し、re-（再び）＋ latio（運ぶこと）が語源。英語の related と語源・意味ともに一致する真のコグネートで、relation（関係）、relative（親戚・相対的な）なども同語根。「情報を運び返す」というニュアンスが元の意味にある。' },
  'relajada / relajado': { es: 'Después de un largo baño caliente, me sentí completamente relajada.', ja: '長い温浴の後、私は完全にリラックスした気分になった。', trivia: 'ラテン語の relaxatus（緩められた）に由来する過去分詞形容詞で、laxus（緩い）が語根。英語の relaxed とほぼ同語源・同意味の真のコグネートで、英語の lax（ゆるい・不注意な）や laxative（便秘薬）とも同じ語根ファミリーに属する。' },
  'relamer / relamerse': { es: 'El perro se relamía los bigotes después de comerse todo el hueso.', ja: '犬は骨を全部食べ終えた後、ひげをなめ回していた。', trivia: 're-（繰り返し）と lamer（なめる）が合わさった動詞で、lamer 自体はラテン語 lambere（なめる）に由来する。英語の lap（液体をなめる）も同じ語根を持ち、再帰形 relamerse は「舌なめずりをする」や「期待でほくそ笑む」という比喩的な意味でも使われる。' },
  'relatada / relatado': { es: 'La historia relatada por la abuela emocionó a todos los nietos reunidos alrededor de la chimenea.', ja: '祖母によって語られたその話は、暖炉の周りに集まったすべての孫たちを感動させた。', trivia: '動詞 relatar の過去分詞女性形。ラテン語 relatum（運び返された・伝えられた）が語源で、英語の narrated や told に相当する。形容詞として名詞を修飾する際は性数一致が必要なスペイン語の特徴を示す語。' },
  'relativas / relativo': { es: 'Hay medidas relativas a la seguridad vial que deben cumplirse en todo el país.', ja: '国全体で遵守されなければならない道路安全に関する措置がある。', trivia: 'ラテン語 relativus（関係づけられた）が語源で、英語の relative と完全な同語根コグネート。文法用語としての「関係詞」(pronombre relativo) でも使われるが、日常でも「〜に関する」という意味で頻繁に使われる点は英語の relative とやや異なる。' },
  'relojera / relojero': { es: 'La relojera experta restauró el viejo reloj de bolsillo con una habilidad impresionante.', ja: 'その熟練した時計職人（女性）は素晴らしい技術で古い懐中時計を修復した。', trivia: 'reloj（時計）＋接尾辞 -ero/-era（職業を示す）の複合語で、reloj 自体はアラビア語 al-rukhāma（大理石の日時計）またはアラビア語 al-rl\\\'ij（仕掛け時計）が語源とされる。英語の watchmaker に相当するが、英語の watch と clock が区別されるのに対しスペイン語では reloj が両方を指す。' },
  'remendada / remendado': { es: 'Llevaba una chaqueta remendada en los codos, pero la lucía con total naturalidad.', ja: '彼女は肘につぎを当てたジャケットを着ていたが、それをごく自然に着こなしていた。', trivia: 'remendar（繕う）の過去分詞の女性形で、ラテン語 ēmendāre（欠点を取り除く・修正する）に由来する。英語の amend（修正する）や emend（校訂する）と同語根であり、「欠点（mendum）を取り除く」という原義から「布を繕う」という具体的な意味に特化したのがスペイン語の特徴だ。' },
  'remilgada / remilgado': { es: 'La jefa era tan remilgada que nunca comía en restaurantes que no tuvieran mantel de tela.', ja: '上司は非常に気取り屋で、布のテーブルクロスがないレストランでは決して食事をしなかった。', trivia: 'remilgo の形容詞・過去分詞形で、語源については諸説あり、ラテン語 mimare（物まねをする・気取る）に由来するという説や、mel（蜂蜜）から来た「甘ったるい」という意味合いとする説がある。英語では prim（お上品ぶった）・squeamish（神経質な）・finicky（えり好みする）などが近い表現で、一語では対応しにくい繊細なニュアンスを持つ。' },
  'remolinar / remolinarse': { es: 'Las hojas secas comenzaron a remolinar con una ráfaga repentina de viento.', ja: '一陣の突風で枯れ葉が渦を巻き始めた。', trivia: '名詞 remolino（渦巻き）から派生した動詞。remolino はラテン語 mola（臼、回転するもの）に由来すると考えられ、英語の mill（製粉所）や maelstrom の mael- と語根が共通する可能性がある。' },
  'remota / remoto': { es: 'Existe una posibilidad remota de que el proyecto sea aprobado antes del fin de año.', ja: '年内にそのプロジェクトが承認される可能性は極めて低い。', trivia: 'ラテン語 remotus（遠ざけられた）から。英語の remote と完全に同語根の同形コグネートで、現代では「リモートワーク」のような新しい意味でも両言語でほぼ同様に使われる。' },
  'remunerada / remunerado': { es: 'Busca una actividad remunerada que también le permita disfrutar de lo que hace.', ja: '報酬をもらいながら、自分のやることを楽しめる仕事を探している。', trivia: '「remunerar」の過去分詞から派生した形容詞で、英語の「remunerated」「paid」に対応する。特に「actividad remunerada（有給の活動）」と「actividad voluntaria（ボランティア活動）」の対比でよく使われる。' },
  'remuneratoria / remuneratorio': { es: 'Se estableció una cláusula remuneratoria en el contrato para garantizar compensaciones adicionales.', ja: '追加補償を保証するために、契約書に報酬条項が設けられた。', trivia: 'ラテン語「remuneratorius」に由来する法律・経済用語で、英語の「remunerative」に相当する。英語では「remunerative work（実入りのいい仕事）」のように日常でも使われるが、スペイン語のこの形は主に法的・契約文書で見られる。' },
  'renca / renco': { es: 'Desde el accidente, camina renca y necesita apoyo para subir escaleras.', ja: '事故以来、彼女は足を引きずって歩き、階段を上るのに助けが必要だ。', trivia: '語源は不明瞭で、ラテン語「reinicare」や「hircinius」などの説があるが定説はない。英語の「lame」に相当するが、英語の「lame」はゲルマン語系（古英語「lama」）で語根が異なる。現代英語では「lame」を人に使うのは差別的とされ「mobility-impaired」などが好まれる。' },
  'rencorosa / rencoroso': { es: 'Es una persona muy rencorosa que nunca olvida las ofensas que le han hecho.', ja: '彼女は非常に根に持つ性格で、受けた侮辱を決して忘れない。', trivia: '「rencor（恨み）」に形容詞語尾「-oso/a」が付いた語で、英語の「rancorous」「resentful」に相当する。英語の「rancorous」は文語的だが、スペイン語の「rencoroso/a」は日常の人物描写でよく使われる実用的な形容詞。' },
  'rendida / rendido': { es: 'Llegó a casa rendida después de trabajar doce horas seguidas sin descanso.', ja: '12時間ぶっ通しで働いた後、彼女はクタクタになって家に帰り着いた。', trivia: '「rendir」の過去分詞から派生した形容詞で、ラテン語「reddere」に由来する。英語では「exhausted」「worn out」に相当するが、英語の「rendered（描写された・提出された）」も同語根で意味が大きく異なる好例のコグネート。' },
  'renegada / renegado': { es: 'La comunidad la consideraba una renegada por haber abandonado las tradiciones familiares.', ja: '彼女は家族の伝統を捨てたため、コミュニティから裏切り者と見なされていた。', trivia: '「renegar（信念を捨てる）」の過去分詞から派生した名詞・形容詞で、ラテン語「renegare（否定する）」に由来する。英語の「renegade」はスペイン語「renegado」からの借用語で、16世紀に「キリスト教からイスラム教に改宗した者」を指す語として英語に入った歴史を持つ。' },
  'reniego / renegar': { es: 'Cada vez que algo le sale mal, reniego de mi mala suerte en voz alta.', ja: '何かうまくいかないたびに、私は大声で自分の不運を嘆く。', trivia: '動詞 renegar はラテン語 renegare（強く否定する）に由来し、接頭辞 re-（強調）＋ negare（否定する）から成る。英語の renegade（背教者・裏切り者）は同語根で、もとはスペイン語 renegado を経由して英語に入った。' },
  'renombrada / renombrado': { es: 'Alicia es una chef renombrada que ha ganado varios premios internacionales.', ja: 'アリシアは国際的な賞をいくつも受賞した名高いシェフだ。', trivia: 'renombrado は re-（再び）＋ nombre（名前、ラテン語 nomen）の合成語で、「何度も名前を呼ばれる＝有名な」という意味合いを持つ。英語の renowned も古フランス語 renomé（re- ＋ nom「名前」）が源で、ラテン語 nomen を共有する同語根語。' },
  'renovada / renovado': { es: 'Salió de las vacaciones con energía renovada y listo para enfrentar nuevos desafíos.', ja: '彼は休暇から新鮮なエネルギーを持って帰り、新たな挑戦に臨む気満々だった。', trivia: 'renovado はラテン語 renovare（re-「再び」＋ novare「新しくする」、novus「新しい」が語根）の過去分詞。英語の renewed も同一の接頭辞 re- と古英語/ラテン語系 new を組み合わせており、構造が鏡のように対応している。' },
  'renuncio / renunciar': { es: 'En el partido de cartas, el árbitro detectó un renuncio que invalidó la jugada.', ja: 'カードゲームの試合で、審判がルール違反を検出し、その手が無効となった。', trivia: '名詞 renuncio はトランプ用語で「出せるカードを出さなかった違反」を指し、動詞 renunciar（ラテン語 renuntiare、re-「再び」＋ nuntiare「報告する」＞「撤回する」）の活用形が名詞化したもの。英語の renounce（放棄する）は同じラテン語根の直接借用語。' },
  'repara / reparo': { es: 'Él repara el motor mientras yo reparo el sistema eléctrico.', ja: '彼がエンジンを修理する間、私は電気系統を直す。', trivia: 'ラテン語 reparare（再び準備する）に由来し、re-（再び）＋ parare（準備する）の構成。英語の repair も同じラテン語源を共有しており、スペイン語と英語でほぼ同形の語根コグネート（同語根語）となっている。' },
  'reparada / reparado': { es: 'La tubería reparada funciona bien desde hace tres semanas.', ja: '修理されたパイプは3週間前からうまく機能している。', trivia: 'reparar の過去分詞女性形。英語の repaired と直接対応するコグネートで、語形も非常に近い。スペイン語では過去分詞が形容詞として用いられる際に名詞の性・数に合わせて語尾変化する点が英語と異なる。' },
  'repartida / repartido': { es: 'La tarea quedó bien repartida entre todos los miembros del equipo.', ja: '仕事はチームの全員にうまく分配された。', trivia: 'repartir の過去分詞女性形。ラテン語 partire（分ける）に由来し、英語の distributed や divided と意味的に対応する。英語の part（部分）や partition（分割）も同語根であり、スペイン語・英語ともに「分ける」という共通の語根概念を持つ。' },
  'repentina / repentino': { es: 'La muerte repentina del director dejó a todo el equipo en estado de shock.', ja: '社長の突然の死はチーム全員をショック状態に陥れた。', trivia: 'ラテン語 repentinus（突然の）に由来し、re-＋ pente（突然に）の構成。英語の sudden は古英語 soden（急いで煮る）に由来し全く別語源だが、英語には repentant（後悔している）という語があり、こちらはスペイン語の repentir（後悔する）とは同語根でも repentino とは無関係という紛らわしい関係がある。' },
  'replegada / replegado': { es: 'Las tropas replegadas esperaban nuevas órdenes en una posición defensiva.', ja: '退却した部隊は防御陣地で新たな命令を待っていた。', trivia: 'replegar の過去分詞・形容詞形。replegar はラテン語 replicare（折り返す）から来ており、re-（再び）+ plicare（折る）の構成。英語の fold と reply はどちらも plicare に由来するが、「退却する」という軍事的意味はスペイン語で特に発達した用法。' },
  'repoio / repollo': { es: 'La ensalada de repollo morado con zanahoria es muy popular en los mercados locales.', ja: '紫キャベツと人参のサラダは地元の市場でとても人気がある。', trivia: '語源は諸説あるが、ラテン語 replum（結合部）または rapulum（かぶ）から派生したとも言われ、「芽が再び丸まって育つ」イメージと結びついた可能性がある。英語の cabbage はフランス語 caboche（頭）に由来し、スペイン語 repollo とは語源が異なる。「丸い頭のような野菜」という発想は両言語で共通する。' },
  'reportada / reportado': { es: 'La cifra reportada de contagios fue mucho mayor de lo esperado.', ja: '報告された感染者数は予想をはるかに上回るものだった。', trivia: 'reportar（報告する）の過去分詞・形容詞形。reportar はラテン語 reportare（持ち帰る、報告する）から来ており、英語の report と完全に同語源。スペイン語では再帰形 reportarse に「自制する」という意味もあり、英語の report にはないニュアンスが存在する点が対照的。' },
  'reportera / reportero': { es: 'La reportera llegó al lugar del accidente antes que ningún otro medio de comunicación.', ja: 'その女性記者は他のどのメディアよりも先に事故現場に到着した。', trivia: '英語の reporter と同語源で、ラテン語 reportare（伝達する）に由来する職業名詞。英語では性別を区別しないが、スペイン語では reportero（男性）/ reportera（女性）と語尾で区別するのが特徴。' },
  'reposada / reposado': { es: 'Con voz reposada, la maestra explicó el problema a los alumnos que se sentían nerviosos.', ja: '先生は落ち着いた声で、緊張している生徒たちに問題を説明した。', trivia: '動詞 reposar（休む）の過去分詞が形容詞化したもので、ラテン語 repausare に由来する。英語の repose（休息、静けさ）と同語根だが、英語では形容詞として reposeful というやや格式張った語が対応する。' },
  'representada / representado': { es: 'La parte representada en el contrato debe dar su consentimiento explícito antes de firmar.', ja: '契約において被代理人は署名前に明示的な同意を示さなければならない。', trivia: '動詞 representar の過去分詞が名詞・形容詞化したもので、ラテン語 repraesentare に由来する。英語の represented と同語源だが、スペイン語では法律用語として「被代理人」という名詞的用法が特に発達している。' },
  'representativa / representativo': { es: 'Esta muestra no es representativa de la población total, por lo que los resultados pueden ser sesgados.', ja: 'このサンプルは全母集団を代表するものではないため、結果が偏っている可能性がある。', trivia: 'ラテン語 repraesentativus に由来し、英語の representative と同語源の同源語。英語では名詞・形容詞が同形だが、スペイン語では representativo / representativa と性によって語尾が変化するのが特徴。' },
  'represora / represor': { es: 'La figura represora del régimen utilizaba el miedo para controlar a la población.', ja: 'その政権の弾圧的な人物は恐怖を使って国民を支配していた。', trivia: 'ラテン語 reprimere（押し戻す）の能動行為者名詞に由来し、英語の repressor と同語源。生物学・分子生物学では repressor protein（リプレッサータンパク質）としてよく知られる英語用語と同じ語根を持つ。' },
  'reprimida / reprimido': { es: 'Llevaba una vida reprimida y, finalmente, decidió expresar sus emociones sin miedo.', ja: '彼女は抑圧された生活を送っていたが、ついに恐れずに感情を表現することを決意した。', trivia: '動詞 reprimir の過去分詞が形容詞化したもので、ラテン語 reprimere（押し戻す）に由来する。英語の repressed と同語源で、心理学的文脈での「抑圧された（感情・欲求）」という用法は英語 repressed からの影響を受けている。' },
  'reprobada / reprobado': { es: 'María llegó a casa llorando porque salió reprobada en el examen de matemáticas.', ja: 'マリアは数学の試験で不合格になったため、泣きながら家に帰ってきた。', trivia: '動詞 reprobar の過去分詞から形成された形容詞・名詞で、女性形。中南米のスペイン語では「落第した」という教育文脈で特に頻繁に使われ、英語の flunked に相当する口語的ニュアンスを持つ。' },
  'reprobatoria / reprobatorio': { es: 'El juez lanzó una mirada reprobatoria al acusado que no mostraba ningún arrepentimiento.', ja: '裁判官は、何の反省も示さない被告に非難の眼差しを向けた。', trivia: 'ラテン語 reprobare に由来する形容詞で、女性形。英語では reproving または disapproving に相当し、同根の reprobatory という英語形も存在するが極めてまれで、日常では disapproving が一般的。' },
  'reproductiva / reproductivo': { es: 'La salud reproductiva de la mujer es un tema central en las políticas de salud pública.', ja: '女性の生殖に関する健康は、公衆衛生政策における中心的なテーマだ。', trivia: 'ラテン語 reproducere（再び産み出す）の形容詞形・女性形。英語の reproductive と同語根で意味も形もほぼ同一の典型的コグネート。reproductive rights（生殖の権利）などの表現は国際的議論で英西語ともに共通して用いられる。' },
  'republicana / republicano': { es: 'La candidata republicana ganó las elecciones por un margen muy estrecho.', ja: '共和党の女性候補は僅差で選挙に勝利した。', trivia: 'ラテン語 res publica から派生した形容詞・名詞の女性形。英語の republican と同語根のコグネートで、アメリカの共和党（Republican Party）を指す場合も含め意味がほぼ一致する。スペイン語圏では米共和党員だけでなく「共和制を支持する人」という一般的意味でも使われる。' },
  'repuesta / repuesto': { es: 'Tras meses de rehabilitación, la atleta llegó repuesta y más fuerte que nunca a la competición.', ja: '数か月のリハビリを経て、そのアスリートは回復し、これまで以上に強くなって大会に臨んだ。', trivia: '動詞 reponer（再び置く・回復する）の不規則過去分詞の女性形で、ラテン語 reponere（re- 再び＋ ponere 置く）に由来する。英語の replace や restore と同語根の概念を持ち、英語では recovered / spare に相当。中南米の一部では「体格の良い・ふっくらした」という独特の意味でも使われる。' },
  'repulsiva / repulsivo': { es: 'La actitud repulsiva del personaje principal hace que sea difícil simpatizar con él.', ja: '主人公の嫌悪感を催す態度のせいで、彼に共感するのが難しい。', trivia: 'ラテン語 repulsivus の女性形で、英語 repulsive と完全な同語根。英語の repulsive も「嫌悪感を与える」と「反発する（物理）」の両義を持ち、スペイン語とほぼ同じ用法で使われる典型的なコグネート（cognate）ペアのひとつ。' },
  'reputada / reputado': { es: 'Esta universidad es muy reputada por la calidad de sus programas de posgrado.', ja: 'この大学は大学院プログラムの質の高さで非常に高い評判を得ている。', trivia: 'reputado の女性形で、ラテン語 reputatus（評価された）の過去分詞から派生した形容詞。英語の reputable（評判の良い）と同語根だが、英語 reputed（～と言われている）は必ずしも肯定的なニュアンスを持たない点が異なる。スペイン語 reputada はほぼ常に「定評ある・高名な」という肯定的な意味で使う。' },
  'requemada / requemado': { es: 'La carne requemada que sacaron del horno no tenía ningún sabor agradable.', ja: 'オーブンから取り出した焦げすぎた肉には、おいしい味が全くなかった。', trivia: 'quemar（燃やす）に re-（過剰・繰り返し）を付けた requemar の過去分詞の女性形。英語では overcooked や charred に相当し、直接の対応語はないが、quemar はラテン語 cremare（焼く）に由来し、英語 cremate（火葬する）と同語根。re- が「やりすぎ」を示す用法は英語の over- と対応する。' },
  'requiebro / requebrar': { es: 'Le dedicó un requiebro tan ingenioso que ella no pudo evitar sonreír.', ja: '彼はとても機知に富んだほめ言葉を贈ったので、彼女は思わず微笑んだ。', trivia: 'requebrar（口説く）の直説法現在1人称単数形が名詞にもなった語。語根の quebrar は「壊す・折る」だが、音声を細かく「折る」ように使う比喩から「甘い言葉で心を溶かす」という意味に転じた。英語では compliment や flattery に相当するが、この詩的・音楽的な転義の経緯は英語語彙にはなく、スペイン語独自の語彙の深みを示す。' },
  'resalada / resalado': { es: 'La profesora era tan resalada que todos los estudiantes querían asistir a su clase.', ja: 'その先生はとても愛嬌があり、すべての学生が彼女の授業に出たがっていた。', trivia: 're-（強調の接頭辞）＋ salada（塩辛い）の構成で、「塩が効きすぎた」が転じてスペインの口語では「ひときわ魅力的な」という意味になった。英語 salty には「皮肉な・むっとした」という現代スラング的な意味もあり、同じ「塩」でも比喩の方向が対照的で興味深い。' },
  'resalva / resalvo': { es: 'Los madereros respetaron la resalva marcada por el guarda forestal para mantener el bosque.', ja: '木材業者たちは森林を維持するために森林警備員が指定した残存木を尊重した。', trivia: 're-（再び）＋ salvar（救う・残す）に由来する林業専門用語で、「次世代の森のために残す木」を指す。英語の save と salvar は共通のラテン語語根 salvare（救う）を持ち、silva（森）という別のラテン語とは異なる由来だが、森林という文脈で混同されやすい。' },
  'resbaladiza / resbaladizo': { es: 'La situación política era tan resbaladiza que ningún partido quería pronunciarse claramente.', ja: '政治状況はあまりにもデリケートで、どの政党もはっきり発言しようとしなかった。', trivia: 'resbalar（滑る）に形容詞を作る接尾辞 -adizo を加えた形。英語の slippery も比喩的に「捕まえどころのない・信用できない」という意味を持ち、「滑らかなもの＝頼りにならない」という比喩は日英西語に共通するが、slippery の語源は北欧語・低地ドイツ語系で全く別の系統である。' },
  'rescatada / rescatado': { es: 'La niña rescatada del pozo fue recibida con aplausos por los vecinos del barrio.', ja: '井戸から救出された少女は、近所の人々に拍手で迎えられた。', trivia: 'rescatar（救出する）の女性過去分詞形。rescatar はゴート語（ゲルマン系）の wrakjan（追い立てる）またはラテン語 excaptare との混合起源が有力とされる。英語の rescue は古フランス語 rescourre（引き離す）に由来し、スペイン語 rescatar とは別経路でラテン系の「引き出す」概念を共有している。' },
  'rescisoria / rescisorio': { es: 'El abogado presentó una cláusula rescisoria que permitía anular el acuerdo en caso de incumplimiento.', ja: '弁護士は、不履行の場合に契約を無効にできる解除条項を提示した。', trivia: 'ラテン語 rescissorius（取り消しの）に由来する形容詞。英語では rescissory に相当するが、日常語としてはほぼ使われず、主に法律文書に登場する点はスペイン語と共通している。' },
  'resco / risco': { es: 'El montañero perdió el equilibrio cerca del resco y tuvo que aferrarse a las rocas para no caer.', ja: '登山者は断崖の近くでバランスを崩し、落ちないように岩にしがみつかなければならなかった。', trivia: 'risco（切り立った岩、断崖）の古い異体字または方言形とされ、語源は諸説あるが、ゲルマン語系の可能性も指摘されている。英語に直接の同語根語はなく、cliff や crag に意味が近い。' },
  'rescuentro / rescontrar': { es: 'El rescuentro de las cuentas reveló una diferencia de mil euros entre los dos registros.', ja: '帳簿の照合により、2つの記録の間に1000ユーロの差異があることが判明した。', trivia: 'rescontrar の直説法現在1人称単数形であり、語幹が変化する不規則動詞（e→ue）。語自体はイタリア語 riscontro（照合）からの借用語で、英語では account reconciliation に相当する会計用語。' },
  'reseca / reseco': { es: 'Después de caminar horas bajo el sol, tenía la garganta reseca y los labios agrietados.', ja: '何時間も炎天下を歩いた後、喉はカラカラで唇はひび割れていた。', trivia: 'resecar（ひどく乾燥させる）の過去分詞・形容詞形で、re-（強意）＋ secar（乾かす）から成る。英語の parched と意味が近く、secar はラテン語 siccare（乾かす）由来で、英語 desiccate とも同語根。' },
  'resentida / resentido': { es: 'Ella seguía resentida porque nunca recibió el reconocimiento que merecía por su trabajo.', ja: '彼女は自分の仕事に対して当然受けるべき評価を一度も得られなかったことで、いまだに根に持っていた。', trivia: 'resentir の過去分詞・形容詞の女性形で、re-（再び）＋ sentir（感じる）から成る。英語の resentful と完全に対応し、両言語ともラテン語 sentire（感じる）を語根とする。英語 sense、sentiment、sensitive も同じ語族に属する。' },
  'reservataria / reservatario': { es: 'Como reservataria, ella tiene derecho a recibir la legítima de la herencia.', ja: '遺留分権利者として、彼女は相続財産の法定相続分を受け取る権利を持つ。', trivia: 'ラテン語 reservare に法律上の代理人を示すサフィックス -ario/-aria を付けた造語で、スペイン語・ポルトガル語圏の相続法に特有の術語。英語の legal heir や forced heir に相当するが、英語には完全対応の単一語がない。' },
  'reseñada / reseñado': { es: 'La novela reseñada por el crítico literario se convirtió en un éxito de ventas al día siguiente.', ja: 'その文芸評論家にレビューされた小説は、翌日ベストセラーになった。', trivia: 'reseñar の過去分詞・形容詞の女性形で、「レビューされた・批評された」の意味。英語の reviewed と対応し、語根の signum（印）はラテン語に遡る。英語 sign、signal とも遠い親戚にあたる。' },
  'resignada / resignado': { es: 'Ella estaba resignada a perder el trabajo y empezó a buscar nuevas oportunidades.', ja: '彼女は仕事を失うことを受け入れ、新たなチャンスを探し始めた。', trivia: 'resignar の女性形過去分詞で形容詞として使われる。英語の resigned（諦めた・辞した）と同語根のコグネートで、「印を消す＝権利を放棄する」というラテン語の原義が「諦める」に転じた経緯は英語・スペイン語で共通している。' },
  'resinosa / resinoso': { es: 'La madera resinosa del pino es difícil de pintar porque el barniz no adhiere bien.', ja: '松の樹脂を含んだ木材は、ニスがうまく密着しないので塗装が難しい。', trivia: 'ラテン語 resinosus（樹脂の多い）に由来し、英語の resinous と同語根。スペイン語では女性形 resinosa・男性形 resinoso と語尾が変化する点が英語との違い。' },
  'resistón / resistona': { es: 'El niño es muy resistón y nunca quiere irse a la cama a su hora.', ja: 'その子はとても頑固で、決まった時間に寝ようとしない。', trivia: 'resistir（耐える・抵抗する）に口語的な増大接尾辞 -ón を加えた派生語。英語では stubborn や headstrong に相当するが、スペイン語の -ón 接尾辞は「やたら〜する人・物」という口語ニュアンスを加える点が特徴的。' },
  'resolutiva / resolutivo': { es: 'Necesitamos una persona resolutiva que sepa tomar decisiones rápidas bajo presión.', ja: 'プレッシャーの下で素早く判断を下せる、決断力のある人材が必要だ。', trivia: 'ラテン語 resolutivus に由来し、英語の resolute（断固とした）と同語根。英語では resolute が形容詞として定着しているのに対し、スペイン語では resuelto / resuelta がより口語的に「決断力がある」の意で使われることも多い。' },
  'resolutoria / resolutorio': { es: 'El contrato incluye una cláusula resolutoria que permite cancelarlo en caso de incumplimiento.', ja: 'その契約には、不履行の場合に解除できる解除条件条項が含まれている。', trivia: 'ラテン語 resolutorius に由来する法律用語で、英語の resolutory または defeasance clause に相当する。英語の法律用語では resolutory condition（解除条件）として使われ、スペイン語法学との共通の語源をもつ。' },
  'resoplada / resoplado': { es: 'Con una resoplada de impaciencia, el jefe cerró la carpeta y salió de la reunión.', ja: '上司は苛立ちのあまり大きく息を吐いてファイルを閉じ、会議室を出て行った。', trivia: 'resoplar（荒く息をする）の過去分詞から派生した名詞・形容詞。英語の snort や puff に相当するが、英語では動詞が主で対応する名詞形は複数ある（snort, puff, huff）。スペイン語では -ada 接尾辞が「一回の行為」を表す点が特徴。' },
  'resoplido / resorbancia': { es: 'Se oyó el resoplido del motor cuando el camión comenzó a subir la cuesta.', ja: 'トラックが坂を上り始めたとき、エンジンのうなり声が聞こえた。', trivia: 'resoplar の派生名詞で、英語の snort や puff に相当する。-ido という接尾辞はスペイン語で音や行為を名詞化する際によく使われ（ladrido「吠え声」、silbido「口笛」など）、英語には対応する規則的な接尾辞がない点が興味深い。' },
  'respectiva / respectivo': { es: 'Los dos equipos volvieron a sus respectivas ciudades después del torneo.', ja: 'トーナメントが終わり、2チームはそれぞれの都市へ戻った。', trivia: 'ラテン語 respectivus に由来し、英語の respective と同語根。英語でも Spanish and English are spoken in their respective countries（それぞれの国でスペイン語と英語が話される）のように使い方が非常に似ている。' },
  'respetada / respetado': { es: 'Es una profesora muy respetada por todos sus estudiantes y colegas.', ja: '彼女はすべての学生と同僚から非常に尊敬されている先生だ。', trivia: 'respetar の過去分詞の女性形で、ラテン語 respectare に由来。英語の respected と同語根・同用法で、形容詞として「定評のある、重んじられている」の意味を持つ。' },
  'respetuosa / respetuoso': { es: 'Siempre ha mantenido una actitud respetuosa hacia las personas mayores.', ja: '彼女はいつも年長者に対して礼儀正しい態度を保ってきた。', trivia: 'ラテン語 respectuosus に由来し、英語の respectful と同語根。英語では -ful 語尾を使うのに対し、スペイン語では -uoso/-uosa という接尾辞が用いられる点が対照的。' },
  'respiratoria / respiratorio': { es: 'El médico le diagnosticó una infección respiratoria leve y le recetó reposo durante una semana.', ja: '医師は彼女に軽い呼吸器感染症と診断し、1週間の安静を処方した。', trivia: 'ラテン語 respiratorius（呼吸に関する）に由来。英語の respiratory と完全に同語根の国際的な医学用語で、スペイン語・英語ともに医療分野でそのまま使われる。' },
  'resplando / resplandor': { es: 'El resplandor del sol al atardecer tiñó el cielo de tonos anaranjados y rojizos.', ja: '夕暮れ時の太陽の輝きが、空をオレンジや赤みがかった色に染めた。', trivia: 'ラテン語 resplendere（re-「再び」+ splendere「輝く」）に由来する。英語 splendor と同語根で、英語には resplendence という形もある。英語の glow（温かい光）に対し、resplandor はより強い・眩しい光のニュアンスを持つ。' },
  'resplandor / resplandores': { es: 'El resplandor del sol al atardecer tiñó el cielo de tonos anaranjados y rojizos.', ja: '夕暮れ時の太陽の輝きが、空をオレンジや赤みがかった色に染めた。', trivia: 'ラテン語 resplendere（re-「再び」+ splendere「輝く」）に由来する。英語 splendor と同語根で、英語には resplendence という形もある。英語の glow（温かい光）に対し、resplandor はより強い・眩しい光のニュアンスを持つ。' },
  'respondida / respondido': { es: 'Todas las preguntas del cuestionario fueron respondidas correctamente por el alumno más aplicado de la clase.', ja: 'アンケートの全質問は、クラスで最も勤勉な生徒によって正確に回答された。', trivia: '動詞 responder（答える）の過去分詞女性形。ラテン語 respondere（re-「再び」+ spondere「約束する」）に由来し、英語の respond・response・responsible はすべて同語根の兄弟語である。' },
  'respondona / respondón': { es: 'La profesora regañó a la niña respondona porque no paraba de contestar mal a sus compañeros.', ja: '先生は口答えばかりする女の子を叱った。彼女はクラスメートに失礼な言い返しをやめなかったからだ。', trivia: 'responder（答える）に強調の接尾辞 -ón/-ona が加わった形で、「過度に言い返す人」という否定的なニュアンスを持つ。英語に直訳できる同語根語はなく、cheeky や mouthy に相当するが、語構造としては英語の respondent（回答者）と同根。' },
  'responsor / responsoria': { es: 'El coro cantó la responsoria durante la misa solemne.', ja: '合唱団は荘厳ミサの間、交唱を歌った。', trivia: 'ラテン語 responsorium（応答歌）に由来するカトリック典礼用語で、聖職者と会衆または二つの合唱団が交互に歌う形式を指す。英語の responsory と同根で、gregorio聖歌（グレゴリオ聖歌）の重要な要素の一つ。' },
  'restada / restado': { es: 'La cantidad restada del total fue mayor de lo esperado.', ja: '合計から差し引かれた金額は予想以上に大きかった。', trivia: 'restar（引き算する）の過去分詞女性形。restar はラテン語 restare から派生し、英語の subtract に相当するが、動詞形は英語の subtracted と形が全く異なる。スペイン語では過去分詞が形容詞として性数一致する点が英語と大きく異なる。' },
  'restauradora / restaurador': { es: 'La restauradora examinó cuidadosamente cada grieta del fresco antes de comenzar su trabajo.', ja: '修復家は作業を始める前に、フレスコ画のひび割れを一つひとつ丁寧に調べた。', trivia: 'restaurar（修復する）の行為者名詞女性形。ラテン語 restaurator に遡り、英語の restorer と同語根・同形の対応語。英語では性別による語形変化がないが、スペイン語では restauradora（女性）/ restaurador（男性）と区別される。' },
  'restitutoria / restitutorio': { es: 'Se presentó una acción restitutoria para recuperar los documentos robados.', ja: '盗まれた書類を取り戻すために原状回復訴訟が提起された。', trivia: 'ラテン語 restitutor（返還者）に由来する法律用語の形容詞女性形。英語では restitutive や restitutory という対応語が存在するがほとんど使われず、通常は restitution claim や restoration order などの表現で代替される専門的な用語。' },
  'restregada / restregado': { es: 'La restregada del suelo dejó las baldosas completamente limpias.', ja: '床をごしごし擦ったおかげでタイルが完全にきれいになった。', trivia: 'restregar（強く擦る）の過去分詞女性形で、名詞としても使われる。restregar はラテン語 re-（繰り返し）+ fricare（こする）に由来するとされ、英語の friction（摩擦）と同語根の fricare から来ている点が興味深い。英語では rubbing や scrubbing に相当する。' },
  'restrego / restregar': { es: 'Cada mañana le doy un buen restrego al suelo de la cocina.', ja: '毎朝、台所の床をよくごしごしと擦り洗いする。', trivia: 'restregar の直説法現在1人称単数形であると同時に、名詞として「強くこする行為」も意味する。ラテン語 fricare（こする）に由来し、英語の friction と同語根。英語では動詞 rub の活用形 rub / I rub と動名詞 rubbing で同じ概念を表す。' },
  'restrictiva / restrictivo': { es: 'La nueva política es demasiado restrictiva y dificulta la innovación.', ja: '新しい方針はあまりにも制限的で、イノベーションを妨げている。', trivia: 'ラテン語 restrictivus に由来し、英語の restrictive と語源・形ともにほぼ同一のコグネート。英語文法でも restrictive clause（制限節）という用語があるように、言語学でも使われる形容詞。語根の stringere（縛る）は英語の strict とも共通する。' },
  'restringida / restringido': { es: 'El acceso a esa zona es restringida para el público en general.', ja: 'その区域への立ち入りは一般市民に対して制限されている。', trivia: 'ラテン語 restringere（再び縛る）に由来し、re-（再）＋ stringere（締める・縛る）が語源。英語の restricted と完全な同語根であり、string（紐）や strict（厳格な）とも同じ語根を持つ。' },
  'restrinjir / restringir': { es: '（警告）「restrinjir」という綴りは誤りであり、正しくは restringir です。', ja: '（注意）「restrinjir」というつづりは間違いで、正しくは restringir です。', trivia: 'これは restringir の誤った綴りとして流通することがある非標準形で、辞書に存在しない。スペイン語の -gir 動詞は yo 形で -jo となるため（restrinjo）、綴りの混乱が生じやすい。英語では restrict に相当する。' },
  'resubida / resubido': { es: 'Después de solucionar el error, hice una resubida del archivo corregido.', ja: 'エラーを修正した後、修正済みのファイルを再アップロードした。', trivia: 're-（再び）＋ subida（上げること・アップロード）から成る新造語で、インターネット時代に生まれたIT口語表現。英語の reupload に相当し、英語と同様に re- 接頭辞で「繰り返し」を表す点は共通しているが、スペイン語では subir（上げる）という方向性のある動詞を使う点が興味深い。' },
  'resucitada / resucitado': { es: 'La tradición resucitada por los jóvenes artistas atrajo mucha atención.', ja: '若い芸術家たちによって復活させられたその伝統は多くの注目を集めた。', trivia: 'ラテン語 resuscitare（再び呼び起こす）に由来し、re-（再び）＋ suscitare（目覚めさせる）が語源。英語の resuscitated（蘇生させられた）と同語根だが、宗教的文脈では英語では resurrected（復活した）が好まれる。' },
  'resuello / resollar': { es: 'Después de subir las escaleras corriendo, llegó sin resuello.', ja: '階段を駆け上がった後、彼は息も絶え絶えに到着した。', trivia: '動詞 resollar（荒い息をする）の名詞形で、ラテン語 sufflare（吹く）または折衷語源とされる。英語では breath や panting に相当するが、resuello は特に疲労や苦しさからくる荒い息遣いに使われる表現で、英語の wheeze とニュアンスが近い場合もある。' },
  'resuelta / resuelto': { es: 'Ella es una mujer resuelta que nunca duda antes de actuar.', ja: '彼女は行動する前に決して迷わない、決然とした女性だ。', trivia: 'ラテン語 resolvere（解き放つ、解決する）の過去分詞 resolutus に由来し、英語の resolute（決然とした）と同語根。英語では resolved と resolute が別々の語として存在するが、スペイン語では resuelto が両方の意味を持つ多義語として機能している。' },
  'resultada / resultado': { es: 'La situación resultada del conflicto fue más compleja de lo esperado.', ja: 'その紛争から生じた状況は予想以上に複雑だった。', trivia: 'resultar（結果として生じる）の過去分詞女性形で、ラテン語 resultare（跳ね返る・反響する）に由来する。英語の result と同語根であり、どちらも re-（再び）＋ saltare（跳ぶ）から成り、「跳ね返ってくるもの」が転じて「結果」を意味するようになった。' },
  'resultando / resultar': { es: 'El equipo trabajó durante meses, resultando en un producto de alta calidad.', ja: 'チームは何ヶ月も取り組み、結果として高品質な製品が生まれた。', trivia: 'resultar の現在分詞（ジェルンディオ）形で、英語の resulting に相当する。ラテン語 resultare（跳ね返る）に由来し、英語の result・resultant と同語根。英語の resultant（結果として生じる）は科学用語として残っており、スペイン語の resultante と形も意味も酷似している。' },
  'resumida / resumido': { es: 'La profesora entregó una versión resumida del texto para los alumnos.', ja: '先生は生徒たちに本文の要約版を配布した。', trivia: 'resumir（要約する）の過去分詞女性形で、ラテン語 resumere（再び取り上げる）に由来する。英語の summarized に相当するが、英語では summary（名詞）と summarize（動詞）が別の語根（ラテン語 summa）から来ており、スペイン語の resumen／resumir とは語源が異なる点が注目される。' },
  'resupinada / resupinado': { es: 'La seta tenía la superficie resupinada, pegada directamente sobre la corteza del árbol.', ja: 'そのキノコは子実体が倒旋していて、直接樹皮の上に張り付いていた。', trivia: 'ラテン語 resupinus（仰向けの・裏返した）に由来し、英語の resupinate と同語源の学術語。英語の supine（仰向けの・無気力な）とも関連しており、体勢・方向の逆転を表す接頭辞 re- の用法が共通する。' },
  'resurtida / resurtido': { es: 'La resurtida de mercancía llegó justo cuando los estantes estaban casi vacíos.', ja: '商品の再入荷は棚がほぼ空になった頃にちょうど届いた。', trivia: '動詞 resurtir（re-＋surtir 補充する）の過去分詞が名詞化したもので、英語の restock や replenishment に対応する。surtir 自体はアラビア語由来とも言われるが語源は諸説あり、中南米の商業・流通の文脈で広く使われる実務語。' },
  'retador / retadora': { es: 'El joven boxeador se mostró muy retador desde el primer asalto del combate.', ja: '若いボクサーは試合の第1ラウンドから非常に挑戦的な姿勢を見せた。', trivia: '動詞 retar（挑戦する）＋行為者接尾辞 -dor から成り、英語の challenger や challenging と意味的に対応する。retar はラテン語 reputare（再び考える・論争する）に由来するとされ、英語の repute（評判）とも遠縁の可能性がある。' },
  'retardador / retardadora': { es: 'Se añadió un retardador al cemento para prolongar el tiempo de fraguado en climas cálidos.', ja: '温暖な気候での硬化時間を延ばすために、セメントに遅延剤が添加された。', trivia: 'ラテン語 tardus（遅い）に由来し、英語の retarder と同語根。化学・建設・自動車工学など工業分野で広く使われる専門語で、英語でも retarder（遅延剤・リターダー）としてそのまま借用される国際的な技術語。' },
  'retasa / retasación': { es: 'Tras la crisis económica, se solicitó una retasa de los bienes inmuebles para ajustar los impuestos.', ja: '経済危機の後、税金を調整するために不動産の再査定が求められた。', trivia: 're-（再び）＋ tasa（税率・査定額）の構成で、tasa 自体はアラビア語 tassa（杯、量）を経由したとされる。英語の reappraisal に相当するが、英語には tasa に直接対応する同語根の日常語はなく、税率を意味する tax はラテン語 taxare 経由の別系統。' },
  'retasación / retaso': { es: 'La retasación del terreno fue imprescindible para determinar el precio justo de venta.', ja: '土地の再査定は、適正な売却価格を決定するために不可欠だった。', trivia: 'retasar（再査定する）の行為名詞形で、接尾辞 -ción はラテン語 -tionem に由来する典型的な名詞化パターン。英語の reappraisal や reassessment に対応するが、assessment 自体はラテン語 assidere（傍らに座る＝補佐する）から来ており、語根が異なる。' },
  'retenida / retenido': { es: 'La retenida del mástil evitó que la grúa se inclinara demasiado durante la operación.', ja: 'マストの控え綱のおかげで、作業中にクレーンが傾きすぎるのを防ぐことができた。', trivia: 'retener（保持する）の過去分詞の女性形が名詞化したもので、ラテン語 retinere（引き留める）に由来。英語の guys wire（控え綱）や stay に相当し、retain と同語根。英語の retain は法律・人材分野でよく使われるが、スペイン語の retenida は建築・船舶用語としての物理的「控え綱」という意味が際立つ。' },
  'retenida / retenimiento': { es: 'La retenida del mástil evitó que la grúa se inclinara demasiado durante la operación.', ja: 'マストの控え綱のおかげで、作業中にクレーンが傾きすぎるのを防ぐことができた。', trivia: 'retener（保持する）の過去分詞の女性形が名詞化したもので、ラテン語 retinere（引き留める）に由来。英語の guys wire（控え綱）や stay に相当し、retain と同語根。英語の retain は法律・人材分野でよく使われるが、スペイン語の retenida は建築・船舶用語としての物理的「控え綱」という意味が際立つ。' },
  'reticulada / reticulado': { es: 'La superficie reticulada del tejido muscular favorece la circulación del oxígeno.', ja: '筋肉組織の網目状の表面が酸素の循環を促進する。', trivia: 'reticular（網状にする）の過去分詞女性形で、ラテン語 reticulum（小さな網）に由来。英語の reticulated と同語根のコグネートで、「網目模様の」を意味する。英語では reticulated python（アミメニシキヘビ）のように動植物の模様の描写に使われることがあり、スペイン語でも同様の用法が存在する。' },
  'retostada / retostado': { es: 'La carne quedó retostada por fuera pero jugosa por dentro.', ja: '肉は外側はこんがりと焼けていたが、中はジューシーだった。', trivia: '接頭辞 re-（過度に）＋ tostar（焼く）から成り、ラテン語 torrere（焼く、干す）を語根とする。英語の toast も同じラテン語語根から来ており、「こんがり焼いたパン」を指す toast と同じ系譜。過度を示す re- の用法はスペイン語特有の口語的強調表現。' },
  'retozón / retozona': { es: 'El gatito retozón no paraba de perseguir su propio rabo por toda la habitación.', ja: 'じゃれん坊の子猫は、部屋中で自分の尻尾を追いかけるのをやめなかった。', trivia: 'retozar の形容詞派生形で、語尾 -ón は「その性質を強く持つ者」を意味するスペイン語典型の接尾辞。英語では playful や frisky に相当するが、frisky はノルウェー語起源とされており、スペイン語の retozón とは語源的なつながりはない。' },
  'retractil / retráctil': { es: 'Las garras retráctiles del gato le permiten mantenerlas afiladas en todo momento.', ja: '猫の引っ込み式の爪は、常に鋭く保つことを可能にする。', trivia: 'ラテン語 retractilis に由来し、英語の retractable にほぼ対応する技術・生物学用語。航空機の「格納式降着装置（引き込み脚）」も retractable landing gear（英）/ tren de aterrizaje retráctil（西）と表現され、両語の対応が非常に明確な専門語のひとつ。' },
  'retractor / retractora': { es: 'El cirujano utilizó un retractor para mantener abierta la incisión durante la operación.', ja: '外科医は手術中に切開部を開いたままにするため、開創器を使用した。', trivia: 'ラテン語 retractor（引き戻す者）に由来し、英語でも全く同じ retractor という形で医療器具を指す。外科手術で切開部や臓器を引き開けて視野を確保する器具で、英語・スペイン語双方の医学用語として国際的に統一された形を持つ例。' },
  'retrasada / retrasado': { es: 'La entrega del proyecto quedó retrasada debido a problemas técnicos inesperados.', ja: '予期しない技術的な問題のため、プロジェクトの納品が遅れた。', trivia: 'retrasar（遅らせる）の過去分詞の女性形で、ラテン語 trans-（向こうへ）が語根のひとつ。英語の delayed と意味が対応するが、delayed は古フランス語 delaier から来ており語源は異なる。なお、名詞的な用法の一部は現代では差別的とみなされており、discapacidad intelectual（知的障害）という表現が推奨される。' },
  'retratada / retratado': { es: 'La protagonista se ve retratada en el cuadro con una expresión solemne y distante.', ja: '主人公は、厳粛で遠い表情をした絵の中に描かれている。', trivia: 'ラテン語 \\\'retrahere\\\'（引き戻す・描き出す）の過去分詞形で、英語の \\\'portrayed\\\' に対応する。英語 \\\'portray\\\' はフランス語経由のラテン語 \\\'protrahere\\\'（前に引き出す）に由来し、スペイン語 \\\'retratar\\\' とは微妙に語根が異なる。' },
  'retratador / retratadora': { es: 'El retratador del siglo XIX captaba la esencia de sus clientes con maestría.', ja: '19世紀の肖像画家は、その巧みさで依頼人の本質を捉えていた。', trivia: 'ラテン語 \\\'retrahere\\\'（描き出す）＋スペイン語の行為者接尾辞 \\\'-ador\\\' から成り、現代では \\\'retratista\\\' が一般的。英語の \\\'portraitist\\\' に相当し、\\\'portray\\\' と同じくラテン語 \\\'trahere\\\'（引く）が共通の語根だ。' },
  'retraída / retraído': { es: 'Siempre fue una persona retraída, pero tenía una inteligencia excepcional.', ja: '彼女はいつも内向的な人だったが、並外れた知性の持ち主だった。', trivia: 'retraer の過去分詞から派生した形容詞の女性形で、英語の withdrawn や introverted に相当。英語の withdrawn はもともと「引き出された」という過去分詞が形容詞化したもので、スペイン語の retraída（引き戻された→内向的な）と全く同じ意味変化のプロセスをたどっている点が興味深い。' },
  'retributoria / retributorio': { es: 'El nuevo sistema retributorio premiará el rendimiento individual de cada empleado.', ja: '新しい報酬制度は各従業員の個人的なパフォーマンスを報奨する。', trivia: 'ラテン語 \\\'retribuere\\\'（返す・報いる）＋接尾辞 \\\'-torio/a\\\' から成り、英語の \\\'remunerative\\\' に相当する。英語の \\\'retributory\\\' は「応報的な」という意味合いが強く、スペイン語の中立的な「報酬に関する」とは微妙にニュアンスが異なる。' },
  'retrogradación / retrogrado': { es: 'La retrogradación del almidón explica por qué el pan se endurece al enfriarse.', ja: 'デンプンの老化現象が、パンが冷えると硬くなる理由を説明している。', trivia: 'ラテン語 \\\'retro-\\\'（後ろへ）＋ \\\'gradus\\\'（歩み）から成り、英語の \\\'retrogradation\\\' とほぼ同形のコグネートだ。天文学では惑星の「逆行」を指すが、食品科学では澱粉の「老化」も意味し、同じ語が分野によって異なる概念に転用されている。' },
  'retrogradación / retrogrados': { es: 'La retrogradación del almidón explica por qué el pan se endurece al enfriarse.', ja: 'デンプンの老化現象が、パンが冷えると硬くなる理由を説明している。', trivia: 'ラテン語 \\\'retro-\\\'（後ろへ）＋ \\\'gradus\\\'（歩み）から成り、英語の \\\'retrogradation\\\' とほぼ同形のコグネートだ。天文学では惑星の「逆行」を指すが、食品科学では澱粉の「老化」も意味し、同じ語が分野によって異なる概念に転用されている。' },
  'retrospectiva / retrospectivo': { es: 'El museo organiza una retrospectiva de los cuadros más famosos del artista para conmemorar su centenario.', ja: '美術館は芸術家の生誕百周年を記念して、その最も有名な絵画の回顧展を企画している。', trivia: 'ラテン語 retrospicere（retro「後ろに」+ specere「見る」）に由来し、英語の retrospective とまったく同じ語源を持つ。IT・アジャイル開発でも「ふりかえり」の意味で retrospective（英）/ retrospectiva（西）が国際的に使われる。' },
  'retrógrada / retrógrado': { es: 'Su actitud retrógrada respecto a la igualdad de género sorprendió a todos los presentes.', ja: 'ジェンダー平等に関する彼女の時代遅れな態度は、出席者全員を驚かせた。', trivia: 'ラテン語 \\\'retrogradus\\\'（後ろへ歩く）に由来し、英語の \\\'retrograde\\\' と形・意味ともに対応するコグネートだ。英語 \\\'retrograde\\\' は主に天文学用語や医学用語として使われるが、スペイン語 \\\'retrógrado/a\\\' は「保守的・反動的な人」という政治・社会的な意味でより頻繁に用いられる。' },
  'reumatóloga / reumatólogo': { es: 'La reumatóloga le recomendó ejercicio moderado para aliviar los síntomas de la artritis.', ja: 'リウマチ科医は、関節炎の症状を和らげるために適度な運動を勧めた。', trivia: '「rheûma（体液の流れ）＋ logos（学問）＋ -ista/-loga（専門家）」というギリシャ語の複合語から来ており、英語の rheumatologist と同語源。スペイン語では女性専門医を指す場合 -a 語尾を使う。' },
  'reumática / reumático': { es: 'Mi abuela reumática tiene dificultades para subir las escaleras en los días de frío.', ja: 'リウマチを患っている祖母は、寒い日に階段を上るのが大変だ。', trivia: 'ギリシャ語の「rheûma（流れ、体液の流れ）」に由来し、古代医学では体液の異常な流れが関節の痛みを引き起こすと考えられていた。英語の rheumatic と同語源で、現代医学でも広く使われる。' },
  'reunida / reunido': { es: 'La familia reunida alrededor de la mesa celebró el fin de año con mucha alegría.', ja: 'テーブルを囲んで集まった家族は、とても楽しく年末を祝った。', trivia: 'ラテン語の「re-（再び）＋ unire（一つにする）」に由来し、英語の reunite や reunion と同じ語根を持つ。過去分詞が形容詞として使われる典型的なスペイン語の用法。' },
  'revalidad / reválida': { es: 'Aprobó la reválida de medicina con una de las notas más altas de su promoción.', ja: '彼女は医師免許認定試験を学年最高点の一つで合格した。', trivia: 'ラテン語 revalidare（再び有効にする）に由来し、スペインでは20世紀中頃まで中等・高等教育の修了を国家が認定する統一試験を指した。英語の revalidation examination に相当するが、英語に同形の口語的な一語は存在せず、スペイン語ならではの教育文化的な語彙といえる。' },
  'revendedora / revendedor': { es: 'La revendedora compró cien entradas para el concierto y las vendió al triple del precio original.', ja: 'その転売屋はコンサートのチケットを100枚買い、定価の3倍で売りさばいた。', trivia: '«re-» （再び）＋ «vender»（売る）から派生した名詞で、ラテン語 «vendere»（売る）が語根。英語の «reseller» や «scalper»（チケット転売屋）に対応し、同語根の英単語には «vend»（自販機で売る）や «vendor» がある。' },
  'revenida / revenido': { es: 'El pan revenido del día anterior ya no estaba bueno para comer.', ja: '前日の湿気ったパンはもう食べられる状態ではなかった。', trivia: '動詞 «revenir»（戻る・なる）の過去分詞で、「しっとりしすぎた状態に戻った」というニュアンスから「しけった・湿気った」を意味する。英語に直接対応する同語根語はないが、金属の「焼き戻し」の意味では英語の «tempering» に相当する技術用語として使われる。' },
  'reventón / reventona': { es: 'Tuve un reventón en la autopista y tuve que llamar a la grúa.', ja: '高速道路でパンクして、レッカー車を呼ばなければならなかった。', trivia: '«reventar» の名詞形（接尾辞 «-ón» は「大きな〜・強烈な〜」を示す増大辞）。英語では「タイヤのパンク」を «blowout» と言い、意味・イメージが非常に近い表現同士。メキシコ口語で「大パーティー」を指す用法は、英語の «blowout party» とも重なる興味深い意味の一致がある。' },
  'revessar / revistar': { es: 'El general revistó a las tropas antes de que partieran hacia la frontera.', ja: '将軍は部隊が国境へ向けて出発する前に閲兵を行った。', trivia: '«re-» ＋ «vistar》（見る）、さらにラテン語 «videre》（見る）が語根で、英語 «review》・«visit》・«vision》と同語族。英語の «inspect》（ラテン語 «inspicere》）とは語根は異なるが意味が近く、軍事文脈では «review troops》に対応する。' },
  'reír / reírse': { es: 'No pude evitar reír cuando vi la cara de susto de mi hermano.', ja: '弟の驚いた顔を見たとき、笑いをこらえることができなかった。', trivia: 'ラテン語の ridere（笑う）に由来し、この語根から英語の ridiculous（滑稽な）や ridicule（あざ笑う）も生まれている。直接「笑う」を表す英単語 laugh はゲルマン語系で語源が異なるが、reír の痕跡は英語の派生語に残っている。' },
  'reñida / reñido': { es: 'La final fue tan reñida que el resultado no se decidió hasta el último segundo.', ja: '決勝はとても接戦で、結果は最後の1秒まで決まらなかった。', trivia: 'reñido は動詞 reñir（口論する・争う）の過去分詞で、ラテン語 rignere / ringere（歯をむく・唸る）に由来するとされるが、語源には諸説ある。英語には対応する同語根語がなく、hard-fought や fiercely contested のように迂言的に表現する。' },
  'riga / restinga': { es: 'El barco encalló en una riga oculta que no aparecía en las cartas náuticas.', ja: '船は海図に載っていない隠れた砂堆に座礁した。', trivia: '語源は不明・諸説あり、ポルトガル語や古いスペイン語の航海用語に由来するとも言われる。英語では sandbank や shoal に相当し、浅瀬や隠れ礁を指す地理的専門用語。ラトビアの首都 Riga とは語源が異なる別語。' },
  'sabana / sábana': { es: 'Después del lavado, tendí las sábanas al sol para que se secaran bien.', ja: '洗濯の後、シーツをよく乾かすために日光の下に広げた。', trivia: 'ラテン語 «sabana》（亜麻布）が語源とされ、元はカリブ先住民語由来の «sabana》（大草原）とはアクセント位置で区別される（sábana＝シーツ vs sabana＝サバンナ）。英語 «sheet》はゲルマン語系で語源が異なるが、英語 «savanna/savannah》はスペイン語 «sabana》を経由して入った借用語。' },
  'sabanero / sabanera': { es: 'El cantante sabanero interpretó una canción típica de los llanos colombianos.', ja: 'そのサバンナ出身の歌手はコロンビアの大平原の典型的な歌を歌った。', trivia: '«sabana》（サバンナ、タイノ語由来）＋形容詞・名詞接尾辞 «-ero》から派生した語。英語に直接対応する語はなく、「サバンナのカウボーイ」を指す場合は «plainsman》や «llanero》（別のスペイン語）で表現される。英語 «savanna》はスペイン語 «sabana》を経由した借用語であるため、間接的に同語族と言える。' },
  'sabihonda / sabihondo': { es: 'La sabihonda de la clase siempre interrumpía al profesor para demostrar que lo sabía todo.', ja: 'クラスの知ったかぶり屋はいつも、何でも知っていることを見せようと先生の話を遮った。', trivia: '«saber》（知る）＋ «-hondo/-honda》（深い、ラテン語 «profundus》由来）が合わさった合成語で、「知識が深い（つもりの）人」が皮肉に転じた。英語の «know-it-all》と意味・ニュアンスが非常に近く、英語にも «wiseacre》という似た意味の古語があるが現在は «know-it-all》が一般的。' },
  'sabio / sabia': { es: 'El sabio maestro nos enseñó que escuchar es más importante que hablar.', ja: 'その賢明な先生は、話すよりも聞くことの方が大切だと教えてくれた。', trivia: 'ラテン語 sapius（賢い）から来ており、英語の sage（賢者、セージ）と同語根。英語で wise に相当するが、英語 wise はゲルマン語系（古英語 wīs）で語源が異なる点が興味深い。' },
  'sablear / sablar': { es: 'No me gusta salir con él porque siempre intenta sablearme cuando llegamos a la caja.', ja: '彼とは外出したくない。会計になるといつも私にたかろうとするから。', trivia: 'sablar と同じく sable（サーベル）から派生した動詞で、sablar の同義語または変形として用いられる。英語に直接対応する同語根語はないが、to sponge off someone（たかる）が意味的に近い表現。' },
  'saboteadora / saboteador': { es: 'La saboteadora fue detenida antes de poder inutilizar el generador eléctrico.', ja: 'その女性破壊工作員は発電機を壊す前に拘束された。', trivia: 'sabotear の行為者名詞で、英語の saboteur に相当する。英語 saboteur はフランス語から直接借用されたのに対し、スペイン語では動詞 sabotear に -dor/-dora の接尾辞を付けて派生させており、語形成の方法が異なる。' },
  'sabrosa / sabroso': { es: 'Esta salsa picante es muy sabrosa y va perfecta con el arroz.', ja: 'この辛いソースはとても美味しくて、ご飯によく合う。', trivia: 'ラテン語 sapor（風味、味）から派生しており、英語の savory（風味豊かな）と同語根。英語 tasty や delicious はそれぞれゲルマン系・フランス系語源で別語族だが、savory だけがスペイン語 sabroso と共通の語根を持つ近縁語。' },
  'sacabocado / sacabocados': { es: 'El técnico utilizó un sacabocado para hacer los agujeros en la correa de cuero.', ja: '技術者は革ベルトに穴を開けるためにポンチを使った。', trivia: 'sacar（取り出す）と bocado（一口、穴）を組み合わせた複合語で、「一口分を抜き取る道具」という意味合いを持つ。英語の punch（穴あけ器）とは全く語源が異なり、英語 punch はラテン語 punctum（刺す）に由来する。' },
  'sacadinero / sacadineros': { es: 'Ese parque de atracciones es un sacadinero: pagas una fortuna por nada.', ja: 'あの遊園地は金食い虫だ。何もないのに大金を払わされる。', trivia: 'sacar（取り出す）＋dinero（お金）の複合語で、「金をむしり取るもの」という意味。英語の money pit（際限なく金がかかるもの）や rip-off（ぼったくり）に相当するが、英語にこの語根の同形語はなく、スペイン語独自の複合語命名スタイルを反映している。' },
  'sacarino / sacarina': { es: 'El sabor sacarino de ese refresco artificial me resulta desagradable comparado con el jugo natural.', ja: 'その人工飲料の砂糖っぽい甘さは、天然ジュースと比べると私には不快に感じられる。', trivia: 'sacarino（糖分の、砂糖のような）はラテン語saccharum（砂糖）から派生した形容詞。英語のsaccharine（甘ったるい、過度に甘い）は転じて「ぞっとするほど甘い、嘘っぽい感傷的な」という比喩的意味でも使われ、スペイン語でも同様のニュアンスが生じつつある。' },
  'sacatinta / sacatintas': { es: 'El sacatinta que utilizaba mi abuela para corregir errores de escritura era muy eficaz, aunque ya nadie lo usa.', ja: '祖母が書き間違いを修正するために使っていたインク消しはとても効果的だったが、今ではもう誰も使わない。', trivia: 'sacatintaはsacar（取り出す・消す）とtinta（インク）の合成語で「インクを消すもの」という意味。英語ではink eraserと言い、eraserはラテン語eradere（根こそぎにする）に由来する。「消す」という概念をスペイン語は「取り出す」、英語は「根こそぎにする」という異なる比喩で表現している。' },
  'saciada / saciado': { es: 'Después de comer tanto en la fiesta, me fui a casa completamente saciada y sin ganas de cenar.', ja: 'パーティーでたくさん食べた後、完全に満腹になって夕食を食べる気なしに家に帰った。', trivia: 'saciada（満ち足りた、の女性形）は動詞saciar（満たす）の過去分詞で、ラテン語satiare（満足させる）に由来する。英語のsatiatedも同語根のラテン語借用語であり、satis（十分）という語幹はsatisfy（満足させる）やsatisfaction（満足）にも含まれる。' },
  'sacra / sacro': { es: 'La música sacra de Bach todavía se interpreta en muchas catedrales europeas durante la Semana Santa.', ja: 'バッハの宗教音楽はイースター期間中、今でもヨーロッパの多くの大聖堂で演奏される。', trivia: 'sacra（神聖な、の女性形）はラテン語sacer（神聖な、禁じられた）に由来する。英語のsacred（神聖な）も同語根であり、sacrilege（冒涜）、sacrifice（犠牲）、sanctuary（聖域）なども同じ語幹sacr-を持つ。また「禁じられた」という元の意味はtabooの概念とも重なる。' },
  'sacratísima / sacratísimo': { es: 'El obispo invocó el nombre de la Sacratísima Virgen al iniciar la ceremonia solemne en la catedral.', ja: '司教は大聖堂での厳粛な式典を始める際に、至聖なる聖母マリアの御名を唱えた。', trivia: 'sacratísimaはsacro/sacra（神聖な）の絶対最上級女性形で、ラテン語sacratissimus（最も神聖な）に直接対応する。英語ではmost sacredという分析的な表現を用い、合成された最上級語形はない。ラテン語からスペイン語には最上級接尾辞-ísimoが継承されたが、英語はゲルマン語的な分析的表現に移行した点が対照的である。' },
  'sacrificada / sacrificado': { es: 'Ella llevó una vida sacrificada, dedicando cada hora a su familia.', ja: '彼女は家族のために毎時間を捧げた、自己犠牲的な人生を送りました。', trivia: 'ラテン語 sacrificium（供犠）の動詞形 sacrificare の過去分詞で、英語の sacrificial や self-sacrificing に相当。英語 sacrifice もラテン語 sacer（神聖）+ facere（行う）の合成語で、まったく同じ語根を共有する。' },
  'sacrificador / sacrificadora': { es: 'El sacerdote actuaba como sacrificador en las ceremonias religiosas antiguas.', ja: 'その司祭は古代の宗教的儀式において生贄を捧げる者として役割を担っていました。', trivia: 'ラテン語 sacrificare（供犠を行う）＋行為者接尾辞 -dor から成り、英語では sacrificer または sacrificial priest に相当する。英語に直接対応する1語はなく、スペイン語の語形成の豊かさが際立つ例である。' },
  'sacrosanta / sacrosanto': { es: 'Para él, la privacidad familiar es una cuestión sacrosanta que nadie debe violar.', ja: '彼にとって、家族のプライバシーは誰も侵してはならない絶対不可侵のことです。', trivia: 'ラテン語 sacrosanctus（sacer「神聖」＋ sanctus「清められた」）に由来し、英語の sacrosanct と完全に同語根。英語の sacrosanct は現在では比喩的に「絶対に変えてはならない」という意味で政治・議論の文脈でよく使われるが、スペイン語でも同じ比喩的拡張が見られる。' },
  'sacrílega / sacrílego': { es: 'La actitud sacrílega del visitante escandalizó a todos los presentes en la catedral.', ja: 'そのカテドラルで居合わせた全員が、訪問者の冒涜的な態度に衝撃を受けました。', trivia: 'ラテン語 sacrilegus（神聖なものを盗む者）の形容詞形で、英語の sacrilegious と同語根。英語 sacrilegious の発音は -reli- の部分が「レリ」となりアクセントも異なるが、スペイン語 sacrílego はラテン語の強勢位置をそのまま保つ点が特徴的。' },
  'sacudidor / sacudidora': { es: 'Mi abuela usaba un sacudidor de plumas para limpiar los muebles cada semana.', ja: '祖母は毎週羽のはたきを使って家具を掃除していました。', trivia: 'sacudir（揺さぶる・はたく）＋行為者・道具接尾辞 -dor から成り、ラテン語 succutere に由来する。英語ではほこり払いの道具を duster や feather duster と呼び、「shaker」とは言わない点がスペイン語と異なる。' },
  'safira / zafiro': { es: 'Encontraron una safira de gran tamaño entre las joyas del antiguo tesoro real.', ja: '古い王家の宝物の中から、大きなサファイアが見つかった。', trivia: 'zafiro の異形で、ヘブライ語 sappir またはギリシャ語 sappheiros に由来し、アラビア語 safīr を経由してスペイン語に入ったとされる。英語の sapphire と同語源で、ラテン語 sapphirus を通じて欧州各語に広まった。現代スペイン語では zafiro が標準形。' },
  'safra / zafra': { es: 'Durante la safra, miles de trabajadores llegan a los cañaverales para participar en la cosecha de caña de azúcar.', ja: 'サトウキビの収穫期には、何千人もの労働者がサトウキビ畑に収穫のためにやって来る。', trivia: 'zafra の異形で、アラビア語 safra\\\'（黄色、または収穫）に由来するとされる。ブラジルやキューバなどスペイン語・ポルトガル語圏の中南米で広く使われる農業用語。英語には直接対応する単語がなく、sugar cane harvest season と説明的に訳す。' },
  'sagita / sagitta': { es: 'En geometría, la sagita es la distancia entre el punto medio de un arco y el punto medio de su cuerda.', ja: '幾何学において、サジタとは弧の中点とその弦の中点との間の距離である。', trivia: 'ラテン語 sagitta（矢）から直接来ており、弧から弦への垂線が矢のように見えることからこの名がついた。英語の mathematical term sagitta と同じ語で、天文学では Sagitta（や座）という星座名にもなっている。英語の arrow とは語源が異なる。' },
  'sagrada / sagrado': { es: 'Para muchas culturas indígenas, la tierra es sagrada y debe ser protegida de la explotación industrial.', ja: '多くの先住民文化にとって、大地は神聖なものであり、産業による搾取から守られなければならない。', trivia: 'ラテン語 sacratus（sacro の過去分詞、「聖別された」の意）に由来し、英語の sacred と同語源。英語の sacrifice（犠牲）、sacrament（秘跡）、sanctuary（聖域）なども同じ語根 sacer（神聖な）を共有しており、宗教語彙の豊かな一族を形成している。' },
  'sahumada / sahumado': { es: 'La carne sahumada con hierbas aromáticas tenía un sabor incomparable en aquella región andina.', ja: 'ハーブの香煙で燻されたその肉は、アンデスのその地域では比類ない味わいだった。', trivia: '動詞 sahumar（香煙で燻す）の過去分詞から派生した形容詞・名詞で、ラテン語 sub-（下に）＋ fumare（煙る）の合成が語源。英語の perfume も同じく per-（通して）＋ fumare に由来し、煙の概念を共有する。' },
  'sahína / zahína': { es: 'En algunas regiones de España, la sahína se cultivaba junto al mijo para alimentar al ganado.', ja: 'スペインの一部の地域では、モロコシは家畜の飼料として粟と一緒に栽培されていた。', trivia: 'zahína（サイナ）の異形で、アラビア語 al-dhurra（ソルガム）に由来するとされる。英語の sorghum はラテン語 Syricum（シリアの）を経由しており、スペイン語形とは語源ルートが異なる。' },
  'sajón / sajona': { es: 'El influjo sajón en el inglés moderno es evidente en el vocabulario cotidiano más básico.', ja: '現代英語におけるサクソン語の影響は、最も基本的な日常語彙に明らかに見られる。', trivia: 'ラテン語 Saxo（サクソン人）に由来し、ゲルマン民族の部族名が語源。英語の Saxon と同語根の明確な借用語であり、Anglo-Saxon（アングロサクソン）という複合語も両言語で共有されている。スペイン語では anglosajón という形も広く使われ、英語圏文化全体を指す場合がある。' },
  'salada / salado': { es: 'La sopa estaba tan salada que nadie pudo terminarla.', ja: 'そのスープはあまりにも塩辛くて、誰も飲み干すことができなかった。', trivia: 'sal（塩）に形容詞接尾辞 -ado/-ada を加えた語で、ラテン語 sal（塩）が語源。英語の salty、salted と同語根であり、sauce（ソース）、salad（サラダ）、salary（給与）もすべてラテン語 sal に由来する大家族。古代ローマでは兵士への給与が塩で支払われたことが salary の語源として有名。' },
  'salamandra / salamandras': { es: 'La salamandra común puede regenerar sus extremidades perdidas, lo que la convierte en objeto de estudio científico.', ja: 'イモリは失った手足を再生できるため、科学研究の対象となっている。', trivia: 'ギリシャ語 salamandra に由来し、ラテン語を経てスペイン語・英語に入った。英語の salamander と全く同形の借用語（コグネート）。中世の伝説では火の中でも生き続ける生き物とされ、錬金術の象徴でもあった。現在の salamander は英語料理用語で「上火強火焼き器」としても使われ、スペイン語も同様の用法がある。' },
  'salame / salami': { es: 'En la pizzería pedimos una pizza de salame con aceitunas negras y mozzarella.', ja: 'ピッツェリアで、ブラックオリーブとモッツァレラ入りのサラミピザを注文した。', trivia: 'イタリア語 salame（複数: salami）に由来し、さらにラテン語 sal（塩）が語源で「塩漬けにしたもの」を意味する。英語でも salami としてイタリア語から直接借用されており、スペイン語も同形で使われる。アルゼンチン口語で「バカ・まぬけ」を意味する点は、イタリア系移民が多い文化的背景を反映している。' },
  'salame / salamis': { es: 'En la pizzería pedimos una pizza de salame con aceitunas negras y mozzarella.', ja: 'ピッツェリアで、ブラックオリーブとモッツァレラ入りのサラミピザを注文した。', trivia: 'イタリア語 salame（複数: salami）に由来し、さらにラテン語 sal（塩）が語源で「塩漬けにしたもの」を意味する。英語でも salami としてイタリア語から直接借用されており、スペイン語も同形で使われる。アルゼンチン口語で「バカ・まぬけ」を意味する点は、イタリア系移民が多い文化的背景を反映している。' },
  'salamin / salami': { es: 'Me gusta preparar una tabla de embutidos con salami, queso manchego y aceitunas.', ja: 'サラミとマンチェゴチーズ、オリーブを使って盛り合わせプレートを作るのが好きだ。', trivia: 'イタリア語 salame（塩漬け肉）の複数形 salami が英語・スペイン語に入った語で、ラテン語 sal（塩）に由来する。英語でも salami とそのままの形で使われ、同語根の英単語 salt や salary と親戚関係にある。' },
  'salariada / salariado': { es: 'Como trabajadora salariada, tiene derecho a vacaciones pagadas y seguro médico.', ja: '給与雇用者として、彼女は有給休暇と医療保険を受ける権利がある。', trivia: 'スペイン語 salario（給与）から派生した形容詞・名詞で、ラテン語 salarium に遡る。英語の salaried（給与制の）と同語根で、英語 salary もこの系譜に属する。古代ローマで兵士に塩（sal）が報酬として支給されたという説があるが、これには異論もある。' },
  'salchichero / salchichera': { es: 'El salchichero del pueblo prepara sus embutidos siguiendo una receta familiar de tres generaciones.', ja: '村のソーセージ職人は、三世代に渡って受け継がれた家族のレシピで加工肉を作っている。', trivia: 'salchicha（ソーセージ）に職業を表す接尾辞 -ero を加えた語で、英語では sausage maker または charcutier（フランス語由来）に相当する。英語の -er 接尾辞と同様に、スペイン語の -ero も職業・担当者を表す点で共通の発想を持つ。' },
  'salcochar / sancochar': { es: 'En muchos países latinoamericanos se suele salcochar la yuca antes de freírla.', ja: '中南米の多くの国では、ユカ芋は揚げる前に塩水で下茹でするのが一般的だ。', trivia: 'sal（塩）と cochar（古形：煮る、ラテン語 coquere に由来）の合成語とみられ、英語の salt と cook が合わさったような発想の語。英語 cook・cuisine・culinary はすべてラテン語 coquere を共通の語源に持つ。中南米では sancochar という形も広く使われる。' },
  'saldis / saldar': { es: 'Con el descuento de fin de temporada, encontramos varios artículos en saldis a precios increíbles.', ja: 'シーズン末のセールで、信じられないほどの価格でいくつかの品物を処分品として見つけた。', trivia: '動詞 saldar（精算する・バランスをとる）の古形・派生形で、イタリア語 saldo（残高・バランス）に由来する。英語の sale（セール）と語源的に近く、「残高を清算すること＝値引き販売」という意味の転換が見られる。' },
  'salerosa / saleroso': { es: 'La actriz tenía una forma salerosa de contar sus anécdotas que hacía reír a todos los presentes.', ja: 'その女優は、その場にいる全員を笑わせる愛嬌たっぷりのエピソードの語り方をしていた。', trivia: 'salero（ユーモア・魅力）に形容詞化接尾辞 -oso/-osa を付けた語で、「塩味が効いている＝ウィットがある」という比喩から生まれた。英語には直訳しにくいが、charming・witty に近く、スペイン南部アンダルシア文化の陽気さを体現する言葉とされる。' },
  'sales / sal': { es: 'El médico recomendó tomar sales minerales para recuperarse más rápido tras el ejercicio intenso.', ja: '医師は激しい運動後の回復を早めるため、ミネラル塩を摂取することを勧めた。', trivia: 'sal（塩）の複数形で、化学・医学用語としては「塩類」を意味する。英語の salts（塩類）と完全に対応し、salt・salary・sauce・sausage など広い語族を形成するラテン語 sal に遡る。「smelling salts（嗅ぎ塩）」という英語表現も同語根。' },
  'salgada / salgado': { es: 'La comida quedó demasiado salgada porque añadimos sal dos veces por equivocación.', ja: '間違えて塩を二度加えてしまったので、料理がしょっぱくなりすぎた。', trivia: 'ポルトガル語・ガリシア語で「塩辛い」を意味する salgado/salgada に相当し、スペイン語標準形 salado/salada とは異なるが同語源（ラテン語 salsus）。英語の salty と同語根で、スペイン語 salado・ポルトガル語 salgado・英語 salty はすべてラテン語 sal の派生語として一致する。' },
  'salia / salina': { es: 'Las salinas de Torrevieja producen miles de toneladas de sal marina cada año.', ja: 'トレビエハの塩田は毎年何千トンもの海塩を生産している。', trivia: 'ラテン語 salinae（塩田）の複数形に由来し、sal（塩）が語根。英語では salt flat・salt pan・salt works に相当するが、英語に salina という語も存在し（塩湖・塩田の意味で）そのままスペイン語から借用されている。米国カリフォルニア州の Salinas 市名もこれに由来する。' },
  'salinera / salinero': { es: 'La empresa salinera local lleva más de cien años produciendo sal artesanal.', ja: '地元の製塩会社は100年以上にわたって伝統的な塩を製造し続けている。', trivia: 'ラテン語 sal（塩）に由来する形容詞・名詞。英語には salt-making や salt industry に相当する単語があるが、salinera のように製塩業者・製塩工場を一語で表す専用語は少なく、スペイン語の語彙の豊富さを示す例。' },
  'salino / salina': { es: 'El médico le administró suero salino para rehidratarlo después del episodio de vómitos.', ja: '医師は嘔吐発作の後、彼を水分補給するために生理食塩水を投与した。', trivia: 'ラテン語 salinus（塩の）に由来し、英語の saline と完全に同語根。英語でも saline solution（生理食塩水）として医療現場で頻用される。インド＝ヨーロッパ語祖語 *sal- は英語の salt、ドイツ語の Salz とも共通する古い語根。' },
  'salitrero / salitrera': { es: 'El suelo salitrero de la región hace difícil el cultivo de cualquier planta.', ja: 'その地域の硝石質の土壌は、どんな植物の栽培も困難にしている。', trivia: 'salitre（硝石）から派生した形容詞・名詞で、「硝石の多い」または「硝石産業に関わる人」を意味する。英語では nitrate や saltpeter を用いた複合語（saltpeter worker, nitrate miner）に相当。語根のラテン語 sal は英語 salt と同じインド＝ヨーロッパ語祖語 *sal- に由来。' },
  'salitrosa / salitroso': { es: 'La tierra salitrosa de la llanura hacía imposible cultivar trigo o maíz.', ja: '平原の硝石質の土は小麦やトウモロコシの栽培を不可能にしていた。', trivia: 'salitre（硝石）＋ 形容詞接尾辞 -osa（豊富に〜を含む）から成る。英語では nitrous や saline に近いが、salitrosa はより「硝石や塩が表面に浮き出た」イメージを持つ。英語の nitrous も窒素・硝石系化合物を形容するが語源はギリシャ語 nitron（炭酸ナトリウム）で、sal 系語根とは異なる。' },
  'salmonada / salmonado': { es: 'Eligieron una pintura salmonada para las paredes del salón, que daba un ambiente cálido y acogedor.', ja: '彼らはリビングの壁にサーモンピンクの塗料を選んだ。温かく居心地の良い雰囲気が生まれた。', trivia: '魚のサーモン（salmón）を語源とし、その身の色を形容する語。英語でも salmon pink または salmon-colored と表現し、色名としてのサーモンはスペイン語・英語ともに魚の名前がそのまま色名になった珍しい例。' },
  'salmódica / salmódico': { es: 'La recitación salmódica del monje llenaba la capilla de una atmósfera de profunda serenidad.', ja: '修道士の賛美歌調の朗唱が礼拝堂を深い静けさの雰囲気で満たしていた。', trivia: 'ギリシャ語 psalmōidia（詩篇の歌）に由来し、ラテン語 psalmodia を経てスペイン語に入った。英語の psalmodic と同語根で、psalm（詩篇）はギリシャ語 psalmos（竪琴を弾く音）から来ている。比喩的に「単調でお経のような」という否定的ニュアンスでも使われる点は英語でも共通。' },
  'salomónica / salomónico': { es: 'La jueza adoptó una solución salomónica que dejó a ambas partes parcialmente satisfechas.', ja: '女性裁判官は双方が部分的に納得できるソロモン的な解決策を採った。', trivia: '旧約聖書のソロモン王（ヘブライ語 Shlomoh）に由来し、英語の Solomonic と完全に同語根。「赤ちゃんを二つに分ける」という有名な裁きから「知恵ある公平な判断」を意味するようになった。建築では「ソロモン神殿の柱」を模したねじれ柱（columna salomónica）を指す専門用語でもある。' },
  'salpimentar / salpimento': { es: 'Antes de poner la carne en la sartén, hay que salpimentarla bien por ambos lados.', ja: '肉をフライパンに入れる前に、両面にしっかり塩コショウをしなければならない。', trivia: 'sal（塩）と pimienta（コショウ）を動詞化した複合語で、英語の「season with salt and pepper」を一語で表した実用的な表現。英語には対応する一語の動詞がなく、スペイン語の料理語彙の簡潔さを示す好例。pimienta はラテン語 pigmentum（染料・スパイス）に由来し、英語の pigment と同語根という意外な関係がある。' },
  'salpique / salpicar': { es: 'El médico advirtió que no salpique la herida con agua sucia para evitar infecciones.', ja: '医師は、感染を防ぐために汚れた水を傷口に飛ばさないよう警告した。', trivia: 'salpicarの接続法現在1・3人称単数形。動詞 salpicar はラテン語の sal（塩）と picar（突く・刺す）の合成語に由来するとも、ゲルマン系の擬音語起源とも言われる。英語の splash や splatter に意味が近いが、語源的な直接の親戚ではない。' },
  'salpullido / sarpullido': { es: 'Al niño le salió un salpullido en el brazo después de jugar en el jardín.', ja: 'その子どもは庭で遊んだ後、腕に発疹が出た。', trivia: 'sal（塩、転じて「粒状のもの」）と pullido（皮膚の状態）に由来するとされ、皮膚に粒が出る状態を表す。英語の rash（発疹）に意味が対応するが、語源は異なる。sarpullido とも言われ、地域によって綴りが揺れる。' },
  'salsero / salsera': { es: 'Mi primo es un salsero apasionado que lleva diez años bailando en concursos internacionales.', ja: '私のいとこは情熱的なサルサダンサーで、10年間国際大会で踊り続けている。', trivia: 'salsa（ラテン語 salsa に由来）に接尾辞 -ero（「〜に関わる人・もの」）を付けた語。英語には salsa dancer / salsa musician という表現があるが、salsero のように1語で表す名詞はない。また接尾辞 -ero は英語の -er に対応することが多い（panadero → baker など）。' },
  'saltadiza / saltadizo': { es: 'La pintura saltadiza del techo empezó a caerse tras las lluvias intensas.', ja: '天井の剥がれやすい塗装が、激しい雨の後から落ちはじめた。', trivia: 'saltar（跳ぶ・はじける、ラテン語 saltare）に形容詞接尾辞 -adizo（「〜しやすい傾向がある」）を付けた語。英語の flaky（剥がれやすい）や brittle（もろい）に近い意味を持ち、接尾辞 -adizo は英語の -prone や -able に対応することがある。' },
  'saltador / saltadora': { es: 'El saltador de pértiga batió el récord nacional con un salto de seis metros.', ja: '棒高跳びの選手が6メートルの跳躍で国内記録を更新した。', trivia: 'saltar（ラテン語 saltare「踊る・跳ぶ」）に行為者を示す接尾辞 -dor を付けた語。英語の jumper や vaulter に対応し、-dor は英語の -er と同様に「〜する人」を意味する接尾辞。ラテン語 saltare は英語の assault（突撃）や somersault（宙返り）にも影響を与えている。' },
  'saltambanco / saltambancos': { es: 'El saltambanco animó a la multitud con sus acrobacias y trucos de magia callejeros.', ja: 'その大道芸人は路上での曲芸とマジックで群衆を沸かせた。', trivia: 'イタリア語 saltimbanco（「ベンチに飛び乗る者」、salti+in+banco）に由来し、市場の台の上で芸を披露する大道芸人を指す。英語の mountebank（ペテン師・大道売薬師）と同語源であり、どちらも「台に飛び乗る」というイタリア語の合成語から来ている。' },
  'saltarín / saltarina': { es: 'El niño saltarín no podía estar quieto ni un momento durante la clase.', ja: 'その飛び跳ねてばかりいる子どもは、授業中一瞬たりじっとしていられなかった。', trivia: 'saltar（ラテン語 saltare「跳ぶ・踊る」）に強調の接尾辞 -ín を付けた語で、「よく跳ね回る」傾向を指す。英語の bouncy や restless に対応するが、1語で表す形容詞は少ない。熱帯の鳥マイコドリ（manakin）もこの名で呼ばれ、英語の manakin も同語源のオランダ語経由。' },
  'salteada / salteado': { es: 'Pedí un salteado de verduras con tofu en el restaurante vegetariano del barrio.', ja: '近所のベジタリアンレストランで豆腐入り野菜炒めを注文した。', trivia: 'saltear（強火で炒める）の過去分詞が名詞・形容詞として定着した語で、フランス語 sauté と同じく「跳ばす・飛び跳ねさせる」という動作に由来する。英語の sautéed や stir-fried に相当し、「とびとびの・不規則な」という比喩的意味も持つ多義語である。' },
  'salteador / salteadora': { es: 'En el siglo XIX, los salteadores de caminos aterrorizaban a los viajeros en los pasos de montaña.', ja: '19世紀、追いはぎたちは山道の峠で旅人を恐怖に陥れていた。', trivia: 'saltear（不意打ちして襲う）＋動作主接尾辞 -ador から成り、「道端で旅人を急襲する強盗」を指す歴史的語彙。英語の highwayman や bandit に相当し、スペイン・中南米の盗賊ロマン文学（ピカレスク小説）でも頻出する語である。' },
  'saludador / saludadora': { es: 'El saludador del pueblo era conocido por su don para calmar a los enfermos.', ja: 'その村の祈祷治癒師は病人を癒す才能で知られていた。', trivia: 'saludar（挨拶する）の動作主名詞で、中世スペインでは狂犬病などを祈りや息で癒すと信じられた「奇跡治癒師」を指す特別な意味でも使われた。英語には対応する一語がなく、faith healer などと説明される。' },
  'salutífera / salutífero': { es: 'El médico destacó las propiedades salutíferas del agua de manantial de esa región.', ja: '医師はその地域の湧き水の健康に良い特性を強調した。', trivia: 'ラテン語 salus（健康）＋ ferre（運ぶ・もたらす）から成る合成語で、「健康をもたらす」という意味。英語の salutary（ためになる、有益な）と語根を共有し、やや文語的・詩的なニュアンスを持つ形容詞だ。' },
  'salvación / salvaciones': { es: 'La llegada del equipo de rescate fue la salvación de los mineros atrapados.', ja: '救助隊の到着は、閉じ込められた鉱山作業員たちの救いとなった。', trivia: 'ラテン語 salvatio（救済）に由来し、英語の salvation と同語源。キリスト教神学における「魂の救済」という意味で中世から使われ続けており、英語の Salvation Army（救世軍）の salvation もこの語と全く同じ語根だ。' },
  'salvador / salvadora': { es: 'El bombero fue considerado el salvador de la familia al rescatarlos del incendio.', ja: 'その消防士は火災から家族を救い出し、救済者とみなされた。', trivia: 'ラテン語 salvator（救済者）に由来し、英語の savior（または saviour）と同語源。キリスト教の伝播とともにスペイン語圏に広まり、El Salvador（エルサルバドル）という国名も「救世主（キリスト）の国」という意味を持つ。' },
  'salvapisas / salvapistas': { es: 'El ingeniero revisó el estado del salvapisas antes de iniciar las operaciones en la pista.', ja: 'エンジニアは滑走路での作業を開始する前に保護設備の状態を確認した。', trivia: 'salvar（保護する）と pista（滑走路・トラック）を組み合わせた専門用語で、航空・土木分野の特殊インフラに関する語。英語では runway protection equipment などと表現される。日常会話ではほとんど使われない技術用語の一例。' },
  'salvo / salva': { es: 'Todo el equipo aprobó la propuesta, salvo uno que pidió más tiempo para decidir.', ja: 'もっと時間が必要と求めた一人を除き、チーム全員が提案を承認した。', trivia: 'ラテン語 salvus（無事な・安全な）に由来し、英語の safe と同語源。前置詞「～を除いて」としての用法は中世ラテン語の「salvo eo（それを安全に除いて）」という法律表現が起源とされ、英語の save（古語で「～を除いて」）と全く並行した意味の発展を遂げた語。' },
  'salílica / salílico': { es: 'El ácido salílica es una forma antigua de referirse al compuesto activo del sauce.', ja: '「ácido salílica」はヤナギの活性成分を指す古い表現です。', trivia: '「salicílico」の異綴り（スペイン語圏の一部で見られる変形）。語源はラテン語 salix（ヤナギ）で、英語の salic acid や salicylic acid と同語根。英語では「サリチル酸」を salicylic acid と呼ぶ。' },
  'samaria / samario': { es: 'La región de Samaria fue escenario de importantes eventos en la historia bíblica.', ja: 'サマリア地方は聖書の歴史における重要な出来事の舞台となった。', trivia: '古代ヘブライ語の Shomron（見張り台の意）に由来する地名サマリアから派生した形容詞・名詞。英語でも Samaria / Samaritan として使われ、「善きサマリア人」の寓話（ルカ10章）を通じて世界的に知られる名称となった。' },
  'samaritana / samaritano': { es: 'Actuó como una auténtica samaritana al ayudar al desconocido herido en la calle.', ja: '彼女は路上で傷ついた見知らぬ人を助け、本物の善きサマリア人のように振る舞った。', trivia: '聖書の「善きサマリア人」の寓話から転じて、見返りを求めずに他者を助ける人を指す言葉として定着した。英語の Good Samaritan も同じ比喩的用法を持ち、多くの国で「善意の第三者を法的に保護する法律」を Good Samaritan Law と呼ぶ。' },
  'sambo / zambo': { es: 'En algunos documentos históricos coloniales, el término sambo se usaba para clasificar a los descendientes de africanos e indígenas.', ja: '一部の植民地時代の歴史文書では、samboという用語はアフリカ人と先住民の子孫を分類するために使われていた。', trivia: 'スペイン語圏ラテンアメリカの植民地時代に使われた人種分類語で、アフリカ系と先住民の混血を指した。語源については諸説あり、アフリカの言語に由来するとも、スペイン語の zambo（内股）に由来するとも言われる。英語の sambo は現在では侮辱語とされており、歴史的文脈以外での使用は避けられる。' },
  'samio / samia': { es: 'El filósofo Pitágoras era samio, nacido en la isla de Samos.', ja: '哲学者ピタゴラスはサモス島出身のサモス人だった。', trivia: 'ラテン語 Samius（サモス島の）に由来し、古代ギリシャの島サモスを指す形容詞・名詞。英語でも Samian という形が使われ、「Samian ware（サモス式陶器）」などの表現が残っている。' },
  'sanandresana / sanandresano': { es: 'La comunidad sanandresana mantiene viva su cultura caribeña y el idioma creole.', ja: 'サン・アンドレス島の人々はカリブ海の文化とクレオール語を生き続けさせている。', trivia: 'コロンビア領のカリブ海に浮かぶサン・アンドレス島（Isla de San Andrés）の形容詞・名詞形で、女性形が sanandresana、男性形が sanandresano。この島はかつてイギリス植民地だったため、住民は英語系クレオール語を話す独自の文化を持つ。' },
  'sanativa / sanativo': { es: 'Las propiedades sanativas de la miel han sido reconocidas desde la antigüedad.', ja: '蜂蜜の治癒効果は古来より認められてきた。', trivia: 'ラテン語 sanativus（治癒的な）に由来し、sanar（治す）と同語根。英語では curative や healing として表現されるが、スペイン語の sanativo/a は自然療法や伝統医学の文脈で特によく使われる形容詞である。' },
  'sangrienta / sangriento': { es: 'La batalla fue sangrienta y dejó miles de víctimas en ambos bandos.', ja: 'その戦闘は血なまぐさく、双方に数千人の犠牲者を出した。', trivia: 'sangre（血）に形容詞化接尾辞 -iento/a が付いた語で、「血にまみれた」を意味する。英語の bloody や gory に相当し、bloody はゲルマン系、gory はノルマン系と語源が異なる。スペイン語では -iento が「充満した・その性質を帯びた」という含意を持つ生産的な接尾辞として機能する。' },
  'sanguinario / sanguinaria': { es: 'El sanguinario dictador ordenó la ejecución de miles de civiles inocentes durante el régimen.', ja: 'その残虐な独裁者は政権期間中に何千人もの無実の市民の処刑を命じた。', trivia: 'ラテン語 sanguinarius（血に関係する、残酷な）から来ており、英語の bloodthirsty や murderous と対応する。同じ語根から英語の sanguine（楽観的・血色の良い）も派生しており、同じ「血」の語源が正反対のニュアンスを持つことが面白い。' },
  'sanguinea / sanguínea': { es: 'La presión sanguínea debe medirse con regularidad para detectar problemas cardiovasculares a tiempo.', ja: '心臓血管系の問題を早期に発見するために血圧は定期的に測定されなければならない。', trivia: 'ラテン語 sanguineus（血の、血に関する）の女性形で、英語の sanguine や sanguineous に対応する。医学用語として血液に関連する語句（presión sanguínea＝血圧、grupo sanguíneo＝血液型）によく用いられる。' },
  'sanguinolenta / sanguinolento': { es: 'Los médicos examinaron el vendaje sanguinolento y decidieron llevar al herido inmediatamente al quirófano.', ja: '医師たちは血まみれの包帯を調べ、負傷者をすぐに手術室に運ぶことを決めた。', trivia: 'ラテン語 sanguinolentus（血に満ちた）から来ており、英語の sanguinolent や bloody に相当する。文学や医学報告書で好まれる語で、単なる sangriento より学術的・古典的な響きを持つ。' },
  'sanguñuela / sanguijuela': { es: 'Mi jefe es una sanguijuela que se aprovecha del trabajo de todos sin dar nada a cambio.', ja: '私の上司は何も返さずに皆の仕事を搾取する寄生虫だ。', trivia: 'ラテン語 sanguisuga（血を吸うもの、sanguis＋sugere）に由来し、医療用ヒルとして古代から現代医療まで使われてきた。英語の leech とほぼ同じ比喩的用法（搾取者・強欲な人）を持つ点が興味深い。' },
  'sanie / sanies': { es: 'El médico observó que la herida comenzaba a secretar sanie, signo de una posible infección bacteriana.', ja: '医師は傷口が血膿を分泌し始めており、細菌感染の可能性があるサインだと観察した。', trivia: 'ラテン語 sanies（血膿、傷口からの分泌物）がそのままスペイン語に入った医学術語で、英語でも sanies として使われる。ギリシャ神話のイコール（神々の血）と概念的に関連付けられることもある古い医学用語である。' },
  'saniosa / sanioso': { es: 'El cirujano describió la herida como saniosa y ordenó un tratamiento antibiótico de inmediato.', ja: '外科医は傷口を血膿性と診断し、ただちに抗生物質による治療を指示した。', trivia: 'ラテン語 saniosus（血膿を伴う）に由来する医学的形容詞で、英語の sanious に直接対応する。臨床医学の記述でのみ使われる専門語であり、日常会話ではほぼ用いられない。' },
  'sanitaria / sanitario': { es: 'Los sanitarios trabajaron sin descanso durante la pandemia para atender a los pacientes más graves.', ja: '医療従事者たちはパンデミックの間、最も重症の患者たちを診るために休みなく働いた。', trivia: 'ラテン語 sanitarius（健康に関する）に由来し、英語の sanitary と同語源。スペインでは名詞として「医療従事者」を指すほか、「衛生陶器（トイレ・洗面台）」の意味でも使われる二重の用法が興味深い。' },
  'sanjuanera / sanjuanero': { es: 'La sanjuanera es una canción tradicional que se entona durante las fiestas de San Juan en algunas regiones.', ja: '「サンフアネーラ」とは、一部の地域で聖ヨハネ祭の期間中に歌われる伝統的な歌のことです。', trivia: '形容詞・名詞としてサン・フアン祭に関連するものを指し、特にスペイン北部のアストゥリアスやガリシアで聖ヨハネ祭の伝統歌やダンスを指す地域色の強い語です。英語に直接対応する語はありません。' },
  'sanjuanina / sanjuanino': { es: 'La industria vitivinícola sanjuanina es una de las más importantes de Argentina.', ja: 'サン・フアン州のワイン産業はアルゼンチンで最も重要な産業の一つです。', trivia: 'アルゼンチン中西部のサン・フアン州（Provincia de San Juan）の住民・文化を表す地域形容詞。この州はアルゼンチン第2のワイン産地として知られ、メンドーサ州と並ぶ「太陽のワイン（vinos del sol）」の産地です。' },
  'sanluqueña / sanluqueño': { es: 'La manzanilla sanluqueña es un vino fino y seco muy apreciado en toda Andalucía.', ja: 'サンルーカル産のマンサニーリャは、アンダルシア全土で高く評価されているすっきりとした辛口ワインです。', trivia: 'スペイン・アンダルシアのカディス県にあるサンルーカル・デ・バラメーダ（Sanlúcar de Barrameda）の住民・文化を指す形容詞。コロンブスやマゼランの出港地として歴史的に重要で、マンサニーリャ産地として世界的に知られています。' },
  'sanmarquina / sanmarquino': { es: 'La comunidad sanmarquina celebra cada año el aniversario de la fundación de su universidad.', ja: 'サン・マルコス大学の関係者たちは毎年、大学創立記念日を祝います。', trivia: 'ペルーのリマにある国立サン・マルコス大学（Universidad Nacional Mayor de San Marcos）の学生・卒業生を指す語。1551年創立の同大学は「アメリカ大陸最古の大学」として知られ、英語圏でも the oldest university in the Americas と紹介されます。' },
  'sano / sana': { es: 'Llevar una dieta sana y hacer ejercicio regularmente son los pilares de una vida larga.', ja: '健康的な食事をとり、定期的に運動することが長寿の柱です。', trivia: 'ラテン語 sanus（健全な、正気の）から直接受け継がれた語で、英語の sane（正気の）や sanitary（衛生的な）と同じ語根を持ちます。「sano y salvo」（無事に）という慣用句でも頻出します。' },
  'sanrafaelina / sanrafaelino': { es: 'La producción agrícola sanrafaelina destaca por sus viñedos y olivares en el sur de Mendoza.', ja: 'サン・ラファエルの農業生産は、メンドーサ南部のブドウ畑とオリーブ畑で際立っています。', trivia: 'アルゼンチン・メンドーサ州南部の都市サン・ラファエル（San Rafael）の住民・文化を指す地域形容詞。同市はアルゼンチン国内でも重要なワイン産地の一つで、アンデスの雪解け水を使ったかんがい農業が発達しています。' },
  'sanroqueña / sanroqueño': { es: 'La cultura sanroqueña muestra la influencia histórica del peñón de Gibraltar en la zona del Estrecho.', ja: 'サン・ロケの文化は、ジブラルタル海峡地域におけるジブラルタルの岩山の歴史的影響を示しています。', trivia: 'スペイン・アンダルシアのカディス県にある都市サン・ロケ（San Roque）の住民・文化を指す形容詞。同市はジブラルタル近郊に位置し、18世紀にジブラルタルから避難したスペイン人が建設した歴史的背景を持ちます。' },
  'sanscrito / sánscrito': { es: 'El sanscrito es una de las lenguas más antiguas del mundo y sigue siendo lengua oficial de la India.', ja: 'サンスクリット語は世界最古の言語の一つで、インドでは現在も公用語の一つとなっています。', trivia: 'サンスクリット語自身の名称 saṃskṛta（「完全に整えられた（言語）」の意）に由来します。アクセント記号ありの sánscrito が標準的な綴りで、英語の Sanskrit と同語源。印欧語族の原形を最もよく保った言語として比較言語学の基盤となっています。' },
  'santafecina / santafecino': { es: 'La gastronomía santafecina combina la herencia italiana con los ingredientes del río Paraná.', ja: 'サンタ・フェの料理は、イタリアの食文化とパラナ川の食材を組み合わせています。', trivia: 'アルゼンチンのサンタ・フェ州（Provincia de Santa Fe）の住民・文化を指す地域形容詞。santafesina / santafesino というバリエーションも存在し、表記揺れが見られます。同州はアルゼンチン農業の中心地で、大豆・トウモロコシの一大産地として知られています。' },
  'santafereña / santafereño': { es: 'La cocina santafereña tiene influencias indígenas y españolas que la hacen única.', ja: 'ボゴタの料理は先住民とスペインの影響を受けており、独自の風味を持っている。', trivia: '「santafereño/a」はコロンビアの首都ボゴタの旧称「Santa Fe de Bogotá」に由来し、特に植民地時代の文化や建築様式を指す際に用いられる。英語では「Bogotano」と呼ぶことが多い。' },
  'santafesina / santafesino': { es: 'La ganadería santafesina es una de las más importantes de Argentina.', ja: 'サンタ・フェ州の畜産業はアルゼンチンで最も重要な産業の一つだ。', trivia: 'アルゼンチンのサンタ・フェ州（Provincia de Santa Fe）はラ・プラタ川流域に広がる農業・牧畜の中心地で、「santafesino/a」はその出身者を指す。形容詞接尾辞 -sino はラテン語 -ensis に起源を持つ。' },
  'santiaguera / santiaguero': { es: 'La música santiaguera, especialmente el son cubano, ha influido en todo el mundo.', ja: 'サンティアゴ（キューバ）の音楽、特にソン・クバーノは世界中に影響を与えてきた。', trivia: '「santiaguera/o」はキューバやドミニカ共和国など複数の「サンティアゴ」出身者を指すが、特にキューバのサンティアゴ・デ・クーバに関連して用いられることが多い。英語では「Santiagan」と表記される場合がある。' },
  'santiaguina / santiaguino': { es: 'La vida santiaguina es agitada, pero la ciudad también ofrece muchos parques y espacios culturales.', ja: 'サンティアゴっ子の生活は忙しいが、この都市には多くの公園や文化施設もある。', trivia: '「santiaguino/a」はチリの首都サンティアゴの市民を指す最も一般的な形で、「santiaguero/a」より正式な響きを持つ。接尾辞 -ino はラテン語 -inus に由来し、英語の -ine（例: masculine, marine）と同語源。' },
  'santiamén / santiamenes': { es: 'Lo terminé en un santiamén porque era una tarea muy sencilla.', ja: 'とても簡単な作業だったので、あっという間に終わらせた。', trivia: '「santiamén」はカトリックの典礼文「In saecula saeculorum, Amen（世々に至るまで、アーメン）」が縮約されたとされ、「amen（アーメン）」が英語にも同形で存在する。英語の「in a jiffy（あっという間に）」に相当する口語表現。' },
  'santiamén / santiaménes': { es: 'Lo terminé en un santiamén porque era una tarea muy sencilla.', ja: 'とても簡単な作業だったので、あっという間に終わらせた。', trivia: '「santiamén」はカトリックの典礼文「In saecula saeculorum, Amen（世々に至るまで、アーメン）」が縮約されたとされ、「amen（アーメン）」が英語にも同形で存在する。英語の「in a jiffy（あっという間に）」に相当する口語表現。' },
  'santificadora / santificador': { es: 'La gracia santificadora es, según el catecismo, el don de Dios que hace al alma partícipe de su vida divina.', ja: 'カテキズムによれば、聖化の恩寵とは魂を神の命に参与させる神の賜物である。', trivia: '「santificadora」はラテン語 sanctificare に行為者接尾辞 -dor/-dora が付いた語で、英語の「sanctifier」に対応する。カトリック神学では「gracia santificadora（聖化の恩寵）」という表現で頻繁に用いられる。' },
  'santiguada / santiguado': { es: 'Al entrar al hospital, la abuela hizo una santiguada y murmuró una oración.', ja: '病院に入るとき、おばあさんは十字を切り、小声で祈りをつぶやいた。', trivia: '「santiguada」は動詞 santiguar の名詞化形で、十字を切る一連の動作を指す。ラテン語 Sanctus Iacobus（聖ヤコブ）に由来するという説があり、英語の「blessing」に意味的に近い。' },
  'santiguador / santiguadora': { es: 'En los pueblos rurales de Andalucía, el santiguador era consultado para curar el mal de ojo.', ja: 'アンダルシアの農村では、邪視（evil eye）を治すために祈祷師に相談することがあった。', trivia: '「santiguador」は民間信仰に根差した呼称で、十字を切りながら祈祷（きとう）して病気や呪いを治すとされた人物を指す。英語の「faith healer」や「folk healer」に相当し、スペインやラテンアメリカの民俗医療の伝統を体現する語。' },
  'santiscario / santiscari': { es: 'El niño se tiró al suelo por su santiscario cuando no le compraron el juguete.', ja: 'おもちゃを買ってもらえなかった子どもは、自分の我を通そうと床に転がった。', trivia: 'スペイン口語の表現で、「santo」（聖）と関連するとも、単純な俗語的派生ともいわれ語源は不明確。英語には直訳しにくく、stubbornness（頑固さ）や whim（気まぐれ）で近い意味を表す。' },
  'santismo / santísimo': { es: 'Los peregrinos se acercaron con reverencia al santísimo expuesto en el altar mayor.', ja: '巡礼者たちは、主祭壇に安置された御聖体に畏敬の念を持って近づいた。', trivia: 'ラテン語 sanctissimus の男性形に由来し、「el Santísimo」はカトリックでは御聖体（聖体拝領のパン）を指す固有名詞的な用法もある。英語では the Blessed Sacrament に相当し、スペイン語圏のカトリック文化に深く根付いた語。' },
  'santo / santa': { es: 'El guardia exigió la contraseña y el soldado respondió con el santo correcto para poder pasar.', ja: '衛兵は合言葉を要求し、兵士は通過するために正しい合言葉を答えた。', trivia: 'ラテン語 sanctus（神聖な）に由来し、英語の saint、sanctuary、sanction なども同じ語根を持つ。スペイン語では「santo y seña」（合言葉・パスワード）という成句でも使われ、宗教的意味から軍事・日常用語まで幅広く活用される語。' },
  'santucho / santucha': { es: 'No soporto a ese santucho que predica virtudes que él mismo no practica.', ja: '自分自身は実践しない美徳を説いているあの偽善者に我慢できない。', trivia: 'santo（聖人）に口語的な指小・軽蔑の接尾辞 -ucho を加えた形で、「なんちゃって聖人」というニュアンスを持つ。英語の hypocrite や goody-goody に近く、スペイン口語に多い接尾辞 -ucho は軽蔑や侮りを表す特徴がある。' },
  'santísima / santísimo': { es: 'El sacerdote elevó la santísima forma durante la misa y los fieles se arrodillaron en silencio.', ja: '司祭はミサの最中に御聖体を高く掲げ、信徒たちは静かにひざまずいた。', trivia: 'ラテン語 sanctissimus（最も神聖な）に由来する santo の絶対最上級形で、英語の most holy に相当。カトリック用語では「la Santísima Trinidad」（至聖三位一体）や「la Santísima Virgen」（聖母マリア）の形で頻繁に用いられる。' },
  'santón / santona': { es: 'El santón del barrio daba consejos a todos, pero en privado llevaba una vida muy diferente.', ja: 'その街の大物ぶった偽善者は皆に助言を与えていたが、私生活ではまったく異なる暮らしをしていた。', trivia: 'スペイン語 santo（聖人）に指小・強調の接尾辞 -ón を加えた形で、もとは北アフリカのイスラム聖者（マラブー）を指した。英語には直訳する単語がなく、bigot や false prophet で意味を近似することが多い。' },
  'sanzala / sanzala / sanzala': { es: 'La sanzala era el centro comunitario donde los habitantes del pueblo se reunían para celebrar sus tradiciones.', ja: 'サンスアラは住民が伝統を祝うために集まるコミュニティの中心地だった。', trivia: 'アンゴラなどのバントゥー系言語に由来するアフリカ起源の語で、ポルトガル語経由でスペイン語に入った。英語では village compound や traditional settlement に相当し、植民地時代の歴史的文脈でアフリカの集落構造を指す民俗学的な語。' },
  'sapenco / sapencas': { es: 'En el jardín había un sapenco enorme que asustó a los niños cuando salió de entre las piedras.', ja: '庭には巨大なヒキガエルがいて、石の間から現れたとき子どもたちを驚かせた。', trivia: 'スペイン語の sapo（ヒキガエル）に接尾辞 -enco を加えた口語形で、「大きくて不格好なヒキガエル」を指す。英語の toad に相当するが、-enco という接尾辞が「大きくて醜い」という軽蔑的なニュアンスを加えるスペイン口語の特徴的な語形成。' },
  'saphena / safena': { es: 'El cirujano extirpó la vena safena de la pierna del paciente para utilizarla como injerto coronario.', ja: '外科医は冠動脈バイパス術に使うため、患者の脚から大伏在静脈を摘出した。', trivia: 'アラビア語 sāfin（「隠れた」「明白な」の両義を持つ）に由来するとされる。英語の saphenous vein と同語源で、医学用語としてラテン語 vena saphena を経由して欧州各語に伝わった国際的な術語。' },
  'saporífera / saporífero': { es: 'Las especias tienen propiedades saporíferas que enriquecen cualquier receta.', ja: '香辛料はあらゆる料理を豊かにする風味付けの特性を持っている。', trivia: 'ラテン語 sapor（味）＋ ferre（運ぶ・もたらす）の合成語で、英語の saporiferous と同語源。「味や風味をもたらすもの」という意味で、形容詞の女性形として使われる。' },
  'saqueador / saqueadora': { es: 'Los saqueadores aprovecharon el caos tras el terremoto para robar tiendas y almacenes.', ja: '略奪者たちは地震後の混乱に乗じて、商店や倉庫を荒らした。', trivia: '動詞 saquear（略奪する）に行為者接尾辞 -dor を加えた派生語で、英語の looter や plunderer に相当。「saco（袋）」を語根に持ち、「袋に詰めて奪い去る者」というイメージが語源的に宿っている。' },
  'saquetera / saquetero': { es: 'La saquetera del mercado medieval cosía y vendía bolsas de cuero para los viajeros.', ja: '中世の市場の女袋職人は、旅人向けに革袋を縫って売っていた。', trivia: 'saco（袋）＋職業接尾辞 -tero/-tera から成る語で、袋を作る・運ぶ職人を指す歴史的な職業名詞。英語の sack（袋）と語源を共有しており、ラテン語 saccus（袋）が共通の祖先。' },
  'sarcástica / sarcástico': { es: 'Hizo una observación sarcástica que dejó a todos incómodos.', ja: '彼女は皮肉な指摘をして、みなを気まずい気分にさせた。', trivia: 'sarcástico / sarcástica はギリシャ語の sarkasmós（肉を噛み切る）に由来し、英語の sarcastic と同源。スペイン語では形容詞が修飾する名詞の性に合わせて語尾が変化するため、女性名詞には -a 形が用いられる。' },
  'sardónica / sardónico': { es: 'La actriz esbozó una sonrisa sardónica antes de abandonar la sala de prensa.', ja: 'その女優は記者会見場を去る前に冷笑的な笑みを浮かべた。', trivia: '古代ギリシャ語の sardónios（σαρδόνιος）に由来し、サルディーニャ島（Sardinia）で生育する植物を食べると顔がひきつるような表情になるという伝説から生まれた語。英語の sardonic と完全に同源で、「不敵な、皮肉な笑い」を指す国際語である。' },
  'sarguera / sangradera': { es: 'La sarguera se usaba antiguamente para extraer sangre de los pacientes como tratamiento médico.', ja: 'サルゲラはかつて治療として患者から血液を採取するために使われていた。', trivia: 'ラテン語 sanguis（血）に由来し、瀉血（しゃけつ）用の器具や灌漑用水路の分水口を指す言葉として地域によって意味が広がった。英語には直接対応する語がなく、医療史の文脈では bloodletting instrument と説明される。' },
  'sarmentosa / sarmentoso': { es: 'La planta sarmentosa trepaba por toda la pared del jardín.', ja: 'そのつる性の植物は庭の壁全体を覆うように伸びていた。', trivia: 'スペイン語の sarmiento（ブドウの細枝）から派生した形容詞で、英語の sarmentose と同源のラテン語 sarmentum（切り枝）に由来する。植物学用語として「つるや巻きひげで伸びる」性質を指し、比喩的に細く筋張った手足の描写にも使われる。' },
  'sarpullido / salpullido': { es: 'El niño salió con un sarpullido en los brazos tras jugar en el jardín.', ja: '子どもは庭で遊んだあと、腕に発疹が出た。', trivia: 'スペイン語独自の語で、語源は sal（塩）＋ pullido（細かい粒）という説や、動詞 salpullar から来るという説がある。英語の rash や hives に相当し、salpullido という異形も存在する口語的な医療・日常語である。' },
  'sarrapia / serrapia': { es: 'El perfumista utilizó extracto de sarrapia para crear una fragancia cálida y almendrada.', ja: '調香師は温かみのあるアーモンドのような香りを作るためにトンカマメのエキスを使った。', trivia: '南米原産のマメ科植物トンカノキ（Dipteryx odorata）の種子（トンカビーン）から採れる香料素材で、英語では tonka bean と呼ばれる。クマリンを含む独特の甘い香りを持ち、欧州ではかつて食品香料として使用されたが、過剰摂取の懸念から現在は規制対象となっている国もある。' },
  'satisfactoria / satisfactorio': { es: 'Los resultados del examen fueron satisfactorios y el profesor quedó contento con los alumnos.', ja: '試験の結果は満足のいくものであり、先生は生徒たちに満足していた。', trivia: 'ラテン語 satisfactorius に由来し、英語の satisfactory と同語源。ビジネスや学術評価において「合格基準を満たす」という意味合いは英語とスペイン語でほぼ同一であり、国際的なビジネス文書でも対応関係が明確な語だ。' },
  'satírica / satírico': { es: 'La revista publicó una columna satírica que criticaba duramente las decisiones del gobierno.', ja: 'その雑誌は政府の決定を厳しく批判する風刺的なコラムを掲載した。', trivia: 'ラテン語 satira（混合物、諷刺詩）に由来し、英語の satirical と同語源。古代ローマで発達した文学ジャンル「サトゥラ」がその起源で、様々な題材を混ぜ合わせた詩形式だった。' },
  'saucedal / sauceda': { es: 'Caminamos por un saucedal a orillas del río para disfrutar de la sombra en verano.', ja: '夏の木陰を楽しもうと、私たちは川岸のヤナギ林を歩いた。', trivia: 'sauce（ヤナギ）に場所を示す接尾辞 -al または -eda が付いた派生語で、「ヤナギが群生する場所」を意味する。英語に直接対応する単語はなく、willow grove や willow thicket と言い換えるが、スペイン語はこうした植物群生地を一語で表す接尾辞が豊富だ。' },
  'saxofón / saxo': { es: 'El saxofón sonó con fuerza en el solo de jazz que emocionó a todo el público.', ja: 'ジャズのソロでサックスが力強く鳴り響き、観客全員を感動させた。', trivia: '19世紀のベルギー人楽器製作者アドルフ・サックス（Adolphe Sax）の名前に由来する比較的新しい語で、英語の saxophone と同語源かつ同発明家の名前を持つ。スペイン語では saxo と略されることも多く、口語では奏者自身を指す場合もある。' },
  'saxón / sajón': { es: 'El rey anglosaxón gobernó Inglaterra con sabiduría durante décadas.', ja: 'そのアングロサクソンの王は何十年もの間、知恵をもってイングランドを治めた。', trivia: 'ラテン語 Saxo（サクソン人）に由来し、英語の Saxon と同語源。サクソン人は現在のドイツ北部を発祥とするゲルマン民族で、5世紀以降ブリテン島に移住してアングロサクソン文化を形成した。スペイン語では anglosajon（アングロサクソン）の形でも頻用される。' },
  'sazonada / sazonado': { es: 'La carne sazonada con hierbas aromáticas desprendía un aroma irresistible durante la cocción.', ja: '香草で味付けされた肉は、調理中に抗いがたい香りを放っていた。', trivia: 'sazonar の過去分詞形容詞で、英語の seasoned に相当。英語でも seasoned は「味付けされた」と「経験豊富な（a seasoned professional）」の二義を持つが、スペイン語の sazonado も「洗練された・時宜を得た」という比喩的用法が存在し、両言語で意味の広がり方が類似している。' },
  'seborreica / seborreico': { es: 'La dermatitis seborreica es una afección crónica de la piel que causa enrojecimiento y descamación.', ja: '脂漏性皮膚炎は皮膚の慢性疾患で、赤みやフケを引き起こす。', trivia: 'seborrea に形容詞語尾 -ico/a を付けた派生語で、英語の seborrheic に対応。主に医学・皮膚科学の文脈で用いられる。' },
  'secadal / secadal': { es: 'En ese secadal apenas crecen algunas plantas xerófilas adaptadas al clima extremo.', ja: 'その乾燥地には極端な気候に適応した乾生植物がわずかに生えているだけだ。', trivia: 'seco（乾いた）に集合・場所を示す接尾辞 -al を付けた語。英語に直訳する対応語はなく「dry land」などと言い換える。スペインの半乾燥地帯を描写する文学や農業文書に見られる。' },
  'secamuelle / secamuelles': { es: 'Ese secamuelle pasaba los días jugando a las cartas en el muelle en lugar de buscar trabajo.', ja: 'そのゴロツキは仕事を探す代わりに、波止場でトランプをして日々を過ごしていた。', trivia: 'secar（乾かす）＋muelle（波止場）の複合語で、字義通りには「波止場を乾かす者」。アルゼンチンの口語表現で、英語の dock loafer や layabout に相当する。港湾労働文化の中で生まれた皮肉的な俗語。' },
  'seco / seca': { es: 'El verano pasado fue tan seco que los ríos se quedaron casi sin agua.', ja: '去年の夏はとても乾燥していて、川がほぼ干上がってしまった。', trivia: 'ラテン語 siccus（乾いた）に由来し、英語の desiccate（乾燥させる）と語源を共有する。ワインの「辛口」を意味する sec（フランス語）も同じ語根から来ており、スペイン語でも辛口ワインは vino seco と言う。' },
  'secreta / secreto': { es: 'La secreta se rezaba en voz baja por el sacerdote durante la misa.', ja: 'ミサの間、司祭は密祷を低い声で唱えた。', trivia: 'ラテン語 secreta（隠されたもの）に由来し、英語の secret と同語源。カトリック典礼用語としての「密祷」のほか、口語では私服警官を指す隠語としても使われた歴史がある。' },
  'secretor / secretora': { es: 'El tejido secretor de las glándulas salivales produce enzimas digestivas.', ja: '唾液腺の分泌組織は消化酵素を産生する。', trivia: 'ラテン語 secretus（分離された）＋ 行為者接尾辞 -or から成り、英語の secretory と同語源。生理学・医学用語として腺や細胞が物質を分泌する性質を表し、日本語の「分泌性の」に対応する専門語。' },
  'sectaria / sectario': { es: 'Su actitud sectaria le impedía escuchar opiniones distintas a las de su grupo.', ja: '彼女の党派的な態度が、自分のグループ以外の意見を聞くことを妨げていた。', trivia: 'secta（宗派）に由来し、英語の sectarian と同語源。ラテン語 sectarius（派に属する者）から来ており、もとは宗教的文脈で使われたが、現在は政治や社会運動における排他的・狂信的な立場を指して幅広く使われる。' },
  'sectorial / sectoriales': { es: 'El gobierno anunció una política sectorial para apoyar a la industria turística.', ja: '政府は観光産業を支援するための業界別政策を発表した。', trivia: 'sector に形容詞語尾 -al を加えた語で、英語の sectoral と同語源・同構造。経済・行政の文脈で「特定分野に特化した」という意味で使われ、política sectorial（業界別政策）や análisis sectorial（セクター分析）などのコロケーションが頻出する。' },
  'secuestradora / secuestrador': { es: 'La secuestradora exigió un rescate millonario a la familia de la víctima.', ja: '女性誘拐犯は被害者の家族に高額の身代金を要求した。', trivia: '動詞 secuestrar から派生した行為者名詞で、ラテン語 sequestrare（預ける、没収する）が語源。英語 kidnapper とは異なり、ハイジャックや法的差し押さえの行為者も指す。' },
  'secundario / secundaria': { es: 'El actor recibió un premio por su papel secundario en la película.', ja: 'その俳優は映画での助演により賞を受賞した。', trivia: 'ラテン語 secundarius（二番目の）が語源で、英語 secondary と同語源。映画・演劇用語として「脇役」を意味する papel secundario は、英語の supporting role に相当する表現として広く使われる。' },
  'sedentaria / sedentario': { es: 'Ella lleva una vida sedentaria desde que trabaja desde casa todo el día.', ja: '彼女は一日中在宅勤務をしていて、座りがちな生活を送っている。', trivia: 'ラテン語 sedentarius（座っている人）が語源で、英語 sedentary と同語源。古代ローマでは「座って仕事をする職人」を指す言葉だったが、現代では運動不足の生活様式を指す医学・健康分野の用語として定着した。' },
  'sediento / sedienta': { es: 'Llegamos al refugio sedientos y exhaustos tras horas de caminata por el desierto.', ja: '砂漠を何時間も歩いた後、私たちは喉が渇いて疲労困憊した状態で避難所に到着した。', trivia: 'ラテン語 sitiens（渇いている）の俗ラテン語形 *seditientem から変化したとされ、英語 thirsty とは異なりゲルマン語系ではなくラテン語由来。「sediento de poder（権力に飢えた）」のように比喩的に使われる表現も豊富である。' },
  'seductora / seductor': { es: 'La música de ese compositor tiene una melodía seductora que es difícil de olvidar.', ja: 'その作曲家の音楽には、忘れがたい魅惑的なメロディーがある。', trivia: 'seducir（誘惑する）の語幹に -tor/-tora という行為者を表すラテン語接尾辞が付いた形容詞・名詞。英語の seductive（形容詞）や seducer（名詞）に相当し、男性形は seductor、女性形は seductora となる。' },
  'segador / segadora': { es: 'El segador pasó toda la mañana cortando la hierba del campo con su guadaña.', ja: '刈り手は午前中ずっと鎌で野原の草を刈り続けた。', trivia: 'segar（刈る）＋行為者接尾辞 -dor から成り、英語の reaper や mower に相当する。「死神（la Muerte con la guadaña）」のイメージと結びつき、カタルーニャ独立運動の歌「Els Segadors（刈り手たち）」はカタルーニャの国歌にもなっている。' },
  'sádica / sádico': { es: 'La directora tenía una actitud sádica, disfrutando del sufrimiento ajeno.', ja: 'その女性監督はサディスティックな態度を持ち、他人の苦しみを楽しんでいました。', trivia: '18世紀フランスの作家マルキ・ド・サド（Marquis de Sade）の名前に由来する固有名詞からの派生語で、英語の sadistic も全く同じ語源。フランス語経由でヨーロッパ各言語に広まり、人名から一般形容詞になった「エポニム」の典型例である。' },
  'sáfico / sáfica': { es: 'El metro sáfico, con su ritmo característico de once sílabas, fue adoptado por poetas latinos como Horacio.', ja: '11音節の独特なリズムを持つサッフォー詩体は、ホラティウスなどローマの詩人たちに採り入れられた。', trivia: '古代ギリシャの女性詩人サッフォー（Sappho、紀元前7〜6世紀頃、レスボス島出身）の名に由来。英語の Sapphic と完全に対応する。「レスビアン（lesbian）」という語も彼女の出身地レスボス島（Lesbos）に由来しており、sáfico の古い意味と連動している。' },
  'sápida / sápido': { es: 'La conferencia resultó ser muy sápida gracias a los ejemplos concretos y el humor del ponente.', ja: '具体的な例と講演者のユーモアのおかげで、その講演はとても面白く知的な刺激に富むものだった。', trivia: 'ラテン語 sapidus（風味のある、味のある）の女性形に由来し、英語の sapid と同語源。転じて「知的に興味深い」という比喩的用法も持ち、その反義語 insípida（味気ない、つまらない）は日常的によく使われる。' },
  'tabaquero / tabaquera': { es: 'La industria tabaquera de Cuba es reconocida mundialmente por la calidad de sus puros.', ja: 'キューバのタバコ産業は葉巻の品質において世界的に知られている。', trivia: 'tabaco＋形容詞・職業人接尾辞 -ero/-era から成り、英語の tobacco（形容詞的用法）や cigar maker に相当する。キューバやドミニカ共和国の手巻き葉巻職人（torcedor）は tabaquero とも呼ばれ、その技術はユネスコの無形文化遺産にも登録されている。' },
  'tabernero / tabernera': { es: 'El tabernero conocía los gustos de cada cliente y servía las bebidas sin necesidad de pedirlas.', ja: '居酒屋の主人は客それぞれの好みを知っており、注文されなくても飲み物を出していた。', trivia: 'taberna（居酒屋）＋職業人接尾辞 -ero/-era から成り、英語の tavern keeper や innkeeper に相当する。古代ローマの tabernarius（商店主）と同語根であり、中世ヨーロッパでは宿の経営者も兼ねることが多かった。' },
  'tacaño / tacaña': { es: 'Mi vecino es tan tacaño que apaga las luces del pasillo para ahorrar electricidad.', ja: '私の隣人はとてもケチで、電気代を節約するために廊下の照明を消してしまう。', trivia: '語源には諸説あり、アラビア語起源説とラテン語 attaccare（くっつける）から転じた説がある。英語の stingy や mean に相当するが、スペイン語では mezquino（卑劣なケチ）よりも日常的な表現として広く使われる。' },
  'talentosa / talentoso': { es: 'La joven pianista es extremadamente talentosa y ya ha ganado varios premios internacionales.', ja: 'その若いピアニストは非常に才能があり、すでにいくつかの国際賞を受賞している。', trivia: 'talento に形容詞接尾辞 -oso/-osa が付いた形で「才能に満ちた」を意味する。英語の talented に相当するが、スペイン語の -oso は「〜を豊富に持つ」というニュアンスが強く、同様の構造が famoso（有名な）や poderoso（力強い）にも見られる。' },
  'tecnológico / tecnológica': { es: 'El avance tecnológico ha creado nuevas oportunidades de empleo en todo el mundo.', ja: '技術的な進歩は、世界中で新たな雇用機会を生み出している。', trivia: 'tecnología に形容詞化接尾辞 -ico を付けた語で、英語の technological と対応する。ギリシャ語 -logos（学問・論理）が -logía という名詞形と -lógico という形容詞形の両方に引き継がれており、語形成の規則性が際立つ。' },
  'telefónico / telefónica': { es: 'La empresa ofrece un servicio de atención telefónica disponible las veinticuatro horas.', ja: 'その会社は24時間対応の電話サポートサービスを提供している。', trivia: 'teléfono に形容詞接尾辞 -ico を付けた語で、英語の telephonic に相当する。ギリシャ語 tele-（遠く）+ phone（音・声）という構成は英語・スペイン語共通で、電話の発明者グラハム・ベルが1876年に命名した。' },
  'templado / templada': { es: 'El clima templado de esa región mediterránea atrae a muchos jubilados europeos cada invierno.', ja: 'その地中海地方の温暖な気候が、毎冬多くのヨーロッパの退職者を引き付けている。', trivia: 'ラテン語 temperare（調節する、和らげる）を語源とし、英語の temperate（温暖な、節度ある）と同語源。金属加工の「焼き入れ」の意味もあり、英語の tempered steel（焼き入れ鋼）に対応する。' },
  'táctico / táctica': { es: 'El general tomó una decisión táctica para rodear al enemigo por el flanco derecho.', ja: '将軍は右翼から敵を包囲するために戦術的な決断を下した。', trivia: 'táctica（名詞）の形容詞形で、ギリシャ語 taktikós（配置に関する）が語源。英語の tactical と完全に対応しており、軍事・スポーツ・ビジネスいずれの文脈でも同様の意味で使われる。' },
  'técnico / técnica': { es: 'El técnico reparó el ordenador en menos de una hora.', ja: '技術者は1時間足らずでコンピューターを修理した。', trivia: 'ギリシャ語 technikos（技術・芸術に関する）に由来し、英語の technical / technician と完全に同語源。ギリシャ語 techne（技術・芸術）はさらに「木を大工する」を意味する語根まで遡れ、人間の「作る能力」を表す古い概念。' },
  'ganal': { es: 'Trabaja mucho para ganar dinero y mantener a su familia.', ja: '家族を養うためにお金を稼ごうと懸命に働いている。', trivia: '「ganar（勝つ・稼ぐ）」の別見出し語。ゲルマン語 waidanōn（牧草で食を得る）に由来し、英語の gain と同語根。' },
  'sangual / sanjual': { es: 'El sangual es un árbol frutal típico de algunas regiones de América del Sur.', ja: 'サンワルは南米の一部地域に固有の果樹だ。', trivia: '南米の地域語・民俗名で、語源には諸説あり確定していない。英語の直接対応語はなく、地域固有の植物名として記録されている。' },
  'sanies': { es: 'La sanies es una secreción serosa y purulenta que puede aparecer en heridas infectadas.', ja: 'サニーズ（膿血）は感染した傷口に現れることのある漿液性の化膿分泌物だ。', trivia: 'ラテン語 sanies（薄い膿・血清）からそのまま受け継がれた医学専門語。英語でも sanies と言い、sanguine（楽観的、血の赤みの）と遠い語根を共有するとも言われる。' },
};
